INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (1, '캔들/가격행동', '02_candlestick_price_action.md', '하락 추세 지속 도중 바닥권에서 몸통이 짧고 아래꼬리가 몸통의 2배 이상인 아래 캔들이 출현했습니다. 이 캔들의 명칭과 올바른 대응은?', '[{"time":"10:00","open":120,"high":122,"low":118,"close":119,"volume":86},{"time":"10:15","open":119,"high":120,"low":113,"close":114,"volume":123},{"time":"10:30","open":114,"high":115,"low":108,"close":109,"volume":127},{"time":"10:45","open":109,"high":110,"low":101,"close":102,"volume":96},{"time":"11:00","open":102,"high":103,"low":90,"close":101,"volume":113}]'::jsonb, '[]'::jsonb, ARRAY['역망치형 (Inverted Hammer) - 하락 경고 및 공매도 대기', '망치형 (Hammer) - 저점 지지 및 분할 매수 대기', '도지 (Doji) - 매수세와 매도세의 팽팽한 균형 및 관망', '하락 장악형 (Bearish Engulfing) - 추세 반전 및 즉시 손절']::text[], 1, '마지막 캔들은 아래꼬리가 긴 ''망치형(Hammer)'' 캔들로 하락 압력을 이겨내고 저가 매수세가 밀어 올렸음을 의미하는 대표적 상승 전환 신호입니다. 지지를 확인한 뒤 분할 매수 관점으로 대기해야 합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (2, '캔들/가격행동', '02_candlestick_price_action.md', '주가가 장기간 급등한 뒤, 고점 부근에서 위꼬리가 매우 길고 몸통이 짧은 형태의 캔들이 발생했습니다. 이 캔들의 해석으로 가장 적절한 것은?', '[{"time":"Day 1","open":100,"high":108,"low":99,"close":105,"volume":106},{"time":"Day 2","open":105,"high":115,"low":104,"close":112,"volume":87},{"time":"Day 3","open":112,"high":125,"low":111,"close":123,"volume":100},{"time":"Day 4","open":123,"high":128,"low":120,"close":126,"volume":120},{"time":"Day 5","open":126,"high":145,"low":125,"close":127,"volume":102}]'::jsonb, '[]'::jsonb, ARRAY['유성형 (Shooting Star) - 고점 저항 및 하락 전환 예고', '망치형 (Hammer) - 저점 매수세 유입 및 상승 랠리 기대', '상승 장악형 (Bullish Engulfing) - 추세 반전 및 홀딩 유도', '도지 (Doji) - 추세 지속 가능성 및 일시 관망']::text[], 0, '급등세 끝에서 위꼬리가 몸통보다 훨씬 길게 솟아오른 캔들은 ''유성형(Shooting Star)''입니다. 장중 상승 시도를 강력한 차익 실현 및 매도 압력이 짓눌렀음을 보여주며, 하락 추세 전환의 강력한 경고 시그널입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (3, '캔들/가격행동', '02_candlestick_price_action.md', '직전의 음봉 몸통을 다음 날의 거대한 양봉 몸통이 완전히 감싸 안는 아래 형태가 포착되었습니다. 이 패턴의 이름과 신뢰도는?', '[{"time":"Day 1","open":98,"high":100,"low":95,"close":96,"volume":86},{"time":"Day 2","open":96,"high":97,"low":92,"close":93,"volume":100},{"time":"Day 3","open":93,"high":95,"low":88,"close":89,"volume":118},{"time":"Day 4","open":87,"high":102,"low":86,"close":101,"volume":98}]'::jsonb, '[]'::jsonb, ARRAY['하락 장악형 (Bearish Engulfing) - 추세 반전 신뢰도 낮음', '상승 장악형 (Bullish Engulfing) - 매수 전환 신뢰도 높음', '상승 관통형 (Piercing Line) - 중간 강도의 반전 신호', '석별형 (Evening Star) - 상승 추세 종결 신호']::text[], 1, '전일의 하락 음봉 몸통을 다음 날의 장대 양봉이 완전히 덮어버리는 형태를 ''상승 장악형(Bullish Engulfing)'' 패턴이라고 합니다. 하락 추세 끝에서 나타날 경우 단기 하락세가 종료되고 강력한 매수세가 들어왔음을 뜻해 전환 신뢰도가 매우 높습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (4, '캔들/가격행동', '01_chart_market_basics.md', '시가와 종가가 거의 일치하여 몸통이 거의 없고 위아래 꼬리만 달린 십자(+) 모양 캔들이 출현했습니다. 이 캔들에 대한 올바른 해석은?', '[{"time":"Day 1","open":150,"high":155,"low":148,"close":152,"volume":113},{"time":"Day 2","open":152,"high":156,"low":151,"close":154,"volume":102},{"time":"Day 3","open":154,"high":159,"low":150,"close":154,"volume":93}]'::jsonb, '[]'::jsonb, ARRAY['상승세 동력 상실로 인한 추세의 하방 반전', '매수/매도 세력 균형에 따른 도지(Doji) 횡보', '매도세 지배에 따른 즉각적인 숏 포지션 진입', '하락 세력 이탈로 인한 즉각적인 상승 랠리']::text[], 1, '시가와 종가가 거의 같은 십자 모양의 캔들은 ''도지(Doji)'' 캔들입니다. 이는 힘의 균형이 팽팽함을 시사하며, 기존 추세의 힘이 빠지고 잠재적인 방향성 전환(상승/하락 모두 포함)의 변곡점이 다가오고 있음을 의미합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (5, '캔들/가격행동', '02_candlestick_price_action.md', '상승 추세 고점에서 직전 양봉의 몸통을 거대 음봉이 아래로 덮어버리는 캔들 조합이 발생했습니다. 이 현상을 의미하는 용어는?', '[{"time":"Day 1","open":120,"high":125,"low":119,"close":124,"volume":93},{"time":"Day 2","open":124,"high":130,"low":123,"close":129,"volume":88},{"time":"Day 3","open":130,"high":131,"low":115,"close":116,"volume":103}]'::jsonb, '[]'::jsonb, ARRAY['하락 장악형 (Bearish Engulfing) - 고점 하락 전환 예고', '상승 장악형 (Bullish Engulfing) - 고점 돌파 랠리 예고', '하락 잉태형 (Harami) - 기존 하락세의 일시 둔화', '샛별형 (Morning Star) - 바닥권 상승 반전 예고']::text[], 0, '고점에서 직전 양봉을 음봉이 감싸 안은 형태는 ''하락 장악형(Bearish Engulfing)''입니다. 매수 세력을 매도 공급이 압도했다는 명백한 증거로, 주가 추세가 하락으로 반전할 리스크가 큽니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (6, '시장구조/SR', '03_market_structure.md', '주가가 장기 저항선인 150달러를 거래량 실린 강한 캔들로 돌파한 뒤, 다시 150달러 부근으로 내려와 버티고 있습니다. 가장 안전한 진입 방식은?', '[{"time":"Day 1","open":140,"high":148,"low":139,"close":145,"volume":86},{"time":"Day 2","open":145,"high":149,"low":143,"close":144,"volume":112},{"time":"Day 3","open":144,"high":156,"low":143,"close":154,"volume":105},{"time":"Day 4","open":154,"high":155,"low":149,"close":151,"volume":367},{"time":"Day 5","open":151,"high":153,"low":150,"close":152,"volume":418}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":150},{"x":4,"y":150}],"label":"돌파된 저항선 -> 지지선 전환선","color":"#3b82f6"}]'::jsonb, ARRAY['돌파 시점에 시장가로 즉시 진입하는 추격 매수', '돌파 후 저항선의 지지선 전환(Retest) 확인 시 진입', '이전 최저가 부근인 140달러 조정 시까지 대기 매수', '돌파 후 즉시 단기 조정을 예상한 역추세 숏 진입']::text[], 1, '저항선이 강하게 뚫리면 역할 전환(Role Reversal)에 의해 신규 지지선으로 바뀝니다. 돌파 시점에 뇌동매매하기보다는 돌파된 선 부근으로 주가가 눌려 지지(Retest)를 완성할 때 진입하는 것이 리스크 대비 기대 수익이 큽니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (7, '거래량/유동성', '05_volume_liquidity.md', '주가가 저항선 위로 거래량 없이 장대양봉을 뿜어 올렸으나, 다음 날 곧바로 장대음봉으로 밀어붙이며 저항선 아래로 내려왔습니다. 이 현상의 명칭은?', '[{"time":"Day 1","open":98,"high":101,"low":97,"close":100,"volume":118},{"time":"Day 2","open":100,"high":102,"low":99,"close":101,"volume":88},{"time":"Day 3","open":101,"high":110,"low":100,"close":108,"volume":29},{"time":"Day 4","open":108,"high":109,"low":95,"close":96,"volume":22}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":102},{"x":3,"y":102}],"label":"저항선","color":"#ef4444"}]'::jsonb, ARRAY['진짜 상승 돌파 (True Breakout)', '불 트랩 (Bull Trap) - 매수자 청산 유도 가짜 돌파', '베어 트랩 (Bear Trap) - 매도자 청산 유도 가짜 하방', '골든 크로스 (Golden Cross) - 이평선 돌파']::text[], 1, '저항선을 일시적으로 뚫었다가 대량 매도세와 함께 직후 캔들에서 하방으로 원상복귀하는 현상을 ''불 트랩(Bull Trap/가짜 돌파)''이라고 합니다. 돌파 후 리테스트를 기다리지 않고 급히 추격 매수했던 투자자들이 고점에 물리는 대표적 함정입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (8, '시장구조/SR', '01_chart_market_basics.md', '아래 차트에서 3번 연속 강하게 반등하며 가격 하락을 저지해 준 주요 가격대는 무엇을 의미하나요?', '[{"time":"Day 1","open":100,"high":102,"low":90,"close":91,"volume":102},{"time":"Day 2","open":91,"high":98,"low":90,"close":97,"volume":99},{"time":"Day 3","open":97,"high":105,"low":96,"close":104,"volume":106},{"time":"Day 4","open":104,"high":106,"low":91,"close":92,"volume":122},{"time":"Day 5","open":92,"high":100,"low":90,"close":99,"volume":107}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":90},{"x":4,"y":90}],"label":"90달러선","color":"#10b981"}]'::jsonb, ARRAY['강력한 저항선 (Resistance Line) - 매도 매물대', '강력한 지지선 (Support Line) - 매수 매물대', '골든크로스 수렴선 - 이평선 밀집대', '이격도 붕괴선 - 가격 과열 분기점']::text[], 1, '특정 가격(90달러)에 접근할 때마다 대기 중이던 저가 매수세가 유입되어 주가의 추가 하락을 방어해 준 이 라인은 ''강력한 지지선(Support Line)''입니다. 이탈하기 전까지는 손절 라인을 바로 밑에 두고 진입하기에 가장 손익비 좋은 구간입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (9, '거래량/유동성', '05_volume_liquidity.md', '지지선 아래로 주가가 이탈하여 공매도가 폭증했으나, 이내 거래량이 급증하며 양봉으로 지지선을 회복한 뒤 반등을 시작했습니다. 이 현상의 명칭은?', '[{"time":"Day 1","open":120,"high":122,"low":118,"close":119,"volume":93},{"time":"Day 2","open":119,"high":120,"low":110,"close":111,"volume":108},{"time":"Day 3","open":111,"high":123,"low":110,"close":122,"volume":91}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":115},{"x":2,"y":115}],"label":"지지선","color":"#10b981"}]'::jsonb, ARRAY['불 트랩 (Bull Trap) - 가짜 상방 돌파', '베어 트랩 (Bear Trap) - 가짜 하방 이탈', '리테스트 실패 - 지지선 붕괴', '추세 추종 돌파 - 하방 랠리 가속']::text[], 1, '지지선을 아래로 뚫고 내려가 하락세가 지속될 것처럼 유도한 뒤, 매물을 털어내고 강력하게 다시 반등해 올리는 현상을 ''베어 트랩(Bear Trap)''이라고 합니다. 하락 돌파로 생각하고 공매도를 치거나 손절했던 사람들의 손실을 강제하며 가격이 급등하게 만듭니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (10, '시장구조/SR', '04_patterns_breakout.md', '저항선을 뚫어내기 직전 돌파 전조 현상 중 하나인 ''지지점 상승''의 특징을 골라보세요.', '[{"time":"Day 1","open":100,"high":105,"low":90,"close":102,"volume":85},{"time":"Day 2","open":102,"high":105,"low":93,"close":103,"volume":90},{"time":"Day 3","open":103,"high":105,"low":96,"close":104,"volume":114}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":105},{"x":2,"y":105}],"label":"저항선 (105)","color":"#ef4444"}]'::jsonb, ARRAY['저항선 부근에서 고점들이 점점 급락하며 붕괴하는 현상', '저항선 부근에서 저점들을 높여가며 밀어 올리는 수렴 현상', '거래량이 완전히 소멸하여 긴 횡보 상태를 보이는 현상', '지속적인 매도세로 인해 갑작스럽게 급락하는 현상']::text[], 1, '저항을 뚫지 못하고 밀려 내려올 때, 이전 저점보다 높은 지점에서 저점을 계속 잡아 올려주는 것은 매도 압력보다 매수 압력이 점점 올라오고 있음을 의미합니다. 수렴 끝에 돌파가 나타날 신뢰도가 매우 높습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (11, '추세/레짐', '03_market_structure.md', '저점들을 연결한 우상향 상승 추세선 아래로 캔들의 종가(마감가격)가 이탈했습니다. 기술적 분석 관점의 올바른 해석은 무엇입니까?', '[{"time":"W-5","open":100,"high":105,"low":100,"close":103,"volume":117},{"time":"W-4","open":103,"high":110,"low":102,"close":108,"volume":98},{"time":"W-3","open":108,"high":109,"low":105,"close":106,"volume":105},{"time":"W-2","open":106,"high":115,"low":107,"close":113,"volume":128},{"time":"Today","open":113,"high":114,"low":103,"close":104,"volume":101}]'::jsonb, '[{"type":"line","points":[{"x":0,"y":100},{"x":2,"y":105},{"x":4,"y":110}],"label":"상승 추세선","color":"#10b981"}]'::jsonb, ARRAY['추세선 이탈은 영향이 없으므로 비중 유지', '상승 추세 붕괴로 하락 반전 대비 비중 축소', '일시적인 속임수이므로 추가 불타기 진입', '채널 상단 도달에 따른 즉각적인 매수 대응']::text[], 1, '신뢰받던 우상향 상승 추세선 하방으로 캔들의 종가가 이탈 마감하는 것은 매수 중심의 시장 주도권이 붕괴했음을 뜻합니다. 지지를 잃은 하락 가속화 리스크에 대비해야 합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (12, '추세/레짐', '07_multitimeframe_regime.md', '아래 차트에서 고점들과 저점들이 일정한 평행 통로를 그리며 하락하고 있습니다. 채널 하단에 도달했을 때 단기 반등을 목표로 하는 매매의 명칭과 관점은?', '[{"time":"Day 1","open":150,"high":152,"low":135,"close":140,"volume":94},{"time":"Day 2","open":140,"high":147,"low":139,"close":145,"volume":101},{"time":"Day 3","open":145,"high":146,"low":128,"close":130,"volume":103},{"time":"Day 4","open":130,"high":138,"low":129,"close":136,"volume":131},{"time":"Day 5","open":136,"high":137,"low":118,"close":120,"volume":107}]'::jsonb, '[{"type":"channel","points":[{"x":0,"y":150},{"x":4,"y":135},{"x":0,"y":135},{"x":4,"y":120}],"label":"하향 평행 채널","color":"#f59e0b"}]'::jsonb, ARRAY['추세 추종 매매 - 대세 상승이므로 장기 보유', '채널 하단 반등 매매 - 단기 역추세 매수 대응', '양방향 물타기 매매 - 평단가를 낮춰 탈출 대기', '돌파 매매 - 채널 하방 붕괴 확정 시 매수 대응']::text[], 1, '가격이 평행한 하락 터널 내에서 움직이는 ''하향 평행 채널(Descending Channel)''입니다. 채널 하단 라인 터치 시에는 기술적 단기 반등이 자주 출현하므로, 손절선을 짧게 잡고 반등 타점을 노리는 역추세(Counter-trend) 트레이딩이 가능합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (13, '추세/레짐', '03_market_structure.md', '우상향 상승 평행 채널의 상단 저항선 부근까지 주가가 도달했습니다. 합리적인 추세 채널 트레이더의 대응은?', '[{"time":"Day 1","open":100,"high":102,"low":99,"close":101,"volume":91},{"time":"Day 2","open":101,"high":108,"low":101,"close":107,"volume":104},{"time":"Day 3","open":107,"high":109,"low":104,"close":105,"volume":126},{"time":"Day 4","open":105,"high":115,"low":105,"close":114,"volume":94},{"time":"Day 5","open":114,"high":116,"low":112,"close":113,"volume":114}]'::jsonb, '[{"type":"channel","points":[{"x":0,"y":102},{"x":4,"y":115},{"x":0,"y":99},{"x":4,"y":112}],"label":"상승 평행 채널","color":"#10b981"}]'::jsonb, ARRAY['채널 상방 돌파를 예상한 고배율 레버리지 매수', '채널 상단 저항에 따른 분할 익절 및 대기', '채널 중간 조정 시 지정을 통한 시장가 추격', '채널 붕괴 신호에 따른 전량 기계적 손절']::text[], 1, '상승 채널이라고 해도 상단 저항선에 닿으면 다시 채널 하단이나 중심선까지 조정을 받을 가능성이 매우 큽니다. 따라서 고점 영역에서의 추격매수를 금지하고, 기존 포지션을 분할 익절하는 기회로 삼아야 합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (14, '추세/레짐', '01_chart_market_basics.md', '고점들을 잇는 우하향 하락 추세선을 주가가 대량의 거래량을 동반하며 장대양봉 종가로 상향 돌파(Breakout)했습니다. 의미하는 시그널은?', '[{"time":"Day 1","open":130,"high":132,"low":125,"close":127,"volume":95},{"time":"Day 2","open":127,"high":128,"low":120,"close":122,"volume":112},{"time":"Day 3","open":122,"high":123,"low":115,"close":117,"volume":99},{"time":"Day 4","open":117,"high":128,"low":116,"close":127,"volume":102}]'::jsonb, '[{"type":"line","points":[{"x":0,"y":131},{"x":2,"y":122},{"x":3,"y":118}],"label":"하락 추세선","color":"#ef4444"}]'::jsonb, ARRAY['하락 추세 지속에 따른 숏 포지션 추가 매수', '하락 추세 돌파 및 상승 전환 가능성에 따른 매수', '속임수 돌파를 예상한 즉시 반대 숏 포지션 진입', '추세와 무관하게 횡보 흐름으로 판단해 관망']::text[], 1, '중요한 하락 추세선을 주가 몸통이 확실하게 뚫고 마감하는 것은 기존 하락 관성의 지배력이 종료되고 상승 추세로 돌아설 수 있는 가장 대표적인 추세 전환(Reversal) 확인 시그널입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (15, '추세/레짐', '03_market_structure.md', '추세선 작도 시 신뢰도를 판단하는 가장 중요한 규칙은 무엇인가요?', '[{"time":"Day 1","open":100,"high":101,"low":100,"close":101,"volume":116},{"time":"Day 2","open":101,"high":105,"low":102,"close":104,"volume":95}]'::jsonb, '[]'::jsonb, ARRAY['차트상 선이 정배열로 정돈되어 그려질 때', '최소 3개 이상의 뚜렷한 저점/고점 터치 확인 시', '가파른 각도로 90도에 가깝게 작도될 때', '보조지표와 결합하여 수평으로 그려질 때']::text[], 1, '두 점만으로도 선을 그릴 수 있지만, 3번째 터치(3rd Touch)에서 정확한 지지나 저항을 보이고 반등해 주는 순간부터 시장 참여자들이 공식 인지하는 신뢰도 높은 추세선이 됩니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (16, '패턴/돌파', '04_patterns_breakout.md', '머리와 양쪽 어깨 형태를 그리며 넥라인 지지선(96달러)을 위태롭게 지탱하다가 하방으로 강한 캔들이 이탈했습니다. 숏(매도) 포지션 진입 시점은?', '[{"time":"Day 1","open":100,"high":115,"low":98,"close":110,"volume":109},{"time":"Day 2","open":110,"high":130,"low":95,"close":105,"volume":89},{"time":"Day 3","open":105,"high":114,"low":96,"close":110,"volume":121},{"time":"Day 4","open":110,"high":111,"low":93,"close":94,"volume":105}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":96},{"x":3,"y":96}],"label":"넥라인 지지선","color":"#ef4444"}]'::jsonb, ARRAY['머리 꼭대기(130달러) 부근에서 예측 숏 진입', '오른쪽 어깨가 올라가고 있을 때 돌파 전 선진입', '저점들을 연결한 넥라인의 하방 돌파 완료 시', '패턴 완성과 무관하게 오른쪽 어깨 끝에서 대기']::text[], 2, '헤드앤숄더(Head & Shoulders) 패턴은 오른쪽 어깨를 그린 후, 저점 지지선인 ''넥라인(Neckline)''을 거래량을 실어 하방 돌파해야 최종 완성이 선언됩니다. 그전에 진입하면 넥라인 반등 시 극심한 손실을 입습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (17, '패턴/돌파', '04_patterns_breakout.md', '하락 추세 끝에서 주가가 비슷한 깊이의 바닥을 두 번(이중바닥) 형성한 뒤, 중간 고점 저항선(넥라인)을 돌파했습니다. 향후 예상 방향성과 매수 타점은?', '[{"time":"Day 1","open":100,"high":100,"low":80,"close":85,"volume":107},{"time":"Day 2","open":85,"high":95,"low":84,"close":94,"volume":93},{"time":"Day 3","open":94,"high":95,"low":79,"close":82,"volume":98},{"time":"Day 4","open":82,"high":99,"low":81,"close":98,"volume":92}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":95},{"x":3,"y":95}],"label":"넥라인 (95)","color":"#3b82f6"}]'::jsonb, ARRAY['추가 폭락 가능성에 따른 전량 손절 대응', 'W 패턴 이중 바닥 완성 및 넥라인 돌파 시 매수', '박스권 횡보 판단에 따른 무대응 및 관망', '이중 바닥의 하방 이탈을 예상한 숏 포지션 진입']::text[], 1, 'W자 모양의 ''이중 바닥형(Double Bottom)'' 패턴입니다. 주가가 하락을 멈추고 바닥을 두 차례 단단히 지지해 준 뒤 중간 봉우리(넥라인 95달러)를 돌파해 마감하면 추세가 상승으로 강하게 전환될 가능성이 매우 높습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (18, '패턴/돌파', '04_patterns_breakout.md', '급격한 기둥식 주가 폭등(깃대) 후, 완만한 하향 평행 채널(깃발) 모양으로 횡보/수렴하다가 채널 상단을 강하게 돌파했습니다. 이 패턴과 예상 목표가는?', '[{"time":"Day 1","open":50,"high":80,"low":49,"close":78,"volume":101},{"time":"Day 2","open":78,"high":79,"low":72,"close":74,"volume":119},{"time":"Day 3","open":74,"high":76,"low":70,"close":71,"volume":106},{"time":"Day 4","open":71,"high":85,"low":70,"close":83,"volume":105}]'::jsonb, '[]'::jsonb, ARRAY['이중 천정형 패턴 - 고점 도달 시 숏 진입', '불 플래그 패턴 - 깃발 돌파 시 추가 상승 기대', '헤드앤숄더 패턴 - 넥라인 하방 돌파 타겟', '대칭 삼각수렴 패턴 - 변동성 축소 후 돌파 대기']::text[], 1, '대표적 강세 지속 패턴인 ''불 플래그(Bull Flag)''입니다. 급격한 상승(깃대) 뒤 숨 고르기 채널(깃발)을 상방 돌파하면, 이전 상승 파동의 크기(깃대 높이)만큼 추가로 수직 랠리를 시작하는 관성이 있습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (19, '패턴/돌파', '04_patterns_breakout.md', '상승 추세의 천정권에서 주가가 동일한 가격 저항을 두 번 확인하며 M자 모양을 만든 뒤, 두 고점 사이의 저점 지지선인 넥라인(120달러)을 이탈했습니다. 올바른 해석은?', '[{"time":"Day 1","open":100,"high":140,"low":99,"close":135,"volume":100},{"time":"Day 2","open":135,"high":136,"low":120,"close":122,"volume":97},{"time":"Day 3","open":122,"high":140,"low":121,"close":138,"volume":115},{"time":"Day 4","open":138,"high":139,"low":115,"close":116,"volume":117}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":120},{"x":3,"y":120}],"label":"넥라인 (120)","color":"#ef4444"}]'::jsonb, ARRAY['상승 추세의 지속 연장에 따른 추가 매수', '이중 천정형(M 패턴) 완성에 따른 하락 반전 대비', '단기 조정에 따른 일시적 횡보 박스권 진입', '방향성 없는 일상적인 잔파동으로 판단해 홀딩']::text[], 1, '고점에서 지지받지 못하고 형성된 M자형 ''이중 천정형(Double Top)'' 패턴입니다. 두 차례 강력한 저항벽(140달러)을 넘지 못하고 넥라인(120달러)마저 붕괴했으므로 하방 추세가 가속화된다는 신호입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (20, '패턴/돌파', '04_patterns_breakout.md', '고점 저항선은 수평(평평함)을 유지하고 있으나, 저점 지지선은 점점 우상향하며 좁게 수렴하는 차트 형태의 명칭과 일반적인 돌파 방향은?', '[{"time":"Day 1","open":80,"high":100,"low":80,"close":95,"volume":116},{"time":"Day 2","open":95,"high":100,"low":86,"close":98,"volume":112},{"time":"Day 3","open":98,"high":100,"low":92,"close":99,"volume":95}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":100},{"x":2,"y":100}],"label":"수평 저항선","color":"#ef4444"},{"type":"line","points":[{"x":0,"y":80},{"x":1,"y":86},{"x":2,"y":92}],"label":"상승 지지선","color":"#10b981"}]'::jsonb, ARRAY['디센딩 트라이앵글 - 일반적으로 하방 돌파 기대', '어센딩 트라이앵글 - 매수 압력 우위로 상방 돌파 기대', '헤드앤숄더 패턴 - 넥라인 하방 돌파 기대', '상향 평행 채널 - 상하단 터치식 채널 매매 기대']::text[], 1, '고점 저항은 평평하고 저점은 계속 높아지는 삼각수렴을 ''어센딩 트라이앵글(Ascending Triangle)''이라고 합니다. 위로 갈수록 저점이 계속 올라가는 현상은 매수세가 가격을 위로 계속 압박하고 있음을 증명하며, 대개 저항선(100달러)을 상향 뚫고 오르는 확률이 높습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (21, '지표/컨플루언스', '06_technical_indicators.md', '주가는 매일 하락하여 신저가를 갱신하고 있으나, RSI 보조지표의 저점은 점점 높아지는 현상을 발견했습니다. 올바른 용어와 매매 대응법은?', '[{"time":"D-4","open":110,"high":112,"low":98,"close":100,"volume":108},{"time":"D-3","open":100,"high":104,"low":96,"close":98,"volume":112},{"time":"D-2","open":98,"high":101,"low":92,"close":94,"volume":127},{"time":"D-1","open":94,"high":97,"low":93,"close":96,"volume":127},{"time":"Today","open":96,"high":99,"low":95,"close":98,"volume":113}]'::jsonb, '[]'::jsonb, ARRAY['하락 다이버전스 - 가격 상승 둔화에 따른 공매도', '상승 다이버전스 - 하락 둔화 및 반등 신호로 매수', '데드 크로스 - 이평선 하방 교차에 따른 관망', '과매수 이탈 시그널 - 단기 반등에 따른 매수']::text[], 1, '주가의 가격 저점은 낮아지나 보조지표(RSI)의 운동 저점이 높아지는 현상을 ''상승 다이버전스(Bullish Divergence)''라고 합니다. 이는 하방 에너지의 실질적 소멸과 상승 압력의 내부 응축을 의미하는 기술적 분석에서 가장 신뢰도 높은 추세 전환 시그널입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (22, '지표/컨플루언스', '06_technical_indicators.md', '주가는 급격히 치솟으며 최고가 갱신 랠리를 이어가고 있으나, RSI 지표의 고점은 계속 낮아지고 있습니다. 이 현상을 지칭하는 명칭과 대처법은?', '[{"time":"Day 1","open":100,"high":120,"low":99,"close":118,"volume":103},{"time":"Day 2","open":118,"high":122,"low":115,"close":120,"volume":111},{"time":"Day 3","open":120,"high":135,"low":119,"close":133,"volume":95}]'::jsonb, '[]'::jsonb, ARRAY['하락 다이버전스 - 매수 둔화 및 하락 우려로 익절', '상승 다이버전스 - 추가 급등 기대로 신규 매수', '골든 크로스 - 추세 강화에 따른 홀딩', '볼린저 밴드 스퀴즈 - 변동성 수축 후 돌파']::text[], 0, '주가는 계속 고점을 높이고 있으나 보조지표의 고점은 꺾여 낮아지는 현상을 ''하락 다이버전스(Bearish Divergence)''라고 합니다. 이는 매수세의 힘이 표면적인 가격 상승에 비해 실질적으로 빠르게 축소되고 있음을 경고하며, 조만간 큰 급락이 발생할 확률이 높습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (23, '지표/컨플루언스', '06_technical_indicators.md', '이동평균선(EMA) 20일선(단기)이 50일선(중기)을 아래에서 위로 강하게 뚫고 솟구쳐 올랐습니다. 이 교차 현상의 정식 명칭은?', '[{"time":"Day 1","open":100,"high":102,"low":98,"close":99,"volume":96},{"time":"Day 2","open":99,"high":104,"low":99,"close":103,"volume":93},{"time":"Day 3","open":103,"high":110,"low":103,"close":109,"volume":113}]'::jsonb, '[]'::jsonb, ARRAY['데드 크로스 - 단기 이평의 하방 교차로 매도 신호', '골든 크로스 - 단기 이평의 상방 교차로 매수 신호', '볼린저 스퀴즈 - 변동성 수축 및 돌파 신호', '다이버전스 수렴 - 지표와 가격의 동반 횡보']::text[], 1, '단기 이평선이 장기 이평선을 위로 치고 올라가는 현상을 ''골든 크로스(Golden Cross)''라고 합니다. 이는 최근 매수 평단가가 장기 평균가보다 확연히 높아졌음을 시사하며, 상승 추세가 본 궤도에 올랐음을 입증해 줍니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (24, '지표/컨플루언스', '07_multitimeframe_regime.md', '매우 강력한 원웨이 폭락장 속에서 RSI 지표가 20(과매도 영역) 이하로 깊이 내려왔습니다. 이를 보고 ''과매도 반등''을 노리며 기계적 시장가 풀매수를 때렸을 때 나타나는 가장 빈번한 오류는?', '[{"time":"Day 1","open":100,"high":101,"low":88,"close":89,"volume":102},{"time":"Day 2","open":89,"high":90,"low":75,"close":76,"volume":16},{"time":"Day 3","open":76,"high":77,"low":62,"close":63,"volume":33}]'::jsonb, '[]'::jsonb, ARRAY['하락 추세 즉시 종료 및 V자 상승 반등 성공', '강력한 하락장에서의 지표 과매도 고착화 리스크', '거래량 급감으로 인한 호가 정지 및 상장 폐지', '주가의 즉각적인 박스권 횡보 및 변동성 축소']::text[], 1, 'RSI 30 이하 과매도 영역은 반등 신호이기도 하지만, 추세가 지나치게 강력한 하락장일 때는 지표만 과매도 구역에 쳐박힌 채 가격은 계속 급락하는 ''과매도 고착화(Oversold Embedded)'' 상태가 이어집니다. 다이버전스나 캔들 반전형 확인 없이 수치만 보고 들어가는 매수는 깡통으로 가는 지름길입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (25, '지표/컨플루언스', '06_technical_indicators.md', '주가의 변동성이 극도로 축소되며 볼린저 밴드의 폭이 매우 좁아지는 ''스퀴즈(Squeeze)'' 현상이 나타났습니다. 이후 기대되는 시장 변동성의 원리는 무엇인가요?', '[{"time":"Day 1","open":100,"high":101,"low":99,"close":100,"volume":116},{"time":"Day 2","open":100,"high":100,"low":99,"close":99,"volume":104},{"time":"Day 3","open":99,"high":100,"low":99,"close":100,"volume":99}]'::jsonb, '[]'::jsonb, ARRAY['변동성 사멸로 인한 장기 횡보 및 거래 정지', '밴드 스퀴즈 후 변동성 팽창에 따른 추세 분출', '주가의 하방 붕괴로 인한 강한 하락 파동 시작', '이평선들의 수평 정렬에 따른 완전한 추세 고정']::text[], 1, '볼린저 밴드의 수축(Squeeze)은 시장의 숨 고르기 및 힘 모으기를 뜻합니다. 에너지가 최대한 압축된 후에는 밴드 상단 혹은 하단선을 이탈하며 매우 거대한 변동성 팽창(Expansion) 추세가 시작되므로, 방향성을 유심히 지켜봐야 합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (26, '리스크/심리', '09_risk_position_management.md', '총 투자 원금은 1,000만 원이며, 1회 거래 시 최대 손실 허용액을 원금의 2%(20만 원)로 제한하는 ''2% 룰''을 지키려 합니다. 진입하려는 종목의 손절 라인 폭이 -5%일 때, 최대 매수(진입) 가능 금액은 얼마인가요?', '[{"time":"Day 1","open":10000,"high":10500,"low":9800,"close":10200,"volume":82},{"time":"Day 2","open":10200,"high":10300,"low":10000,"close":10000,"volume":121}]'::jsonb, '[]'::jsonb, ARRAY['1,000만 원 (원금 전액 진입)', '200만 원 (원금의 20% 진입)', '400만 원 (원금의 40% 진입)', '500만 원 (원금의 50% 진입)']::text[], 2, '2% 룰에 기초한 포지션 사이징 공식은 `진입금액 = (총원금 * 리스크비율) / 손절비율` 입니다. 따라서 `20만 원 / 0.05 = 400만 원`이 됩니다. 400만 원어치 주식을 샀을 때 가격이 -5% 떨어져 강제 손절을 맞아도 내 계좌 총액에서 손실을 보는 돈은 정확히 2%인 20만 원으로 통제됩니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (27, '리스크/심리', '09_risk_position_management.md', '어느 주식에 10,000원에 매수 진입합니다. 손절 라인은 9,500원(-5%)에 배치하고, 목표가는 11,500원(+15%)에 설정했습니다. 이 트레이딩 시나리오의 손익비(Risk-to-Reward Ratio)는 얼마입니까?', '[{"time":"Today","open":10000,"high":10000,"low":10000,"close":10000}]'::jsonb, '[]'::jsonb, ARRAY['1 : 1 (동일한 기대 수익과 리스크)', '1 : 2 (기대 수익이 리스크의 2배)', '1 : 3 (기대 수익이 리스크의 3배)', '2 : 1 (기대 수익이 리스크의 0.5배)']::text[], 2, '손절 폭(500원) 대비 익절 폭(1,500원)의 비례를 의미하므로 `1,500 / 500 = 3`, 즉 손익비는 1:3이 됩니다. 이처럼 잃는 돈의 최소 2~3배를 벌 수 있는 손익비 높은 구간만 반복적으로 거래해야 장기적으로 계좌가 생존합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (28, '리스크/심리', '09_risk_position_management.md', '손익비를 엄격히 통제하여 항상 기대 손실의 2배를 버는 매매(손익비 1:2)만 고집합니다. 이 경우 내 계좌 잔고가 손실 없이 제자리걸음(본전)을 유지하기 위해 필요한 수학적인 최소 승률(Win Rate)은 얼마인가요?', '[{"time":"Today","open":100,"high":100,"low":100,"close":100}]'::jsonb, '[]'::jsonb, ARRAY['50.0% (최소 절반 이상 성공)', '33.3% (3번 중 1번 성공으로 본전)', '25.0% (4번 중 1번 성공으로 본전)', '66.6% (3번 중 2번 성공으로 본전)']::text[], 1, '손익비가 1:2일 경우, 1번 이기면 +2를 벌고 2번 지면 -2를 잃으므로 3번 매매 중 1번만 이겨도 누적 수익은 0이 됩니다. 즉 손익비를 1:2 이상으로 유지하면 수학적으로 승률이 겨우 33.3%만 나와도 절대 파산하지 않고 계좌가 우상향할 발판이 마련됩니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (29, '셋업/실행', '08_setup_entry_exit.md', '10,000원에 산 주식이 15,000원까지 올랐습니다. 이익을 보존하면서 상승세를 끝까지 타기 위해, 최고점 대비 10% 하방 이탈 시 즉시 자동 익절되는 ''추적 손절매(Trailing Stop)''를 적용했습니다. 최고점 15,000원 달성 후 주가가 조정받을 때 실제로 청산(익절)되는 가격은 얼마인가요?', '[{"time":"Day 1","open":10000,"high":12000,"low":9900,"close":11900,"volume":108},{"time":"Day 2","open":11900,"high":15000,"low":11800,"close":14800,"volume":112}]'::jsonb, '[]'::jsonb, ARRAY['10,000원 (본전 수준 청산)', '13,500원 (최고점 대비 10% 하방 청산)', '14,000원 (최고점 대비 6.6% 하방 청산)', '12,000원 (최고점 대비 20% 하방 청산)']::text[], 1, '추적 손절매(Trailing Stop)는 가격 상승에 따라 청산 가격을 자동으로 올려주는 주문입니다. 최고점 15,000원을 기록했으므로 청산 트리거 라인은 최고점에서 10% 차감된 `15,000 * 0.9 = 13,500원`으로 확정 셋업되며, 주가가 13,500원을 건드리는 순간 자동 이익실현됩니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (30, '리스크/심리', '09_risk_position_management.md', '레버리지 10배를 적용하여 비트코인 롱(매수) 포지션을 구축했습니다. 만약 비트코인 가격이 매수가 대비 몇 % 역방향으로 등락하면 내 투자 원금이 100% 강제 청산(증거금 완전 소멸)당할까요?', '[{"time":"Today","open":50000,"high":50100,"low":49900,"close":50000}]'::jsonb, '[]'::jsonb, ARRAY['5.0% 하락 시', '10.0% 하락 시', '20.0% 하락 시', '100.0% 하락 시']::text[], 1, '레버리지 비율과 청산 거리 비율은 역수 관계입니다. `100% / 레버리지 배수` 공식에 따라, 10배 레버리지는 주가가 내 베팅의 반대 방향으로 단 10%만 움직여도 투자 원금이 전부 증발하고 포지션이 강제 종료(Liquidation)됩니다. 고배율 레버리지가 파산의 지름길인 이유입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (31, '캔들/가격행동', '02_candlestick_price_action.md', '상승 추세 고점 영역(150달러선)에서 몸통이 매우 작고 아래꼬리가 긴 행잉맨(Hanging Man) 캔들이 출현한 이후, 다음 날 시가가 전일 종가보다 큰 갭을 그리며 낮게 하락 출발(145달러)했습니다. 포지션을 보유한 스윙 트레이더로서 가장 적절한 위기 대응 행동은 무엇입니까?', '[{"time":"Day 1","open":120,"high":125,"low":119,"close":124,"volume":84},{"time":"Day 2","open":124,"high":135,"low":123,"close":134,"volume":115},{"time":"Day 3","open":134,"high":148,"low":133,"close":146,"volume":97},{"time":"Day 4","open":146,"high":151,"low":140,"close":147,"volume":128},{"time":"Day 5","open":141,"high":143,"low":135,"close":136,"volume":130}]'::jsonb, '[]'::jsonb, ARRAY['상승 랠리를 기대로 보유 비중 확대 및 추격 매수', '일시적 속임수(휩소) 판단으로 추가 레버리지 매수', '행잉맨 출현 후 갭하락에 따른 전량 또는 일부 정리', '조치 없이 전고점 돌파 시까지 무기한 관망 및 홀딩']::text[], 2, '고가권에서 나타난 행잉맨(Hanging Man)은 잠재적 하락 전환 신호이며, 특히 다음날 갭하락 음봉으로 직전 행잉맨의 저가를 깨고 내려가는 움직임은 강력한 하락 컨펌 시그널입니다. 따라서 이 시점에서는 즉시 비중을 전량 정리하거나 최소 절반 이상 매도하여 리스크를 통제하는 것이 정석입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (32, '캔들/가격행동', '01_chart_market_basics.md', '지속적인 하락 추세 도중 바닥권(80달러선)에서 시가와 종가가 일치하고 긴 아래꼬리를 단 십자 형태의 도지(Doji) 캔들이 생성되었습니다. 다음 날 대량의 거래량과 함께 장대양봉이 솟구치며 87달러로 마감하는 샛별형(Morning Star) 조합이 확정되었습니다. 이때 가장 합리적인 매수 진입 지점과 손절가 기준은 무엇입니까?', '[{"time":"Day 1","open":100,"high":101,"low":93,"close":94,"volume":97},{"time":"Day 2","open":94,"high":95,"low":88,"close":89,"volume":94},{"time":"Day 3","open":89,"high":90,"low":80,"close":81,"volume":94},{"time":"Day 4","open":80,"high":82,"low":75,"close":80,"volume":98},{"time":"Day 5","open":80,"high":88,"low":79,"close":87,"volume":132}]'::jsonb, '[]'::jsonb, ARRAY['손절 없이 100% 비중으로 시장가 매수', '샛별형 완성에 따라 분할 매수 후 최저점 손절 셋업', '바닥 도달 기대로 주문 없이 무작정 대기', '상승 꼭대기에서 숏 진입 후 손절 없이 방치']::text[], 1, '하락 추세 끝에 도지와 장대양봉이 결합된 샛별형(Morning Star)은 매우 신뢰도 높은 바닥 상승 전환 신호입니다. 이 패턴을 보고 진입할 때는 반등 상승세에 분할 매수로 동참하되, 바닥을 잡아준 도지 캔들의 최저점(75달러) 아래를 최종 손절 라인으로 잡는 것이 수학적으로 가장 리스크 대비 보상 비율(손익비)이 훌륭한 전략입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (33, '거래량/유동성', '02_candlestick_price_action.md', '주가가 강력한 횡보 박스권 고점(200달러 저항선)에 세 번째 터치하는 와중에, 윗꼬리가 길고 몸통이 매우 얇은 유성형(Shooting Star) 캔들이 이틀 연속 발생했습니다. 거래량 역시 저항선 부근에서 매수세가 더 올라가지 못하고 매도 압력이 실려 나타났습니다. 롱(매수) 포지션을 들고 있는 당신의 합리적인 의사결정은?', '[{"time":"Day 1","open":175,"high":185,"low":174,"close":182,"volume":116},{"time":"Day 2","open":182,"high":195,"low":180,"close":193,"volume":85},{"time":"Day 3","open":193,"high":202,"low":190,"close":191,"volume":104},{"time":"Day 4","open":191,"high":201,"low":188,"close":189,"volume":111}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":200}],"label":"박스권 상단 저항선 (200)","color":"#ef4444"}]'::jsonb, ARRAY['신고가 갱신을 예상한 전재산 추가 불타기', '저항 돌파 실패 신호 확인 후 분할 익절 및 관망', '손익 평단가 부근이므로 추가 손절 없이 방치', '거래를 종료하고 다른 신규 급등주를 시장가 추격']::text[], 1, '박스권 상단 저항선(200달러)에 부딪히며 나타난 유성형(Shooting Star) 연속 출현은 저항 돌파 실패와 차익 실현 세력의 강력한 등장을 경고하는 캔들 신호입니다. 돌파를 확신하기보다는 리스크 관리 관점에서 물량을 축소(50% 분할 익절)하거나 전량 매도하여 이익을 확정 짓는 것이 현명합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (34, '캔들/가격행동', '02_candlestick_price_action.md', '극심한 하락 추세 중 100달러선 아래로 떨어지던 주가가 전일 장대음봉을 형성했습니다. 그러나 당일 시가는 갭하락하여 더 낮게 시작했으나, 장중에 강한 매수세가 들어오며 전일 음봉 몸통의 정확히 70% 라인(93달러선) 위로 덮어버리는 관통형(Piercing Line) 상승 캔들로 마감했습니다. 종가 매수(롱) 진입 시 원칙 대응은?', '[{"time":"Day 1","open":110,"high":111,"low":104,"close":105,"volume":92},{"time":"Day 2","open":105,"high":106,"low":97,"close":98,"volume":88},{"time":"Day 3","open":92,"high":101,"low":91,"close":100,"volume":94}]'::jsonb, '[]'::jsonb, ARRAY['상승 모멘텀 미달로 매수 보류 및 하방 숏 포지션 진입', '관통형 확인 후 분할 매수 및 당일 최저점 손절 설정', '손절 라인 설정 없이 100% 비중 시장가 매수 집행', '조정을 대기하며 예약 주문 없이 무작정 관망 유지']::text[], 1, '전일 음봉의 50% 이상을 당일 양봉 몸통으로 관통해 올린 ''관통형(Piercing Line)''은 하락 모멘텀이 쇠퇴하고 저가 매수세가 우위를 점하기 시작했음을 뜻하는 바닥 신호입니다. 이 패턴 확인 후 진입할 시에는 손절 한도를 당일 최저점(91달러) 밑에 가깝게 설정할 수 있어 매우 유리한 리스크 대비 기대수익 매매가 성립됩니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (35, '캔들/가격행동', '05_volume_liquidity.md', '강한 급등세를 지속하던 주가가 최고점에서 큰 거래량을 터뜨리며 장대양봉을 만들었습니다. 그러나 다음 날, 전일 양봉 몸통의 한가운데 범위 안에서 움직이며 시가와 종가가 모두 갇혀버리는 짧은 음봉인 ''하락 잉태형(Bearish Harami)'' 캔들이 형성되었습니다. 단기 스윙 트레이더로서 당신의 포지션 리스크 관리 행동은?', '[{"time":"Day 1","open":120,"high":128,"low":119,"close":127,"volume":107},{"time":"Day 2","open":127,"high":138,"low":126,"close":136,"volume":103},{"time":"Day 3","open":133,"high":134,"low":130,"close":131,"volume":97}]'::jsonb, '[]'::jsonb, ARRAY['상승 둔화 조짐에 따른 보유 물량 50% 분할 익절', '추세 일시 조정으로 간주하여 비중 확대 추가 매수', '추세 종결 판단에 따른 고배율 숏 포지션 즉시 진입', '이익 실현 없이 전량 장기 보유 전략 유지']::text[], 0, '하락 잉태형(Bearish Harami)은 이전의 강한 상승 추세 동력이 감속하기 시작했으며, 매도 압력이 힘을 기르고 있음을 암시하는 변곡 캔들입니다. 따라서 단기 스윙 트레이더는 물량의 일부(50%)를 분할 익절하여 리스크를 낮추고, 다음 캔들에서 이전 양봉 저점을 깨뜨리는 하락 하방 이탈이 추가되는지 지켜보는 것이 정석입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (36, '시장구조/SR', '03_market_structure.md', '오랫동안 지켜지던 핵심 지지선인 100달러 부근에서 매수 진입을 완료했습니다. 그러나 가격이 대량의 거래량을 동반하며 장대음봉으로 지지선을 하방으로 강하게 뚫어냈고, 종가가 지지선 대비 1.5% 아래인 98.5달러로 결정되었습니다. 이 상황에서 원칙을 지키는 올바른 위기 대응 행동은?', '[{"time":"Day 1","open":105,"high":108,"low":102,"close":103,"volume":111},{"time":"Day 2","open":103,"high":104,"low":99,"close":100,"volume":85},{"time":"Day 3","open":100,"high":101,"low":98,"close":98.5,"volume":109}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":100}],"label":"중요 지지선 (100)","color":"#10b981"}]'::jsonb, ARRAY['추가 물타기를 위해 자금을 동원하여 평단가 관리', '중요 지지선 붕괴(Breakdown) 확인 후 즉시 전량 손절', '지속 하락 시 추가 평단가 관리를 위해 매수 유보', '하방 이탈 시 즉시 반대 고배율 롱 포지션 진입']::text[], 1, '거래량이 동반된 장대음봉으로 주요 지지선 아래에서 종가가 결정되는 이탈 마감은 매수 지지 세력의 패배이자 추세 붕괴(Breakdown)의 신호입니다. 이 시점에서 물타기를 하거나 존버를 하면 파산적인 하락 조정을 겪을 수 있으므로 즉시 룰에 근거한 ''전량 손절''을 집행해야 계좌를 살릴 수 있습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (37, '시장구조/SR', '03_market_structure.md', '150달러의 중요 저항선이 강한 거래량을 실은 돌파봉으로 뚫렸습니다. 이후 주가가 숨 고르기 조정을 받으며 150달러 부근까지 되돌아왔고(리테스트 구간), 저항선 부근에서 거래량이 크게 감소하며 아래꼬리가 달린 도지 캔들로 안착하는 모습을 보입니다. 이때 가장 안전하고 합리적인 매매 조치는?', '[{"time":"Day 1","open":140,"high":146,"low":139,"close":144,"volume":114},{"time":"Day 2","open":144,"high":157,"low":143,"close":155,"volume":98},{"time":"Day 3","open":155,"high":156,"low":149,"close":150,"volume":94}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":150}],"label":"돌파된 저항선 -> 지지선 전환선 (150)","color":"#3b82f6"}]'::jsonb, ARRAY['가짜 돌파(휩소) 판단에 따른 고배율 숏 진입', '돌파 후 리테스트 성공 확인 시 지지선 눌림목 매수', '추격 매수 기회 상실로 판단하고 거래 포기', '160달러 추가 돌파를 타겟으로 시장가 추격 매수']::text[], 1, '강하게 돌파된 저항선은 룰 체인지에 의해 지지선으로 변합니다(역할 전환). 돌파 당시 추격 매수하기보다, 돌파된 선(150달러)으로 주가가 되돌아오는 리테스트(Retest) 시점에 저조한 거래량과 지지 캔들을 확인하고 손절선을 바로 밑에 설정하여 눌림목 진입하는 것이 리스크가 가장 적은 프로 트레이더의 정석입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (38, '시장구조/SR', '03_market_structure.md', '가격이 80달러 지지선 근처에서 반등을 시도하고 있으나, 반등의 폭이 직전 고점에 턱없이 못 미치며 저점 부근으로 다시 짓눌리고 있습니다. 즉, 고점들이 계속 낮아지는 하락 우위 삼각수렴(Descending)의 형태가 지지선 바로 위에서 감지됩니다. 이 시점에서 지지선 반등을 믿고 신규 매수(롱)를 진입하는 것은 원칙에 맞습니까?', '[{"time":"Day 1","open":95,"high":98,"low":80,"close":88,"volume":99},{"time":"Day 2","open":88,"high":91,"low":80,"close":84,"volume":118},{"time":"Day 3","open":84,"high":86,"low":80,"close":81,"volume":102}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":80}],"label":"지지선 (80)","color":"#10b981"}]'::jsonb, ARRAY['삼중 바닥 지지로 판단하고 매수 비중 대폭 확대', '디센딩 수렴 확인 후 하방 이탈 위험 대비 관망', '물타기 평단가 관리를 위해 매수 보증금 추가 투입', '추세와 무관하게 숏 포지션으로 전환 후 무기한 보유']::text[], 1, '지지선 부근에서 고점이 점점 낮아지는 ''디센딩'' 형태는 매수 지원 강도가 둔화되고 매도 출하 공급이 가격을 계속 하방으로 압박하고 있음을 증명합니다. 지지 성공보다 지선 하방 붕괴 후 급락할 확률이 높으므로, 지지선이라는 명목만으로 함부로 매수 진입하지 말고 돌파/이탈 컨펌을 기다려 관망하는 것이 현명합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (39, '거래량/유동성', '05_volume_liquidity.md', '주가가 120달러의 장기 저항벽을 거래량이 거의 실리지 않은 얇은 양봉으로 상방으로 살짝 뚫었으나, 바로 다음 날 직전 양봉 몸통을 통째로 덮어버리는 대량 거래량의 장대음봉이 출현하며 116달러로 곤두박질쳤습니다. 매수 포지션을 추격 진입했던 당신의 올바른 조치는?', '[{"time":"Day 1","open":112,"high":118,"low":111,"close":117,"volume":98},{"time":"Day 2","open":117,"high":122,"low":116,"close":121,"volume":353},{"time":"Day 3","open":121,"high":122,"low":115,"close":116,"volume":408}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":120}],"label":"장기 저항선 (120)","color":"#ef4444"}]'::jsonb, ARRAY['불 트랩(Bull Trap) 확인 후 추가 하락 방지 즉시 손절', '저항선 부근 매수세 복귀를 기대하며 전량 홀딩', '평단가 관리 차원에서 추가 물타기 매수 집행', '상황을 판단하기 위해 시장가로 추가 분할 진입']::text[], 0, '거래량 없는 돌파 직후에 거래량 실린 강한 음봉이 기존 돌파선(120달러) 아래로 재진입하여 마감하는 현상은 전형적인 불 트랩(Bull Trap/가짜 돌파) 함정입니다. 돌파 당시 샀던 매수자들의 패닉 셀이 출현하며 하락 가속화가 나오기 쉬우므로 즉시 손절하여 물량을 털어내야 생존할 수 있습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (40, '시장구조/SR', '10_psychology_routine_review.md', '주요 지지선(250달러선)이 아래로 무너질 때 제때 손절 처리를 하지 못해 주가가 220달러선까지 끌려 내려갔습니다. 다행히 단기 매도 진정세로 반등이 나와 주가가 다시 250달러 부근까지 상승하여 회복을 눈앞에 두고 있습니다. 이때 손실을 최소화하는 현명한 시나리오 대처법은?', '[{"time":"Day 1","open":260,"high":262,"low":248,"close":249,"volume":110},{"time":"Day 2","open":249,"high":250,"low":220,"close":222,"volume":109},{"time":"Day 3","open":222,"high":235,"low":221,"close":234,"volume":115},{"time":"Day 4","open":234,"high":251,"low":233,"close":249,"volume":108}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":250}],"label":"붕괴된 지지선 -> 저항선으로 변형 (250)","color":"#ef4444"}]'::jsonb, ARRAY['역할 전환(저항선) 도달에 따른 탈출 및 현금화', 'V자 반등 성공 확신에 따른 추가 매수 비중 확대', '원금 회복 및 추가 수익 시까지 영구 홀딩 관망', '하락 추세 지속에 따른 반대 숏 포지션 스위칭']::text[], 0, '하방으로 깨진 지지선은 반등할 때 가장 뚫기 힘든 ''강력한 저항선''으로 성격이 바뀝니다. 따라서 손절 기회를 놓치고 물려있던 트레이더는 반등하여 옛 지지선(250달러)에 도달했을 때를 ''최선의 리스크 탈출 기회(탈출구)''로 삼아 전량 매도하거나 비중을 극도로 덜어내야 다가올 2차 하락 파동의 파산을 막을 수 있습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (41, '추세/레짐', '03_market_structure.md', '주가가 매우 가파르게 올라가던 1차 단기 상승 추세선을 강한 음봉 종가로 뚫고 내려왔습니다. 다행히 각도가 완만하고 탄탄한 장기 핵심 상승 추세선은 저 밑에 지지 영역을 유지하고 있습니다. 스윙 트레이더로서 가장 정석적인 포지션 제어 방식은 무엇인가요?', '[{"time":"Day 1","open":100,"high":102,"low":100,"close":102,"volume":99},{"time":"Day 2","open":102,"high":110,"low":102,"close":109,"volume":111},{"time":"Day 3","open":109,"high":125,"low":109,"close":124,"volume":91},{"time":"Day 4","open":124,"high":125,"low":114,"close":115,"volume":107}]'::jsonb, '[{"type":"line","points":[{"x":0,"y":100},{"x":3,"y":123}],"label":"가파른 단기 추세선 (붕괴)","color":"#ef4444"},{"type":"line","points":[{"x":0,"y":100},{"x":3,"y":110}],"label":"완만한 장기 추세선 (지탱 중)","color":"#10b981"}]'::jsonb, ARRAY['추세 붕괴 판단에 따른 전량 손절 및 영구 이탈', '가속 추세 이탈에 따른 50% 분할 익절 및 분산', '단기 지지선 붕괴를 무시한 고배율 물타기 매수', '장기 추세선까지 조정을 대비한 신규 매수 대기']::text[], 1, '가파르게 우상향하던 가속 추세선(Accelerated Trendline)이 하방 돌파되는 것은 기존 폭등 랠리의 속도가 둔화되고 완만한 본래 장기 추세선(장기 매물대)을 향해 정상적인 가격 조정을 받기 시작했음을 뜻합니다. 따라서 물량의 50%가량을 털어 수익을 실현하고 남은 물량으로 장기 추세선의 3rd Touch 지지 성공 여부를 테스트하는 것이 리스크 관리의 기본입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (42, '거래량/유동성', '05_volume_liquidity.md', '고점과 저점이 연속으로 낮아지는 명확한 하락 평행 채널 내에서 하락 압력을 받아 숏(매도) 포지션을 잡고 수익 중이었습니다. 그런데 당일 캔들이 대량의 거래량과 함께 장대양봉을 그리며 채널 상단 저항선 위로 종가 안착(상방 돌파)했습니다. 숏 포지션을 쥔 당신의 결단은?', '[{"time":"Day 1","open":100,"high":102,"low":90,"close":92,"volume":104},{"time":"Day 2","open":92,"high":94,"low":82,"close":83,"volume":122},{"time":"Day 3","open":83,"high":85,"low":75,"close":76,"volume":99},{"time":"Day 4","open":76,"high":90,"low":75,"close":89,"volume":131}]'::jsonb, '[{"type":"channel","points":[{"x":0,"y":102},{"x":3,"y":86},{"x":0,"y":90},{"x":3,"y":76}],"label":"하락 평행 채널 상한/하한","color":"#f59e0b"}]'::jsonb, ARRAY['상단 돌파 확인 즉시 숏 전량 손절 및 대피', '채널 재진입 기대로 숏 포지션 추가 물타기', '손절 없이 유지하면서 포지션 본전 도달 대기', '포지션 유지 후 증거금을 출금하여 강제 횡보']::text[], 0, '하락 평행 채널의 상단 저항선 상향 돌파(Breakout)는 기존 하락 트렌드의 사멸과 매수세 지배령 복귀를 뜻합니다. 지표와 거래량이 동반된 돌파 확인 시에는 숏 포지션을 지체 없이 기계적으로 칼손절하여 자산을 보호하는 것이 원칙입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (43, '추세/레짐', '07_multitimeframe_regime.md', '우상향하는 상승 평행 채널 안에서 순항하던 주가가 중심선(Mid-line)을 뚫고 하방으로 이탈 마감했습니다. 이후 중심선 부근까지 반등을 시도했으나 재차 저항을 받고 아래꼬리가 꺾여 채널 하단선을 향해 하락 조정을 재개하려 합니다. 신규 매수(롱) 포지션 진입을 계획 중인 트레이더의 대응법은?', '[{"time":"Day 1","open":100,"high":108,"low":99,"close":106,"volume":112},{"time":"Day 2","open":106,"high":112,"low":102,"close":104,"volume":111},{"time":"Day 3","open":104,"high":106,"low":98,"close":100,"volume":109}]'::jsonb, '[{"type":"channel","points":[{"x":0,"y":110},{"x":2,"y":112},{"x":0,"y":98},{"x":2,"y":100}],"label":"상승 평행 채널","color":"#10b981"}]'::jsonb, ARRAY['채널 내 유지를 기대로 지정가 즉시 매수', '중심선 저항 확인 후 채널 하단 안착 대기', '하방 휩소 판단에 따른 레버리지 추가 매수', '추세와 무관한 숏 포지션 구축 후 관망']::text[], 1, '상승 평행 채널에서 미드라인(Mid-line)은 매우 중요한 심리적 지지와 저항선입니다. 미드라인이 저항선으로 뒤바뀌어 음봉으로 흘러내리는 경우 높은 확률로 채널 하단 경계선까지 가격이 조정을 받게 되므로, 중심선 저항 확인 시점에서는 섣부른 매수 진입을 피하고 채널 하단의 명확한 반등 타점을 유도해야 합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (44, '추세/레짐', '03_market_structure.md', '저점과 저점을 이은 장기 상승 추세선 상의 3번째 터치 포인트(지지선 부근)에 캔들이 매우 조심스럽게 안착하며 아래꼬리를 형성했습니다. 손익비(Risk-to-Reward) 관점에서 가장 이상적인 매수 타점 집행 및 손절 셋업 방법은 무엇입니까?', '[{"time":"Day 1","open":80,"high":90,"low":80,"close":88,"volume":99},{"time":"Day 2","open":88,"high":99,"low":88,"close":95,"volume":100},{"time":"Day 3","open":95,"high":96,"low":90,"close":92,"volume":109}]'::jsonb, '[{"type":"line","points":[{"x":0,"y":80},{"x":1,"y":88},{"x":2,"y":90}],"label":"상승 추세선 (3rd Touch 기대선)","color":"#10b981"}]'::jsonb, ARRAY['손절 라인 없이 지정가로 1차 매수 몰빵 진입', '3rd Touch 타점 진입 및 추세선 하단 칼손절 셋업', '하방 붕괴 예상을 통한 고배율 숏 즉각 진입', '목표가 터치 시까지 무작정 대기 후 추격 매수']::text[], 1, '추세선 상의 3번째 지지 포인트(3rd Touch)는 추세 신뢰도가 형성되는 대단히 성공률 높은 정석적 눌림목 타점입니다. 진입 가격과 손절 라인(추세선 이탈가)의 거리가 매우 가깝기 때문에 기대 수익 대비 잃을 금액이 매우 적어 프로 트레이더들이 가장 선호하는 칼손절 매수 스팟입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (45, '추세/레짐', '08_setup_entry_exit.md', '주가가 장기 하락 추세선을 힘차게 뚫어 상방 돌파(Breakout)했습니다. 하지만 돌파선 바로 위(약 120달러)에 최근 여러 번 강한 매도 잔량이 쏟아지며 가격을 찍어 눌렀던 핵심 매물대 저항선이 떡하니 버티고 있습니다. 당신의 신규 진입 매수 순서는 어떻게 결정해야 안전할까요?', '[{"time":"Day 1","open":125,"high":126,"low":110,"close":112,"volume":84},{"time":"Day 2","open":112,"high":113,"low":98,"close":100,"volume":102},{"time":"Day 3","open":100,"high":119,"low":99,"close":118,"volume":92}]'::jsonb, '[{"type":"line","points":[{"x":0,"y":125},{"x":1,"y":112},{"x":2,"y":105}],"label":"하락 추세선 (돌파됨)","color":"#ef4444"},{"type":"horizontal-line","points":[{"x":0,"y":120}],"label":"수평 매물대 저항선 (120)","color":"#ef4444"}]'::jsonb, ARRAY['돌파 확인 즉시 종가 기준 시장가 100% 매수', '수평 저항 돌파 검증 시까지 매수 유보 및 대기', '돌파 전조 현상 기대로 레버리지 선배팅 집행', '추세선 돌파를 가짜로 간주한 숏 포지션 진입']::text[], 1, '하락 추세선의 돌파는 긍정적이나 수평 매물대 저항선이 바로 위에 있다면 이중 저항 작용에 의해 막히는 경우가 대단히 잦습니다. 추세선 상방 휩소(속임수)에 당하지 않으려면 겹저항 중 최종 관문인 수평 매물대 저항선 돌파 혹은 리테스트 지지를 확인하고 진입하는 것이 보수적이고 안전한 원칙입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (46, '패턴/돌파', '04_patterns_breakout.md', '고점 수평 저항선(100달러)과 저점 상승 지지선으로 이루어진 어센딩 트라이앵글 수렴 도중, 100달러를 돌파할 것을 미리 예측하고 98달러에서 비중 100% 매수로 진입했습니다. 그러나 주가는 돌파에 실패하고 하방 상승 지지선을 대량 거래량 장대음봉으로 뚫어 92달러로 하향 마감했습니다. 올바른 매매 액션은?', '[{"time":"Day 1","open":80,"high":100,"low":80,"close":95,"volume":92},{"time":"Day 2","open":95,"high":100,"low":88,"close":97,"volume":119},{"time":"Day 3","open":97,"high":98,"low":91,"close":92,"volume":112}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":100}],"label":"수평 저항선 (100)","color":"#ef4444"},{"type":"line","points":[{"x":0,"y":80},{"x":1,"y":88},{"x":2,"y":94}],"label":"상승 지지선 (붕괴)","color":"#10b981"}]'::jsonb, ARRAY['하방 이탈 확인 즉시 손절하여 추가 폭락 차단', '조정을 이용해 평단가를 조절하는 분할 물타기', '본전 탈출 시까지 포지션을 유지하며 관망', '손절 라인을 하단으로 조정하고 대기 주문 유지']::text[], 0, '어센딩 트라이앵글은 상방 확률이 다소 높지만, 하단 지지선이 뚫려 무너지는 순간 패턴 실패와 함께 엄청난 실망 매도 매물이 출하됩니다. 특히 돌파를 미리 예견해 들어간 포지션은 즉시 룰 위반을 시정하고 손절(92달러)해야 큰 자산 보호를 할 수 있습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (47, '패턴/돌파', '04_patterns_breakout.md', '하락 바닥권에서 왼쪽 어깨, 머리, 오른쪽 어깨를 그리며 역헤드앤숄더(Inverse Head & Shoulders) 패턴이 완성되었습니다. 가격이 넥라인 저항벽(80달러선)을 돌파했으나 이미 장대양봉으로 높이 솟아(87달러) 추격 매수 타이밍을 아쉽게 놓쳤습니다. 이때 뇌동매매를 피하는 가장 현명한 매수 타점 공략법은?', '[{"time":"Day 1","open":95,"high":95,"low":70,"close":78,"volume":97},{"time":"Day 2","open":78,"high":82,"low":60,"close":75,"volume":122},{"time":"Day 3","open":75,"high":79,"low":68,"close":76,"volume":99},{"time":"Day 4","open":76,"high":88,"low":75,"close":87,"volume":119}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":80}],"label":"넥라인 저항선 (80)","color":"#ef4444"}]'::jsonb, ARRAY['포모(FOMO) 현상에 따른 돌파봉 꼭대기 추격 매수', '돌파 넥라인 부근의 리테스트 조정 눌림목 매수', '반등 랠리 종결 판단에 따른 역베팅 숏 포지션', '추세 전환 확인 후 무조건적인 관심종목 제외']::text[], 1, '강한 패턴 돌파봉 확인 후 뇌동매매로 추격하는 것은 손절 거리가 너무 멀어져 손익비가 최악인 나쁜 습관입니다. 정석 돌파 트레이더는 넥라인 역할 전환 지점(80달러)으로의 되돌림 눌림목(Retest)을 차분히 기다려 리스크를 짧게 끊고 들어가는 훈련을 해야 합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (48, '패턴/돌파', '04_patterns_breakout.md', '지속적인 하락 추세 중, 고점과 저점이 수렴하며 우하향하는 하락 쐐기형(Falling Wedge) 패턴의 끝자락에 도달했습니다. 거래량이 급감하다가 마침내 쐐기형 상단 저항선을 상방으로 뚫는 강한 양봉 종가 마감(110달러)이 포착되었습니다. 합리적인 매수 진입 시 손절가 설정 기준은 무엇인가요?', '[{"time":"Day 1","open":130,"high":132,"low":110,"close":112,"volume":96},{"time":"Day 2","open":112,"high":116,"low":102,"close":104,"volume":119},{"time":"Day 3","open":104,"high":108,"low":98,"close":100,"volume":121},{"time":"Day 4","open":100,"high":112,"low":99,"close":110,"volume":106}]'::jsonb, '[]'::jsonb, ARRAY['손절 없이 청산가에 의존하여 장기 홀딩', '상방 돌파 확인 후 진입 및 직전 최저점 손절 셋업', '평단가 개선을 위한 지속적인 분할 물타기 매수', '상단 저항선 돌파 시점을 이용한 숏 포지션 스위칭']::text[], 1, '하락 쐐기형(Falling Wedge)의 상방 돌파는 강력한 반전 신호입니다. 이 패턴의 장점은 진입 즉시 명확하고 짧은 기준점(수렴 바닥 최저가 98달러 혹은 돌파봉 하단)을 손절가로 설정할 수 있어, 리스크 한도를 안전하게 통제한 채 상방 랠리를 도모할 수 있다는 점입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (49, '패턴/돌파', '04_patterns_breakout.md', '주가가 약한 매수세와 거래량 급감 속에 고점과 저점을 높이며 좁게 상승 쐐기형(Rising Wedge)을 그리고 있습니다. 현재 가격은 상승 쐐기형 하단 지지선(300달러)에 아주 밀착하여 붕괴 위기에 놓여 있습니다. 이 시점에서 롱(매수) 포지션을 들고 있는 트레이더의 리스크 대응은?', '[{"time":"Day 1","open":260,"high":280,"low":260,"close":278,"volume":96},{"time":"Day 2","open":278,"high":295,"low":272,"close":290,"volume":15},{"time":"Day 3","open":290,"high":305,"low":298,"close":301,"volume":17}]'::jsonb, '[{"type":"line","points":[{"x":0,"y":260},{"x":1,"y":272},{"x":2,"y":298}],"label":"쐐기 하단 지지선 (300)","color":"#ef4444"}]'::jsonb, ARRAY['상승 쐐기형 하방 이탈 위험에 따른 롱 포지션 매도', '상승 지속 확신에 따른 레버리지 추가 불타기', '장기 상승 흐름 기대로 손절 없이 무기한 홀딩', '다른 종목으로의 포지션 분산을 위한 관망']::text[], 0, '상승 쐐기형(Rising Wedge)은 약세 세력이 억지로 쥐어짜며 상승 가격을 만드는 패턴으로, 수렴 끝에서 거래량 소멸과 함께 하방 이탈(Breakdown)하여 폭락할 위험이 매우 높은 대표적인 하락 대비 패턴입니다. 하단 지지선 이탈 낌새 시에는 매수 포지션을 전부 도망쳐 나와야 큰 손실을 막을 수 있습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (50, '패턴/돌파', '04_patterns_breakout.md', '둥근 대야 모양의 바닥(Cup)을 그리며 상승 회복한 주가가 전고점 저항벽 부근에서 하향 채널식 완만한 되돌림 조정 핸들(Handle)을 그리는 중입니다. 이후 핸들의 상단 저항선(150달러선)을 강한 거래량의 장대양봉으로 상향 돌파했습니다. 이때 합리적인 트레이더의 대응은?', '[{"time":"Day 1","open":140,"high":142,"low":128,"close":130,"volume":108},{"time":"Day 2","open":130,"high":140,"low":129,"close":138,"volume":108},{"time":"Day 3","open":138,"high":140,"low":134,"close":135,"volume":95},{"time":"Day 4","open":135,"high":154,"low":134,"close":152,"volume":93}]'::jsonb, '[]'::jsonb, ARRAY['핸들 상방 돌파 확인 후 진입 및 핸들 저점 손절', '하락 지속 판단에 따른 즉각적인 전량 손절', '평단가 부근이므로 추가 손절 설정 없이 관망', '돌파 여부 확인 전 고점 돌파 매수 주문 100%']::text[], 0, '전형적인 강세 지속 패턴인 컵앤핸들(Cup & Handle)입니다. 핸들의 하락 조정 채널 상단 돌파는 매물 소화를 성공적으로 완수하고 본 랠리로 진입한다는 강력한 신호입니다. 손익비 관점에서 핸들의 지지 저점인 134달러 아래에 안전 손절을 지정한 뒤 진입 시 우수한 기대 수익을 가질 수 있습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (51, '지표/컨플루언스', '06_technical_indicators.md', '강력한 대세 상승 국면인 종목이 일시 조정을 거쳐 전저점 지지 영역(100달러)에 도달해 저점을 지키고 있습니다(저점 높임 또는 수평). 그런데 이때 보조지표 RSI의 저점은 이전보다 훨씬 깊게 파여 낮아지는 ''히든 상승 다이버전스(Hidden Bullish Divergence)''가 포착되었습니다. 현명한 의사결정은?', '[{"time":"Day 1","open":90,"high":110,"low":88,"close":105,"volume":102},{"time":"Day 2","open":105,"high":107,"low":98,"close":100,"volume":121}]'::jsonb, '[]'::jsonb, ARRAY['하락 전환 신호로 판단하여 전량 즉시 손절', '추세 지속 신호 기대로 지선 부근 추가/신규 매수', '지표 과매수 판단에 따른 계좌 거래 정지', '손절 설정 없이 무제한 레버리지 롱 대응']::text[], 1, '주가의 저점은 높아지는데 보조지표(RSI 등)의 저점은 낮아지는 형태는 ''히든 상승 다이버전스''입니다. 이는 기존의 강력한 상승 트렌드 내부에서 일시 조정을 겪는 매수자들이 활기차게 물량을 주워 담아 다음 상승 랠리를 추진한다는 신호이므로, 짧은 손절 라인(98달러)을 설정하고 매수 비중을 태우기 가장 적합한 정석 타점입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (52, '지표/컨플루언스', '07_multitimeframe_regime.md', '주가가 호재와 함께 밴드 상단선 바깥을 타고 계속 상승하는 강력한 볼린저 밴드 밴드워크(Band Walk) 현상이 발생 중이며, RSI는 80을 넘어 극단적 과매수 수치를 가리키고 있습니다. 이 구간에서 취해야 할 가장 합리적인 리스크 및 포지션 관리 행동은?', '[{"time":"Day 1","open":100,"high":115,"low":99,"close":112,"volume":103},{"time":"Day 2","open":112,"high":128,"low":110,"close":125,"volume":84},{"time":"Day 3","open":125,"high":139,"low":122,"close":136,"volume":97}]'::jsonb, '[]'::jsonb, ARRAY['과매수 도달 판단에 따른 고배율 숏 무리한 진입', '추종 손절매(Trailing Stop)를 통한 수익 극대화', '상승폭 만족에 따른 즉각적인 전량 시장가 익절', '손절 가격을 해제하고 시세 지속 시까지 방치']::text[], 1, '강세 추세가 지나치게 강할 경우 볼린저 밴드 상단을 타고 오르는 밴드워크 현상과 RSI 과매수 현상이 영구 유지될 수 있습니다. 이때 단순 과매수 수치를 이유로 숏 포지션을 잡으면 파산합니다. 기존 매수 포지션의 익절선(Trailing Stop)을 상향 관리하여 추세 상승 이익을 극대화하고 신규 진입은 자제하는 것이 정석 리스크 관리입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (53, '지표/컨플루언스', '06_technical_indicators.md', '1시간 봉 차트 상에서 주가가 확실히 낮아졌으나 RSI 저점은 유의미하게 상승한 ''상승 다이버전스''가 확인되어 매수 타점을 노리고 있습니다. 다만 15분 봉 단기 차트에서는 하락 장대음봉 관성이 아직 살아있어 매도 압력이 보입니다. 멀티 타임프레임 트레이더의 진입 의사결정은?', '[{"time":"Hour 1","open":100,"high":102,"low":90,"close":91,"volume":82},{"time":"Hour 2","open":91,"high":92,"low":80,"close":82,"volume":108}]'::jsonb, '[]'::jsonb, ARRAY['단기 음봉 관성 기대로 즉각 숏 포지션 진입', '큰 시간 프레임의 상승 다이버전스 타점 매수', '지표 충돌로 판단하고 시장가 즉시 롱 진입', '변동성 기대로 무작정 도박성 잡코인 진입']::text[], 1, '큰 프레임(1시간 봉)의 다이버전스가 주는 중장기 추세 신뢰도는 작은 프레임의 단기 노이즈보다 압도적으로 강력합니다. 단, 진입 시 타이밍의 정밀도를 높이기 위해 소파동(15분 봉)의 하락 동력이 꺾이고 지지해 주는 단기 확인 캔들이 나오는 찰나에 롱 포지션 타이밍을 잡는 것이 멀티 타임프레임 정석 매매입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (54, '지표/컨플루언스', '06_technical_indicators.md', '주가는 200달러 저항대를 뚫고 220달러까지 계속 우상향하며 고점을 갱신하고 있으나, MACD 오실레이터의 히스토그램 산 높이는 직전 고점 시점 대비 현저하게 쪼그라들며 꺾여 내려가 하락 다이버전스를 형성 중입니다. 현명한 포지션 보유자의 이익 관리 행동은?', '[{"time":"Day 1","open":180,"high":205,"low":179,"close":200,"volume":82},{"time":"Day 2","open":200,"high":222,"low":198,"close":220,"volume":88}]'::jsonb, '[]'::jsonb, ARRAY['추세 지속 확신으로 보유 비중 추가 불타기', '상승 모멘텀 약화 다이버전스 확인 후 50% 익절', '익절 설정 없이 전고점 도달 시까지 홀딩', '고점 붕괴 기대로 숏 포지션 10배 베팅']::text[], 1, '주가는 올라가나 모멘텀 지표인 MACD 오실레이터 고점이 낮아지는 현상은 대표적인 하락 다이버전스로, 매수 에너지가 속 빈 강정처럼 쇠퇴하고 있어 언제든 급격한 폭락 조정이 발생할 수 있는 고위험 신호입니다. 이 시점에는 탐욕을 통제하고 물량의 50% 이상을 분할 매도하여 현금을 챙기는 것이 원칙입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (55, '지표/컨플루언스', '06_technical_indicators.md', '주가가 하락 횡보하던 도중, 단기 지평선인 EMA 20일선이 중장기선인 EMA 50일선에 극도로 밀착하며 수렴했습니다. 당일 대량 거래량의 음봉 캔들이 터지며 단기선이 장기선 아래로 교차하기 직전(데드크로스 임박)이며 주요 지지선 밑으로 떨어졌습니다. 롱(매수) 포지션 보유자의 올바른 대응은?', '[{"time":"Day 1","open":105,"high":106,"low":99,"close":100,"volume":84},{"time":"Day 2","open":100,"high":101,"low":95,"close":96,"volume":104}]'::jsonb, '[]'::jsonb, ARRAY['지지선 이탈 및 데드크로스 확인 즉시 손절', '이평선 지지력을 믿고 하방 물타기 추가 매수', '하락 조정 후 반등 기대로 무기한 홀딩 관망', '청산가 도달 시까지 어떠한 대응 없이 방치']::text[], 0, '20일선과 50일선의 데드크로스 임박 수렴 상태에서 가격이 지지선마저 무너뜨린 것은 하락 가속화 추세가 폭발하기 직전인 매우 위험한 기술적 상태입니다. 하락 추세가 본격 정배열(하락 정배열)화 되기 전에 즉시 전량 손절하고 시장 밖에서 피신해 있는 것이 계좌의 영구 파산을 막는 유일한 생존 규칙입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (56, '리스크/심리', '09_risk_position_management.md', '주식 매수 후 가격이 급락하여 내가 설정해 둔 최대 감내 손실 한도인 계좌 총원금 대비 -2% 라인(손절매 지정 가격)에 완벽하게 닿았습니다. 마침 본전 생각과 함께 ''조금만 더 버티면 반등할 텐데...''하는 강한 뇌동매매 유혹이 솟구칩니다. 이때 원칙 트레이더의 결정은?', '[{"time":"Day 1","open":100,"high":102,"low":99,"close":100,"volume":115},{"time":"Day 2","open":100,"high":101,"low":94,"close":95,"volume":107}]'::jsonb, '[]'::jsonb, ARRAY['손절 라인을 임의로 하향 조정하고 홀딩', '평단가 관리 차원의 지속적 물타기 매수 집행', '원칙에 따라 뇌동을 제어하고 즉시 기계적 손절', '손실은 배제하고 반등 기대를 통한 무기한 보유']::text[], 2, '트레이딩의 승패는 예측이 아닌 ''리스크 통제''에 달려 있습니다. 사전에 정한 계좌 대비 2% 리스크 한도에 도달했을 때 희망 회로를 돌리며 손절을 미루거나 물타기를 집행하는 순간 계좌는 서서히 영으로 깎여 파산합니다. 멘탈의 충동을 통제하고 기계적으로 전량 칼손절하는 것이 절대 파산하지 않는 시장의 1법칙입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (57, '리스크/심리', '10_psychology_routine_review.md', '최근 3회 연속 거래에서 계속해서 손절(Stop Loss)을 맞아 뇌 내의 도파민 체계가 무너지고 심리가 극도로 불안해져 분노와 보복 매매 충동이 밀려옵니다. 이 상황에서 파산을 막는 가장 훌륭한 매매 심리 대처법은?', '[{"time":"Today","open":100,"high":100,"low":100,"close":100}]'::jsonb, '[]'::jsonb, ARRAY['손실 복구를 위해 레버리지를 증액해 즉시 진입', '뇌동 방지를 위해 HTS를 종료하고 매매 일지 작성 및 휴식', '추천 매매 신호 유료 리딩방에 즉시 가입 및 추종', '심리적 회복을 위해 역베팅 숏 포지션 추가']::text[], 1, '연속 손실 후 발생하는 복수심과 분노는 트레이더를 뇌동매매와 계좌 파멸로 이끄는 가장 치명적인 감정 상태입니다. 멘탈 붕괴를 느꼈을 때는 즉각 행동을 멈추고 시스템을 강제 종료하여 시장과 물리적 격리를 통해 냉정을 찾는 것만이 자산을 파산 리스크로부터 살려내는 훌륭한 트레이딩 행동입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (58, '셋업/실행', '09_risk_position_management.md', '진입하고자 하는 매수 자리를 분석해 보니, 기술적 분석 상 이길 수 있는 확률(승률)은 반반인 50% 수준입니다. 그러나 손절 시 기대 손실금액 대비 성공 시 획득할 수 있는 기대 수익금액의 비율(손익비)을 정밀 셋업 해보니 1 : 1.2 수준으로 다소 애매하게 도출되었습니다. 원칙 트레이더의 진입 결정은?', '[{"time":"Today","open":100,"high":100,"low":100,"close":100}]'::jsonb, '[]'::jsonb, ARRAY['단기 변동성 기대로 부적합한 손익비 시장가 진입', '마이너스 기댓값 거래 유보 및 우수 타점 대기', '레버리지를 높여 손익비 구조를 임의 조정 시도', '반대 방향으로 고배율 역베팅을 즉시 실행']::text[], 1, '수학적으로 승률 50%일 때 손익비가 최소 1:2(잃을 때 1, 벌 때 2) 이상이 나오지 않으면 복리 매매 시 수수료와 호가 슬리피지에 밀려 잔고가 무조건 마이너스로 수렴합니다. 타점이 눈에 들어오더라도 사전에 기대 손익비 필터에 걸려 탈락한다면 패스를 선언하고 관망하는 것이 현명한 생존 원칙입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (59, '리스크/심리', '09_risk_position_management.md', '갑작스러운 거시 경제 발표로 내가 매매 중인 종목의 캔들 변동성 폭(ATR)이 평소 시세의 2배 수준으로 널뛰기 시작했습니다. 1회 거래당 내 계좌 원금의 최대 2% 리스크 한도를 동일하게 고수하기 위해 취해야 할 올바른 조치는?', '[{"time":"Day 1","open":100,"high":102,"low":98,"close":100,"volume":88},{"time":"Day 2","open":100,"high":110,"low":90,"close":102,"volume":106}]'::jsonb, '[]'::jsonb, ARRAY['평소 변동성과 동일한 비중 및 손절 거리 고수', '손절 거리를 넓히는 대신 진입 포지션 수량 축소', '변동성이 확대되었으므로 2배 비중으로 적극 지름', '즉시 전량 손절하고 시장 상황 정상화 대기']::text[], 1, '시장 변동성이 커질 때는 손절 스톱 아웃이 잦으므로 손절폭(%)을 넓혀 숨 쉴 공간을 확보해 주는 것이 합리적입니다. 단, 손절폭을 2배로 늘린다면 계좌 대비 리스크 한도가 2배(4%)로 커지므로, 진입 포지션의 계약 수량을 50%로 줄여 리스크 노출 총액을 2%로 완벽하게 동일 통제하는 것이 포지션 사이징(Position Sizing)의 정석 원칙입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (60, '리스크/심리', '09_risk_position_management.md', '투자자 A의 전체 투자 원금은 500만 원이며, 1회 거래당 최대 허용 리스크 금액은 원금의 2%인 10만 원입니다. 현재 주가가 10,000원이며, 기술적 분석 상 합리적인 손절선은 지지선 바로 밑인 9,500원(-5%)입니다. 2% 룰 리스크 관리 원칙에 따라 A가 진입(매수)해야 하는 최대 주식 수량은?', '[{"time":"Today","open":10000,"high":10000,"low":10000,"close":10000}]'::jsonb, '[]'::jsonb, ARRAY['500주 (투자금 전액 시장가 매수)', '200주 (손실 한도 10만 원 맞춤 매수)', '50주 (보수적 극단적 비중 축소)', '100주 (절반 비중 고정 매수)']::text[], 1, '포지션 크기 계산 공식은 `최대 매수 규모 = 최대 허용 리스크 금액 / 손절매 비율` 입니다. 이 시나리오에서 `100,000원 / 0.05(5%) = 2,000,000원`이 최대 허용 진입금액이 되며, 이를 주가 10,000원으로 나누면 `200주`가 도출됩니다. 200주 진입 후 -5% 가격 폭락으로 손절 당해도 내 총원금에서 깎이는 돈은 정확히 10만 원(2%)으로 완벽히 리스크 통제됩니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (61, '거래량/유동성', '05_volume_liquidity.md', '주가가 수평 저항선 부근까지 급상승했으나 캔들 몸통(Spread)이 지극히 좁아진 도지 형태로 마감하였고, 거래량은 이전 5일 평균 대비 3배 이상 폭증했습니다. VSA(Volume Spread Analysis) 관점에서 가장 타당한 차트 분석은?', '[{"time":"Day 1","open":100,"high":105,"low":99,"close":104,"volume":91},{"time":"Day 2","open":104,"high":109,"low":103,"close":108,"volume":118},{"time":"Day 3","open":108,"high":110,"low":107,"close":108,"volume":102}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":109},{"x":2,"y":109}],"label":"저항선","color":"#ef4444"}]'::jsonb, ARRAY['강한 매수 기세 기대로 즉시 돌파 매매 풀매수', '저항벽 매도 공급 세력 분산 확인 후 이익 실현', '대량 거래 확인에 따른 손절 해제 후 장기 투자', '반등 실패에 따른 고배율 보복 숏 베팅 가동']::text[], 1, '캔들 몸통 크기(스프레드)가 좁은데 거래량이 매우 크게 폭증했다는 것은 저항선 부근에서 들어오는 매수세만큼 세력의 매도 물량 공급이 쏟아져 막강한 저항 벽을 형성하고 있다는 뜻입니다. VSA에서는 이를 불화(Disharmony)로 규정하며 상승 추세 감속 및 하락 반전의 경고로 해독합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (62, '거래량/유동성', '05_volume_liquidity.md', '주가가 장기 횡보하던 박스권 지지선인 200달러를 깨고 195달러까지 하락 투매가 발생했으나, 종가 마감 직전 거래량이 크게 실린 긴 아래꼬리를 그리며 다시 201달러 위로 복귀 안착했습니다. 이 스톱 헌팅 유동성 현상에서의 실전 트레이더의 대응은?', '[{"time":"Day 1","open":210,"high":212,"low":200,"close":202,"volume":99},{"time":"Day 2","open":202,"high":204,"low":195,"close":201,"volume":90}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":200},{"x":1,"y":200}],"label":"지지선","color":"#10b981"}]'::jsonb, ARRAY['지지선 붕괴 확정으로 간주한 시장가 숏 추격', '스윕(sweep) 판단 하에 아래꼬리 저점 손절 잡고 롱', '아무런 신호도 아니라고 판단하고 포지션 방치', '지지선 이탈 기대로 전량 손절 후 시장 영구 탈출']::text[], 1, '지지선 아래에 걸려 있던 개인들의 손절 주문(Sell Stop)을 강제로 청산(Liquidity Sweep)시킨 뒤, 세력이 물량을 헐값에 다 받아 삼켜 종가를 지지선 위로 신속하게 복귀시킨 휩소(베어 트랩) 패턴입니다. 아래꼬리 극점(195달러)에 아주 좁은 손절 라인을 설정할 수 있어, 기대 손익비가 극대화되는 고확률 상승 반전 매수 타점입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (63, '거래량/유동성', '05_volume_liquidity.md', '주가는 250달러에서 290달러까지 계속 고점을 높이며 상승 추세를 이어가고 있습니다. 그러나 각 상승 파동마다 터지는 거래량은 전고점 돌파 시점 대비 눈에 띄게 하향 곡선을 그리며 감소하고 있습니다. VSA 기법에 따른 합리적인 진단은?', '[{"time":"Wave 1","open":230,"high":260,"low":228,"close":255,"volume":94},{"time":"Wave 2","open":255,"high":275,"low":250,"close":270,"volume":85},{"time":"Wave 3","open":270,"high":290,"low":265,"close":288,"volume":127}]'::jsonb, '[]'::jsonb, ARRAY['가격 상승으로 인한 매수 지속 강화 초강세', '매도 물량 고갈에 따른 무중력 안심 홀딩', '신규 자금 유입 둔화 거래량 다이버전스로 분할 익절', '지표 조작으로 판단하여 매매 중단 및 차트 종료']::text[], 2, '주가는 상승하여 신고점을 갱신하지만 파동별 거래량이 지속 감소하는 흐름은 ''거래량 다이버전스''로 상승 모멘텀의 내부 엔진이 식어감을 경고합니다. 조만간 가벼운 매도 포격에도 대규모의 차익 실현 폭락 조정이 발생할 수 있는 잠재적 폭락 국면이므로 물량을 덜어내고 현금을 확보해야 합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (64, '거래량/유동성', '05_volume_liquidity.md', '가격이 이전 고점 저항선을 뚫고 강하게 솟구치며 장대양봉을 만들었습니다. 이때 가짜 이탈(Whipsaw / Bull Trap)이 아닌 진성 돌파(True Breakout)로 판정할 수 있는 가장 신뢰도 높은 거래량 기준은?', '[{"time":"Day 1","open":100,"high":102,"low":99,"close":100,"volume":328},{"time":"Day 2","open":100,"high":112,"low":99,"close":110,"volume":404}]'::jsonb, '[]'::jsonb, ARRAY['수렴 끝자락에서 거래량이 최저치인 상태 유지', '평균 대비 1.5~2배 이상 거래량 급증하며 돌파 마감', '거래량이 전혀 변하지 않는 평이한 상태 유지', '호가 스프레드가 가장 좁아지는 횡보 상태']::text[], 1, '참된 저항 돌파(True Breakout)는 저항선 부근의 두터운 대기 매도 공급 물량을 대규모 자금으로 전부 씹어 삼키고 돌파해야 함을 뜻합니다. 따라서 반드시 평균 대비 1.5배~2배 이상의 거래량 분출이 동반되어야 신뢰할 수 있으며, 거래량이 적은 돌파는 꼬리 달고 내려앉는 불 트랩(Bull Trap)일 확률이 매우 높습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (65, '거래량/유동성', '05_volume_liquidity.md', '비트코인 차트에서 중요 지지선 직전 저점 아래에 엄청난 규모의 롱 포지션 청산 및 매도 손절 주문이 쌓여 있는 유동성 풀(Liquidity Pool) 구간이 감지되었습니다. 세력이 이 구간을 공략할 때 나타날 캔들의 전형적인 무빙 패턴은?', '[{"time":"Day 1","open":50000,"high":50500,"low":49200,"close":49500,"volume":30},{"time":"Day 2","open":49500,"high":49800,"low":48000,"close":49600,"volume":15}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":49200},{"x":1,"y":49200}],"label":"전저점 지지선","color":"#3b82f6"}]'::jsonb, ARRAY['지지선을 장대음봉으로 돌파하여 20% 폭락 마감', '전저점 이탈로 손절 유도 후 지지선 위 아래꼬리 안착', '오차 없이 지지선 터치 후 꼬리 없는 수평 도지 횡보', '거래량 없이 즉각 상승 빔 분출로 전고점 탈환']::text[], 1, '기관 세력(스마트 머니)은 대량 포지션을 구축하기 위해 개인의 손절 주문(Sell Stop)을 의도적으로 터트려 매도 유동성을 유도한 후 이를 다 매수합니다. 이로 인해 주가는 지지선 아래로 일시 급락 후(스톱 헌팅), 아래꼬리를 매우 길게 달며 지선 안쪽으로 급반등 마감하게 됩니다. 이것이 유동성 스윕(Liquidity Sweep)의 정석 패턴입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (66, '거래량/유동성', '05_volume_liquidity.md', '상승 추세 도중 전고점 저항선 부근에서 위꼬리가 아주 긴 캔들이 터졌고, 거래량은 최근 보름 중 최고 수치로 솟구쳤습니다. VSA 관점에서 이 상승 거절(Upside Rejection) 현상에 대한 올바른 대처는?', '[{"time":"Day 1","open":100,"high":115,"low":98,"close":101}]'::jsonb, '[]'::jsonb, ARRAY['강한 저점 매수 기회로 인지하여 비중 대폭 추가', '고점 매도 Rejection 확인 후 기존 롱 포지션 대피', '박스 횡보 수렴 기대로 마틴게일 추가 매수 가동', '이평선 정배열 판단에 따른 포지션 변경 없이 홀딩']::text[], 1, '위꼬리가 매우 긴 캔들이 대량 거래량과 함께 터졌다는 것은 고점 돌파 시도가 있었으나 그 자리에 숨어 있던 세력의 막강한 청산 매도 벽(Supply)을 만나 격렬하게 두들겨 맞고 밀려났음을 의미합니다. 상방 거절의 심리가 지배적이므로 고점 피로 및 하락 전환이 임박한 위험 징후입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (67, '지표/컨플루언스', '06_technical_indicators.md', '주가가 장기 박스권 횡보를 이어가며 볼린저 밴드의 폭이 최근 몇 달 중 가장 좁은 형태로 밀착 수렴(Squeeze)되었습니다. 이 스퀴즈 국면에 대한 올바른 기술적 이해와 매매 시나리오는?', '[{"time":"Week 1","open":100,"high":103,"low":97,"close":101,"volume":101},{"time":"Week 2","open":101,"high":102,"low":99,"close":100,"volume":95}]'::jsonb, '[]'::jsonb, ARRAY['박스권 변동성 부재 기대로 장기 무대응 관망', '에너지 수축 스퀴즈 확인 후 밴드 이탈 돌파 대기', '지표 신뢰 불가 판단으로 볼린저 밴드 지표 삭제', '중심선 지지로 판단하여 고배율 매수 대기 주문']::text[], 1, '볼린저 밴드의 폭이 극도로 좁아지는 스퀴즈(Squeeze) 현상은 시장의 표준편차 변동성이 임계치까지 압축 수렴되었음을 알려줍니다. 에너지 압축 뒤에는 항상 폭발적인 가격 분출(상방/하방 이탈)이 뒤따르므로, 밴드를 뚫고 거래량이 실려 돌파 마감하는 방향으로 추세 추종 시나리오를 설계해야 합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (68, '지표/컨플루언스', '06_technical_indicators.md', '주가는 HL(Higher Low)을 형성하며 이전 직전 저점(90달러)보다 높은 저점(95달러)을 지키고 있으나, RSI 지표는 이전 35 수치보다 더 깊숙하게 25 수치까지 떨어졌습니다. 이 지표 불일치 현상의 공식 명칭과 올바른 포지션 셋업은?', '[{"time":"Day 1","open":100,"high":102,"low":90,"close":91,"volume":90},{"time":"Day 2","open":91,"high":96,"low":95,"close":95,"volume":84}]'::jsonb, '[]'::jsonb, ARRAY['일반 상승 다이버전스 - 추세 종결로 즉각 공매도', '히든 상승 다이버전스 - 지선 눌림목 롱 진입 활용', '일반 하락 다이버전스 - 모든 매수 포지션 정리', '지표 오작동 휩소 구간 판단으로 양방향 관망']::text[], 1, '가격의 저점은 높아졌는데(Higher Low) 모멘텀 지표의 저점은 낮아지는 현상은 ''히든 상승 다이버전스(Hidden Bullish Divergence)''입니다. 이는 추세 반전이 아닌 **기존 강세 추세 지속**을 뜻하며, 조정 눌림목이 완성되고 다음 상승 랠리를 준비한다는 최고의 매수 신호 중 하나입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (69, '지표/컨플루언스', '06_technical_indicators.md', '매수 타점을 신중하게 선별하고자 합니다. 기술적 분석의 성공 확률을 비약적으로 끌어올리는 ''다중 컨플루언스(Confluence)'' 결합 사례로 가장 적합한 조건 구성은?', '[{"time":"Today","open":100,"high":100,"low":100,"close":100}]'::jsonb, '[]'::jsonb, ARRAY['트위터 및 뉴스의 호재 찌라시 확인 즉시 추격', '지지선+이평선+다이버전스+아래꼬리 등 분석 중첩 시', 'RSI 과매수 영역 진입 즉시 롱 포지션 진입', '독립적 분석 없이 오직 보조지표의 단일 수치 신호']::text[], 1, '다중 컨플루언스(Confluence)는 독립적인 기술적 근거들이 동일한 특정 가격 구역에 중첩되는 현상입니다. 지지 저항, 이평선, 보조지표 다이버전스, 캔들 가격행동(Rejection 핀바)이 한 곳에 묶여 매수 자리를 형성할 때 매매를 실행하면, 높은 신뢰도와 좁은 손절 라인 덕분에 장기 기대값이 극대화됩니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (70, '셋업/실행', '08_setup_entry_exit.md', '중요 수평 저항선(120달러)을 상방으로 장대양봉 종가 돌파한 것을 확인하고 롱(매수) 진입 셋업을 준비하고 있습니다. 원칙 트레이더가 뇌동매매 추격을 막고 최상의 손익비를 확보하기 위해 즐겨 쓰는 정석적인 진입 실행법은?', '[{"time":"Day 1","open":110,"high":112,"low":109,"close":111,"volume":109},{"time":"Day 2","open":111,"high":124,"low":110,"close":122,"volume":112}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":120},{"x":1,"y":120}],"label":"저항선","color":"#ef4444"}]'::jsonb, ARRAY['돌파 마감 확인 즉시 시장가 추가 매수 집행', '돌파된 저항선의 지지 전환(Retest) 시 지정가 진입', '반등 조정이 불가능하다고 판단하여 최고점 롱 추격', '속임수 돌파 확신으로 고배율 역베팅 숏 진입']::text[], 1, '저항 돌파 후 즉시 가격을 따라붙는 추격 매수는 휩소 조정 시 심각한 손실을 초래합니다. 돌파된 라인이 S/R Flip을 통해 지지로 작용하는지 확인하는 되돌림 리테스트(Retest) 시점에 진입하는 것이, 지선 바로 아래에 좁은 손절 라인을 설계하고 이익 기대 폭을 넓힐 수 있는 가장 이상적인 정석 실행법입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (71, '셋업/실행', '08_setup_entry_exit.md', '포지션 진입 직후, 가격이 계획대로 내 방향으로 순탄하게 우상향하고 있습니다. 기존 진입 시 설정한 손익비 1:2의 최종 목표가 도달 전에, 리스크 관리 차원에서 계좌 드로다운을 0으로 만드는 정석적인 1차 포지션 관리 행동은?', '[{"time":"Entry","open":100,"high":100,"low":100,"close":100,"volume":88},{"time":"Day 1","open":100,"high":106,"low":100,"close":105,"volume":108}]'::jsonb, '[]'::jsonb, ARRAY['1차 저항대 진입 시 레버리지를 활용해 불타기', '목표가 터치 시까지 100% 비중 무대응 홀딩', '1:1 지점 50% 분할 익절 및 남은 물량 본전 손절 상향', '단기 반등 확인 즉시 전량 기계적 청산 및 퇴장']::text[], 2, '이득이 발생해 손익비 1:1 수준에 오면 물량의 절반을 분할 익절(Scale-out)하고 남은 포지션의 스톱로스를 진입가로 이동(Break-even)시키는 것이 포지션 관리의 기본입니다. 이렇게 셋업하면 차트가 갑자기 폭락세로 뒤집혀도 최소 본전 혹은 반절 익절 약수익으로 끝나 해당 거래의 최대 리스크가 Zero(0)로 봉쇄됩니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (72, '셋업/실행', '08_setup_entry_exit.md', '강력한 장기 상승 추세가 터져 주가가 20일 이평선을 타고 계속해서 폭발적으로 신고가를 갱신하고 있습니다. 이때 익절 시점을 서둘러 잡지 않고, 추세 상승 이익을 최대한 길게 끝까지 빨아먹기 위한 정석 청산 실행법은?', '[{"time":"Day 1","open":100,"high":110,"low":99,"close":108,"volume":96},{"time":"Day 2","open":108,"high":120,"low":107,"close":118,"volume":85},{"time":"Day 3","open":118,"high":135,"low":117,"close":132,"volume":88}]'::jsonb, '[]'::jsonb, ARRAY['RSI 과과열 조짐 확인 즉시 시장가 전량 익절', 'Higher Low 지지 직하방으로 손절 추종 익절 셋업', '이익 보존을 포기하고 손익절 라인을 해제 후 홀딩', '즉시 숏 포지션 10배로 맞불을 놓는다']::text[], 1, '강세 추세가 터졌을 때 지레짐작으로 청산하면 상승 파동의 초입만 먹고 끝납니다. 추세 붕괴의 명확한 신호(BOS/MSB)가 나오거나, 가격의 구조적 높은 저점(HL)이 깨질 때까지 손절 라인을 계속 추종해서 상향하는 ''추격 손절매(Trailing Stop)''를 가동하는 것이 추세 이익을 극대화하는 정석 기법입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (73, '셋업/실행', '01_chart_market_basics.md', '차트 분석 결과, 돌파 시점의 체결 변동성과 거래소 호가창의 얇은 매물 상태를 감안할 때 내가 진입하려는 주문 가격에서 체결이 뒤로 밀리는 ''슬리피지(Slippage)''가 심각하게 예상됩니다. 이를 감안한 올바른 주문 실행법은?', '[{"time":"Today","open":100,"high":100,"low":100,"close":100}]'::jsonb, '[]'::jsonb, ARRAY['시장가로 최고 배율을 설정하여 즉시 체결', '돌파 확인 후 지정가 대기 주문으로 단가 조절', '슬리피지를 예방하기 위해 즉각적인 거래 취소', '호가창 스프레드와 무관하게 고배율 레버리지']::text[], 1, '변동성이 크고 호가가 얇은 시장에서 돌파 시 시장가 진입은 나쁜 단가로 체결되는 슬리피지 비용을 발생시켜 시작부터 손실을 크게 안고 갑니다. 돌파 확인 후 되돌림 가격대에서 지정가(Limit Order)를 대기시켜 체결 단가를 내 손아귀에 고정하는 리스크 관리가 필요합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (74, '셋업/실행', '10_psychology_routine_review.md', '원칙 기반의 정석 매매 셋업(Trading Setup)을 설계할 때, 진입 전 반드시 사전에 수치로 명문화되어 결정되어야 할 요소가 아닌 것은?', '[{"time":"Today","open":100,"high":100,"low":100,"close":100}]'::jsonb, '[]'::jsonb, ARRAY['진입 조건(Trigger)과 구체적인 손절 가격(Stop Loss)', '거래 당일 본인의 주관적인 직감과 감정적 목표가', '진입하려는 구체적인 포지션 규모 및 분할 익절선', '거래 아이디어가 무효화되는 구체적 가격 지점']::text[], 1, '매매 셋업은 규칙에 기반한 수치들(진입가, 손절가, 목표가, 수량)로 사전에 철저히 규격화되어야 합니다. 당일의 운이나 주관적 느낌, 예감에 기초한 비과학적 청산 설정은 셋업에서 배제되어야 할 대표적 뇌동매매 요소입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (75, '셋업/실행', '08_setup_entry_exit.md', '하락 횡보하던 주가가 중요 매물대이자 피보나치 되돌림 0.618 지점에 정확히 맞닿아 아래꼬리가 긴 양봉 핀바(Pin Bar)를 그리며 마감했습니다. 룰베이스 트레이더가 진입 버튼을 누를 때 성립된 IF-THEN 시나리오는?', '[{"time":"Day 1","open":100,"high":100,"low":80,"close":82,"volume":93},{"time":"Day 2","open":82,"high":86,"low":78,"close":85,"volume":115}]'::jsonb, '[]'::jsonb, ARRAY['익일 가격 상황과 관계없이 100배 레버리지 진입', '중첩 자리 핀바(rejection) 확인 후 익일 시가 롱 진입', '상단 저항 도달 판단으로 즉각적인 숏 포지션 진입', '돌파 랠리가 완전히 끝날 때까지 HTS 종료 및 관망']::text[], 1, '훌륭한 트레이딩 실행은 ''IF(조건 만족 시) ➔ THEN(원칙대로 포지션 진입 및 손절/목표가 기계적 배치)''의 룰베이스 알고리즘에 의해 움직여야 감정을 배제할 수 있습니다. 지지 구간 중첩과 핀바 출현 조건이 성립했으므로 다음 봉 시가에 진입하되 꼬리 저점 이탈 시 칼손절하여 리스크를 통제하는 것이 정석입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (76, '리스크/심리', '09_risk_position_management.md', '나의 트레이딩 시스템 승률이 40%로 다소 낮게 고정되어 있습니다. 이 시스템을 통해 장기적으로 파산하지 않고 복리로 계좌 자산을 우상향시키기 위해 필수적으로 지켜야 할 손익비(평균손실 대비 평균수익 비율)의 최소 기준은?', '[{"time":"Today","open":100,"high":100,"low":100,"close":100}]'::jsonb, '[]'::jsonb, ARRAY['손익비 1:1 수준 (매매 승률이 낮을 때 파산)', '승률 40% 대비 기댓값 개선을 위한 손익비 1:1.5 이상', '낮은 승률 상태에서 손익비와 무관하게 무조건 파산', '승률 극복을 위한 레버리지 20배 수준 설정']::text[], 1, '승률이 40%일 때 기대값 수학적 수수료 감안 최소 손익비는 1:1.5입니다. 손익비 1.5배 이상 구간만 취하면 10번 중 6번 손절당하고 단 4번만 익절하더라도 계좌 총합은 수익 우위에 서게 됩니다. 저승률 시스템일수록 철저히 손익비가 유리한 진입가 근처 타점만 기계적으로 필터링해 진입해야 생존합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (77, '리스크/심리', '09_risk_position_management.md', '선물 트레이더인 B는 담보금 효율을 극대화한다는 명목으로 50배 레버리지 롱 포지션 진입을 실행했습니다. 진입 가격 대비 B의 포지션 원금이 완전 소멸(강제 청산)되는 역방향 하락 거리(%)는 대략 몇 % 수준입니까?', '[{"time":"Today","open":100,"high":100,"low":100,"close":100}]'::jsonb, '[]'::jsonb, ARRAY['진입 단가 대비 20.0%의 강한 하락 발생 시', '진입 단가 대비 단 -2.0% 변동성 노이즈 터치 시', '진입 단가 대비 50.0%의 강한 폭락 발생 시', '청산가가 산출되지 않는 특이 종목 거래 시']::text[], 1, '청산 거리 계산 공식은 대략 `100% / 레버리지 배수` 입니다. 50배 고배율 레버리지의 경우, 내 포지션 반대 방향으로 단 **-2%**의 시세 변동성(장중 흔한 잔파동 노이즈)만 터치해도 원금이 100% 강제 청산 증발됩니다. 고배율 레버리지는 수학적 확률상 100% 파멸을 초래하는 도박성 거래 행위입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (78, '리스크/심리', '09_risk_position_management.md', '트레이딩 계좌 총자산이 2,000만 원인 트레이더가 있습니다. 1회 거래당 총자산의 2% 룰 원칙에 근거하여 리스크 한도(40만 원)를 설정했습니다. 진입하려는 종목의 손절가 거리가 -8%인 경우, 2% 룰을 완벽하게 충족하는 최대 진입(매수) 금액은?', '[{"time":"Today","open":100,"high":100,"low":100,"close":100}]'::jsonb, '[]'::jsonb, ARRAY['2,000만 원 전액 매수 (손절 폭을 배제한 대규모 베팅)', '500만 원 진입 (-8% 손절 시 리스크 한도 40만 원 충족)', '1,000만 원 진입 (손익비 1:1 기준에 맞춘 베팅)', '200만 원 진입 (보수적 원칙에 입각한 극단적 축소)']::text[], 1, '포지션 사이징 공식은 `진입금액 = 최대 리스크 허용액(40만 원) / 손절 비율(0.08)` 입니다. 이에 따라 `400,000원 / 0.08 = 5,000,000원`이 도출됩니다. 500만 원 규모로 매수 진입 시 가격이 급락해 -8% 손절 라인을 때려도 내 총자산에서 깎이는 금액은 정확히 원칙 한도인 40만 원(2%)으로 제한되어 계좌가 완벽히 방어됩니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (79, '리스크/심리', '10_psychology_routine_review.md', '장중에 내가 째려보며 타점을 기다리던 주식이 아무런 조정도 없이 장대양봉을 그리며 갑자기 수직 폭등하기 시작하여 5% 이상 치솟았습니다. 이때 머릿속에 ''나만 두고 날아가는 것 아닌가''하는 극심한 소외감 공포(FOMO)가 솟구칩니다. 원칙 트레이더의 올바른 심리 대응은?', '[{"time":"Day 1","open":100,"high":102,"low":99,"close":100,"volume":96},{"time":"Day 2","open":100,"high":106,"low":100,"close":105,"volume":110}]'::jsonb, '[]'::jsonb, ARRAY['추세 연장 판단으로 시장가 전액 추격 매수', 'FOMO 판단 하에 매수 보류 및 정석 되돌림 타점 대기', '돌파 실패 판단 하에 반대 방향 고배율 숏 베팅', '거래를 종료하고 즉각 주식 시장에서 전량 탈출']::text[], 1, '나만 기회를 잃는다는 공포(FOMO)로 날아가는 장대양봉 꼭대기에서 추격 매수하는 행위는 고점 물리기를 자처하는 가장 흔한 뇌동매매 패턴입니다. 내 타점을 비껴간 상승은 내 돈이 아니라고 인정하고, 사전에 정의한 룰베이스 타점까지 냉정하게 대기하는 것이 장기 생존자의 멘탈 습관입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (80, '리스크/심리', '10_psychology_routine_review.md', '오전 거래에서 원칙을 어긴 무리한 진입으로 인해 3회 연속 스톱아웃(손절)을 당하여 당일 원금의 -6%의 큰 손실을 입었습니다. 본전 생각과 분노로 눈이 뒤집혀 비중을 올려 한 판으로 복수하려는 ''보폭 매매'' 충동이 폭발할 때, 파산을 막는 가장 강력한 멘탈 시스템 룰은?', '[{"time":"Today","open":100,"high":100,"low":100,"close":100}]'::jsonb, '[]'::jsonb, ARRAY['손실 만회를 위해 빌린 돈으로 100배 고배율 복수 베팅', '일일 손실 한도 도달에 따른 매매 강제 종료 및 격리', '주변 유료 전문가 추천 종목을 탐색해 즉각 매수', 'RSI 과매도 상태이므로 즉시 반대 숏 포지션 진입']::text[], 1, '연패를 겪은 후 홧김에 비중을 더 크게 실어 한 번에 본전을 찾으려는 보복 매매는 계좌를 하루 만에 휴지조각으로 만드는 가장 무서운 파산 유도 심리 상태입니다. 이를 막기 위해 하루 최대 손실 한도 한계선(예: 3회 손절 또는 원금의 5%)을 정해두고, 이 한계선 터치 시 즉시 차트를 종료하고 냉각기를 강제 집행하는 룰이 필수입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (101, '캔들/가격행동', '02_candlestick_price_action.md', '하락 추세 지속 도중 바닥권에서 몸통이 짧고 아래꼬리가 몸통의 2배 이상인 아래 캔들이 출현했습니다. 이 캔들의 명칭과 올바른 대응은?', '[{"time":"10:00","open":180,"high":183,"low":177,"close":178.5,"volume":100},{"time":"10:15","open":178.5,"high":180,"low":169.5,"close":171,"volume":88},{"time":"10:30","open":171,"high":172.5,"low":162,"close":163.5,"volume":124},{"time":"10:45","open":163.5,"high":165,"low":151.5,"close":153,"volume":128},{"time":"11:00","open":153,"high":154.5,"low":135,"close":151.5,"volume":121}]'::jsonb, '[]'::jsonb, ARRAY['역망치형 (Inverted Hammer) - 하락 경고 및 공매도 대기', '망치형 (Hammer) - 저점 지지 및 분할 매수 대기', '도지 (Doji) - 매수세와 매도세의 팽팽한 균형 및 관망', '하락 장악형 (Bearish Engulfing) - 추세 반전 및 즉시 손절']::text[], 1, '마지막 캔들은 아래꼬리가 긴 ''망치형(Hammer)'' 캔들로 하락 압력을 이겨내고 저가 매수세가 밀어 올렸음을 의미하는 대표적 상승 전환 신호입니다. 지지를 확인한 뒤 분할 매수 관점으로 대기해야 합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (102, '캔들/가격행동', '02_candlestick_price_action.md', '코인 가격가 장기간 급등한 뒤, 고점 부근에서 위꼬리가 매우 길고 몸통이 짧은 형태의 캔들이 발생했습니다. 이 캔들의 해석으로 가장 적절한 것은?', '[{"time":"Day 1","open":150,"high":162,"low":148.5,"close":157.5,"volume":113},{"time":"Day 2","open":157.5,"high":172.5,"low":156,"close":168,"volume":102},{"time":"Day 3","open":168,"high":187.5,"low":166.5,"close":184.5,"volume":103},{"time":"Day 4","open":184.5,"high":192,"low":180,"close":189,"volume":103},{"time":"Day 5","open":189,"high":217.5,"low":187.5,"close":190.5,"volume":96}]'::jsonb, '[]'::jsonb, ARRAY['유성형 (Shooting Star) - 고점 저항 및 하락 전환 예고', '망치형 (Hammer) - 저점 매수세 유입 및 상승 랠리 기대', '상승 장악형 (Bullish Engulfing) - 추세 반전 및 홀딩 유도', '도지 (Doji) - 추세 지속 가능성 및 일시 관망']::text[], 0, '급등세 끝에서 위꼬리가 몸통보다 훨씬 길게 솟아오른 캔들은 ''유성형(Shooting Star)''입니다. 장중 상승 시도를 강력한 차익 실현 및 매도 압력이 짓눌렀음을 보여주며, 하락 추세 전환의 강력한 경고 시그널입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (103, '캔들/가격행동', '02_candlestick_price_action.md', '직전의 음봉 몸통을 다음 날의 거대한 양봉 몸통이 완전히 감싸 안는 아래 형태가 포착되었습니다. 이 패턴의 이름과 신뢰도는?', '[{"time":"Day 1","open":147,"high":150,"low":142.5,"close":144,"volume":89},{"time":"Day 2","open":144,"high":145.5,"low":138,"close":139.5,"volume":112},{"time":"Day 3","open":139.5,"high":142.5,"low":132,"close":133.5,"volume":126},{"time":"Day 4","open":130.5,"high":153,"low":129,"close":151.5,"volume":105}]'::jsonb, '[]'::jsonb, ARRAY['하락 장악형 (Bearish Engulfing) - 추세 반전 신뢰도 낮음', '상승 장악형 (Bullish Engulfing) - 매수 전환 신뢰도 높음', '상승 관통형 (Piercing Line) - 중간 강도의 반전 신호', '석별형 (Evening Star) - 상승 추세 종결 신호']::text[], 1, '전일의 하락 음봉 몸통을 다음 날의 장대 양봉이 완전히 덮어버리는 형태를 ''상승 장악형(Bullish Engulfing)'' 패턴이라고 합니다. 하락 추세 끝에서 나타날 경우 단기 하락세가 종료되고 강력한 매수세가 들어왔음을 뜻해 전환 신뢰도가 매우 높습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (104, '캔들/가격행동', '01_chart_market_basics.md', '시가와 종가가 거의 일치하여 몸통이 거의 없고 위아래 꼬리만 달린 십자(+) 모양 캔들이 출현했습니다. 이 캔들에 대한 올바른 해석은?', '[{"time":"Day 1","open":225,"high":232.5,"low":222,"close":228,"volume":97},{"time":"Day 2","open":228,"high":234,"low":226.5,"close":231,"volume":122},{"time":"Day 3","open":231,"high":238.5,"low":225,"close":231,"volume":114}]'::jsonb, '[]'::jsonb, ARRAY['상승세 동력 상실로 인한 추세의 하방 반전', '매수/매도 세력 균형에 따른 도지(Doji) 횡보', '매도세 지배에 따른 즉각적인 숏 포지션 진입', '하락 세력 이탈로 인한 즉각적인 상승 랠리']::text[], 1, '시가와 종가가 거의 같은 십자 모양의 캔들은 ''도지(Doji)'' 캔들입니다. 이는 힘의 균형이 팽팽함을 시사하며, 기존 추세의 힘이 빠지고 잠재적인 방향성 전환(상승/하락 모두 포함)의 변곡점이 다가오고 있음을 의미합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (105, '캔들/가격행동', '02_candlestick_price_action.md', '상승 추세 고점에서 직전 양봉의 몸통을 거대 음봉이 아래로 덮어버리는 캔들 조합이 발생했습니다. 이 현상을 의미하는 용어는?', '[{"time":"Day 1","open":180,"high":187.5,"low":178.5,"close":186,"volume":119},{"time":"Day 2","open":186,"high":195,"low":184.5,"close":193.5,"volume":121},{"time":"Day 3","open":195,"high":196.5,"low":172.5,"close":174,"volume":127}]'::jsonb, '[]'::jsonb, ARRAY['하락 장악형 (Bearish Engulfing) - 고점 하락 전환 예고', '상승 장악형 (Bullish Engulfing) - 고점 돌파 랠리 예고', '하락 잉태형 (Harami) - 기존 하락세의 일시 둔화', '샛별형 (Morning Star) - 바닥권 상승 반전 예고']::text[], 0, '고점에서 직전 양봉을 음봉이 감싸 안은 형태는 ''하락 장악형(Bearish Engulfing)''입니다. 매수 세력을 매도 공급이 압도했다는 명백한 증거로, 코인 가격 추세가 하락으로 반전할 리스크가 큽니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (106, '시장구조/SR', '03_market_structure.md', '코인 가격가 장기 저항선인 225달러를 거래량 실린 강한 캔들로 돌파한 뒤, 다시 225달러 부근으로 내려와 버티고 있습니다. 가장 안전한 진입 방식은?', '[{"time":"Day 1","open":210,"high":222,"low":208.5,"close":217.5,"volume":80},{"time":"Day 2","open":217.5,"high":223.5,"low":214.5,"close":216,"volume":91},{"time":"Day 3","open":216,"high":234,"low":214.5,"close":231,"volume":89},{"time":"Day 4","open":231,"high":232.5,"low":223.5,"close":226.5,"volume":389},{"time":"Day 5","open":226.5,"high":229.5,"low":225,"close":228,"volume":324}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":225},{"x":4,"y":225}],"label":"돌파된 저항선 -> 지지선 전환선","color":"#3b82f6"}]'::jsonb, ARRAY['돌파 시점에 시장가로 즉시 진입하는 추격 매수', '돌파 후 저항선의 지지선 전환(Retest) 확인 시 진입', '이전 최저가 부근인 210달러 조정 시까지 대기 매수', '돌파 후 즉시 단기 조정을 예상한 역추세 숏 진입']::text[], 1, '저항선이 강하게 뚫리면 역할 전환(Role Reversal)에 의해 신규 지지선으로 바뀝니다. 돌파 시점에 뇌동매매하기보다는 돌파된 선 부근으로 코인 가격가 눌려 지지(Retest)를 완성할 때 진입하는 것이 리스크 대비 기대 수익이 큽니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (107, '거래량/유동성', '05_volume_liquidity.md', '코인 가격가 저항선 위로 거래량 없이 장대양봉을 뿜어 올렸으나, 다음 날 곧바로 장대음봉으로 밀어붙이며 저항선 아래로 내려왔습니다. 이 현상의 명칭은?', '[{"time":"Day 1","open":147,"high":151.5,"low":145.5,"close":150,"volume":80},{"time":"Day 2","open":150,"high":153,"low":148.5,"close":151.5,"volume":102},{"time":"Day 3","open":151.5,"high":165,"low":150,"close":162,"volume":30},{"time":"Day 4","open":162,"high":163.5,"low":142.5,"close":144,"volume":17}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":153},{"x":3,"y":153}],"label":"저항선","color":"#ef4444"}]'::jsonb, ARRAY['진짜 상승 돌파 (True Breakout)', '불 트랩 (Bull Trap) - 매수자 청산 유도 가짜 돌파', '베어 트랩 (Bear Trap) - 매도자 청산 유도 가짜 하방', '골든 크로스 (Golden Cross) - 이평선 돌파']::text[], 1, '저항선을 일시적으로 뚫었다가 대량 매도세와 함께 직후 캔들에서 하방으로 원상복귀하는 현상을 ''불 트랩(Bull Trap/가짜 돌파)''이라고 합니다. 돌파 후 리테스트를 기다리지 않고 급히 추격 매수했던 투자자들이 고점에 물리는 대표적 함정입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (108, '시장구조/SR', '01_chart_market_basics.md', '아래 차트에서 3번 연속 강하게 반등하며 가격 하락을 저지해 준 주요 가격대는 무엇을 의미하나요?', '[{"time":"Day 1","open":150,"high":153,"low":135,"close":136.5,"volume":86},{"time":"Day 2","open":136.5,"high":147,"low":135,"close":145.5,"volume":86},{"time":"Day 3","open":145.5,"high":157.5,"low":144,"close":156,"volume":101},{"time":"Day 4","open":156,"high":159,"low":136.5,"close":138,"volume":108},{"time":"Day 5","open":138,"high":150,"low":135,"close":148.5,"volume":120}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":135},{"x":4,"y":135}],"label":"135달러선","color":"#10b981"}]'::jsonb, ARRAY['강력한 저항선 (Resistance Line) - 매도 매물대', '강력한 지지선 (Support Line) - 매수 매물대', '골든크로스 수렴선 - 이평선 밀집대', '이격도 붕괴선 - 가격 과열 분기점']::text[], 1, '특정 가격(135달러)에 접근할 때마다 대기 중이던 저가 매수세가 유입되어 코인 가격의 추가 하락을 방어해 준 이 라인은 ''강력한 지지선(Support Line)''입니다. 이탈하기 전까지는 손절 라인을 바로 밑에 두고 진입하기에 가장 손익비 좋은 구간입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (109, '거래량/유동성', '05_volume_liquidity.md', '지지선 아래로 코인 가격가 이탈하여 공매도가 폭증했으나, 이내 거래량이 급증하며 양봉으로 지지선을 회복한 뒤 반등을 시작했습니다. 이 현상의 명칭은?', '[{"time":"Day 1","open":180,"high":183,"low":177,"close":178.5,"volume":92},{"time":"Day 2","open":178.5,"high":180,"low":165,"close":166.5,"volume":104},{"time":"Day 3","open":166.5,"high":184.5,"low":165,"close":183,"volume":93}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":172.5},{"x":2,"y":172.5}],"label":"지지선","color":"#10b981"}]'::jsonb, ARRAY['불 트랩 (Bull Trap) - 가짜 상방 돌파', '베어 트랩 (Bear Trap) - 가짜 하방 이탈', '리테스트 실패 - 지지선 붕괴', '추세 추종 돌파 - 하방 랠리 가속']::text[], 1, '지지선을 아래로 뚫고 내려가 하락세가 지속될 것처럼 유도한 뒤, 매물을 털어내고 강력하게 다시 반등해 올리는 현상을 ''베어 트랩(Bear Trap)''이라고 합니다. 하락 돌파로 생각하고 공매도를 치거나 손절했던 사람들의 손실을 강제하며 가격이 급등하게 만듭니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (110, '시장구조/SR', '04_patterns_breakout.md', '저항선을 뚫어내기 직전 돌파 전조 현상 중 하나인 ''지지점 상승''의 특징을 골라보세요.', '[{"time":"Day 1","open":150,"high":157.5,"low":135,"close":153,"volume":118},{"time":"Day 2","open":153,"high":157.5,"low":139.5,"close":154.5,"volume":84},{"time":"Day 3","open":154.5,"high":157.5,"low":144,"close":156,"volume":125}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":157.5},{"x":2,"y":157.5}],"label":"저항선 (105)","color":"#ef4444"}]'::jsonb, ARRAY['저항선 부근에서 고점들이 점점 급락하며 붕괴하는 현상', '저항선 부근에서 저점들을 높여가며 밀어 올리는 수렴 현상', '거래량이 완전히 소멸하여 긴 횡보 상태를 보이는 현상', '지속적인 매도세로 인해 갑작스럽게 급락하는 현상']::text[], 1, '저항을 뚫지 못하고 밀려 내려올 때, 이전 저점보다 높은 지점에서 저점을 계속 잡아 올려주는 것은 매도 압력보다 매수 압력이 점점 올라오고 있음을 의미합니다. 수렴 끝에 돌파가 나타날 신뢰도가 매우 높습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (111, '추세/레짐', '03_market_structure.md', '저점들을 연결한 우상향 상승 추세선 아래로 캔들의 종가(마감가격)가 이탈했습니다. 기술적 분석 관점의 올바른 해석은 무엇입니까?', '[{"time":"W-5","open":150,"high":157.5,"low":150,"close":154.5,"volume":104},{"time":"W-4","open":154.5,"high":165,"low":153,"close":162,"volume":104},{"time":"W-3","open":162,"high":163.5,"low":157.5,"close":159,"volume":111},{"time":"W-2","open":159,"high":172.5,"low":160.5,"close":169.5,"volume":121},{"time":"Today","open":169.5,"high":171,"low":154.5,"close":156,"volume":104}]'::jsonb, '[{"type":"line","points":[{"x":0,"y":150},{"x":2,"y":157.5},{"x":4,"y":165}],"label":"상승 추세선","color":"#10b981"}]'::jsonb, ARRAY['추세선 이탈은 영향이 없으므로 비중 유지', '상승 추세 붕괴로 하락 반전 대비 비중 축소', '일시적인 속임수이므로 추가 불타기 진입', '채널 상단 도달에 따른 즉각적인 매수 대응']::text[], 1, '신뢰받던 우상향 상승 추세선 하방으로 캔들의 종가가 이탈 마감하는 것은 매수 중심의 시장 주도권이 붕괴했음을 뜻합니다. 지지를 잃은 하락 가속화 리스크에 대비해야 합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (112, '추세/레짐', '07_multitimeframe_regime.md', '아래 차트에서 고점들과 저점들이 일정한 평행 통로를 그리며 하락하고 있습니다. 채널 하단에 도달했을 때 단기 반등을 목표로 하는 매매의 명칭과 관점은?', '[{"time":"Day 1","open":225,"high":228,"low":202.5,"close":210,"volume":91},{"time":"Day 2","open":210,"high":220.5,"low":208.5,"close":217.5,"volume":112},{"time":"Day 3","open":217.5,"high":219,"low":192,"close":195,"volume":120},{"time":"Day 4","open":195,"high":207,"low":193.5,"close":204,"volume":106},{"time":"Day 5","open":204,"high":205.5,"low":177,"close":180,"volume":133}]'::jsonb, '[{"type":"channel","points":[{"x":0,"y":225},{"x":4,"y":202.5},{"x":0,"y":202.5},{"x":4,"y":180}],"label":"하향 평행 채널","color":"#f59e0b"}]'::jsonb, ARRAY['추세 추종 매매 - 대세 상승이므로 장기 보유', '채널 하단 반등 매매 - 단기 역추세 매수 대응', '양방향 물타기 매매 - 평단가를 낮춰 탈출 대기', '돌파 매매 - 채널 하방 붕괴 확정 시 매수 대응']::text[], 1, '가격이 평행한 하락 터널 내에서 움직이는 ''하향 평행 채널(Descending Channel)''입니다. 채널 하단 라인 터치 시에는 기술적 단기 반등이 자주 출현하므로, 손절선을 짧게 잡고 반등 타점을 노리는 역추세(Counter-trend) 트레이딩이 가능합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (113, '추세/레짐', '03_market_structure.md', '우상향 상승 평행 채널의 상단 저항선 부근까지 코인 가격가 도달했습니다. 합리적인 추세 채널 트레이더의 대응은?', '[{"time":"Day 1","open":150,"high":153,"low":148.5,"close":151.5,"volume":106},{"time":"Day 2","open":151.5,"high":162,"low":151.5,"close":160.5,"volume":84},{"time":"Day 3","open":160.5,"high":163.5,"low":156,"close":157.5,"volume":115},{"time":"Day 4","open":157.5,"high":172.5,"low":157.5,"close":171,"volume":92},{"time":"Day 5","open":171,"high":174,"low":168,"close":169.5,"volume":100}]'::jsonb, '[{"type":"channel","points":[{"x":0,"y":153},{"x":4,"y":172.5},{"x":0,"y":148.5},{"x":4,"y":168}],"label":"상승 평행 채널","color":"#10b981"}]'::jsonb, ARRAY['채널 상방 돌파를 예상한 고배율 레버리지 매수', '채널 상단 저항에 따른 분할 익절 및 대기', '채널 중간 조정 시 지정을 통한 시장가 추격', '채널 붕괴 신호에 따른 전량 기계적 손절']::text[], 1, '상승 채널이라고 해도 상단 저항선에 닿으면 다시 채널 하단이나 중심선까지 조정을 받을 가능성이 매우 큽니다. 따라서 고점 영역에서의 추격매수를 금지하고, 기존 포지션을 분할 익절하는 기회로 삼아야 합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (114, '추세/레짐', '01_chart_market_basics.md', '고점들을 잇는 우하향 하락 추세선을 코인 가격가 대량의 거래량을 동반하며 장대양봉 종가로 상향 돌파(Breakout)했습니다. 의미하는 시그널은?', '[{"time":"Day 1","open":195,"high":198,"low":187.5,"close":190.5,"volume":112},{"time":"Day 2","open":190.5,"high":192,"low":180,"close":183,"volume":96},{"time":"Day 3","open":183,"high":184.5,"low":172.5,"close":175.5,"volume":112},{"time":"Day 4","open":175.5,"high":192,"low":174,"close":190.5,"volume":99}]'::jsonb, '[{"type":"line","points":[{"x":0,"y":196.5},{"x":2,"y":183},{"x":3,"y":177}],"label":"하락 추세선","color":"#ef4444"}]'::jsonb, ARRAY['하락 추세 지속에 따른 숏 포지션 추가 매수', '하락 추세 돌파 및 상승 전환 가능성에 따른 매수', '속임수 돌파를 예상한 즉시 반대 숏 포지션 진입', '추세와 무관하게 횡보 흐름으로 판단해 관망']::text[], 1, '중요한 하락 추세선을 코인 가격 몸통이 확실하게 뚫고 마감하는 것은 기존 하락 관성의 지배력이 종료되고 상승 추세로 돌아설 수 있는 가장 대표적인 추세 전환(Reversal) 확인 시그널입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (115, '추세/레짐', '03_market_structure.md', '추세선 작도 시 신뢰도를 판단하는 가장 중요한 규칙은 무엇인가요?', '[{"time":"Day 1","open":150,"high":151.5,"low":150,"close":151.5,"volume":93},{"time":"Day 2","open":151.5,"high":157.5,"low":153,"close":156,"volume":118}]'::jsonb, '[]'::jsonb, ARRAY['차트상 선이 정배열로 정돈되어 그려질 때', '최소 3개 이상의 뚜렷한 저점/고점 터치 확인 시', '가파른 각도로 90도에 가깝게 작도될 때', '보조지표와 결합하여 수평으로 그려질 때']::text[], 1, '두 점만으로도 선을 그릴 수 있지만, 3번째 터치(3rd Touch)에서 정확한 지지나 저항을 보이고 반등해 주는 순간부터 시장 참여자들이 공식 인지하는 신뢰도 높은 추세선이 됩니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (116, '패턴/돌파', '04_patterns_breakout.md', '머리와 양쪽 어깨 형태를 그리며 넥라인 지지선(144달러)을 위태롭게 지탱하다가 하방으로 강한 캔들이 이탈했습니다. 숏(매도) 포지션 진입 시점은?', '[{"time":"Day 1","open":150,"high":172.5,"low":147,"close":165,"volume":96},{"time":"Day 2","open":165,"high":195,"low":142.5,"close":157.5,"volume":92},{"time":"Day 3","open":157.5,"high":171,"low":144,"close":165,"volume":102},{"time":"Day 4","open":165,"high":166.5,"low":139.5,"close":141,"volume":118}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":144},{"x":3,"y":144}],"label":"넥라인 지지선","color":"#ef4444"}]'::jsonb, ARRAY['머리 꼭대기(195달러) 부근에서 예측 숏 진입', '오른쪽 어깨가 올라가고 있을 때 돌파 전 선진입', '저점들을 연결한 넥라인의 하방 돌파 완료 시', '패턴 완성과 무관하게 오른쪽 어깨 끝에서 대기']::text[], 2, '헤드앤숄더(Head & Shoulders) 패턴은 오른쪽 어깨를 그린 후, 저점 지지선인 ''넥라인(Neckline)''을 거래량을 실어 하방 돌파해야 최종 완성이 선언됩니다. 그전에 진입하면 넥라인 반등 시 극심한 손실을 입습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (117, '패턴/돌파', '04_patterns_breakout.md', '하락 추세 끝에서 코인 가격가 비슷한 깊이의 바닥을 두 번(이중바닥) 형성한 뒤, 중간 고점 저항선(넥라인)을 돌파했습니다. 향후 예상 방향성과 매수 타점은?', '[{"time":"Day 1","open":150,"high":150,"low":120,"close":127.5,"volume":108},{"time":"Day 2","open":127.5,"high":142.5,"low":126,"close":141,"volume":123},{"time":"Day 3","open":141,"high":142.5,"low":118.5,"close":123,"volume":119},{"time":"Day 4","open":123,"high":148.5,"low":121.5,"close":147,"volume":116}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":142.5},{"x":3,"y":142.5}],"label":"넥라인 (95)","color":"#3b82f6"}]'::jsonb, ARRAY['추가 폭락 가능성에 따른 전량 손절 대응', 'W 패턴 이중 바닥 완성 및 넥라인 돌파 시 매수', '박스권 횡보 판단에 따른 무대응 및 관망', '이중 바닥의 하방 이탈을 예상한 숏 포지션 진입']::text[], 1, 'W자 모양의 ''이중 바닥형(Double Bottom)'' 패턴입니다. 코인 가격가 하락을 멈추고 바닥을 두 차례 단단히 지지해 준 뒤 중간 봉우리(넥라인 142.50달러)를 돌파해 마감하면 추세가 상승으로 강하게 전환될 가능성이 매우 높습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (118, '패턴/돌파', '04_patterns_breakout.md', '급격한 기둥식 코인 가격 폭등(깃대) 후, 완만한 하향 평행 채널(깃발) 모양으로 횡보/수렴하다가 채널 상단을 강하게 돌파했습니다. 이 패턴과 예상 목표가는?', '[{"time":"Day 1","open":75,"high":120,"low":73.5,"close":117,"volume":96},{"time":"Day 2","open":117,"high":118.5,"low":108,"close":111,"volume":121},{"time":"Day 3","open":111,"high":114,"low":105,"close":106.5,"volume":105},{"time":"Day 4","open":106.5,"high":127.5,"low":105,"close":124.5,"volume":113}]'::jsonb, '[]'::jsonb, ARRAY['이중 천정형 패턴 - 고점 도달 시 숏 진입', '불 플래그 패턴 - 깃발 돌파 시 추가 상승 기대', '헤드앤숄더 패턴 - 넥라인 하방 돌파 타겟', '대칭 삼각수렴 패턴 - 변동성 축소 후 돌파 대기']::text[], 1, '대표적 강세 지속 패턴인 ''불 플래그(Bull Flag)''입니다. 급격한 상승(깃대) 뒤 숨 고르기 채널(깃발)을 상방 돌파하면, 이전 상승 파동의 크기(깃대 높이)만큼 추가로 수직 랠리를 시작하는 관성이 있습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (119, '패턴/돌파', '04_patterns_breakout.md', '상승 추세의 천정권에서 코인 가격가 동일한 가격 저항을 두 번 확인하며 M자 모양을 만든 뒤, 두 고점 사이의 저점 지지선인 넥라인(180달러)을 이탈했습니다. 올바른 해석은?', '[{"time":"Day 1","open":150,"high":210,"low":148.5,"close":202.5,"volume":99},{"time":"Day 2","open":202.5,"high":204,"low":180,"close":183,"volume":87},{"time":"Day 3","open":183,"high":210,"low":181.5,"close":207,"volume":127},{"time":"Day 4","open":207,"high":208.5,"low":172.5,"close":174,"volume":112}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":180},{"x":3,"y":180}],"label":"넥라인 (120)","color":"#ef4444"}]'::jsonb, ARRAY['상승 추세의 지속 연장에 따른 추가 매수', '이중 천정형(M 패턴) 완성에 따른 하락 반전 대비', '단기 조정에 따른 일시적 횡보 박스권 진입', '방향성 없는 일상적인 잔파동으로 판단해 홀딩']::text[], 1, '고점에서 지지받지 못하고 형성된 M자형 ''이중 천정형(Double Top)'' 패턴입니다. 두 차례 강력한 저항벽(210달러)을 넘지 못하고 넥라인(180달러)마저 붕괴했으므로 하방 추세가 가속화된다는 신호입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (120, '패턴/돌파', '04_patterns_breakout.md', '고점 저항선은 수평(평평함)을 유지하고 있으나, 저점 지지선은 점점 우상향하며 좁게 수렴하는 차트 형태의 명칭과 일반적인 돌파 방향은?', '[{"time":"Day 1","open":120,"high":150,"low":120,"close":142.5,"volume":103},{"time":"Day 2","open":142.5,"high":150,"low":129,"close":147,"volume":103},{"time":"Day 3","open":147,"high":150,"low":138,"close":148.5,"volume":125}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":150},{"x":2,"y":150}],"label":"수평 저항선","color":"#ef4444"},{"type":"line","points":[{"x":0,"y":120},{"x":1,"y":129},{"x":2,"y":138}],"label":"상승 지지선","color":"#10b981"}]'::jsonb, ARRAY['디센딩 트라이앵글 - 일반적으로 하방 돌파 기대', '어센딩 트라이앵글 - 매수 압력 우위로 상방 돌파 기대', '헤드앤숄더 패턴 - 넥라인 하방 돌파 기대', '상향 평행 채널 - 상하단 터치식 채널 매매 기대']::text[], 1, '고점 저항은 평평하고 저점은 계속 높아지는 삼각수렴을 ''어센딩 트라이앵글(Ascending Triangle)''이라고 합니다. 위로 갈수록 저점이 계속 올라가는 현상은 매수세가 가격을 위로 계속 압박하고 있음을 증명하며, 대개 저항선(150달러)을 상향 뚫고 오르는 확률이 높습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (121, '지표/컨플루언스', '06_technical_indicators.md', '코인 가격는 매일 하락하여 신저가를 갱신하고 있으나, RSI 보조지표의 저점은 점점 높아지는 현상을 발견했습니다. 올바른 용어와 매매 대응법은?', '[{"time":"D-4","open":165,"high":168,"low":147,"close":150,"volume":83},{"time":"D-3","open":150,"high":156,"low":144,"close":147,"volume":120},{"time":"D-2","open":147,"high":151.5,"low":138,"close":141,"volume":110},{"time":"D-1","open":141,"high":145.5,"low":139.5,"close":144,"volume":118},{"time":"Today","open":144,"high":148.5,"low":142.5,"close":147,"volume":107}]'::jsonb, '[]'::jsonb, ARRAY['하락 다이버전스 - 가격 상승 둔화에 따른 공매도', '상승 다이버전스 - 하락 둔화 및 반등 신호로 매수', '데드 크로스 - 이평선 하방 교차에 따른 관망', '과매수 이탈 시그널 - 단기 반등에 따른 매수']::text[], 1, '코인 가격의 가격 저점은 낮아지나 보조지표(RSI)의 운동 저점이 높아지는 현상을 ''상승 다이버전스(Bullish Divergence)''라고 합니다. 이는 하방 에너지의 실질적 소멸과 상승 압력의 내부 응축을 의미하는 기술적 분석에서 가장 신뢰도 높은 추세 전환 시그널입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (122, '지표/컨플루언스', '06_technical_indicators.md', '코인 가격는 급격히 치솟으며 최고가 갱신 랠리를 이어가고 있으나, RSI 지표의 고점은 계속 낮아지고 있습니다. 이 현상을 지칭하는 명칭과 대처법은?', '[{"time":"Day 1","open":150,"high":180,"low":148.5,"close":177,"volume":92},{"time":"Day 2","open":177,"high":183,"low":172.5,"close":180,"volume":120},{"time":"Day 3","open":180,"high":202.5,"low":178.5,"close":199.5,"volume":107}]'::jsonb, '[]'::jsonb, ARRAY['하락 다이버전스 - 매수 둔화 및 하락 우려로 익절', '상승 다이버전스 - 추가 급등 기대로 신규 매수', '골든 크로스 - 추세 강화에 따른 홀딩', '볼린저 밴드 스퀴즈 - 변동성 수축 후 돌파']::text[], 0, '코인 가격는 계속 고점을 높이고 있으나 보조지표의 고점은 꺾여 낮아지는 현상을 ''하락 다이버전스(Bearish Divergence)''라고 합니다. 이는 매수세의 힘이 표면적인 가격 상승에 비해 실질적으로 빠르게 축소되고 있음을 경고하며, 조만간 큰 급락이 발생할 확률이 높습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (123, '지표/컨플루언스', '06_technical_indicators.md', '이동평균선(EMA) 20일선(단기)이 50일선(중기)을 아래에서 위로 강하게 뚫고 솟구쳐 올랐습니다. 이 교차 현상의 정식 명칭은?', '[{"time":"Day 1","open":150,"high":153,"low":147,"close":148.5,"volume":109},{"time":"Day 2","open":148.5,"high":156,"low":148.5,"close":154.5,"volume":116},{"time":"Day 3","open":154.5,"high":165,"low":154.5,"close":163.5,"volume":121}]'::jsonb, '[]'::jsonb, ARRAY['데드 크로스 - 단기 이평의 하방 교차로 매도 신호', '골든 크로스 - 단기 이평의 상방 교차로 매수 신호', '볼린저 스퀴즈 - 변동성 수축 및 돌파 신호', '다이버전스 수렴 - 지표와 가격의 동반 횡보']::text[], 1, '단기 이평선이 장기 이평선을 위로 치고 올라가는 현상을 ''골든 크로스(Golden Cross)''라고 합니다. 이는 최근 매수 평단가가 장기 평균가보다 확연히 높아졌음을 시사하며, 상승 추세가 본 궤도에 올랐음을 입증해 줍니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (124, '지표/컨플루언스', '07_multitimeframe_regime.md', '매우 강력한 원웨이 폭락장 속에서 RSI 지표가 20(과매도 영역) 이하로 깊이 내려왔습니다. 이를 보고 ''과매도 반등''을 노리며 기계적 시장가 풀매수를 때렸을 때 나타나는 가장 빈번한 오류는?', '[{"time":"Day 1","open":150,"high":151.5,"low":132,"close":133.5,"volume":119},{"time":"Day 2","open":133.5,"high":135,"low":112.5,"close":114,"volume":15},{"time":"Day 3","open":114,"high":115.5,"low":93,"close":94.5,"volume":15}]'::jsonb, '[]'::jsonb, ARRAY['하락 추세 즉시 종료 및 V자 상승 반등 성공', '강력한 하락장에서의 지표 과매도 고착화 리스크', '거래량 급감으로 인한 호가 정지 및 상장 폐지', '코인 가격의 즉각적인 박스권 횡보 및 변동성 축소']::text[], 1, 'RSI 30 이하 과매도 영역은 반등 신호이기도 하지만, 추세가 지나치게 강력한 하락장일 때는 지표만 과매도 구역에 쳐박힌 채 가격은 계속 급락하는 ''과매도 고착화(Oversold Embedded)'' 상태가 이어집니다. 다이버전스나 캔들 반전형 확인 없이 수치만 보고 들어가는 매수는 깡통으로 가는 지름길입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (125, '지표/컨플루언스', '06_technical_indicators.md', '코인 가격의 변동성이 극도로 축소되며 볼린저 밴드의 폭이 매우 좁아지는 ''스퀴즈(Squeeze)'' 현상이 나타났습니다. 이후 기대되는 시장 변동성의 원리는 무엇인가요?', '[{"time":"Day 1","open":150,"high":151.5,"low":148.5,"close":150,"volume":112},{"time":"Day 2","open":150,"high":150,"low":148.5,"close":148.5,"volume":98},{"time":"Day 3","open":148.5,"high":150,"low":148.5,"close":150,"volume":103}]'::jsonb, '[]'::jsonb, ARRAY['변동성 사멸로 인한 장기 횡보 및 거래 정지', '밴드 스퀴즈 후 변동성 팽창에 따른 추세 분출', '코인 가격의 하방 붕괴로 인한 강한 하락 파동 시작', '이평선들의 수평 정렬에 따른 완전한 추세 고정']::text[], 1, '볼린저 밴드의 수축(Squeeze)은 시장의 숨 고르기 및 힘 모으기를 뜻합니다. 에너지가 최대한 압축된 후에는 밴드 상단 혹은 하단선을 이탈하며 매우 거대한 변동성 팽창(Expansion) 추세가 시작되므로, 방향성을 유심히 지켜봐야 합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (126, '리스크/심리', '09_risk_position_management.md', '총 투자 원금은 1,500만 원이며, 1회 거래 시 최대 손실 허용액을 원금의 2%(30만 원)로 제한하는 ''2% 룰''을 지키려 합니다. 진입하려는 종목의 손절 라인 폭이 -5%일 때, 최대 매수(진입) 가능 금액은 얼마인가요?', '[{"time":"Day 1","open":15000,"high":15750,"low":14700,"close":15300,"volume":100},{"time":"Day 2","open":15300,"high":15450,"low":15000,"close":15000,"volume":108}]'::jsonb, '[]'::jsonb, ARRAY['1,500만 원 (원금 전액 진입)', '300만 원 (원금의 20% 진입)', '600만 원 (원금의 40% 진입)', '750만 원 (원금의 50% 진입)']::text[], 2, '2% 룰에 기초한 포지션 사이징 공식은 `진입금액 = (총원금 * 리스크비율) / 손절비율` 입니다. 따라서 `30만 원 / 0.05 = 600만 원`이 됩니다. 600만 원어치 알트코인을 샀을 때 가격이 -5% 떨어져 강제 손절을 맞아도 내 계좌 총액에서 손실을 보는 돈은 정확히 2%인 30만 원으로 통제됩니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (127, '리스크/심리', '09_risk_position_management.md', '어느 알트코인에 15,000원에 매수 진입합니다. 손절 라인은 14,250원(-5%)에 배치하고, 목표가는 17,250원(+15%)에 설정했습니다. 이 트레이딩 시나리오의 손익비(Risk-to-Reward Ratio)는 얼마입니까?', '[{"time":"Today","open":15000,"high":15000,"low":15000,"close":15000}]'::jsonb, '[]'::jsonb, ARRAY['1 : 1 (동일한 기대 수익과 리스크)', '1 : 2 (기대 수익이 리스크의 2배)', '1 : 3 (기대 수익이 리스크의 3배)', '2 : 1 (기대 수익이 리스크의 0.5배)']::text[], 2, '손절 폭(750원) 대비 익절 폭(2,250원)의 비례를 의미하므로 `1,500 / 500 = 3`, 즉 손익비는 1:3이 됩니다. 이처럼 잃는 돈의 최소 2~3배를 벌 수 있는 손익비 높은 구간만 반복적으로 거래해야 장기적으로 계좌가 생존합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (128, '리스크/심리', '09_risk_position_management.md', '손익비를 엄격히 통제하여 항상 기대 손실의 2배를 버는 매매(손익비 1:2)만 고집합니다. 이 경우 내 계좌 잔고가 손실 없이 제자리걸음(본전)을 유지하기 위해 필요한 수학적인 최소 승률(Win Rate)은 얼마인가요?', '[{"time":"Today","open":150,"high":150,"low":150,"close":150}]'::jsonb, '[]'::jsonb, ARRAY['50.0% (최소 절반 이상 성공)', '33.3% (3번 중 1번 성공으로 본전)', '25.0% (4번 중 1번 성공으로 본전)', '66.6% (3번 중 2번 성공으로 본전)']::text[], 1, '손익비가 1:2일 경우, 1번 이기면 +2를 벌고 2번 지면 -2를 잃으므로 3번 매매 중 1번만 이겨도 누적 수익은 0이 됩니다. 즉 손익비를 1:2 이상으로 유지하면 수학적으로 승률이 겨우 33.3%만 나와도 절대 파산하지 않고 계좌가 우상향할 발판이 마련됩니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (129, '셋업/실행', '08_setup_entry_exit.md', '15,000원에 산 알트코인이 22,500원까지 올랐습니다. 이익을 보존하면서 상승세를 끝까지 타기 위해, 최고점 대비 10% 하방 이탈 시 즉시 자동 익절되는 ''추적 손절매(Trailing Stop)''를 적용했습니다. 최고점 22,500원 달성 후 코인 가격가 조정받을 때 실제로 청산(익절)되는 가격은 얼마인가요?', '[{"time":"Day 1","open":15000,"high":18000,"low":14850,"close":17850,"volume":81},{"time":"Day 2","open":17850,"high":22500,"low":17700,"close":22200,"volume":99}]'::jsonb, '[]'::jsonb, ARRAY['15,000원 (본전 수준 청산)', '20,250원 (최고점 대비 10% 하방 청산)', '21,000원 (최고점 대비 6.6% 하방 청산)', '18,000원 (최고점 대비 20% 하방 청산)']::text[], 1, '추적 손절매(Trailing Stop)는 가격 상승에 따라 청산 가격을 자동으로 올려주는 주문입니다. 최고점 22,500원을 기록했으므로 청산 트리거 라인은 최고점에서 10% 차감된 `15,000 * 0.9 = 20,250원`으로 확정 셋업되며, 코인 가격가 20,250원을 건드리는 순간 자동 이익실현됩니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (130, '리스크/심리', '09_risk_position_management.md', '레버리지 10배를 적용하여 이더리움 롱(매수) 포지션을 구축했습니다. 만약 이더리움 가격이 매수가 대비 몇 % 역방향으로 등락하면 내 투자 원금이 100% 강제 청산(증거금 완전 소멸)당할까요?', '[{"time":"Today","open":75000,"high":75150,"low":74850,"close":75000}]'::jsonb, '[]'::jsonb, ARRAY['5.0% 하락 시', '10.0% 하락 시', '20.0% 하락 시', '100.0% 하락 시']::text[], 1, '레버리지 비율과 청산 거리 비율은 역수 관계입니다. `100% / 레버리지 배수` 공식에 따라, 10배 레버리지는 코인 가격가 내 베팅의 반대 방향으로 단 10%만 움직여도 투자 원금이 전부 증발하고 포지션이 강제 종료(Liquidation)됩니다. 고배율 레버리지가 파산의 지름길인 이유입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (131, '캔들/가격행동', '02_candlestick_price_action.md', '상승 추세 고점 영역(225달러선)에서 몸통이 매우 작고 아래꼬리가 긴 행잉맨(Hanging Man) 캔들이 출현한 이후, 다음 날 시가가 전일 종가보다 큰 갭을 그리며 낮게 하락 출발(217.50달러)했습니다. 포지션을 보유한 스윙 트레이더로서 가장 적절한 위기 대응 행동은 무엇입니까?', '[{"time":"Day 1","open":180,"high":187.5,"low":178.5,"close":186,"volume":92},{"time":"Day 2","open":186,"high":202.5,"low":184.5,"close":201,"volume":106},{"time":"Day 3","open":201,"high":222,"low":199.5,"close":219,"volume":120},{"time":"Day 4","open":219,"high":226.5,"low":210,"close":220.5,"volume":115},{"time":"Day 5","open":211.5,"high":214.5,"low":202.5,"close":204,"volume":131}]'::jsonb, '[]'::jsonb, ARRAY['상승 랠리를 기대로 보유 비중 확대 및 추격 매수', '일시적 속임수(휩소) 판단으로 추가 레버리지 매수', '행잉맨 출현 후 갭하락에 따른 전량 또는 일부 정리', '조치 없이 전고점 돌파 시까지 무기한 관망 및 홀딩']::text[], 2, '고가권에서 나타난 행잉맨(Hanging Man)은 잠재적 하락 전환 신호이며, 특히 다음날 갭하락 음봉으로 직전 행잉맨의 저가를 깨고 내려가는 움직임은 강력한 하락 컨펌 시그널입니다. 따라서 이 시점에서는 즉시 비중을 전량 정리하거나 최소 절반 이상 매도하여 리스크를 통제하는 것이 정석입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (132, '캔들/가격행동', '01_chart_market_basics.md', '지속적인 하락 추세 도중 바닥권(120달러선)에서 시가와 종가가 일치하고 긴 아래꼬리를 단 십자 형태의 도지(Doji) 캔들이 생성되었습니다. 다음 날 대량의 거래량과 함께 장대양봉이 솟구치며 130.50달러로 마감하는 샛별형(Morning Star) 조합이 확정되었습니다. 이때 가장 합리적인 매수 진입 지점과 손절가 기준은 무엇입니까?', '[{"time":"Day 1","open":150,"high":151.5,"low":139.5,"close":141,"volume":107},{"time":"Day 2","open":141,"high":142.5,"low":132,"close":133.5,"volume":97},{"time":"Day 3","open":133.5,"high":135,"low":120,"close":121.5,"volume":89},{"time":"Day 4","open":120,"high":123,"low":112.5,"close":120,"volume":115},{"time":"Day 5","open":120,"high":132,"low":118.5,"close":130.5,"volume":112}]'::jsonb, '[]'::jsonb, ARRAY['손절 없이 100% 비중으로 시장가 매수', '샛별형 완성에 따라 분할 매수 후 최저점 손절 셋업', '바닥 도달 기대로 주문 없이 무작정 대기', '상승 꼭대기에서 숏 진입 후 손절 없이 방치']::text[], 1, '하락 추세 끝에 도지와 장대양봉이 결합된 샛별형(Morning Star)은 매우 신뢰도 높은 바닥 상승 전환 신호입니다. 이 패턴을 보고 진입할 때는 반등 상승세에 분할 매수로 동참하되, 바닥을 잡아준 도지 캔들의 최저점(112.50달러) 아래를 최종 손절 라인으로 잡는 것이 수학적으로 가장 리스크 대비 보상 비율(손익비)이 훌륭한 전략입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (133, '거래량/유동성', '02_candlestick_price_action.md', '코인 가격가 강력한 횡보 박스권 고점(300달러 저항선)에 세 번째 터치하는 와중에, 윗꼬리가 길고 몸통이 매우 얇은 유성형(Shooting Star) 캔들이 이틀 연속 발생했습니다. 거래량 역시 저항선 부근에서 매수세가 더 올라가지 못하고 매도 압력이 실려 나타났습니다. 롱(매수) 포지션을 들고 있는 당신의 합리적인 의사결정은?', '[{"time":"Day 1","open":262.5,"high":277.5,"low":261,"close":273,"volume":112},{"time":"Day 2","open":273,"high":292.5,"low":270,"close":289.5,"volume":102},{"time":"Day 3","open":289.5,"high":303,"low":285,"close":286.5,"volume":94},{"time":"Day 4","open":286.5,"high":301.5,"low":282,"close":283.5,"volume":111}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":300}],"label":"박스권 상단 저항선 (200)","color":"#ef4444"}]'::jsonb, ARRAY['신고가 갱신을 예상한 전재산 추가 불타기', '저항 돌파 실패 신호 확인 후 분할 익절 및 관망', '손익 평단가 부근이므로 추가 손절 없이 방치', '거래를 종료하고 다른 신규 급등주를 시장가 추격']::text[], 1, '박스권 상단 저항선(300달러)에 부딪히며 나타난 유성형(Shooting Star) 연속 출현은 저항 돌파 실패와 차익 실현 세력의 강력한 등장을 경고하는 캔들 신호입니다. 돌파를 확신하기보다는 리스크 관리 관점에서 물량을 축소(50% 분할 익절)하거나 전량 매도하여 이익을 확정 짓는 것이 현명합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (134, '캔들/가격행동', '02_candlestick_price_action.md', '극심한 하락 추세 중 150달러선 아래로 떨어지던 코인 가격가 전일 장대음봉을 형성했습니다. 그러나 당일 시가는 갭하락하여 더 낮게 시작했으나, 장중에 강한 매수세가 들어오며 전일 음봉 몸통의 정확히 70% 라인(139.50달러선) 위로 덮어버리는 관통형(Piercing Line) 상승 캔들로 마감했습니다. 종가 매수(롱) 진입 시 원칙 대응은?', '[{"time":"Day 1","open":165,"high":166.5,"low":156,"close":157.5,"volume":102},{"time":"Day 2","open":157.5,"high":159,"low":145.5,"close":147,"volume":92},{"time":"Day 3","open":138,"high":151.5,"low":136.5,"close":150,"volume":104}]'::jsonb, '[]'::jsonb, ARRAY['상승 모멘텀 미달로 매수 보류 및 하방 숏 포지션 진입', '관통형 확인 후 분할 매수 및 당일 최저점 손절 설정', '손절 라인 설정 없이 100% 비중 시장가 매수 집행', '조정을 대기하며 예약 주문 없이 무작정 관망 유지']::text[], 1, '전일 음봉의 50% 이상을 당일 양봉 몸통으로 관통해 올린 ''관통형(Piercing Line)''은 하락 모멘텀이 쇠퇴하고 저가 매수세가 우위를 점하기 시작했음을 뜻하는 바닥 신호입니다. 이 패턴 확인 후 진입할 시에는 손절 한도를 당일 최저점(136.50달러) 밑에 가깝게 설정할 수 있어 매우 유리한 리스크 대비 기대수익 매매가 성립됩니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (135, '캔들/가격행동', '05_volume_liquidity.md', '강한 급등세를 지속하던 코인 가격가 최고점에서 큰 거래량을 터뜨리며 장대양봉을 만들었습니다. 그러나 다음 날, 전일 양봉 몸통의 한가운데 범위 안에서 움직이며 시가와 종가가 모두 갇혀버리는 짧은 음봉인 ''하락 잉태형(Bearish Harami)'' 캔들이 형성되었습니다. 단기 스윙 트레이더로서 당신의 포지션 리스크 관리 행동은?', '[{"time":"Day 1","open":180,"high":192,"low":178.5,"close":190.5,"volume":104},{"time":"Day 2","open":190.5,"high":207,"low":189,"close":204,"volume":101},{"time":"Day 3","open":199.5,"high":201,"low":195,"close":196.5,"volume":112}]'::jsonb, '[]'::jsonb, ARRAY['상승 둔화 조짐에 따른 보유 물량 50% 분할 익절', '추세 일시 조정으로 간주하여 비중 확대 추가 매수', '추세 종결 판단에 따른 고배율 숏 포지션 즉시 진입', '이익 실현 없이 전량 장기 보유 전략 유지']::text[], 0, '하락 잉태형(Bearish Harami)은 이전의 강한 상승 추세 동력이 감속하기 시작했으며, 매도 압력이 힘을 기르고 있음을 암시하는 변곡 캔들입니다. 따라서 단기 스윙 트레이더는 물량의 일부(50%)를 분할 익절하여 리스크를 낮추고, 다음 캔들에서 이전 양봉 저점을 깨뜨리는 하락 하방 이탈이 추가되는지 지켜보는 것이 정석입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (136, '시장구조/SR', '03_market_structure.md', '오랫동안 지켜지던 핵심 지지선인 150달러 부근에서 매수 진입을 완료했습니다. 그러나 가격이 대량의 거래량을 동반하며 장대음봉으로 지지선을 하방으로 강하게 뚫어냈고, 종가가 지지선 대비 1.5% 아래인 98.7.50달러로 결정되었습니다. 이 상황에서 원칙을 지키는 올바른 위기 대응 행동은?', '[{"time":"Day 1","open":157.5,"high":162,"low":153,"close":154.5,"volume":91},{"time":"Day 2","open":154.5,"high":156,"low":148.5,"close":150,"volume":84},{"time":"Day 3","open":150,"high":151.5,"low":147,"close":147.75,"volume":120}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":150}],"label":"중요 지지선 (100)","color":"#10b981"}]'::jsonb, ARRAY['추가 물타기를 위해 자금을 동원하여 평단가 관리', '중요 지지선 붕괴(Breakdown) 확인 후 즉시 전량 손절', '지속 하락 시 추가 평단가 관리를 위해 매수 유보', '하방 이탈 시 즉시 반대 고배율 롱 포지션 진입']::text[], 1, '거래량이 동반된 장대음봉으로 주요 지지선 아래에서 종가가 결정되는 이탈 마감은 매수 지지 세력의 패배이자 추세 붕괴(Breakdown)의 신호입니다. 이 시점에서 물타기를 하거나 존버를 하면 파산적인 하락 조정을 겪을 수 있으므로 즉시 룰에 근거한 ''전량 손절''을 집행해야 계좌를 살릴 수 있습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (137, '시장구조/SR', '03_market_structure.md', '225달러의 중요 저항선이 강한 거래량을 실은 돌파봉으로 뚫렸습니다. 이후 코인 가격가 숨 고르기 조정을 받으며 225달러 부근까지 되돌아왔고(리테스트 구간), 저항선 부근에서 거래량이 크게 감소하며 아래꼬리가 달린 도지 캔들로 안착하는 모습을 보입니다. 이때 가장 안전하고 합리적인 매매 조치는?', '[{"time":"Day 1","open":210,"high":219,"low":208.5,"close":216,"volume":92},{"time":"Day 2","open":216,"high":235.5,"low":214.5,"close":232.5,"volume":111},{"time":"Day 3","open":232.5,"high":234,"low":223.5,"close":225,"volume":124}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":225}],"label":"돌파된 저항선 -> 지지선 전환선 (150)","color":"#3b82f6"}]'::jsonb, ARRAY['가짜 돌파(휩소) 판단에 따른 고배율 숏 진입', '돌파 후 리테스트 성공 확인 시 지지선 눌림목 매수', '추격 매수 기회 상실로 판단하고 거래 포기', '240달러 추가 돌파를 타겟으로 시장가 추격 매수']::text[], 1, '강하게 돌파된 저항선은 룰 체인지에 의해 지지선으로 변합니다(역할 전환). 돌파 당시 추격 매수하기보다, 돌파된 선(225달러)으로 코인 가격가 되돌아오는 리테스트(Retest) 시점에 저조한 거래량과 지지 캔들을 확인하고 손절선을 바로 밑에 설정하여 눌림목 진입하는 것이 리스크가 가장 적은 프로 트레이더의 정석입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (138, '시장구조/SR', '03_market_structure.md', '가격이 120달러 지지선 근처에서 반등을 시도하고 있으나, 반등의 폭이 직전 고점에 턱없이 못 미치며 저점 부근으로 다시 짓눌리고 있습니다. 즉, 고점들이 계속 낮아지는 하락 우위 삼각수렴(Descending)의 형태가 지지선 바로 위에서 감지됩니다. 이 시점에서 지지선 반등을 믿고 신규 매수(롱)를 진입하는 것은 원칙에 맞습니까?', '[{"time":"Day 1","open":142.5,"high":147,"low":120,"close":132,"volume":111},{"time":"Day 2","open":132,"high":136.5,"low":120,"close":126,"volume":101},{"time":"Day 3","open":126,"high":129,"low":120,"close":121.5,"volume":115}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":120}],"label":"지지선 (80)","color":"#10b981"}]'::jsonb, ARRAY['삼중 바닥 지지로 판단하고 매수 비중 대폭 확대', '디센딩 수렴 확인 후 하방 이탈 위험 대비 관망', '물타기 평단가 관리를 위해 매수 보증금 추가 투입', '추세와 무관하게 숏 포지션으로 전환 후 무기한 보유']::text[], 1, '지지선 부근에서 고점이 점점 낮아지는 ''디센딩'' 형태는 매수 지원 강도가 둔화되고 매도 출하 공급이 가격을 계속 하방으로 압박하고 있음을 증명합니다. 지지 성공보다 지선 하방 붕괴 후 급락할 확률이 높으므로, 지지선이라는 명목만으로 함부로 매수 진입하지 말고 돌파/이탈 컨펌을 기다려 관망하는 것이 현명합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (139, '거래량/유동성', '05_volume_liquidity.md', '코인 가격가 180달러의 장기 저항벽을 거래량이 거의 실리지 않은 얇은 양봉으로 상방으로 살짝 뚫었으나, 바로 다음 날 직전 양봉 몸통을 통째로 덮어버리는 대량 거래량의 장대음봉이 출현하며 174달러로 곤두박질쳤습니다. 매수 포지션을 추격 진입했던 당신의 올바른 조치는?', '[{"time":"Day 1","open":168,"high":177,"low":166.5,"close":175.5,"volume":115},{"time":"Day 2","open":175.5,"high":183,"low":174,"close":181.5,"volume":401},{"time":"Day 3","open":181.5,"high":183,"low":172.5,"close":174,"volume":419}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":180}],"label":"장기 저항선 (120)","color":"#ef4444"}]'::jsonb, ARRAY['불 트랩(Bull Trap) 확인 후 추가 하락 방지 즉시 손절', '저항선 부근 매수세 복귀를 기대하며 전량 홀딩', '평단가 관리 차원에서 추가 물타기 매수 집행', '상황을 판단하기 위해 시장가로 추가 분할 진입']::text[], 0, '거래량 없는 돌파 직후에 거래량 실린 강한 음봉이 기존 돌파선(180달러) 아래로 재진입하여 마감하는 현상은 전형적인 불 트랩(Bull Trap/가짜 돌파) 함정입니다. 돌파 당시 샀던 매수자들의 패닉 셀이 출현하며 하락 가속화가 나오기 쉬우므로 즉시 손절하여 물량을 털어내야 생존할 수 있습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (140, '시장구조/SR', '10_psychology_routine_review.md', '주요 지지선(375달러선)이 아래로 무너질 때 제때 손절 처리를 하지 못해 코인 가격가 330달러선까지 끌려 내려갔습니다. 다행히 단기 매도 진정세로 반등이 나와 코인 가격가 다시 375달러 부근까지 상승하여 회복을 눈앞에 두고 있습니다. 이때 손실을 최소화하는 현명한 시나리오 대처법은?', '[{"time":"Day 1","open":390,"high":393,"low":372,"close":373.5,"volume":110},{"time":"Day 2","open":373.5,"high":375,"low":330,"close":333,"volume":90},{"time":"Day 3","open":333,"high":352.5,"low":331.5,"close":351,"volume":114},{"time":"Day 4","open":351,"high":376.5,"low":349.5,"close":373.5,"volume":107}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":375}],"label":"붕괴된 지지선 -> 저항선으로 변형 (250)","color":"#ef4444"}]'::jsonb, ARRAY['역할 전환(저항선) 도달에 따른 탈출 및 현금화', 'V자 반등 성공 확신에 따른 추가 매수 비중 확대', '원금 회복 및 추가 수익 시까지 영구 홀딩 관망', '하락 추세 지속에 따른 반대 숏 포지션 스위칭']::text[], 0, '하방으로 깨진 지지선은 반등할 때 가장 뚫기 힘든 ''강력한 저항선''으로 성격이 바뀝니다. 따라서 손절 기회를 놓치고 물려있던 트레이더는 반등하여 옛 지지선(375달러)에 도달했을 때를 ''최선의 리스크 탈출 기회(탈출구)''로 삼아 전량 매도하거나 비중을 극도로 덜어내야 다가올 2차 하락 파동의 파산을 막을 수 있습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (141, '추세/레짐', '03_market_structure.md', '코인 가격가 매우 가파르게 올라가던 1차 단기 상승 추세선을 강한 음봉 종가로 뚫고 내려왔습니다. 다행히 각도가 완만하고 탄탄한 장기 핵심 상승 추세선은 저 밑에 지지 영역을 유지하고 있습니다. 스윙 트레이더로서 가장 정석적인 포지션 제어 방식은 무엇인가요?', '[{"time":"Day 1","open":150,"high":153,"low":150,"close":153,"volume":102},{"time":"Day 2","open":153,"high":165,"low":153,"close":163.5,"volume":121},{"time":"Day 3","open":163.5,"high":187.5,"low":163.5,"close":186,"volume":107},{"time":"Day 4","open":186,"high":187.5,"low":171,"close":172.5,"volume":102}]'::jsonb, '[{"type":"line","points":[{"x":0,"y":150},{"x":3,"y":184.5}],"label":"가파른 단기 추세선 (붕괴)","color":"#ef4444"},{"type":"line","points":[{"x":0,"y":150},{"x":3,"y":165}],"label":"완만한 장기 추세선 (지탱 중)","color":"#10b981"}]'::jsonb, ARRAY['추세 붕괴 판단에 따른 전량 손절 및 영구 이탈', '가속 추세 이탈에 따른 50% 분할 익절 및 분산', '단기 지지선 붕괴를 무시한 고배율 물타기 매수', '장기 추세선까지 조정을 대비한 신규 매수 대기']::text[], 1, '가파르게 우상향하던 가속 추세선(Accelerated Trendline)이 하방 돌파되는 것은 기존 폭등 랠리의 속도가 둔화되고 완만한 본래 장기 추세선(장기 매물대)을 향해 정상적인 가격 조정을 받기 시작했음을 뜻합니다. 따라서 물량의 50%가량을 털어 수익을 실현하고 남은 물량으로 장기 추세선의 3rd Touch 지지 성공 여부를 테스트하는 것이 리스크 관리의 기본입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (142, '거래량/유동성', '05_volume_liquidity.md', '고점과 저점이 연속으로 낮아지는 명확한 하락 평행 채널 내에서 하락 압력을 받아 숏(매도) 포지션을 잡고 수익 중이었습니다. 그런데 당일 캔들이 대량의 거래량과 함께 장대양봉을 그리며 채널 상단 저항선 위로 종가 안착(상방 돌파)했습니다. 숏 포지션을 쥔 당신의 결단은?', '[{"time":"Day 1","open":150,"high":153,"low":135,"close":138,"volume":103},{"time":"Day 2","open":138,"high":141,"low":123,"close":124.5,"volume":94},{"time":"Day 3","open":124.5,"high":127.5,"low":112.5,"close":114,"volume":95},{"time":"Day 4","open":114,"high":135,"low":112.5,"close":133.5,"volume":108}]'::jsonb, '[{"type":"channel","points":[{"x":0,"y":153},{"x":3,"y":129},{"x":0,"y":135},{"x":3,"y":114}],"label":"하락 평행 채널 상한/하한","color":"#f59e0b"}]'::jsonb, ARRAY['상단 돌파 확인 즉시 숏 전량 손절 및 대피', '채널 재진입 기대로 숏 포지션 추가 물타기', '손절 없이 유지하면서 포지션 본전 도달 대기', '포지션 유지 후 증거금을 출금하여 강제 횡보']::text[], 0, '하락 평행 채널의 상단 저항선 상향 돌파(Breakout)는 기존 하락 트렌드의 사멸과 매수세 지배령 복귀를 뜻합니다. 지표와 거래량이 동반된 돌파 확인 시에는 숏 포지션을 지체 없이 기계적으로 칼손절하여 자산을 보호하는 것이 원칙입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (143, '추세/레짐', '07_multitimeframe_regime.md', '우상향하는 상승 평행 채널 안에서 순항하던 코인 가격가 중심선(Mid-line)을 뚫고 하방으로 이탈 마감했습니다. 이후 중심선 부근까지 반등을 시도했으나 재차 저항을 받고 아래꼬리가 꺾여 채널 하단선을 향해 하락 조정을 재개하려 합니다. 신규 매수(롱) 포지션 진입을 계획 중인 트레이더의 대응법은?', '[{"time":"Day 1","open":150,"high":162,"low":148.5,"close":159,"volume":88},{"time":"Day 2","open":159,"high":168,"low":153,"close":156,"volume":109},{"time":"Day 3","open":156,"high":159,"low":147,"close":150,"volume":104}]'::jsonb, '[{"type":"channel","points":[{"x":0,"y":165},{"x":2,"y":168},{"x":0,"y":147},{"x":2,"y":150}],"label":"상승 평행 채널","color":"#10b981"}]'::jsonb, ARRAY['채널 내 유지를 기대로 지정가 즉시 매수', '중심선 저항 확인 후 채널 하단 안착 대기', '하방 휩소 판단에 따른 레버리지 추가 매수', '추세와 무관한 숏 포지션 구축 후 관망']::text[], 1, '상승 평행 채널에서 미드라인(Mid-line)은 매우 중요한 심리적 지지와 저항선입니다. 미드라인이 저항선으로 뒤바뀌어 음봉으로 흘러내리는 경우 높은 확률로 채널 하단 경계선까지 가격이 조정을 받게 되므로, 중심선 저항 확인 시점에서는 섣부른 매수 진입을 피하고 채널 하단의 명확한 반등 타점을 유도해야 합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (144, '추세/레짐', '03_market_structure.md', '저점과 저점을 이은 장기 상승 추세선 상의 3번째 터치 포인트(지지선 부근)에 캔들이 매우 조심스럽게 안착하며 아래꼬리를 형성했습니다. 손익비(Risk-to-Reward) 관점에서 가장 이상적인 매수 타점 집행 및 손절 셋업 방법은 무엇입니까?', '[{"time":"Day 1","open":120,"high":135,"low":120,"close":132,"volume":103},{"time":"Day 2","open":132,"high":148.5,"low":132,"close":142.5,"volume":108},{"time":"Day 3","open":142.5,"high":144,"low":135,"close":138,"volume":111}]'::jsonb, '[{"type":"line","points":[{"x":0,"y":120},{"x":1,"y":132},{"x":2,"y":135}],"label":"상승 추세선 (3rd Touch 기대선)","color":"#10b981"}]'::jsonb, ARRAY['손절 라인 없이 지정가로 1차 매수 몰빵 진입', '3rd Touch 타점 진입 및 추세선 하단 칼손절 셋업', '하방 붕괴 예상을 통한 고배율 숏 즉각 진입', '목표가 터치 시까지 무작정 대기 후 추격 매수']::text[], 1, '추세선 상의 3번째 지지 포인트(3rd Touch)는 추세 신뢰도가 형성되는 대단히 성공률 높은 정석적 눌림목 타점입니다. 진입 가격과 손절 라인(추세선 이탈가)의 거리가 매우 가깝기 때문에 기대 수익 대비 잃을 금액이 매우 적어 프로 트레이더들이 가장 선호하는 칼손절 매수 스팟입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (145, '추세/레짐', '08_setup_entry_exit.md', '코인 가격가 장기 하락 추세선을 힘차게 뚫어 상방 돌파(Breakout)했습니다. 하지만 돌파선 바로 위(약 180달러)에 최근 여러 번 강한 매도 잔량이 쏟아지며 가격을 찍어 눌렀던 핵심 매물대 저항선이 떡하니 버티고 있습니다. 당신의 신규 진입 매수 순서는 어떻게 결정해야 안전할까요?', '[{"time":"Day 1","open":187.5,"high":189,"low":165,"close":168,"volume":100},{"time":"Day 2","open":168,"high":169.5,"low":147,"close":150,"volume":93},{"time":"Day 3","open":150,"high":178.5,"low":148.5,"close":177,"volume":119}]'::jsonb, '[{"type":"line","points":[{"x":0,"y":187.5},{"x":1,"y":168},{"x":2,"y":157.5}],"label":"하락 추세선 (돌파됨)","color":"#ef4444"},{"type":"horizontal-line","points":[{"x":0,"y":180}],"label":"수평 매물대 저항선 (120)","color":"#ef4444"}]'::jsonb, ARRAY['돌파 확인 즉시 종가 기준 시장가 100% 매수', '수평 저항 돌파 검증 시까지 매수 유보 및 대기', '돌파 전조 현상 기대로 레버리지 선배팅 집행', '추세선 돌파를 가짜로 간주한 숏 포지션 진입']::text[], 1, '하락 추세선의 돌파는 긍정적이나 수평 매물대 저항선이 바로 위에 있다면 이중 저항 작용에 의해 막히는 경우가 대단히 잦습니다. 추세선 상방 휩소(속임수)에 당하지 않으려면 겹저항 중 최종 관문인 수평 매물대 저항선 돌파 혹은 리테스트 지지를 확인하고 진입하는 것이 보수적이고 안전한 원칙입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (146, '패턴/돌파', '04_patterns_breakout.md', '고점 수평 저항선(150달러)과 저점 상승 지지선으로 이루어진 어센딩 트라이앵글 수렴 도중, 150달러를 돌파할 것을 미리 예측하고 147달러에서 비중 100% 매수로 진입했습니다. 그러나 코인 가격는 돌파에 실패하고 하방 상승 지지선을 대량 거래량 장대음봉으로 뚫어 138달러로 하향 마감했습니다. 올바른 매매 액션은?', '[{"time":"Day 1","open":120,"high":150,"low":120,"close":142.5,"volume":107},{"time":"Day 2","open":142.5,"high":150,"low":132,"close":145.5,"volume":93},{"time":"Day 3","open":145.5,"high":147,"low":136.5,"close":138,"volume":103}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":150}],"label":"수평 저항선 (100)","color":"#ef4444"},{"type":"line","points":[{"x":0,"y":120},{"x":1,"y":132},{"x":2,"y":141}],"label":"상승 지지선 (붕괴)","color":"#10b981"}]'::jsonb, ARRAY['하방 이탈 확인 즉시 손절하여 추가 폭락 차단', '조정을 이용해 평단가를 조절하는 분할 물타기', '본전 탈출 시까지 포지션을 유지하며 관망', '손절 라인을 하단으로 조정하고 대기 주문 유지']::text[], 0, '어센딩 트라이앵글은 상방 확률이 다소 높지만, 하단 지지선이 뚫려 무너지는 순간 패턴 실패와 함께 엄청난 실망 매도 매물이 출하됩니다. 특히 돌파를 미리 예견해 들어간 포지션은 즉시 룰 위반을 시정하고 손절(138달러)해야 큰 자산 보호를 할 수 있습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (147, '패턴/돌파', '04_patterns_breakout.md', '하락 바닥권에서 왼쪽 어깨, 머리, 오른쪽 어깨를 그리며 역헤드앤숄더(Inverse Head & Shoulders) 패턴이 완성되었습니다. 가격이 넥라인 저항벽(120달러선)을 돌파했으나 이미 장대양봉으로 높이 솟아(130.50달러) 추격 매수 타이밍을 아쉽게 놓쳤습니다. 이때 뇌동매매를 피하는 가장 현명한 매수 타점 공략법은?', '[{"time":"Day 1","open":142.5,"high":142.5,"low":105,"close":117,"volume":95},{"time":"Day 2","open":117,"high":123,"low":90,"close":112.5,"volume":110},{"time":"Day 3","open":112.5,"high":118.5,"low":102,"close":114,"volume":124},{"time":"Day 4","open":114,"high":132,"low":112.5,"close":130.5,"volume":114}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":120}],"label":"넥라인 저항선 (80)","color":"#ef4444"}]'::jsonb, ARRAY['포모(FOMO) 현상에 따른 돌파봉 꼭대기 추격 매수', '돌파 넥라인 부근의 리테스트 조정 눌림목 매수', '반등 랠리 종결 판단에 따른 역베팅 숏 포지션', '추세 전환 확인 후 무조건적인 관심종목 제외']::text[], 1, '강한 패턴 돌파봉 확인 후 뇌동매매로 추격하는 것은 손절 거리가 너무 멀어져 손익비가 최악인 나쁜 습관입니다. 정석 돌파 트레이더는 넥라인 역할 전환 지점(120달러)으로의 되돌림 눌림목(Retest)을 차분히 기다려 리스크를 짧게 끊고 들어가는 훈련을 해야 합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (148, '패턴/돌파', '04_patterns_breakout.md', '지속적인 하락 추세 중, 고점과 저점이 수렴하며 우하향하는 하락 쐐기형(Falling Wedge) 패턴의 끝자락에 도달했습니다. 거래량이 급감하다가 마침내 쐐기형 상단 저항선을 상방으로 뚫는 강한 양봉 종가 마감(165달러)이 포착되었습니다. 합리적인 매수 진입 시 손절가 설정 기준은 무엇인가요?', '[{"time":"Day 1","open":195,"high":198,"low":165,"close":168,"volume":108},{"time":"Day 2","open":168,"high":174,"low":153,"close":156,"volume":122},{"time":"Day 3","open":156,"high":162,"low":147,"close":150,"volume":91},{"time":"Day 4","open":150,"high":168,"low":148.5,"close":165,"volume":106}]'::jsonb, '[]'::jsonb, ARRAY['손절 없이 청산가에 의존하여 장기 홀딩', '상방 돌파 확인 후 진입 및 직전 최저점 손절 셋업', '평단가 개선을 위한 지속적인 분할 물타기 매수', '상단 저항선 돌파 시점을 이용한 숏 포지션 스위칭']::text[], 1, '하락 쐐기형(Falling Wedge)의 상방 돌파는 강력한 반전 신호입니다. 이 패턴의 장점은 진입 즉시 명확하고 짧은 기준점(수렴 바닥 최저가 147달러 혹은 돌파봉 하단)을 손절가로 설정할 수 있어, 리스크 한도를 안전하게 통제한 채 상방 랠리를 도모할 수 있다는 점입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (149, '패턴/돌파', '04_patterns_breakout.md', '코인 가격가 약한 매수세와 거래량 급감 속에 고점과 저점을 높이며 좁게 상승 쐐기형(Rising Wedge)을 그리고 있습니다. 현재 가격은 상승 쐐기형 하단 지지선(450달러)에 아주 밀착하여 붕괴 위기에 놓여 있습니다. 이 시점에서 롱(매수) 포지션을 들고 있는 트레이더의 리스크 대응은?', '[{"time":"Day 1","open":390,"high":420,"low":390,"close":417,"volume":104},{"time":"Day 2","open":417,"high":442.5,"low":408,"close":435,"volume":32},{"time":"Day 3","open":435,"high":457.5,"low":447,"close":451.5,"volume":20}]'::jsonb, '[{"type":"line","points":[{"x":0,"y":390},{"x":1,"y":408},{"x":2,"y":447}],"label":"쐐기 하단 지지선 (300)","color":"#ef4444"}]'::jsonb, ARRAY['상승 쐐기형 하방 이탈 위험에 따른 롱 포지션 매도', '상승 지속 확신에 따른 레버리지 추가 불타기', '장기 상승 흐름 기대로 손절 없이 무기한 홀딩', '다른 종목으로의 포지션 분산을 위한 관망']::text[], 0, '상승 쐐기형(Rising Wedge)은 약세 세력이 억지로 쥐어짜며 상승 가격을 만드는 패턴으로, 수렴 끝에서 거래량 소멸과 함께 하방 이탈(Breakdown)하여 폭락할 위험이 매우 높은 대표적인 하락 대비 패턴입니다. 하단 지지선 이탈 낌새 시에는 매수 포지션을 전부 도망쳐 나와야 큰 손실을 막을 수 있습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (150, '패턴/돌파', '04_patterns_breakout.md', '둥근 대야 모양의 바닥(Cup)을 그리며 상승 회복한 코인 가격가 전고점 저항벽 부근에서 하향 채널식 완만한 되돌림 조정 핸들(Handle)을 그리는 중입니다. 이후 핸들의 상단 저항선(225달러선)을 강한 거래량의 장대양봉으로 상향 돌파했습니다. 이때 합리적인 트레이더의 대응은?', '[{"time":"Day 1","open":210,"high":213,"low":192,"close":195,"volume":102},{"time":"Day 2","open":195,"high":210,"low":193.5,"close":207,"volume":121},{"time":"Day 3","open":207,"high":210,"low":201,"close":202.5,"volume":118},{"time":"Day 4","open":202.5,"high":231,"low":201,"close":228,"volume":129}]'::jsonb, '[]'::jsonb, ARRAY['핸들 상방 돌파 확인 후 진입 및 핸들 저점 손절', '하락 지속 판단에 따른 즉각적인 전량 손절', '평단가 부근이므로 추가 손절 설정 없이 관망', '돌파 여부 확인 전 고점 돌파 매수 주문 100%']::text[], 0, '전형적인 강세 지속 패턴인 컵앤핸들(Cup & Handle)입니다. 핸들의 하락 조정 채널 상단 돌파는 매물 소화를 성공적으로 완수하고 본 랠리로 진입한다는 강력한 신호입니다. 손익비 관점에서 핸들의 지지 저점인 201달러 아래에 안전 손절을 지정한 뒤 진입 시 우수한 기대 수익을 가질 수 있습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (151, '지표/컨플루언스', '06_technical_indicators.md', '강력한 대세 상승 국면인 종목이 일시 조정을 거쳐 전저점 지지 영역(150달러)에 도달해 저점을 지키고 있습니다(저점 높임 또는 수평). 그런데 이때 보조지표 RSI의 저점은 이전보다 훨씬 깊게 파여 낮아지는 ''히든 상승 다이버전스(Hidden Bullish Divergence)''가 포착되었습니다. 현명한 의사결정은?', '[{"time":"Day 1","open":135,"high":165,"low":132,"close":157.5,"volume":95},{"time":"Day 2","open":157.5,"high":160.5,"low":147,"close":150,"volume":87}]'::jsonb, '[]'::jsonb, ARRAY['하락 전환 신호로 판단하여 전량 즉시 손절', '추세 지속 신호 기대로 지선 부근 추가/신규 매수', '지표 과매수 판단에 따른 계좌 거래 정지', '손절 설정 없이 무제한 레버리지 롱 대응']::text[], 1, '코인 가격의 저점은 높아지는데 보조지표(RSI 등)의 저점은 낮아지는 형태는 ''히든 상승 다이버전스''입니다. 이는 기존의 강력한 상승 트렌드 내부에서 일시 조정을 겪는 매수자들이 활기차게 물량을 주워 담아 다음 상승 랠리를 추진한다는 신호이므로, 짧은 손절 라인(147달러)을 설정하고 매수 비중을 태우기 가장 적합한 정석 타점입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (152, '지표/컨플루언스', '07_multitimeframe_regime.md', '코인 가격가 호재와 함께 밴드 상단선 바깥을 타고 계속 상승하는 강력한 볼린저 밴드 밴드워크(Band Walk) 현상이 발생 중이며, RSI는 80을 넘어 극단적 과매수 수치를 가리키고 있습니다. 이 구간에서 취해야 할 가장 합리적인 리스크 및 포지션 관리 행동은?', '[{"time":"Day 1","open":150,"high":172.5,"low":148.5,"close":168,"volume":114},{"time":"Day 2","open":168,"high":192,"low":165,"close":187.5,"volume":93},{"time":"Day 3","open":187.5,"high":208.5,"low":183,"close":204,"volume":122}]'::jsonb, '[]'::jsonb, ARRAY['과매수 도달 판단에 따른 고배율 숏 무리한 진입', '추종 손절매(Trailing Stop)를 통한 수익 극대화', '상승폭 만족에 따른 즉각적인 전량 시장가 익절', '손절 가격을 해제하고 시세 지속 시까지 방치']::text[], 1, '강세 추세가 지나치게 강할 경우 볼린저 밴드 상단을 타고 오르는 밴드워크 현상과 RSI 과매수 현상이 영구 유지될 수 있습니다. 이때 단순 과매수 수치를 이유로 숏 포지션을 잡으면 파산합니다. 기존 매수 포지션의 익절선(Trailing Stop)을 상향 관리하여 추세 상승 이익을 극대화하고 신규 진입은 자제하는 것이 정석 리스크 관리입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (153, '지표/컨플루언스', '06_technical_indicators.md', '1시간 봉 차트 상에서 코인 가격가 확실히 낮아졌으나 RSI 저점은 유의미하게 상승한 ''상승 다이버전스''가 확인되어 매수 타점을 노리고 있습니다. 다만 15분 봉 단기 차트에서는 하락 장대음봉 관성이 아직 살아있어 매도 압력이 보입니다. 멀티 타임프레임 트레이더의 진입 의사결정은?', '[{"time":"Hour 1","open":150,"high":153,"low":135,"close":136.5,"volume":105},{"time":"Hour 2","open":136.5,"high":138,"low":120,"close":123,"volume":87}]'::jsonb, '[]'::jsonb, ARRAY['단기 음봉 관성 기대로 즉각 숏 포지션 진입', '큰 시간 프레임의 상승 다이버전스 타점 매수', '지표 충돌로 판단하고 시장가 즉시 롱 진입', '변동성 기대로 무작정 도박성 잡코인 진입']::text[], 1, '큰 프레임(1시간 봉)의 다이버전스가 주는 중장기 추세 신뢰도는 작은 프레임의 단기 노이즈보다 압도적으로 강력합니다. 단, 진입 시 타이밍의 정밀도를 높이기 위해 소파동(15분 봉)의 하락 동력이 꺾이고 지지해 주는 단기 확인 캔들이 나오는 찰나에 롱 포지션 타이밍을 잡는 것이 멀티 타임프레임 정석 매매입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (154, '지표/컨플루언스', '06_technical_indicators.md', '코인 가격는 300달러 저항대를 뚫고 330달러까지 계속 우상향하며 고점을 갱신하고 있으나, MACD 오실레이터의 히스토그램 산 높이는 직전 고점 시점 대비 현저하게 쪼그라들며 꺾여 내려가 하락 다이버전스를 형성 중입니다. 현명한 포지션 보유자의 이익 관리 행동은?', '[{"time":"Day 1","open":270,"high":307.5,"low":268.5,"close":300,"volume":93},{"time":"Day 2","open":300,"high":333,"low":297,"close":330,"volume":122}]'::jsonb, '[]'::jsonb, ARRAY['추세 지속 확신으로 보유 비중 추가 불타기', '상승 모멘텀 약화 다이버전스 확인 후 50% 익절', '익절 설정 없이 전고점 도달 시까지 홀딩', '고점 붕괴 기대로 숏 포지션 10배 베팅']::text[], 1, '코인 가격는 올라가나 모멘텀 지표인 MACD 오실레이터 고점이 낮아지는 현상은 대표적인 하락 다이버전스로, 매수 에너지가 속 빈 강정처럼 쇠퇴하고 있어 언제든 급격한 폭락 조정이 발생할 수 있는 고위험 신호입니다. 이 시점에는 탐욕을 통제하고 물량의 50% 이상을 분할 매도하여 현금을 챙기는 것이 원칙입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (155, '지표/컨플루언스', '06_technical_indicators.md', '코인 가격가 하락 횡보하던 도중, 단기 지평선인 EMA 20일선이 중장기선인 EMA 50일선에 극도로 밀착하며 수렴했습니다. 당일 대량 거래량의 음봉 캔들이 터지며 단기선이 장기선 아래로 교차하기 직전(데드크로스 임박)이며 주요 지지선 밑으로 떨어졌습니다. 롱(매수) 포지션 보유자의 올바른 대응은?', '[{"time":"Day 1","open":157.5,"high":159,"low":148.5,"close":150,"volume":102},{"time":"Day 2","open":150,"high":151.5,"low":142.5,"close":144,"volume":93}]'::jsonb, '[]'::jsonb, ARRAY['지지선 이탈 및 데드크로스 확인 즉시 손절', '이평선 지지력을 믿고 하방 물타기 추가 매수', '하락 조정 후 반등 기대로 무기한 홀딩 관망', '청산가 도달 시까지 어떠한 대응 없이 방치']::text[], 0, '20일선과 50일선의 데드크로스 임박 수렴 상태에서 가격이 지지선마저 무너뜨린 것은 하락 가속화 추세가 폭발하기 직전인 매우 위험한 기술적 상태입니다. 하락 추세가 본격 정배열(하락 정배열)화 되기 전에 즉시 전량 손절하고 시장 밖에서 피신해 있는 것이 계좌의 영구 파산을 막는 유일한 생존 규칙입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (156, '리스크/심리', '09_risk_position_management.md', '알트코인 매수 후 가격이 급락하여 내가 설정해 둔 최대 감내 손실 한도인 계좌 총원금 대비 -2% 라인(손절매 지정 가격)에 완벽하게 닿았습니다. 마침 본전 생각과 함께 ''조금만 더 버티면 반등할 텐데...''하는 강한 뇌동매매 유혹이 솟구칩니다. 이때 원칙 트레이더의 결정은?', '[{"time":"Day 1","open":150,"high":153,"low":148.5,"close":150,"volume":93},{"time":"Day 2","open":150,"high":151.5,"low":141,"close":142.5,"volume":109}]'::jsonb, '[]'::jsonb, ARRAY['손절 라인을 임의로 하향 조정하고 홀딩', '평단가 관리 차원의 지속적 물타기 매수 집행', '원칙에 따라 뇌동을 제어하고 즉시 기계적 손절', '손실은 배제하고 반등 기대를 통한 무기한 보유']::text[], 2, '트레이딩의 승패는 예측이 아닌 ''리스크 통제''에 달려 있습니다. 사전에 정한 계좌 대비 2% 리스크 한도에 도달했을 때 희망 회로를 돌리며 손절을 미루거나 물타기를 집행하는 순간 계좌는 서서히 영으로 깎여 파산합니다. 멘탈의 충동을 통제하고 기계적으로 전량 칼손절하는 것이 절대 파산하지 않는 시장의 1법칙입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (157, '리스크/심리', '10_psychology_routine_review.md', '최근 3회 연속 거래에서 계속해서 손절(Stop Loss)을 맞아 뇌 내의 도파민 체계가 무너지고 심리가 극도로 불안해져 분노와 보복 매매 충동이 밀려옵니다. 이 상황에서 파산을 막는 가장 훌륭한 매매 심리 대처법은?', '[{"time":"Today","open":150,"high":150,"low":150,"close":150}]'::jsonb, '[]'::jsonb, ARRAY['손실 복구를 위해 레버리지를 증액해 즉시 진입', '뇌동 방지를 위해 HTS를 종료하고 매매 일지 작성 및 휴식', '추천 매매 신호 유료 리딩방에 즉시 가입 및 추종', '심리적 회복을 위해 역베팅 숏 포지션 추가']::text[], 1, '연속 손실 후 발생하는 복수심과 분노는 트레이더를 뇌동매매와 계좌 파멸로 이끄는 가장 치명적인 감정 상태입니다. 멘탈 붕괴를 느꼈을 때는 즉각 행동을 멈추고 시스템을 강제 종료하여 시장과 물리적 격리를 통해 냉정을 찾는 것만이 자산을 파산 리스크로부터 살려내는 훌륭한 트레이딩 행동입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (158, '셋업/실행', '09_risk_position_management.md', '진입하고자 하는 매수 자리를 분석해 보니, 기술적 분석 상 이길 수 있는 확률(승률)은 반반인 50% 수준입니다. 그러나 손절 시 기대 손실금액 대비 성공 시 획득할 수 있는 기대 수익금액의 비율(손익비)을 정밀 셋업 해보니 1 : 1.2 수준으로 다소 애매하게 도출되었습니다. 원칙 트레이더의 진입 결정은?', '[{"time":"Today","open":150,"high":150,"low":150,"close":150}]'::jsonb, '[]'::jsonb, ARRAY['단기 변동성 기대로 부적합한 손익비 시장가 진입', '마이너스 기댓값 거래 유보 및 우수 타점 대기', '레버리지를 높여 손익비 구조를 임의 조정 시도', '반대 방향으로 고배율 역베팅을 즉시 실행']::text[], 1, '수학적으로 승률 50%일 때 손익비가 최소 1:2(잃을 때 1, 벌 때 2) 이상이 나오지 않으면 복리 매매 시 수수료와 호가 슬리피지에 밀려 잔고가 무조건 마이너스로 수렴합니다. 타점이 눈에 들어오더라도 사전에 기대 손익비 필터에 걸려 탈락한다면 패스를 선언하고 관망하는 것이 현명한 생존 원칙입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (159, '리스크/심리', '09_risk_position_management.md', '갑작스러운 거시 경제 발표로 내가 매매 중인 종목의 캔들 변동성 폭(ATR)이 평소 시세의 2배 수준으로 널뛰기 시작했습니다. 1회 거래당 내 계좌 원금의 최대 2% 리스크 한도를 동일하게 고수하기 위해 취해야 할 올바른 조치는?', '[{"time":"Day 1","open":150,"high":153,"low":147,"close":150,"volume":87},{"time":"Day 2","open":150,"high":165,"low":135,"close":153,"volume":85}]'::jsonb, '[]'::jsonb, ARRAY['평소 변동성과 동일한 비중 및 손절 거리 고수', '손절 거리를 넓히는 대신 진입 포지션 수량 축소', '변동성이 확대되었으므로 2배 비중으로 적극 지름', '즉시 전량 손절하고 시장 상황 정상화 대기']::text[], 1, '시장 변동성이 커질 때는 손절 스톱 아웃이 잦으므로 손절폭(%)을 넓혀 숨 쉴 공간을 확보해 주는 것이 합리적입니다. 단, 손절폭을 2배로 늘린다면 계좌 대비 리스크 한도가 2배(4%)로 커지므로, 진입 포지션의 계약 수량을 50%로 줄여 리스크 노출 총액을 2%로 완벽하게 동일 통제하는 것이 포지션 사이징(Position Sizing)의 정석 원칙입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (160, '리스크/심리', '09_risk_position_management.md', '투자자 A의 전체 투자 원금은 750만 원이며, 1회 거래당 최대 허용 리스크 금액은 원금의 2%인 15만 원입니다. 현재 코인 가격가 15,000원이며, 기술적 분석 상 합리적인 손절선은 지지선 바로 밑인 14,250원(-5%)입니다. 2% 룰 리스크 관리 원칙에 따라 A가 진입(매수)해야 하는 최대 알트코인 수량은?', '[{"time":"Today","open":15000,"high":15000,"low":15000,"close":15000}]'::jsonb, '[]'::jsonb, ARRAY['500주 (투자금 전액 시장가 매수)', '200주 (손실 한도 15만 원 맞춤 매수)', '50주 (보수적 극단적 비중 축소)', '100주 (절반 비중 고정 매수)']::text[], 1, '포지션 크기 계산 공식은 `최대 매수 규모 = 최대 허용 리스크 금액 / 손절매 비율` 입니다. 이 시나리오에서 `150,000원 / 0.05(5%) = 3,000,000원`이 최대 허용 진입금액이 되며, 이를 코인 가격 15,000원으로 나누면 `200주`가 도출됩니다. 200주 진입 후 -5% 가격 폭락으로 손절 당해도 내 총원금에서 깎이는 돈은 정확히 15만 원(2%)으로 완벽히 리스크 통제됩니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (161, '거래량/유동성', '05_volume_liquidity.md', '코인 가격가 수평 저항선 부근까지 급상승했으나 캔들 몸통(Spread)이 지극히 좁아진 도지 형태로 마감하였고, 거래량은 이전 5일 평균 대비 3배 이상 폭증했습니다. VSA(Volume Spread Analysis) 관점에서 가장 타당한 차트 분석은?', '[{"time":"Day 1","open":150,"high":157.5,"low":148.5,"close":156,"volume":105},{"time":"Day 2","open":156,"high":163.5,"low":154.5,"close":162,"volume":91},{"time":"Day 3","open":162,"high":165,"low":160.5,"close":162,"volume":113}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":163.5},{"x":2,"y":163.5}],"label":"저항선","color":"#ef4444"}]'::jsonb, ARRAY['강한 매수 기세 기대로 즉시 돌파 매매 풀매수', '저항벽 매도 공급 세력 분산 확인 후 이익 실현', '대량 거래 확인에 따른 손절 해제 후 장기 투자', '반등 실패에 따른 고배율 보복 숏 베팅 가동']::text[], 1, '캔들 몸통 크기(스프레드)가 좁은데 거래량이 매우 크게 폭증했다는 것은 저항선 부근에서 들어오는 매수세만큼 세력의 매도 물량 공급이 쏟아져 막강한 저항 벽을 형성하고 있다는 뜻입니다. VSA에서는 이를 불화(Disharmony)로 규정하며 상승 추세 감속 및 하락 반전의 경고로 해독합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (162, '거래량/유동성', '05_volume_liquidity.md', '코인 가격가 장기 횡보하던 박스권 지지선인 300달러를 깨고 292.50달러까지 하락 투매가 발생했으나, 종가 마감 직전 거래량이 크게 실린 긴 아래꼬리를 그리며 다시 301.50달러 위로 복귀 안착했습니다. 이 스톱 헌팅 유동성 현상에서의 실전 트레이더의 대응은?', '[{"time":"Day 1","open":315,"high":318,"low":300,"close":303,"volume":85},{"time":"Day 2","open":303,"high":306,"low":292.5,"close":301.5,"volume":97}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":300},{"x":1,"y":300}],"label":"지지선","color":"#10b981"}]'::jsonb, ARRAY['지지선 붕괴 확정으로 간주한 시장가 숏 추격', '스윕(sweep) 판단 하에 아래꼬리 저점 손절 잡고 롱', '아무런 신호도 아니라고 판단하고 포지션 방치', '지지선 이탈 기대로 전량 손절 후 시장 영구 탈출']::text[], 1, '지지선 아래에 걸려 있던 개인들의 손절 주문(Sell Stop)을 강제로 청산(Liquidity Sweep)시킨 뒤, 세력이 물량을 헐값에 다 받아 삼켜 종가를 지지선 위로 신속하게 복귀시킨 휩소(베어 트랩) 패턴입니다. 아래꼬리 극점(292.50달러)에 아주 좁은 손절 라인을 설정할 수 있어, 기대 손익비가 극대화되는 고확률 상승 반전 매수 타점입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (163, '거래량/유동성', '05_volume_liquidity.md', '코인 가격는 375달러에서 435달러까지 계속 고점을 높이며 상승 추세를 이어가고 있습니다. 그러나 각 상승 파동마다 터지는 거래량은 전고점 돌파 시점 대비 눈에 띄게 하향 곡선을 그리며 감소하고 있습니다. VSA 기법에 따른 합리적인 진단은?', '[{"time":"Wave 1","open":345,"high":390,"low":342,"close":382.5,"volume":87},{"time":"Wave 2","open":382.5,"high":412.5,"low":375,"close":405,"volume":100},{"time":"Wave 3","open":405,"high":435,"low":397.5,"close":432,"volume":105}]'::jsonb, '[]'::jsonb, ARRAY['가격 상승으로 인한 매수 지속 강화 초강세', '매도 물량 고갈에 따른 무중력 안심 홀딩', '신규 자금 유입 둔화 거래량 다이버전스로 분할 익절', '지표 조작으로 판단하여 매매 중단 및 차트 종료']::text[], 2, '코인 가격는 상승하여 신고점을 갱신하지만 파동별 거래량이 지속 감소하는 흐름은 ''거래량 다이버전스''로 상승 모멘텀의 내부 엔진이 식어감을 경고합니다. 조만간 가벼운 매도 포격에도 대규모의 차익 실현 폭락 조정이 발생할 수 있는 잠재적 폭락 국면이므로 물량을 덜어내고 현금을 확보해야 합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (164, '거래량/유동성', '05_volume_liquidity.md', '가격이 이전 고점 저항선을 뚫고 강하게 솟구치며 장대양봉을 만들었습니다. 이때 가짜 이탈(Whipsaw / Bull Trap)이 아닌 진성 돌파(True Breakout)로 판정할 수 있는 가장 신뢰도 높은 거래량 기준은?', '[{"time":"Day 1","open":150,"high":153,"low":148.5,"close":150,"volume":383},{"time":"Day 2","open":150,"high":168,"low":148.5,"close":165,"volume":347}]'::jsonb, '[]'::jsonb, ARRAY['수렴 끝자락에서 거래량이 최저치인 상태 유지', '평균 대비 1.5~2배 이상 거래량 급증하며 돌파 마감', '거래량이 전혀 변하지 않는 평이한 상태 유지', '호가 스프레드가 가장 좁아지는 횡보 상태']::text[], 1, '참된 저항 돌파(True Breakout)는 저항선 부근의 두터운 대기 매도 공급 물량을 대규모 자금으로 전부 씹어 삼키고 돌파해야 함을 뜻합니다. 따라서 반드시 평균 대비 1.5배~2배 이상의 거래량 분출이 동반되어야 신뢰할 수 있으며, 거래량이 적은 돌파는 꼬리 달고 내려앉는 불 트랩(Bull Trap)일 확률이 매우 높습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (165, '거래량/유동성', '05_volume_liquidity.md', '이더리움 차트에서 중요 지지선 직전 저점 아래에 엄청난 규모의 롱 포지션 청산 및 매도 손절 주문이 쌓여 있는 유동성 풀(Liquidity Pool) 구간이 감지되었습니다. 세력이 이 구간을 공략할 때 나타날 캔들의 전형적인 무빙 패턴은?', '[{"time":"Day 1","open":75000,"high":75750,"low":73800,"close":74250,"volume":29},{"time":"Day 2","open":74250,"high":74700,"low":72000,"close":74400,"volume":24}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":73800},{"x":1,"y":73800}],"label":"전저점 지지선","color":"#3b82f6"}]'::jsonb, ARRAY['지지선을 장대음봉으로 돌파하여 20% 폭락 마감', '전저점 이탈로 손절 유도 후 지지선 위 아래꼬리 안착', '오차 없이 지지선 터치 후 꼬리 없는 수평 도지 횡보', '거래량 없이 즉각 상승 빔 분출로 전고점 탈환']::text[], 1, '기관 세력(스마트 머니)은 대량 포지션을 구축하기 위해 개인의 손절 주문(Sell Stop)을 의도적으로 터트려 매도 유동성을 유도한 후 이를 다 매수합니다. 이로 인해 코인 가격는 지지선 아래로 일시 급락 후(스톱 헌팅), 아래꼬리를 매우 길게 달며 지선 안쪽으로 급반등 마감하게 됩니다. 이것이 유동성 스윕(Liquidity Sweep)의 정석 패턴입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (166, '거래량/유동성', '05_volume_liquidity.md', '상승 추세 도중 전고점 저항선 부근에서 위꼬리가 아주 긴 캔들이 터졌고, 거래량은 최근 보름 중 최고 수치로 솟구쳤습니다. VSA 관점에서 이 상승 거절(Upside Rejection) 현상에 대한 올바른 대처는?', '[{"time":"Day 1","open":150,"high":172.5,"low":147,"close":151.5}]'::jsonb, '[]'::jsonb, ARRAY['강한 저점 매수 기회로 인지하여 비중 대폭 추가', '고점 매도 Rejection 확인 후 기존 롱 포지션 대피', '박스 횡보 수렴 기대로 마틴게일 추가 매수 가동', '이평선 정배열 판단에 따른 포지션 변경 없이 홀딩']::text[], 1, '위꼬리가 매우 긴 캔들이 대량 거래량과 함께 터졌다는 것은 고점 돌파 시도가 있었으나 그 자리에 숨어 있던 세력의 막강한 청산 매도 벽(Supply)을 만나 격렬하게 두들겨 맞고 밀려났음을 의미합니다. 상방 거절의 심리가 지배적이므로 고점 피로 및 하락 전환이 임박한 위험 징후입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (167, '지표/컨플루언스', '06_technical_indicators.md', '코인 가격가 장기 박스권 횡보를 이어가며 볼린저 밴드의 폭이 최근 몇 달 중 가장 좁은 형태로 밀착 수렴(Squeeze)되었습니다. 이 스퀴즈 국면에 대한 올바른 기술적 이해와 매매 시나리오는?', '[{"time":"Week 1","open":150,"high":154.5,"low":145.5,"close":151.5,"volume":107},{"time":"Week 2","open":151.5,"high":153,"low":148.5,"close":150,"volume":106}]'::jsonb, '[]'::jsonb, ARRAY['박스권 변동성 부재 기대로 장기 무대응 관망', '에너지 수축 스퀴즈 확인 후 밴드 이탈 돌파 대기', '지표 신뢰 불가 판단으로 볼린저 밴드 지표 삭제', '중심선 지지로 판단하여 고배율 매수 대기 주문']::text[], 1, '볼린저 밴드의 폭이 극도로 좁아지는 스퀴즈(Squeeze) 현상은 시장의 표준편차 변동성이 임계치까지 압축 수렴되었음을 알려줍니다. 에너지 압축 뒤에는 항상 폭발적인 가격 분출(상방/하방 이탈)이 뒤따르므로, 밴드를 뚫고 거래량이 실려 돌파 마감하는 방향으로 추세 추종 시나리오를 설계해야 합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (168, '지표/컨플루언스', '06_technical_indicators.md', '코인 가격는 HL(Higher Low)을 형성하며 이전 직전 저점(135달러)보다 높은 저점(142.50달러)을 지키고 있으나, RSI 지표는 이전 35 수치보다 더 깊숙하게 25 수치까지 떨어졌습니다. 이 지표 불일치 현상의 공식 명칭과 올바른 포지션 셋업은?', '[{"time":"Day 1","open":150,"high":153,"low":135,"close":136.5,"volume":97},{"time":"Day 2","open":136.5,"high":144,"low":142.5,"close":142.5,"volume":103}]'::jsonb, '[]'::jsonb, ARRAY['일반 상승 다이버전스 - 추세 종결로 즉각 공매도', '히든 상승 다이버전스 - 지선 눌림목 롱 진입 활용', '일반 하락 다이버전스 - 모든 매수 포지션 정리', '지표 오작동 휩소 구간 판단으로 양방향 관망']::text[], 1, '가격의 저점은 높아졌는데(Higher Low) 모멘텀 지표의 저점은 낮아지는 현상은 ''히든 상승 다이버전스(Hidden Bullish Divergence)''입니다. 이는 추세 반전이 아닌 **기존 강세 추세 지속**을 뜻하며, 조정 눌림목이 완성되고 다음 상승 랠리를 준비한다는 최고의 매수 신호 중 하나입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (169, '지표/컨플루언스', '06_technical_indicators.md', '매수 타점을 신중하게 선별하고자 합니다. 기술적 분석의 성공 확률을 비약적으로 끌어올리는 ''다중 컨플루언스(Confluence)'' 결합 사례로 가장 적합한 조건 구성은?', '[{"time":"Today","open":150,"high":150,"low":150,"close":150}]'::jsonb, '[]'::jsonb, ARRAY['트위터 및 뉴스의 호재 찌라시 확인 즉시 추격', '지지선+이평선+다이버전스+아래꼬리 등 분석 중첩 시', 'RSI 과매수 영역 진입 즉시 롱 포지션 진입', '독립적 분석 없이 오직 보조지표의 단일 수치 신호']::text[], 1, '다중 컨플루언스(Confluence)는 독립적인 기술적 근거들이 동일한 특정 가격 구역에 중첩되는 현상입니다. 지지 저항, 이평선, 보조지표 다이버전스, 캔들 가격행동(Rejection 핀바)이 한 곳에 묶여 매수 자리를 형성할 때 매매를 실행하면, 높은 신뢰도와 좁은 손절 라인 덕분에 장기 기대값이 극대화됩니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (170, '셋업/실행', '08_setup_entry_exit.md', '중요 수평 저항선(180달러)을 상방으로 장대양봉 종가 돌파한 것을 확인하고 롱(매수) 진입 셋업을 준비하고 있습니다. 원칙 트레이더가 뇌동매매 추격을 막고 최상의 손익비를 확보하기 위해 즐겨 쓰는 정석적인 진입 실행법은?', '[{"time":"Day 1","open":165,"high":168,"low":163.5,"close":166.5,"volume":100},{"time":"Day 2","open":166.5,"high":186,"low":165,"close":183,"volume":87}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":180},{"x":1,"y":180}],"label":"저항선","color":"#ef4444"}]'::jsonb, ARRAY['돌파 마감 확인 즉시 시장가 추가 매수 집행', '돌파된 저항선의 지지 전환(Retest) 시 지정가 진입', '반등 조정이 불가능하다고 판단하여 최고점 롱 추격', '속임수 돌파 확신으로 고배율 역베팅 숏 진입']::text[], 1, '저항 돌파 후 즉시 가격을 따라붙는 추격 매수는 휩소 조정 시 심각한 손실을 초래합니다. 돌파된 라인이 S/R Flip을 통해 지지로 작용하는지 확인하는 되돌림 리테스트(Retest) 시점에 진입하는 것이, 지선 바로 아래에 좁은 손절 라인을 설계하고 이익 기대 폭을 넓힐 수 있는 가장 이상적인 정석 실행법입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (171, '셋업/실행', '08_setup_entry_exit.md', '포지션 진입 직후, 가격이 계획대로 내 방향으로 순탄하게 우상향하고 있습니다. 기존 진입 시 설정한 손익비 1:2의 최종 목표가 도달 전에, 리스크 관리 차원에서 계좌 드로다운을 0으로 만드는 정석적인 1차 포지션 관리 행동은?', '[{"time":"Entry","open":150,"high":150,"low":150,"close":150,"volume":106},{"time":"Day 1","open":150,"high":159,"low":150,"close":157.5,"volume":110}]'::jsonb, '[]'::jsonb, ARRAY['1차 저항대 진입 시 레버리지를 활용해 불타기', '목표가 터치 시까지 100% 비중 무대응 홀딩', '1:1 지점 50% 분할 익절 및 남은 물량 본전 손절 상향', '단기 반등 확인 즉시 전량 기계적 청산 및 퇴장']::text[], 2, '이득이 발생해 손익비 1:1 수준에 오면 물량의 절반을 분할 익절(Scale-out)하고 남은 포지션의 스톱로스를 진입가로 이동(Break-even)시키는 것이 포지션 관리의 기본입니다. 이렇게 셋업하면 차트가 갑자기 폭락세로 뒤집혀도 최소 본전 혹은 반절 익절 약수익으로 끝나 해당 거래의 최대 리스크가 Zero(0)로 봉쇄됩니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (172, '셋업/실행', '08_setup_entry_exit.md', '강력한 장기 상승 추세가 터져 코인 가격가 20일 이평선을 타고 계속해서 폭발적으로 신고가를 갱신하고 있습니다. 이때 익절 시점을 서둘러 잡지 않고, 추세 상승 이익을 최대한 길게 끝까지 빨아먹기 위한 정석 청산 실행법은?', '[{"time":"Day 1","open":150,"high":165,"low":148.5,"close":162,"volume":112},{"time":"Day 2","open":162,"high":180,"low":160.5,"close":177,"volume":109},{"time":"Day 3","open":177,"high":202.5,"low":175.5,"close":198,"volume":116}]'::jsonb, '[]'::jsonb, ARRAY['RSI 과과열 조짐 확인 즉시 시장가 전량 익절', 'Higher Low 지지 직하방으로 손절 추종 익절 셋업', '이익 보존을 포기하고 손익절 라인을 해제 후 홀딩', '즉시 숏 포지션 10배로 맞불을 놓는다']::text[], 1, '강세 추세가 터졌을 때 지레짐작으로 청산하면 상승 파동의 초입만 먹고 끝납니다. 추세 붕괴의 명확한 신호(BOS/MSB)가 나오거나, 가격의 구조적 높은 저점(HL)이 깨질 때까지 손절 라인을 계속 추종해서 상향하는 ''추격 손절매(Trailing Stop)''를 가동하는 것이 추세 이익을 극대화하는 정석 기법입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (173, '셋업/실행', '01_chart_market_basics.md', '차트 분석 결과, 돌파 시점의 체결 변동성과 거래소 호가창의 얇은 매물 상태를 감안할 때 내가 진입하려는 주문 가격에서 체결이 뒤로 밀리는 ''슬리피지(Slippage)''가 심각하게 예상됩니다. 이를 감안한 올바른 주문 실행법은?', '[{"time":"Today","open":150,"high":150,"low":150,"close":150}]'::jsonb, '[]'::jsonb, ARRAY['시장가로 최고 배율을 설정하여 즉시 체결', '돌파 확인 후 지정가 대기 주문으로 단가 조절', '슬리피지를 예방하기 위해 즉각적인 거래 취소', '호가창 스프레드와 무관하게 고배율 레버리지']::text[], 1, '변동성이 크고 호가가 얇은 시장에서 돌파 시 시장가 진입은 나쁜 단가로 체결되는 슬리피지 비용을 발생시켜 시작부터 손실을 크게 안고 갑니다. 돌파 확인 후 되돌림 가격대에서 지정가(Limit Order)를 대기시켜 체결 단가를 내 손아귀에 고정하는 리스크 관리가 필요합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (174, '셋업/실행', '10_psychology_routine_review.md', '원칙 기반의 정석 매매 셋업(Trading Setup)을 설계할 때, 진입 전 반드시 사전에 수치로 명문화되어 결정되어야 할 요소가 아닌 것은?', '[{"time":"Today","open":150,"high":150,"low":150,"close":150}]'::jsonb, '[]'::jsonb, ARRAY['진입 조건(Trigger)과 구체적인 손절 가격(Stop Loss)', '거래 당일 본인의 주관적인 직감과 감정적 목표가', '진입하려는 구체적인 포지션 규모 및 분할 익절선', '거래 아이디어가 무효화되는 구체적 가격 지점']::text[], 1, '매매 셋업은 규칙에 기반한 수치들(진입가, 손절가, 목표가, 수량)로 사전에 철저히 규격화되어야 합니다. 당일의 운이나 주관적 느낌, 예감에 기초한 비과학적 청산 설정은 셋업에서 배제되어야 할 대표적 뇌동매매 요소입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (175, '셋업/실행', '08_setup_entry_exit.md', '하락 횡보하던 코인 가격가 중요 매물대이자 피보나치 되돌림 0.618 지점에 정확히 맞닿아 아래꼬리가 긴 양봉 핀바(Pin Bar)를 그리며 마감했습니다. 룰베이스 트레이더가 진입 버튼을 누를 때 성립된 IF-THEN 시나리오는?', '[{"time":"Day 1","open":150,"high":150,"low":120,"close":123,"volume":118},{"time":"Day 2","open":123,"high":129,"low":117,"close":127.5,"volume":98}]'::jsonb, '[]'::jsonb, ARRAY['익일 가격 상황과 관계없이 100배 레버리지 진입', '중첩 자리 핀바(rejection) 확인 후 익일 시가 롱 진입', '상단 저항 도달 판단으로 즉각적인 숏 포지션 진입', '돌파 랠리가 완전히 끝날 때까지 HTS 종료 및 관망']::text[], 1, '훌륭한 트레이딩 실행은 ''IF(조건 만족 시) ➔ THEN(원칙대로 포지션 진입 및 손절/목표가 기계적 배치)''의 룰베이스 알고리즘에 의해 움직여야 감정을 배제할 수 있습니다. 지지 구간 중첩과 핀바 출현 조건이 성립했으므로 다음 봉 시가에 진입하되 꼬리 저점 이탈 시 칼손절하여 리스크를 통제하는 것이 정석입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (176, '리스크/심리', '09_risk_position_management.md', '나의 트레이딩 시스템 승률이 40%로 다소 낮게 고정되어 있습니다. 이 시스템을 통해 장기적으로 파산하지 않고 복리로 계좌 자산을 우상향시키기 위해 필수적으로 지켜야 할 손익비(평균손실 대비 평균수익 비율)의 최소 기준은?', '[{"time":"Today","open":150,"high":150,"low":150,"close":150}]'::jsonb, '[]'::jsonb, ARRAY['손익비 1:1 수준 (매매 승률이 낮을 때 파산)', '승률 40% 대비 기댓값 개선을 위한 손익비 1:1.5 이상', '낮은 승률 상태에서 손익비와 무관하게 무조건 파산', '승률 극복을 위한 레버리지 20배 수준 설정']::text[], 1, '승률이 40%일 때 기대값 수학적 수수료 감안 최소 손익비는 1:1.5입니다. 손익비 1.5배 이상 구간만 취하면 10번 중 6번 손절당하고 단 4번만 익절하더라도 계좌 총합은 수익 우위에 서게 됩니다. 저승률 시스템일수록 철저히 손익비가 유리한 진입가 근처 타점만 기계적으로 필터링해 진입해야 생존합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (177, '리스크/심리', '09_risk_position_management.md', '선물 트레이더인 B는 담보금 효율을 극대화한다는 명목으로 50배 레버리지 롱 포지션 진입을 실행했습니다. 진입 가격 대비 B의 포지션 원금이 완전 소멸(강제 청산)되는 역방향 하락 거리(%)는 대략 몇 % 수준입니까?', '[{"time":"Today","open":150,"high":150,"low":150,"close":150}]'::jsonb, '[]'::jsonb, ARRAY['진입 단가 대비 20.0%의 강한 하락 발생 시', '진입 단가 대비 단 -2.0% 변동성 노이즈 터치 시', '진입 단가 대비 50.0%의 강한 폭락 발생 시', '청산가가 산출되지 않는 특이 종목 거래 시']::text[], 1, '청산 거리 계산 공식은 대략 `100% / 레버리지 배수` 입니다. 50배 고배율 레버리지의 경우, 내 포지션 반대 방향으로 단 **-2%**의 시세 변동성(장중 흔한 잔파동 노이즈)만 터치해도 원금이 100% 강제 청산 증발됩니다. 고배율 레버리지는 수학적 확률상 100% 파멸을 초래하는 도박성 거래 행위입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (178, '리스크/심리', '09_risk_position_management.md', '트레이딩 계좌 총자산이 3,000만 원인 트레이더가 있습니다. 1회 거래당 총자산의 2% 룰 원칙에 근거하여 리스크 한도(60만 원)를 설정했습니다. 진입하려는 종목의 손절가 거리가 -8%인 경우, 2% 룰을 완벽하게 충족하는 최대 진입(매수) 금액은?', '[{"time":"Today","open":150,"high":150,"low":150,"close":150}]'::jsonb, '[]'::jsonb, ARRAY['3,000만 원 전액 매수 (손절 폭을 배제한 대규모 베팅)', '750만 원 진입 (-8% 손절 시 리스크 한도 60만 원 충족)', '1,500만 원 진입 (손익비 1:1 기준에 맞춘 베팅)', '300만 원 진입 (보수적 원칙에 입각한 극단적 축소)']::text[], 1, '포지션 사이징 공식은 `진입금액 = 최대 리스크 허용액(60만 원) / 손절 비율(0.08)` 입니다. 이에 따라 `600,000원 / 0.08 = 7,500,000원`이 도출됩니다. 750만 원 규모로 매수 진입 시 가격이 급락해 -8% 손절 라인을 때려도 내 총자산에서 깎이는 금액은 정확히 원칙 한도인 60만 원(2%)으로 제한되어 계좌가 완벽히 방어됩니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (179, '리스크/심리', '10_psychology_routine_review.md', '장중에 내가 째려보며 타점을 기다리던 알트코인이 아무런 조정도 없이 장대양봉을 그리며 갑자기 수직 폭등하기 시작하여 5% 이상 치솟았습니다. 이때 머릿속에 ''나만 두고 날아가는 것 아닌가''하는 극심한 소외감 공포(FOMO)가 솟구칩니다. 원칙 트레이더의 올바른 심리 대응은?', '[{"time":"Day 1","open":150,"high":153,"low":148.5,"close":150,"volume":84},{"time":"Day 2","open":150,"high":159,"low":150,"close":157.5,"volume":101}]'::jsonb, '[]'::jsonb, ARRAY['추세 연장 판단으로 시장가 전액 추격 매수', 'FOMO 판단 하에 매수 보류 및 정석 되돌림 타점 대기', '돌파 실패 판단 하에 반대 방향 고배율 숏 베팅', '거래를 종료하고 즉각 알트코인 시장에서 전량 탈출']::text[], 1, '나만 기회를 잃는다는 공포(FOMO)로 날아가는 장대양봉 꼭대기에서 추격 매수하는 행위는 고점 물리기를 자처하는 가장 흔한 뇌동매매 패턴입니다. 내 타점을 비껴간 상승은 내 돈이 아니라고 인정하고, 사전에 정의한 룰베이스 타점까지 냉정하게 대기하는 것이 장기 생존자의 멘탈 습관입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (180, '리스크/심리', '10_psychology_routine_review.md', '오전 거래에서 원칙을 어긴 무리한 진입으로 인해 3회 연속 스톱아웃(손절)을 당하여 당일 원금의 -6%의 큰 손실을 입었습니다. 본전 생각과 분노로 눈이 뒤집혀 비중을 올려 한 판으로 복수하려는 ''보폭 매매'' 충동이 폭발할 때, 파산을 막는 가장 강력한 멘탈 시스템 룰은?', '[{"time":"Today","open":150,"high":150,"low":150,"close":150}]'::jsonb, '[]'::jsonb, ARRAY['손실 만회를 위해 빌린 돈으로 100배 고배율 복수 베팅', '일일 손실 한도 도달에 따른 매매 강제 종료 및 격리', '주변 유료 전문가 추천 종목을 탐색해 즉각 매수', 'RSI 과매도 상태이므로 즉시 반대 숏 포지션 진입']::text[], 1, '연패를 겪은 후 홧김에 비중을 더 크게 실어 한 번에 본전을 찾으려는 보복 매매는 계좌를 하루 만에 휴지조각으로 만드는 가장 무서운 파산 유도 심리 상태입니다. 이를 막기 위해 하루 최대 손실 한도 한계선(예: 3회 손절 또는 원금의 5%)을 정해두고, 이 한계선 터치 시 즉시 차트를 종료하고 냉각기를 강제 집행하는 룰이 필수입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (201, '캔들/가격행동', '02_candlestick_price_action.md', '하락 추세 지속 도중 바닥권에서 몸통이 짧고 아래꼬리가 몸통의 2배 이상인 아래 캔들이 출현했습니다. 이 캔들의 명칭과 올바른 대응은?', '[{"time":"10:00","open":240,"high":244,"low":236,"close":238,"volume":92},{"time":"10:15","open":238,"high":240,"low":226,"close":228,"volume":97},{"time":"10:30","open":228,"high":230,"low":216,"close":218,"volume":113},{"time":"10:45","open":218,"high":220,"low":202,"close":204,"volume":108},{"time":"11:00","open":204,"high":206,"low":180,"close":202,"volume":116}]'::jsonb, '[]'::jsonb, ARRAY['역망치형 (Inverted Hammer) - 하락 경고 및 공매도 대기', '망치형 (Hammer) - 저점 지지 및 분할 매수 대기', '도지 (Doji) - 매수세와 매도세의 팽팽한 균형 및 관망', '하락 장악형 (Bearish Engulfing) - 추세 반전 및 즉시 손절']::text[], 1, '마지막 캔들은 아래꼬리가 긴 ''망치형(Hammer)'' 캔들로 하락 압력을 이겨내고 저가 매수세가 밀어 올렸음을 의미하는 대표적 상승 전환 신호입니다. 지지를 확인한 뒤 분할 매수 관점으로 대기해야 합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (202, '캔들/가격행동', '02_candlestick_price_action.md', '시세가 장기간 급등한 뒤, 고점 부근에서 위꼬리가 매우 길고 몸통이 짧은 형태의 캔들이 발생했습니다. 이 캔들의 해석으로 가장 적절한 것은?', '[{"time":"Day 1","open":200,"high":216,"low":198,"close":210,"volume":113},{"time":"Day 2","open":210,"high":230,"low":208,"close":224,"volume":102},{"time":"Day 3","open":224,"high":250,"low":222,"close":246,"volume":124},{"time":"Day 4","open":246,"high":256,"low":240,"close":252,"volume":94},{"time":"Day 5","open":252,"high":290,"low":250,"close":254,"volume":100}]'::jsonb, '[]'::jsonb, ARRAY['유성형 (Shooting Star) - 고점 저항 및 하락 전환 예고', '망치형 (Hammer) - 저점 매수세 유입 및 상승 랠리 기대', '상승 장악형 (Bullish Engulfing) - 추세 반전 및 홀딩 유도', '도지 (Doji) - 추세 지속 가능성 및 일시 관망']::text[], 0, '급등세 끝에서 위꼬리가 몸통보다 훨씬 길게 솟아오른 캔들은 ''유성형(Shooting Star)''입니다. 장중 상승 시도를 강력한 차익 실현 및 매도 압력이 짓눌렀음을 보여주며, 하락 추세 전환의 강력한 경고 시그널입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (203, '캔들/가격행동', '02_candlestick_price_action.md', '직전의 음봉 몸통을 다음 날의 거대한 양봉 몸통이 완전히 감싸 안는 아래 형태가 포착되었습니다. 이 패턴의 이름과 신뢰도는?', '[{"time":"Day 1","open":196,"high":200,"low":190,"close":192,"volume":118},{"time":"Day 2","open":192,"high":194,"low":184,"close":186,"volume":118},{"time":"Day 3","open":186,"high":190,"low":176,"close":178,"volume":90},{"time":"Day 4","open":174,"high":204,"low":172,"close":202,"volume":104}]'::jsonb, '[]'::jsonb, ARRAY['하락 장악형 (Bearish Engulfing) - 추세 반전 신뢰도 낮음', '상승 장악형 (Bullish Engulfing) - 매수 전환 신뢰도 높음', '상승 관통형 (Piercing Line) - 중간 강도의 반전 신호', '석별형 (Evening Star) - 상승 추세 종결 신호']::text[], 1, '전일의 하락 음봉 몸통을 다음 날의 장대 양봉이 완전히 덮어버리는 형태를 ''상승 장악형(Bullish Engulfing)'' 패턴이라고 합니다. 하락 추세 끝에서 나타날 경우 단기 하락세가 종료되고 강력한 매수세가 들어왔음을 뜻해 전환 신뢰도가 매우 높습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (204, '캔들/가격행동', '01_chart_market_basics.md', '시가와 종가가 거의 일치하여 몸통이 거의 없고 위아래 꼬리만 달린 십자(+) 모양 캔들이 출현했습니다. 이 캔들에 대한 올바른 해석은?', '[{"time":"Day 1","open":300,"high":310,"low":296,"close":304,"volume":100},{"time":"Day 2","open":304,"high":312,"low":302,"close":308,"volume":118},{"time":"Day 3","open":308,"high":318,"low":300,"close":308,"volume":94}]'::jsonb, '[]'::jsonb, ARRAY['상승세 동력 상실로 인한 추세의 하방 반전', '매수/매도 세력 균형에 따른 도지(Doji) 횡보', '매도세 지배에 따른 즉각적인 숏 포지션 진입', '하락 세력 이탈로 인한 즉각적인 상승 랠리']::text[], 1, '시가와 종가가 거의 같은 십자 모양의 캔들은 ''도지(Doji)'' 캔들입니다. 이는 힘의 균형이 팽팽함을 시사하며, 기존 추세의 힘이 빠지고 잠재적인 방향성 전환(상승/하락 모두 포함)의 변곡점이 다가오고 있음을 의미합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (205, '캔들/가격행동', '02_candlestick_price_action.md', '상승 추세 고점에서 직전 양봉의 몸통을 거대 음봉이 아래로 덮어버리는 캔들 조합이 발생했습니다. 이 현상을 의미하는 용어는?', '[{"time":"Day 1","open":240,"high":250,"low":238,"close":248,"volume":117},{"time":"Day 2","open":248,"high":260,"low":246,"close":258,"volume":104},{"time":"Day 3","open":260,"high":262,"low":230,"close":232,"volume":125}]'::jsonb, '[]'::jsonb, ARRAY['하락 장악형 (Bearish Engulfing) - 고점 하락 전환 예고', '상승 장악형 (Bullish Engulfing) - 고점 돌파 랠리 예고', '하락 잉태형 (Harami) - 기존 하락세의 일시 둔화', '샛별형 (Morning Star) - 바닥권 상승 반전 예고']::text[], 0, '고점에서 직전 양봉을 음봉이 감싸 안은 형태는 ''하락 장악형(Bearish Engulfing)''입니다. 매수 세력을 매도 공급이 압도했다는 명백한 증거로, 시세 추세가 하락으로 반전할 리스크가 큽니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (206, '시장구조/SR', '03_market_structure.md', '시세가 장기 저항선인 300달러를 거래량 실린 강한 캔들로 돌파한 뒤, 다시 300달러 부근으로 내려와 버티고 있습니다. 가장 안전한 진입 방식은?', '[{"time":"Day 1","open":280,"high":296,"low":278,"close":290,"volume":103},{"time":"Day 2","open":290,"high":298,"low":286,"close":288,"volume":91},{"time":"Day 3","open":288,"high":312,"low":286,"close":308,"volume":127},{"time":"Day 4","open":308,"high":310,"low":298,"close":302,"volume":357},{"time":"Day 5","open":302,"high":306,"low":300,"close":304,"volume":408}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":300},{"x":4,"y":300}],"label":"돌파된 저항선 -> 지지선 전환선","color":"#3b82f6"}]'::jsonb, ARRAY['돌파 시점에 시장가로 즉시 진입하는 추격 매수', '돌파 후 저항선의 지지선 전환(Retest) 확인 시 진입', '이전 최저가 부근인 280달러 조정 시까지 대기 매수', '돌파 후 즉시 단기 조정을 예상한 역추세 숏 진입']::text[], 1, '저항선이 강하게 뚫리면 역할 전환(Role Reversal)에 의해 신규 지지선으로 바뀝니다. 돌파 시점에 뇌동매매하기보다는 돌파된 선 부근으로 시세가 눌려 지지(Retest)를 완성할 때 진입하는 것이 리스크 대비 기대 수익이 큽니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (207, '거래량/유동성', '05_volume_liquidity.md', '시세가 저항선 위로 거래량 없이 장대양봉을 뿜어 올렸으나, 다음 날 곧바로 장대음봉으로 밀어붙이며 저항선 아래로 내려왔습니다. 이 현상의 명칭은?', '[{"time":"Day 1","open":196,"high":202,"low":194,"close":200,"volume":95},{"time":"Day 2","open":200,"high":204,"low":198,"close":202,"volume":85},{"time":"Day 3","open":202,"high":220,"low":200,"close":216,"volume":33},{"time":"Day 4","open":216,"high":218,"low":190,"close":192,"volume":22}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":204},{"x":3,"y":204}],"label":"저항선","color":"#ef4444"}]'::jsonb, ARRAY['진짜 상승 돌파 (True Breakout)', '불 트랩 (Bull Trap) - 매수자 청산 유도 가짜 돌파', '베어 트랩 (Bear Trap) - 매도자 청산 유도 가짜 하방', '골든 크로스 (Golden Cross) - 이평선 돌파']::text[], 1, '저항선을 일시적으로 뚫었다가 대량 매도세와 함께 직후 캔들에서 하방으로 원상복귀하는 현상을 ''불 트랩(Bull Trap/가짜 돌파)''이라고 합니다. 돌파 후 리테스트를 기다리지 않고 급히 추격 매수했던 투자자들이 고점에 물리는 대표적 함정입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (208, '시장구조/SR', '01_chart_market_basics.md', '아래 차트에서 3번 연속 강하게 반등하며 가격 하락을 저지해 준 주요 가격대는 무엇을 의미하나요?', '[{"time":"Day 1","open":200,"high":204,"low":180,"close":182,"volume":81},{"time":"Day 2","open":182,"high":196,"low":180,"close":194,"volume":103},{"time":"Day 3","open":194,"high":210,"low":192,"close":208,"volume":88},{"time":"Day 4","open":208,"high":212,"low":182,"close":184,"volume":113},{"time":"Day 5","open":184,"high":200,"low":180,"close":198,"volume":126}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":180},{"x":4,"y":180}],"label":"180달러선","color":"#10b981"}]'::jsonb, ARRAY['강력한 저항선 (Resistance Line) - 매도 매물대', '강력한 지지선 (Support Line) - 매수 매물대', '골든크로스 수렴선 - 이평선 밀집대', '이격도 붕괴선 - 가격 과열 분기점']::text[], 1, '특정 가격(180달러)에 접근할 때마다 대기 중이던 저가 매수세가 유입되어 시세의 추가 하락을 방어해 준 이 라인은 ''강력한 지지선(Support Line)''입니다. 이탈하기 전까지는 손절 라인을 바로 밑에 두고 진입하기에 가장 손익비 좋은 구간입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (209, '거래량/유동성', '05_volume_liquidity.md', '지지선 아래로 시세가 이탈하여 공매도가 폭증했으나, 이내 거래량이 급증하며 양봉으로 지지선을 회복한 뒤 반등을 시작했습니다. 이 현상의 명칭은?', '[{"time":"Day 1","open":240,"high":244,"low":236,"close":238,"volume":91},{"time":"Day 2","open":238,"high":240,"low":220,"close":222,"volume":108},{"time":"Day 3","open":222,"high":246,"low":220,"close":244,"volume":119}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":230},{"x":2,"y":230}],"label":"지지선","color":"#10b981"}]'::jsonb, ARRAY['불 트랩 (Bull Trap) - 가짜 상방 돌파', '베어 트랩 (Bear Trap) - 가짜 하방 이탈', '리테스트 실패 - 지지선 붕괴', '추세 추종 돌파 - 하방 랠리 가속']::text[], 1, '지지선을 아래로 뚫고 내려가 하락세가 지속될 것처럼 유도한 뒤, 매물을 털어내고 강력하게 다시 반등해 올리는 현상을 ''베어 트랩(Bear Trap)''이라고 합니다. 하락 돌파로 생각하고 공매도를 치거나 손절했던 사람들의 손실을 강제하며 가격이 급등하게 만듭니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (210, '시장구조/SR', '04_patterns_breakout.md', '저항선을 뚫어내기 직전 돌파 전조 현상 중 하나인 ''지지점 상승''의 특징을 골라보세요.', '[{"time":"Day 1","open":200,"high":210,"low":180,"close":204,"volume":84},{"time":"Day 2","open":204,"high":210,"low":186,"close":206,"volume":120},{"time":"Day 3","open":206,"high":210,"low":192,"close":208,"volume":105}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":210},{"x":2,"y":210}],"label":"저항선 (105)","color":"#ef4444"}]'::jsonb, ARRAY['저항선 부근에서 고점들이 점점 급락하며 붕괴하는 현상', '저항선 부근에서 저점들을 높여가며 밀어 올리는 수렴 현상', '거래량이 완전히 소멸하여 긴 횡보 상태를 보이는 현상', '지속적인 매도세로 인해 갑작스럽게 급락하는 현상']::text[], 1, '저항을 뚫지 못하고 밀려 내려올 때, 이전 저점보다 높은 지점에서 저점을 계속 잡아 올려주는 것은 매도 압력보다 매수 압력이 점점 올라오고 있음을 의미합니다. 수렴 끝에 돌파가 나타날 신뢰도가 매우 높습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (211, '추세/레짐', '03_market_structure.md', '저점들을 연결한 우상향 상승 추세선 아래로 캔들의 종가(마감가격)가 이탈했습니다. 기술적 분석 관점의 올바른 해석은 무엇입니까?', '[{"time":"W-5","open":200,"high":210,"low":200,"close":206,"volume":96},{"time":"W-4","open":206,"high":220,"low":204,"close":216,"volume":121},{"time":"W-3","open":216,"high":218,"low":210,"close":212,"volume":117},{"time":"W-2","open":212,"high":230,"low":214,"close":226,"volume":122},{"time":"Today","open":226,"high":228,"low":206,"close":208,"volume":114}]'::jsonb, '[{"type":"line","points":[{"x":0,"y":200},{"x":2,"y":210},{"x":4,"y":220}],"label":"상승 추세선","color":"#10b981"}]'::jsonb, ARRAY['추세선 이탈은 영향이 없으므로 비중 유지', '상승 추세 붕괴로 하락 반전 대비 비중 축소', '일시적인 속임수이므로 추가 불타기 진입', '채널 상단 도달에 따른 즉각적인 매수 대응']::text[], 1, '신뢰받던 우상향 상승 추세선 하방으로 캔들의 종가가 이탈 마감하는 것은 매수 중심의 시장 주도권이 붕괴했음을 뜻합니다. 지지를 잃은 하락 가속화 리스크에 대비해야 합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (212, '추세/레짐', '07_multitimeframe_regime.md', '아래 차트에서 고점들과 저점들이 일정한 평행 통로를 그리며 하락하고 있습니다. 채널 하단에 도달했을 때 단기 반등을 목표로 하는 매매의 명칭과 관점은?', '[{"time":"Day 1","open":300,"high":304,"low":270,"close":280,"volume":117},{"time":"Day 2","open":280,"high":294,"low":278,"close":290,"volume":113},{"time":"Day 3","open":290,"high":292,"low":256,"close":260,"volume":114},{"time":"Day 4","open":260,"high":276,"low":258,"close":272,"volume":131},{"time":"Day 5","open":272,"high":274,"low":236,"close":240,"volume":132}]'::jsonb, '[{"type":"channel","points":[{"x":0,"y":300},{"x":4,"y":270},{"x":0,"y":270},{"x":4,"y":240}],"label":"하향 평행 채널","color":"#f59e0b"}]'::jsonb, ARRAY['추세 추종 매매 - 대세 상승이므로 장기 보유', '채널 하단 반등 매매 - 단기 역추세 매수 대응', '양방향 물타기 매매 - 평단가를 낮춰 탈출 대기', '돌파 매매 - 채널 하방 붕괴 확정 시 매수 대응']::text[], 1, '가격이 평행한 하락 터널 내에서 움직이는 ''하향 평행 채널(Descending Channel)''입니다. 채널 하단 라인 터치 시에는 기술적 단기 반등이 자주 출현하므로, 손절선을 짧게 잡고 반등 타점을 노리는 역추세(Counter-trend) 트레이딩이 가능합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (213, '추세/레짐', '03_market_structure.md', '우상향 상승 평행 채널의 상단 저항선 부근까지 시세가 도달했습니다. 합리적인 추세 채널 트레이더의 대응은?', '[{"time":"Day 1","open":200,"high":204,"low":198,"close":202,"volume":107},{"time":"Day 2","open":202,"high":216,"low":202,"close":214,"volume":122},{"time":"Day 3","open":214,"high":218,"low":208,"close":210,"volume":104},{"time":"Day 4","open":210,"high":230,"low":210,"close":228,"volume":92},{"time":"Day 5","open":228,"high":232,"low":224,"close":226,"volume":133}]'::jsonb, '[{"type":"channel","points":[{"x":0,"y":204},{"x":4,"y":230},{"x":0,"y":198},{"x":4,"y":224}],"label":"상승 평행 채널","color":"#10b981"}]'::jsonb, ARRAY['채널 상방 돌파를 예상한 고배율 레버리지 매수', '채널 상단 저항에 따른 분할 익절 및 대기', '채널 중간 조정 시 지정을 통한 시장가 추격', '채널 붕괴 신호에 따른 전량 기계적 손절']::text[], 1, '상승 채널이라고 해도 상단 저항선에 닿으면 다시 채널 하단이나 중심선까지 조정을 받을 가능성이 매우 큽니다. 따라서 고점 영역에서의 추격매수를 금지하고, 기존 포지션을 분할 익절하는 기회로 삼아야 합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (214, '추세/레짐', '01_chart_market_basics.md', '고점들을 잇는 우하향 하락 추세선을 시세가 대량의 거래량을 동반하며 장대양봉 종가로 상향 돌파(Breakout)했습니다. 의미하는 시그널은?', '[{"time":"Day 1","open":260,"high":264,"low":250,"close":254,"volume":113},{"time":"Day 2","open":254,"high":256,"low":240,"close":244,"volume":114},{"time":"Day 3","open":244,"high":246,"low":230,"close":234,"volume":114},{"time":"Day 4","open":234,"high":256,"low":232,"close":254,"volume":107}]'::jsonb, '[{"type":"line","points":[{"x":0,"y":262},{"x":2,"y":244},{"x":3,"y":236}],"label":"하락 추세선","color":"#ef4444"}]'::jsonb, ARRAY['하락 추세 지속에 따른 숏 포지션 추가 매수', '하락 추세 돌파 및 상승 전환 가능성에 따른 매수', '속임수 돌파를 예상한 즉시 반대 숏 포지션 진입', '추세와 무관하게 횡보 흐름으로 판단해 관망']::text[], 1, '중요한 하락 추세선을 시세 몸통이 확실하게 뚫고 마감하는 것은 기존 하락 관성의 지배력이 종료되고 상승 추세로 돌아설 수 있는 가장 대표적인 추세 전환(Reversal) 확인 시그널입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (215, '추세/레짐', '03_market_structure.md', '추세선 작도 시 신뢰도를 판단하는 가장 중요한 규칙은 무엇인가요?', '[{"time":"Day 1","open":200,"high":202,"low":200,"close":202,"volume":89},{"time":"Day 2","open":202,"high":210,"low":204,"close":208,"volume":122}]'::jsonb, '[]'::jsonb, ARRAY['차트상 선이 정배열로 정돈되어 그려질 때', '최소 3개 이상의 뚜렷한 저점/고점 터치 확인 시', '가파른 각도로 90도에 가깝게 작도될 때', '보조지표와 결합하여 수평으로 그려질 때']::text[], 1, '두 점만으로도 선을 그릴 수 있지만, 3번째 터치(3rd Touch)에서 정확한 지지나 저항을 보이고 반등해 주는 순간부터 시장 참여자들이 공식 인지하는 신뢰도 높은 추세선이 됩니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (216, '패턴/돌파', '04_patterns_breakout.md', '머리와 양쪽 어깨 형태를 그리며 넥라인 지지선(192달러)을 위태롭게 지탱하다가 하방으로 강한 캔들이 이탈했습니다. 숏(매도) 포지션 진입 시점은?', '[{"time":"Day 1","open":200,"high":230,"low":196,"close":220,"volume":116},{"time":"Day 2","open":220,"high":260,"low":190,"close":210,"volume":86},{"time":"Day 3","open":210,"high":228,"low":192,"close":220,"volume":120},{"time":"Day 4","open":220,"high":222,"low":186,"close":188,"volume":104}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":192},{"x":3,"y":192}],"label":"넥라인 지지선","color":"#ef4444"}]'::jsonb, ARRAY['머리 꼭대기(260달러) 부근에서 예측 숏 진입', '오른쪽 어깨가 올라가고 있을 때 돌파 전 선진입', '저점들을 연결한 넥라인의 하방 돌파 완료 시', '패턴 완성과 무관하게 오른쪽 어깨 끝에서 대기']::text[], 2, '헤드앤숄더(Head & Shoulders) 패턴은 오른쪽 어깨를 그린 후, 저점 지지선인 ''넥라인(Neckline)''을 거래량을 실어 하방 돌파해야 최종 완성이 선언됩니다. 그전에 진입하면 넥라인 반등 시 극심한 손실을 입습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (217, '패턴/돌파', '04_patterns_breakout.md', '하락 추세 끝에서 시세가 비슷한 깊이의 바닥을 두 번(이중바닥) 형성한 뒤, 중간 고점 저항선(넥라인)을 돌파했습니다. 향후 예상 방향성과 매수 타점은?', '[{"time":"Day 1","open":200,"high":200,"low":160,"close":170,"volume":110},{"time":"Day 2","open":170,"high":190,"low":168,"close":188,"volume":102},{"time":"Day 3","open":188,"high":190,"low":158,"close":164,"volume":120},{"time":"Day 4","open":164,"high":198,"low":162,"close":196,"volume":122}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":190},{"x":3,"y":190}],"label":"넥라인 (95)","color":"#3b82f6"}]'::jsonb, ARRAY['추가 폭락 가능성에 따른 전량 손절 대응', 'W 패턴 이중 바닥 완성 및 넥라인 돌파 시 매수', '박스권 횡보 판단에 따른 무대응 및 관망', '이중 바닥의 하방 이탈을 예상한 숏 포지션 진입']::text[], 1, 'W자 모양의 ''이중 바닥형(Double Bottom)'' 패턴입니다. 시세가 하락을 멈추고 바닥을 두 차례 단단히 지지해 준 뒤 중간 봉우리(넥라인 190달러)를 돌파해 마감하면 추세가 상승으로 강하게 전환될 가능성이 매우 높습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (218, '패턴/돌파', '04_patterns_breakout.md', '급격한 기둥식 시세 폭등(깃대) 후, 완만한 하향 평행 채널(깃발) 모양으로 횡보/수렴하다가 채널 상단을 강하게 돌파했습니다. 이 패턴과 예상 목표가는?', '[{"time":"Day 1","open":100,"high":160,"low":98,"close":156,"volume":116},{"time":"Day 2","open":156,"high":158,"low":144,"close":148,"volume":115},{"time":"Day 3","open":148,"high":152,"low":140,"close":142,"volume":109},{"time":"Day 4","open":142,"high":170,"low":140,"close":166,"volume":100}]'::jsonb, '[]'::jsonb, ARRAY['이중 천정형 패턴 - 고점 도달 시 숏 진입', '불 플래그 패턴 - 깃발 돌파 시 추가 상승 기대', '헤드앤숄더 패턴 - 넥라인 하방 돌파 타겟', '대칭 삼각수렴 패턴 - 변동성 축소 후 돌파 대기']::text[], 1, '대표적 강세 지속 패턴인 ''불 플래그(Bull Flag)''입니다. 급격한 상승(깃대) 뒤 숨 고르기 채널(깃발)을 상방 돌파하면, 이전 상승 파동의 크기(깃대 높이)만큼 추가로 수직 랠리를 시작하는 관성이 있습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (219, '패턴/돌파', '04_patterns_breakout.md', '상승 추세의 천정권에서 시세가 동일한 가격 저항을 두 번 확인하며 M자 모양을 만든 뒤, 두 고점 사이의 저점 지지선인 넥라인(240달러)을 이탈했습니다. 올바른 해석은?', '[{"time":"Day 1","open":200,"high":280,"low":198,"close":270,"volume":88},{"time":"Day 2","open":270,"high":272,"low":240,"close":244,"volume":123},{"time":"Day 3","open":244,"high":280,"low":242,"close":276,"volume":111},{"time":"Day 4","open":276,"high":278,"low":230,"close":232,"volume":125}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":240},{"x":3,"y":240}],"label":"넥라인 (120)","color":"#ef4444"}]'::jsonb, ARRAY['상승 추세의 지속 연장에 따른 추가 매수', '이중 천정형(M 패턴) 완성에 따른 하락 반전 대비', '단기 조정에 따른 일시적 횡보 박스권 진입', '방향성 없는 일상적인 잔파동으로 판단해 홀딩']::text[], 1, '고점에서 지지받지 못하고 형성된 M자형 ''이중 천정형(Double Top)'' 패턴입니다. 두 차례 강력한 저항벽(280달러)을 넘지 못하고 넥라인(240달러)마저 붕괴했으므로 하방 추세가 가속화된다는 신호입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (220, '패턴/돌파', '04_patterns_breakout.md', '고점 저항선은 수평(평평함)을 유지하고 있으나, 저점 지지선은 점점 우상향하며 좁게 수렴하는 차트 형태의 명칭과 일반적인 돌파 방향은?', '[{"time":"Day 1","open":160,"high":200,"low":160,"close":190,"volume":111},{"time":"Day 2","open":190,"high":200,"low":172,"close":196,"volume":92},{"time":"Day 3","open":196,"high":200,"low":184,"close":198,"volume":96}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":200},{"x":2,"y":200}],"label":"수평 저항선","color":"#ef4444"},{"type":"line","points":[{"x":0,"y":160},{"x":1,"y":172},{"x":2,"y":184}],"label":"상승 지지선","color":"#10b981"}]'::jsonb, ARRAY['디센딩 트라이앵글 - 일반적으로 하방 돌파 기대', '어센딩 트라이앵글 - 매수 압력 우위로 상방 돌파 기대', '헤드앤숄더 패턴 - 넥라인 하방 돌파 기대', '상향 평행 채널 - 상하단 터치식 채널 매매 기대']::text[], 1, '고점 저항은 평평하고 저점은 계속 높아지는 삼각수렴을 ''어센딩 트라이앵글(Ascending Triangle)''이라고 합니다. 위로 갈수록 저점이 계속 올라가는 현상은 매수세가 가격을 위로 계속 압박하고 있음을 증명하며, 대개 저항선(200달러)을 상향 뚫고 오르는 확률이 높습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (221, '지표/컨플루언스', '06_technical_indicators.md', '시세는 매일 하락하여 신저가를 갱신하고 있으나, RSI 보조지표의 저점은 점점 높아지는 현상을 발견했습니다. 올바른 용어와 매매 대응법은?', '[{"time":"D-4","open":220,"high":224,"low":196,"close":200,"volume":93},{"time":"D-3","open":200,"high":208,"low":192,"close":196,"volume":111},{"time":"D-2","open":196,"high":202,"low":184,"close":188,"volume":118},{"time":"D-1","open":188,"high":194,"low":186,"close":192,"volume":95},{"time":"Today","open":192,"high":198,"low":190,"close":196,"volume":128}]'::jsonb, '[]'::jsonb, ARRAY['하락 다이버전스 - 가격 상승 둔화에 따른 공매도', '상승 다이버전스 - 하락 둔화 및 반등 신호로 매수', '데드 크로스 - 이평선 하방 교차에 따른 관망', '과매수 이탈 시그널 - 단기 반등에 따른 매수']::text[], 1, '시세의 가격 저점은 낮아지나 보조지표(RSI)의 운동 저점이 높아지는 현상을 ''상승 다이버전스(Bullish Divergence)''라고 합니다. 이는 하방 에너지의 실질적 소멸과 상승 압력의 내부 응축을 의미하는 기술적 분석에서 가장 신뢰도 높은 추세 전환 시그널입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (222, '지표/컨플루언스', '06_technical_indicators.md', '시세는 급격히 치솟으며 최고가 갱신 랠리를 이어가고 있으나, RSI 지표의 고점은 계속 낮아지고 있습니다. 이 현상을 지칭하는 명칭과 대처법은?', '[{"time":"Day 1","open":200,"high":240,"low":198,"close":236,"volume":104},{"time":"Day 2","open":236,"high":244,"low":230,"close":240,"volume":97},{"time":"Day 3","open":240,"high":270,"low":238,"close":266,"volume":127}]'::jsonb, '[]'::jsonb, ARRAY['하락 다이버전스 - 매수 둔화 및 하락 우려로 익절', '상승 다이버전스 - 추가 급등 기대로 신규 매수', '골든 크로스 - 추세 강화에 따른 홀딩', '볼린저 밴드 스퀴즈 - 변동성 수축 후 돌파']::text[], 0, '시세는 계속 고점을 높이고 있으나 보조지표의 고점은 꺾여 낮아지는 현상을 ''하락 다이버전스(Bearish Divergence)''라고 합니다. 이는 매수세의 힘이 표면적인 가격 상승에 비해 실질적으로 빠르게 축소되고 있음을 경고하며, 조만간 큰 급락이 발생할 확률이 높습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (223, '지표/컨플루언스', '06_technical_indicators.md', '이동평균선(EMA) 20일선(단기)이 50일선(중기)을 아래에서 위로 강하게 뚫고 솟구쳐 올랐습니다. 이 교차 현상의 정식 명칭은?', '[{"time":"Day 1","open":200,"high":204,"low":196,"close":198,"volume":93},{"time":"Day 2","open":198,"high":208,"low":198,"close":206,"volume":91},{"time":"Day 3","open":206,"high":220,"low":206,"close":218,"volume":107}]'::jsonb, '[]'::jsonb, ARRAY['데드 크로스 - 단기 이평의 하방 교차로 매도 신호', '골든 크로스 - 단기 이평의 상방 교차로 매수 신호', '볼린저 스퀴즈 - 변동성 수축 및 돌파 신호', '다이버전스 수렴 - 지표와 가격의 동반 횡보']::text[], 1, '단기 이평선이 장기 이평선을 위로 치고 올라가는 현상을 ''골든 크로스(Golden Cross)''라고 합니다. 이는 최근 매수 평단가가 장기 평균가보다 확연히 높아졌음을 시사하며, 상승 추세가 본 궤도에 올랐음을 입증해 줍니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (224, '지표/컨플루언스', '07_multitimeframe_regime.md', '매우 강력한 원웨이 폭락장 속에서 RSI 지표가 20(과매도 영역) 이하로 깊이 내려왔습니다. 이를 보고 ''과매도 반등''을 노리며 기계적 시장가 풀매수를 때렸을 때 나타나는 가장 빈번한 오류는?', '[{"time":"Day 1","open":200,"high":202,"low":176,"close":178,"volume":99},{"time":"Day 2","open":178,"high":180,"low":150,"close":152,"volume":16},{"time":"Day 3","open":152,"high":154,"low":124,"close":126,"volume":23}]'::jsonb, '[]'::jsonb, ARRAY['하락 추세 즉시 종료 및 V자 상승 반등 성공', '강력한 하락장에서의 지표 과매도 고착화 리스크', '거래량 급감으로 인한 호가 정지 및 상장 폐지', '시세의 즉각적인 박스권 횡보 및 변동성 축소']::text[], 1, 'RSI 30 이하 과매도 영역은 반등 신호이기도 하지만, 추세가 지나치게 강력한 하락장일 때는 지표만 과매도 구역에 쳐박힌 채 가격은 계속 급락하는 ''과매도 고착화(Oversold Embedded)'' 상태가 이어집니다. 다이버전스나 캔들 반전형 확인 없이 수치만 보고 들어가는 매수는 깡통으로 가는 지름길입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (225, '지표/컨플루언스', '06_technical_indicators.md', '시세의 변동성이 극도로 축소되며 볼린저 밴드의 폭이 매우 좁아지는 ''스퀴즈(Squeeze)'' 현상이 나타났습니다. 이후 기대되는 시장 변동성의 원리는 무엇인가요?', '[{"time":"Day 1","open":200,"high":202,"low":198,"close":200,"volume":115},{"time":"Day 2","open":200,"high":200,"low":198,"close":198,"volume":105},{"time":"Day 3","open":198,"high":200,"low":198,"close":200,"volume":96}]'::jsonb, '[]'::jsonb, ARRAY['변동성 사멸로 인한 장기 횡보 및 거래 정지', '밴드 스퀴즈 후 변동성 팽창에 따른 추세 분출', '시세의 하방 붕괴로 인한 강한 하락 파동 시작', '이평선들의 수평 정렬에 따른 완전한 추세 고정']::text[], 1, '볼린저 밴드의 수축(Squeeze)은 시장의 숨 고르기 및 힘 모으기를 뜻합니다. 에너지가 최대한 압축된 후에는 밴드 상단 혹은 하단선을 이탈하며 매우 거대한 변동성 팽창(Expansion) 추세가 시작되므로, 방향성을 유심히 지켜봐야 합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (226, '리스크/심리', '09_risk_position_management.md', '총 투자 원금은 2,000만 원이며, 1회 거래 시 최대 손실 허용액을 원금의 2%(40만 원)로 제한하는 ''2% 룰''을 지키려 합니다. 진입하려는 종목의 손절 라인 폭이 -5%일 때, 최대 매수(진입) 가능 금액은 얼마인가요?', '[{"time":"Day 1","open":20000,"high":21000,"low":19600,"close":20400,"volume":116},{"time":"Day 2","open":20400,"high":20600,"low":20000,"close":20000,"volume":86}]'::jsonb, '[]'::jsonb, ARRAY['2,000만 원 (원금 전액 진입)', '400만 원 (원금의 20% 진입)', '800만 원 (원금의 40% 진입)', '1,000만 원 (원금의 50% 진입)']::text[], 2, '2% 룰에 기초한 포지션 사이징 공식은 `진입금액 = (총원금 * 리스크비율) / 손절비율` 입니다. 따라서 `40만 원 / 0.05 = 800만 원`이 됩니다. 800만 원어치 가상자산을 샀을 때 가격이 -5% 떨어져 강제 손절을 맞아도 내 계좌 총액에서 손실을 보는 돈은 정확히 2%인 40만 원으로 통제됩니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (227, '리스크/심리', '09_risk_position_management.md', '어느 가상자산에 20,000원에 매수 진입합니다. 손절 라인은 19,000원(-5%)에 배치하고, 목표가는 23,000원(+15%)에 설정했습니다. 이 트레이딩 시나리오의 손익비(Risk-to-Reward Ratio)는 얼마입니까?', '[{"time":"Today","open":20000,"high":20000,"low":20000,"close":20000}]'::jsonb, '[]'::jsonb, ARRAY['1 : 1 (동일한 기대 수익과 리스크)', '1 : 2 (기대 수익이 리스크의 2배)', '1 : 3 (기대 수익이 리스크의 3배)', '2 : 1 (기대 수익이 리스크의 0.5배)']::text[], 2, '손절 폭(1,000원) 대비 익절 폭(3,000원)의 비례를 의미하므로 `1,500 / 500 = 3`, 즉 손익비는 1:3이 됩니다. 이처럼 잃는 돈의 최소 2~3배를 벌 수 있는 손익비 높은 구간만 반복적으로 거래해야 장기적으로 계좌가 생존합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (228, '리스크/심리', '09_risk_position_management.md', '손익비를 엄격히 통제하여 항상 기대 손실의 2배를 버는 매매(손익비 1:2)만 고집합니다. 이 경우 내 계좌 잔고가 손실 없이 제자리걸음(본전)을 유지하기 위해 필요한 수학적인 최소 승률(Win Rate)은 얼마인가요?', '[{"time":"Today","open":200,"high":200,"low":200,"close":200}]'::jsonb, '[]'::jsonb, ARRAY['50.0% (최소 절반 이상 성공)', '33.3% (3번 중 1번 성공으로 본전)', '25.0% (4번 중 1번 성공으로 본전)', '66.6% (3번 중 2번 성공으로 본전)']::text[], 1, '손익비가 1:2일 경우, 1번 이기면 +2를 벌고 2번 지면 -2를 잃으므로 3번 매매 중 1번만 이겨도 누적 수익은 0이 됩니다. 즉 손익비를 1:2 이상으로 유지하면 수학적으로 승률이 겨우 33.3%만 나와도 절대 파산하지 않고 계좌가 우상향할 발판이 마련됩니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (229, '셋업/실행', '08_setup_entry_exit.md', '20,000원에 산 가상자산이 30,000원까지 올랐습니다. 이익을 보존하면서 상승세를 끝까지 타기 위해, 최고점 대비 10% 하방 이탈 시 즉시 자동 익절되는 ''추적 손절매(Trailing Stop)''를 적용했습니다. 최고점 30,000원 달성 후 시세가 조정받을 때 실제로 청산(익절)되는 가격은 얼마인가요?', '[{"time":"Day 1","open":20000,"high":24000,"low":19800,"close":23800,"volume":90},{"time":"Day 2","open":23800,"high":30000,"low":23600,"close":29600,"volume":88}]'::jsonb, '[]'::jsonb, ARRAY['20,000원 (본전 수준 청산)', '27,000원 (최고점 대비 10% 하방 청산)', '28,000원 (최고점 대비 6.6% 하방 청산)', '24,000원 (최고점 대비 20% 하방 청산)']::text[], 1, '추적 손절매(Trailing Stop)는 가격 상승에 따라 청산 가격을 자동으로 올려주는 주문입니다. 최고점 30,000원을 기록했으므로 청산 트리거 라인은 최고점에서 10% 차감된 `15,000 * 0.9 = 27,000원`으로 확정 셋업되며, 시세가 27,000원을 건드리는 순간 자동 이익실현됩니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (230, '리스크/심리', '09_risk_position_management.md', '레버리지 10배를 적용하여 솔라나 롱(매수) 포지션을 구축했습니다. 만약 솔라나 가격이 매수가 대비 몇 % 역방향으로 등락하면 내 투자 원금이 100% 강제 청산(증거금 완전 소멸)당할까요?', '[{"time":"Today","open":100000,"high":100200,"low":99800,"close":100000}]'::jsonb, '[]'::jsonb, ARRAY['5.0% 하락 시', '10.0% 하락 시', '20.0% 하락 시', '100.0% 하락 시']::text[], 1, '레버리지 비율과 청산 거리 비율은 역수 관계입니다. `100% / 레버리지 배수` 공식에 따라, 10배 레버리지는 시세가 내 베팅의 반대 방향으로 단 10%만 움직여도 투자 원금이 전부 증발하고 포지션이 강제 종료(Liquidation)됩니다. 고배율 레버리지가 파산의 지름길인 이유입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (231, '캔들/가격행동', '02_candlestick_price_action.md', '상승 추세 고점 영역(300달러선)에서 몸통이 매우 작고 아래꼬리가 긴 행잉맨(Hanging Man) 캔들이 출현한 이후, 다음 날 시가가 전일 종가보다 큰 갭을 그리며 낮게 하락 출발(290달러)했습니다. 포지션을 보유한 스윙 트레이더로서 가장 적절한 위기 대응 행동은 무엇입니까?', '[{"time":"Day 1","open":240,"high":250,"low":238,"close":248,"volume":108},{"time":"Day 2","open":248,"high":270,"low":246,"close":268,"volume":89},{"time":"Day 3","open":268,"high":296,"low":266,"close":292,"volume":100},{"time":"Day 4","open":292,"high":302,"low":280,"close":294,"volume":116},{"time":"Day 5","open":282,"high":286,"low":270,"close":272,"volume":118}]'::jsonb, '[]'::jsonb, ARRAY['상승 랠리를 기대로 보유 비중 확대 및 추격 매수', '일시적 속임수(휩소) 판단으로 추가 레버리지 매수', '행잉맨 출현 후 갭하락에 따른 전량 또는 일부 정리', '조치 없이 전고점 돌파 시까지 무기한 관망 및 홀딩']::text[], 2, '고가권에서 나타난 행잉맨(Hanging Man)은 잠재적 하락 전환 신호이며, 특히 다음날 갭하락 음봉으로 직전 행잉맨의 저가를 깨고 내려가는 움직임은 강력한 하락 컨펌 시그널입니다. 따라서 이 시점에서는 즉시 비중을 전량 정리하거나 최소 절반 이상 매도하여 리스크를 통제하는 것이 정석입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (232, '캔들/가격행동', '01_chart_market_basics.md', '지속적인 하락 추세 도중 바닥권(160달러선)에서 시가와 종가가 일치하고 긴 아래꼬리를 단 십자 형태의 도지(Doji) 캔들이 생성되었습니다. 다음 날 대량의 거래량과 함께 장대양봉이 솟구치며 174달러로 마감하는 샛별형(Morning Star) 조합이 확정되었습니다. 이때 가장 합리적인 매수 진입 지점과 손절가 기준은 무엇입니까?', '[{"time":"Day 1","open":200,"high":202,"low":186,"close":188,"volume":108},{"time":"Day 2","open":188,"high":190,"low":176,"close":178,"volume":116},{"time":"Day 3","open":178,"high":180,"low":160,"close":162,"volume":109},{"time":"Day 4","open":160,"high":164,"low":150,"close":160,"volume":127},{"time":"Day 5","open":160,"high":176,"low":158,"close":174,"volume":101}]'::jsonb, '[]'::jsonb, ARRAY['손절 없이 100% 비중으로 시장가 매수', '샛별형 완성에 따라 분할 매수 후 최저점 손절 셋업', '바닥 도달 기대로 주문 없이 무작정 대기', '상승 꼭대기에서 숏 진입 후 손절 없이 방치']::text[], 1, '하락 추세 끝에 도지와 장대양봉이 결합된 샛별형(Morning Star)은 매우 신뢰도 높은 바닥 상승 전환 신호입니다. 이 패턴을 보고 진입할 때는 반등 상승세에 분할 매수로 동참하되, 바닥을 잡아준 도지 캔들의 최저점(150달러) 아래를 최종 손절 라인으로 잡는 것이 수학적으로 가장 리스크 대비 보상 비율(손익비)이 훌륭한 전략입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (233, '거래량/유동성', '02_candlestick_price_action.md', '시세가 강력한 횡보 박스권 고점(400달러 저항선)에 세 번째 터치하는 와중에, 윗꼬리가 길고 몸통이 매우 얇은 유성형(Shooting Star) 캔들이 이틀 연속 발생했습니다. 거래량 역시 저항선 부근에서 매수세가 더 올라가지 못하고 매도 압력이 실려 나타났습니다. 롱(매수) 포지션을 들고 있는 당신의 합리적인 의사결정은?', '[{"time":"Day 1","open":350,"high":370,"low":348,"close":364,"volume":82},{"time":"Day 2","open":364,"high":390,"low":360,"close":386,"volume":107},{"time":"Day 3","open":386,"high":404,"low":380,"close":382,"volume":88},{"time":"Day 4","open":382,"high":402,"low":376,"close":378,"volume":95}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":400}],"label":"박스권 상단 저항선 (200)","color":"#ef4444"}]'::jsonb, ARRAY['신고가 갱신을 예상한 전재산 추가 불타기', '저항 돌파 실패 신호 확인 후 분할 익절 및 관망', '손익 평단가 부근이므로 추가 손절 없이 방치', '거래를 종료하고 다른 신규 급등주를 시장가 추격']::text[], 1, '박스권 상단 저항선(400달러)에 부딪히며 나타난 유성형(Shooting Star) 연속 출현은 저항 돌파 실패와 차익 실현 세력의 강력한 등장을 경고하는 캔들 신호입니다. 돌파를 확신하기보다는 리스크 관리 관점에서 물량을 축소(50% 분할 익절)하거나 전량 매도하여 이익을 확정 짓는 것이 현명합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (234, '캔들/가격행동', '02_candlestick_price_action.md', '극심한 하락 추세 중 200달러선 아래로 떨어지던 시세가 전일 장대음봉을 형성했습니다. 그러나 당일 시가는 갭하락하여 더 낮게 시작했으나, 장중에 강한 매수세가 들어오며 전일 음봉 몸통의 정확히 70% 라인(186달러선) 위로 덮어버리는 관통형(Piercing Line) 상승 캔들로 마감했습니다. 종가 매수(롱) 진입 시 원칙 대응은?', '[{"time":"Day 1","open":220,"high":222,"low":208,"close":210,"volume":119},{"time":"Day 2","open":210,"high":212,"low":194,"close":196,"volume":113},{"time":"Day 3","open":184,"high":202,"low":182,"close":200,"volume":104}]'::jsonb, '[]'::jsonb, ARRAY['상승 모멘텀 미달로 매수 보류 및 하방 숏 포지션 진입', '관통형 확인 후 분할 매수 및 당일 최저점 손절 설정', '손절 라인 설정 없이 100% 비중 시장가 매수 집행', '조정을 대기하며 예약 주문 없이 무작정 관망 유지']::text[], 1, '전일 음봉의 50% 이상을 당일 양봉 몸통으로 관통해 올린 ''관통형(Piercing Line)''은 하락 모멘텀이 쇠퇴하고 저가 매수세가 우위를 점하기 시작했음을 뜻하는 바닥 신호입니다. 이 패턴 확인 후 진입할 시에는 손절 한도를 당일 최저점(182달러) 밑에 가깝게 설정할 수 있어 매우 유리한 리스크 대비 기대수익 매매가 성립됩니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (235, '캔들/가격행동', '05_volume_liquidity.md', '강한 급등세를 지속하던 시세가 최고점에서 큰 거래량을 터뜨리며 장대양봉을 만들었습니다. 그러나 다음 날, 전일 양봉 몸통의 한가운데 범위 안에서 움직이며 시가와 종가가 모두 갇혀버리는 짧은 음봉인 ''하락 잉태형(Bearish Harami)'' 캔들이 형성되었습니다. 단기 스윙 트레이더로서 당신의 포지션 리스크 관리 행동은?', '[{"time":"Day 1","open":240,"high":256,"low":238,"close":254,"volume":99},{"time":"Day 2","open":254,"high":276,"low":252,"close":272,"volume":123},{"time":"Day 3","open":266,"high":268,"low":260,"close":262,"volume":100}]'::jsonb, '[]'::jsonb, ARRAY['상승 둔화 조짐에 따른 보유 물량 50% 분할 익절', '추세 일시 조정으로 간주하여 비중 확대 추가 매수', '추세 종결 판단에 따른 고배율 숏 포지션 즉시 진입', '이익 실현 없이 전량 장기 보유 전략 유지']::text[], 0, '하락 잉태형(Bearish Harami)은 이전의 강한 상승 추세 동력이 감속하기 시작했으며, 매도 압력이 힘을 기르고 있음을 암시하는 변곡 캔들입니다. 따라서 단기 스윙 트레이더는 물량의 일부(50%)를 분할 익절하여 리스크를 낮추고, 다음 캔들에서 이전 양봉 저점을 깨뜨리는 하락 하방 이탈이 추가되는지 지켜보는 것이 정석입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (236, '시장구조/SR', '03_market_structure.md', '오랫동안 지켜지던 핵심 지지선인 200달러 부근에서 매수 진입을 완료했습니다. 그러나 가격이 대량의 거래량을 동반하며 장대음봉으로 지지선을 하방으로 강하게 뚫어냈고, 종가가 지지선 대비 1.5% 아래인 98.10달러로 결정되었습니다. 이 상황에서 원칙을 지키는 올바른 위기 대응 행동은?', '[{"time":"Day 1","open":210,"high":216,"low":204,"close":206,"volume":115},{"time":"Day 2","open":206,"high":208,"low":198,"close":200,"volume":100},{"time":"Day 3","open":200,"high":202,"low":196,"close":197,"volume":124}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":200}],"label":"중요 지지선 (100)","color":"#10b981"}]'::jsonb, ARRAY['추가 물타기를 위해 자금을 동원하여 평단가 관리', '중요 지지선 붕괴(Breakdown) 확인 후 즉시 전량 손절', '지속 하락 시 추가 평단가 관리를 위해 매수 유보', '하방 이탈 시 즉시 반대 고배율 롱 포지션 진입']::text[], 1, '거래량이 동반된 장대음봉으로 주요 지지선 아래에서 종가가 결정되는 이탈 마감은 매수 지지 세력의 패배이자 추세 붕괴(Breakdown)의 신호입니다. 이 시점에서 물타기를 하거나 존버를 하면 파산적인 하락 조정을 겪을 수 있으므로 즉시 룰에 근거한 ''전량 손절''을 집행해야 계좌를 살릴 수 있습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (237, '시장구조/SR', '03_market_structure.md', '300달러의 중요 저항선이 강한 거래량을 실은 돌파봉으로 뚫렸습니다. 이후 시세가 숨 고르기 조정을 받으며 300달러 부근까지 되돌아왔고(리테스트 구간), 저항선 부근에서 거래량이 크게 감소하며 아래꼬리가 달린 도지 캔들로 안착하는 모습을 보입니다. 이때 가장 안전하고 합리적인 매매 조치는?', '[{"time":"Day 1","open":280,"high":292,"low":278,"close":288,"volume":98},{"time":"Day 2","open":288,"high":314,"low":286,"close":310,"volume":88},{"time":"Day 3","open":310,"high":312,"low":298,"close":300,"volume":111}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":300}],"label":"돌파된 저항선 -> 지지선 전환선 (150)","color":"#3b82f6"}]'::jsonb, ARRAY['가짜 돌파(휩소) 판단에 따른 고배율 숏 진입', '돌파 후 리테스트 성공 확인 시 지지선 눌림목 매수', '추격 매수 기회 상실로 판단하고 거래 포기', '320달러 추가 돌파를 타겟으로 시장가 추격 매수']::text[], 1, '강하게 돌파된 저항선은 룰 체인지에 의해 지지선으로 변합니다(역할 전환). 돌파 당시 추격 매수하기보다, 돌파된 선(300달러)으로 시세가 되돌아오는 리테스트(Retest) 시점에 저조한 거래량과 지지 캔들을 확인하고 손절선을 바로 밑에 설정하여 눌림목 진입하는 것이 리스크가 가장 적은 프로 트레이더의 정석입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (238, '시장구조/SR', '03_market_structure.md', '가격이 160달러 지지선 근처에서 반등을 시도하고 있으나, 반등의 폭이 직전 고점에 턱없이 못 미치며 저점 부근으로 다시 짓눌리고 있습니다. 즉, 고점들이 계속 낮아지는 하락 우위 삼각수렴(Descending)의 형태가 지지선 바로 위에서 감지됩니다. 이 시점에서 지지선 반등을 믿고 신규 매수(롱)를 진입하는 것은 원칙에 맞습니까?', '[{"time":"Day 1","open":190,"high":196,"low":160,"close":176,"volume":80},{"time":"Day 2","open":176,"high":182,"low":160,"close":168,"volume":106},{"time":"Day 3","open":168,"high":172,"low":160,"close":162,"volume":121}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":160}],"label":"지지선 (80)","color":"#10b981"}]'::jsonb, ARRAY['삼중 바닥 지지로 판단하고 매수 비중 대폭 확대', '디센딩 수렴 확인 후 하방 이탈 위험 대비 관망', '물타기 평단가 관리를 위해 매수 보증금 추가 투입', '추세와 무관하게 숏 포지션으로 전환 후 무기한 보유']::text[], 1, '지지선 부근에서 고점이 점점 낮아지는 ''디센딩'' 형태는 매수 지원 강도가 둔화되고 매도 출하 공급이 가격을 계속 하방으로 압박하고 있음을 증명합니다. 지지 성공보다 지선 하방 붕괴 후 급락할 확률이 높으므로, 지지선이라는 명목만으로 함부로 매수 진입하지 말고 돌파/이탈 컨펌을 기다려 관망하는 것이 현명합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (239, '거래량/유동성', '05_volume_liquidity.md', '시세가 240달러의 장기 저항벽을 거래량이 거의 실리지 않은 얇은 양봉으로 상방으로 살짝 뚫었으나, 바로 다음 날 직전 양봉 몸통을 통째로 덮어버리는 대량 거래량의 장대음봉이 출현하며 232달러로 곤두박질쳤습니다. 매수 포지션을 추격 진입했던 당신의 올바른 조치는?', '[{"time":"Day 1","open":224,"high":236,"low":222,"close":234,"volume":82},{"time":"Day 2","open":234,"high":244,"low":232,"close":242,"volume":342},{"time":"Day 3","open":242,"high":244,"low":230,"close":232,"volume":323}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":240}],"label":"장기 저항선 (120)","color":"#ef4444"}]'::jsonb, ARRAY['불 트랩(Bull Trap) 확인 후 추가 하락 방지 즉시 손절', '저항선 부근 매수세 복귀를 기대하며 전량 홀딩', '평단가 관리 차원에서 추가 물타기 매수 집행', '상황을 판단하기 위해 시장가로 추가 분할 진입']::text[], 0, '거래량 없는 돌파 직후에 거래량 실린 강한 음봉이 기존 돌파선(240달러) 아래로 재진입하여 마감하는 현상은 전형적인 불 트랩(Bull Trap/가짜 돌파) 함정입니다. 돌파 당시 샀던 매수자들의 패닉 셀이 출현하며 하락 가속화가 나오기 쉬우므로 즉시 손절하여 물량을 털어내야 생존할 수 있습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (240, '시장구조/SR', '10_psychology_routine_review.md', '주요 지지선(500달러선)이 아래로 무너질 때 제때 손절 처리를 하지 못해 시세가 440달러선까지 끌려 내려갔습니다. 다행히 단기 매도 진정세로 반등이 나와 시세가 다시 500달러 부근까지 상승하여 회복을 눈앞에 두고 있습니다. 이때 손실을 최소화하는 현명한 시나리오 대처법은?', '[{"time":"Day 1","open":520,"high":524,"low":496,"close":498,"volume":108},{"time":"Day 2","open":498,"high":500,"low":440,"close":444,"volume":86},{"time":"Day 3","open":444,"high":470,"low":442,"close":468,"volume":123},{"time":"Day 4","open":468,"high":502,"low":466,"close":498,"volume":99}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":500}],"label":"붕괴된 지지선 -> 저항선으로 변형 (250)","color":"#ef4444"}]'::jsonb, ARRAY['역할 전환(저항선) 도달에 따른 탈출 및 현금화', 'V자 반등 성공 확신에 따른 추가 매수 비중 확대', '원금 회복 및 추가 수익 시까지 영구 홀딩 관망', '하락 추세 지속에 따른 반대 숏 포지션 스위칭']::text[], 0, '하방으로 깨진 지지선은 반등할 때 가장 뚫기 힘든 ''강력한 저항선''으로 성격이 바뀝니다. 따라서 손절 기회를 놓치고 물려있던 트레이더는 반등하여 옛 지지선(500달러)에 도달했을 때를 ''최선의 리스크 탈출 기회(탈출구)''로 삼아 전량 매도하거나 비중을 극도로 덜어내야 다가올 2차 하락 파동의 파산을 막을 수 있습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (241, '추세/레짐', '03_market_structure.md', '시세가 매우 가파르게 올라가던 1차 단기 상승 추세선을 강한 음봉 종가로 뚫고 내려왔습니다. 다행히 각도가 완만하고 탄탄한 장기 핵심 상승 추세선은 저 밑에 지지 영역을 유지하고 있습니다. 스윙 트레이더로서 가장 정석적인 포지션 제어 방식은 무엇인가요?', '[{"time":"Day 1","open":200,"high":204,"low":200,"close":204,"volume":97},{"time":"Day 2","open":204,"high":220,"low":204,"close":218,"volume":114},{"time":"Day 3","open":218,"high":250,"low":218,"close":248,"volume":117},{"time":"Day 4","open":248,"high":250,"low":228,"close":230,"volume":97}]'::jsonb, '[{"type":"line","points":[{"x":0,"y":200},{"x":3,"y":246}],"label":"가파른 단기 추세선 (붕괴)","color":"#ef4444"},{"type":"line","points":[{"x":0,"y":200},{"x":3,"y":220}],"label":"완만한 장기 추세선 (지탱 중)","color":"#10b981"}]'::jsonb, ARRAY['추세 붕괴 판단에 따른 전량 손절 및 영구 이탈', '가속 추세 이탈에 따른 50% 분할 익절 및 분산', '단기 지지선 붕괴를 무시한 고배율 물타기 매수', '장기 추세선까지 조정을 대비한 신규 매수 대기']::text[], 1, '가파르게 우상향하던 가속 추세선(Accelerated Trendline)이 하방 돌파되는 것은 기존 폭등 랠리의 속도가 둔화되고 완만한 본래 장기 추세선(장기 매물대)을 향해 정상적인 가격 조정을 받기 시작했음을 뜻합니다. 따라서 물량의 50%가량을 털어 수익을 실현하고 남은 물량으로 장기 추세선의 3rd Touch 지지 성공 여부를 테스트하는 것이 리스크 관리의 기본입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (242, '거래량/유동성', '05_volume_liquidity.md', '고점과 저점이 연속으로 낮아지는 명확한 하락 평행 채널 내에서 하락 압력을 받아 숏(매도) 포지션을 잡고 수익 중이었습니다. 그런데 당일 캔들이 대량의 거래량과 함께 장대양봉을 그리며 채널 상단 저항선 위로 종가 안착(상방 돌파)했습니다. 숏 포지션을 쥔 당신의 결단은?', '[{"time":"Day 1","open":200,"high":204,"low":180,"close":184,"volume":84},{"time":"Day 2","open":184,"high":188,"low":164,"close":166,"volume":116},{"time":"Day 3","open":166,"high":170,"low":150,"close":152,"volume":120},{"time":"Day 4","open":152,"high":180,"low":150,"close":178,"volume":131}]'::jsonb, '[{"type":"channel","points":[{"x":0,"y":204},{"x":3,"y":172},{"x":0,"y":180},{"x":3,"y":152}],"label":"하락 평행 채널 상한/하한","color":"#f59e0b"}]'::jsonb, ARRAY['상단 돌파 확인 즉시 숏 전량 손절 및 대피', '채널 재진입 기대로 숏 포지션 추가 물타기', '손절 없이 유지하면서 포지션 본전 도달 대기', '포지션 유지 후 증거금을 출금하여 강제 횡보']::text[], 0, '하락 평행 채널의 상단 저항선 상향 돌파(Breakout)는 기존 하락 트렌드의 사멸과 매수세 지배령 복귀를 뜻합니다. 지표와 거래량이 동반된 돌파 확인 시에는 숏 포지션을 지체 없이 기계적으로 칼손절하여 자산을 보호하는 것이 원칙입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (243, '추세/레짐', '07_multitimeframe_regime.md', '우상향하는 상승 평행 채널 안에서 순항하던 시세가 중심선(Mid-line)을 뚫고 하방으로 이탈 마감했습니다. 이후 중심선 부근까지 반등을 시도했으나 재차 저항을 받고 아래꼬리가 꺾여 채널 하단선을 향해 하락 조정을 재개하려 합니다. 신규 매수(롱) 포지션 진입을 계획 중인 트레이더의 대응법은?', '[{"time":"Day 1","open":200,"high":216,"low":198,"close":212,"volume":114},{"time":"Day 2","open":212,"high":224,"low":204,"close":208,"volume":118},{"time":"Day 3","open":208,"high":212,"low":196,"close":200,"volume":113}]'::jsonb, '[{"type":"channel","points":[{"x":0,"y":220},{"x":2,"y":224},{"x":0,"y":196},{"x":2,"y":200}],"label":"상승 평행 채널","color":"#10b981"}]'::jsonb, ARRAY['채널 내 유지를 기대로 지정가 즉시 매수', '중심선 저항 확인 후 채널 하단 안착 대기', '하방 휩소 판단에 따른 레버리지 추가 매수', '추세와 무관한 숏 포지션 구축 후 관망']::text[], 1, '상승 평행 채널에서 미드라인(Mid-line)은 매우 중요한 심리적 지지와 저항선입니다. 미드라인이 저항선으로 뒤바뀌어 음봉으로 흘러내리는 경우 높은 확률로 채널 하단 경계선까지 가격이 조정을 받게 되므로, 중심선 저항 확인 시점에서는 섣부른 매수 진입을 피하고 채널 하단의 명확한 반등 타점을 유도해야 합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (244, '추세/레짐', '03_market_structure.md', '저점과 저점을 이은 장기 상승 추세선 상의 3번째 터치 포인트(지지선 부근)에 캔들이 매우 조심스럽게 안착하며 아래꼬리를 형성했습니다. 손익비(Risk-to-Reward) 관점에서 가장 이상적인 매수 타점 집행 및 손절 셋업 방법은 무엇입니까?', '[{"time":"Day 1","open":160,"high":180,"low":160,"close":176,"volume":102},{"time":"Day 2","open":176,"high":198,"low":176,"close":190,"volume":106},{"time":"Day 3","open":190,"high":192,"low":180,"close":184,"volume":113}]'::jsonb, '[{"type":"line","points":[{"x":0,"y":160},{"x":1,"y":176},{"x":2,"y":180}],"label":"상승 추세선 (3rd Touch 기대선)","color":"#10b981"}]'::jsonb, ARRAY['손절 라인 없이 지정가로 1차 매수 몰빵 진입', '3rd Touch 타점 진입 및 추세선 하단 칼손절 셋업', '하방 붕괴 예상을 통한 고배율 숏 즉각 진입', '목표가 터치 시까지 무작정 대기 후 추격 매수']::text[], 1, '추세선 상의 3번째 지지 포인트(3rd Touch)는 추세 신뢰도가 형성되는 대단히 성공률 높은 정석적 눌림목 타점입니다. 진입 가격과 손절 라인(추세선 이탈가)의 거리가 매우 가깝기 때문에 기대 수익 대비 잃을 금액이 매우 적어 프로 트레이더들이 가장 선호하는 칼손절 매수 스팟입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (245, '추세/레짐', '08_setup_entry_exit.md', '시세가 장기 하락 추세선을 힘차게 뚫어 상방 돌파(Breakout)했습니다. 하지만 돌파선 바로 위(약 240달러)에 최근 여러 번 강한 매도 잔량이 쏟아지며 가격을 찍어 눌렀던 핵심 매물대 저항선이 떡하니 버티고 있습니다. 당신의 신규 진입 매수 순서는 어떻게 결정해야 안전할까요?', '[{"time":"Day 1","open":250,"high":252,"low":220,"close":224,"volume":102},{"time":"Day 2","open":224,"high":226,"low":196,"close":200,"volume":102},{"time":"Day 3","open":200,"high":238,"low":198,"close":236,"volume":115}]'::jsonb, '[{"type":"line","points":[{"x":0,"y":250},{"x":1,"y":224},{"x":2,"y":210}],"label":"하락 추세선 (돌파됨)","color":"#ef4444"},{"type":"horizontal-line","points":[{"x":0,"y":240}],"label":"수평 매물대 저항선 (120)","color":"#ef4444"}]'::jsonb, ARRAY['돌파 확인 즉시 종가 기준 시장가 100% 매수', '수평 저항 돌파 검증 시까지 매수 유보 및 대기', '돌파 전조 현상 기대로 레버리지 선배팅 집행', '추세선 돌파를 가짜로 간주한 숏 포지션 진입']::text[], 1, '하락 추세선의 돌파는 긍정적이나 수평 매물대 저항선이 바로 위에 있다면 이중 저항 작용에 의해 막히는 경우가 대단히 잦습니다. 추세선 상방 휩소(속임수)에 당하지 않으려면 겹저항 중 최종 관문인 수평 매물대 저항선 돌파 혹은 리테스트 지지를 확인하고 진입하는 것이 보수적이고 안전한 원칙입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (246, '패턴/돌파', '04_patterns_breakout.md', '고점 수평 저항선(200달러)과 저점 상승 지지선으로 이루어진 어센딩 트라이앵글 수렴 도중, 200달러를 돌파할 것을 미리 예측하고 196달러에서 비중 100% 매수로 진입했습니다. 그러나 시세는 돌파에 실패하고 하방 상승 지지선을 대량 거래량 장대음봉으로 뚫어 184달러로 하향 마감했습니다. 올바른 매매 액션은?', '[{"time":"Day 1","open":160,"high":200,"low":160,"close":190,"volume":108},{"time":"Day 2","open":190,"high":200,"low":176,"close":194,"volume":111},{"time":"Day 3","open":194,"high":196,"low":182,"close":184,"volume":88}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":200}],"label":"수평 저항선 (100)","color":"#ef4444"},{"type":"line","points":[{"x":0,"y":160},{"x":1,"y":176},{"x":2,"y":188}],"label":"상승 지지선 (붕괴)","color":"#10b981"}]'::jsonb, ARRAY['하방 이탈 확인 즉시 손절하여 추가 폭락 차단', '조정을 이용해 평단가를 조절하는 분할 물타기', '본전 탈출 시까지 포지션을 유지하며 관망', '손절 라인을 하단으로 조정하고 대기 주문 유지']::text[], 0, '어센딩 트라이앵글은 상방 확률이 다소 높지만, 하단 지지선이 뚫려 무너지는 순간 패턴 실패와 함께 엄청난 실망 매도 매물이 출하됩니다. 특히 돌파를 미리 예견해 들어간 포지션은 즉시 룰 위반을 시정하고 손절(184달러)해야 큰 자산 보호를 할 수 있습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (247, '패턴/돌파', '04_patterns_breakout.md', '하락 바닥권에서 왼쪽 어깨, 머리, 오른쪽 어깨를 그리며 역헤드앤숄더(Inverse Head & Shoulders) 패턴이 완성되었습니다. 가격이 넥라인 저항벽(160달러선)을 돌파했으나 이미 장대양봉으로 높이 솟아(174달러) 추격 매수 타이밍을 아쉽게 놓쳤습니다. 이때 뇌동매매를 피하는 가장 현명한 매수 타점 공략법은?', '[{"time":"Day 1","open":190,"high":190,"low":140,"close":156,"volume":96},{"time":"Day 2","open":156,"high":164,"low":120,"close":150,"volume":96},{"time":"Day 3","open":150,"high":158,"low":136,"close":152,"volume":118},{"time":"Day 4","open":152,"high":176,"low":150,"close":174,"volume":105}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":160}],"label":"넥라인 저항선 (80)","color":"#ef4444"}]'::jsonb, ARRAY['포모(FOMO) 현상에 따른 돌파봉 꼭대기 추격 매수', '돌파 넥라인 부근의 리테스트 조정 눌림목 매수', '반등 랠리 종결 판단에 따른 역베팅 숏 포지션', '추세 전환 확인 후 무조건적인 관심종목 제외']::text[], 1, '강한 패턴 돌파봉 확인 후 뇌동매매로 추격하는 것은 손절 거리가 너무 멀어져 손익비가 최악인 나쁜 습관입니다. 정석 돌파 트레이더는 넥라인 역할 전환 지점(160달러)으로의 되돌림 눌림목(Retest)을 차분히 기다려 리스크를 짧게 끊고 들어가는 훈련을 해야 합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (248, '패턴/돌파', '04_patterns_breakout.md', '지속적인 하락 추세 중, 고점과 저점이 수렴하며 우하향하는 하락 쐐기형(Falling Wedge) 패턴의 끝자락에 도달했습니다. 거래량이 급감하다가 마침내 쐐기형 상단 저항선을 상방으로 뚫는 강한 양봉 종가 마감(220달러)이 포착되었습니다. 합리적인 매수 진입 시 손절가 설정 기준은 무엇인가요?', '[{"time":"Day 1","open":260,"high":264,"low":220,"close":224,"volume":114},{"time":"Day 2","open":224,"high":232,"low":204,"close":208,"volume":102},{"time":"Day 3","open":208,"high":216,"low":196,"close":200,"volume":119},{"time":"Day 4","open":200,"high":224,"low":198,"close":220,"volume":128}]'::jsonb, '[]'::jsonb, ARRAY['손절 없이 청산가에 의존하여 장기 홀딩', '상방 돌파 확인 후 진입 및 직전 최저점 손절 셋업', '평단가 개선을 위한 지속적인 분할 물타기 매수', '상단 저항선 돌파 시점을 이용한 숏 포지션 스위칭']::text[], 1, '하락 쐐기형(Falling Wedge)의 상방 돌파는 강력한 반전 신호입니다. 이 패턴의 장점은 진입 즉시 명확하고 짧은 기준점(수렴 바닥 최저가 196달러 혹은 돌파봉 하단)을 손절가로 설정할 수 있어, 리스크 한도를 안전하게 통제한 채 상방 랠리를 도모할 수 있다는 점입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (249, '패턴/돌파', '04_patterns_breakout.md', '시세가 약한 매수세와 거래량 급감 속에 고점과 저점을 높이며 좁게 상승 쐐기형(Rising Wedge)을 그리고 있습니다. 현재 가격은 상승 쐐기형 하단 지지선(600달러)에 아주 밀착하여 붕괴 위기에 놓여 있습니다. 이 시점에서 롱(매수) 포지션을 들고 있는 트레이더의 리스크 대응은?', '[{"time":"Day 1","open":520,"high":560,"low":520,"close":556,"volume":84},{"time":"Day 2","open":556,"high":590,"low":544,"close":580,"volume":34},{"time":"Day 3","open":580,"high":610,"low":596,"close":602,"volume":24}]'::jsonb, '[{"type":"line","points":[{"x":0,"y":520},{"x":1,"y":544},{"x":2,"y":596}],"label":"쐐기 하단 지지선 (300)","color":"#ef4444"}]'::jsonb, ARRAY['상승 쐐기형 하방 이탈 위험에 따른 롱 포지션 매도', '상승 지속 확신에 따른 레버리지 추가 불타기', '장기 상승 흐름 기대로 손절 없이 무기한 홀딩', '다른 종목으로의 포지션 분산을 위한 관망']::text[], 0, '상승 쐐기형(Rising Wedge)은 약세 세력이 억지로 쥐어짜며 상승 가격을 만드는 패턴으로, 수렴 끝에서 거래량 소멸과 함께 하방 이탈(Breakdown)하여 폭락할 위험이 매우 높은 대표적인 하락 대비 패턴입니다. 하단 지지선 이탈 낌새 시에는 매수 포지션을 전부 도망쳐 나와야 큰 손실을 막을 수 있습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (250, '패턴/돌파', '04_patterns_breakout.md', '둥근 대야 모양의 바닥(Cup)을 그리며 상승 회복한 시세가 전고점 저항벽 부근에서 하향 채널식 완만한 되돌림 조정 핸들(Handle)을 그리는 중입니다. 이후 핸들의 상단 저항선(300달러선)을 강한 거래량의 장대양봉으로 상향 돌파했습니다. 이때 합리적인 트레이더의 대응은?', '[{"time":"Day 1","open":280,"high":284,"low":256,"close":260,"volume":98},{"time":"Day 2","open":260,"high":280,"low":258,"close":276,"volume":112},{"time":"Day 3","open":276,"high":280,"low":268,"close":270,"volume":116},{"time":"Day 4","open":270,"high":308,"low":268,"close":304,"volume":118}]'::jsonb, '[]'::jsonb, ARRAY['핸들 상방 돌파 확인 후 진입 및 핸들 저점 손절', '하락 지속 판단에 따른 즉각적인 전량 손절', '평단가 부근이므로 추가 손절 설정 없이 관망', '돌파 여부 확인 전 고점 돌파 매수 주문 100%']::text[], 0, '전형적인 강세 지속 패턴인 컵앤핸들(Cup & Handle)입니다. 핸들의 하락 조정 채널 상단 돌파는 매물 소화를 성공적으로 완수하고 본 랠리로 진입한다는 강력한 신호입니다. 손익비 관점에서 핸들의 지지 저점인 268달러 아래에 안전 손절을 지정한 뒤 진입 시 우수한 기대 수익을 가질 수 있습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (251, '지표/컨플루언스', '06_technical_indicators.md', '강력한 대세 상승 국면인 종목이 일시 조정을 거쳐 전저점 지지 영역(200달러)에 도달해 저점을 지키고 있습니다(저점 높임 또는 수평). 그런데 이때 보조지표 RSI의 저점은 이전보다 훨씬 깊게 파여 낮아지는 ''히든 상승 다이버전스(Hidden Bullish Divergence)''가 포착되었습니다. 현명한 의사결정은?', '[{"time":"Day 1","open":180,"high":220,"low":176,"close":210,"volume":99},{"time":"Day 2","open":210,"high":214,"low":196,"close":200,"volume":91}]'::jsonb, '[]'::jsonb, ARRAY['하락 전환 신호로 판단하여 전량 즉시 손절', '추세 지속 신호 기대로 지선 부근 추가/신규 매수', '지표 과매수 판단에 따른 계좌 거래 정지', '손절 설정 없이 무제한 레버리지 롱 대응']::text[], 1, '시세의 저점은 높아지는데 보조지표(RSI 등)의 저점은 낮아지는 형태는 ''히든 상승 다이버전스''입니다. 이는 기존의 강력한 상승 트렌드 내부에서 일시 조정을 겪는 매수자들이 활기차게 물량을 주워 담아 다음 상승 랠리를 추진한다는 신호이므로, 짧은 손절 라인(196달러)을 설정하고 매수 비중을 태우기 가장 적합한 정석 타점입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (252, '지표/컨플루언스', '07_multitimeframe_regime.md', '시세가 호재와 함께 밴드 상단선 바깥을 타고 계속 상승하는 강력한 볼린저 밴드 밴드워크(Band Walk) 현상이 발생 중이며, RSI는 80을 넘어 극단적 과매수 수치를 가리키고 있습니다. 이 구간에서 취해야 할 가장 합리적인 리스크 및 포지션 관리 행동은?', '[{"time":"Day 1","open":200,"high":230,"low":198,"close":224,"volume":109},{"time":"Day 2","open":224,"high":256,"low":220,"close":250,"volume":122},{"time":"Day 3","open":250,"high":278,"low":244,"close":272,"volume":105}]'::jsonb, '[]'::jsonb, ARRAY['과매수 도달 판단에 따른 고배율 숏 무리한 진입', '추종 손절매(Trailing Stop)를 통한 수익 극대화', '상승폭 만족에 따른 즉각적인 전량 시장가 익절', '손절 가격을 해제하고 시세 지속 시까지 방치']::text[], 1, '강세 추세가 지나치게 강할 경우 볼린저 밴드 상단을 타고 오르는 밴드워크 현상과 RSI 과매수 현상이 영구 유지될 수 있습니다. 이때 단순 과매수 수치를 이유로 숏 포지션을 잡으면 파산합니다. 기존 매수 포지션의 익절선(Trailing Stop)을 상향 관리하여 추세 상승 이익을 극대화하고 신규 진입은 자제하는 것이 정석 리스크 관리입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (253, '지표/컨플루언스', '06_technical_indicators.md', '1시간 봉 차트 상에서 시세가 확실히 낮아졌으나 RSI 저점은 유의미하게 상승한 ''상승 다이버전스''가 확인되어 매수 타점을 노리고 있습니다. 다만 15분 봉 단기 차트에서는 하락 장대음봉 관성이 아직 살아있어 매도 압력이 보입니다. 멀티 타임프레임 트레이더의 진입 의사결정은?', '[{"time":"Hour 1","open":200,"high":204,"low":180,"close":182,"volume":110},{"time":"Hour 2","open":182,"high":184,"low":160,"close":164,"volume":100}]'::jsonb, '[]'::jsonb, ARRAY['단기 음봉 관성 기대로 즉각 숏 포지션 진입', '큰 시간 프레임의 상승 다이버전스 타점 매수', '지표 충돌로 판단하고 시장가 즉시 롱 진입', '변동성 기대로 무작정 도박성 잡코인 진입']::text[], 1, '큰 프레임(1시간 봉)의 다이버전스가 주는 중장기 추세 신뢰도는 작은 프레임의 단기 노이즈보다 압도적으로 강력합니다. 단, 진입 시 타이밍의 정밀도를 높이기 위해 소파동(15분 봉)의 하락 동력이 꺾이고 지지해 주는 단기 확인 캔들이 나오는 찰나에 롱 포지션 타이밍을 잡는 것이 멀티 타임프레임 정석 매매입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (254, '지표/컨플루언스', '06_technical_indicators.md', '시세는 400달러 저항대를 뚫고 440달러까지 계속 우상향하며 고점을 갱신하고 있으나, MACD 오실레이터의 히스토그램 산 높이는 직전 고점 시점 대비 현저하게 쪼그라들며 꺾여 내려가 하락 다이버전스를 형성 중입니다. 현명한 포지션 보유자의 이익 관리 행동은?', '[{"time":"Day 1","open":360,"high":410,"low":358,"close":400,"volume":119},{"time":"Day 2","open":400,"high":444,"low":396,"close":440,"volume":104}]'::jsonb, '[]'::jsonb, ARRAY['추세 지속 확신으로 보유 비중 추가 불타기', '상승 모멘텀 약화 다이버전스 확인 후 50% 익절', '익절 설정 없이 전고점 도달 시까지 홀딩', '고점 붕괴 기대로 숏 포지션 10배 베팅']::text[], 1, '시세는 올라가나 모멘텀 지표인 MACD 오실레이터 고점이 낮아지는 현상은 대표적인 하락 다이버전스로, 매수 에너지가 속 빈 강정처럼 쇠퇴하고 있어 언제든 급격한 폭락 조정이 발생할 수 있는 고위험 신호입니다. 이 시점에는 탐욕을 통제하고 물량의 50% 이상을 분할 매도하여 현금을 챙기는 것이 원칙입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (255, '지표/컨플루언스', '06_technical_indicators.md', '시세가 하락 횡보하던 도중, 단기 지평선인 EMA 20일선이 중장기선인 EMA 50일선에 극도로 밀착하며 수렴했습니다. 당일 대량 거래량의 음봉 캔들이 터지며 단기선이 장기선 아래로 교차하기 직전(데드크로스 임박)이며 주요 지지선 밑으로 떨어졌습니다. 롱(매수) 포지션 보유자의 올바른 대응은?', '[{"time":"Day 1","open":210,"high":212,"low":198,"close":200,"volume":93},{"time":"Day 2","open":200,"high":202,"low":190,"close":192,"volume":92}]'::jsonb, '[]'::jsonb, ARRAY['지지선 이탈 및 데드크로스 확인 즉시 손절', '이평선 지지력을 믿고 하방 물타기 추가 매수', '하락 조정 후 반등 기대로 무기한 홀딩 관망', '청산가 도달 시까지 어떠한 대응 없이 방치']::text[], 0, '20일선과 50일선의 데드크로스 임박 수렴 상태에서 가격이 지지선마저 무너뜨린 것은 하락 가속화 추세가 폭발하기 직전인 매우 위험한 기술적 상태입니다. 하락 추세가 본격 정배열(하락 정배열)화 되기 전에 즉시 전량 손절하고 시장 밖에서 피신해 있는 것이 계좌의 영구 파산을 막는 유일한 생존 규칙입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (256, '리스크/심리', '09_risk_position_management.md', '가상자산 매수 후 가격이 급락하여 내가 설정해 둔 최대 감내 손실 한도인 계좌 총원금 대비 -2% 라인(손절매 지정 가격)에 완벽하게 닿았습니다. 마침 본전 생각과 함께 ''조금만 더 버티면 반등할 텐데...''하는 강한 뇌동매매 유혹이 솟구칩니다. 이때 원칙 트레이더의 결정은?', '[{"time":"Day 1","open":200,"high":204,"low":198,"close":200,"volume":115},{"time":"Day 2","open":200,"high":202,"low":188,"close":190,"volume":116}]'::jsonb, '[]'::jsonb, ARRAY['손절 라인을 임의로 하향 조정하고 홀딩', '평단가 관리 차원의 지속적 물타기 매수 집행', '원칙에 따라 뇌동을 제어하고 즉시 기계적 손절', '손실은 배제하고 반등 기대를 통한 무기한 보유']::text[], 2, '트레이딩의 승패는 예측이 아닌 ''리스크 통제''에 달려 있습니다. 사전에 정한 계좌 대비 2% 리스크 한도에 도달했을 때 희망 회로를 돌리며 손절을 미루거나 물타기를 집행하는 순간 계좌는 서서히 영으로 깎여 파산합니다. 멘탈의 충동을 통제하고 기계적으로 전량 칼손절하는 것이 절대 파산하지 않는 시장의 1법칙입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (257, '리스크/심리', '10_psychology_routine_review.md', '최근 3회 연속 거래에서 계속해서 손절(Stop Loss)을 맞아 뇌 내의 도파민 체계가 무너지고 심리가 극도로 불안해져 분노와 보복 매매 충동이 밀려옵니다. 이 상황에서 파산을 막는 가장 훌륭한 매매 심리 대처법은?', '[{"time":"Today","open":200,"high":200,"low":200,"close":200}]'::jsonb, '[]'::jsonb, ARRAY['손실 복구를 위해 레버리지를 증액해 즉시 진입', '뇌동 방지를 위해 HTS를 종료하고 매매 일지 작성 및 휴식', '추천 매매 신호 유료 리딩방에 즉시 가입 및 추종', '심리적 회복을 위해 역베팅 숏 포지션 추가']::text[], 1, '연속 손실 후 발생하는 복수심과 분노는 트레이더를 뇌동매매와 계좌 파멸로 이끄는 가장 치명적인 감정 상태입니다. 멘탈 붕괴를 느꼈을 때는 즉각 행동을 멈추고 시스템을 강제 종료하여 시장과 물리적 격리를 통해 냉정을 찾는 것만이 자산을 파산 리스크로부터 살려내는 훌륭한 트레이딩 행동입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (258, '셋업/실행', '09_risk_position_management.md', '진입하고자 하는 매수 자리를 분석해 보니, 기술적 분석 상 이길 수 있는 확률(승률)은 반반인 50% 수준입니다. 그러나 손절 시 기대 손실금액 대비 성공 시 획득할 수 있는 기대 수익금액의 비율(손익비)을 정밀 셋업 해보니 1 : 1.2 수준으로 다소 애매하게 도출되었습니다. 원칙 트레이더의 진입 결정은?', '[{"time":"Today","open":200,"high":200,"low":200,"close":200}]'::jsonb, '[]'::jsonb, ARRAY['단기 변동성 기대로 부적합한 손익비 시장가 진입', '마이너스 기댓값 거래 유보 및 우수 타점 대기', '레버리지를 높여 손익비 구조를 임의 조정 시도', '반대 방향으로 고배율 역베팅을 즉시 실행']::text[], 1, '수학적으로 승률 50%일 때 손익비가 최소 1:2(잃을 때 1, 벌 때 2) 이상이 나오지 않으면 복리 매매 시 수수료와 호가 슬리피지에 밀려 잔고가 무조건 마이너스로 수렴합니다. 타점이 눈에 들어오더라도 사전에 기대 손익비 필터에 걸려 탈락한다면 패스를 선언하고 관망하는 것이 현명한 생존 원칙입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (259, '리스크/심리', '09_risk_position_management.md', '갑작스러운 거시 경제 발표로 내가 매매 중인 종목의 캔들 변동성 폭(ATR)이 평소 시세의 2배 수준으로 널뛰기 시작했습니다. 1회 거래당 내 계좌 원금의 최대 2% 리스크 한도를 동일하게 고수하기 위해 취해야 할 올바른 조치는?', '[{"time":"Day 1","open":200,"high":204,"low":196,"close":200,"volume":116},{"time":"Day 2","open":200,"high":220,"low":180,"close":204,"volume":116}]'::jsonb, '[]'::jsonb, ARRAY['평소 변동성과 동일한 비중 및 손절 거리 고수', '손절 거리를 넓히는 대신 진입 포지션 수량 축소', '변동성이 확대되었으므로 2배 비중으로 적극 지름', '즉시 전량 손절하고 시장 상황 정상화 대기']::text[], 1, '시장 변동성이 커질 때는 손절 스톱 아웃이 잦으므로 손절폭(%)을 넓혀 숨 쉴 공간을 확보해 주는 것이 합리적입니다. 단, 손절폭을 2배로 늘린다면 계좌 대비 리스크 한도가 2배(4%)로 커지므로, 진입 포지션의 계약 수량을 50%로 줄여 리스크 노출 총액을 2%로 완벽하게 동일 통제하는 것이 포지션 사이징(Position Sizing)의 정석 원칙입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (260, '리스크/심리', '09_risk_position_management.md', '투자자 A의 전체 투자 원금은 1,000만 원이며, 1회 거래당 최대 허용 리스크 금액은 원금의 2%인 20만 원입니다. 현재 시세가 20,000원이며, 기술적 분석 상 합리적인 손절선은 지지선 바로 밑인 19,000원(-5%)입니다. 2% 룰 리스크 관리 원칙에 따라 A가 진입(매수)해야 하는 최대 가상자산 수량은?', '[{"time":"Today","open":20000,"high":20000,"low":20000,"close":20000}]'::jsonb, '[]'::jsonb, ARRAY['500주 (투자금 전액 시장가 매수)', '200주 (손실 한도 20만 원 맞춤 매수)', '50주 (보수적 극단적 비중 축소)', '100주 (절반 비중 고정 매수)']::text[], 1, '포지션 크기 계산 공식은 `최대 매수 규모 = 최대 허용 리스크 금액 / 손절매 비율` 입니다. 이 시나리오에서 `200,000원 / 0.05(5%) = 4,000,000원`이 최대 허용 진입금액이 되며, 이를 시세 20,000원으로 나누면 `200주`가 도출됩니다. 200주 진입 후 -5% 가격 폭락으로 손절 당해도 내 총원금에서 깎이는 돈은 정확히 20만 원(2%)으로 완벽히 리스크 통제됩니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (261, '거래량/유동성', '05_volume_liquidity.md', '시세가 수평 저항선 부근까지 급상승했으나 캔들 몸통(Spread)이 지극히 좁아진 도지 형태로 마감하였고, 거래량은 이전 5일 평균 대비 3배 이상 폭증했습니다. VSA(Volume Spread Analysis) 관점에서 가장 타당한 차트 분석은?', '[{"time":"Day 1","open":200,"high":210,"low":198,"close":208,"volume":86},{"time":"Day 2","open":208,"high":218,"low":206,"close":216,"volume":102},{"time":"Day 3","open":216,"high":220,"low":214,"close":216,"volume":99}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":218},{"x":2,"y":218}],"label":"저항선","color":"#ef4444"}]'::jsonb, ARRAY['강한 매수 기세 기대로 즉시 돌파 매매 풀매수', '저항벽 매도 공급 세력 분산 확인 후 이익 실현', '대량 거래 확인에 따른 손절 해제 후 장기 투자', '반등 실패에 따른 고배율 보복 숏 베팅 가동']::text[], 1, '캔들 몸통 크기(스프레드)가 좁은데 거래량이 매우 크게 폭증했다는 것은 저항선 부근에서 들어오는 매수세만큼 세력의 매도 물량 공급이 쏟아져 막강한 저항 벽을 형성하고 있다는 뜻입니다. VSA에서는 이를 불화(Disharmony)로 규정하며 상승 추세 감속 및 하락 반전의 경고로 해독합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (262, '거래량/유동성', '05_volume_liquidity.md', '시세가 장기 횡보하던 박스권 지지선인 400달러를 깨고 390달러까지 하락 투매가 발생했으나, 종가 마감 직전 거래량이 크게 실린 긴 아래꼬리를 그리며 다시 402달러 위로 복귀 안착했습니다. 이 스톱 헌팅 유동성 현상에서의 실전 트레이더의 대응은?', '[{"time":"Day 1","open":420,"high":424,"low":400,"close":404,"volume":100},{"time":"Day 2","open":404,"high":408,"low":390,"close":402,"volume":90}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":400},{"x":1,"y":400}],"label":"지지선","color":"#10b981"}]'::jsonb, ARRAY['지지선 붕괴 확정으로 간주한 시장가 숏 추격', '스윕(sweep) 판단 하에 아래꼬리 저점 손절 잡고 롱', '아무런 신호도 아니라고 판단하고 포지션 방치', '지지선 이탈 기대로 전량 손절 후 시장 영구 탈출']::text[], 1, '지지선 아래에 걸려 있던 개인들의 손절 주문(Sell Stop)을 강제로 청산(Liquidity Sweep)시킨 뒤, 세력이 물량을 헐값에 다 받아 삼켜 종가를 지지선 위로 신속하게 복귀시킨 휩소(베어 트랩) 패턴입니다. 아래꼬리 극점(390달러)에 아주 좁은 손절 라인을 설정할 수 있어, 기대 손익비가 극대화되는 고확률 상승 반전 매수 타점입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (263, '거래량/유동성', '05_volume_liquidity.md', '시세는 500달러에서 580달러까지 계속 고점을 높이며 상승 추세를 이어가고 있습니다. 그러나 각 상승 파동마다 터지는 거래량은 전고점 돌파 시점 대비 눈에 띄게 하향 곡선을 그리며 감소하고 있습니다. VSA 기법에 따른 합리적인 진단은?', '[{"time":"Wave 1","open":460,"high":520,"low":456,"close":510,"volume":91},{"time":"Wave 2","open":510,"high":550,"low":500,"close":540,"volume":88},{"time":"Wave 3","open":540,"high":580,"low":530,"close":576,"volume":122}]'::jsonb, '[]'::jsonb, ARRAY['가격 상승으로 인한 매수 지속 강화 초강세', '매도 물량 고갈에 따른 무중력 안심 홀딩', '신규 자금 유입 둔화 거래량 다이버전스로 분할 익절', '지표 조작으로 판단하여 매매 중단 및 차트 종료']::text[], 2, '시세는 상승하여 신고점을 갱신하지만 파동별 거래량이 지속 감소하는 흐름은 ''거래량 다이버전스''로 상승 모멘텀의 내부 엔진이 식어감을 경고합니다. 조만간 가벼운 매도 포격에도 대규모의 차익 실현 폭락 조정이 발생할 수 있는 잠재적 폭락 국면이므로 물량을 덜어내고 현금을 확보해야 합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (264, '거래량/유동성', '05_volume_liquidity.md', '가격이 이전 고점 저항선을 뚫고 강하게 솟구치며 장대양봉을 만들었습니다. 이때 가짜 이탈(Whipsaw / Bull Trap)이 아닌 진성 돌파(True Breakout)로 판정할 수 있는 가장 신뢰도 높은 거래량 기준은?', '[{"time":"Day 1","open":200,"high":204,"low":198,"close":200,"volume":381},{"time":"Day 2","open":200,"high":224,"low":198,"close":220,"volume":346}]'::jsonb, '[]'::jsonb, ARRAY['수렴 끝자락에서 거래량이 최저치인 상태 유지', '평균 대비 1.5~2배 이상 거래량 급증하며 돌파 마감', '거래량이 전혀 변하지 않는 평이한 상태 유지', '호가 스프레드가 가장 좁아지는 횡보 상태']::text[], 1, '참된 저항 돌파(True Breakout)는 저항선 부근의 두터운 대기 매도 공급 물량을 대규모 자금으로 전부 씹어 삼키고 돌파해야 함을 뜻합니다. 따라서 반드시 평균 대비 1.5배~2배 이상의 거래량 분출이 동반되어야 신뢰할 수 있으며, 거래량이 적은 돌파는 꼬리 달고 내려앉는 불 트랩(Bull Trap)일 확률이 매우 높습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (265, '거래량/유동성', '05_volume_liquidity.md', '솔라나 차트에서 중요 지지선 직전 저점 아래에 엄청난 규모의 롱 포지션 청산 및 매도 손절 주문이 쌓여 있는 유동성 풀(Liquidity Pool) 구간이 감지되었습니다. 세력이 이 구간을 공략할 때 나타날 캔들의 전형적인 무빙 패턴은?', '[{"time":"Day 1","open":100000,"high":101000,"low":98400,"close":99000,"volume":31},{"time":"Day 2","open":99000,"high":99600,"low":96000,"close":99200,"volume":31}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":98400},{"x":1,"y":98400}],"label":"전저점 지지선","color":"#3b82f6"}]'::jsonb, ARRAY['지지선을 장대음봉으로 돌파하여 20% 폭락 마감', '전저점 이탈로 손절 유도 후 지지선 위 아래꼬리 안착', '오차 없이 지지선 터치 후 꼬리 없는 수평 도지 횡보', '거래량 없이 즉각 상승 빔 분출로 전고점 탈환']::text[], 1, '기관 세력(스마트 머니)은 대량 포지션을 구축하기 위해 개인의 손절 주문(Sell Stop)을 의도적으로 터트려 매도 유동성을 유도한 후 이를 다 매수합니다. 이로 인해 시세는 지지선 아래로 일시 급락 후(스톱 헌팅), 아래꼬리를 매우 길게 달며 지선 안쪽으로 급반등 마감하게 됩니다. 이것이 유동성 스윕(Liquidity Sweep)의 정석 패턴입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (266, '거래량/유동성', '05_volume_liquidity.md', '상승 추세 도중 전고점 저항선 부근에서 위꼬리가 아주 긴 캔들이 터졌고, 거래량은 최근 보름 중 최고 수치로 솟구쳤습니다. VSA 관점에서 이 상승 거절(Upside Rejection) 현상에 대한 올바른 대처는?', '[{"time":"Day 1","open":200,"high":230,"low":196,"close":202}]'::jsonb, '[]'::jsonb, ARRAY['강한 저점 매수 기회로 인지하여 비중 대폭 추가', '고점 매도 Rejection 확인 후 기존 롱 포지션 대피', '박스 횡보 수렴 기대로 마틴게일 추가 매수 가동', '이평선 정배열 판단에 따른 포지션 변경 없이 홀딩']::text[], 1, '위꼬리가 매우 긴 캔들이 대량 거래량과 함께 터졌다는 것은 고점 돌파 시도가 있었으나 그 자리에 숨어 있던 세력의 막강한 청산 매도 벽(Supply)을 만나 격렬하게 두들겨 맞고 밀려났음을 의미합니다. 상방 거절의 심리가 지배적이므로 고점 피로 및 하락 전환이 임박한 위험 징후입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (267, '지표/컨플루언스', '06_technical_indicators.md', '시세가 장기 박스권 횡보를 이어가며 볼린저 밴드의 폭이 최근 몇 달 중 가장 좁은 형태로 밀착 수렴(Squeeze)되었습니다. 이 스퀴즈 국면에 대한 올바른 기술적 이해와 매매 시나리오는?', '[{"time":"Week 1","open":200,"high":206,"low":194,"close":202,"volume":96},{"time":"Week 2","open":202,"high":204,"low":198,"close":200,"volume":101}]'::jsonb, '[]'::jsonb, ARRAY['박스권 변동성 부재 기대로 장기 무대응 관망', '에너지 수축 스퀴즈 확인 후 밴드 이탈 돌파 대기', '지표 신뢰 불가 판단으로 볼린저 밴드 지표 삭제', '중심선 지지로 판단하여 고배율 매수 대기 주문']::text[], 1, '볼린저 밴드의 폭이 극도로 좁아지는 스퀴즈(Squeeze) 현상은 시장의 표준편차 변동성이 임계치까지 압축 수렴되었음을 알려줍니다. 에너지 압축 뒤에는 항상 폭발적인 가격 분출(상방/하방 이탈)이 뒤따르므로, 밴드를 뚫고 거래량이 실려 돌파 마감하는 방향으로 추세 추종 시나리오를 설계해야 합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (268, '지표/컨플루언스', '06_technical_indicators.md', '시세는 HL(Higher Low)을 형성하며 이전 직전 저점(180달러)보다 높은 저점(190달러)을 지키고 있으나, RSI 지표는 이전 35 수치보다 더 깊숙하게 25 수치까지 떨어졌습니다. 이 지표 불일치 현상의 공식 명칭과 올바른 포지션 셋업은?', '[{"time":"Day 1","open":200,"high":204,"low":180,"close":182,"volume":107},{"time":"Day 2","open":182,"high":192,"low":190,"close":190,"volume":95}]'::jsonb, '[]'::jsonb, ARRAY['일반 상승 다이버전스 - 추세 종결로 즉각 공매도', '히든 상승 다이버전스 - 지선 눌림목 롱 진입 활용', '일반 하락 다이버전스 - 모든 매수 포지션 정리', '지표 오작동 휩소 구간 판단으로 양방향 관망']::text[], 1, '가격의 저점은 높아졌는데(Higher Low) 모멘텀 지표의 저점은 낮아지는 현상은 ''히든 상승 다이버전스(Hidden Bullish Divergence)''입니다. 이는 추세 반전이 아닌 **기존 강세 추세 지속**을 뜻하며, 조정 눌림목이 완성되고 다음 상승 랠리를 준비한다는 최고의 매수 신호 중 하나입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (269, '지표/컨플루언스', '06_technical_indicators.md', '매수 타점을 신중하게 선별하고자 합니다. 기술적 분석의 성공 확률을 비약적으로 끌어올리는 ''다중 컨플루언스(Confluence)'' 결합 사례로 가장 적합한 조건 구성은?', '[{"time":"Today","open":200,"high":200,"low":200,"close":200}]'::jsonb, '[]'::jsonb, ARRAY['트위터 및 뉴스의 호재 찌라시 확인 즉시 추격', '지지선+이평선+다이버전스+아래꼬리 등 분석 중첩 시', 'RSI 과매수 영역 진입 즉시 롱 포지션 진입', '독립적 분석 없이 오직 보조지표의 단일 수치 신호']::text[], 1, '다중 컨플루언스(Confluence)는 독립적인 기술적 근거들이 동일한 특정 가격 구역에 중첩되는 현상입니다. 지지 저항, 이평선, 보조지표 다이버전스, 캔들 가격행동(Rejection 핀바)이 한 곳에 묶여 매수 자리를 형성할 때 매매를 실행하면, 높은 신뢰도와 좁은 손절 라인 덕분에 장기 기대값이 극대화됩니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (270, '셋업/실행', '08_setup_entry_exit.md', '중요 수평 저항선(240달러)을 상방으로 장대양봉 종가 돌파한 것을 확인하고 롱(매수) 진입 셋업을 준비하고 있습니다. 원칙 트레이더가 뇌동매매 추격을 막고 최상의 손익비를 확보하기 위해 즐겨 쓰는 정석적인 진입 실행법은?', '[{"time":"Day 1","open":220,"high":224,"low":218,"close":222,"volume":100},{"time":"Day 2","open":222,"high":248,"low":220,"close":244,"volume":120}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":240},{"x":1,"y":240}],"label":"저항선","color":"#ef4444"}]'::jsonb, ARRAY['돌파 마감 확인 즉시 시장가 추가 매수 집행', '돌파된 저항선의 지지 전환(Retest) 시 지정가 진입', '반등 조정이 불가능하다고 판단하여 최고점 롱 추격', '속임수 돌파 확신으로 고배율 역베팅 숏 진입']::text[], 1, '저항 돌파 후 즉시 가격을 따라붙는 추격 매수는 휩소 조정 시 심각한 손실을 초래합니다. 돌파된 라인이 S/R Flip을 통해 지지로 작용하는지 확인하는 되돌림 리테스트(Retest) 시점에 진입하는 것이, 지선 바로 아래에 좁은 손절 라인을 설계하고 이익 기대 폭을 넓힐 수 있는 가장 이상적인 정석 실행법입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (271, '셋업/실행', '08_setup_entry_exit.md', '포지션 진입 직후, 가격이 계획대로 내 방향으로 순탄하게 우상향하고 있습니다. 기존 진입 시 설정한 손익비 1:2의 최종 목표가 도달 전에, 리스크 관리 차원에서 계좌 드로다운을 0으로 만드는 정석적인 1차 포지션 관리 행동은?', '[{"time":"Entry","open":200,"high":200,"low":200,"close":200,"volume":94},{"time":"Day 1","open":200,"high":212,"low":200,"close":210,"volume":116}]'::jsonb, '[]'::jsonb, ARRAY['1차 저항대 진입 시 레버리지를 활용해 불타기', '목표가 터치 시까지 100% 비중 무대응 홀딩', '1:1 지점 50% 분할 익절 및 남은 물량 본전 손절 상향', '단기 반등 확인 즉시 전량 기계적 청산 및 퇴장']::text[], 2, '이득이 발생해 손익비 1:1 수준에 오면 물량의 절반을 분할 익절(Scale-out)하고 남은 포지션의 스톱로스를 진입가로 이동(Break-even)시키는 것이 포지션 관리의 기본입니다. 이렇게 셋업하면 차트가 갑자기 폭락세로 뒤집혀도 최소 본전 혹은 반절 익절 약수익으로 끝나 해당 거래의 최대 리스크가 Zero(0)로 봉쇄됩니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (272, '셋업/실행', '08_setup_entry_exit.md', '강력한 장기 상승 추세가 터져 시세가 20일 이평선을 타고 계속해서 폭발적으로 신고가를 갱신하고 있습니다. 이때 익절 시점을 서둘러 잡지 않고, 추세 상승 이익을 최대한 길게 끝까지 빨아먹기 위한 정석 청산 실행법은?', '[{"time":"Day 1","open":200,"high":220,"low":198,"close":216,"volume":87},{"time":"Day 2","open":216,"high":240,"low":214,"close":236,"volume":102},{"time":"Day 3","open":236,"high":270,"low":234,"close":264,"volume":100}]'::jsonb, '[]'::jsonb, ARRAY['RSI 과과열 조짐 확인 즉시 시장가 전량 익절', 'Higher Low 지지 직하방으로 손절 추종 익절 셋업', '이익 보존을 포기하고 손익절 라인을 해제 후 홀딩', '즉시 숏 포지션 10배로 맞불을 놓는다']::text[], 1, '강세 추세가 터졌을 때 지레짐작으로 청산하면 상승 파동의 초입만 먹고 끝납니다. 추세 붕괴의 명확한 신호(BOS/MSB)가 나오거나, 가격의 구조적 높은 저점(HL)이 깨질 때까지 손절 라인을 계속 추종해서 상향하는 ''추격 손절매(Trailing Stop)''를 가동하는 것이 추세 이익을 극대화하는 정석 기법입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (273, '셋업/실행', '01_chart_market_basics.md', '차트 분석 결과, 돌파 시점의 체결 변동성과 거래소 호가창의 얇은 매물 상태를 감안할 때 내가 진입하려는 주문 가격에서 체결이 뒤로 밀리는 ''슬리피지(Slippage)''가 심각하게 예상됩니다. 이를 감안한 올바른 주문 실행법은?', '[{"time":"Today","open":200,"high":200,"low":200,"close":200}]'::jsonb, '[]'::jsonb, ARRAY['시장가로 최고 배율을 설정하여 즉시 체결', '돌파 확인 후 지정가 대기 주문으로 단가 조절', '슬리피지를 예방하기 위해 즉각적인 거래 취소', '호가창 스프레드와 무관하게 고배율 레버리지']::text[], 1, '변동성이 크고 호가가 얇은 시장에서 돌파 시 시장가 진입은 나쁜 단가로 체결되는 슬리피지 비용을 발생시켜 시작부터 손실을 크게 안고 갑니다. 돌파 확인 후 되돌림 가격대에서 지정가(Limit Order)를 대기시켜 체결 단가를 내 손아귀에 고정하는 리스크 관리가 필요합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (274, '셋업/실행', '10_psychology_routine_review.md', '원칙 기반의 정석 매매 셋업(Trading Setup)을 설계할 때, 진입 전 반드시 사전에 수치로 명문화되어 결정되어야 할 요소가 아닌 것은?', '[{"time":"Today","open":200,"high":200,"low":200,"close":200}]'::jsonb, '[]'::jsonb, ARRAY['진입 조건(Trigger)과 구체적인 손절 가격(Stop Loss)', '거래 당일 본인의 주관적인 직감과 감정적 목표가', '진입하려는 구체적인 포지션 규모 및 분할 익절선', '거래 아이디어가 무효화되는 구체적 가격 지점']::text[], 1, '매매 셋업은 규칙에 기반한 수치들(진입가, 손절가, 목표가, 수량)로 사전에 철저히 규격화되어야 합니다. 당일의 운이나 주관적 느낌, 예감에 기초한 비과학적 청산 설정은 셋업에서 배제되어야 할 대표적 뇌동매매 요소입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (275, '셋업/실행', '08_setup_entry_exit.md', '하락 횡보하던 시세가 중요 매물대이자 피보나치 되돌림 0.618 지점에 정확히 맞닿아 아래꼬리가 긴 양봉 핀바(Pin Bar)를 그리며 마감했습니다. 룰베이스 트레이더가 진입 버튼을 누를 때 성립된 IF-THEN 시나리오는?', '[{"time":"Day 1","open":200,"high":200,"low":160,"close":164,"volume":97},{"time":"Day 2","open":164,"high":172,"low":156,"close":170,"volume":100}]'::jsonb, '[]'::jsonb, ARRAY['익일 가격 상황과 관계없이 100배 레버리지 진입', '중첩 자리 핀바(rejection) 확인 후 익일 시가 롱 진입', '상단 저항 도달 판단으로 즉각적인 숏 포지션 진입', '돌파 랠리가 완전히 끝날 때까지 HTS 종료 및 관망']::text[], 1, '훌륭한 트레이딩 실행은 ''IF(조건 만족 시) ➔ THEN(원칙대로 포지션 진입 및 손절/목표가 기계적 배치)''의 룰베이스 알고리즘에 의해 움직여야 감정을 배제할 수 있습니다. 지지 구간 중첩과 핀바 출현 조건이 성립했으므로 다음 봉 시가에 진입하되 꼬리 저점 이탈 시 칼손절하여 리스크를 통제하는 것이 정석입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (276, '리스크/심리', '09_risk_position_management.md', '나의 트레이딩 시스템 승률이 40%로 다소 낮게 고정되어 있습니다. 이 시스템을 통해 장기적으로 파산하지 않고 복리로 계좌 자산을 우상향시키기 위해 필수적으로 지켜야 할 손익비(평균손실 대비 평균수익 비율)의 최소 기준은?', '[{"time":"Today","open":200,"high":200,"low":200,"close":200}]'::jsonb, '[]'::jsonb, ARRAY['손익비 1:1 수준 (매매 승률이 낮을 때 파산)', '승률 40% 대비 기댓값 개선을 위한 손익비 1:1.5 이상', '낮은 승률 상태에서 손익비와 무관하게 무조건 파산', '승률 극복을 위한 레버리지 20배 수준 설정']::text[], 1, '승률이 40%일 때 기대값 수학적 수수료 감안 최소 손익비는 1:1.5입니다. 손익비 1.5배 이상 구간만 취하면 10번 중 6번 손절당하고 단 4번만 익절하더라도 계좌 총합은 수익 우위에 서게 됩니다. 저승률 시스템일수록 철저히 손익비가 유리한 진입가 근처 타점만 기계적으로 필터링해 진입해야 생존합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (277, '리스크/심리', '09_risk_position_management.md', '선물 트레이더인 B는 담보금 효율을 극대화한다는 명목으로 50배 레버리지 롱 포지션 진입을 실행했습니다. 진입 가격 대비 B의 포지션 원금이 완전 소멸(강제 청산)되는 역방향 하락 거리(%)는 대략 몇 % 수준입니까?', '[{"time":"Today","open":200,"high":200,"low":200,"close":200}]'::jsonb, '[]'::jsonb, ARRAY['진입 단가 대비 20.0%의 강한 하락 발생 시', '진입 단가 대비 단 -2.0% 변동성 노이즈 터치 시', '진입 단가 대비 50.0%의 강한 폭락 발생 시', '청산가가 산출되지 않는 특이 종목 거래 시']::text[], 1, '청산 거리 계산 공식은 대략 `100% / 레버리지 배수` 입니다. 50배 고배율 레버리지의 경우, 내 포지션 반대 방향으로 단 **-2%**의 시세 변동성(장중 흔한 잔파동 노이즈)만 터치해도 원금이 100% 강제 청산 증발됩니다. 고배율 레버리지는 수학적 확률상 100% 파멸을 초래하는 도박성 거래 행위입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (278, '리스크/심리', '09_risk_position_management.md', '트레이딩 계좌 총자산이 4,000만 원인 트레이더가 있습니다. 1회 거래당 총자산의 2% 룰 원칙에 근거하여 리스크 한도(80만 원)를 설정했습니다. 진입하려는 종목의 손절가 거리가 -8%인 경우, 2% 룰을 완벽하게 충족하는 최대 진입(매수) 금액은?', '[{"time":"Today","open":200,"high":200,"low":200,"close":200}]'::jsonb, '[]'::jsonb, ARRAY['4,000만 원 전액 매수 (손절 폭을 배제한 대규모 베팅)', '1,000만 원 진입 (-8% 손절 시 리스크 한도 80만 원 충족)', '2,000만 원 진입 (손익비 1:1 기준에 맞춘 베팅)', '400만 원 진입 (보수적 원칙에 입각한 극단적 축소)']::text[], 1, '포지션 사이징 공식은 `진입금액 = 최대 리스크 허용액(80만 원) / 손절 비율(0.08)` 입니다. 이에 따라 `800,000원 / 0.08 = 10,000,000원`이 도출됩니다. 1,000만 원 규모로 매수 진입 시 가격이 급락해 -8% 손절 라인을 때려도 내 총자산에서 깎이는 금액은 정확히 원칙 한도인 80만 원(2%)으로 제한되어 계좌가 완벽히 방어됩니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (279, '리스크/심리', '10_psychology_routine_review.md', '장중에 내가 째려보며 타점을 기다리던 가상자산이 아무런 조정도 없이 장대양봉을 그리며 갑자기 수직 폭등하기 시작하여 5% 이상 치솟았습니다. 이때 머릿속에 ''나만 두고 날아가는 것 아닌가''하는 극심한 소외감 공포(FOMO)가 솟구칩니다. 원칙 트레이더의 올바른 심리 대응은?', '[{"time":"Day 1","open":200,"high":204,"low":198,"close":200,"volume":117},{"time":"Day 2","open":200,"high":212,"low":200,"close":210,"volume":112}]'::jsonb, '[]'::jsonb, ARRAY['추세 연장 판단으로 시장가 전액 추격 매수', 'FOMO 판단 하에 매수 보류 및 정석 되돌림 타점 대기', '돌파 실패 판단 하에 반대 방향 고배율 숏 베팅', '거래를 종료하고 즉각 가상자산 시장에서 전량 탈출']::text[], 1, '나만 기회를 잃는다는 공포(FOMO)로 날아가는 장대양봉 꼭대기에서 추격 매수하는 행위는 고점 물리기를 자처하는 가장 흔한 뇌동매매 패턴입니다. 내 타점을 비껴간 상승은 내 돈이 아니라고 인정하고, 사전에 정의한 룰베이스 타점까지 냉정하게 대기하는 것이 장기 생존자의 멘탈 습관입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (280, '리스크/심리', '10_psychology_routine_review.md', '오전 거래에서 원칙을 어긴 무리한 진입으로 인해 3회 연속 스톱아웃(손절)을 당하여 당일 원금의 -6%의 큰 손실을 입었습니다. 본전 생각과 분노로 눈이 뒤집혀 비중을 올려 한 판으로 복수하려는 ''보폭 매매'' 충동이 폭발할 때, 파산을 막는 가장 강력한 멘탈 시스템 룰은?', '[{"time":"Today","open":200,"high":200,"low":200,"close":200}]'::jsonb, '[]'::jsonb, ARRAY['손실 만회를 위해 빌린 돈으로 100배 고배율 복수 베팅', '일일 손실 한도 도달에 따른 매매 강제 종료 및 격리', '주변 유료 전문가 추천 종목을 탐색해 즉각 매수', 'RSI 과매도 상태이므로 즉시 반대 숏 포지션 진입']::text[], 1, '연패를 겪은 후 홧김에 비중을 더 크게 실어 한 번에 본전을 찾으려는 보복 매매는 계좌를 하루 만에 휴지조각으로 만드는 가장 무서운 파산 유도 심리 상태입니다. 이를 막기 위해 하루 최대 손실 한도 한계선(예: 3회 손절 또는 원금의 5%)을 정해두고, 이 한계선 터치 시 즉시 차트를 종료하고 냉각기를 강제 집행하는 룰이 필수입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (301, '캔들/가격행동', '02_candlestick_price_action.md', '하락 추세 지속 도중 바닥권에서 몸통이 짧고 아래꼬리가 몸통의 2배 이상인 아래 캔들이 출현했습니다. 이 캔들의 명칭과 올바른 대응은?', '[{"time":"10:00","open":360,"high":366,"low":354,"close":357,"volume":98},{"time":"10:15","open":357,"high":360,"low":339,"close":342,"volume":112},{"time":"10:30","open":342,"high":345,"low":324,"close":327,"volume":94},{"time":"10:45","open":327,"high":330,"low":303,"close":306,"volume":94},{"time":"11:00","open":306,"high":309,"low":270,"close":303,"volume":118}]'::jsonb, '[]'::jsonb, ARRAY['역망치형 (Inverted Hammer) - 하락 경고 및 공매도 대기', '망치형 (Hammer) - 저점 지지 및 분할 매수 대기', '도지 (Doji) - 매수세와 매도세의 팽팽한 균형 및 관망', '하락 장악형 (Bearish Engulfing) - 추세 반전 및 즉시 손절']::text[], 1, '마지막 캔들은 아래꼬리가 긴 ''망치형(Hammer)'' 캔들로 하락 압력을 이겨내고 저가 매수세가 밀어 올렸음을 의미하는 대표적 상승 전환 신호입니다. 지지를 확인한 뒤 분할 매수 관점으로 대기해야 합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (302, '캔들/가격행동', '02_candlestick_price_action.md', '삼성전자 주가가 장기간 급등한 뒤, 고점 부근에서 위꼬리가 매우 길고 몸통이 짧은 형태의 캔들이 발생했습니다. 이 캔들의 해석으로 가장 적절한 것은?', '[{"time":"Day 1","open":300,"high":324,"low":297,"close":315,"volume":90},{"time":"Day 2","open":315,"high":345,"low":312,"close":336,"volume":102},{"time":"Day 3","open":336,"high":375,"low":333,"close":369,"volume":117},{"time":"Day 4","open":369,"high":384,"low":360,"close":378,"volume":95},{"time":"Day 5","open":378,"high":435,"low":375,"close":381,"volume":129}]'::jsonb, '[]'::jsonb, ARRAY['유성형 (Shooting Star) - 고점 저항 및 하락 전환 예고', '망치형 (Hammer) - 저점 매수세 유입 및 상승 랠리 기대', '상승 장악형 (Bullish Engulfing) - 추세 반전 및 홀딩 유도', '도지 (Doji) - 추세 지속 가능성 및 일시 관망']::text[], 0, '급등세 끝에서 위꼬리가 몸통보다 훨씬 길게 솟아오른 캔들은 ''유성형(Shooting Star)''입니다. 장중 상승 시도를 강력한 차익 실현 및 매도 압력이 짓눌렀음을 보여주며, 하락 추세 전환의 강력한 경고 시그널입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (303, '캔들/가격행동', '02_candlestick_price_action.md', '직전의 음봉 몸통을 다음 날의 거대한 양봉 몸통이 완전히 감싸 안는 아래 형태가 포착되었습니다. 이 패턴의 이름과 신뢰도는?', '[{"time":"Day 1","open":294,"high":300,"low":285,"close":288,"volume":90},{"time":"Day 2","open":288,"high":291,"low":276,"close":279,"volume":104},{"time":"Day 3","open":279,"high":285,"low":264,"close":267,"volume":92},{"time":"Day 4","open":261,"high":306,"low":258,"close":303,"volume":107}]'::jsonb, '[]'::jsonb, ARRAY['하락 장악형 (Bearish Engulfing) - 추세 반전 신뢰도 낮음', '상승 장악형 (Bullish Engulfing) - 매수 전환 신뢰도 높음', '상승 관통형 (Piercing Line) - 중간 강도의 반전 신호', '석별형 (Evening Star) - 상승 추세 종결 신호']::text[], 1, '전일의 하락 음봉 몸통을 다음 날의 장대 양봉이 완전히 덮어버리는 형태를 ''상승 장악형(Bullish Engulfing)'' 패턴이라고 합니다. 하락 추세 끝에서 나타날 경우 단기 하락세가 종료되고 강력한 매수세가 들어왔음을 뜻해 전환 신뢰도가 매우 높습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (304, '캔들/가격행동', '01_chart_market_basics.md', '시가와 종가가 거의 일치하여 몸통이 거의 없고 위아래 꼬리만 달린 십자(+) 모양 캔들이 출현했습니다. 이 캔들에 대한 올바른 해석은?', '[{"time":"Day 1","open":450,"high":465,"low":444,"close":456,"volume":104},{"time":"Day 2","open":456,"high":468,"low":453,"close":462,"volume":100},{"time":"Day 3","open":462,"high":477,"low":450,"close":462,"volume":112}]'::jsonb, '[]'::jsonb, ARRAY['상승세 동력 상실로 인한 추세의 하방 반전', '매수/매도 세력 균형에 따른 도지(Doji) 횡보', '매도세 지배에 따른 즉각적인 숏 포지션 진입', '하락 세력 이탈로 인한 즉각적인 상승 랠리']::text[], 1, '시가와 종가가 거의 같은 십자 모양의 캔들은 ''도지(Doji)'' 캔들입니다. 이는 힘의 균형이 팽팽함을 시사하며, 기존 추세의 힘이 빠지고 잠재적인 방향성 전환(상승/하락 모두 포함)의 변곡점이 다가오고 있음을 의미합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (305, '캔들/가격행동', '02_candlestick_price_action.md', '상승 추세 고점에서 직전 양봉의 몸통을 거대 음봉이 아래로 덮어버리는 캔들 조합이 발생했습니다. 이 현상을 의미하는 용어는?', '[{"time":"Day 1","open":360,"high":375,"low":357,"close":372,"volume":92},{"time":"Day 2","open":372,"high":390,"low":369,"close":387,"volume":95},{"time":"Day 3","open":390,"high":393,"low":345,"close":348,"volume":89}]'::jsonb, '[]'::jsonb, ARRAY['하락 장악형 (Bearish Engulfing) - 고점 하락 전환 예고', '상승 장악형 (Bullish Engulfing) - 고점 돌파 랠리 예고', '하락 잉태형 (Harami) - 기존 하락세의 일시 둔화', '샛별형 (Morning Star) - 바닥권 상승 반전 예고']::text[], 0, '고점에서 직전 양봉을 음봉이 감싸 안은 형태는 ''하락 장악형(Bearish Engulfing)''입니다. 매수 세력을 매도 공급이 압도했다는 명백한 증거로, 삼성전자 주가 추세가 하락으로 반전할 리스크가 큽니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (306, '시장구조/SR', '03_market_structure.md', '삼성전자 주가가 장기 저항선인 450달러를 거래량 실린 강한 캔들로 돌파한 뒤, 다시 450달러 부근으로 내려와 버티고 있습니다. 가장 안전한 진입 방식은?', '[{"time":"Day 1","open":420,"high":444,"low":417,"close":435,"volume":103},{"time":"Day 2","open":435,"high":447,"low":429,"close":432,"volume":107},{"time":"Day 3","open":432,"high":468,"low":429,"close":462,"volume":93},{"time":"Day 4","open":462,"high":465,"low":447,"close":453,"volume":416},{"time":"Day 5","open":453,"high":459,"low":450,"close":456,"volume":403}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":450},{"x":4,"y":450}],"label":"돌파된 저항선 -> 지지선 전환선","color":"#3b82f6"}]'::jsonb, ARRAY['돌파 시점에 시장가로 즉시 진입하는 추격 매수', '돌파 후 저항선의 지지선 전환(Retest) 확인 시 진입', '이전 최저가 부근인 420달러 조정 시까지 대기 매수', '돌파 후 즉시 단기 조정을 예상한 역추세 숏 진입']::text[], 1, '저항선이 강하게 뚫리면 역할 전환(Role Reversal)에 의해 신규 지지선으로 바뀝니다. 돌파 시점에 뇌동매매하기보다는 돌파된 선 부근으로 삼성전자 주가가 눌려 지지(Retest)를 완성할 때 진입하는 것이 리스크 대비 기대 수익이 큽니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (307, '거래량/유동성', '05_volume_liquidity.md', '삼성전자 주가가 저항선 위로 거래량 없이 장대양봉을 뿜어 올렸으나, 다음 날 곧바로 장대음봉으로 밀어붙이며 저항선 아래로 내려왔습니다. 이 현상의 명칭은?', '[{"time":"Day 1","open":294,"high":303,"low":291,"close":300,"volume":100},{"time":"Day 2","open":300,"high":306,"low":297,"close":303,"volume":104},{"time":"Day 3","open":303,"high":330,"low":300,"close":324,"volume":22},{"time":"Day 4","open":324,"high":327,"low":285,"close":288,"volume":17}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":306},{"x":3,"y":306}],"label":"저항선","color":"#ef4444"}]'::jsonb, ARRAY['진짜 상승 돌파 (True Breakout)', '불 트랩 (Bull Trap) - 매수자 청산 유도 가짜 돌파', '베어 트랩 (Bear Trap) - 매도자 청산 유도 가짜 하방', '골든 크로스 (Golden Cross) - 이평선 돌파']::text[], 1, '저항선을 일시적으로 뚫었다가 대량 매도세와 함께 직후 캔들에서 하방으로 원상복귀하는 현상을 ''불 트랩(Bull Trap/가짜 돌파)''이라고 합니다. 돌파 후 리테스트를 기다리지 않고 급히 추격 매수했던 투자자들이 고점에 물리는 대표적 함정입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (308, '시장구조/SR', '01_chart_market_basics.md', '아래 차트에서 3번 연속 강하게 반등하며 가격 하락을 저지해 준 주요 가격대는 무엇을 의미하나요?', '[{"time":"Day 1","open":300,"high":306,"low":270,"close":273,"volume":96},{"time":"Day 2","open":273,"high":294,"low":270,"close":291,"volume":97},{"time":"Day 3","open":291,"high":315,"low":288,"close":312,"volume":100},{"time":"Day 4","open":312,"high":318,"low":273,"close":276,"volume":122},{"time":"Day 5","open":276,"high":300,"low":270,"close":297,"volume":133}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":270},{"x":4,"y":270}],"label":"270달러선","color":"#10b981"}]'::jsonb, ARRAY['강력한 저항선 (Resistance Line) - 매도 매물대', '강력한 지지선 (Support Line) - 매수 매물대', '골든크로스 수렴선 - 이평선 밀집대', '이격도 붕괴선 - 가격 과열 분기점']::text[], 1, '특정 가격(270달러)에 접근할 때마다 대기 중이던 저가 매수세가 유입되어 삼성전자 주가의 추가 하락을 방어해 준 이 라인은 ''강력한 지지선(Support Line)''입니다. 이탈하기 전까지는 손절 라인을 바로 밑에 두고 진입하기에 가장 손익비 좋은 구간입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (309, '거래량/유동성', '05_volume_liquidity.md', '지지선 아래로 삼성전자 주가가 이탈하여 공매도가 폭증했으나, 이내 거래량이 급증하며 양봉으로 지지선을 회복한 뒤 반등을 시작했습니다. 이 현상의 명칭은?', '[{"time":"Day 1","open":360,"high":366,"low":354,"close":357,"volume":101},{"time":"Day 2","open":357,"high":360,"low":330,"close":333,"volume":88},{"time":"Day 3","open":333,"high":369,"low":330,"close":366,"volume":121}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":345},{"x":2,"y":345}],"label":"지지선","color":"#10b981"}]'::jsonb, ARRAY['불 트랩 (Bull Trap) - 가짜 상방 돌파', '베어 트랩 (Bear Trap) - 가짜 하방 이탈', '리테스트 실패 - 지지선 붕괴', '추세 추종 돌파 - 하방 랠리 가속']::text[], 1, '지지선을 아래로 뚫고 내려가 하락세가 지속될 것처럼 유도한 뒤, 매물을 털어내고 강력하게 다시 반등해 올리는 현상을 ''베어 트랩(Bear Trap)''이라고 합니다. 하락 돌파로 생각하고 공매도를 치거나 손절했던 사람들의 손실을 강제하며 가격이 급등하게 만듭니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (310, '시장구조/SR', '04_patterns_breakout.md', '저항선을 뚫어내기 직전 돌파 전조 현상 중 하나인 ''지지점 상승''의 특징을 골라보세요.', '[{"time":"Day 1","open":300,"high":315,"low":270,"close":306,"volume":81},{"time":"Day 2","open":306,"high":315,"low":279,"close":309,"volume":105},{"time":"Day 3","open":309,"high":315,"low":288,"close":312,"volume":95}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":315},{"x":2,"y":315}],"label":"저항선 (105)","color":"#ef4444"}]'::jsonb, ARRAY['저항선 부근에서 고점들이 점점 급락하며 붕괴하는 현상', '저항선 부근에서 저점들을 높여가며 밀어 올리는 수렴 현상', '거래량이 완전히 소멸하여 긴 횡보 상태를 보이는 현상', '지속적인 매도세로 인해 갑작스럽게 급락하는 현상']::text[], 1, '저항을 뚫지 못하고 밀려 내려올 때, 이전 저점보다 높은 지점에서 저점을 계속 잡아 올려주는 것은 매도 압력보다 매수 압력이 점점 올라오고 있음을 의미합니다. 수렴 끝에 돌파가 나타날 신뢰도가 매우 높습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (311, '추세/레짐', '03_market_structure.md', '저점들을 연결한 우상향 상승 추세선 아래로 캔들의 종가(마감가격)가 이탈했습니다. 기술적 분석 관점의 올바른 해석은 무엇입니까?', '[{"time":"W-5","open":300,"high":315,"low":300,"close":309,"volume":112},{"time":"W-4","open":309,"high":330,"low":306,"close":324,"volume":93},{"time":"W-3","open":324,"high":327,"low":315,"close":318,"volume":99},{"time":"W-2","open":318,"high":345,"low":321,"close":339,"volume":97},{"time":"Today","open":339,"high":342,"low":309,"close":312,"volume":134}]'::jsonb, '[{"type":"line","points":[{"x":0,"y":300},{"x":2,"y":315},{"x":4,"y":330}],"label":"상승 추세선","color":"#10b981"}]'::jsonb, ARRAY['추세선 이탈은 영향이 없으므로 비중 유지', '상승 추세 붕괴로 하락 반전 대비 비중 축소', '일시적인 속임수이므로 추가 불타기 진입', '채널 상단 도달에 따른 즉각적인 매수 대응']::text[], 1, '신뢰받던 우상향 상승 추세선 하방으로 캔들의 종가가 이탈 마감하는 것은 매수 중심의 시장 주도권이 붕괴했음을 뜻합니다. 지지를 잃은 하락 가속화 리스크에 대비해야 합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (312, '추세/레짐', '07_multitimeframe_regime.md', '아래 차트에서 고점들과 저점들이 일정한 평행 통로를 그리며 하락하고 있습니다. 채널 하단에 도달했을 때 단기 반등을 목표로 하는 매매의 명칭과 관점은?', '[{"time":"Day 1","open":450,"high":456,"low":405,"close":420,"volume":94},{"time":"Day 2","open":420,"high":441,"low":417,"close":435,"volume":93},{"time":"Day 3","open":435,"high":438,"low":384,"close":390,"volume":115},{"time":"Day 4","open":390,"high":414,"low":387,"close":408,"volume":102},{"time":"Day 5","open":408,"high":411,"low":354,"close":360,"volume":134}]'::jsonb, '[{"type":"channel","points":[{"x":0,"y":450},{"x":4,"y":405},{"x":0,"y":405},{"x":4,"y":360}],"label":"하향 평행 채널","color":"#f59e0b"}]'::jsonb, ARRAY['추세 추종 매매 - 대세 상승이므로 장기 보유', '채널 하단 반등 매매 - 단기 역추세 매수 대응', '양방향 물타기 매매 - 평단가를 낮춰 탈출 대기', '돌파 매매 - 채널 하방 붕괴 확정 시 매수 대응']::text[], 1, '가격이 평행한 하락 터널 내에서 움직이는 ''하향 평행 채널(Descending Channel)''입니다. 채널 하단 라인 터치 시에는 기술적 단기 반등이 자주 출현하므로, 손절선을 짧게 잡고 반등 타점을 노리는 역추세(Counter-trend) 트레이딩이 가능합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (313, '추세/레짐', '03_market_structure.md', '우상향 상승 평행 채널의 상단 저항선 부근까지 삼성전자 주가가 도달했습니다. 합리적인 추세 채널 트레이더의 대응은?', '[{"time":"Day 1","open":300,"high":306,"low":297,"close":303,"volume":98},{"time":"Day 2","open":303,"high":324,"low":303,"close":321,"volume":120},{"time":"Day 3","open":321,"high":327,"low":312,"close":315,"volume":107},{"time":"Day 4","open":315,"high":345,"low":315,"close":342,"volume":122},{"time":"Day 5","open":342,"high":348,"low":336,"close":339,"volume":105}]'::jsonb, '[{"type":"channel","points":[{"x":0,"y":306},{"x":4,"y":345},{"x":0,"y":297},{"x":4,"y":336}],"label":"상승 평행 채널","color":"#10b981"}]'::jsonb, ARRAY['채널 상방 돌파를 예상한 고배율 레버리지 매수', '채널 상단 저항에 따른 분할 익절 및 대기', '채널 중간 조정 시 지정을 통한 시장가 추격', '채널 붕괴 신호에 따른 전량 기계적 손절']::text[], 1, '상승 채널이라고 해도 상단 저항선에 닿으면 다시 채널 하단이나 중심선까지 조정을 받을 가능성이 매우 큽니다. 따라서 고점 영역에서의 추격매수를 금지하고, 기존 포지션을 분할 익절하는 기회로 삼아야 합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (314, '추세/레짐', '01_chart_market_basics.md', '고점들을 잇는 우하향 하락 추세선을 삼성전자 주가가 대량의 거래량을 동반하며 장대양봉 종가로 상향 돌파(Breakout)했습니다. 의미하는 시그널은?', '[{"time":"Day 1","open":390,"high":396,"low":375,"close":381,"volume":90},{"time":"Day 2","open":381,"high":384,"low":360,"close":366,"volume":95},{"time":"Day 3","open":366,"high":369,"low":345,"close":351,"volume":124},{"time":"Day 4","open":351,"high":384,"low":348,"close":381,"volume":110}]'::jsonb, '[{"type":"line","points":[{"x":0,"y":393},{"x":2,"y":366},{"x":3,"y":354}],"label":"하락 추세선","color":"#ef4444"}]'::jsonb, ARRAY['하락 추세 지속에 따른 숏 포지션 추가 매수', '하락 추세 돌파 및 상승 전환 가능성에 따른 매수', '속임수 돌파를 예상한 즉시 반대 숏 포지션 진입', '추세와 무관하게 횡보 흐름으로 판단해 관망']::text[], 1, '중요한 하락 추세선을 삼성전자 주가 몸통이 확실하게 뚫고 마감하는 것은 기존 하락 관성의 지배력이 종료되고 상승 추세로 돌아설 수 있는 가장 대표적인 추세 전환(Reversal) 확인 시그널입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (315, '추세/레짐', '03_market_structure.md', '추세선 작도 시 신뢰도를 판단하는 가장 중요한 규칙은 무엇인가요?', '[{"time":"Day 1","open":300,"high":303,"low":300,"close":303,"volume":83},{"time":"Day 2","open":303,"high":315,"low":306,"close":312,"volume":112}]'::jsonb, '[]'::jsonb, ARRAY['차트상 선이 정배열로 정돈되어 그려질 때', '최소 3개 이상의 뚜렷한 저점/고점 터치 확인 시', '가파른 각도로 90도에 가깝게 작도될 때', '보조지표와 결합하여 수평으로 그려질 때']::text[], 1, '두 점만으로도 선을 그릴 수 있지만, 3번째 터치(3rd Touch)에서 정확한 지지나 저항을 보이고 반등해 주는 순간부터 시장 참여자들이 공식 인지하는 신뢰도 높은 추세선이 됩니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (316, '패턴/돌파', '04_patterns_breakout.md', '머리와 양쪽 어깨 형태를 그리며 넥라인 지지선(288달러)을 위태롭게 지탱하다가 하방으로 강한 캔들이 이탈했습니다. 숏(매도) 포지션 진입 시점은?', '[{"time":"Day 1","open":300,"high":345,"low":294,"close":330,"volume":117},{"time":"Day 2","open":330,"high":390,"low":285,"close":315,"volume":97},{"time":"Day 3","open":315,"high":342,"low":288,"close":330,"volume":127},{"time":"Day 4","open":330,"high":333,"low":279,"close":282,"volume":125}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":288},{"x":3,"y":288}],"label":"넥라인 지지선","color":"#ef4444"}]'::jsonb, ARRAY['머리 꼭대기(390달러) 부근에서 예측 숏 진입', '오른쪽 어깨가 올라가고 있을 때 돌파 전 선진입', '저점들을 연결한 넥라인의 하방 돌파 완료 시', '패턴 완성과 무관하게 오른쪽 어깨 끝에서 대기']::text[], 2, '헤드앤숄더(Head & Shoulders) 패턴은 오른쪽 어깨를 그린 후, 저점 지지선인 ''넥라인(Neckline)''을 거래량을 실어 하방 돌파해야 최종 완성이 선언됩니다. 그전에 진입하면 넥라인 반등 시 극심한 손실을 입습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (317, '패턴/돌파', '04_patterns_breakout.md', '하락 추세 끝에서 삼성전자 주가가 비슷한 깊이의 바닥을 두 번(이중바닥) 형성한 뒤, 중간 고점 저항선(넥라인)을 돌파했습니다. 향후 예상 방향성과 매수 타점은?', '[{"time":"Day 1","open":300,"high":300,"low":240,"close":255,"volume":114},{"time":"Day 2","open":255,"high":285,"low":252,"close":282,"volume":92},{"time":"Day 3","open":282,"high":285,"low":237,"close":246,"volume":116},{"time":"Day 4","open":246,"high":297,"low":243,"close":294,"volume":106}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":285},{"x":3,"y":285}],"label":"넥라인 (95)","color":"#3b82f6"}]'::jsonb, ARRAY['추가 폭락 가능성에 따른 전량 손절 대응', 'W 패턴 이중 바닥 완성 및 넥라인 돌파 시 매수', '박스권 횡보 판단에 따른 무대응 및 관망', '이중 바닥의 하방 이탈을 예상한 숏 포지션 진입']::text[], 1, 'W자 모양의 ''이중 바닥형(Double Bottom)'' 패턴입니다. 삼성전자 주가가 하락을 멈추고 바닥을 두 차례 단단히 지지해 준 뒤 중간 봉우리(넥라인 285달러)를 돌파해 마감하면 추세가 상승으로 강하게 전환될 가능성이 매우 높습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (318, '패턴/돌파', '04_patterns_breakout.md', '급격한 기둥식 삼성전자 주가 폭등(깃대) 후, 완만한 하향 평행 채널(깃발) 모양으로 횡보/수렴하다가 채널 상단을 강하게 돌파했습니다. 이 패턴과 예상 목표가는?', '[{"time":"Day 1","open":150,"high":240,"low":147,"close":234,"volume":102},{"time":"Day 2","open":234,"high":237,"low":216,"close":222,"volume":86},{"time":"Day 3","open":222,"high":228,"low":210,"close":213,"volume":103},{"time":"Day 4","open":213,"high":255,"low":210,"close":249,"volume":101}]'::jsonb, '[]'::jsonb, ARRAY['이중 천정형 패턴 - 고점 도달 시 숏 진입', '불 플래그 패턴 - 깃발 돌파 시 추가 상승 기대', '헤드앤숄더 패턴 - 넥라인 하방 돌파 타겟', '대칭 삼각수렴 패턴 - 변동성 축소 후 돌파 대기']::text[], 1, '대표적 강세 지속 패턴인 ''불 플래그(Bull Flag)''입니다. 급격한 상승(깃대) 뒤 숨 고르기 채널(깃발)을 상방 돌파하면, 이전 상승 파동의 크기(깃대 높이)만큼 추가로 수직 랠리를 시작하는 관성이 있습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (319, '패턴/돌파', '04_patterns_breakout.md', '상승 추세의 천정권에서 삼성전자 주가가 동일한 가격 저항을 두 번 확인하며 M자 모양을 만든 뒤, 두 고점 사이의 저점 지지선인 넥라인(360달러)을 이탈했습니다. 올바른 해석은?', '[{"time":"Day 1","open":300,"high":420,"low":297,"close":405,"volume":100},{"time":"Day 2","open":405,"high":408,"low":360,"close":366,"volume":84},{"time":"Day 3","open":366,"high":420,"low":363,"close":414,"volume":102},{"time":"Day 4","open":414,"high":417,"low":345,"close":348,"volume":94}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":360},{"x":3,"y":360}],"label":"넥라인 (120)","color":"#ef4444"}]'::jsonb, ARRAY['상승 추세의 지속 연장에 따른 추가 매수', '이중 천정형(M 패턴) 완성에 따른 하락 반전 대비', '단기 조정에 따른 일시적 횡보 박스권 진입', '방향성 없는 일상적인 잔파동으로 판단해 홀딩']::text[], 1, '고점에서 지지받지 못하고 형성된 M자형 ''이중 천정형(Double Top)'' 패턴입니다. 두 차례 강력한 저항벽(420달러)을 넘지 못하고 넥라인(360달러)마저 붕괴했으므로 하방 추세가 가속화된다는 신호입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (320, '패턴/돌파', '04_patterns_breakout.md', '고점 저항선은 수평(평평함)을 유지하고 있으나, 저점 지지선은 점점 우상향하며 좁게 수렴하는 차트 형태의 명칭과 일반적인 돌파 방향은?', '[{"time":"Day 1","open":240,"high":300,"low":240,"close":285,"volume":101},{"time":"Day 2","open":285,"high":300,"low":258,"close":294,"volume":109},{"time":"Day 3","open":294,"high":300,"low":276,"close":297,"volume":95}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":300},{"x":2,"y":300}],"label":"수평 저항선","color":"#ef4444"},{"type":"line","points":[{"x":0,"y":240},{"x":1,"y":258},{"x":2,"y":276}],"label":"상승 지지선","color":"#10b981"}]'::jsonb, ARRAY['디센딩 트라이앵글 - 일반적으로 하방 돌파 기대', '어센딩 트라이앵글 - 매수 압력 우위로 상방 돌파 기대', '헤드앤숄더 패턴 - 넥라인 하방 돌파 기대', '상향 평행 채널 - 상하단 터치식 채널 매매 기대']::text[], 1, '고점 저항은 평평하고 저점은 계속 높아지는 삼각수렴을 ''어센딩 트라이앵글(Ascending Triangle)''이라고 합니다. 위로 갈수록 저점이 계속 올라가는 현상은 매수세가 가격을 위로 계속 압박하고 있음을 증명하며, 대개 저항선(300달러)을 상향 뚫고 오르는 확률이 높습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (321, '지표/컨플루언스', '06_technical_indicators.md', '삼성전자 주가는 매일 하락하여 신저가를 갱신하고 있으나, RSI 보조지표의 저점은 점점 높아지는 현상을 발견했습니다. 올바른 용어와 매매 대응법은?', '[{"time":"D-4","open":330,"high":336,"low":294,"close":300,"volume":110},{"time":"D-3","open":300,"high":312,"low":288,"close":294,"volume":116},{"time":"D-2","open":294,"high":303,"low":276,"close":282,"volume":123},{"time":"D-1","open":282,"high":291,"low":279,"close":288,"volume":112},{"time":"Today","open":288,"high":297,"low":285,"close":294,"volume":134}]'::jsonb, '[]'::jsonb, ARRAY['하락 다이버전스 - 가격 상승 둔화에 따른 공매도', '상승 다이버전스 - 하락 둔화 및 반등 신호로 매수', '데드 크로스 - 이평선 하방 교차에 따른 관망', '과매수 이탈 시그널 - 단기 반등에 따른 매수']::text[], 1, '삼성전자 주가의 가격 저점은 낮아지나 보조지표(RSI)의 운동 저점이 높아지는 현상을 ''상승 다이버전스(Bullish Divergence)''라고 합니다. 이는 하방 에너지의 실질적 소멸과 상승 압력의 내부 응축을 의미하는 기술적 분석에서 가장 신뢰도 높은 추세 전환 시그널입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (322, '지표/컨플루언스', '06_technical_indicators.md', '삼성전자 주가는 급격히 치솟으며 최고가 갱신 랠리를 이어가고 있으나, RSI 지표의 고점은 계속 낮아지고 있습니다. 이 현상을 지칭하는 명칭과 대처법은?', '[{"time":"Day 1","open":300,"high":360,"low":297,"close":354,"volume":110},{"time":"Day 2","open":354,"high":366,"low":345,"close":360,"volume":101},{"time":"Day 3","open":360,"high":405,"low":357,"close":399,"volume":112}]'::jsonb, '[]'::jsonb, ARRAY['하락 다이버전스 - 매수 둔화 및 하락 우려로 익절', '상승 다이버전스 - 추가 급등 기대로 신규 매수', '골든 크로스 - 추세 강화에 따른 홀딩', '볼린저 밴드 스퀴즈 - 변동성 수축 후 돌파']::text[], 0, '삼성전자 주가는 계속 고점을 높이고 있으나 보조지표의 고점은 꺾여 낮아지는 현상을 ''하락 다이버전스(Bearish Divergence)''라고 합니다. 이는 매수세의 힘이 표면적인 가격 상승에 비해 실질적으로 빠르게 축소되고 있음을 경고하며, 조만간 큰 급락이 발생할 확률이 높습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (323, '지표/컨플루언스', '06_technical_indicators.md', '이동평균선(EMA) 20일선(단기)이 50일선(중기)을 아래에서 위로 강하게 뚫고 솟구쳐 올랐습니다. 이 교차 현상의 정식 명칭은?', '[{"time":"Day 1","open":300,"high":306,"low":294,"close":297,"volume":105},{"time":"Day 2","open":297,"high":312,"low":297,"close":309,"volume":87},{"time":"Day 3","open":309,"high":330,"low":309,"close":327,"volume":88}]'::jsonb, '[]'::jsonb, ARRAY['데드 크로스 - 단기 이평의 하방 교차로 매도 신호', '골든 크로스 - 단기 이평의 상방 교차로 매수 신호', '볼린저 스퀴즈 - 변동성 수축 및 돌파 신호', '다이버전스 수렴 - 지표와 가격의 동반 횡보']::text[], 1, '단기 이평선이 장기 이평선을 위로 치고 올라가는 현상을 ''골든 크로스(Golden Cross)''라고 합니다. 이는 최근 매수 평단가가 장기 평균가보다 확연히 높아졌음을 시사하며, 상승 추세가 본 궤도에 올랐음을 입증해 줍니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (324, '지표/컨플루언스', '07_multitimeframe_regime.md', '매우 강력한 원웨이 폭락장 속에서 RSI 지표가 20(과매도 영역) 이하로 깊이 내려왔습니다. 이를 보고 ''과매도 반등''을 노리며 기계적 시장가 풀매수를 때렸을 때 나타나는 가장 빈번한 오류는?', '[{"time":"Day 1","open":300,"high":303,"low":264,"close":267,"volume":93},{"time":"Day 2","open":267,"high":270,"low":225,"close":228,"volume":33},{"time":"Day 3","open":228,"high":231,"low":186,"close":189,"volume":34}]'::jsonb, '[]'::jsonb, ARRAY['하락 추세 즉시 종료 및 V자 상승 반등 성공', '강력한 하락장에서의 지표 과매도 고착화 리스크', '거래량 급감으로 인한 호가 정지 및 상장 폐지', '삼성전자 주가의 즉각적인 박스권 횡보 및 변동성 축소']::text[], 1, 'RSI 30 이하 과매도 영역은 반등 신호이기도 하지만, 추세가 지나치게 강력한 하락장일 때는 지표만 과매도 구역에 쳐박힌 채 가격은 계속 급락하는 ''과매도 고착화(Oversold Embedded)'' 상태가 이어집니다. 다이버전스나 캔들 반전형 확인 없이 수치만 보고 들어가는 매수는 깡통으로 가는 지름길입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (325, '지표/컨플루언스', '06_technical_indicators.md', '삼성전자 주가의 변동성이 극도로 축소되며 볼린저 밴드의 폭이 매우 좁아지는 ''스퀴즈(Squeeze)'' 현상이 나타났습니다. 이후 기대되는 시장 변동성의 원리는 무엇인가요?', '[{"time":"Day 1","open":300,"high":303,"low":297,"close":300,"volume":100},{"time":"Day 2","open":300,"high":300,"low":297,"close":297,"volume":103},{"time":"Day 3","open":297,"high":300,"low":297,"close":300,"volume":127}]'::jsonb, '[]'::jsonb, ARRAY['변동성 사멸로 인한 장기 횡보 및 거래 정지', '밴드 스퀴즈 후 변동성 팽창에 따른 추세 분출', '삼성전자 주가의 하방 붕괴로 인한 강한 하락 파동 시작', '이평선들의 수평 정렬에 따른 완전한 추세 고정']::text[], 1, '볼린저 밴드의 수축(Squeeze)은 시장의 숨 고르기 및 힘 모으기를 뜻합니다. 에너지가 최대한 압축된 후에는 밴드 상단 혹은 하단선을 이탈하며 매우 거대한 변동성 팽창(Expansion) 추세가 시작되므로, 방향성을 유심히 지켜봐야 합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (326, '리스크/심리', '09_risk_position_management.md', '총 투자 원금은 3,000만 원이며, 1회 거래 시 최대 손실 허용액을 원금의 2%(60만 원)로 제한하는 ''2% 룰''을 지키려 합니다. 진입하려는 종목의 손절 라인 폭이 -5%일 때, 최대 매수(진입) 가능 금액은 얼마인가요?', '[{"time":"Day 1","open":30000,"high":31500,"low":29400,"close":30600,"volume":85},{"time":"Day 2","open":30600,"high":30900,"low":30000,"close":30000,"volume":102}]'::jsonb, '[]'::jsonb, ARRAY['3,000만 원 (원금 전액 진입)', '600만 원 (원금의 20% 진입)', '1,200만 원 (원금의 40% 진입)', '1,500만 원 (원금의 50% 진입)']::text[], 2, '2% 룰에 기초한 포지션 사이징 공식은 `진입금액 = (총원금 * 리스크비율) / 손절비율` 입니다. 따라서 `60만 원 / 0.05 = 1,200만 원`이 됩니다. 1,200만 원어치 국내 주식을 샀을 때 가격이 -5% 떨어져 강제 손절을 맞아도 내 계좌 총액에서 손실을 보는 돈은 정확히 2%인 60만 원으로 통제됩니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (327, '리스크/심리', '09_risk_position_management.md', '어느 국내 주식에 30,000원에 매수 진입합니다. 손절 라인은 28,500원(-5%)에 배치하고, 목표가는 34,500원(+15%)에 설정했습니다. 이 트레이딩 시나리오의 손익비(Risk-to-Reward Ratio)는 얼마입니까?', '[{"time":"Today","open":30000,"high":30000,"low":30000,"close":30000}]'::jsonb, '[]'::jsonb, ARRAY['1 : 1 (동일한 기대 수익과 리스크)', '1 : 2 (기대 수익이 리스크의 2배)', '1 : 3 (기대 수익이 리스크의 3배)', '2 : 1 (기대 수익이 리스크의 0.5배)']::text[], 2, '손절 폭(1,500원) 대비 익절 폭(4,500원)의 비례를 의미하므로 `1,500 / 500 = 3`, 즉 손익비는 1:3이 됩니다. 이처럼 잃는 돈의 최소 2~3배를 벌 수 있는 손익비 높은 구간만 반복적으로 거래해야 장기적으로 계좌가 생존합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (328, '리스크/심리', '09_risk_position_management.md', '손익비를 엄격히 통제하여 항상 기대 손실의 2배를 버는 매매(손익비 1:2)만 고집합니다. 이 경우 내 계좌 잔고가 손실 없이 제자리걸음(본전)을 유지하기 위해 필요한 수학적인 최소 승률(Win Rate)은 얼마인가요?', '[{"time":"Today","open":300,"high":300,"low":300,"close":300}]'::jsonb, '[]'::jsonb, ARRAY['50.0% (최소 절반 이상 성공)', '33.3% (3번 중 1번 성공으로 본전)', '25.0% (4번 중 1번 성공으로 본전)', '66.6% (3번 중 2번 성공으로 본전)']::text[], 1, '손익비가 1:2일 경우, 1번 이기면 +2를 벌고 2번 지면 -2를 잃으므로 3번 매매 중 1번만 이겨도 누적 수익은 0이 됩니다. 즉 손익비를 1:2 이상으로 유지하면 수학적으로 승률이 겨우 33.3%만 나와도 절대 파산하지 않고 계좌가 우상향할 발판이 마련됩니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (329, '셋업/실행', '08_setup_entry_exit.md', '30,000원에 산 국내 주식이 45,000원까지 올랐습니다. 이익을 보존하면서 상승세를 끝까지 타기 위해, 최고점 대비 10% 하방 이탈 시 즉시 자동 익절되는 ''추적 손절매(Trailing Stop)''를 적용했습니다. 최고점 45,000원 달성 후 삼성전자 주가가 조정받을 때 실제로 청산(익절)되는 가격은 얼마인가요?', '[{"time":"Day 1","open":30000,"high":36000,"low":29700,"close":35700,"volume":106},{"time":"Day 2","open":35700,"high":45000,"low":35400,"close":44400,"volume":111}]'::jsonb, '[]'::jsonb, ARRAY['30,000원 (본전 수준 청산)', '40,500원 (최고점 대비 10% 하방 청산)', '42,000원 (최고점 대비 6.6% 하방 청산)', '36,000원 (최고점 대비 20% 하방 청산)']::text[], 1, '추적 손절매(Trailing Stop)는 가격 상승에 따라 청산 가격을 자동으로 올려주는 주문입니다. 최고점 45,000원을 기록했으므로 청산 트리거 라인은 최고점에서 10% 차감된 `15,000 * 0.9 = 40,500원`으로 확정 셋업되며, 삼성전자 주가가 40,500원을 건드리는 순간 자동 이익실현됩니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (330, '리스크/심리', '09_risk_position_management.md', '레버리지 10배를 적용하여 삼성전자 롱(매수) 포지션을 구축했습니다. 만약 삼성전자 가격이 매수가 대비 몇 % 역방향으로 등락하면 내 투자 원금이 100% 강제 청산(증거금 완전 소멸)당할까요?', '[{"time":"Today","open":150000,"high":150300,"low":149700,"close":150000}]'::jsonb, '[]'::jsonb, ARRAY['5.0% 하락 시', '10.0% 하락 시', '20.0% 하락 시', '100.0% 하락 시']::text[], 1, '레버리지 비율과 청산 거리 비율은 역수 관계입니다. `100% / 레버리지 배수` 공식에 따라, 10배 레버리지는 삼성전자 주가가 내 베팅의 반대 방향으로 단 10%만 움직여도 투자 원금이 전부 증발하고 포지션이 강제 종료(Liquidation)됩니다. 고배율 레버리지가 파산의 지름길인 이유입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (331, '캔들/가격행동', '02_candlestick_price_action.md', '상승 추세 고점 영역(450달러선)에서 몸통이 매우 작고 아래꼬리가 긴 행잉맨(Hanging Man) 캔들이 출현한 이후, 다음 날 시가가 전일 종가보다 큰 갭을 그리며 낮게 하락 출발(435달러)했습니다. 포지션을 보유한 스윙 트레이더로서 가장 적절한 위기 대응 행동은 무엇입니까?', '[{"time":"Day 1","open":360,"high":375,"low":357,"close":372,"volume":85},{"time":"Day 2","open":372,"high":405,"low":369,"close":402,"volume":119},{"time":"Day 3","open":402,"high":444,"low":399,"close":438,"volume":108},{"time":"Day 4","open":438,"high":453,"low":420,"close":441,"volume":124},{"time":"Day 5","open":423,"high":429,"low":405,"close":408,"volume":100}]'::jsonb, '[]'::jsonb, ARRAY['상승 랠리를 기대로 보유 비중 확대 및 추격 매수', '일시적 속임수(휩소) 판단으로 추가 레버리지 매수', '행잉맨 출현 후 갭하락에 따른 전량 또는 일부 정리', '조치 없이 전고점 돌파 시까지 무기한 관망 및 홀딩']::text[], 2, '고가권에서 나타난 행잉맨(Hanging Man)은 잠재적 하락 전환 신호이며, 특히 다음날 갭하락 음봉으로 직전 행잉맨의 저가를 깨고 내려가는 움직임은 강력한 하락 컨펌 시그널입니다. 따라서 이 시점에서는 즉시 비중을 전량 정리하거나 최소 절반 이상 매도하여 리스크를 통제하는 것이 정석입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (332, '캔들/가격행동', '01_chart_market_basics.md', '지속적인 하락 추세 도중 바닥권(240달러선)에서 시가와 종가가 일치하고 긴 아래꼬리를 단 십자 형태의 도지(Doji) 캔들이 생성되었습니다. 다음 날 대량의 거래량과 함께 장대양봉이 솟구치며 261달러로 마감하는 샛별형(Morning Star) 조합이 확정되었습니다. 이때 가장 합리적인 매수 진입 지점과 손절가 기준은 무엇입니까?', '[{"time":"Day 1","open":300,"high":303,"low":279,"close":282,"volume":96},{"time":"Day 2","open":282,"high":285,"low":264,"close":267,"volume":109},{"time":"Day 3","open":267,"high":270,"low":240,"close":243,"volume":104},{"time":"Day 4","open":240,"high":246,"low":225,"close":240,"volume":123},{"time":"Day 5","open":240,"high":264,"low":237,"close":261,"volume":126}]'::jsonb, '[]'::jsonb, ARRAY['손절 없이 100% 비중으로 시장가 매수', '샛별형 완성에 따라 분할 매수 후 최저점 손절 셋업', '바닥 도달 기대로 주문 없이 무작정 대기', '상승 꼭대기에서 숏 진입 후 손절 없이 방치']::text[], 1, '하락 추세 끝에 도지와 장대양봉이 결합된 샛별형(Morning Star)은 매우 신뢰도 높은 바닥 상승 전환 신호입니다. 이 패턴을 보고 진입할 때는 반등 상승세에 분할 매수로 동참하되, 바닥을 잡아준 도지 캔들의 최저점(225달러) 아래를 최종 손절 라인으로 잡는 것이 수학적으로 가장 리스크 대비 보상 비율(손익비)이 훌륭한 전략입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (333, '거래량/유동성', '02_candlestick_price_action.md', '삼성전자 주가가 강력한 횡보 박스권 고점(600달러 저항선)에 세 번째 터치하는 와중에, 윗꼬리가 길고 몸통이 매우 얇은 유성형(Shooting Star) 캔들이 이틀 연속 발생했습니다. 거래량 역시 저항선 부근에서 매수세가 더 올라가지 못하고 매도 압력이 실려 나타났습니다. 롱(매수) 포지션을 들고 있는 당신의 합리적인 의사결정은?', '[{"time":"Day 1","open":525,"high":555,"low":522,"close":546,"volume":106},{"time":"Day 2","open":546,"high":585,"low":540,"close":579,"volume":121},{"time":"Day 3","open":579,"high":606,"low":570,"close":573,"volume":97},{"time":"Day 4","open":573,"high":603,"low":564,"close":567,"volume":102}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":600}],"label":"박스권 상단 저항선 (200)","color":"#ef4444"}]'::jsonb, ARRAY['신고가 갱신을 예상한 전재산 추가 불타기', '저항 돌파 실패 신호 확인 후 분할 익절 및 관망', '손익 평단가 부근이므로 추가 손절 없이 방치', '거래를 종료하고 다른 신규 급등주를 시장가 추격']::text[], 1, '박스권 상단 저항선(600달러)에 부딪히며 나타난 유성형(Shooting Star) 연속 출현은 저항 돌파 실패와 차익 실현 세력의 강력한 등장을 경고하는 캔들 신호입니다. 돌파를 확신하기보다는 리스크 관리 관점에서 물량을 축소(50% 분할 익절)하거나 전량 매도하여 이익을 확정 짓는 것이 현명합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (334, '캔들/가격행동', '02_candlestick_price_action.md', '극심한 하락 추세 중 300달러선 아래로 떨어지던 삼성전자 주가가 전일 장대음봉을 형성했습니다. 그러나 당일 시가는 갭하락하여 더 낮게 시작했으나, 장중에 강한 매수세가 들어오며 전일 음봉 몸통의 정확히 70% 라인(279달러선) 위로 덮어버리는 관통형(Piercing Line) 상승 캔들로 마감했습니다. 종가 매수(롱) 진입 시 원칙 대응은?', '[{"time":"Day 1","open":330,"high":333,"low":312,"close":315,"volume":114},{"time":"Day 2","open":315,"high":318,"low":291,"close":294,"volume":99},{"time":"Day 3","open":276,"high":303,"low":273,"close":300,"volume":93}]'::jsonb, '[]'::jsonb, ARRAY['상승 모멘텀 미달로 매수 보류 및 하방 숏 포지션 진입', '관통형 확인 후 분할 매수 및 당일 최저점 손절 설정', '손절 라인 설정 없이 100% 비중 시장가 매수 집행', '조정을 대기하며 예약 주문 없이 무작정 관망 유지']::text[], 1, '전일 음봉의 50% 이상을 당일 양봉 몸통으로 관통해 올린 ''관통형(Piercing Line)''은 하락 모멘텀이 쇠퇴하고 저가 매수세가 우위를 점하기 시작했음을 뜻하는 바닥 신호입니다. 이 패턴 확인 후 진입할 시에는 손절 한도를 당일 최저점(273달러) 밑에 가깝게 설정할 수 있어 매우 유리한 리스크 대비 기대수익 매매가 성립됩니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (335, '캔들/가격행동', '05_volume_liquidity.md', '강한 급등세를 지속하던 삼성전자 주가가 최고점에서 큰 거래량을 터뜨리며 장대양봉을 만들었습니다. 그러나 다음 날, 전일 양봉 몸통의 한가운데 범위 안에서 움직이며 시가와 종가가 모두 갇혀버리는 짧은 음봉인 ''하락 잉태형(Bearish Harami)'' 캔들이 형성되었습니다. 단기 스윙 트레이더로서 당신의 포지션 리스크 관리 행동은?', '[{"time":"Day 1","open":360,"high":384,"low":357,"close":381,"volume":87},{"time":"Day 2","open":381,"high":414,"low":378,"close":408,"volume":108},{"time":"Day 3","open":399,"high":402,"low":390,"close":393,"volume":91}]'::jsonb, '[]'::jsonb, ARRAY['상승 둔화 조짐에 따른 보유 물량 50% 분할 익절', '추세 일시 조정으로 간주하여 비중 확대 추가 매수', '추세 종결 판단에 따른 고배율 숏 포지션 즉시 진입', '이익 실현 없이 전량 장기 보유 전략 유지']::text[], 0, '하락 잉태형(Bearish Harami)은 이전의 강한 상승 추세 동력이 감속하기 시작했으며, 매도 압력이 힘을 기르고 있음을 암시하는 변곡 캔들입니다. 따라서 단기 스윙 트레이더는 물량의 일부(50%)를 분할 익절하여 리스크를 낮추고, 다음 캔들에서 이전 양봉 저점을 깨뜨리는 하락 하방 이탈이 추가되는지 지켜보는 것이 정석입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (336, '시장구조/SR', '03_market_structure.md', '오랫동안 지켜지던 핵심 지지선인 300달러 부근에서 매수 진입을 완료했습니다. 그러나 가격이 대량의 거래량을 동반하며 장대음봉으로 지지선을 하방으로 강하게 뚫어냈고, 종가가 지지선 대비 1.5% 아래인 98.15달러로 결정되었습니다. 이 상황에서 원칙을 지키는 올바른 위기 대응 행동은?', '[{"time":"Day 1","open":315,"high":324,"low":306,"close":309,"volume":103},{"time":"Day 2","open":309,"high":312,"low":297,"close":300,"volume":113},{"time":"Day 3","open":300,"high":303,"low":294,"close":295.5,"volume":107}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":300}],"label":"중요 지지선 (100)","color":"#10b981"}]'::jsonb, ARRAY['추가 물타기를 위해 자금을 동원하여 평단가 관리', '중요 지지선 붕괴(Breakdown) 확인 후 즉시 전량 손절', '지속 하락 시 추가 평단가 관리를 위해 매수 유보', '하방 이탈 시 즉시 반대 고배율 롱 포지션 진입']::text[], 1, '거래량이 동반된 장대음봉으로 주요 지지선 아래에서 종가가 결정되는 이탈 마감은 매수 지지 세력의 패배이자 추세 붕괴(Breakdown)의 신호입니다. 이 시점에서 물타기를 하거나 존버를 하면 파산적인 하락 조정을 겪을 수 있으므로 즉시 룰에 근거한 ''전량 손절''을 집행해야 계좌를 살릴 수 있습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (337, '시장구조/SR', '03_market_structure.md', '450달러의 중요 저항선이 강한 거래량을 실은 돌파봉으로 뚫렸습니다. 이후 삼성전자 주가가 숨 고르기 조정을 받으며 450달러 부근까지 되돌아왔고(리테스트 구간), 저항선 부근에서 거래량이 크게 감소하며 아래꼬리가 달린 도지 캔들로 안착하는 모습을 보입니다. 이때 가장 안전하고 합리적인 매매 조치는?', '[{"time":"Day 1","open":420,"high":438,"low":417,"close":432,"volume":119},{"time":"Day 2","open":432,"high":471,"low":429,"close":465,"volume":84},{"time":"Day 3","open":465,"high":468,"low":447,"close":450,"volume":115}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":450}],"label":"돌파된 저항선 -> 지지선 전환선 (150)","color":"#3b82f6"}]'::jsonb, ARRAY['가짜 돌파(휩소) 판단에 따른 고배율 숏 진입', '돌파 후 리테스트 성공 확인 시 지지선 눌림목 매수', '추격 매수 기회 상실로 판단하고 거래 포기', '480달러 추가 돌파를 타겟으로 시장가 추격 매수']::text[], 1, '강하게 돌파된 저항선은 룰 체인지에 의해 지지선으로 변합니다(역할 전환). 돌파 당시 추격 매수하기보다, 돌파된 선(450달러)으로 삼성전자 주가가 되돌아오는 리테스트(Retest) 시점에 저조한 거래량과 지지 캔들을 확인하고 손절선을 바로 밑에 설정하여 눌림목 진입하는 것이 리스크가 가장 적은 프로 트레이더의 정석입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (338, '시장구조/SR', '03_market_structure.md', '가격이 240달러 지지선 근처에서 반등을 시도하고 있으나, 반등의 폭이 직전 고점에 턱없이 못 미치며 저점 부근으로 다시 짓눌리고 있습니다. 즉, 고점들이 계속 낮아지는 하락 우위 삼각수렴(Descending)의 형태가 지지선 바로 위에서 감지됩니다. 이 시점에서 지지선 반등을 믿고 신규 매수(롱)를 진입하는 것은 원칙에 맞습니까?', '[{"time":"Day 1","open":285,"high":294,"low":240,"close":264,"volume":110},{"time":"Day 2","open":264,"high":273,"low":240,"close":252,"volume":113},{"time":"Day 3","open":252,"high":258,"low":240,"close":243,"volume":117}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":240}],"label":"지지선 (80)","color":"#10b981"}]'::jsonb, ARRAY['삼중 바닥 지지로 판단하고 매수 비중 대폭 확대', '디센딩 수렴 확인 후 하방 이탈 위험 대비 관망', '물타기 평단가 관리를 위해 매수 보증금 추가 투입', '추세와 무관하게 숏 포지션으로 전환 후 무기한 보유']::text[], 1, '지지선 부근에서 고점이 점점 낮아지는 ''디센딩'' 형태는 매수 지원 강도가 둔화되고 매도 출하 공급이 가격을 계속 하방으로 압박하고 있음을 증명합니다. 지지 성공보다 지선 하방 붕괴 후 급락할 확률이 높으므로, 지지선이라는 명목만으로 함부로 매수 진입하지 말고 돌파/이탈 컨펌을 기다려 관망하는 것이 현명합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (339, '거래량/유동성', '05_volume_liquidity.md', '삼성전자 주가가 360달러의 장기 저항벽을 거래량이 거의 실리지 않은 얇은 양봉으로 상방으로 살짝 뚫었으나, 바로 다음 날 직전 양봉 몸통을 통째로 덮어버리는 대량 거래량의 장대음봉이 출현하며 348달러로 곤두박질쳤습니다. 매수 포지션을 추격 진입했던 당신의 올바른 조치는?', '[{"time":"Day 1","open":336,"high":354,"low":333,"close":351,"volume":86},{"time":"Day 2","open":351,"high":366,"low":348,"close":363,"volume":364},{"time":"Day 3","open":363,"high":366,"low":345,"close":348,"volume":327}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":360}],"label":"장기 저항선 (120)","color":"#ef4444"}]'::jsonb, ARRAY['불 트랩(Bull Trap) 확인 후 추가 하락 방지 즉시 손절', '저항선 부근 매수세 복귀를 기대하며 전량 홀딩', '평단가 관리 차원에서 추가 물타기 매수 집행', '상황을 판단하기 위해 시장가로 추가 분할 진입']::text[], 0, '거래량 없는 돌파 직후에 거래량 실린 강한 음봉이 기존 돌파선(360달러) 아래로 재진입하여 마감하는 현상은 전형적인 불 트랩(Bull Trap/가짜 돌파) 함정입니다. 돌파 당시 샀던 매수자들의 패닉 셀이 출현하며 하락 가속화가 나오기 쉬우므로 즉시 손절하여 물량을 털어내야 생존할 수 있습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (340, '시장구조/SR', '10_psychology_routine_review.md', '주요 지지선(750달러선)이 아래로 무너질 때 제때 손절 처리를 하지 못해 삼성전자 주가가 660달러선까지 끌려 내려갔습니다. 다행히 단기 매도 진정세로 반등이 나와 삼성전자 주가가 다시 750달러 부근까지 상승하여 회복을 눈앞에 두고 있습니다. 이때 손실을 최소화하는 현명한 시나리오 대처법은?', '[{"time":"Day 1","open":780,"high":786,"low":744,"close":747,"volume":94},{"time":"Day 2","open":747,"high":750,"low":660,"close":666,"volume":92},{"time":"Day 3","open":666,"high":705,"low":663,"close":702,"volume":100},{"time":"Day 4","open":702,"high":753,"low":699,"close":747,"volume":109}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":750}],"label":"붕괴된 지지선 -> 저항선으로 변형 (250)","color":"#ef4444"}]'::jsonb, ARRAY['역할 전환(저항선) 도달에 따른 탈출 및 현금화', 'V자 반등 성공 확신에 따른 추가 매수 비중 확대', '원금 회복 및 추가 수익 시까지 영구 홀딩 관망', '하락 추세 지속에 따른 반대 숏 포지션 스위칭']::text[], 0, '하방으로 깨진 지지선은 반등할 때 가장 뚫기 힘든 ''강력한 저항선''으로 성격이 바뀝니다. 따라서 손절 기회를 놓치고 물려있던 트레이더는 반등하여 옛 지지선(750달러)에 도달했을 때를 ''최선의 리스크 탈출 기회(탈출구)''로 삼아 전량 매도하거나 비중을 극도로 덜어내야 다가올 2차 하락 파동의 파산을 막을 수 있습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (341, '추세/레짐', '03_market_structure.md', '삼성전자 주가가 매우 가파르게 올라가던 1차 단기 상승 추세선을 강한 음봉 종가로 뚫고 내려왔습니다. 다행히 각도가 완만하고 탄탄한 장기 핵심 상승 추세선은 저 밑에 지지 영역을 유지하고 있습니다. 스윙 트레이더로서 가장 정석적인 포지션 제어 방식은 무엇인가요?', '[{"time":"Day 1","open":300,"high":306,"low":300,"close":306,"volume":110},{"time":"Day 2","open":306,"high":330,"low":306,"close":327,"volume":103},{"time":"Day 3","open":327,"high":375,"low":327,"close":372,"volume":101},{"time":"Day 4","open":372,"high":375,"low":342,"close":345,"volume":99}]'::jsonb, '[{"type":"line","points":[{"x":0,"y":300},{"x":3,"y":369}],"label":"가파른 단기 추세선 (붕괴)","color":"#ef4444"},{"type":"line","points":[{"x":0,"y":300},{"x":3,"y":330}],"label":"완만한 장기 추세선 (지탱 중)","color":"#10b981"}]'::jsonb, ARRAY['추세 붕괴 판단에 따른 전량 손절 및 영구 이탈', '가속 추세 이탈에 따른 50% 분할 익절 및 분산', '단기 지지선 붕괴를 무시한 고배율 물타기 매수', '장기 추세선까지 조정을 대비한 신규 매수 대기']::text[], 1, '가파르게 우상향하던 가속 추세선(Accelerated Trendline)이 하방 돌파되는 것은 기존 폭등 랠리의 속도가 둔화되고 완만한 본래 장기 추세선(장기 매물대)을 향해 정상적인 가격 조정을 받기 시작했음을 뜻합니다. 따라서 물량의 50%가량을 털어 수익을 실현하고 남은 물량으로 장기 추세선의 3rd Touch 지지 성공 여부를 테스트하는 것이 리스크 관리의 기본입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (342, '거래량/유동성', '05_volume_liquidity.md', '고점과 저점이 연속으로 낮아지는 명확한 하락 평행 채널 내에서 하락 압력을 받아 숏(매도) 포지션을 잡고 수익 중이었습니다. 그런데 당일 캔들이 대량의 거래량과 함께 장대양봉을 그리며 채널 상단 저항선 위로 종가 안착(상방 돌파)했습니다. 숏 포지션을 쥔 당신의 결단은?', '[{"time":"Day 1","open":300,"high":306,"low":270,"close":276,"volume":84},{"time":"Day 2","open":276,"high":282,"low":246,"close":249,"volume":88},{"time":"Day 3","open":249,"high":255,"low":225,"close":228,"volume":123},{"time":"Day 4","open":228,"high":270,"low":225,"close":267,"volume":101}]'::jsonb, '[{"type":"channel","points":[{"x":0,"y":306},{"x":3,"y":258},{"x":0,"y":270},{"x":3,"y":228}],"label":"하락 평행 채널 상한/하한","color":"#f59e0b"}]'::jsonb, ARRAY['상단 돌파 확인 즉시 숏 전량 손절 및 대피', '채널 재진입 기대로 숏 포지션 추가 물타기', '손절 없이 유지하면서 포지션 본전 도달 대기', '포지션 유지 후 증거금을 출금하여 강제 횡보']::text[], 0, '하락 평행 채널의 상단 저항선 상향 돌파(Breakout)는 기존 하락 트렌드의 사멸과 매수세 지배령 복귀를 뜻합니다. 지표와 거래량이 동반된 돌파 확인 시에는 숏 포지션을 지체 없이 기계적으로 칼손절하여 자산을 보호하는 것이 원칙입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (343, '추세/레짐', '07_multitimeframe_regime.md', '우상향하는 상승 평행 채널 안에서 순항하던 삼성전자 주가가 중심선(Mid-line)을 뚫고 하방으로 이탈 마감했습니다. 이후 중심선 부근까지 반등을 시도했으나 재차 저항을 받고 아래꼬리가 꺾여 채널 하단선을 향해 하락 조정을 재개하려 합니다. 신규 매수(롱) 포지션 진입을 계획 중인 트레이더의 대응법은?', '[{"time":"Day 1","open":300,"high":324,"low":297,"close":318,"volume":94},{"time":"Day 2","open":318,"high":336,"low":306,"close":312,"volume":120},{"time":"Day 3","open":312,"high":318,"low":294,"close":300,"volume":110}]'::jsonb, '[{"type":"channel","points":[{"x":0,"y":330},{"x":2,"y":336},{"x":0,"y":294},{"x":2,"y":300}],"label":"상승 평행 채널","color":"#10b981"}]'::jsonb, ARRAY['채널 내 유지를 기대로 지정가 즉시 매수', '중심선 저항 확인 후 채널 하단 안착 대기', '하방 휩소 판단에 따른 레버리지 추가 매수', '추세와 무관한 숏 포지션 구축 후 관망']::text[], 1, '상승 평행 채널에서 미드라인(Mid-line)은 매우 중요한 심리적 지지와 저항선입니다. 미드라인이 저항선으로 뒤바뀌어 음봉으로 흘러내리는 경우 높은 확률로 채널 하단 경계선까지 가격이 조정을 받게 되므로, 중심선 저항 확인 시점에서는 섣부른 매수 진입을 피하고 채널 하단의 명확한 반등 타점을 유도해야 합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (344, '추세/레짐', '03_market_structure.md', '저점과 저점을 이은 장기 상승 추세선 상의 3번째 터치 포인트(지지선 부근)에 캔들이 매우 조심스럽게 안착하며 아래꼬리를 형성했습니다. 손익비(Risk-to-Reward) 관점에서 가장 이상적인 매수 타점 집행 및 손절 셋업 방법은 무엇입니까?', '[{"time":"Day 1","open":240,"high":270,"low":240,"close":264,"volume":101},{"time":"Day 2","open":264,"high":297,"low":264,"close":285,"volume":107},{"time":"Day 3","open":285,"high":288,"low":270,"close":276,"volume":90}]'::jsonb, '[{"type":"line","points":[{"x":0,"y":240},{"x":1,"y":264},{"x":2,"y":270}],"label":"상승 추세선 (3rd Touch 기대선)","color":"#10b981"}]'::jsonb, ARRAY['손절 라인 없이 지정가로 1차 매수 몰빵 진입', '3rd Touch 타점 진입 및 추세선 하단 칼손절 셋업', '하방 붕괴 예상을 통한 고배율 숏 즉각 진입', '목표가 터치 시까지 무작정 대기 후 추격 매수']::text[], 1, '추세선 상의 3번째 지지 포인트(3rd Touch)는 추세 신뢰도가 형성되는 대단히 성공률 높은 정석적 눌림목 타점입니다. 진입 가격과 손절 라인(추세선 이탈가)의 거리가 매우 가깝기 때문에 기대 수익 대비 잃을 금액이 매우 적어 프로 트레이더들이 가장 선호하는 칼손절 매수 스팟입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (345, '추세/레짐', '08_setup_entry_exit.md', '삼성전자 주가가 장기 하락 추세선을 힘차게 뚫어 상방 돌파(Breakout)했습니다. 하지만 돌파선 바로 위(약 360달러)에 최근 여러 번 강한 매도 잔량이 쏟아지며 가격을 찍어 눌렀던 핵심 매물대 저항선이 떡하니 버티고 있습니다. 당신의 신규 진입 매수 순서는 어떻게 결정해야 안전할까요?', '[{"time":"Day 1","open":375,"high":378,"low":330,"close":336,"volume":86},{"time":"Day 2","open":336,"high":339,"low":294,"close":300,"volume":110},{"time":"Day 3","open":300,"high":357,"low":297,"close":354,"volume":88}]'::jsonb, '[{"type":"line","points":[{"x":0,"y":375},{"x":1,"y":336},{"x":2,"y":315}],"label":"하락 추세선 (돌파됨)","color":"#ef4444"},{"type":"horizontal-line","points":[{"x":0,"y":360}],"label":"수평 매물대 저항선 (120)","color":"#ef4444"}]'::jsonb, ARRAY['돌파 확인 즉시 종가 기준 시장가 100% 매수', '수평 저항 돌파 검증 시까지 매수 유보 및 대기', '돌파 전조 현상 기대로 레버리지 선배팅 집행', '추세선 돌파를 가짜로 간주한 숏 포지션 진입']::text[], 1, '하락 추세선의 돌파는 긍정적이나 수평 매물대 저항선이 바로 위에 있다면 이중 저항 작용에 의해 막히는 경우가 대단히 잦습니다. 추세선 상방 휩소(속임수)에 당하지 않으려면 겹저항 중 최종 관문인 수평 매물대 저항선 돌파 혹은 리테스트 지지를 확인하고 진입하는 것이 보수적이고 안전한 원칙입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (346, '패턴/돌파', '04_patterns_breakout.md', '고점 수평 저항선(300달러)과 저점 상승 지지선으로 이루어진 어센딩 트라이앵글 수렴 도중, 300달러를 돌파할 것을 미리 예측하고 294달러에서 비중 100% 매수로 진입했습니다. 그러나 삼성전자 주가는 돌파에 실패하고 하방 상승 지지선을 대량 거래량 장대음봉으로 뚫어 276달러로 하향 마감했습니다. 올바른 매매 액션은?', '[{"time":"Day 1","open":240,"high":300,"low":240,"close":285,"volume":114},{"time":"Day 2","open":285,"high":300,"low":264,"close":291,"volume":113},{"time":"Day 3","open":291,"high":294,"low":273,"close":276,"volume":109}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":300}],"label":"수평 저항선 (100)","color":"#ef4444"},{"type":"line","points":[{"x":0,"y":240},{"x":1,"y":264},{"x":2,"y":282}],"label":"상승 지지선 (붕괴)","color":"#10b981"}]'::jsonb, ARRAY['하방 이탈 확인 즉시 손절하여 추가 폭락 차단', '조정을 이용해 평단가를 조절하는 분할 물타기', '본전 탈출 시까지 포지션을 유지하며 관망', '손절 라인을 하단으로 조정하고 대기 주문 유지']::text[], 0, '어센딩 트라이앵글은 상방 확률이 다소 높지만, 하단 지지선이 뚫려 무너지는 순간 패턴 실패와 함께 엄청난 실망 매도 매물이 출하됩니다. 특히 돌파를 미리 예견해 들어간 포지션은 즉시 룰 위반을 시정하고 손절(276달러)해야 큰 자산 보호를 할 수 있습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (347, '패턴/돌파', '04_patterns_breakout.md', '하락 바닥권에서 왼쪽 어깨, 머리, 오른쪽 어깨를 그리며 역헤드앤숄더(Inverse Head & Shoulders) 패턴이 완성되었습니다. 가격이 넥라인 저항벽(240달러선)을 돌파했으나 이미 장대양봉으로 높이 솟아(261달러) 추격 매수 타이밍을 아쉽게 놓쳤습니다. 이때 뇌동매매를 피하는 가장 현명한 매수 타점 공략법은?', '[{"time":"Day 1","open":285,"high":285,"low":210,"close":234,"volume":107},{"time":"Day 2","open":234,"high":246,"low":180,"close":225,"volume":110},{"time":"Day 3","open":225,"high":237,"low":204,"close":228,"volume":101},{"time":"Day 4","open":228,"high":264,"low":225,"close":261,"volume":97}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":240}],"label":"넥라인 저항선 (80)","color":"#ef4444"}]'::jsonb, ARRAY['포모(FOMO) 현상에 따른 돌파봉 꼭대기 추격 매수', '돌파 넥라인 부근의 리테스트 조정 눌림목 매수', '반등 랠리 종결 판단에 따른 역베팅 숏 포지션', '추세 전환 확인 후 무조건적인 관심종목 제외']::text[], 1, '강한 패턴 돌파봉 확인 후 뇌동매매로 추격하는 것은 손절 거리가 너무 멀어져 손익비가 최악인 나쁜 습관입니다. 정석 돌파 트레이더는 넥라인 역할 전환 지점(240달러)으로의 되돌림 눌림목(Retest)을 차분히 기다려 리스크를 짧게 끊고 들어가는 훈련을 해야 합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (348, '패턴/돌파', '04_patterns_breakout.md', '지속적인 하락 추세 중, 고점과 저점이 수렴하며 우하향하는 하락 쐐기형(Falling Wedge) 패턴의 끝자락에 도달했습니다. 거래량이 급감하다가 마침내 쐐기형 상단 저항선을 상방으로 뚫는 강한 양봉 종가 마감(330달러)이 포착되었습니다. 합리적인 매수 진입 시 손절가 설정 기준은 무엇인가요?', '[{"time":"Day 1","open":390,"high":396,"low":330,"close":336,"volume":112},{"time":"Day 2","open":336,"high":348,"low":306,"close":312,"volume":89},{"time":"Day 3","open":312,"high":324,"low":294,"close":300,"volume":90},{"time":"Day 4","open":300,"high":336,"low":297,"close":330,"volume":128}]'::jsonb, '[]'::jsonb, ARRAY['손절 없이 청산가에 의존하여 장기 홀딩', '상방 돌파 확인 후 진입 및 직전 최저점 손절 셋업', '평단가 개선을 위한 지속적인 분할 물타기 매수', '상단 저항선 돌파 시점을 이용한 숏 포지션 스위칭']::text[], 1, '하락 쐐기형(Falling Wedge)의 상방 돌파는 강력한 반전 신호입니다. 이 패턴의 장점은 진입 즉시 명확하고 짧은 기준점(수렴 바닥 최저가 294달러 혹은 돌파봉 하단)을 손절가로 설정할 수 있어, 리스크 한도를 안전하게 통제한 채 상방 랠리를 도모할 수 있다는 점입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (349, '패턴/돌파', '04_patterns_breakout.md', '삼성전자 주가가 약한 매수세와 거래량 급감 속에 고점과 저점을 높이며 좁게 상승 쐐기형(Rising Wedge)을 그리고 있습니다. 현재 가격은 상승 쐐기형 하단 지지선(900달러)에 아주 밀착하여 붕괴 위기에 놓여 있습니다. 이 시점에서 롱(매수) 포지션을 들고 있는 트레이더의 리스크 대응은?', '[{"time":"Day 1","open":780,"high":840,"low":780,"close":834,"volume":104},{"time":"Day 2","open":834,"high":885,"low":816,"close":870,"volume":25},{"time":"Day 3","open":870,"high":915,"low":894,"close":903,"volume":29}]'::jsonb, '[{"type":"line","points":[{"x":0,"y":780},{"x":1,"y":816},{"x":2,"y":894}],"label":"쐐기 하단 지지선 (300)","color":"#ef4444"}]'::jsonb, ARRAY['상승 쐐기형 하방 이탈 위험에 따른 롱 포지션 매도', '상승 지속 확신에 따른 레버리지 추가 불타기', '장기 상승 흐름 기대로 손절 없이 무기한 홀딩', '다른 종목으로의 포지션 분산을 위한 관망']::text[], 0, '상승 쐐기형(Rising Wedge)은 약세 세력이 억지로 쥐어짜며 상승 가격을 만드는 패턴으로, 수렴 끝에서 거래량 소멸과 함께 하방 이탈(Breakdown)하여 폭락할 위험이 매우 높은 대표적인 하락 대비 패턴입니다. 하단 지지선 이탈 낌새 시에는 매수 포지션을 전부 도망쳐 나와야 큰 손실을 막을 수 있습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (350, '패턴/돌파', '04_patterns_breakout.md', '둥근 대야 모양의 바닥(Cup)을 그리며 상승 회복한 삼성전자 주가가 전고점 저항벽 부근에서 하향 채널식 완만한 되돌림 조정 핸들(Handle)을 그리는 중입니다. 이후 핸들의 상단 저항선(450달러선)을 강한 거래량의 장대양봉으로 상향 돌파했습니다. 이때 합리적인 트레이더의 대응은?', '[{"time":"Day 1","open":420,"high":426,"low":384,"close":390,"volume":93},{"time":"Day 2","open":390,"high":420,"low":387,"close":414,"volume":91},{"time":"Day 3","open":414,"high":420,"low":402,"close":405,"volume":89},{"time":"Day 4","open":405,"high":462,"low":402,"close":456,"volume":112}]'::jsonb, '[]'::jsonb, ARRAY['핸들 상방 돌파 확인 후 진입 및 핸들 저점 손절', '하락 지속 판단에 따른 즉각적인 전량 손절', '평단가 부근이므로 추가 손절 설정 없이 관망', '돌파 여부 확인 전 고점 돌파 매수 주문 100%']::text[], 0, '전형적인 강세 지속 패턴인 컵앤핸들(Cup & Handle)입니다. 핸들의 하락 조정 채널 상단 돌파는 매물 소화를 성공적으로 완수하고 본 랠리로 진입한다는 강력한 신호입니다. 손익비 관점에서 핸들의 지지 저점인 402달러 아래에 안전 손절을 지정한 뒤 진입 시 우수한 기대 수익을 가질 수 있습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (351, '지표/컨플루언스', '06_technical_indicators.md', '강력한 대세 상승 국면인 종목이 일시 조정을 거쳐 전저점 지지 영역(300달러)에 도달해 저점을 지키고 있습니다(저점 높임 또는 수평). 그런데 이때 보조지표 RSI의 저점은 이전보다 훨씬 깊게 파여 낮아지는 ''히든 상승 다이버전스(Hidden Bullish Divergence)''가 포착되었습니다. 현명한 의사결정은?', '[{"time":"Day 1","open":270,"high":330,"low":264,"close":315,"volume":119},{"time":"Day 2","open":315,"high":321,"low":294,"close":300,"volume":104}]'::jsonb, '[]'::jsonb, ARRAY['하락 전환 신호로 판단하여 전량 즉시 손절', '추세 지속 신호 기대로 지선 부근 추가/신규 매수', '지표 과매수 판단에 따른 계좌 거래 정지', '손절 설정 없이 무제한 레버리지 롱 대응']::text[], 1, '삼성전자 주가의 저점은 높아지는데 보조지표(RSI 등)의 저점은 낮아지는 형태는 ''히든 상승 다이버전스''입니다. 이는 기존의 강력한 상승 트렌드 내부에서 일시 조정을 겪는 매수자들이 활기차게 물량을 주워 담아 다음 상승 랠리를 추진한다는 신호이므로, 짧은 손절 라인(294달러)을 설정하고 매수 비중을 태우기 가장 적합한 정석 타점입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (352, '지표/컨플루언스', '07_multitimeframe_regime.md', '삼성전자 주가가 호재와 함께 밴드 상단선 바깥을 타고 계속 상승하는 강력한 볼린저 밴드 밴드워크(Band Walk) 현상이 발생 중이며, RSI는 80을 넘어 극단적 과매수 수치를 가리키고 있습니다. 이 구간에서 취해야 할 가장 합리적인 리스크 및 포지션 관리 행동은?', '[{"time":"Day 1","open":300,"high":345,"low":297,"close":336,"volume":116},{"time":"Day 2","open":336,"high":384,"low":330,"close":375,"volume":114},{"time":"Day 3","open":375,"high":417,"low":366,"close":408,"volume":104}]'::jsonb, '[]'::jsonb, ARRAY['과매수 도달 판단에 따른 고배율 숏 무리한 진입', '추종 손절매(Trailing Stop)를 통한 수익 극대화', '상승폭 만족에 따른 즉각적인 전량 시장가 익절', '손절 가격을 해제하고 시세 지속 시까지 방치']::text[], 1, '강세 추세가 지나치게 강할 경우 볼린저 밴드 상단을 타고 오르는 밴드워크 현상과 RSI 과매수 현상이 영구 유지될 수 있습니다. 이때 단순 과매수 수치를 이유로 숏 포지션을 잡으면 파산합니다. 기존 매수 포지션의 익절선(Trailing Stop)을 상향 관리하여 추세 상승 이익을 극대화하고 신규 진입은 자제하는 것이 정석 리스크 관리입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (353, '지표/컨플루언스', '06_technical_indicators.md', '1시간 봉 차트 상에서 삼성전자 주가가 확실히 낮아졌으나 RSI 저점은 유의미하게 상승한 ''상승 다이버전스''가 확인되어 매수 타점을 노리고 있습니다. 다만 15분 봉 단기 차트에서는 하락 장대음봉 관성이 아직 살아있어 매도 압력이 보입니다. 멀티 타임프레임 트레이더의 진입 의사결정은?', '[{"time":"Hour 1","open":300,"high":306,"low":270,"close":273,"volume":114},{"time":"Hour 2","open":273,"high":276,"low":240,"close":246,"volume":117}]'::jsonb, '[]'::jsonb, ARRAY['단기 음봉 관성 기대로 즉각 숏 포지션 진입', '큰 시간 프레임의 상승 다이버전스 타점 매수', '지표 충돌로 판단하고 시장가 즉시 롱 진입', '변동성 기대로 무작정 도박성 잡코인 진입']::text[], 1, '큰 프레임(1시간 봉)의 다이버전스가 주는 중장기 추세 신뢰도는 작은 프레임의 단기 노이즈보다 압도적으로 강력합니다. 단, 진입 시 타이밍의 정밀도를 높이기 위해 소파동(15분 봉)의 하락 동력이 꺾이고 지지해 주는 단기 확인 캔들이 나오는 찰나에 롱 포지션 타이밍을 잡는 것이 멀티 타임프레임 정석 매매입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (354, '지표/컨플루언스', '06_technical_indicators.md', '삼성전자 주가는 600달러 저항대를 뚫고 660달러까지 계속 우상향하며 고점을 갱신하고 있으나, MACD 오실레이터의 히스토그램 산 높이는 직전 고점 시점 대비 현저하게 쪼그라들며 꺾여 내려가 하락 다이버전스를 형성 중입니다. 현명한 포지션 보유자의 이익 관리 행동은?', '[{"time":"Day 1","open":540,"high":615,"low":537,"close":600,"volume":106},{"time":"Day 2","open":600,"high":666,"low":594,"close":660,"volume":85}]'::jsonb, '[]'::jsonb, ARRAY['추세 지속 확신으로 보유 비중 추가 불타기', '상승 모멘텀 약화 다이버전스 확인 후 50% 익절', '익절 설정 없이 전고점 도달 시까지 홀딩', '고점 붕괴 기대로 숏 포지션 10배 베팅']::text[], 1, '삼성전자 주가는 올라가나 모멘텀 지표인 MACD 오실레이터 고점이 낮아지는 현상은 대표적인 하락 다이버전스로, 매수 에너지가 속 빈 강정처럼 쇠퇴하고 있어 언제든 급격한 폭락 조정이 발생할 수 있는 고위험 신호입니다. 이 시점에는 탐욕을 통제하고 물량의 50% 이상을 분할 매도하여 현금을 챙기는 것이 원칙입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (355, '지표/컨플루언스', '06_technical_indicators.md', '삼성전자 주가가 하락 횡보하던 도중, 단기 지평선인 EMA 20일선이 중장기선인 EMA 50일선에 극도로 밀착하며 수렴했습니다. 당일 대량 거래량의 음봉 캔들이 터지며 단기선이 장기선 아래로 교차하기 직전(데드크로스 임박)이며 주요 지지선 밑으로 떨어졌습니다. 롱(매수) 포지션 보유자의 올바른 대응은?', '[{"time":"Day 1","open":315,"high":318,"low":297,"close":300,"volume":89},{"time":"Day 2","open":300,"high":303,"low":285,"close":288,"volume":91}]'::jsonb, '[]'::jsonb, ARRAY['지지선 이탈 및 데드크로스 확인 즉시 손절', '이평선 지지력을 믿고 하방 물타기 추가 매수', '하락 조정 후 반등 기대로 무기한 홀딩 관망', '청산가 도달 시까지 어떠한 대응 없이 방치']::text[], 0, '20일선과 50일선의 데드크로스 임박 수렴 상태에서 가격이 지지선마저 무너뜨린 것은 하락 가속화 추세가 폭발하기 직전인 매우 위험한 기술적 상태입니다. 하락 추세가 본격 정배열(하락 정배열)화 되기 전에 즉시 전량 손절하고 시장 밖에서 피신해 있는 것이 계좌의 영구 파산을 막는 유일한 생존 규칙입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (356, '리스크/심리', '09_risk_position_management.md', '국내 주식 매수 후 가격이 급락하여 내가 설정해 둔 최대 감내 손실 한도인 계좌 총원금 대비 -2% 라인(손절매 지정 가격)에 완벽하게 닿았습니다. 마침 본전 생각과 함께 ''조금만 더 버티면 반등할 텐데...''하는 강한 뇌동매매 유혹이 솟구칩니다. 이때 원칙 트레이더의 결정은?', '[{"time":"Day 1","open":300,"high":306,"low":297,"close":300,"volume":84},{"time":"Day 2","open":300,"high":303,"low":282,"close":285,"volume":90}]'::jsonb, '[]'::jsonb, ARRAY['손절 라인을 임의로 하향 조정하고 홀딩', '평단가 관리 차원의 지속적 물타기 매수 집행', '원칙에 따라 뇌동을 제어하고 즉시 기계적 손절', '손실은 배제하고 반등 기대를 통한 무기한 보유']::text[], 2, '트레이딩의 승패는 예측이 아닌 ''리스크 통제''에 달려 있습니다. 사전에 정한 계좌 대비 2% 리스크 한도에 도달했을 때 희망 회로를 돌리며 손절을 미루거나 물타기를 집행하는 순간 계좌는 서서히 영으로 깎여 파산합니다. 멘탈의 충동을 통제하고 기계적으로 전량 칼손절하는 것이 절대 파산하지 않는 시장의 1법칙입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (357, '리스크/심리', '10_psychology_routine_review.md', '최근 3회 연속 거래에서 계속해서 손절(Stop Loss)을 맞아 뇌 내의 도파민 체계가 무너지고 심리가 극도로 불안해져 분노와 보복 매매 충동이 밀려옵니다. 이 상황에서 파산을 막는 가장 훌륭한 매매 심리 대처법은?', '[{"time":"Today","open":300,"high":300,"low":300,"close":300}]'::jsonb, '[]'::jsonb, ARRAY['손실 복구를 위해 레버리지를 증액해 즉시 진입', '뇌동 방지를 위해 HTS를 종료하고 매매 일지 작성 및 휴식', '추천 매매 신호 유료 리딩방에 즉시 가입 및 추종', '심리적 회복을 위해 역베팅 숏 포지션 추가']::text[], 1, '연속 손실 후 발생하는 복수심과 분노는 트레이더를 뇌동매매와 계좌 파멸로 이끄는 가장 치명적인 감정 상태입니다. 멘탈 붕괴를 느꼈을 때는 즉각 행동을 멈추고 시스템을 강제 종료하여 시장과 물리적 격리를 통해 냉정을 찾는 것만이 자산을 파산 리스크로부터 살려내는 훌륭한 트레이딩 행동입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (358, '셋업/실행', '09_risk_position_management.md', '진입하고자 하는 매수 자리를 분석해 보니, 기술적 분석 상 이길 수 있는 확률(승률)은 반반인 50% 수준입니다. 그러나 손절 시 기대 손실금액 대비 성공 시 획득할 수 있는 기대 수익금액의 비율(손익비)을 정밀 셋업 해보니 1 : 1.2 수준으로 다소 애매하게 도출되었습니다. 원칙 트레이더의 진입 결정은?', '[{"time":"Today","open":300,"high":300,"low":300,"close":300}]'::jsonb, '[]'::jsonb, ARRAY['단기 변동성 기대로 부적합한 손익비 시장가 진입', '마이너스 기댓값 거래 유보 및 우수 타점 대기', '레버리지를 높여 손익비 구조를 임의 조정 시도', '반대 방향으로 고배율 역베팅을 즉시 실행']::text[], 1, '수학적으로 승률 50%일 때 손익비가 최소 1:2(잃을 때 1, 벌 때 2) 이상이 나오지 않으면 복리 매매 시 수수료와 호가 슬리피지에 밀려 잔고가 무조건 마이너스로 수렴합니다. 타점이 눈에 들어오더라도 사전에 기대 손익비 필터에 걸려 탈락한다면 패스를 선언하고 관망하는 것이 현명한 생존 원칙입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (359, '리스크/심리', '09_risk_position_management.md', '갑작스러운 거시 경제 발표로 내가 매매 중인 종목의 캔들 변동성 폭(ATR)이 평소 시세의 2배 수준으로 널뛰기 시작했습니다. 1회 거래당 내 계좌 원금의 최대 2% 리스크 한도를 동일하게 고수하기 위해 취해야 할 올바른 조치는?', '[{"time":"Day 1","open":300,"high":306,"low":294,"close":300,"volume":80},{"time":"Day 2","open":300,"high":330,"low":270,"close":306,"volume":123}]'::jsonb, '[]'::jsonb, ARRAY['평소 변동성과 동일한 비중 및 손절 거리 고수', '손절 거리를 넓히는 대신 진입 포지션 수량 축소', '변동성이 확대되었으므로 2배 비중으로 적극 지름', '즉시 전량 손절하고 시장 상황 정상화 대기']::text[], 1, '시장 변동성이 커질 때는 손절 스톱 아웃이 잦으므로 손절폭(%)을 넓혀 숨 쉴 공간을 확보해 주는 것이 합리적입니다. 단, 손절폭을 2배로 늘린다면 계좌 대비 리스크 한도가 2배(4%)로 커지므로, 진입 포지션의 계약 수량을 50%로 줄여 리스크 노출 총액을 2%로 완벽하게 동일 통제하는 것이 포지션 사이징(Position Sizing)의 정석 원칙입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (360, '리스크/심리', '09_risk_position_management.md', '투자자 A의 전체 투자 원금은 1,500만 원이며, 1회 거래당 최대 허용 리스크 금액은 원금의 2%인 30만 원입니다. 현재 삼성전자 주가가 30,000원이며, 기술적 분석 상 합리적인 손절선은 지지선 바로 밑인 28,500원(-5%)입니다. 2% 룰 리스크 관리 원칙에 따라 A가 진입(매수)해야 하는 최대 국내 주식 수량은?', '[{"time":"Today","open":30000,"high":30000,"low":30000,"close":30000}]'::jsonb, '[]'::jsonb, ARRAY['500주 (투자금 전액 시장가 매수)', '200주 (손실 한도 30만 원 맞춤 매수)', '50주 (보수적 극단적 비중 축소)', '100주 (절반 비중 고정 매수)']::text[], 1, '포지션 크기 계산 공식은 `최대 매수 규모 = 최대 허용 리스크 금액 / 손절매 비율` 입니다. 이 시나리오에서 `300,000원 / 0.05(5%) = 6,000,000원`이 최대 허용 진입금액이 되며, 이를 삼성전자 주가 30,000원으로 나누면 `200주`가 도출됩니다. 200주 진입 후 -5% 가격 폭락으로 손절 당해도 내 총원금에서 깎이는 돈은 정확히 30만 원(2%)으로 완벽히 리스크 통제됩니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (361, '거래량/유동성', '05_volume_liquidity.md', '삼성전자 주가가 수평 저항선 부근까지 급상승했으나 캔들 몸통(Spread)이 지극히 좁아진 도지 형태로 마감하였고, 거래량은 이전 5일 평균 대비 3배 이상 폭증했습니다. VSA(Volume Spread Analysis) 관점에서 가장 타당한 차트 분석은?', '[{"time":"Day 1","open":300,"high":315,"low":297,"close":312,"volume":115},{"time":"Day 2","open":312,"high":327,"low":309,"close":324,"volume":116},{"time":"Day 3","open":324,"high":330,"low":321,"close":324,"volume":112}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":327},{"x":2,"y":327}],"label":"저항선","color":"#ef4444"}]'::jsonb, ARRAY['강한 매수 기세 기대로 즉시 돌파 매매 풀매수', '저항벽 매도 공급 세력 분산 확인 후 이익 실현', '대량 거래 확인에 따른 손절 해제 후 장기 투자', '반등 실패에 따른 고배율 보복 숏 베팅 가동']::text[], 1, '캔들 몸통 크기(스프레드)가 좁은데 거래량이 매우 크게 폭증했다는 것은 저항선 부근에서 들어오는 매수세만큼 세력의 매도 물량 공급이 쏟아져 막강한 저항 벽을 형성하고 있다는 뜻입니다. VSA에서는 이를 불화(Disharmony)로 규정하며 상승 추세 감속 및 하락 반전의 경고로 해독합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (362, '거래량/유동성', '05_volume_liquidity.md', '삼성전자 주가가 장기 횡보하던 박스권 지지선인 600달러를 깨고 585달러까지 하락 투매가 발생했으나, 종가 마감 직전 거래량이 크게 실린 긴 아래꼬리를 그리며 다시 603달러 위로 복귀 안착했습니다. 이 스톱 헌팅 유동성 현상에서의 실전 트레이더의 대응은?', '[{"time":"Day 1","open":630,"high":636,"low":600,"close":606,"volume":95},{"time":"Day 2","open":606,"high":612,"low":585,"close":603,"volume":108}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":600},{"x":1,"y":600}],"label":"지지선","color":"#10b981"}]'::jsonb, ARRAY['지지선 붕괴 확정으로 간주한 시장가 숏 추격', '스윕(sweep) 판단 하에 아래꼬리 저점 손절 잡고 롱', '아무런 신호도 아니라고 판단하고 포지션 방치', '지지선 이탈 기대로 전량 손절 후 시장 영구 탈출']::text[], 1, '지지선 아래에 걸려 있던 개인들의 손절 주문(Sell Stop)을 강제로 청산(Liquidity Sweep)시킨 뒤, 세력이 물량을 헐값에 다 받아 삼켜 종가를 지지선 위로 신속하게 복귀시킨 휩소(베어 트랩) 패턴입니다. 아래꼬리 극점(585달러)에 아주 좁은 손절 라인을 설정할 수 있어, 기대 손익비가 극대화되는 고확률 상승 반전 매수 타점입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (363, '거래량/유동성', '05_volume_liquidity.md', '삼성전자 주가는 750달러에서 870달러까지 계속 고점을 높이며 상승 추세를 이어가고 있습니다. 그러나 각 상승 파동마다 터지는 거래량은 전고점 돌파 시점 대비 눈에 띄게 하향 곡선을 그리며 감소하고 있습니다. VSA 기법에 따른 합리적인 진단은?', '[{"time":"Wave 1","open":690,"high":780,"low":684,"close":765,"volume":113},{"time":"Wave 2","open":765,"high":825,"low":750,"close":810,"volume":116},{"time":"Wave 3","open":810,"high":870,"low":795,"close":864,"volume":100}]'::jsonb, '[]'::jsonb, ARRAY['가격 상승으로 인한 매수 지속 강화 초강세', '매도 물량 고갈에 따른 무중력 안심 홀딩', '신규 자금 유입 둔화 거래량 다이버전스로 분할 익절', '지표 조작으로 판단하여 매매 중단 및 차트 종료']::text[], 2, '삼성전자 주가는 상승하여 신고점을 갱신하지만 파동별 거래량이 지속 감소하는 흐름은 ''거래량 다이버전스''로 상승 모멘텀의 내부 엔진이 식어감을 경고합니다. 조만간 가벼운 매도 포격에도 대규모의 차익 실현 폭락 조정이 발생할 수 있는 잠재적 폭락 국면이므로 물량을 덜어내고 현금을 확보해야 합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (364, '거래량/유동성', '05_volume_liquidity.md', '가격이 이전 고점 저항선을 뚫고 강하게 솟구치며 장대양봉을 만들었습니다. 이때 가짜 이탈(Whipsaw / Bull Trap)이 아닌 진성 돌파(True Breakout)로 판정할 수 있는 가장 신뢰도 높은 거래량 기준은?', '[{"time":"Day 1","open":300,"high":306,"low":297,"close":300,"volume":368},{"time":"Day 2","open":300,"high":336,"low":297,"close":330,"volume":396}]'::jsonb, '[]'::jsonb, ARRAY['수렴 끝자락에서 거래량이 최저치인 상태 유지', '평균 대비 1.5~2배 이상 거래량 급증하며 돌파 마감', '거래량이 전혀 변하지 않는 평이한 상태 유지', '호가 스프레드가 가장 좁아지는 횡보 상태']::text[], 1, '참된 저항 돌파(True Breakout)는 저항선 부근의 두터운 대기 매도 공급 물량을 대규모 자금으로 전부 씹어 삼키고 돌파해야 함을 뜻합니다. 따라서 반드시 평균 대비 1.5배~2배 이상의 거래량 분출이 동반되어야 신뢰할 수 있으며, 거래량이 적은 돌파는 꼬리 달고 내려앉는 불 트랩(Bull Trap)일 확률이 매우 높습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (365, '거래량/유동성', '05_volume_liquidity.md', '삼성전자 차트에서 중요 지지선 직전 저점 아래에 엄청난 규모의 롱 포지션 청산 및 매도 손절 주문이 쌓여 있는 유동성 풀(Liquidity Pool) 구간이 감지되었습니다. 세력이 이 구간을 공략할 때 나타날 캔들의 전형적인 무빙 패턴은?', '[{"time":"Day 1","open":150000,"high":151500,"low":147600,"close":148500,"volume":17},{"time":"Day 2","open":148500,"high":149400,"low":144000,"close":148800,"volume":17}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":147600},{"x":1,"y":147600}],"label":"전저점 지지선","color":"#3b82f6"}]'::jsonb, ARRAY['지지선을 장대음봉으로 돌파하여 20% 폭락 마감', '전저점 이탈로 손절 유도 후 지지선 위 아래꼬리 안착', '오차 없이 지지선 터치 후 꼬리 없는 수평 도지 횡보', '거래량 없이 즉각 상승 빔 분출로 전고점 탈환']::text[], 1, '기관 세력(스마트 머니)은 대량 포지션을 구축하기 위해 개인의 손절 주문(Sell Stop)을 의도적으로 터트려 매도 유동성을 유도한 후 이를 다 매수합니다. 이로 인해 삼성전자 주가는 지지선 아래로 일시 급락 후(스톱 헌팅), 아래꼬리를 매우 길게 달며 지선 안쪽으로 급반등 마감하게 됩니다. 이것이 유동성 스윕(Liquidity Sweep)의 정석 패턴입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (366, '거래량/유동성', '05_volume_liquidity.md', '상승 추세 도중 전고점 저항선 부근에서 위꼬리가 아주 긴 캔들이 터졌고, 거래량은 최근 보름 중 최고 수치로 솟구쳤습니다. VSA 관점에서 이 상승 거절(Upside Rejection) 현상에 대한 올바른 대처는?', '[{"time":"Day 1","open":300,"high":345,"low":294,"close":303}]'::jsonb, '[]'::jsonb, ARRAY['강한 저점 매수 기회로 인지하여 비중 대폭 추가', '고점 매도 Rejection 확인 후 기존 롱 포지션 대피', '박스 횡보 수렴 기대로 마틴게일 추가 매수 가동', '이평선 정배열 판단에 따른 포지션 변경 없이 홀딩']::text[], 1, '위꼬리가 매우 긴 캔들이 대량 거래량과 함께 터졌다는 것은 고점 돌파 시도가 있었으나 그 자리에 숨어 있던 세력의 막강한 청산 매도 벽(Supply)을 만나 격렬하게 두들겨 맞고 밀려났음을 의미합니다. 상방 거절의 심리가 지배적이므로 고점 피로 및 하락 전환이 임박한 위험 징후입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (367, '지표/컨플루언스', '06_technical_indicators.md', '삼성전자 주가가 장기 박스권 횡보를 이어가며 볼린저 밴드의 폭이 최근 몇 달 중 가장 좁은 형태로 밀착 수렴(Squeeze)되었습니다. 이 스퀴즈 국면에 대한 올바른 기술적 이해와 매매 시나리오는?', '[{"time":"Week 1","open":300,"high":309,"low":291,"close":303,"volume":104},{"time":"Week 2","open":303,"high":306,"low":297,"close":300,"volume":91}]'::jsonb, '[]'::jsonb, ARRAY['박스권 변동성 부재 기대로 장기 무대응 관망', '에너지 수축 스퀴즈 확인 후 밴드 이탈 돌파 대기', '지표 신뢰 불가 판단으로 볼린저 밴드 지표 삭제', '중심선 지지로 판단하여 고배율 매수 대기 주문']::text[], 1, '볼린저 밴드의 폭이 극도로 좁아지는 스퀴즈(Squeeze) 현상은 시장의 표준편차 변동성이 임계치까지 압축 수렴되었음을 알려줍니다. 에너지 압축 뒤에는 항상 폭발적인 가격 분출(상방/하방 이탈)이 뒤따르므로, 밴드를 뚫고 거래량이 실려 돌파 마감하는 방향으로 추세 추종 시나리오를 설계해야 합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (368, '지표/컨플루언스', '06_technical_indicators.md', '삼성전자 주가는 HL(Higher Low)을 형성하며 이전 직전 저점(270달러)보다 높은 저점(285달러)을 지키고 있으나, RSI 지표는 이전 35 수치보다 더 깊숙하게 25 수치까지 떨어졌습니다. 이 지표 불일치 현상의 공식 명칭과 올바른 포지션 셋업은?', '[{"time":"Day 1","open":300,"high":306,"low":270,"close":273,"volume":106},{"time":"Day 2","open":273,"high":288,"low":285,"close":285,"volume":106}]'::jsonb, '[]'::jsonb, ARRAY['일반 상승 다이버전스 - 추세 종결로 즉각 공매도', '히든 상승 다이버전스 - 지선 눌림목 롱 진입 활용', '일반 하락 다이버전스 - 모든 매수 포지션 정리', '지표 오작동 휩소 구간 판단으로 양방향 관망']::text[], 1, '가격의 저점은 높아졌는데(Higher Low) 모멘텀 지표의 저점은 낮아지는 현상은 ''히든 상승 다이버전스(Hidden Bullish Divergence)''입니다. 이는 추세 반전이 아닌 **기존 강세 추세 지속**을 뜻하며, 조정 눌림목이 완성되고 다음 상승 랠리를 준비한다는 최고의 매수 신호 중 하나입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (369, '지표/컨플루언스', '06_technical_indicators.md', '매수 타점을 신중하게 선별하고자 합니다. 기술적 분석의 성공 확률을 비약적으로 끌어올리는 ''다중 컨플루언스(Confluence)'' 결합 사례로 가장 적합한 조건 구성은?', '[{"time":"Today","open":300,"high":300,"low":300,"close":300}]'::jsonb, '[]'::jsonb, ARRAY['트위터 및 뉴스의 호재 찌라시 확인 즉시 추격', '지지선+이평선+다이버전스+아래꼬리 등 분석 중첩 시', 'RSI 과매수 영역 진입 즉시 롱 포지션 진입', '독립적 분석 없이 오직 보조지표의 단일 수치 신호']::text[], 1, '다중 컨플루언스(Confluence)는 독립적인 기술적 근거들이 동일한 특정 가격 구역에 중첩되는 현상입니다. 지지 저항, 이평선, 보조지표 다이버전스, 캔들 가격행동(Rejection 핀바)이 한 곳에 묶여 매수 자리를 형성할 때 매매를 실행하면, 높은 신뢰도와 좁은 손절 라인 덕분에 장기 기대값이 극대화됩니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (370, '셋업/실행', '08_setup_entry_exit.md', '중요 수평 저항선(360달러)을 상방으로 장대양봉 종가 돌파한 것을 확인하고 롱(매수) 진입 셋업을 준비하고 있습니다. 원칙 트레이더가 뇌동매매 추격을 막고 최상의 손익비를 확보하기 위해 즐겨 쓰는 정석적인 진입 실행법은?', '[{"time":"Day 1","open":330,"high":336,"low":327,"close":333,"volume":94},{"time":"Day 2","open":333,"high":372,"low":330,"close":366,"volume":94}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":360},{"x":1,"y":360}],"label":"저항선","color":"#ef4444"}]'::jsonb, ARRAY['돌파 마감 확인 즉시 시장가 추가 매수 집행', '돌파된 저항선의 지지 전환(Retest) 시 지정가 진입', '반등 조정이 불가능하다고 판단하여 최고점 롱 추격', '속임수 돌파 확신으로 고배율 역베팅 숏 진입']::text[], 1, '저항 돌파 후 즉시 가격을 따라붙는 추격 매수는 휩소 조정 시 심각한 손실을 초래합니다. 돌파된 라인이 S/R Flip을 통해 지지로 작용하는지 확인하는 되돌림 리테스트(Retest) 시점에 진입하는 것이, 지선 바로 아래에 좁은 손절 라인을 설계하고 이익 기대 폭을 넓힐 수 있는 가장 이상적인 정석 실행법입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (371, '셋업/실행', '08_setup_entry_exit.md', '포지션 진입 직후, 가격이 계획대로 내 방향으로 순탄하게 우상향하고 있습니다. 기존 진입 시 설정한 손익비 1:2의 최종 목표가 도달 전에, 리스크 관리 차원에서 계좌 드로다운을 0으로 만드는 정석적인 1차 포지션 관리 행동은?', '[{"time":"Entry","open":300,"high":300,"low":300,"close":300,"volume":80},{"time":"Day 1","open":300,"high":318,"low":300,"close":315,"volume":104}]'::jsonb, '[]'::jsonb, ARRAY['1차 저항대 진입 시 레버리지를 활용해 불타기', '목표가 터치 시까지 100% 비중 무대응 홀딩', '1:1 지점 50% 분할 익절 및 남은 물량 본전 손절 상향', '단기 반등 확인 즉시 전량 기계적 청산 및 퇴장']::text[], 2, '이득이 발생해 손익비 1:1 수준에 오면 물량의 절반을 분할 익절(Scale-out)하고 남은 포지션의 스톱로스를 진입가로 이동(Break-even)시키는 것이 포지션 관리의 기본입니다. 이렇게 셋업하면 차트가 갑자기 폭락세로 뒤집혀도 최소 본전 혹은 반절 익절 약수익으로 끝나 해당 거래의 최대 리스크가 Zero(0)로 봉쇄됩니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (372, '셋업/실행', '08_setup_entry_exit.md', '강력한 장기 상승 추세가 터져 삼성전자 주가가 20일 이평선을 타고 계속해서 폭발적으로 신고가를 갱신하고 있습니다. 이때 익절 시점을 서둘러 잡지 않고, 추세 상승 이익을 최대한 길게 끝까지 빨아먹기 위한 정석 청산 실행법은?', '[{"time":"Day 1","open":300,"high":330,"low":297,"close":324,"volume":118},{"time":"Day 2","open":324,"high":360,"low":321,"close":354,"volume":105},{"time":"Day 3","open":354,"high":405,"low":351,"close":396,"volume":111}]'::jsonb, '[]'::jsonb, ARRAY['RSI 과과열 조짐 확인 즉시 시장가 전량 익절', 'Higher Low 지지 직하방으로 손절 추종 익절 셋업', '이익 보존을 포기하고 손익절 라인을 해제 후 홀딩', '즉시 숏 포지션 10배로 맞불을 놓는다']::text[], 1, '강세 추세가 터졌을 때 지레짐작으로 청산하면 상승 파동의 초입만 먹고 끝납니다. 추세 붕괴의 명확한 신호(BOS/MSB)가 나오거나, 가격의 구조적 높은 저점(HL)이 깨질 때까지 손절 라인을 계속 추종해서 상향하는 ''추격 손절매(Trailing Stop)''를 가동하는 것이 추세 이익을 극대화하는 정석 기법입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (373, '셋업/실행', '01_chart_market_basics.md', '차트 분석 결과, 돌파 시점의 체결 변동성과 거래소 호가창의 얇은 매물 상태를 감안할 때 내가 진입하려는 주문 가격에서 체결이 뒤로 밀리는 ''슬리피지(Slippage)''가 심각하게 예상됩니다. 이를 감안한 올바른 주문 실행법은?', '[{"time":"Today","open":300,"high":300,"low":300,"close":300}]'::jsonb, '[]'::jsonb, ARRAY['시장가로 최고 배율을 설정하여 즉시 체결', '돌파 확인 후 지정가 대기 주문으로 단가 조절', '슬리피지를 예방하기 위해 즉각적인 거래 취소', '호가창 스프레드와 무관하게 고배율 레버리지']::text[], 1, '변동성이 크고 호가가 얇은 시장에서 돌파 시 시장가 진입은 나쁜 단가로 체결되는 슬리피지 비용을 발생시켜 시작부터 손실을 크게 안고 갑니다. 돌파 확인 후 되돌림 가격대에서 지정가(Limit Order)를 대기시켜 체결 단가를 내 손아귀에 고정하는 리스크 관리가 필요합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (374, '셋업/실행', '10_psychology_routine_review.md', '원칙 기반의 정석 매매 셋업(Trading Setup)을 설계할 때, 진입 전 반드시 사전에 수치로 명문화되어 결정되어야 할 요소가 아닌 것은?', '[{"time":"Today","open":300,"high":300,"low":300,"close":300}]'::jsonb, '[]'::jsonb, ARRAY['진입 조건(Trigger)과 구체적인 손절 가격(Stop Loss)', '거래 당일 본인의 주관적인 직감과 감정적 목표가', '진입하려는 구체적인 포지션 규모 및 분할 익절선', '거래 아이디어가 무효화되는 구체적 가격 지점']::text[], 1, '매매 셋업은 규칙에 기반한 수치들(진입가, 손절가, 목표가, 수량)로 사전에 철저히 규격화되어야 합니다. 당일의 운이나 주관적 느낌, 예감에 기초한 비과학적 청산 설정은 셋업에서 배제되어야 할 대표적 뇌동매매 요소입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (375, '셋업/실행', '08_setup_entry_exit.md', '하락 횡보하던 삼성전자 주가가 중요 매물대이자 피보나치 되돌림 0.618 지점에 정확히 맞닿아 아래꼬리가 긴 양봉 핀바(Pin Bar)를 그리며 마감했습니다. 룰베이스 트레이더가 진입 버튼을 누를 때 성립된 IF-THEN 시나리오는?', '[{"time":"Day 1","open":300,"high":300,"low":240,"close":246,"volume":91},{"time":"Day 2","open":246,"high":258,"low":234,"close":255,"volume":109}]'::jsonb, '[]'::jsonb, ARRAY['익일 가격 상황과 관계없이 100배 레버리지 진입', '중첩 자리 핀바(rejection) 확인 후 익일 시가 롱 진입', '상단 저항 도달 판단으로 즉각적인 숏 포지션 진입', '돌파 랠리가 완전히 끝날 때까지 HTS 종료 및 관망']::text[], 1, '훌륭한 트레이딩 실행은 ''IF(조건 만족 시) ➔ THEN(원칙대로 포지션 진입 및 손절/목표가 기계적 배치)''의 룰베이스 알고리즘에 의해 움직여야 감정을 배제할 수 있습니다. 지지 구간 중첩과 핀바 출현 조건이 성립했으므로 다음 봉 시가에 진입하되 꼬리 저점 이탈 시 칼손절하여 리스크를 통제하는 것이 정석입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (376, '리스크/심리', '09_risk_position_management.md', '나의 트레이딩 시스템 승률이 40%로 다소 낮게 고정되어 있습니다. 이 시스템을 통해 장기적으로 파산하지 않고 복리로 계좌 자산을 우상향시키기 위해 필수적으로 지켜야 할 손익비(평균손실 대비 평균수익 비율)의 최소 기준은?', '[{"time":"Today","open":300,"high":300,"low":300,"close":300}]'::jsonb, '[]'::jsonb, ARRAY['손익비 1:1 수준 (매매 승률이 낮을 때 파산)', '승률 40% 대비 기댓값 개선을 위한 손익비 1:1.5 이상', '낮은 승률 상태에서 손익비와 무관하게 무조건 파산', '승률 극복을 위한 레버리지 20배 수준 설정']::text[], 1, '승률이 40%일 때 기대값 수학적 수수료 감안 최소 손익비는 1:1.5입니다. 손익비 1.5배 이상 구간만 취하면 10번 중 6번 손절당하고 단 4번만 익절하더라도 계좌 총합은 수익 우위에 서게 됩니다. 저승률 시스템일수록 철저히 손익비가 유리한 진입가 근처 타점만 기계적으로 필터링해 진입해야 생존합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (377, '리스크/심리', '09_risk_position_management.md', '선물 트레이더인 B는 담보금 효율을 극대화한다는 명목으로 50배 레버리지 롱 포지션 진입을 실행했습니다. 진입 가격 대비 B의 포지션 원금이 완전 소멸(강제 청산)되는 역방향 하락 거리(%)는 대략 몇 % 수준입니까?', '[{"time":"Today","open":300,"high":300,"low":300,"close":300}]'::jsonb, '[]'::jsonb, ARRAY['진입 단가 대비 20.0%의 강한 하락 발생 시', '진입 단가 대비 단 -2.0% 변동성 노이즈 터치 시', '진입 단가 대비 50.0%의 강한 폭락 발생 시', '청산가가 산출되지 않는 특이 종목 거래 시']::text[], 1, '청산 거리 계산 공식은 대략 `100% / 레버리지 배수` 입니다. 50배 고배율 레버리지의 경우, 내 포지션 반대 방향으로 단 **-2%**의 시세 변동성(장중 흔한 잔파동 노이즈)만 터치해도 원금이 100% 강제 청산 증발됩니다. 고배율 레버리지는 수학적 확률상 100% 파멸을 초래하는 도박성 거래 행위입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (378, '리스크/심리', '09_risk_position_management.md', '트레이딩 계좌 총자산이 6,000만 원인 트레이더가 있습니다. 1회 거래당 총자산의 2% 룰 원칙에 근거하여 리스크 한도(120만 원)를 설정했습니다. 진입하려는 종목의 손절가 거리가 -8%인 경우, 2% 룰을 완벽하게 충족하는 최대 진입(매수) 금액은?', '[{"time":"Today","open":300,"high":300,"low":300,"close":300}]'::jsonb, '[]'::jsonb, ARRAY['6,000만 원 전액 매수 (손절 폭을 배제한 대규모 베팅)', '1,500만 원 진입 (-8% 손절 시 리스크 한도 120만 원 충족)', '3,000만 원 진입 (손익비 1:1 기준에 맞춘 베팅)', '600만 원 진입 (보수적 원칙에 입각한 극단적 축소)']::text[], 1, '포지션 사이징 공식은 `진입금액 = 최대 리스크 허용액(120만 원) / 손절 비율(0.08)` 입니다. 이에 따라 `1,200,000원 / 0.08 = 15,000,000원`이 도출됩니다. 1,500만 원 규모로 매수 진입 시 가격이 급락해 -8% 손절 라인을 때려도 내 총자산에서 깎이는 금액은 정확히 원칙 한도인 120만 원(2%)으로 제한되어 계좌가 완벽히 방어됩니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (379, '리스크/심리', '10_psychology_routine_review.md', '장중에 내가 째려보며 타점을 기다리던 국내 주식이 아무런 조정도 없이 장대양봉을 그리며 갑자기 수직 폭등하기 시작하여 5% 이상 치솟았습니다. 이때 머릿속에 ''나만 두고 날아가는 것 아닌가''하는 극심한 소외감 공포(FOMO)가 솟구칩니다. 원칙 트레이더의 올바른 심리 대응은?', '[{"time":"Day 1","open":300,"high":306,"low":297,"close":300,"volume":95},{"time":"Day 2","open":300,"high":318,"low":300,"close":315,"volume":111}]'::jsonb, '[]'::jsonb, ARRAY['추세 연장 판단으로 시장가 전액 추격 매수', 'FOMO 판단 하에 매수 보류 및 정석 되돌림 타점 대기', '돌파 실패 판단 하에 반대 방향 고배율 숏 베팅', '거래를 종료하고 즉각 국내 주식 시장에서 전량 탈출']::text[], 1, '나만 기회를 잃는다는 공포(FOMO)로 날아가는 장대양봉 꼭대기에서 추격 매수하는 행위는 고점 물리기를 자처하는 가장 흔한 뇌동매매 패턴입니다. 내 타점을 비껴간 상승은 내 돈이 아니라고 인정하고, 사전에 정의한 룰베이스 타점까지 냉정하게 대기하는 것이 장기 생존자의 멘탈 습관입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (380, '리스크/심리', '10_psychology_routine_review.md', '오전 거래에서 원칙을 어긴 무리한 진입으로 인해 3회 연속 스톱아웃(손절)을 당하여 당일 원금의 -6%의 큰 손실을 입었습니다. 본전 생각과 분노로 눈이 뒤집혀 비중을 올려 한 판으로 복수하려는 ''보폭 매매'' 충동이 폭발할 때, 파산을 막는 가장 강력한 멘탈 시스템 룰은?', '[{"time":"Today","open":300,"high":300,"low":300,"close":300}]'::jsonb, '[]'::jsonb, ARRAY['손실 만회를 위해 빌린 돈으로 100배 고배율 복수 베팅', '일일 손실 한도 도달에 따른 매매 강제 종료 및 격리', '주변 유료 전문가 추천 종목을 탐색해 즉각 매수', 'RSI 과매도 상태이므로 즉시 반대 숏 포지션 진입']::text[], 1, '연패를 겪은 후 홧김에 비중을 더 크게 실어 한 번에 본전을 찾으려는 보복 매매는 계좌를 하루 만에 휴지조각으로 만드는 가장 무서운 파산 유도 심리 상태입니다. 이를 막기 위해 하루 최대 손실 한도 한계선(예: 3회 손절 또는 원금의 5%)을 정해두고, 이 한계선 터치 시 즉시 차트를 종료하고 냉각기를 강제 집행하는 룰이 필수입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (401, '캔들/가격행동', '02_candlestick_price_action.md', '하락 추세 지속 도중 바닥권에서 몸통이 짧고 아래꼬리가 몸통의 2배 이상인 아래 캔들이 출현했습니다. 이 캔들의 명칭과 올바른 대응은?', '[{"time":"10:00","open":600,"high":610,"low":590,"close":595,"volume":115},{"time":"10:15","open":595,"high":600,"low":565,"close":570,"volume":119},{"time":"10:30","open":570,"high":575,"low":540,"close":545,"volume":89},{"time":"10:45","open":545,"high":550,"low":505,"close":510,"volume":130},{"time":"11:00","open":510,"high":515,"low":450,"close":505,"volume":102}]'::jsonb, '[]'::jsonb, ARRAY['역망치형 (Inverted Hammer) - 하락 경고 및 공매도 대기', '망치형 (Hammer) - 저점 지지 및 분할 매수 대기', '도지 (Doji) - 매수세와 매도세의 팽팽한 균형 및 관망', '하락 장악형 (Bearish Engulfing) - 추세 반전 및 즉시 손절']::text[], 1, '마지막 캔들은 아래꼬리가 긴 ''망치형(Hammer)'' 캔들로 하락 압력을 이겨내고 저가 매수세가 밀어 올렸음을 의미하는 대표적 상승 전환 신호입니다. 지지를 확인한 뒤 분할 매수 관점으로 대기해야 합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (402, '캔들/가격행동', '02_candlestick_price_action.md', '테슬라 주가가 장기간 급등한 뒤, 고점 부근에서 위꼬리가 매우 길고 몸통이 짧은 형태의 캔들이 발생했습니다. 이 캔들의 해석으로 가장 적절한 것은?', '[{"time":"Day 1","open":500,"high":540,"low":495,"close":525,"volume":108},{"time":"Day 2","open":525,"high":575,"low":520,"close":560,"volume":97},{"time":"Day 3","open":560,"high":625,"low":555,"close":615,"volume":105},{"time":"Day 4","open":615,"high":640,"low":600,"close":630,"volume":128},{"time":"Day 5","open":630,"high":725,"low":625,"close":635,"volume":120}]'::jsonb, '[]'::jsonb, ARRAY['유성형 (Shooting Star) - 고점 저항 및 하락 전환 예고', '망치형 (Hammer) - 저점 매수세 유입 및 상승 랠리 기대', '상승 장악형 (Bullish Engulfing) - 추세 반전 및 홀딩 유도', '도지 (Doji) - 추세 지속 가능성 및 일시 관망']::text[], 0, '급등세 끝에서 위꼬리가 몸통보다 훨씬 길게 솟아오른 캔들은 ''유성형(Shooting Star)''입니다. 장중 상승 시도를 강력한 차익 실현 및 매도 압력이 짓눌렀음을 보여주며, 하락 추세 전환의 강력한 경고 시그널입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (403, '캔들/가격행동', '02_candlestick_price_action.md', '직전의 음봉 몸통을 다음 날의 거대한 양봉 몸통이 완전히 감싸 안는 아래 형태가 포착되었습니다. 이 패턴의 이름과 신뢰도는?', '[{"time":"Day 1","open":490,"high":500,"low":475,"close":480,"volume":94},{"time":"Day 2","open":480,"high":485,"low":460,"close":465,"volume":117},{"time":"Day 3","open":465,"high":475,"low":440,"close":445,"volume":123},{"time":"Day 4","open":435,"high":510,"low":430,"close":505,"volume":102}]'::jsonb, '[]'::jsonb, ARRAY['하락 장악형 (Bearish Engulfing) - 추세 반전 신뢰도 낮음', '상승 장악형 (Bullish Engulfing) - 매수 전환 신뢰도 높음', '상승 관통형 (Piercing Line) - 중간 강도의 반전 신호', '석별형 (Evening Star) - 상승 추세 종결 신호']::text[], 1, '전일의 하락 음봉 몸통을 다음 날의 장대 양봉이 완전히 덮어버리는 형태를 ''상승 장악형(Bullish Engulfing)'' 패턴이라고 합니다. 하락 추세 끝에서 나타날 경우 단기 하락세가 종료되고 강력한 매수세가 들어왔음을 뜻해 전환 신뢰도가 매우 높습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (404, '캔들/가격행동', '01_chart_market_basics.md', '시가와 종가가 거의 일치하여 몸통이 거의 없고 위아래 꼬리만 달린 십자(+) 모양 캔들이 출현했습니다. 이 캔들에 대한 올바른 해석은?', '[{"time":"Day 1","open":750,"high":775,"low":740,"close":760,"volume":101},{"time":"Day 2","open":760,"high":780,"low":755,"close":770,"volume":90},{"time":"Day 3","open":770,"high":795,"low":750,"close":770,"volume":93}]'::jsonb, '[]'::jsonb, ARRAY['상승세 동력 상실로 인한 추세의 하방 반전', '매수/매도 세력 균형에 따른 도지(Doji) 횡보', '매도세 지배에 따른 즉각적인 숏 포지션 진입', '하락 세력 이탈로 인한 즉각적인 상승 랠리']::text[], 1, '시가와 종가가 거의 같은 십자 모양의 캔들은 ''도지(Doji)'' 캔들입니다. 이는 힘의 균형이 팽팽함을 시사하며, 기존 추세의 힘이 빠지고 잠재적인 방향성 전환(상승/하락 모두 포함)의 변곡점이 다가오고 있음을 의미합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (405, '캔들/가격행동', '02_candlestick_price_action.md', '상승 추세 고점에서 직전 양봉의 몸통을 거대 음봉이 아래로 덮어버리는 캔들 조합이 발생했습니다. 이 현상을 의미하는 용어는?', '[{"time":"Day 1","open":600,"high":625,"low":595,"close":620,"volume":116},{"time":"Day 2","open":620,"high":650,"low":615,"close":645,"volume":106},{"time":"Day 3","open":650,"high":655,"low":575,"close":580,"volume":91}]'::jsonb, '[]'::jsonb, ARRAY['하락 장악형 (Bearish Engulfing) - 고점 하락 전환 예고', '상승 장악형 (Bullish Engulfing) - 고점 돌파 랠리 예고', '하락 잉태형 (Harami) - 기존 하락세의 일시 둔화', '샛별형 (Morning Star) - 바닥권 상승 반전 예고']::text[], 0, '고점에서 직전 양봉을 음봉이 감싸 안은 형태는 ''하락 장악형(Bearish Engulfing)''입니다. 매수 세력을 매도 공급이 압도했다는 명백한 증거로, 테슬라 주가 추세가 하락으로 반전할 리스크가 큽니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (406, '시장구조/SR', '03_market_structure.md', '테슬라 주가가 장기 저항선인 750달러를 거래량 실린 강한 캔들로 돌파한 뒤, 다시 750달러 부근으로 내려와 버티고 있습니다. 가장 안전한 진입 방식은?', '[{"time":"Day 1","open":700,"high":740,"low":695,"close":725,"volume":117},{"time":"Day 2","open":725,"high":745,"low":715,"close":720,"volume":118},{"time":"Day 3","open":720,"high":780,"low":715,"close":770,"volume":102},{"time":"Day 4","open":770,"high":775,"low":745,"close":755,"volume":361},{"time":"Day 5","open":755,"high":765,"low":750,"close":760,"volume":357}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":750},{"x":4,"y":750}],"label":"돌파된 저항선 -> 지지선 전환선","color":"#3b82f6"}]'::jsonb, ARRAY['돌파 시점에 시장가로 즉시 진입하는 추격 매수', '돌파 후 저항선의 지지선 전환(Retest) 확인 시 진입', '이전 최저가 부근인 700달러 조정 시까지 대기 매수', '돌파 후 즉시 단기 조정을 예상한 역추세 숏 진입']::text[], 1, '저항선이 강하게 뚫리면 역할 전환(Role Reversal)에 의해 신규 지지선으로 바뀝니다. 돌파 시점에 뇌동매매하기보다는 돌파된 선 부근으로 테슬라 주가가 눌려 지지(Retest)를 완성할 때 진입하는 것이 리스크 대비 기대 수익이 큽니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (407, '거래량/유동성', '05_volume_liquidity.md', '테슬라 주가가 저항선 위로 거래량 없이 장대양봉을 뿜어 올렸으나, 다음 날 곧바로 장대음봉으로 밀어붙이며 저항선 아래로 내려왔습니다. 이 현상의 명칭은?', '[{"time":"Day 1","open":490,"high":505,"low":485,"close":500,"volume":88},{"time":"Day 2","open":500,"high":510,"low":495,"close":505,"volume":120},{"time":"Day 3","open":505,"high":550,"low":500,"close":540,"volume":15},{"time":"Day 4","open":540,"high":545,"low":475,"close":480,"volume":19}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":510},{"x":3,"y":510}],"label":"저항선","color":"#ef4444"}]'::jsonb, ARRAY['진짜 상승 돌파 (True Breakout)', '불 트랩 (Bull Trap) - 매수자 청산 유도 가짜 돌파', '베어 트랩 (Bear Trap) - 매도자 청산 유도 가짜 하방', '골든 크로스 (Golden Cross) - 이평선 돌파']::text[], 1, '저항선을 일시적으로 뚫었다가 대량 매도세와 함께 직후 캔들에서 하방으로 원상복귀하는 현상을 ''불 트랩(Bull Trap/가짜 돌파)''이라고 합니다. 돌파 후 리테스트를 기다리지 않고 급히 추격 매수했던 투자자들이 고점에 물리는 대표적 함정입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (408, '시장구조/SR', '01_chart_market_basics.md', '아래 차트에서 3번 연속 강하게 반등하며 가격 하락을 저지해 준 주요 가격대는 무엇을 의미하나요?', '[{"time":"Day 1","open":500,"high":510,"low":450,"close":455,"volume":109},{"time":"Day 2","open":455,"high":490,"low":450,"close":485,"volume":114},{"time":"Day 3","open":485,"high":525,"low":480,"close":520,"volume":89},{"time":"Day 4","open":520,"high":530,"low":455,"close":460,"volume":109},{"time":"Day 5","open":460,"high":500,"low":450,"close":495,"volume":100}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":450},{"x":4,"y":450}],"label":"450달러선","color":"#10b981"}]'::jsonb, ARRAY['강력한 저항선 (Resistance Line) - 매도 매물대', '강력한 지지선 (Support Line) - 매수 매물대', '골든크로스 수렴선 - 이평선 밀집대', '이격도 붕괴선 - 가격 과열 분기점']::text[], 1, '특정 가격(450달러)에 접근할 때마다 대기 중이던 저가 매수세가 유입되어 테슬라 주가의 추가 하락을 방어해 준 이 라인은 ''강력한 지지선(Support Line)''입니다. 이탈하기 전까지는 손절 라인을 바로 밑에 두고 진입하기에 가장 손익비 좋은 구간입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (409, '거래량/유동성', '05_volume_liquidity.md', '지지선 아래로 테슬라 주가가 이탈하여 공매도가 폭증했으나, 이내 거래량이 급증하며 양봉으로 지지선을 회복한 뒤 반등을 시작했습니다. 이 현상의 명칭은?', '[{"time":"Day 1","open":600,"high":610,"low":590,"close":595,"volume":119},{"time":"Day 2","open":595,"high":600,"low":550,"close":555,"volume":115},{"time":"Day 3","open":555,"high":615,"low":550,"close":610,"volume":126}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":575},{"x":2,"y":575}],"label":"지지선","color":"#10b981"}]'::jsonb, ARRAY['불 트랩 (Bull Trap) - 가짜 상방 돌파', '베어 트랩 (Bear Trap) - 가짜 하방 이탈', '리테스트 실패 - 지지선 붕괴', '추세 추종 돌파 - 하방 랠리 가속']::text[], 1, '지지선을 아래로 뚫고 내려가 하락세가 지속될 것처럼 유도한 뒤, 매물을 털어내고 강력하게 다시 반등해 올리는 현상을 ''베어 트랩(Bear Trap)''이라고 합니다. 하락 돌파로 생각하고 공매도를 치거나 손절했던 사람들의 손실을 강제하며 가격이 급등하게 만듭니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (410, '시장구조/SR', '04_patterns_breakout.md', '저항선을 뚫어내기 직전 돌파 전조 현상 중 하나인 ''지지점 상승''의 특징을 골라보세요.', '[{"time":"Day 1","open":500,"high":525,"low":450,"close":510,"volume":93},{"time":"Day 2","open":510,"high":525,"low":465,"close":515,"volume":92},{"time":"Day 3","open":515,"high":525,"low":480,"close":520,"volume":90}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":525},{"x":2,"y":525}],"label":"저항선 (105)","color":"#ef4444"}]'::jsonb, ARRAY['저항선 부근에서 고점들이 점점 급락하며 붕괴하는 현상', '저항선 부근에서 저점들을 높여가며 밀어 올리는 수렴 현상', '거래량이 완전히 소멸하여 긴 횡보 상태를 보이는 현상', '지속적인 매도세로 인해 갑작스럽게 급락하는 현상']::text[], 1, '저항을 뚫지 못하고 밀려 내려올 때, 이전 저점보다 높은 지점에서 저점을 계속 잡아 올려주는 것은 매도 압력보다 매수 압력이 점점 올라오고 있음을 의미합니다. 수렴 끝에 돌파가 나타날 신뢰도가 매우 높습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (411, '추세/레짐', '03_market_structure.md', '저점들을 연결한 우상향 상승 추세선 아래로 캔들의 종가(마감가격)가 이탈했습니다. 기술적 분석 관점의 올바른 해석은 무엇입니까?', '[{"time":"W-5","open":500,"high":525,"low":500,"close":515,"volume":86},{"time":"W-4","open":515,"high":550,"low":510,"close":540,"volume":111},{"time":"W-3","open":540,"high":545,"low":525,"close":530,"volume":120},{"time":"W-2","open":530,"high":575,"low":535,"close":565,"volume":103},{"time":"Today","open":565,"high":570,"low":515,"close":520,"volume":107}]'::jsonb, '[{"type":"line","points":[{"x":0,"y":500},{"x":2,"y":525},{"x":4,"y":550}],"label":"상승 추세선","color":"#10b981"}]'::jsonb, ARRAY['추세선 이탈은 영향이 없으므로 비중 유지', '상승 추세 붕괴로 하락 반전 대비 비중 축소', '일시적인 속임수이므로 추가 불타기 진입', '채널 상단 도달에 따른 즉각적인 매수 대응']::text[], 1, '신뢰받던 우상향 상승 추세선 하방으로 캔들의 종가가 이탈 마감하는 것은 매수 중심의 시장 주도권이 붕괴했음을 뜻합니다. 지지를 잃은 하락 가속화 리스크에 대비해야 합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (412, '추세/레짐', '07_multitimeframe_regime.md', '아래 차트에서 고점들과 저점들이 일정한 평행 통로를 그리며 하락하고 있습니다. 채널 하단에 도달했을 때 단기 반등을 목표로 하는 매매의 명칭과 관점은?', '[{"time":"Day 1","open":750,"high":760,"low":675,"close":700,"volume":90},{"time":"Day 2","open":700,"high":735,"low":695,"close":725,"volume":118},{"time":"Day 3","open":725,"high":730,"low":640,"close":650,"volume":115},{"time":"Day 4","open":650,"high":690,"low":645,"close":680,"volume":122},{"time":"Day 5","open":680,"high":685,"low":590,"close":600,"volume":105}]'::jsonb, '[{"type":"channel","points":[{"x":0,"y":750},{"x":4,"y":675},{"x":0,"y":675},{"x":4,"y":600}],"label":"하향 평행 채널","color":"#f59e0b"}]'::jsonb, ARRAY['추세 추종 매매 - 대세 상승이므로 장기 보유', '채널 하단 반등 매매 - 단기 역추세 매수 대응', '양방향 물타기 매매 - 평단가를 낮춰 탈출 대기', '돌파 매매 - 채널 하방 붕괴 확정 시 매수 대응']::text[], 1, '가격이 평행한 하락 터널 내에서 움직이는 ''하향 평행 채널(Descending Channel)''입니다. 채널 하단 라인 터치 시에는 기술적 단기 반등이 자주 출현하므로, 손절선을 짧게 잡고 반등 타점을 노리는 역추세(Counter-trend) 트레이딩이 가능합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (413, '추세/레짐', '03_market_structure.md', '우상향 상승 평행 채널의 상단 저항선 부근까지 테슬라 주가가 도달했습니다. 합리적인 추세 채널 트레이더의 대응은?', '[{"time":"Day 1","open":500,"high":510,"low":495,"close":505,"volume":116},{"time":"Day 2","open":505,"high":540,"low":505,"close":535,"volume":123},{"time":"Day 3","open":535,"high":545,"low":520,"close":525,"volume":110},{"time":"Day 4","open":525,"high":575,"low":525,"close":570,"volume":112},{"time":"Day 5","open":570,"high":580,"low":560,"close":565,"volume":133}]'::jsonb, '[{"type":"channel","points":[{"x":0,"y":510},{"x":4,"y":575},{"x":0,"y":495},{"x":4,"y":560}],"label":"상승 평행 채널","color":"#10b981"}]'::jsonb, ARRAY['채널 상방 돌파를 예상한 고배율 레버리지 매수', '채널 상단 저항에 따른 분할 익절 및 대기', '채널 중간 조정 시 지정을 통한 시장가 추격', '채널 붕괴 신호에 따른 전량 기계적 손절']::text[], 1, '상승 채널이라고 해도 상단 저항선에 닿으면 다시 채널 하단이나 중심선까지 조정을 받을 가능성이 매우 큽니다. 따라서 고점 영역에서의 추격매수를 금지하고, 기존 포지션을 분할 익절하는 기회로 삼아야 합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (414, '추세/레짐', '01_chart_market_basics.md', '고점들을 잇는 우하향 하락 추세선을 테슬라 주가가 대량의 거래량을 동반하며 장대양봉 종가로 상향 돌파(Breakout)했습니다. 의미하는 시그널은?', '[{"time":"Day 1","open":650,"high":660,"low":625,"close":635,"volume":93},{"time":"Day 2","open":635,"high":640,"low":600,"close":610,"volume":106},{"time":"Day 3","open":610,"high":615,"low":575,"close":585,"volume":127},{"time":"Day 4","open":585,"high":640,"low":580,"close":635,"volume":124}]'::jsonb, '[{"type":"line","points":[{"x":0,"y":655},{"x":2,"y":610},{"x":3,"y":590}],"label":"하락 추세선","color":"#ef4444"}]'::jsonb, ARRAY['하락 추세 지속에 따른 숏 포지션 추가 매수', '하락 추세 돌파 및 상승 전환 가능성에 따른 매수', '속임수 돌파를 예상한 즉시 반대 숏 포지션 진입', '추세와 무관하게 횡보 흐름으로 판단해 관망']::text[], 1, '중요한 하락 추세선을 테슬라 주가 몸통이 확실하게 뚫고 마감하는 것은 기존 하락 관성의 지배력이 종료되고 상승 추세로 돌아설 수 있는 가장 대표적인 추세 전환(Reversal) 확인 시그널입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (415, '추세/레짐', '03_market_structure.md', '추세선 작도 시 신뢰도를 판단하는 가장 중요한 규칙은 무엇인가요?', '[{"time":"Day 1","open":500,"high":505,"low":500,"close":505,"volume":84},{"time":"Day 2","open":505,"high":525,"low":510,"close":520,"volume":114}]'::jsonb, '[]'::jsonb, ARRAY['차트상 선이 정배열로 정돈되어 그려질 때', '최소 3개 이상의 뚜렷한 저점/고점 터치 확인 시', '가파른 각도로 90도에 가깝게 작도될 때', '보조지표와 결합하여 수평으로 그려질 때']::text[], 1, '두 점만으로도 선을 그릴 수 있지만, 3번째 터치(3rd Touch)에서 정확한 지지나 저항을 보이고 반등해 주는 순간부터 시장 참여자들이 공식 인지하는 신뢰도 높은 추세선이 됩니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (416, '패턴/돌파', '04_patterns_breakout.md', '머리와 양쪽 어깨 형태를 그리며 넥라인 지지선(480달러)을 위태롭게 지탱하다가 하방으로 강한 캔들이 이탈했습니다. 숏(매도) 포지션 진입 시점은?', '[{"time":"Day 1","open":500,"high":575,"low":490,"close":550,"volume":114},{"time":"Day 2","open":550,"high":650,"low":475,"close":525,"volume":123},{"time":"Day 3","open":525,"high":570,"low":480,"close":550,"volume":117},{"time":"Day 4","open":550,"high":555,"low":465,"close":470,"volume":99}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":480},{"x":3,"y":480}],"label":"넥라인 지지선","color":"#ef4444"}]'::jsonb, ARRAY['머리 꼭대기(650달러) 부근에서 예측 숏 진입', '오른쪽 어깨가 올라가고 있을 때 돌파 전 선진입', '저점들을 연결한 넥라인의 하방 돌파 완료 시', '패턴 완성과 무관하게 오른쪽 어깨 끝에서 대기']::text[], 2, '헤드앤숄더(Head & Shoulders) 패턴은 오른쪽 어깨를 그린 후, 저점 지지선인 ''넥라인(Neckline)''을 거래량을 실어 하방 돌파해야 최종 완성이 선언됩니다. 그전에 진입하면 넥라인 반등 시 극심한 손실을 입습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (417, '패턴/돌파', '04_patterns_breakout.md', '하락 추세 끝에서 테슬라 주가가 비슷한 깊이의 바닥을 두 번(이중바닥) 형성한 뒤, 중간 고점 저항선(넥라인)을 돌파했습니다. 향후 예상 방향성과 매수 타점은?', '[{"time":"Day 1","open":500,"high":500,"low":400,"close":425,"volume":105},{"time":"Day 2","open":425,"high":475,"low":420,"close":470,"volume":90},{"time":"Day 3","open":470,"high":475,"low":395,"close":410,"volume":105},{"time":"Day 4","open":410,"high":495,"low":405,"close":490,"volume":120}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":475},{"x":3,"y":475}],"label":"넥라인 (95)","color":"#3b82f6"}]'::jsonb, ARRAY['추가 폭락 가능성에 따른 전량 손절 대응', 'W 패턴 이중 바닥 완성 및 넥라인 돌파 시 매수', '박스권 횡보 판단에 따른 무대응 및 관망', '이중 바닥의 하방 이탈을 예상한 숏 포지션 진입']::text[], 1, 'W자 모양의 ''이중 바닥형(Double Bottom)'' 패턴입니다. 테슬라 주가가 하락을 멈추고 바닥을 두 차례 단단히 지지해 준 뒤 중간 봉우리(넥라인 475달러)를 돌파해 마감하면 추세가 상승으로 강하게 전환될 가능성이 매우 높습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (418, '패턴/돌파', '04_patterns_breakout.md', '급격한 기둥식 테슬라 주가 폭등(깃대) 후, 완만한 하향 평행 채널(깃발) 모양으로 횡보/수렴하다가 채널 상단을 강하게 돌파했습니다. 이 패턴과 예상 목표가는?', '[{"time":"Day 1","open":250,"high":400,"low":245,"close":390,"volume":102},{"time":"Day 2","open":390,"high":395,"low":360,"close":370,"volume":87},{"time":"Day 3","open":370,"high":380,"low":350,"close":355,"volume":106},{"time":"Day 4","open":355,"high":425,"low":350,"close":415,"volume":119}]'::jsonb, '[]'::jsonb, ARRAY['이중 천정형 패턴 - 고점 도달 시 숏 진입', '불 플래그 패턴 - 깃발 돌파 시 추가 상승 기대', '헤드앤숄더 패턴 - 넥라인 하방 돌파 타겟', '대칭 삼각수렴 패턴 - 변동성 축소 후 돌파 대기']::text[], 1, '대표적 강세 지속 패턴인 ''불 플래그(Bull Flag)''입니다. 급격한 상승(깃대) 뒤 숨 고르기 채널(깃발)을 상방 돌파하면, 이전 상승 파동의 크기(깃대 높이)만큼 추가로 수직 랠리를 시작하는 관성이 있습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (419, '패턴/돌파', '04_patterns_breakout.md', '상승 추세의 천정권에서 테슬라 주가가 동일한 가격 저항을 두 번 확인하며 M자 모양을 만든 뒤, 두 고점 사이의 저점 지지선인 넥라인(600달러)을 이탈했습니다. 올바른 해석은?', '[{"time":"Day 1","open":500,"high":700,"low":495,"close":675,"volume":91},{"time":"Day 2","open":675,"high":680,"low":600,"close":610,"volume":95},{"time":"Day 3","open":610,"high":700,"low":605,"close":690,"volume":89},{"time":"Day 4","open":690,"high":695,"low":575,"close":580,"volume":116}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":600},{"x":3,"y":600}],"label":"넥라인 (120)","color":"#ef4444"}]'::jsonb, ARRAY['상승 추세의 지속 연장에 따른 추가 매수', '이중 천정형(M 패턴) 완성에 따른 하락 반전 대비', '단기 조정에 따른 일시적 횡보 박스권 진입', '방향성 없는 일상적인 잔파동으로 판단해 홀딩']::text[], 1, '고점에서 지지받지 못하고 형성된 M자형 ''이중 천정형(Double Top)'' 패턴입니다. 두 차례 강력한 저항벽(700달러)을 넘지 못하고 넥라인(600달러)마저 붕괴했으므로 하방 추세가 가속화된다는 신호입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (420, '패턴/돌파', '04_patterns_breakout.md', '고점 저항선은 수평(평평함)을 유지하고 있으나, 저점 지지선은 점점 우상향하며 좁게 수렴하는 차트 형태의 명칭과 일반적인 돌파 방향은?', '[{"time":"Day 1","open":400,"high":500,"low":400,"close":475,"volume":86},{"time":"Day 2","open":475,"high":500,"low":430,"close":490,"volume":96},{"time":"Day 3","open":490,"high":500,"low":460,"close":495,"volume":97}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":500},{"x":2,"y":500}],"label":"수평 저항선","color":"#ef4444"},{"type":"line","points":[{"x":0,"y":400},{"x":1,"y":430},{"x":2,"y":460}],"label":"상승 지지선","color":"#10b981"}]'::jsonb, ARRAY['디센딩 트라이앵글 - 일반적으로 하방 돌파 기대', '어센딩 트라이앵글 - 매수 압력 우위로 상방 돌파 기대', '헤드앤숄더 패턴 - 넥라인 하방 돌파 기대', '상향 평행 채널 - 상하단 터치식 채널 매매 기대']::text[], 1, '고점 저항은 평평하고 저점은 계속 높아지는 삼각수렴을 ''어센딩 트라이앵글(Ascending Triangle)''이라고 합니다. 위로 갈수록 저점이 계속 올라가는 현상은 매수세가 가격을 위로 계속 압박하고 있음을 증명하며, 대개 저항선(500달러)을 상향 뚫고 오르는 확률이 높습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (421, '지표/컨플루언스', '06_technical_indicators.md', '테슬라 주가는 매일 하락하여 신저가를 갱신하고 있으나, RSI 보조지표의 저점은 점점 높아지는 현상을 발견했습니다. 올바른 용어와 매매 대응법은?', '[{"time":"D-4","open":550,"high":560,"low":490,"close":500,"volume":108},{"time":"D-3","open":500,"high":520,"low":480,"close":490,"volume":120},{"time":"D-2","open":490,"high":505,"low":460,"close":470,"volume":126},{"time":"D-1","open":470,"high":485,"low":465,"close":480,"volume":104},{"time":"Today","open":480,"high":495,"low":475,"close":490,"volume":126}]'::jsonb, '[]'::jsonb, ARRAY['하락 다이버전스 - 가격 상승 둔화에 따른 공매도', '상승 다이버전스 - 하락 둔화 및 반등 신호로 매수', '데드 크로스 - 이평선 하방 교차에 따른 관망', '과매수 이탈 시그널 - 단기 반등에 따른 매수']::text[], 1, '테슬라 주가의 가격 저점은 낮아지나 보조지표(RSI)의 운동 저점이 높아지는 현상을 ''상승 다이버전스(Bullish Divergence)''라고 합니다. 이는 하방 에너지의 실질적 소멸과 상승 압력의 내부 응축을 의미하는 기술적 분석에서 가장 신뢰도 높은 추세 전환 시그널입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (422, '지표/컨플루언스', '06_technical_indicators.md', '테슬라 주가는 급격히 치솟으며 최고가 갱신 랠리를 이어가고 있으나, RSI 지표의 고점은 계속 낮아지고 있습니다. 이 현상을 지칭하는 명칭과 대처법은?', '[{"time":"Day 1","open":500,"high":600,"low":495,"close":590,"volume":106},{"time":"Day 2","open":590,"high":610,"low":575,"close":600,"volume":92},{"time":"Day 3","open":600,"high":675,"low":595,"close":665,"volume":123}]'::jsonb, '[]'::jsonb, ARRAY['하락 다이버전스 - 매수 둔화 및 하락 우려로 익절', '상승 다이버전스 - 추가 급등 기대로 신규 매수', '골든 크로스 - 추세 강화에 따른 홀딩', '볼린저 밴드 스퀴즈 - 변동성 수축 후 돌파']::text[], 0, '테슬라 주가는 계속 고점을 높이고 있으나 보조지표의 고점은 꺾여 낮아지는 현상을 ''하락 다이버전스(Bearish Divergence)''라고 합니다. 이는 매수세의 힘이 표면적인 가격 상승에 비해 실질적으로 빠르게 축소되고 있음을 경고하며, 조만간 큰 급락이 발생할 확률이 높습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (423, '지표/컨플루언스', '06_technical_indicators.md', '이동평균선(EMA) 20일선(단기)이 50일선(중기)을 아래에서 위로 강하게 뚫고 솟구쳐 올랐습니다. 이 교차 현상의 정식 명칭은?', '[{"time":"Day 1","open":500,"high":510,"low":490,"close":495,"volume":90},{"time":"Day 2","open":495,"high":520,"low":495,"close":515,"volume":84},{"time":"Day 3","open":515,"high":550,"low":515,"close":545,"volume":89}]'::jsonb, '[]'::jsonb, ARRAY['데드 크로스 - 단기 이평의 하방 교차로 매도 신호', '골든 크로스 - 단기 이평의 상방 교차로 매수 신호', '볼린저 스퀴즈 - 변동성 수축 및 돌파 신호', '다이버전스 수렴 - 지표와 가격의 동반 횡보']::text[], 1, '단기 이평선이 장기 이평선을 위로 치고 올라가는 현상을 ''골든 크로스(Golden Cross)''라고 합니다. 이는 최근 매수 평단가가 장기 평균가보다 확연히 높아졌음을 시사하며, 상승 추세가 본 궤도에 올랐음을 입증해 줍니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (424, '지표/컨플루언스', '07_multitimeframe_regime.md', '매우 강력한 원웨이 폭락장 속에서 RSI 지표가 20(과매도 영역) 이하로 깊이 내려왔습니다. 이를 보고 ''과매도 반등''을 노리며 기계적 시장가 풀매수를 때렸을 때 나타나는 가장 빈번한 오류는?', '[{"time":"Day 1","open":500,"high":505,"low":440,"close":445,"volume":111},{"time":"Day 2","open":445,"high":450,"low":375,"close":380,"volume":34},{"time":"Day 3","open":380,"high":385,"low":310,"close":315,"volume":17}]'::jsonb, '[]'::jsonb, ARRAY['하락 추세 즉시 종료 및 V자 상승 반등 성공', '강력한 하락장에서의 지표 과매도 고착화 리스크', '거래량 급감으로 인한 호가 정지 및 상장 폐지', '테슬라 주가의 즉각적인 박스권 횡보 및 변동성 축소']::text[], 1, 'RSI 30 이하 과매도 영역은 반등 신호이기도 하지만, 추세가 지나치게 강력한 하락장일 때는 지표만 과매도 구역에 쳐박힌 채 가격은 계속 급락하는 ''과매도 고착화(Oversold Embedded)'' 상태가 이어집니다. 다이버전스나 캔들 반전형 확인 없이 수치만 보고 들어가는 매수는 깡통으로 가는 지름길입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (425, '지표/컨플루언스', '06_technical_indicators.md', '테슬라 주가의 변동성이 극도로 축소되며 볼린저 밴드의 폭이 매우 좁아지는 ''스퀴즈(Squeeze)'' 현상이 나타났습니다. 이후 기대되는 시장 변동성의 원리는 무엇인가요?', '[{"time":"Day 1","open":500,"high":505,"low":495,"close":500,"volume":118},{"time":"Day 2","open":500,"high":500,"low":495,"close":495,"volume":121},{"time":"Day 3","open":495,"high":500,"low":495,"close":500,"volume":103}]'::jsonb, '[]'::jsonb, ARRAY['변동성 사멸로 인한 장기 횡보 및 거래 정지', '밴드 스퀴즈 후 변동성 팽창에 따른 추세 분출', '테슬라 주가의 하방 붕괴로 인한 강한 하락 파동 시작', '이평선들의 수평 정렬에 따른 완전한 추세 고정']::text[], 1, '볼린저 밴드의 수축(Squeeze)은 시장의 숨 고르기 및 힘 모으기를 뜻합니다. 에너지가 최대한 압축된 후에는 밴드 상단 혹은 하단선을 이탈하며 매우 거대한 변동성 팽창(Expansion) 추세가 시작되므로, 방향성을 유심히 지켜봐야 합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (426, '리스크/심리', '09_risk_position_management.md', '총 투자 원금은 5,000만 원이며, 1회 거래 시 최대 손실 허용액을 원금의 2%(100만 원)로 제한하는 ''2% 룰''을 지키려 합니다. 진입하려는 종목의 손절 라인 폭이 -5%일 때, 최대 매수(진입) 가능 금액은 얼마인가요?', '[{"time":"Day 1","open":50000,"high":52500,"low":49000,"close":51000,"volume":96},{"time":"Day 2","open":51000,"high":51500,"low":50000,"close":50000,"volume":90}]'::jsonb, '[]'::jsonb, ARRAY['5,000만 원 (원금 전액 진입)', '1,000만 원 (원금의 20% 진입)', '2,000만 원 (원금의 40% 진입)', '2,500만 원 (원금의 50% 진입)']::text[], 2, '2% 룰에 기초한 포지션 사이징 공식은 `진입금액 = (총원금 * 리스크비율) / 손절비율` 입니다. 따라서 `100만 원 / 0.05 = 2,000만 원`이 됩니다. 2,000만 원어치 해외 주식을 샀을 때 가격이 -5% 떨어져 강제 손절을 맞아도 내 계좌 총액에서 손실을 보는 돈은 정확히 2%인 100만 원으로 통제됩니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (427, '리스크/심리', '09_risk_position_management.md', '어느 해외 주식에 50,000원에 매수 진입합니다. 손절 라인은 47,500원(-5%)에 배치하고, 목표가는 57,500원(+15%)에 설정했습니다. 이 트레이딩 시나리오의 손익비(Risk-to-Reward Ratio)는 얼마입니까?', '[{"time":"Today","open":50000,"high":50000,"low":50000,"close":50000}]'::jsonb, '[]'::jsonb, ARRAY['1 : 1 (동일한 기대 수익과 리스크)', '1 : 2 (기대 수익이 리스크의 2배)', '1 : 3 (기대 수익이 리스크의 3배)', '2 : 1 (기대 수익이 리스크의 0.5배)']::text[], 2, '손절 폭(2,500원) 대비 익절 폭(7,500원)의 비례를 의미하므로 `1,500 / 500 = 3`, 즉 손익비는 1:3이 됩니다. 이처럼 잃는 돈의 최소 2~3배를 벌 수 있는 손익비 높은 구간만 반복적으로 거래해야 장기적으로 계좌가 생존합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (428, '리스크/심리', '09_risk_position_management.md', '손익비를 엄격히 통제하여 항상 기대 손실의 2배를 버는 매매(손익비 1:2)만 고집합니다. 이 경우 내 계좌 잔고가 손실 없이 제자리걸음(본전)을 유지하기 위해 필요한 수학적인 최소 승률(Win Rate)은 얼마인가요?', '[{"time":"Today","open":500,"high":500,"low":500,"close":500}]'::jsonb, '[]'::jsonb, ARRAY['50.0% (최소 절반 이상 성공)', '33.3% (3번 중 1번 성공으로 본전)', '25.0% (4번 중 1번 성공으로 본전)', '66.6% (3번 중 2번 성공으로 본전)']::text[], 1, '손익비가 1:2일 경우, 1번 이기면 +2를 벌고 2번 지면 -2를 잃으므로 3번 매매 중 1번만 이겨도 누적 수익은 0이 됩니다. 즉 손익비를 1:2 이상으로 유지하면 수학적으로 승률이 겨우 33.3%만 나와도 절대 파산하지 않고 계좌가 우상향할 발판이 마련됩니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (429, '셋업/실행', '08_setup_entry_exit.md', '50,000원에 산 해외 주식이 75,000원까지 올랐습니다. 이익을 보존하면서 상승세를 끝까지 타기 위해, 최고점 대비 10% 하방 이탈 시 즉시 자동 익절되는 ''추적 손절매(Trailing Stop)''를 적용했습니다. 최고점 75,000원 달성 후 테슬라 주가가 조정받을 때 실제로 청산(익절)되는 가격은 얼마인가요?', '[{"time":"Day 1","open":50000,"high":60000,"low":49500,"close":59500,"volume":116},{"time":"Day 2","open":59500,"high":75000,"low":59000,"close":74000,"volume":101}]'::jsonb, '[]'::jsonb, ARRAY['50,000원 (본전 수준 청산)', '67,500원 (최고점 대비 10% 하방 청산)', '70,000원 (최고점 대비 6.6% 하방 청산)', '60,000원 (최고점 대비 20% 하방 청산)']::text[], 1, '추적 손절매(Trailing Stop)는 가격 상승에 따라 청산 가격을 자동으로 올려주는 주문입니다. 최고점 75,000원을 기록했으므로 청산 트리거 라인은 최고점에서 10% 차감된 `15,000 * 0.9 = 67,500원`으로 확정 셋업되며, 테슬라 주가가 67,500원을 건드리는 순간 자동 이익실현됩니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (430, '리스크/심리', '09_risk_position_management.md', '레버리지 10배를 적용하여 테슬라 롱(매수) 포지션을 구축했습니다. 만약 테슬라 가격이 매수가 대비 몇 % 역방향으로 등락하면 내 투자 원금이 100% 강제 청산(증거금 완전 소멸)당할까요?', '[{"time":"Today","open":250000,"high":250500,"low":249500,"close":250000}]'::jsonb, '[]'::jsonb, ARRAY['5.0% 하락 시', '10.0% 하락 시', '20.0% 하락 시', '100.0% 하락 시']::text[], 1, '레버리지 비율과 청산 거리 비율은 역수 관계입니다. `100% / 레버리지 배수` 공식에 따라, 10배 레버리지는 테슬라 주가가 내 베팅의 반대 방향으로 단 10%만 움직여도 투자 원금이 전부 증발하고 포지션이 강제 종료(Liquidation)됩니다. 고배율 레버리지가 파산의 지름길인 이유입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (431, '캔들/가격행동', '02_candlestick_price_action.md', '상승 추세 고점 영역(750달러선)에서 몸통이 매우 작고 아래꼬리가 긴 행잉맨(Hanging Man) 캔들이 출현한 이후, 다음 날 시가가 전일 종가보다 큰 갭을 그리며 낮게 하락 출발(725달러)했습니다. 포지션을 보유한 스윙 트레이더로서 가장 적절한 위기 대응 행동은 무엇입니까?', '[{"time":"Day 1","open":600,"high":625,"low":595,"close":620,"volume":119},{"time":"Day 2","open":620,"high":675,"low":615,"close":670,"volume":103},{"time":"Day 3","open":670,"high":740,"low":665,"close":730,"volume":117},{"time":"Day 4","open":730,"high":755,"low":700,"close":735,"volume":122},{"time":"Day 5","open":705,"high":715,"low":675,"close":680,"volume":111}]'::jsonb, '[]'::jsonb, ARRAY['상승 랠리를 기대로 보유 비중 확대 및 추격 매수', '일시적 속임수(휩소) 판단으로 추가 레버리지 매수', '행잉맨 출현 후 갭하락에 따른 전량 또는 일부 정리', '조치 없이 전고점 돌파 시까지 무기한 관망 및 홀딩']::text[], 2, '고가권에서 나타난 행잉맨(Hanging Man)은 잠재적 하락 전환 신호이며, 특히 다음날 갭하락 음봉으로 직전 행잉맨의 저가를 깨고 내려가는 움직임은 강력한 하락 컨펌 시그널입니다. 따라서 이 시점에서는 즉시 비중을 전량 정리하거나 최소 절반 이상 매도하여 리스크를 통제하는 것이 정석입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (432, '캔들/가격행동', '01_chart_market_basics.md', '지속적인 하락 추세 도중 바닥권(400달러선)에서 시가와 종가가 일치하고 긴 아래꼬리를 단 십자 형태의 도지(Doji) 캔들이 생성되었습니다. 다음 날 대량의 거래량과 함께 장대양봉이 솟구치며 435달러로 마감하는 샛별형(Morning Star) 조합이 확정되었습니다. 이때 가장 합리적인 매수 진입 지점과 손절가 기준은 무엇입니까?', '[{"time":"Day 1","open":500,"high":505,"low":465,"close":470,"volume":90},{"time":"Day 2","open":470,"high":475,"low":440,"close":445,"volume":95},{"time":"Day 3","open":445,"high":450,"low":400,"close":405,"volume":96},{"time":"Day 4","open":400,"high":410,"low":375,"close":400,"volume":93},{"time":"Day 5","open":400,"high":440,"low":395,"close":435,"volume":133}]'::jsonb, '[]'::jsonb, ARRAY['손절 없이 100% 비중으로 시장가 매수', '샛별형 완성에 따라 분할 매수 후 최저점 손절 셋업', '바닥 도달 기대로 주문 없이 무작정 대기', '상승 꼭대기에서 숏 진입 후 손절 없이 방치']::text[], 1, '하락 추세 끝에 도지와 장대양봉이 결합된 샛별형(Morning Star)은 매우 신뢰도 높은 바닥 상승 전환 신호입니다. 이 패턴을 보고 진입할 때는 반등 상승세에 분할 매수로 동참하되, 바닥을 잡아준 도지 캔들의 최저점(375달러) 아래를 최종 손절 라인으로 잡는 것이 수학적으로 가장 리스크 대비 보상 비율(손익비)이 훌륭한 전략입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (433, '거래량/유동성', '02_candlestick_price_action.md', '테슬라 주가가 강력한 횡보 박스권 고점(1,000달러 저항선)에 세 번째 터치하는 와중에, 윗꼬리가 길고 몸통이 매우 얇은 유성형(Shooting Star) 캔들이 이틀 연속 발생했습니다. 거래량 역시 저항선 부근에서 매수세가 더 올라가지 못하고 매도 압력이 실려 나타났습니다. 롱(매수) 포지션을 들고 있는 당신의 합리적인 의사결정은?', '[{"time":"Day 1","open":875,"high":925,"low":870,"close":910,"volume":101},{"time":"Day 2","open":910,"high":975,"low":900,"close":965,"volume":122},{"time":"Day 3","open":965,"high":1010,"low":950,"close":955,"volume":101},{"time":"Day 4","open":955,"high":1005,"low":940,"close":945,"volume":106}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":1000}],"label":"박스권 상단 저항선 (200)","color":"#ef4444"}]'::jsonb, ARRAY['신고가 갱신을 예상한 전재산 추가 불타기', '저항 돌파 실패 신호 확인 후 분할 익절 및 관망', '손익 평단가 부근이므로 추가 손절 없이 방치', '거래를 종료하고 다른 신규 급등주를 시장가 추격']::text[], 1, '박스권 상단 저항선(1,000달러)에 부딪히며 나타난 유성형(Shooting Star) 연속 출현은 저항 돌파 실패와 차익 실현 세력의 강력한 등장을 경고하는 캔들 신호입니다. 돌파를 확신하기보다는 리스크 관리 관점에서 물량을 축소(50% 분할 익절)하거나 전량 매도하여 이익을 확정 짓는 것이 현명합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (434, '캔들/가격행동', '02_candlestick_price_action.md', '극심한 하락 추세 중 500달러선 아래로 떨어지던 테슬라 주가가 전일 장대음봉을 형성했습니다. 그러나 당일 시가는 갭하락하여 더 낮게 시작했으나, 장중에 강한 매수세가 들어오며 전일 음봉 몸통의 정확히 70% 라인(465달러선) 위로 덮어버리는 관통형(Piercing Line) 상승 캔들로 마감했습니다. 종가 매수(롱) 진입 시 원칙 대응은?', '[{"time":"Day 1","open":550,"high":555,"low":520,"close":525,"volume":88},{"time":"Day 2","open":525,"high":530,"low":485,"close":490,"volume":106},{"time":"Day 3","open":460,"high":505,"low":455,"close":500,"volume":95}]'::jsonb, '[]'::jsonb, ARRAY['상승 모멘텀 미달로 매수 보류 및 하방 숏 포지션 진입', '관통형 확인 후 분할 매수 및 당일 최저점 손절 설정', '손절 라인 설정 없이 100% 비중 시장가 매수 집행', '조정을 대기하며 예약 주문 없이 무작정 관망 유지']::text[], 1, '전일 음봉의 50% 이상을 당일 양봉 몸통으로 관통해 올린 ''관통형(Piercing Line)''은 하락 모멘텀이 쇠퇴하고 저가 매수세가 우위를 점하기 시작했음을 뜻하는 바닥 신호입니다. 이 패턴 확인 후 진입할 시에는 손절 한도를 당일 최저점(455달러) 밑에 가깝게 설정할 수 있어 매우 유리한 리스크 대비 기대수익 매매가 성립됩니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (435, '캔들/가격행동', '05_volume_liquidity.md', '강한 급등세를 지속하던 테슬라 주가가 최고점에서 큰 거래량을 터뜨리며 장대양봉을 만들었습니다. 그러나 다음 날, 전일 양봉 몸통의 한가운데 범위 안에서 움직이며 시가와 종가가 모두 갇혀버리는 짧은 음봉인 ''하락 잉태형(Bearish Harami)'' 캔들이 형성되었습니다. 단기 스윙 트레이더로서 당신의 포지션 리스크 관리 행동은?', '[{"time":"Day 1","open":600,"high":640,"low":595,"close":635,"volume":91},{"time":"Day 2","open":635,"high":690,"low":630,"close":680,"volume":106},{"time":"Day 3","open":665,"high":670,"low":650,"close":655,"volume":97}]'::jsonb, '[]'::jsonb, ARRAY['상승 둔화 조짐에 따른 보유 물량 50% 분할 익절', '추세 일시 조정으로 간주하여 비중 확대 추가 매수', '추세 종결 판단에 따른 고배율 숏 포지션 즉시 진입', '이익 실현 없이 전량 장기 보유 전략 유지']::text[], 0, '하락 잉태형(Bearish Harami)은 이전의 강한 상승 추세 동력이 감속하기 시작했으며, 매도 압력이 힘을 기르고 있음을 암시하는 변곡 캔들입니다. 따라서 단기 스윙 트레이더는 물량의 일부(50%)를 분할 익절하여 리스크를 낮추고, 다음 캔들에서 이전 양봉 저점을 깨뜨리는 하락 하방 이탈이 추가되는지 지켜보는 것이 정석입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (436, '시장구조/SR', '03_market_structure.md', '오랫동안 지켜지던 핵심 지지선인 500달러 부근에서 매수 진입을 완료했습니다. 그러나 가격이 대량의 거래량을 동반하며 장대음봉으로 지지선을 하방으로 강하게 뚫어냈고, 종가가 지지선 대비 1.5% 아래인 98.25달러로 결정되었습니다. 이 상황에서 원칙을 지키는 올바른 위기 대응 행동은?', '[{"time":"Day 1","open":525,"high":540,"low":510,"close":515,"volume":101},{"time":"Day 2","open":515,"high":520,"low":495,"close":500,"volume":88},{"time":"Day 3","open":500,"high":505,"low":490,"close":492.5,"volume":92}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":500}],"label":"중요 지지선 (100)","color":"#10b981"}]'::jsonb, ARRAY['추가 물타기를 위해 자금을 동원하여 평단가 관리', '중요 지지선 붕괴(Breakdown) 확인 후 즉시 전량 손절', '지속 하락 시 추가 평단가 관리를 위해 매수 유보', '하방 이탈 시 즉시 반대 고배율 롱 포지션 진입']::text[], 1, '거래량이 동반된 장대음봉으로 주요 지지선 아래에서 종가가 결정되는 이탈 마감은 매수 지지 세력의 패배이자 추세 붕괴(Breakdown)의 신호입니다. 이 시점에서 물타기를 하거나 존버를 하면 파산적인 하락 조정을 겪을 수 있으므로 즉시 룰에 근거한 ''전량 손절''을 집행해야 계좌를 살릴 수 있습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (437, '시장구조/SR', '03_market_structure.md', '750달러의 중요 저항선이 강한 거래량을 실은 돌파봉으로 뚫렸습니다. 이후 테슬라 주가가 숨 고르기 조정을 받으며 750달러 부근까지 되돌아왔고(리테스트 구간), 저항선 부근에서 거래량이 크게 감소하며 아래꼬리가 달린 도지 캔들로 안착하는 모습을 보입니다. 이때 가장 안전하고 합리적인 매매 조치는?', '[{"time":"Day 1","open":700,"high":730,"low":695,"close":720,"volume":96},{"time":"Day 2","open":720,"high":785,"low":715,"close":775,"volume":102},{"time":"Day 3","open":775,"high":780,"low":745,"close":750,"volume":97}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":750}],"label":"돌파된 저항선 -> 지지선 전환선 (150)","color":"#3b82f6"}]'::jsonb, ARRAY['가짜 돌파(휩소) 판단에 따른 고배율 숏 진입', '돌파 후 리테스트 성공 확인 시 지지선 눌림목 매수', '추격 매수 기회 상실로 판단하고 거래 포기', '800달러 추가 돌파를 타겟으로 시장가 추격 매수']::text[], 1, '강하게 돌파된 저항선은 룰 체인지에 의해 지지선으로 변합니다(역할 전환). 돌파 당시 추격 매수하기보다, 돌파된 선(750달러)으로 테슬라 주가가 되돌아오는 리테스트(Retest) 시점에 저조한 거래량과 지지 캔들을 확인하고 손절선을 바로 밑에 설정하여 눌림목 진입하는 것이 리스크가 가장 적은 프로 트레이더의 정석입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (438, '시장구조/SR', '03_market_structure.md', '가격이 400달러 지지선 근처에서 반등을 시도하고 있으나, 반등의 폭이 직전 고점에 턱없이 못 미치며 저점 부근으로 다시 짓눌리고 있습니다. 즉, 고점들이 계속 낮아지는 하락 우위 삼각수렴(Descending)의 형태가 지지선 바로 위에서 감지됩니다. 이 시점에서 지지선 반등을 믿고 신규 매수(롱)를 진입하는 것은 원칙에 맞습니까?', '[{"time":"Day 1","open":475,"high":490,"low":400,"close":440,"volume":108},{"time":"Day 2","open":440,"high":455,"low":400,"close":420,"volume":103},{"time":"Day 3","open":420,"high":430,"low":400,"close":405,"volume":115}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":400}],"label":"지지선 (80)","color":"#10b981"}]'::jsonb, ARRAY['삼중 바닥 지지로 판단하고 매수 비중 대폭 확대', '디센딩 수렴 확인 후 하방 이탈 위험 대비 관망', '물타기 평단가 관리를 위해 매수 보증금 추가 투입', '추세와 무관하게 숏 포지션으로 전환 후 무기한 보유']::text[], 1, '지지선 부근에서 고점이 점점 낮아지는 ''디센딩'' 형태는 매수 지원 강도가 둔화되고 매도 출하 공급이 가격을 계속 하방으로 압박하고 있음을 증명합니다. 지지 성공보다 지선 하방 붕괴 후 급락할 확률이 높으므로, 지지선이라는 명목만으로 함부로 매수 진입하지 말고 돌파/이탈 컨펌을 기다려 관망하는 것이 현명합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (439, '거래량/유동성', '05_volume_liquidity.md', '테슬라 주가가 600달러의 장기 저항벽을 거래량이 거의 실리지 않은 얇은 양봉으로 상방으로 살짝 뚫었으나, 바로 다음 날 직전 양봉 몸통을 통째로 덮어버리는 대량 거래량의 장대음봉이 출현하며 580달러로 곤두박질쳤습니다. 매수 포지션을 추격 진입했던 당신의 올바른 조치는?', '[{"time":"Day 1","open":560,"high":590,"low":555,"close":585,"volume":115},{"time":"Day 2","open":585,"high":610,"low":580,"close":605,"volume":347},{"time":"Day 3","open":605,"high":610,"low":575,"close":580,"volume":375}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":600}],"label":"장기 저항선 (120)","color":"#ef4444"}]'::jsonb, ARRAY['불 트랩(Bull Trap) 확인 후 추가 하락 방지 즉시 손절', '저항선 부근 매수세 복귀를 기대하며 전량 홀딩', '평단가 관리 차원에서 추가 물타기 매수 집행', '상황을 판단하기 위해 시장가로 추가 분할 진입']::text[], 0, '거래량 없는 돌파 직후에 거래량 실린 강한 음봉이 기존 돌파선(600달러) 아래로 재진입하여 마감하는 현상은 전형적인 불 트랩(Bull Trap/가짜 돌파) 함정입니다. 돌파 당시 샀던 매수자들의 패닉 셀이 출현하며 하락 가속화가 나오기 쉬우므로 즉시 손절하여 물량을 털어내야 생존할 수 있습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (440, '시장구조/SR', '10_psychology_routine_review.md', '주요 지지선(1,250달러선)이 아래로 무너질 때 제때 손절 처리를 하지 못해 테슬라 주가가 1,100달러선까지 끌려 내려갔습니다. 다행히 단기 매도 진정세로 반등이 나와 테슬라 주가가 다시 1,250달러 부근까지 상승하여 회복을 눈앞에 두고 있습니다. 이때 손실을 최소화하는 현명한 시나리오 대처법은?', '[{"time":"Day 1","open":1300,"high":1310,"low":1240,"close":1245,"volume":109},{"time":"Day 2","open":1245,"high":1250,"low":1100,"close":1110,"volume":86},{"time":"Day 3","open":1110,"high":1175,"low":1105,"close":1170,"volume":120},{"time":"Day 4","open":1170,"high":1255,"low":1165,"close":1245,"volume":116}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":1250}],"label":"붕괴된 지지선 -> 저항선으로 변형 (250)","color":"#ef4444"}]'::jsonb, ARRAY['역할 전환(저항선) 도달에 따른 탈출 및 현금화', 'V자 반등 성공 확신에 따른 추가 매수 비중 확대', '원금 회복 및 추가 수익 시까지 영구 홀딩 관망', '하락 추세 지속에 따른 반대 숏 포지션 스위칭']::text[], 0, '하방으로 깨진 지지선은 반등할 때 가장 뚫기 힘든 ''강력한 저항선''으로 성격이 바뀝니다. 따라서 손절 기회를 놓치고 물려있던 트레이더는 반등하여 옛 지지선(1,250달러)에 도달했을 때를 ''최선의 리스크 탈출 기회(탈출구)''로 삼아 전량 매도하거나 비중을 극도로 덜어내야 다가올 2차 하락 파동의 파산을 막을 수 있습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (441, '추세/레짐', '03_market_structure.md', '테슬라 주가가 매우 가파르게 올라가던 1차 단기 상승 추세선을 강한 음봉 종가로 뚫고 내려왔습니다. 다행히 각도가 완만하고 탄탄한 장기 핵심 상승 추세선은 저 밑에 지지 영역을 유지하고 있습니다. 스윙 트레이더로서 가장 정석적인 포지션 제어 방식은 무엇인가요?', '[{"time":"Day 1","open":500,"high":510,"low":500,"close":510,"volume":81},{"time":"Day 2","open":510,"high":550,"low":510,"close":545,"volume":120},{"time":"Day 3","open":545,"high":625,"low":545,"close":620,"volume":88},{"time":"Day 4","open":620,"high":625,"low":570,"close":575,"volume":128}]'::jsonb, '[{"type":"line","points":[{"x":0,"y":500},{"x":3,"y":615}],"label":"가파른 단기 추세선 (붕괴)","color":"#ef4444"},{"type":"line","points":[{"x":0,"y":500},{"x":3,"y":550}],"label":"완만한 장기 추세선 (지탱 중)","color":"#10b981"}]'::jsonb, ARRAY['추세 붕괴 판단에 따른 전량 손절 및 영구 이탈', '가속 추세 이탈에 따른 50% 분할 익절 및 분산', '단기 지지선 붕괴를 무시한 고배율 물타기 매수', '장기 추세선까지 조정을 대비한 신규 매수 대기']::text[], 1, '가파르게 우상향하던 가속 추세선(Accelerated Trendline)이 하방 돌파되는 것은 기존 폭등 랠리의 속도가 둔화되고 완만한 본래 장기 추세선(장기 매물대)을 향해 정상적인 가격 조정을 받기 시작했음을 뜻합니다. 따라서 물량의 50%가량을 털어 수익을 실현하고 남은 물량으로 장기 추세선의 3rd Touch 지지 성공 여부를 테스트하는 것이 리스크 관리의 기본입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (442, '거래량/유동성', '05_volume_liquidity.md', '고점과 저점이 연속으로 낮아지는 명확한 하락 평행 채널 내에서 하락 압력을 받아 숏(매도) 포지션을 잡고 수익 중이었습니다. 그런데 당일 캔들이 대량의 거래량과 함께 장대양봉을 그리며 채널 상단 저항선 위로 종가 안착(상방 돌파)했습니다. 숏 포지션을 쥔 당신의 결단은?', '[{"time":"Day 1","open":500,"high":510,"low":450,"close":460,"volume":102},{"time":"Day 2","open":460,"high":470,"low":410,"close":415,"volume":93},{"time":"Day 3","open":415,"high":425,"low":375,"close":380,"volume":125},{"time":"Day 4","open":380,"high":450,"low":375,"close":445,"volume":105}]'::jsonb, '[{"type":"channel","points":[{"x":0,"y":510},{"x":3,"y":430},{"x":0,"y":450},{"x":3,"y":380}],"label":"하락 평행 채널 상한/하한","color":"#f59e0b"}]'::jsonb, ARRAY['상단 돌파 확인 즉시 숏 전량 손절 및 대피', '채널 재진입 기대로 숏 포지션 추가 물타기', '손절 없이 유지하면서 포지션 본전 도달 대기', '포지션 유지 후 증거금을 출금하여 강제 횡보']::text[], 0, '하락 평행 채널의 상단 저항선 상향 돌파(Breakout)는 기존 하락 트렌드의 사멸과 매수세 지배령 복귀를 뜻합니다. 지표와 거래량이 동반된 돌파 확인 시에는 숏 포지션을 지체 없이 기계적으로 칼손절하여 자산을 보호하는 것이 원칙입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (443, '추세/레짐', '07_multitimeframe_regime.md', '우상향하는 상승 평행 채널 안에서 순항하던 테슬라 주가가 중심선(Mid-line)을 뚫고 하방으로 이탈 마감했습니다. 이후 중심선 부근까지 반등을 시도했으나 재차 저항을 받고 아래꼬리가 꺾여 채널 하단선을 향해 하락 조정을 재개하려 합니다. 신규 매수(롱) 포지션 진입을 계획 중인 트레이더의 대응법은?', '[{"time":"Day 1","open":500,"high":540,"low":495,"close":530,"volume":81},{"time":"Day 2","open":530,"high":560,"low":510,"close":520,"volume":114},{"time":"Day 3","open":520,"high":530,"low":490,"close":500,"volume":113}]'::jsonb, '[{"type":"channel","points":[{"x":0,"y":550},{"x":2,"y":560},{"x":0,"y":490},{"x":2,"y":500}],"label":"상승 평행 채널","color":"#10b981"}]'::jsonb, ARRAY['채널 내 유지를 기대로 지정가 즉시 매수', '중심선 저항 확인 후 채널 하단 안착 대기', '하방 휩소 판단에 따른 레버리지 추가 매수', '추세와 무관한 숏 포지션 구축 후 관망']::text[], 1, '상승 평행 채널에서 미드라인(Mid-line)은 매우 중요한 심리적 지지와 저항선입니다. 미드라인이 저항선으로 뒤바뀌어 음봉으로 흘러내리는 경우 높은 확률로 채널 하단 경계선까지 가격이 조정을 받게 되므로, 중심선 저항 확인 시점에서는 섣부른 매수 진입을 피하고 채널 하단의 명확한 반등 타점을 유도해야 합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (444, '추세/레짐', '03_market_structure.md', '저점과 저점을 이은 장기 상승 추세선 상의 3번째 터치 포인트(지지선 부근)에 캔들이 매우 조심스럽게 안착하며 아래꼬리를 형성했습니다. 손익비(Risk-to-Reward) 관점에서 가장 이상적인 매수 타점 집행 및 손절 셋업 방법은 무엇입니까?', '[{"time":"Day 1","open":400,"high":450,"low":400,"close":440,"volume":81},{"time":"Day 2","open":440,"high":495,"low":440,"close":475,"volume":122},{"time":"Day 3","open":475,"high":480,"low":450,"close":460,"volume":105}]'::jsonb, '[{"type":"line","points":[{"x":0,"y":400},{"x":1,"y":440},{"x":2,"y":450}],"label":"상승 추세선 (3rd Touch 기대선)","color":"#10b981"}]'::jsonb, ARRAY['손절 라인 없이 지정가로 1차 매수 몰빵 진입', '3rd Touch 타점 진입 및 추세선 하단 칼손절 셋업', '하방 붕괴 예상을 통한 고배율 숏 즉각 진입', '목표가 터치 시까지 무작정 대기 후 추격 매수']::text[], 1, '추세선 상의 3번째 지지 포인트(3rd Touch)는 추세 신뢰도가 형성되는 대단히 성공률 높은 정석적 눌림목 타점입니다. 진입 가격과 손절 라인(추세선 이탈가)의 거리가 매우 가깝기 때문에 기대 수익 대비 잃을 금액이 매우 적어 프로 트레이더들이 가장 선호하는 칼손절 매수 스팟입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (445, '추세/레짐', '08_setup_entry_exit.md', '테슬라 주가가 장기 하락 추세선을 힘차게 뚫어 상방 돌파(Breakout)했습니다. 하지만 돌파선 바로 위(약 600달러)에 최근 여러 번 강한 매도 잔량이 쏟아지며 가격을 찍어 눌렀던 핵심 매물대 저항선이 떡하니 버티고 있습니다. 당신의 신규 진입 매수 순서는 어떻게 결정해야 안전할까요?', '[{"time":"Day 1","open":625,"high":630,"low":550,"close":560,"volume":89},{"time":"Day 2","open":560,"high":565,"low":490,"close":500,"volume":114},{"time":"Day 3","open":500,"high":595,"low":495,"close":590,"volume":98}]'::jsonb, '[{"type":"line","points":[{"x":0,"y":625},{"x":1,"y":560},{"x":2,"y":525}],"label":"하락 추세선 (돌파됨)","color":"#ef4444"},{"type":"horizontal-line","points":[{"x":0,"y":600}],"label":"수평 매물대 저항선 (120)","color":"#ef4444"}]'::jsonb, ARRAY['돌파 확인 즉시 종가 기준 시장가 100% 매수', '수평 저항 돌파 검증 시까지 매수 유보 및 대기', '돌파 전조 현상 기대로 레버리지 선배팅 집행', '추세선 돌파를 가짜로 간주한 숏 포지션 진입']::text[], 1, '하락 추세선의 돌파는 긍정적이나 수평 매물대 저항선이 바로 위에 있다면 이중 저항 작용에 의해 막히는 경우가 대단히 잦습니다. 추세선 상방 휩소(속임수)에 당하지 않으려면 겹저항 중 최종 관문인 수평 매물대 저항선 돌파 혹은 리테스트 지지를 확인하고 진입하는 것이 보수적이고 안전한 원칙입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (446, '패턴/돌파', '04_patterns_breakout.md', '고점 수평 저항선(500달러)과 저점 상승 지지선으로 이루어진 어센딩 트라이앵글 수렴 도중, 500달러를 돌파할 것을 미리 예측하고 490달러에서 비중 100% 매수로 진입했습니다. 그러나 테슬라 주가는 돌파에 실패하고 하방 상승 지지선을 대량 거래량 장대음봉으로 뚫어 460달러로 하향 마감했습니다. 올바른 매매 액션은?', '[{"time":"Day 1","open":400,"high":500,"low":400,"close":475,"volume":85},{"time":"Day 2","open":475,"high":500,"low":440,"close":485,"volume":111},{"time":"Day 3","open":485,"high":490,"low":455,"close":460,"volume":119}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":500}],"label":"수평 저항선 (100)","color":"#ef4444"},{"type":"line","points":[{"x":0,"y":400},{"x":1,"y":440},{"x":2,"y":470}],"label":"상승 지지선 (붕괴)","color":"#10b981"}]'::jsonb, ARRAY['하방 이탈 확인 즉시 손절하여 추가 폭락 차단', '조정을 이용해 평단가를 조절하는 분할 물타기', '본전 탈출 시까지 포지션을 유지하며 관망', '손절 라인을 하단으로 조정하고 대기 주문 유지']::text[], 0, '어센딩 트라이앵글은 상방 확률이 다소 높지만, 하단 지지선이 뚫려 무너지는 순간 패턴 실패와 함께 엄청난 실망 매도 매물이 출하됩니다. 특히 돌파를 미리 예견해 들어간 포지션은 즉시 룰 위반을 시정하고 손절(460달러)해야 큰 자산 보호를 할 수 있습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (447, '패턴/돌파', '04_patterns_breakout.md', '하락 바닥권에서 왼쪽 어깨, 머리, 오른쪽 어깨를 그리며 역헤드앤숄더(Inverse Head & Shoulders) 패턴이 완성되었습니다. 가격이 넥라인 저항벽(400달러선)을 돌파했으나 이미 장대양봉으로 높이 솟아(435달러) 추격 매수 타이밍을 아쉽게 놓쳤습니다. 이때 뇌동매매를 피하는 가장 현명한 매수 타점 공략법은?', '[{"time":"Day 1","open":475,"high":475,"low":350,"close":390,"volume":96},{"time":"Day 2","open":390,"high":410,"low":300,"close":375,"volume":111},{"time":"Day 3","open":375,"high":395,"low":340,"close":380,"volume":88},{"time":"Day 4","open":380,"high":440,"low":375,"close":435,"volume":118}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":400}],"label":"넥라인 저항선 (80)","color":"#ef4444"}]'::jsonb, ARRAY['포모(FOMO) 현상에 따른 돌파봉 꼭대기 추격 매수', '돌파 넥라인 부근의 리테스트 조정 눌림목 매수', '반등 랠리 종결 판단에 따른 역베팅 숏 포지션', '추세 전환 확인 후 무조건적인 관심종목 제외']::text[], 1, '강한 패턴 돌파봉 확인 후 뇌동매매로 추격하는 것은 손절 거리가 너무 멀어져 손익비가 최악인 나쁜 습관입니다. 정석 돌파 트레이더는 넥라인 역할 전환 지점(400달러)으로의 되돌림 눌림목(Retest)을 차분히 기다려 리스크를 짧게 끊고 들어가는 훈련을 해야 합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (448, '패턴/돌파', '04_patterns_breakout.md', '지속적인 하락 추세 중, 고점과 저점이 수렴하며 우하향하는 하락 쐐기형(Falling Wedge) 패턴의 끝자락에 도달했습니다. 거래량이 급감하다가 마침내 쐐기형 상단 저항선을 상방으로 뚫는 강한 양봉 종가 마감(550달러)이 포착되었습니다. 합리적인 매수 진입 시 손절가 설정 기준은 무엇인가요?', '[{"time":"Day 1","open":650,"high":660,"low":550,"close":560,"volume":109},{"time":"Day 2","open":560,"high":580,"low":510,"close":520,"volume":106},{"time":"Day 3","open":520,"high":540,"low":490,"close":500,"volume":104},{"time":"Day 4","open":500,"high":560,"low":495,"close":550,"volume":106}]'::jsonb, '[]'::jsonb, ARRAY['손절 없이 청산가에 의존하여 장기 홀딩', '상방 돌파 확인 후 진입 및 직전 최저점 손절 셋업', '평단가 개선을 위한 지속적인 분할 물타기 매수', '상단 저항선 돌파 시점을 이용한 숏 포지션 스위칭']::text[], 1, '하락 쐐기형(Falling Wedge)의 상방 돌파는 강력한 반전 신호입니다. 이 패턴의 장점은 진입 즉시 명확하고 짧은 기준점(수렴 바닥 최저가 490달러 혹은 돌파봉 하단)을 손절가로 설정할 수 있어, 리스크 한도를 안전하게 통제한 채 상방 랠리를 도모할 수 있다는 점입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (449, '패턴/돌파', '04_patterns_breakout.md', '테슬라 주가가 약한 매수세와 거래량 급감 속에 고점과 저점을 높이며 좁게 상승 쐐기형(Rising Wedge)을 그리고 있습니다. 현재 가격은 상승 쐐기형 하단 지지선(1,500달러)에 아주 밀착하여 붕괴 위기에 놓여 있습니다. 이 시점에서 롱(매수) 포지션을 들고 있는 트레이더의 리스크 대응은?', '[{"time":"Day 1","open":1300,"high":1400,"low":1300,"close":1390,"volume":106},{"time":"Day 2","open":1390,"high":1475,"low":1360,"close":1450,"volume":25},{"time":"Day 3","open":1450,"high":1525,"low":1490,"close":1505,"volume":22}]'::jsonb, '[{"type":"line","points":[{"x":0,"y":1300},{"x":1,"y":1360},{"x":2,"y":1490}],"label":"쐐기 하단 지지선 (300)","color":"#ef4444"}]'::jsonb, ARRAY['상승 쐐기형 하방 이탈 위험에 따른 롱 포지션 매도', '상승 지속 확신에 따른 레버리지 추가 불타기', '장기 상승 흐름 기대로 손절 없이 무기한 홀딩', '다른 종목으로의 포지션 분산을 위한 관망']::text[], 0, '상승 쐐기형(Rising Wedge)은 약세 세력이 억지로 쥐어짜며 상승 가격을 만드는 패턴으로, 수렴 끝에서 거래량 소멸과 함께 하방 이탈(Breakdown)하여 폭락할 위험이 매우 높은 대표적인 하락 대비 패턴입니다. 하단 지지선 이탈 낌새 시에는 매수 포지션을 전부 도망쳐 나와야 큰 손실을 막을 수 있습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (450, '패턴/돌파', '04_patterns_breakout.md', '둥근 대야 모양의 바닥(Cup)을 그리며 상승 회복한 테슬라 주가가 전고점 저항벽 부근에서 하향 채널식 완만한 되돌림 조정 핸들(Handle)을 그리는 중입니다. 이후 핸들의 상단 저항선(750달러선)을 강한 거래량의 장대양봉으로 상향 돌파했습니다. 이때 합리적인 트레이더의 대응은?', '[{"time":"Day 1","open":700,"high":710,"low":640,"close":650,"volume":102},{"time":"Day 2","open":650,"high":700,"low":645,"close":690,"volume":116},{"time":"Day 3","open":690,"high":700,"low":670,"close":675,"volume":123},{"time":"Day 4","open":675,"high":770,"low":670,"close":760,"volume":113}]'::jsonb, '[]'::jsonb, ARRAY['핸들 상방 돌파 확인 후 진입 및 핸들 저점 손절', '하락 지속 판단에 따른 즉각적인 전량 손절', '평단가 부근이므로 추가 손절 설정 없이 관망', '돌파 여부 확인 전 고점 돌파 매수 주문 100%']::text[], 0, '전형적인 강세 지속 패턴인 컵앤핸들(Cup & Handle)입니다. 핸들의 하락 조정 채널 상단 돌파는 매물 소화를 성공적으로 완수하고 본 랠리로 진입한다는 강력한 신호입니다. 손익비 관점에서 핸들의 지지 저점인 670달러 아래에 안전 손절을 지정한 뒤 진입 시 우수한 기대 수익을 가질 수 있습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (451, '지표/컨플루언스', '06_technical_indicators.md', '강력한 대세 상승 국면인 종목이 일시 조정을 거쳐 전저점 지지 영역(500달러)에 도달해 저점을 지키고 있습니다(저점 높임 또는 수평). 그런데 이때 보조지표 RSI의 저점은 이전보다 훨씬 깊게 파여 낮아지는 ''히든 상승 다이버전스(Hidden Bullish Divergence)''가 포착되었습니다. 현명한 의사결정은?', '[{"time":"Day 1","open":450,"high":550,"low":440,"close":525,"volume":116},{"time":"Day 2","open":525,"high":535,"low":490,"close":500,"volume":119}]'::jsonb, '[]'::jsonb, ARRAY['하락 전환 신호로 판단하여 전량 즉시 손절', '추세 지속 신호 기대로 지선 부근 추가/신규 매수', '지표 과매수 판단에 따른 계좌 거래 정지', '손절 설정 없이 무제한 레버리지 롱 대응']::text[], 1, '테슬라 주가의 저점은 높아지는데 보조지표(RSI 등)의 저점은 낮아지는 형태는 ''히든 상승 다이버전스''입니다. 이는 기존의 강력한 상승 트렌드 내부에서 일시 조정을 겪는 매수자들이 활기차게 물량을 주워 담아 다음 상승 랠리를 추진한다는 신호이므로, 짧은 손절 라인(490달러)을 설정하고 매수 비중을 태우기 가장 적합한 정석 타점입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (452, '지표/컨플루언스', '07_multitimeframe_regime.md', '테슬라 주가가 호재와 함께 밴드 상단선 바깥을 타고 계속 상승하는 강력한 볼린저 밴드 밴드워크(Band Walk) 현상이 발생 중이며, RSI는 80을 넘어 극단적 과매수 수치를 가리키고 있습니다. 이 구간에서 취해야 할 가장 합리적인 리스크 및 포지션 관리 행동은?', '[{"time":"Day 1","open":500,"high":575,"low":495,"close":560,"volume":103},{"time":"Day 2","open":560,"high":640,"low":550,"close":625,"volume":85},{"time":"Day 3","open":625,"high":695,"low":610,"close":680,"volume":111}]'::jsonb, '[]'::jsonb, ARRAY['과매수 도달 판단에 따른 고배율 숏 무리한 진입', '추종 손절매(Trailing Stop)를 통한 수익 극대화', '상승폭 만족에 따른 즉각적인 전량 시장가 익절', '손절 가격을 해제하고 시세 지속 시까지 방치']::text[], 1, '강세 추세가 지나치게 강할 경우 볼린저 밴드 상단을 타고 오르는 밴드워크 현상과 RSI 과매수 현상이 영구 유지될 수 있습니다. 이때 단순 과매수 수치를 이유로 숏 포지션을 잡으면 파산합니다. 기존 매수 포지션의 익절선(Trailing Stop)을 상향 관리하여 추세 상승 이익을 극대화하고 신규 진입은 자제하는 것이 정석 리스크 관리입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (453, '지표/컨플루언스', '06_technical_indicators.md', '1시간 봉 차트 상에서 테슬라 주가가 확실히 낮아졌으나 RSI 저점은 유의미하게 상승한 ''상승 다이버전스''가 확인되어 매수 타점을 노리고 있습니다. 다만 15분 봉 단기 차트에서는 하락 장대음봉 관성이 아직 살아있어 매도 압력이 보입니다. 멀티 타임프레임 트레이더의 진입 의사결정은?', '[{"time":"Hour 1","open":500,"high":510,"low":450,"close":455,"volume":97},{"time":"Hour 2","open":455,"high":460,"low":400,"close":410,"volume":108}]'::jsonb, '[]'::jsonb, ARRAY['단기 음봉 관성 기대로 즉각 숏 포지션 진입', '큰 시간 프레임의 상승 다이버전스 타점 매수', '지표 충돌로 판단하고 시장가 즉시 롱 진입', '변동성 기대로 무작정 도박성 잡코인 진입']::text[], 1, '큰 프레임(1시간 봉)의 다이버전스가 주는 중장기 추세 신뢰도는 작은 프레임의 단기 노이즈보다 압도적으로 강력합니다. 단, 진입 시 타이밍의 정밀도를 높이기 위해 소파동(15분 봉)의 하락 동력이 꺾이고 지지해 주는 단기 확인 캔들이 나오는 찰나에 롱 포지션 타이밍을 잡는 것이 멀티 타임프레임 정석 매매입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (454, '지표/컨플루언스', '06_technical_indicators.md', '테슬라 주가는 1,000달러 저항대를 뚫고 1,100달러까지 계속 우상향하며 고점을 갱신하고 있으나, MACD 오실레이터의 히스토그램 산 높이는 직전 고점 시점 대비 현저하게 쪼그라들며 꺾여 내려가 하락 다이버전스를 형성 중입니다. 현명한 포지션 보유자의 이익 관리 행동은?', '[{"time":"Day 1","open":900,"high":1025,"low":895,"close":1000,"volume":103},{"time":"Day 2","open":1000,"high":1110,"low":990,"close":1100,"volume":114}]'::jsonb, '[]'::jsonb, ARRAY['추세 지속 확신으로 보유 비중 추가 불타기', '상승 모멘텀 약화 다이버전스 확인 후 50% 익절', '익절 설정 없이 전고점 도달 시까지 홀딩', '고점 붕괴 기대로 숏 포지션 10배 베팅']::text[], 1, '테슬라 주가는 올라가나 모멘텀 지표인 MACD 오실레이터 고점이 낮아지는 현상은 대표적인 하락 다이버전스로, 매수 에너지가 속 빈 강정처럼 쇠퇴하고 있어 언제든 급격한 폭락 조정이 발생할 수 있는 고위험 신호입니다. 이 시점에는 탐욕을 통제하고 물량의 50% 이상을 분할 매도하여 현금을 챙기는 것이 원칙입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (455, '지표/컨플루언스', '06_technical_indicators.md', '테슬라 주가가 하락 횡보하던 도중, 단기 지평선인 EMA 20일선이 중장기선인 EMA 50일선에 극도로 밀착하며 수렴했습니다. 당일 대량 거래량의 음봉 캔들이 터지며 단기선이 장기선 아래로 교차하기 직전(데드크로스 임박)이며 주요 지지선 밑으로 떨어졌습니다. 롱(매수) 포지션 보유자의 올바른 대응은?', '[{"time":"Day 1","open":525,"high":530,"low":495,"close":500,"volume":93},{"time":"Day 2","open":500,"high":505,"low":475,"close":480,"volume":115}]'::jsonb, '[]'::jsonb, ARRAY['지지선 이탈 및 데드크로스 확인 즉시 손절', '이평선 지지력을 믿고 하방 물타기 추가 매수', '하락 조정 후 반등 기대로 무기한 홀딩 관망', '청산가 도달 시까지 어떠한 대응 없이 방치']::text[], 0, '20일선과 50일선의 데드크로스 임박 수렴 상태에서 가격이 지지선마저 무너뜨린 것은 하락 가속화 추세가 폭발하기 직전인 매우 위험한 기술적 상태입니다. 하락 추세가 본격 정배열(하락 정배열)화 되기 전에 즉시 전량 손절하고 시장 밖에서 피신해 있는 것이 계좌의 영구 파산을 막는 유일한 생존 규칙입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (456, '리스크/심리', '09_risk_position_management.md', '해외 주식 매수 후 가격이 급락하여 내가 설정해 둔 최대 감내 손실 한도인 계좌 총원금 대비 -2% 라인(손절매 지정 가격)에 완벽하게 닿았습니다. 마침 본전 생각과 함께 ''조금만 더 버티면 반등할 텐데...''하는 강한 뇌동매매 유혹이 솟구칩니다. 이때 원칙 트레이더의 결정은?', '[{"time":"Day 1","open":500,"high":510,"low":495,"close":500,"volume":81},{"time":"Day 2","open":500,"high":505,"low":470,"close":475,"volume":98}]'::jsonb, '[]'::jsonb, ARRAY['손절 라인을 임의로 하향 조정하고 홀딩', '평단가 관리 차원의 지속적 물타기 매수 집행', '원칙에 따라 뇌동을 제어하고 즉시 기계적 손절', '손실은 배제하고 반등 기대를 통한 무기한 보유']::text[], 2, '트레이딩의 승패는 예측이 아닌 ''리스크 통제''에 달려 있습니다. 사전에 정한 계좌 대비 2% 리스크 한도에 도달했을 때 희망 회로를 돌리며 손절을 미루거나 물타기를 집행하는 순간 계좌는 서서히 영으로 깎여 파산합니다. 멘탈의 충동을 통제하고 기계적으로 전량 칼손절하는 것이 절대 파산하지 않는 시장의 1법칙입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (457, '리스크/심리', '10_psychology_routine_review.md', '최근 3회 연속 거래에서 계속해서 손절(Stop Loss)을 맞아 뇌 내의 도파민 체계가 무너지고 심리가 극도로 불안해져 분노와 보복 매매 충동이 밀려옵니다. 이 상황에서 파산을 막는 가장 훌륭한 매매 심리 대처법은?', '[{"time":"Today","open":500,"high":500,"low":500,"close":500}]'::jsonb, '[]'::jsonb, ARRAY['손실 복구를 위해 레버리지를 증액해 즉시 진입', '뇌동 방지를 위해 HTS를 종료하고 매매 일지 작성 및 휴식', '추천 매매 신호 유료 리딩방에 즉시 가입 및 추종', '심리적 회복을 위해 역베팅 숏 포지션 추가']::text[], 1, '연속 손실 후 발생하는 복수심과 분노는 트레이더를 뇌동매매와 계좌 파멸로 이끄는 가장 치명적인 감정 상태입니다. 멘탈 붕괴를 느꼈을 때는 즉각 행동을 멈추고 시스템을 강제 종료하여 시장과 물리적 격리를 통해 냉정을 찾는 것만이 자산을 파산 리스크로부터 살려내는 훌륭한 트레이딩 행동입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (458, '셋업/실행', '09_risk_position_management.md', '진입하고자 하는 매수 자리를 분석해 보니, 기술적 분석 상 이길 수 있는 확률(승률)은 반반인 50% 수준입니다. 그러나 손절 시 기대 손실금액 대비 성공 시 획득할 수 있는 기대 수익금액의 비율(손익비)을 정밀 셋업 해보니 1 : 1.2 수준으로 다소 애매하게 도출되었습니다. 원칙 트레이더의 진입 결정은?', '[{"time":"Today","open":500,"high":500,"low":500,"close":500}]'::jsonb, '[]'::jsonb, ARRAY['단기 변동성 기대로 부적합한 손익비 시장가 진입', '마이너스 기댓값 거래 유보 및 우수 타점 대기', '레버리지를 높여 손익비 구조를 임의 조정 시도', '반대 방향으로 고배율 역베팅을 즉시 실행']::text[], 1, '수학적으로 승률 50%일 때 손익비가 최소 1:2(잃을 때 1, 벌 때 2) 이상이 나오지 않으면 복리 매매 시 수수료와 호가 슬리피지에 밀려 잔고가 무조건 마이너스로 수렴합니다. 타점이 눈에 들어오더라도 사전에 기대 손익비 필터에 걸려 탈락한다면 패스를 선언하고 관망하는 것이 현명한 생존 원칙입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (459, '리스크/심리', '09_risk_position_management.md', '갑작스러운 거시 경제 발표로 내가 매매 중인 종목의 캔들 변동성 폭(ATR)이 평소 시세의 2배 수준으로 널뛰기 시작했습니다. 1회 거래당 내 계좌 원금의 최대 2% 리스크 한도를 동일하게 고수하기 위해 취해야 할 올바른 조치는?', '[{"time":"Day 1","open":500,"high":510,"low":490,"close":500,"volume":107},{"time":"Day 2","open":500,"high":550,"low":450,"close":510,"volume":108}]'::jsonb, '[]'::jsonb, ARRAY['평소 변동성과 동일한 비중 및 손절 거리 고수', '손절 거리를 넓히는 대신 진입 포지션 수량 축소', '변동성이 확대되었으므로 2배 비중으로 적극 지름', '즉시 전량 손절하고 시장 상황 정상화 대기']::text[], 1, '시장 변동성이 커질 때는 손절 스톱 아웃이 잦으므로 손절폭(%)을 넓혀 숨 쉴 공간을 확보해 주는 것이 합리적입니다. 단, 손절폭을 2배로 늘린다면 계좌 대비 리스크 한도가 2배(4%)로 커지므로, 진입 포지션의 계약 수량을 50%로 줄여 리스크 노출 총액을 2%로 완벽하게 동일 통제하는 것이 포지션 사이징(Position Sizing)의 정석 원칙입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (460, '리스크/심리', '09_risk_position_management.md', '투자자 A의 전체 투자 원금은 2,500만 원이며, 1회 거래당 최대 허용 리스크 금액은 원금의 2%인 50만 원입니다. 현재 테슬라 주가가 50,000원이며, 기술적 분석 상 합리적인 손절선은 지지선 바로 밑인 47,500원(-5%)입니다. 2% 룰 리스크 관리 원칙에 따라 A가 진입(매수)해야 하는 최대 해외 주식 수량은?', '[{"time":"Today","open":50000,"high":50000,"low":50000,"close":50000}]'::jsonb, '[]'::jsonb, ARRAY['500주 (투자금 전액 시장가 매수)', '200주 (손실 한도 50만 원 맞춤 매수)', '50주 (보수적 극단적 비중 축소)', '100주 (절반 비중 고정 매수)']::text[], 1, '포지션 크기 계산 공식은 `최대 매수 규모 = 최대 허용 리스크 금액 / 손절매 비율` 입니다. 이 시나리오에서 `500,000원 / 0.05(5%) = 10,000,000원`이 최대 허용 진입금액이 되며, 이를 테슬라 주가 50,000원으로 나누면 `200주`가 도출됩니다. 200주 진입 후 -5% 가격 폭락으로 손절 당해도 내 총원금에서 깎이는 돈은 정확히 50만 원(2%)으로 완벽히 리스크 통제됩니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (461, '거래량/유동성', '05_volume_liquidity.md', '테슬라 주가가 수평 저항선 부근까지 급상승했으나 캔들 몸통(Spread)이 지극히 좁아진 도지 형태로 마감하였고, 거래량은 이전 5일 평균 대비 3배 이상 폭증했습니다. VSA(Volume Spread Analysis) 관점에서 가장 타당한 차트 분석은?', '[{"time":"Day 1","open":500,"high":525,"low":495,"close":520,"volume":104},{"time":"Day 2","open":520,"high":545,"low":515,"close":540,"volume":101},{"time":"Day 3","open":540,"high":550,"low":535,"close":540,"volume":126}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":545},{"x":2,"y":545}],"label":"저항선","color":"#ef4444"}]'::jsonb, ARRAY['강한 매수 기세 기대로 즉시 돌파 매매 풀매수', '저항벽 매도 공급 세력 분산 확인 후 이익 실현', '대량 거래 확인에 따른 손절 해제 후 장기 투자', '반등 실패에 따른 고배율 보복 숏 베팅 가동']::text[], 1, '캔들 몸통 크기(스프레드)가 좁은데 거래량이 매우 크게 폭증했다는 것은 저항선 부근에서 들어오는 매수세만큼 세력의 매도 물량 공급이 쏟아져 막강한 저항 벽을 형성하고 있다는 뜻입니다. VSA에서는 이를 불화(Disharmony)로 규정하며 상승 추세 감속 및 하락 반전의 경고로 해독합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (462, '거래량/유동성', '05_volume_liquidity.md', '테슬라 주가가 장기 횡보하던 박스권 지지선인 1,000달러를 깨고 975달러까지 하락 투매가 발생했으나, 종가 마감 직전 거래량이 크게 실린 긴 아래꼬리를 그리며 다시 1,005달러 위로 복귀 안착했습니다. 이 스톱 헌팅 유동성 현상에서의 실전 트레이더의 대응은?', '[{"time":"Day 1","open":1050,"high":1060,"low":1000,"close":1010,"volume":109},{"time":"Day 2","open":1010,"high":1020,"low":975,"close":1005,"volume":97}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":1000},{"x":1,"y":1000}],"label":"지지선","color":"#10b981"}]'::jsonb, ARRAY['지지선 붕괴 확정으로 간주한 시장가 숏 추격', '스윕(sweep) 판단 하에 아래꼬리 저점 손절 잡고 롱', '아무런 신호도 아니라고 판단하고 포지션 방치', '지지선 이탈 기대로 전량 손절 후 시장 영구 탈출']::text[], 1, '지지선 아래에 걸려 있던 개인들의 손절 주문(Sell Stop)을 강제로 청산(Liquidity Sweep)시킨 뒤, 세력이 물량을 헐값에 다 받아 삼켜 종가를 지지선 위로 신속하게 복귀시킨 휩소(베어 트랩) 패턴입니다. 아래꼬리 극점(975달러)에 아주 좁은 손절 라인을 설정할 수 있어, 기대 손익비가 극대화되는 고확률 상승 반전 매수 타점입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (463, '거래량/유동성', '05_volume_liquidity.md', '테슬라 주가는 1,250달러에서 1,450달러까지 계속 고점을 높이며 상승 추세를 이어가고 있습니다. 그러나 각 상승 파동마다 터지는 거래량은 전고점 돌파 시점 대비 눈에 띄게 하향 곡선을 그리며 감소하고 있습니다. VSA 기법에 따른 합리적인 진단은?', '[{"time":"Wave 1","open":1150,"high":1300,"low":1140,"close":1275,"volume":103},{"time":"Wave 2","open":1275,"high":1375,"low":1250,"close":1350,"volume":89},{"time":"Wave 3","open":1350,"high":1450,"low":1325,"close":1440,"volume":95}]'::jsonb, '[]'::jsonb, ARRAY['가격 상승으로 인한 매수 지속 강화 초강세', '매도 물량 고갈에 따른 무중력 안심 홀딩', '신규 자금 유입 둔화 거래량 다이버전스로 분할 익절', '지표 조작으로 판단하여 매매 중단 및 차트 종료']::text[], 2, '테슬라 주가는 상승하여 신고점을 갱신하지만 파동별 거래량이 지속 감소하는 흐름은 ''거래량 다이버전스''로 상승 모멘텀의 내부 엔진이 식어감을 경고합니다. 조만간 가벼운 매도 포격에도 대규모의 차익 실현 폭락 조정이 발생할 수 있는 잠재적 폭락 국면이므로 물량을 덜어내고 현금을 확보해야 합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (464, '거래량/유동성', '05_volume_liquidity.md', '가격이 이전 고점 저항선을 뚫고 강하게 솟구치며 장대양봉을 만들었습니다. 이때 가짜 이탈(Whipsaw / Bull Trap)이 아닌 진성 돌파(True Breakout)로 판정할 수 있는 가장 신뢰도 높은 거래량 기준은?', '[{"time":"Day 1","open":500,"high":510,"low":495,"close":500,"volume":358},{"time":"Day 2","open":500,"high":560,"low":495,"close":550,"volume":409}]'::jsonb, '[]'::jsonb, ARRAY['수렴 끝자락에서 거래량이 최저치인 상태 유지', '평균 대비 1.5~2배 이상 거래량 급증하며 돌파 마감', '거래량이 전혀 변하지 않는 평이한 상태 유지', '호가 스프레드가 가장 좁아지는 횡보 상태']::text[], 1, '참된 저항 돌파(True Breakout)는 저항선 부근의 두터운 대기 매도 공급 물량을 대규모 자금으로 전부 씹어 삼키고 돌파해야 함을 뜻합니다. 따라서 반드시 평균 대비 1.5배~2배 이상의 거래량 분출이 동반되어야 신뢰할 수 있으며, 거래량이 적은 돌파는 꼬리 달고 내려앉는 불 트랩(Bull Trap)일 확률이 매우 높습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (465, '거래량/유동성', '05_volume_liquidity.md', '테슬라 차트에서 중요 지지선 직전 저점 아래에 엄청난 규모의 롱 포지션 청산 및 매도 손절 주문이 쌓여 있는 유동성 풀(Liquidity Pool) 구간이 감지되었습니다. 세력이 이 구간을 공략할 때 나타날 캔들의 전형적인 무빙 패턴은?', '[{"time":"Day 1","open":250000,"high":252500,"low":246000,"close":247500,"volume":28},{"time":"Day 2","open":247500,"high":249000,"low":240000,"close":248000,"volume":25}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":246000},{"x":1,"y":246000}],"label":"전저점 지지선","color":"#3b82f6"}]'::jsonb, ARRAY['지지선을 장대음봉으로 돌파하여 20% 폭락 마감', '전저점 이탈로 손절 유도 후 지지선 위 아래꼬리 안착', '오차 없이 지지선 터치 후 꼬리 없는 수평 도지 횡보', '거래량 없이 즉각 상승 빔 분출로 전고점 탈환']::text[], 1, '기관 세력(스마트 머니)은 대량 포지션을 구축하기 위해 개인의 손절 주문(Sell Stop)을 의도적으로 터트려 매도 유동성을 유도한 후 이를 다 매수합니다. 이로 인해 테슬라 주가는 지지선 아래로 일시 급락 후(스톱 헌팅), 아래꼬리를 매우 길게 달며 지선 안쪽으로 급반등 마감하게 됩니다. 이것이 유동성 스윕(Liquidity Sweep)의 정석 패턴입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (466, '거래량/유동성', '05_volume_liquidity.md', '상승 추세 도중 전고점 저항선 부근에서 위꼬리가 아주 긴 캔들이 터졌고, 거래량은 최근 보름 중 최고 수치로 솟구쳤습니다. VSA 관점에서 이 상승 거절(Upside Rejection) 현상에 대한 올바른 대처는?', '[{"time":"Day 1","open":500,"high":575,"low":490,"close":505}]'::jsonb, '[]'::jsonb, ARRAY['강한 저점 매수 기회로 인지하여 비중 대폭 추가', '고점 매도 Rejection 확인 후 기존 롱 포지션 대피', '박스 횡보 수렴 기대로 마틴게일 추가 매수 가동', '이평선 정배열 판단에 따른 포지션 변경 없이 홀딩']::text[], 1, '위꼬리가 매우 긴 캔들이 대량 거래량과 함께 터졌다는 것은 고점 돌파 시도가 있었으나 그 자리에 숨어 있던 세력의 막강한 청산 매도 벽(Supply)을 만나 격렬하게 두들겨 맞고 밀려났음을 의미합니다. 상방 거절의 심리가 지배적이므로 고점 피로 및 하락 전환이 임박한 위험 징후입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (467, '지표/컨플루언스', '06_technical_indicators.md', '테슬라 주가가 장기 박스권 횡보를 이어가며 볼린저 밴드의 폭이 최근 몇 달 중 가장 좁은 형태로 밀착 수렴(Squeeze)되었습니다. 이 스퀴즈 국면에 대한 올바른 기술적 이해와 매매 시나리오는?', '[{"time":"Week 1","open":500,"high":515,"low":485,"close":505,"volume":103},{"time":"Week 2","open":505,"high":510,"low":495,"close":500,"volume":87}]'::jsonb, '[]'::jsonb, ARRAY['박스권 변동성 부재 기대로 장기 무대응 관망', '에너지 수축 스퀴즈 확인 후 밴드 이탈 돌파 대기', '지표 신뢰 불가 판단으로 볼린저 밴드 지표 삭제', '중심선 지지로 판단하여 고배율 매수 대기 주문']::text[], 1, '볼린저 밴드의 폭이 극도로 좁아지는 스퀴즈(Squeeze) 현상은 시장의 표준편차 변동성이 임계치까지 압축 수렴되었음을 알려줍니다. 에너지 압축 뒤에는 항상 폭발적인 가격 분출(상방/하방 이탈)이 뒤따르므로, 밴드를 뚫고 거래량이 실려 돌파 마감하는 방향으로 추세 추종 시나리오를 설계해야 합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (468, '지표/컨플루언스', '06_technical_indicators.md', '테슬라 주가는 HL(Higher Low)을 형성하며 이전 직전 저점(450달러)보다 높은 저점(475달러)을 지키고 있으나, RSI 지표는 이전 35 수치보다 더 깊숙하게 25 수치까지 떨어졌습니다. 이 지표 불일치 현상의 공식 명칭과 올바른 포지션 셋업은?', '[{"time":"Day 1","open":500,"high":510,"low":450,"close":455,"volume":99},{"time":"Day 2","open":455,"high":480,"low":475,"close":475,"volume":105}]'::jsonb, '[]'::jsonb, ARRAY['일반 상승 다이버전스 - 추세 종결로 즉각 공매도', '히든 상승 다이버전스 - 지선 눌림목 롱 진입 활용', '일반 하락 다이버전스 - 모든 매수 포지션 정리', '지표 오작동 휩소 구간 판단으로 양방향 관망']::text[], 1, '가격의 저점은 높아졌는데(Higher Low) 모멘텀 지표의 저점은 낮아지는 현상은 ''히든 상승 다이버전스(Hidden Bullish Divergence)''입니다. 이는 추세 반전이 아닌 **기존 강세 추세 지속**을 뜻하며, 조정 눌림목이 완성되고 다음 상승 랠리를 준비한다는 최고의 매수 신호 중 하나입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (469, '지표/컨플루언스', '06_technical_indicators.md', '매수 타점을 신중하게 선별하고자 합니다. 기술적 분석의 성공 확률을 비약적으로 끌어올리는 ''다중 컨플루언스(Confluence)'' 결합 사례로 가장 적합한 조건 구성은?', '[{"time":"Today","open":500,"high":500,"low":500,"close":500}]'::jsonb, '[]'::jsonb, ARRAY['트위터 및 뉴스의 호재 찌라시 확인 즉시 추격', '지지선+이평선+다이버전스+아래꼬리 등 분석 중첩 시', 'RSI 과매수 영역 진입 즉시 롱 포지션 진입', '독립적 분석 없이 오직 보조지표의 단일 수치 신호']::text[], 1, '다중 컨플루언스(Confluence)는 독립적인 기술적 근거들이 동일한 특정 가격 구역에 중첩되는 현상입니다. 지지 저항, 이평선, 보조지표 다이버전스, 캔들 가격행동(Rejection 핀바)이 한 곳에 묶여 매수 자리를 형성할 때 매매를 실행하면, 높은 신뢰도와 좁은 손절 라인 덕분에 장기 기대값이 극대화됩니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (470, '셋업/실행', '08_setup_entry_exit.md', '중요 수평 저항선(600달러)을 상방으로 장대양봉 종가 돌파한 것을 확인하고 롱(매수) 진입 셋업을 준비하고 있습니다. 원칙 트레이더가 뇌동매매 추격을 막고 최상의 손익비를 확보하기 위해 즐겨 쓰는 정석적인 진입 실행법은?', '[{"time":"Day 1","open":550,"high":560,"low":545,"close":555,"volume":95},{"time":"Day 2","open":555,"high":620,"low":550,"close":610,"volume":117}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":600},{"x":1,"y":600}],"label":"저항선","color":"#ef4444"}]'::jsonb, ARRAY['돌파 마감 확인 즉시 시장가 추가 매수 집행', '돌파된 저항선의 지지 전환(Retest) 시 지정가 진입', '반등 조정이 불가능하다고 판단하여 최고점 롱 추격', '속임수 돌파 확신으로 고배율 역베팅 숏 진입']::text[], 1, '저항 돌파 후 즉시 가격을 따라붙는 추격 매수는 휩소 조정 시 심각한 손실을 초래합니다. 돌파된 라인이 S/R Flip을 통해 지지로 작용하는지 확인하는 되돌림 리테스트(Retest) 시점에 진입하는 것이, 지선 바로 아래에 좁은 손절 라인을 설계하고 이익 기대 폭을 넓힐 수 있는 가장 이상적인 정석 실행법입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (471, '셋업/실행', '08_setup_entry_exit.md', '포지션 진입 직후, 가격이 계획대로 내 방향으로 순탄하게 우상향하고 있습니다. 기존 진입 시 설정한 손익비 1:2의 최종 목표가 도달 전에, 리스크 관리 차원에서 계좌 드로다운을 0으로 만드는 정석적인 1차 포지션 관리 행동은?', '[{"time":"Entry","open":500,"high":500,"low":500,"close":500,"volume":81},{"time":"Day 1","open":500,"high":530,"low":500,"close":525,"volume":115}]'::jsonb, '[]'::jsonb, ARRAY['1차 저항대 진입 시 레버리지를 활용해 불타기', '목표가 터치 시까지 100% 비중 무대응 홀딩', '1:1 지점 50% 분할 익절 및 남은 물량 본전 손절 상향', '단기 반등 확인 즉시 전량 기계적 청산 및 퇴장']::text[], 2, '이득이 발생해 손익비 1:1 수준에 오면 물량의 절반을 분할 익절(Scale-out)하고 남은 포지션의 스톱로스를 진입가로 이동(Break-even)시키는 것이 포지션 관리의 기본입니다. 이렇게 셋업하면 차트가 갑자기 폭락세로 뒤집혀도 최소 본전 혹은 반절 익절 약수익으로 끝나 해당 거래의 최대 리스크가 Zero(0)로 봉쇄됩니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (472, '셋업/실행', '08_setup_entry_exit.md', '강력한 장기 상승 추세가 터져 테슬라 주가가 20일 이평선을 타고 계속해서 폭발적으로 신고가를 갱신하고 있습니다. 이때 익절 시점을 서둘러 잡지 않고, 추세 상승 이익을 최대한 길게 끝까지 빨아먹기 위한 정석 청산 실행법은?', '[{"time":"Day 1","open":500,"high":550,"low":495,"close":540,"volume":100},{"time":"Day 2","open":540,"high":600,"low":535,"close":590,"volume":118},{"time":"Day 3","open":590,"high":675,"low":585,"close":660,"volume":99}]'::jsonb, '[]'::jsonb, ARRAY['RSI 과과열 조짐 확인 즉시 시장가 전량 익절', 'Higher Low 지지 직하방으로 손절 추종 익절 셋업', '이익 보존을 포기하고 손익절 라인을 해제 후 홀딩', '즉시 숏 포지션 10배로 맞불을 놓는다']::text[], 1, '강세 추세가 터졌을 때 지레짐작으로 청산하면 상승 파동의 초입만 먹고 끝납니다. 추세 붕괴의 명확한 신호(BOS/MSB)가 나오거나, 가격의 구조적 높은 저점(HL)이 깨질 때까지 손절 라인을 계속 추종해서 상향하는 ''추격 손절매(Trailing Stop)''를 가동하는 것이 추세 이익을 극대화하는 정석 기법입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (473, '셋업/실행', '01_chart_market_basics.md', '차트 분석 결과, 돌파 시점의 체결 변동성과 거래소 호가창의 얇은 매물 상태를 감안할 때 내가 진입하려는 주문 가격에서 체결이 뒤로 밀리는 ''슬리피지(Slippage)''가 심각하게 예상됩니다. 이를 감안한 올바른 주문 실행법은?', '[{"time":"Today","open":500,"high":500,"low":500,"close":500}]'::jsonb, '[]'::jsonb, ARRAY['시장가로 최고 배율을 설정하여 즉시 체결', '돌파 확인 후 지정가 대기 주문으로 단가 조절', '슬리피지를 예방하기 위해 즉각적인 거래 취소', '호가창 스프레드와 무관하게 고배율 레버리지']::text[], 1, '변동성이 크고 호가가 얇은 시장에서 돌파 시 시장가 진입은 나쁜 단가로 체결되는 슬리피지 비용을 발생시켜 시작부터 손실을 크게 안고 갑니다. 돌파 확인 후 되돌림 가격대에서 지정가(Limit Order)를 대기시켜 체결 단가를 내 손아귀에 고정하는 리스크 관리가 필요합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (474, '셋업/실행', '10_psychology_routine_review.md', '원칙 기반의 정석 매매 셋업(Trading Setup)을 설계할 때, 진입 전 반드시 사전에 수치로 명문화되어 결정되어야 할 요소가 아닌 것은?', '[{"time":"Today","open":500,"high":500,"low":500,"close":500}]'::jsonb, '[]'::jsonb, ARRAY['진입 조건(Trigger)과 구체적인 손절 가격(Stop Loss)', '거래 당일 본인의 주관적인 직감과 감정적 목표가', '진입하려는 구체적인 포지션 규모 및 분할 익절선', '거래 아이디어가 무효화되는 구체적 가격 지점']::text[], 1, '매매 셋업은 규칙에 기반한 수치들(진입가, 손절가, 목표가, 수량)로 사전에 철저히 규격화되어야 합니다. 당일의 운이나 주관적 느낌, 예감에 기초한 비과학적 청산 설정은 셋업에서 배제되어야 할 대표적 뇌동매매 요소입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (475, '셋업/실행', '08_setup_entry_exit.md', '하락 횡보하던 테슬라 주가가 중요 매물대이자 피보나치 되돌림 0.618 지점에 정확히 맞닿아 아래꼬리가 긴 양봉 핀바(Pin Bar)를 그리며 마감했습니다. 룰베이스 트레이더가 진입 버튼을 누를 때 성립된 IF-THEN 시나리오는?', '[{"time":"Day 1","open":500,"high":500,"low":400,"close":410,"volume":109},{"time":"Day 2","open":410,"high":430,"low":390,"close":425,"volume":96}]'::jsonb, '[]'::jsonb, ARRAY['익일 가격 상황과 관계없이 100배 레버리지 진입', '중첩 자리 핀바(rejection) 확인 후 익일 시가 롱 진입', '상단 저항 도달 판단으로 즉각적인 숏 포지션 진입', '돌파 랠리가 완전히 끝날 때까지 HTS 종료 및 관망']::text[], 1, '훌륭한 트레이딩 실행은 ''IF(조건 만족 시) ➔ THEN(원칙대로 포지션 진입 및 손절/목표가 기계적 배치)''의 룰베이스 알고리즘에 의해 움직여야 감정을 배제할 수 있습니다. 지지 구간 중첩과 핀바 출현 조건이 성립했으므로 다음 봉 시가에 진입하되 꼬리 저점 이탈 시 칼손절하여 리스크를 통제하는 것이 정석입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (476, '리스크/심리', '09_risk_position_management.md', '나의 트레이딩 시스템 승률이 40%로 다소 낮게 고정되어 있습니다. 이 시스템을 통해 장기적으로 파산하지 않고 복리로 계좌 자산을 우상향시키기 위해 필수적으로 지켜야 할 손익비(평균손실 대비 평균수익 비율)의 최소 기준은?', '[{"time":"Today","open":500,"high":500,"low":500,"close":500}]'::jsonb, '[]'::jsonb, ARRAY['손익비 1:1 수준 (매매 승률이 낮을 때 파산)', '승률 40% 대비 기댓값 개선을 위한 손익비 1:1.5 이상', '낮은 승률 상태에서 손익비와 무관하게 무조건 파산', '승률 극복을 위한 레버리지 20배 수준 설정']::text[], 1, '승률이 40%일 때 기대값 수학적 수수료 감안 최소 손익비는 1:1.5입니다. 손익비 1.5배 이상 구간만 취하면 10번 중 6번 손절당하고 단 4번만 익절하더라도 계좌 총합은 수익 우위에 서게 됩니다. 저승률 시스템일수록 철저히 손익비가 유리한 진입가 근처 타점만 기계적으로 필터링해 진입해야 생존합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (477, '리스크/심리', '09_risk_position_management.md', '선물 트레이더인 B는 담보금 효율을 극대화한다는 명목으로 50배 레버리지 롱 포지션 진입을 실행했습니다. 진입 가격 대비 B의 포지션 원금이 완전 소멸(강제 청산)되는 역방향 하락 거리(%)는 대략 몇 % 수준입니까?', '[{"time":"Today","open":500,"high":500,"low":500,"close":500}]'::jsonb, '[]'::jsonb, ARRAY['진입 단가 대비 20.0%의 강한 하락 발생 시', '진입 단가 대비 단 -2.0% 변동성 노이즈 터치 시', '진입 단가 대비 50.0%의 강한 폭락 발생 시', '청산가가 산출되지 않는 특이 종목 거래 시']::text[], 1, '청산 거리 계산 공식은 대략 `100% / 레버리지 배수` 입니다. 50배 고배율 레버리지의 경우, 내 포지션 반대 방향으로 단 **-2%**의 시세 변동성(장중 흔한 잔파동 노이즈)만 터치해도 원금이 100% 강제 청산 증발됩니다. 고배율 레버리지는 수학적 확률상 100% 파멸을 초래하는 도박성 거래 행위입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (478, '리스크/심리', '09_risk_position_management.md', '트레이딩 계좌 총자산이 10,000만 원인 트레이더가 있습니다. 1회 거래당 총자산의 2% 룰 원칙에 근거하여 리스크 한도(200만 원)를 설정했습니다. 진입하려는 종목의 손절가 거리가 -8%인 경우, 2% 룰을 완벽하게 충족하는 최대 진입(매수) 금액은?', '[{"time":"Today","open":500,"high":500,"low":500,"close":500}]'::jsonb, '[]'::jsonb, ARRAY['10,000만 원 전액 매수 (손절 폭을 배제한 대규모 베팅)', '2,500만 원 진입 (-8% 손절 시 리스크 한도 200만 원 충족)', '5,000만 원 진입 (손익비 1:1 기준에 맞춘 베팅)', '1,000만 원 진입 (보수적 원칙에 입각한 극단적 축소)']::text[], 1, '포지션 사이징 공식은 `진입금액 = 최대 리스크 허용액(200만 원) / 손절 비율(0.08)` 입니다. 이에 따라 `2,000,000원 / 0.08 = 25,000,000원`이 도출됩니다. 2,500만 원 규모로 매수 진입 시 가격이 급락해 -8% 손절 라인을 때려도 내 총자산에서 깎이는 금액은 정확히 원칙 한도인 200만 원(2%)으로 제한되어 계좌가 완벽히 방어됩니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (479, '리스크/심리', '10_psychology_routine_review.md', '장중에 내가 째려보며 타점을 기다리던 해외 주식이 아무런 조정도 없이 장대양봉을 그리며 갑자기 수직 폭등하기 시작하여 5% 이상 치솟았습니다. 이때 머릿속에 ''나만 두고 날아가는 것 아닌가''하는 극심한 소외감 공포(FOMO)가 솟구칩니다. 원칙 트레이더의 올바른 심리 대응은?', '[{"time":"Day 1","open":500,"high":510,"low":495,"close":500,"volume":100},{"time":"Day 2","open":500,"high":530,"low":500,"close":525,"volume":94}]'::jsonb, '[]'::jsonb, ARRAY['추세 연장 판단으로 시장가 전액 추격 매수', 'FOMO 판단 하에 매수 보류 및 정석 되돌림 타점 대기', '돌파 실패 판단 하에 반대 방향 고배율 숏 베팅', '거래를 종료하고 즉각 해외 주식 시장에서 전량 탈출']::text[], 1, '나만 기회를 잃는다는 공포(FOMO)로 날아가는 장대양봉 꼭대기에서 추격 매수하는 행위는 고점 물리기를 자처하는 가장 흔한 뇌동매매 패턴입니다. 내 타점을 비껴간 상승은 내 돈이 아니라고 인정하고, 사전에 정의한 룰베이스 타점까지 냉정하게 대기하는 것이 장기 생존자의 멘탈 습관입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (480, '리스크/심리', '10_psychology_routine_review.md', '오전 거래에서 원칙을 어긴 무리한 진입으로 인해 3회 연속 스톱아웃(손절)을 당하여 당일 원금의 -6%의 큰 손실을 입었습니다. 본전 생각과 분노로 눈이 뒤집혀 비중을 올려 한 판으로 복수하려는 ''보폭 매매'' 충동이 폭발할 때, 파산을 막는 가장 강력한 멘탈 시스템 룰은?', '[{"time":"Today","open":500,"high":500,"low":500,"close":500}]'::jsonb, '[]'::jsonb, ARRAY['손실 만회를 위해 빌린 돈으로 100배 고배율 복수 베팅', '일일 손실 한도 도달에 따른 매매 강제 종료 및 격리', '주변 유료 전문가 추천 종목을 탐색해 즉각 매수', 'RSI 과매도 상태이므로 즉시 반대 숏 포지션 진입']::text[], 1, '연패를 겪은 후 홧김에 비중을 더 크게 실어 한 번에 본전을 찾으려는 보복 매매는 계좌를 하루 만에 휴지조각으로 만드는 가장 무서운 파산 유도 심리 상태입니다. 이를 막기 위해 하루 최대 손실 한도 한계선(예: 3회 손절 또는 원금의 5%)을 정해두고, 이 한계선 터치 시 즉시 차트를 종료하고 냉각기를 강제 집행하는 룰이 필수입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (501, '캔들/가격행동', '02_candlestick_price_action.md', '하락 추세 지속 도중 바닥권에서 몸통이 짧고 아래꼬리가 몸통의 2배 이상인 아래 캔들이 출현했습니다. 이 캔들의 명칭과 올바른 대응은?', '[{"time":"10:00","open":960,"high":976,"low":944,"close":952,"volume":119},{"time":"10:15","open":952,"high":960,"low":904,"close":912,"volume":95},{"time":"10:30","open":912,"high":920,"low":864,"close":872,"volume":98},{"time":"10:45","open":872,"high":880,"low":808,"close":816,"volume":109},{"time":"11:00","open":816,"high":824,"low":720,"close":808,"volume":113}]'::jsonb, '[]'::jsonb, ARRAY['역망치형 (Inverted Hammer) - 하락 경고 및 공매도 대기', '망치형 (Hammer) - 저점 지지 및 분할 매수 대기', '도지 (Doji) - 매수세와 매도세의 팽팽한 균형 및 관망', '하락 장악형 (Bearish Engulfing) - 추세 반전 및 즉시 손절']::text[], 1, '마지막 캔들은 아래꼬리가 긴 ''망치형(Hammer)'' 캔들로 하락 압력을 이겨내고 저가 매수세가 밀어 올렸음을 의미하는 대표적 상승 전환 신호입니다. 지지를 확인한 뒤 분할 매수 관점으로 대기해야 합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (502, '캔들/가격행동', '02_candlestick_price_action.md', '애플 주가가 장기간 급등한 뒤, 고점 부근에서 위꼬리가 매우 길고 몸통이 짧은 형태의 캔들이 발생했습니다. 이 캔들의 해석으로 가장 적절한 것은?', '[{"time":"Day 1","open":800,"high":864,"low":792,"close":840,"volume":107},{"time":"Day 2","open":840,"high":920,"low":832,"close":896,"volume":111},{"time":"Day 3","open":896,"high":1000,"low":888,"close":984,"volume":114},{"time":"Day 4","open":984,"high":1024,"low":960,"close":1008,"volume":116},{"time":"Day 5","open":1008,"high":1160,"low":1000,"close":1016,"volume":99}]'::jsonb, '[]'::jsonb, ARRAY['유성형 (Shooting Star) - 고점 저항 및 하락 전환 예고', '망치형 (Hammer) - 저점 매수세 유입 및 상승 랠리 기대', '상승 장악형 (Bullish Engulfing) - 추세 반전 및 홀딩 유도', '도지 (Doji) - 추세 지속 가능성 및 일시 관망']::text[], 0, '급등세 끝에서 위꼬리가 몸통보다 훨씬 길게 솟아오른 캔들은 ''유성형(Shooting Star)''입니다. 장중 상승 시도를 강력한 차익 실현 및 매도 압력이 짓눌렀음을 보여주며, 하락 추세 전환의 강력한 경고 시그널입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (503, '캔들/가격행동', '02_candlestick_price_action.md', '직전의 음봉 몸통을 다음 날의 거대한 양봉 몸통이 완전히 감싸 안는 아래 형태가 포착되었습니다. 이 패턴의 이름과 신뢰도는?', '[{"time":"Day 1","open":784,"high":800,"low":760,"close":768,"volume":94},{"time":"Day 2","open":768,"high":776,"low":736,"close":744,"volume":98},{"time":"Day 3","open":744,"high":760,"low":704,"close":712,"volume":89},{"time":"Day 4","open":696,"high":816,"low":688,"close":808,"volume":110}]'::jsonb, '[]'::jsonb, ARRAY['하락 장악형 (Bearish Engulfing) - 추세 반전 신뢰도 낮음', '상승 장악형 (Bullish Engulfing) - 매수 전환 신뢰도 높음', '상승 관통형 (Piercing Line) - 중간 강도의 반전 신호', '석별형 (Evening Star) - 상승 추세 종결 신호']::text[], 1, '전일의 하락 음봉 몸통을 다음 날의 장대 양봉이 완전히 덮어버리는 형태를 ''상승 장악형(Bullish Engulfing)'' 패턴이라고 합니다. 하락 추세 끝에서 나타날 경우 단기 하락세가 종료되고 강력한 매수세가 들어왔음을 뜻해 전환 신뢰도가 매우 높습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (504, '캔들/가격행동', '01_chart_market_basics.md', '시가와 종가가 거의 일치하여 몸통이 거의 없고 위아래 꼬리만 달린 십자(+) 모양 캔들이 출현했습니다. 이 캔들에 대한 올바른 해석은?', '[{"time":"Day 1","open":1200,"high":1240,"low":1184,"close":1216,"volume":89},{"time":"Day 2","open":1216,"high":1248,"low":1208,"close":1232,"volume":92},{"time":"Day 3","open":1232,"high":1272,"low":1200,"close":1232,"volume":127}]'::jsonb, '[]'::jsonb, ARRAY['상승세 동력 상실로 인한 추세의 하방 반전', '매수/매도 세력 균형에 따른 도지(Doji) 횡보', '매도세 지배에 따른 즉각적인 숏 포지션 진입', '하락 세력 이탈로 인한 즉각적인 상승 랠리']::text[], 1, '시가와 종가가 거의 같은 십자 모양의 캔들은 ''도지(Doji)'' 캔들입니다. 이는 힘의 균형이 팽팽함을 시사하며, 기존 추세의 힘이 빠지고 잠재적인 방향성 전환(상승/하락 모두 포함)의 변곡점이 다가오고 있음을 의미합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (505, '캔들/가격행동', '02_candlestick_price_action.md', '상승 추세 고점에서 직전 양봉의 몸통을 거대 음봉이 아래로 덮어버리는 캔들 조합이 발생했습니다. 이 현상을 의미하는 용어는?', '[{"time":"Day 1","open":960,"high":1000,"low":952,"close":992,"volume":88},{"time":"Day 2","open":992,"high":1040,"low":984,"close":1032,"volume":106},{"time":"Day 3","open":1040,"high":1048,"low":920,"close":928,"volume":123}]'::jsonb, '[]'::jsonb, ARRAY['하락 장악형 (Bearish Engulfing) - 고점 하락 전환 예고', '상승 장악형 (Bullish Engulfing) - 고점 돌파 랠리 예고', '하락 잉태형 (Harami) - 기존 하락세의 일시 둔화', '샛별형 (Morning Star) - 바닥권 상승 반전 예고']::text[], 0, '고점에서 직전 양봉을 음봉이 감싸 안은 형태는 ''하락 장악형(Bearish Engulfing)''입니다. 매수 세력을 매도 공급이 압도했다는 명백한 증거로, 애플 주가 추세가 하락으로 반전할 리스크가 큽니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (506, '시장구조/SR', '03_market_structure.md', '애플 주가가 장기 저항선인 1,200달러를 거래량 실린 강한 캔들로 돌파한 뒤, 다시 1,200달러 부근으로 내려와 버티고 있습니다. 가장 안전한 진입 방식은?', '[{"time":"Day 1","open":1120,"high":1184,"low":1112,"close":1160,"volume":106},{"time":"Day 2","open":1160,"high":1192,"low":1144,"close":1152,"volume":112},{"time":"Day 3","open":1152,"high":1248,"low":1144,"close":1232,"volume":108},{"time":"Day 4","open":1232,"high":1240,"low":1192,"close":1208,"volume":353},{"time":"Day 5","open":1208,"high":1224,"low":1200,"close":1216,"volume":402}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":1200},{"x":4,"y":1200}],"label":"돌파된 저항선 -> 지지선 전환선","color":"#3b82f6"}]'::jsonb, ARRAY['돌파 시점에 시장가로 즉시 진입하는 추격 매수', '돌파 후 저항선의 지지선 전환(Retest) 확인 시 진입', '이전 최저가 부근인 1,120달러 조정 시까지 대기 매수', '돌파 후 즉시 단기 조정을 예상한 역추세 숏 진입']::text[], 1, '저항선이 강하게 뚫리면 역할 전환(Role Reversal)에 의해 신규 지지선으로 바뀝니다. 돌파 시점에 뇌동매매하기보다는 돌파된 선 부근으로 애플 주가가 눌려 지지(Retest)를 완성할 때 진입하는 것이 리스크 대비 기대 수익이 큽니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (507, '거래량/유동성', '05_volume_liquidity.md', '애플 주가가 저항선 위로 거래량 없이 장대양봉을 뿜어 올렸으나, 다음 날 곧바로 장대음봉으로 밀어붙이며 저항선 아래로 내려왔습니다. 이 현상의 명칭은?', '[{"time":"Day 1","open":784,"high":808,"low":776,"close":800,"volume":117},{"time":"Day 2","open":800,"high":816,"low":792,"close":808,"volume":117},{"time":"Day 3","open":808,"high":880,"low":800,"close":864,"volume":28},{"time":"Day 4","open":864,"high":872,"low":760,"close":768,"volume":17}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":816},{"x":3,"y":816}],"label":"저항선","color":"#ef4444"}]'::jsonb, ARRAY['진짜 상승 돌파 (True Breakout)', '불 트랩 (Bull Trap) - 매수자 청산 유도 가짜 돌파', '베어 트랩 (Bear Trap) - 매도자 청산 유도 가짜 하방', '골든 크로스 (Golden Cross) - 이평선 돌파']::text[], 1, '저항선을 일시적으로 뚫었다가 대량 매도세와 함께 직후 캔들에서 하방으로 원상복귀하는 현상을 ''불 트랩(Bull Trap/가짜 돌파)''이라고 합니다. 돌파 후 리테스트를 기다리지 않고 급히 추격 매수했던 투자자들이 고점에 물리는 대표적 함정입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (508, '시장구조/SR', '01_chart_market_basics.md', '아래 차트에서 3번 연속 강하게 반등하며 가격 하락을 저지해 준 주요 가격대는 무엇을 의미하나요?', '[{"time":"Day 1","open":800,"high":816,"low":720,"close":728,"volume":83},{"time":"Day 2","open":728,"high":784,"low":720,"close":776,"volume":115},{"time":"Day 3","open":776,"high":840,"low":768,"close":832,"volume":105},{"time":"Day 4","open":832,"high":848,"low":728,"close":736,"volume":100},{"time":"Day 5","open":736,"high":800,"low":720,"close":792,"volume":102}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":720},{"x":4,"y":720}],"label":"720달러선","color":"#10b981"}]'::jsonb, ARRAY['강력한 저항선 (Resistance Line) - 매도 매물대', '강력한 지지선 (Support Line) - 매수 매물대', '골든크로스 수렴선 - 이평선 밀집대', '이격도 붕괴선 - 가격 과열 분기점']::text[], 1, '특정 가격(720달러)에 접근할 때마다 대기 중이던 저가 매수세가 유입되어 애플 주가의 추가 하락을 방어해 준 이 라인은 ''강력한 지지선(Support Line)''입니다. 이탈하기 전까지는 손절 라인을 바로 밑에 두고 진입하기에 가장 손익비 좋은 구간입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (509, '거래량/유동성', '05_volume_liquidity.md', '지지선 아래로 애플 주가가 이탈하여 공매도가 폭증했으나, 이내 거래량이 급증하며 양봉으로 지지선을 회복한 뒤 반등을 시작했습니다. 이 현상의 명칭은?', '[{"time":"Day 1","open":960,"high":976,"low":944,"close":952,"volume":86},{"time":"Day 2","open":952,"high":960,"low":880,"close":888,"volume":96},{"time":"Day 3","open":888,"high":984,"low":880,"close":976,"volume":115}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":920},{"x":2,"y":920}],"label":"지지선","color":"#10b981"}]'::jsonb, ARRAY['불 트랩 (Bull Trap) - 가짜 상방 돌파', '베어 트랩 (Bear Trap) - 가짜 하방 이탈', '리테스트 실패 - 지지선 붕괴', '추세 추종 돌파 - 하방 랠리 가속']::text[], 1, '지지선을 아래로 뚫고 내려가 하락세가 지속될 것처럼 유도한 뒤, 매물을 털어내고 강력하게 다시 반등해 올리는 현상을 ''베어 트랩(Bear Trap)''이라고 합니다. 하락 돌파로 생각하고 공매도를 치거나 손절했던 사람들의 손실을 강제하며 가격이 급등하게 만듭니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (510, '시장구조/SR', '04_patterns_breakout.md', '저항선을 뚫어내기 직전 돌파 전조 현상 중 하나인 ''지지점 상승''의 특징을 골라보세요.', '[{"time":"Day 1","open":800,"high":840,"low":720,"close":816,"volume":115},{"time":"Day 2","open":816,"high":840,"low":744,"close":824,"volume":94},{"time":"Day 3","open":824,"high":840,"low":768,"close":832,"volume":121}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":840},{"x":2,"y":840}],"label":"저항선 (105)","color":"#ef4444"}]'::jsonb, ARRAY['저항선 부근에서 고점들이 점점 급락하며 붕괴하는 현상', '저항선 부근에서 저점들을 높여가며 밀어 올리는 수렴 현상', '거래량이 완전히 소멸하여 긴 횡보 상태를 보이는 현상', '지속적인 매도세로 인해 갑작스럽게 급락하는 현상']::text[], 1, '저항을 뚫지 못하고 밀려 내려올 때, 이전 저점보다 높은 지점에서 저점을 계속 잡아 올려주는 것은 매도 압력보다 매수 압력이 점점 올라오고 있음을 의미합니다. 수렴 끝에 돌파가 나타날 신뢰도가 매우 높습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (511, '추세/레짐', '03_market_structure.md', '저점들을 연결한 우상향 상승 추세선 아래로 캔들의 종가(마감가격)가 이탈했습니다. 기술적 분석 관점의 올바른 해석은 무엇입니까?', '[{"time":"W-5","open":800,"high":840,"low":800,"close":824,"volume":104},{"time":"W-4","open":824,"high":880,"low":816,"close":864,"volume":122},{"time":"W-3","open":864,"high":872,"low":840,"close":848,"volume":120},{"time":"W-2","open":848,"high":920,"low":856,"close":904,"volume":126},{"time":"Today","open":904,"high":912,"low":824,"close":832,"volume":99}]'::jsonb, '[{"type":"line","points":[{"x":0,"y":800},{"x":2,"y":840},{"x":4,"y":880}],"label":"상승 추세선","color":"#10b981"}]'::jsonb, ARRAY['추세선 이탈은 영향이 없으므로 비중 유지', '상승 추세 붕괴로 하락 반전 대비 비중 축소', '일시적인 속임수이므로 추가 불타기 진입', '채널 상단 도달에 따른 즉각적인 매수 대응']::text[], 1, '신뢰받던 우상향 상승 추세선 하방으로 캔들의 종가가 이탈 마감하는 것은 매수 중심의 시장 주도권이 붕괴했음을 뜻합니다. 지지를 잃은 하락 가속화 리스크에 대비해야 합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (512, '추세/레짐', '07_multitimeframe_regime.md', '아래 차트에서 고점들과 저점들이 일정한 평행 통로를 그리며 하락하고 있습니다. 채널 하단에 도달했을 때 단기 반등을 목표로 하는 매매의 명칭과 관점은?', '[{"time":"Day 1","open":1200,"high":1216,"low":1080,"close":1120,"volume":91},{"time":"Day 2","open":1120,"high":1176,"low":1112,"close":1160,"volume":98},{"time":"Day 3","open":1160,"high":1168,"low":1024,"close":1040,"volume":106},{"time":"Day 4","open":1040,"high":1104,"low":1032,"close":1088,"volume":125},{"time":"Day 5","open":1088,"high":1096,"low":944,"close":960,"volume":105}]'::jsonb, '[{"type":"channel","points":[{"x":0,"y":1200},{"x":4,"y":1080},{"x":0,"y":1080},{"x":4,"y":960}],"label":"하향 평행 채널","color":"#f59e0b"}]'::jsonb, ARRAY['추세 추종 매매 - 대세 상승이므로 장기 보유', '채널 하단 반등 매매 - 단기 역추세 매수 대응', '양방향 물타기 매매 - 평단가를 낮춰 탈출 대기', '돌파 매매 - 채널 하방 붕괴 확정 시 매수 대응']::text[], 1, '가격이 평행한 하락 터널 내에서 움직이는 ''하향 평행 채널(Descending Channel)''입니다. 채널 하단 라인 터치 시에는 기술적 단기 반등이 자주 출현하므로, 손절선을 짧게 잡고 반등 타점을 노리는 역추세(Counter-trend) 트레이딩이 가능합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (513, '추세/레짐', '03_market_structure.md', '우상향 상승 평행 채널의 상단 저항선 부근까지 애플 주가가 도달했습니다. 합리적인 추세 채널 트레이더의 대응은?', '[{"time":"Day 1","open":800,"high":816,"low":792,"close":808,"volume":114},{"time":"Day 2","open":808,"high":864,"low":808,"close":856,"volume":108},{"time":"Day 3","open":856,"high":872,"low":832,"close":840,"volume":107},{"time":"Day 4","open":840,"high":920,"low":840,"close":912,"volume":109},{"time":"Day 5","open":912,"high":928,"low":896,"close":904,"volume":135}]'::jsonb, '[{"type":"channel","points":[{"x":0,"y":816},{"x":4,"y":920},{"x":0,"y":792},{"x":4,"y":896}],"label":"상승 평행 채널","color":"#10b981"}]'::jsonb, ARRAY['채널 상방 돌파를 예상한 고배율 레버리지 매수', '채널 상단 저항에 따른 분할 익절 및 대기', '채널 중간 조정 시 지정을 통한 시장가 추격', '채널 붕괴 신호에 따른 전량 기계적 손절']::text[], 1, '상승 채널이라고 해도 상단 저항선에 닿으면 다시 채널 하단이나 중심선까지 조정을 받을 가능성이 매우 큽니다. 따라서 고점 영역에서의 추격매수를 금지하고, 기존 포지션을 분할 익절하는 기회로 삼아야 합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (514, '추세/레짐', '01_chart_market_basics.md', '고점들을 잇는 우하향 하락 추세선을 애플 주가가 대량의 거래량을 동반하며 장대양봉 종가로 상향 돌파(Breakout)했습니다. 의미하는 시그널은?', '[{"time":"Day 1","open":1040,"high":1056,"low":1000,"close":1016,"volume":86},{"time":"Day 2","open":1016,"high":1024,"low":960,"close":976,"volume":107},{"time":"Day 3","open":976,"high":984,"low":920,"close":936,"volume":94},{"time":"Day 4","open":936,"high":1024,"low":928,"close":1016,"volume":123}]'::jsonb, '[{"type":"line","points":[{"x":0,"y":1048},{"x":2,"y":976},{"x":3,"y":944}],"label":"하락 추세선","color":"#ef4444"}]'::jsonb, ARRAY['하락 추세 지속에 따른 숏 포지션 추가 매수', '하락 추세 돌파 및 상승 전환 가능성에 따른 매수', '속임수 돌파를 예상한 즉시 반대 숏 포지션 진입', '추세와 무관하게 횡보 흐름으로 판단해 관망']::text[], 1, '중요한 하락 추세선을 애플 주가 몸통이 확실하게 뚫고 마감하는 것은 기존 하락 관성의 지배력이 종료되고 상승 추세로 돌아설 수 있는 가장 대표적인 추세 전환(Reversal) 확인 시그널입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (515, '추세/레짐', '03_market_structure.md', '추세선 작도 시 신뢰도를 판단하는 가장 중요한 규칙은 무엇인가요?', '[{"time":"Day 1","open":800,"high":808,"low":800,"close":808,"volume":96},{"time":"Day 2","open":808,"high":840,"low":816,"close":832,"volume":113}]'::jsonb, '[]'::jsonb, ARRAY['차트상 선이 정배열로 정돈되어 그려질 때', '최소 3개 이상의 뚜렷한 저점/고점 터치 확인 시', '가파른 각도로 90도에 가깝게 작도될 때', '보조지표와 결합하여 수평으로 그려질 때']::text[], 1, '두 점만으로도 선을 그릴 수 있지만, 3번째 터치(3rd Touch)에서 정확한 지지나 저항을 보이고 반등해 주는 순간부터 시장 참여자들이 공식 인지하는 신뢰도 높은 추세선이 됩니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (516, '패턴/돌파', '04_patterns_breakout.md', '머리와 양쪽 어깨 형태를 그리며 넥라인 지지선(768달러)을 위태롭게 지탱하다가 하방으로 강한 캔들이 이탈했습니다. 숏(매도) 포지션 진입 시점은?', '[{"time":"Day 1","open":800,"high":920,"low":784,"close":880,"volume":84},{"time":"Day 2","open":880,"high":1040,"low":760,"close":840,"volume":89},{"time":"Day 3","open":840,"high":912,"low":768,"close":880,"volume":97},{"time":"Day 4","open":880,"high":888,"low":744,"close":752,"volume":119}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":768},{"x":3,"y":768}],"label":"넥라인 지지선","color":"#ef4444"}]'::jsonb, ARRAY['머리 꼭대기(1,040달러) 부근에서 예측 숏 진입', '오른쪽 어깨가 올라가고 있을 때 돌파 전 선진입', '저점들을 연결한 넥라인의 하방 돌파 완료 시', '패턴 완성과 무관하게 오른쪽 어깨 끝에서 대기']::text[], 2, '헤드앤숄더(Head & Shoulders) 패턴은 오른쪽 어깨를 그린 후, 저점 지지선인 ''넥라인(Neckline)''을 거래량을 실어 하방 돌파해야 최종 완성이 선언됩니다. 그전에 진입하면 넥라인 반등 시 극심한 손실을 입습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (517, '패턴/돌파', '04_patterns_breakout.md', '하락 추세 끝에서 애플 주가가 비슷한 깊이의 바닥을 두 번(이중바닥) 형성한 뒤, 중간 고점 저항선(넥라인)을 돌파했습니다. 향후 예상 방향성과 매수 타점은?', '[{"time":"Day 1","open":800,"high":800,"low":640,"close":680,"volume":102},{"time":"Day 2","open":680,"high":760,"low":672,"close":752,"volume":96},{"time":"Day 3","open":752,"high":760,"low":632,"close":656,"volume":126},{"time":"Day 4","open":656,"high":792,"low":648,"close":784,"volume":123}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":760},{"x":3,"y":760}],"label":"넥라인 (95)","color":"#3b82f6"}]'::jsonb, ARRAY['추가 폭락 가능성에 따른 전량 손절 대응', 'W 패턴 이중 바닥 완성 및 넥라인 돌파 시 매수', '박스권 횡보 판단에 따른 무대응 및 관망', '이중 바닥의 하방 이탈을 예상한 숏 포지션 진입']::text[], 1, 'W자 모양의 ''이중 바닥형(Double Bottom)'' 패턴입니다. 애플 주가가 하락을 멈추고 바닥을 두 차례 단단히 지지해 준 뒤 중간 봉우리(넥라인 760달러)를 돌파해 마감하면 추세가 상승으로 강하게 전환될 가능성이 매우 높습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (518, '패턴/돌파', '04_patterns_breakout.md', '급격한 기둥식 애플 주가 폭등(깃대) 후, 완만한 하향 평행 채널(깃발) 모양으로 횡보/수렴하다가 채널 상단을 강하게 돌파했습니다. 이 패턴과 예상 목표가는?', '[{"time":"Day 1","open":400,"high":640,"low":392,"close":624,"volume":110},{"time":"Day 2","open":624,"high":632,"low":576,"close":592,"volume":117},{"time":"Day 3","open":592,"high":608,"low":560,"close":568,"volume":106},{"time":"Day 4","open":568,"high":680,"low":560,"close":664,"volume":129}]'::jsonb, '[]'::jsonb, ARRAY['이중 천정형 패턴 - 고점 도달 시 숏 진입', '불 플래그 패턴 - 깃발 돌파 시 추가 상승 기대', '헤드앤숄더 패턴 - 넥라인 하방 돌파 타겟', '대칭 삼각수렴 패턴 - 변동성 축소 후 돌파 대기']::text[], 1, '대표적 강세 지속 패턴인 ''불 플래그(Bull Flag)''입니다. 급격한 상승(깃대) 뒤 숨 고르기 채널(깃발)을 상방 돌파하면, 이전 상승 파동의 크기(깃대 높이)만큼 추가로 수직 랠리를 시작하는 관성이 있습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (519, '패턴/돌파', '04_patterns_breakout.md', '상승 추세의 천정권에서 애플 주가가 동일한 가격 저항을 두 번 확인하며 M자 모양을 만든 뒤, 두 고점 사이의 저점 지지선인 넥라인(960달러)을 이탈했습니다. 올바른 해석은?', '[{"time":"Day 1","open":800,"high":1120,"low":792,"close":1080,"volume":85},{"time":"Day 2","open":1080,"high":1088,"low":960,"close":976,"volume":98},{"time":"Day 3","open":976,"high":1120,"low":968,"close":1104,"volume":117},{"time":"Day 4","open":1104,"high":1112,"low":920,"close":928,"volume":118}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":960},{"x":3,"y":960}],"label":"넥라인 (120)","color":"#ef4444"}]'::jsonb, ARRAY['상승 추세의 지속 연장에 따른 추가 매수', '이중 천정형(M 패턴) 완성에 따른 하락 반전 대비', '단기 조정에 따른 일시적 횡보 박스권 진입', '방향성 없는 일상적인 잔파동으로 판단해 홀딩']::text[], 1, '고점에서 지지받지 못하고 형성된 M자형 ''이중 천정형(Double Top)'' 패턴입니다. 두 차례 강력한 저항벽(1,120달러)을 넘지 못하고 넥라인(960달러)마저 붕괴했으므로 하방 추세가 가속화된다는 신호입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (520, '패턴/돌파', '04_patterns_breakout.md', '고점 저항선은 수평(평평함)을 유지하고 있으나, 저점 지지선은 점점 우상향하며 좁게 수렴하는 차트 형태의 명칭과 일반적인 돌파 방향은?', '[{"time":"Day 1","open":640,"high":800,"low":640,"close":760,"volume":119},{"time":"Day 2","open":760,"high":800,"low":688,"close":784,"volume":92},{"time":"Day 3","open":784,"high":800,"low":736,"close":792,"volume":101}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":800},{"x":2,"y":800}],"label":"수평 저항선","color":"#ef4444"},{"type":"line","points":[{"x":0,"y":640},{"x":1,"y":688},{"x":2,"y":736}],"label":"상승 지지선","color":"#10b981"}]'::jsonb, ARRAY['디센딩 트라이앵글 - 일반적으로 하방 돌파 기대', '어센딩 트라이앵글 - 매수 압력 우위로 상방 돌파 기대', '헤드앤숄더 패턴 - 넥라인 하방 돌파 기대', '상향 평행 채널 - 상하단 터치식 채널 매매 기대']::text[], 1, '고점 저항은 평평하고 저점은 계속 높아지는 삼각수렴을 ''어센딩 트라이앵글(Ascending Triangle)''이라고 합니다. 위로 갈수록 저점이 계속 올라가는 현상은 매수세가 가격을 위로 계속 압박하고 있음을 증명하며, 대개 저항선(800달러)을 상향 뚫고 오르는 확률이 높습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (521, '지표/컨플루언스', '06_technical_indicators.md', '애플 주가는 매일 하락하여 신저가를 갱신하고 있으나, RSI 보조지표의 저점은 점점 높아지는 현상을 발견했습니다. 올바른 용어와 매매 대응법은?', '[{"time":"D-4","open":880,"high":896,"low":784,"close":800,"volume":102},{"time":"D-3","open":800,"high":832,"low":768,"close":784,"volume":111},{"time":"D-2","open":784,"high":808,"low":736,"close":752,"volume":113},{"time":"D-1","open":752,"high":776,"low":744,"close":768,"volume":104},{"time":"Today","open":768,"high":792,"low":760,"close":784,"volume":135}]'::jsonb, '[]'::jsonb, ARRAY['하락 다이버전스 - 가격 상승 둔화에 따른 공매도', '상승 다이버전스 - 하락 둔화 및 반등 신호로 매수', '데드 크로스 - 이평선 하방 교차에 따른 관망', '과매수 이탈 시그널 - 단기 반등에 따른 매수']::text[], 1, '애플 주가의 가격 저점은 낮아지나 보조지표(RSI)의 운동 저점이 높아지는 현상을 ''상승 다이버전스(Bullish Divergence)''라고 합니다. 이는 하방 에너지의 실질적 소멸과 상승 압력의 내부 응축을 의미하는 기술적 분석에서 가장 신뢰도 높은 추세 전환 시그널입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (522, '지표/컨플루언스', '06_technical_indicators.md', '애플 주가는 급격히 치솟으며 최고가 갱신 랠리를 이어가고 있으나, RSI 지표의 고점은 계속 낮아지고 있습니다. 이 현상을 지칭하는 명칭과 대처법은?', '[{"time":"Day 1","open":800,"high":960,"low":792,"close":944,"volume":90},{"time":"Day 2","open":944,"high":976,"low":920,"close":960,"volume":101},{"time":"Day 3","open":960,"high":1080,"low":952,"close":1064,"volume":123}]'::jsonb, '[]'::jsonb, ARRAY['하락 다이버전스 - 매수 둔화 및 하락 우려로 익절', '상승 다이버전스 - 추가 급등 기대로 신규 매수', '골든 크로스 - 추세 강화에 따른 홀딩', '볼린저 밴드 스퀴즈 - 변동성 수축 후 돌파']::text[], 0, '애플 주가는 계속 고점을 높이고 있으나 보조지표의 고점은 꺾여 낮아지는 현상을 ''하락 다이버전스(Bearish Divergence)''라고 합니다. 이는 매수세의 힘이 표면적인 가격 상승에 비해 실질적으로 빠르게 축소되고 있음을 경고하며, 조만간 큰 급락이 발생할 확률이 높습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (523, '지표/컨플루언스', '06_technical_indicators.md', '이동평균선(EMA) 20일선(단기)이 50일선(중기)을 아래에서 위로 강하게 뚫고 솟구쳐 올랐습니다. 이 교차 현상의 정식 명칭은?', '[{"time":"Day 1","open":800,"high":816,"low":784,"close":792,"volume":113},{"time":"Day 2","open":792,"high":832,"low":792,"close":824,"volume":84},{"time":"Day 3","open":824,"high":880,"low":824,"close":872,"volume":92}]'::jsonb, '[]'::jsonb, ARRAY['데드 크로스 - 단기 이평의 하방 교차로 매도 신호', '골든 크로스 - 단기 이평의 상방 교차로 매수 신호', '볼린저 스퀴즈 - 변동성 수축 및 돌파 신호', '다이버전스 수렴 - 지표와 가격의 동반 횡보']::text[], 1, '단기 이평선이 장기 이평선을 위로 치고 올라가는 현상을 ''골든 크로스(Golden Cross)''라고 합니다. 이는 최근 매수 평단가가 장기 평균가보다 확연히 높아졌음을 시사하며, 상승 추세가 본 궤도에 올랐음을 입증해 줍니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (524, '지표/컨플루언스', '07_multitimeframe_regime.md', '매우 강력한 원웨이 폭락장 속에서 RSI 지표가 20(과매도 영역) 이하로 깊이 내려왔습니다. 이를 보고 ''과매도 반등''을 노리며 기계적 시장가 풀매수를 때렸을 때 나타나는 가장 빈번한 오류는?', '[{"time":"Day 1","open":800,"high":808,"low":704,"close":712,"volume":95},{"time":"Day 2","open":712,"high":720,"low":600,"close":608,"volume":20},{"time":"Day 3","open":608,"high":616,"low":496,"close":504,"volume":23}]'::jsonb, '[]'::jsonb, ARRAY['하락 추세 즉시 종료 및 V자 상승 반등 성공', '강력한 하락장에서의 지표 과매도 고착화 리스크', '거래량 급감으로 인한 호가 정지 및 상장 폐지', '애플 주가의 즉각적인 박스권 횡보 및 변동성 축소']::text[], 1, 'RSI 30 이하 과매도 영역은 반등 신호이기도 하지만, 추세가 지나치게 강력한 하락장일 때는 지표만 과매도 구역에 쳐박힌 채 가격은 계속 급락하는 ''과매도 고착화(Oversold Embedded)'' 상태가 이어집니다. 다이버전스나 캔들 반전형 확인 없이 수치만 보고 들어가는 매수는 깡통으로 가는 지름길입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (525, '지표/컨플루언스', '06_technical_indicators.md', '애플 주가의 변동성이 극도로 축소되며 볼린저 밴드의 폭이 매우 좁아지는 ''스퀴즈(Squeeze)'' 현상이 나타났습니다. 이후 기대되는 시장 변동성의 원리는 무엇인가요?', '[{"time":"Day 1","open":800,"high":808,"low":792,"close":800,"volume":111},{"time":"Day 2","open":800,"high":800,"low":792,"close":792,"volume":91},{"time":"Day 3","open":792,"high":800,"low":792,"close":800,"volume":94}]'::jsonb, '[]'::jsonb, ARRAY['변동성 사멸로 인한 장기 횡보 및 거래 정지', '밴드 스퀴즈 후 변동성 팽창에 따른 추세 분출', '애플 주가의 하방 붕괴로 인한 강한 하락 파동 시작', '이평선들의 수평 정렬에 따른 완전한 추세 고정']::text[], 1, '볼린저 밴드의 수축(Squeeze)은 시장의 숨 고르기 및 힘 모으기를 뜻합니다. 에너지가 최대한 압축된 후에는 밴드 상단 혹은 하단선을 이탈하며 매우 거대한 변동성 팽창(Expansion) 추세가 시작되므로, 방향성을 유심히 지켜봐야 합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (526, '리스크/심리', '09_risk_position_management.md', '총 투자 원금은 8,000만 원이며, 1회 거래 시 최대 손실 허용액을 원금의 2%(160만 원)로 제한하는 ''2% 룰''을 지키려 합니다. 진입하려는 종목의 손절 라인 폭이 -5%일 때, 최대 매수(진입) 가능 금액은 얼마인가요?', '[{"time":"Day 1","open":80000,"high":84000,"low":78400,"close":81600,"volume":111},{"time":"Day 2","open":81600,"high":82400,"low":80000,"close":80000,"volume":113}]'::jsonb, '[]'::jsonb, ARRAY['8,000만 원 (원금 전액 진입)', '1,600만 원 (원금의 20% 진입)', '3,200만 원 (원금의 40% 진입)', '4,000만 원 (원금의 50% 진입)']::text[], 2, '2% 룰에 기초한 포지션 사이징 공식은 `진입금액 = (총원금 * 리스크비율) / 손절비율` 입니다. 따라서 `160만 원 / 0.05 = 3,200만 원`이 됩니다. 3,200만 원어치 미국 주식을 샀을 때 가격이 -5% 떨어져 강제 손절을 맞아도 내 계좌 총액에서 손실을 보는 돈은 정확히 2%인 160만 원으로 통제됩니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (527, '리스크/심리', '09_risk_position_management.md', '어느 미국 주식에 80,000원에 매수 진입합니다. 손절 라인은 76,000원(-5%)에 배치하고, 목표가는 92,000원(+15%)에 설정했습니다. 이 트레이딩 시나리오의 손익비(Risk-to-Reward Ratio)는 얼마입니까?', '[{"time":"Today","open":80000,"high":80000,"low":80000,"close":80000}]'::jsonb, '[]'::jsonb, ARRAY['1 : 1 (동일한 기대 수익과 리스크)', '1 : 2 (기대 수익이 리스크의 2배)', '1 : 3 (기대 수익이 리스크의 3배)', '2 : 1 (기대 수익이 리스크의 0.5배)']::text[], 2, '손절 폭(4,000원) 대비 익절 폭(12,000원)의 비례를 의미하므로 `1,500 / 500 = 3`, 즉 손익비는 1:3이 됩니다. 이처럼 잃는 돈의 최소 2~3배를 벌 수 있는 손익비 높은 구간만 반복적으로 거래해야 장기적으로 계좌가 생존합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (528, '리스크/심리', '09_risk_position_management.md', '손익비를 엄격히 통제하여 항상 기대 손실의 2배를 버는 매매(손익비 1:2)만 고집합니다. 이 경우 내 계좌 잔고가 손실 없이 제자리걸음(본전)을 유지하기 위해 필요한 수학적인 최소 승률(Win Rate)은 얼마인가요?', '[{"time":"Today","open":800,"high":800,"low":800,"close":800}]'::jsonb, '[]'::jsonb, ARRAY['50.0% (최소 절반 이상 성공)', '33.3% (3번 중 1번 성공으로 본전)', '25.0% (4번 중 1번 성공으로 본전)', '66.6% (3번 중 2번 성공으로 본전)']::text[], 1, '손익비가 1:2일 경우, 1번 이기면 +2를 벌고 2번 지면 -2를 잃으므로 3번 매매 중 1번만 이겨도 누적 수익은 0이 됩니다. 즉 손익비를 1:2 이상으로 유지하면 수학적으로 승률이 겨우 33.3%만 나와도 절대 파산하지 않고 계좌가 우상향할 발판이 마련됩니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (529, '셋업/실행', '08_setup_entry_exit.md', '80,000원에 산 미국 주식이 120,000원까지 올랐습니다. 이익을 보존하면서 상승세를 끝까지 타기 위해, 최고점 대비 10% 하방 이탈 시 즉시 자동 익절되는 ''추적 손절매(Trailing Stop)''를 적용했습니다. 최고점 120,000원 달성 후 애플 주가가 조정받을 때 실제로 청산(익절)되는 가격은 얼마인가요?', '[{"time":"Day 1","open":80000,"high":96000,"low":79200,"close":95200,"volume":103},{"time":"Day 2","open":95200,"high":120000,"low":94400,"close":118400,"volume":104}]'::jsonb, '[]'::jsonb, ARRAY['80,000원 (본전 수준 청산)', '108,000원 (최고점 대비 10% 하방 청산)', '112,000원 (최고점 대비 6.6% 하방 청산)', '96,000원 (최고점 대비 20% 하방 청산)']::text[], 1, '추적 손절매(Trailing Stop)는 가격 상승에 따라 청산 가격을 자동으로 올려주는 주문입니다. 최고점 120,000원을 기록했으므로 청산 트리거 라인은 최고점에서 10% 차감된 `15,000 * 0.9 = 108,000원`으로 확정 셋업되며, 애플 주가가 108,000원을 건드리는 순간 자동 이익실현됩니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (530, '리스크/심리', '09_risk_position_management.md', '레버리지 10배를 적용하여 애플 롱(매수) 포지션을 구축했습니다. 만약 애플 가격이 매수가 대비 몇 % 역방향으로 등락하면 내 투자 원금이 100% 강제 청산(증거금 완전 소멸)당할까요?', '[{"time":"Today","open":400000,"high":400800,"low":399200,"close":400000}]'::jsonb, '[]'::jsonb, ARRAY['5.0% 하락 시', '10.0% 하락 시', '20.0% 하락 시', '100.0% 하락 시']::text[], 1, '레버리지 비율과 청산 거리 비율은 역수 관계입니다. `100% / 레버리지 배수` 공식에 따라, 10배 레버리지는 애플 주가가 내 베팅의 반대 방향으로 단 10%만 움직여도 투자 원금이 전부 증발하고 포지션이 강제 종료(Liquidation)됩니다. 고배율 레버리지가 파산의 지름길인 이유입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (531, '캔들/가격행동', '02_candlestick_price_action.md', '상승 추세 고점 영역(1,200달러선)에서 몸통이 매우 작고 아래꼬리가 긴 행잉맨(Hanging Man) 캔들이 출현한 이후, 다음 날 시가가 전일 종가보다 큰 갭을 그리며 낮게 하락 출발(1,160달러)했습니다. 포지션을 보유한 스윙 트레이더로서 가장 적절한 위기 대응 행동은 무엇입니까?', '[{"time":"Day 1","open":960,"high":1000,"low":952,"close":992,"volume":106},{"time":"Day 2","open":992,"high":1080,"low":984,"close":1072,"volume":119},{"time":"Day 3","open":1072,"high":1184,"low":1064,"close":1168,"volume":113},{"time":"Day 4","open":1168,"high":1208,"low":1120,"close":1176,"volume":109},{"time":"Day 5","open":1128,"high":1144,"low":1080,"close":1088,"volume":119}]'::jsonb, '[]'::jsonb, ARRAY['상승 랠리를 기대로 보유 비중 확대 및 추격 매수', '일시적 속임수(휩소) 판단으로 추가 레버리지 매수', '행잉맨 출현 후 갭하락에 따른 전량 또는 일부 정리', '조치 없이 전고점 돌파 시까지 무기한 관망 및 홀딩']::text[], 2, '고가권에서 나타난 행잉맨(Hanging Man)은 잠재적 하락 전환 신호이며, 특히 다음날 갭하락 음봉으로 직전 행잉맨의 저가를 깨고 내려가는 움직임은 강력한 하락 컨펌 시그널입니다. 따라서 이 시점에서는 즉시 비중을 전량 정리하거나 최소 절반 이상 매도하여 리스크를 통제하는 것이 정석입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (532, '캔들/가격행동', '01_chart_market_basics.md', '지속적인 하락 추세 도중 바닥권(640달러선)에서 시가와 종가가 일치하고 긴 아래꼬리를 단 십자 형태의 도지(Doji) 캔들이 생성되었습니다. 다음 날 대량의 거래량과 함께 장대양봉이 솟구치며 696달러로 마감하는 샛별형(Morning Star) 조합이 확정되었습니다. 이때 가장 합리적인 매수 진입 지점과 손절가 기준은 무엇입니까?', '[{"time":"Day 1","open":800,"high":808,"low":744,"close":752,"volume":112},{"time":"Day 2","open":752,"high":760,"low":704,"close":712,"volume":107},{"time":"Day 3","open":712,"high":720,"low":640,"close":648,"volume":98},{"time":"Day 4","open":640,"high":656,"low":600,"close":640,"volume":128},{"time":"Day 5","open":640,"high":704,"low":632,"close":696,"volume":127}]'::jsonb, '[]'::jsonb, ARRAY['손절 없이 100% 비중으로 시장가 매수', '샛별형 완성에 따라 분할 매수 후 최저점 손절 셋업', '바닥 도달 기대로 주문 없이 무작정 대기', '상승 꼭대기에서 숏 진입 후 손절 없이 방치']::text[], 1, '하락 추세 끝에 도지와 장대양봉이 결합된 샛별형(Morning Star)은 매우 신뢰도 높은 바닥 상승 전환 신호입니다. 이 패턴을 보고 진입할 때는 반등 상승세에 분할 매수로 동참하되, 바닥을 잡아준 도지 캔들의 최저점(600달러) 아래를 최종 손절 라인으로 잡는 것이 수학적으로 가장 리스크 대비 보상 비율(손익비)이 훌륭한 전략입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (533, '거래량/유동성', '02_candlestick_price_action.md', '애플 주가가 강력한 횡보 박스권 고점(1,600달러 저항선)에 세 번째 터치하는 와중에, 윗꼬리가 길고 몸통이 매우 얇은 유성형(Shooting Star) 캔들이 이틀 연속 발생했습니다. 거래량 역시 저항선 부근에서 매수세가 더 올라가지 못하고 매도 압력이 실려 나타났습니다. 롱(매수) 포지션을 들고 있는 당신의 합리적인 의사결정은?', '[{"time":"Day 1","open":1400,"high":1480,"low":1392,"close":1456,"volume":112},{"time":"Day 2","open":1456,"high":1560,"low":1440,"close":1544,"volume":92},{"time":"Day 3","open":1544,"high":1616,"low":1520,"close":1528,"volume":123},{"time":"Day 4","open":1528,"high":1608,"low":1504,"close":1512,"volume":104}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":1600}],"label":"박스권 상단 저항선 (200)","color":"#ef4444"}]'::jsonb, ARRAY['신고가 갱신을 예상한 전재산 추가 불타기', '저항 돌파 실패 신호 확인 후 분할 익절 및 관망', '손익 평단가 부근이므로 추가 손절 없이 방치', '거래를 종료하고 다른 신규 급등주를 시장가 추격']::text[], 1, '박스권 상단 저항선(1,600달러)에 부딪히며 나타난 유성형(Shooting Star) 연속 출현은 저항 돌파 실패와 차익 실현 세력의 강력한 등장을 경고하는 캔들 신호입니다. 돌파를 확신하기보다는 리스크 관리 관점에서 물량을 축소(50% 분할 익절)하거나 전량 매도하여 이익을 확정 짓는 것이 현명합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (534, '캔들/가격행동', '02_candlestick_price_action.md', '극심한 하락 추세 중 800달러선 아래로 떨어지던 애플 주가가 전일 장대음봉을 형성했습니다. 그러나 당일 시가는 갭하락하여 더 낮게 시작했으나, 장중에 강한 매수세가 들어오며 전일 음봉 몸통의 정확히 70% 라인(744달러선) 위로 덮어버리는 관통형(Piercing Line) 상승 캔들로 마감했습니다. 종가 매수(롱) 진입 시 원칙 대응은?', '[{"time":"Day 1","open":880,"high":888,"low":832,"close":840,"volume":114},{"time":"Day 2","open":840,"high":848,"low":776,"close":784,"volume":109},{"time":"Day 3","open":736,"high":808,"low":728,"close":800,"volume":109}]'::jsonb, '[]'::jsonb, ARRAY['상승 모멘텀 미달로 매수 보류 및 하방 숏 포지션 진입', '관통형 확인 후 분할 매수 및 당일 최저점 손절 설정', '손절 라인 설정 없이 100% 비중 시장가 매수 집행', '조정을 대기하며 예약 주문 없이 무작정 관망 유지']::text[], 1, '전일 음봉의 50% 이상을 당일 양봉 몸통으로 관통해 올린 ''관통형(Piercing Line)''은 하락 모멘텀이 쇠퇴하고 저가 매수세가 우위를 점하기 시작했음을 뜻하는 바닥 신호입니다. 이 패턴 확인 후 진입할 시에는 손절 한도를 당일 최저점(728달러) 밑에 가깝게 설정할 수 있어 매우 유리한 리스크 대비 기대수익 매매가 성립됩니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (535, '캔들/가격행동', '05_volume_liquidity.md', '강한 급등세를 지속하던 애플 주가가 최고점에서 큰 거래량을 터뜨리며 장대양봉을 만들었습니다. 그러나 다음 날, 전일 양봉 몸통의 한가운데 범위 안에서 움직이며 시가와 종가가 모두 갇혀버리는 짧은 음봉인 ''하락 잉태형(Bearish Harami)'' 캔들이 형성되었습니다. 단기 스윙 트레이더로서 당신의 포지션 리스크 관리 행동은?', '[{"time":"Day 1","open":960,"high":1024,"low":952,"close":1016,"volume":89},{"time":"Day 2","open":1016,"high":1104,"low":1008,"close":1088,"volume":84},{"time":"Day 3","open":1064,"high":1072,"low":1040,"close":1048,"volume":114}]'::jsonb, '[]'::jsonb, ARRAY['상승 둔화 조짐에 따른 보유 물량 50% 분할 익절', '추세 일시 조정으로 간주하여 비중 확대 추가 매수', '추세 종결 판단에 따른 고배율 숏 포지션 즉시 진입', '이익 실현 없이 전량 장기 보유 전략 유지']::text[], 0, '하락 잉태형(Bearish Harami)은 이전의 강한 상승 추세 동력이 감속하기 시작했으며, 매도 압력이 힘을 기르고 있음을 암시하는 변곡 캔들입니다. 따라서 단기 스윙 트레이더는 물량의 일부(50%)를 분할 익절하여 리스크를 낮추고, 다음 캔들에서 이전 양봉 저점을 깨뜨리는 하락 하방 이탈이 추가되는지 지켜보는 것이 정석입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (536, '시장구조/SR', '03_market_structure.md', '오랫동안 지켜지던 핵심 지지선인 800달러 부근에서 매수 진입을 완료했습니다. 그러나 가격이 대량의 거래량을 동반하며 장대음봉으로 지지선을 하방으로 강하게 뚫어냈고, 종가가 지지선 대비 1.5% 아래인 98.40달러로 결정되었습니다. 이 상황에서 원칙을 지키는 올바른 위기 대응 행동은?', '[{"time":"Day 1","open":840,"high":864,"low":816,"close":824,"volume":90},{"time":"Day 2","open":824,"high":832,"low":792,"close":800,"volume":95},{"time":"Day 3","open":800,"high":808,"low":784,"close":788,"volume":96}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":800}],"label":"중요 지지선 (100)","color":"#10b981"}]'::jsonb, ARRAY['추가 물타기를 위해 자금을 동원하여 평단가 관리', '중요 지지선 붕괴(Breakdown) 확인 후 즉시 전량 손절', '지속 하락 시 추가 평단가 관리를 위해 매수 유보', '하방 이탈 시 즉시 반대 고배율 롱 포지션 진입']::text[], 1, '거래량이 동반된 장대음봉으로 주요 지지선 아래에서 종가가 결정되는 이탈 마감은 매수 지지 세력의 패배이자 추세 붕괴(Breakdown)의 신호입니다. 이 시점에서 물타기를 하거나 존버를 하면 파산적인 하락 조정을 겪을 수 있으므로 즉시 룰에 근거한 ''전량 손절''을 집행해야 계좌를 살릴 수 있습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (537, '시장구조/SR', '03_market_structure.md', '1,200달러의 중요 저항선이 강한 거래량을 실은 돌파봉으로 뚫렸습니다. 이후 애플 주가가 숨 고르기 조정을 받으며 1,200달러 부근까지 되돌아왔고(리테스트 구간), 저항선 부근에서 거래량이 크게 감소하며 아래꼬리가 달린 도지 캔들로 안착하는 모습을 보입니다. 이때 가장 안전하고 합리적인 매매 조치는?', '[{"time":"Day 1","open":1120,"high":1168,"low":1112,"close":1152,"volume":83},{"time":"Day 2","open":1152,"high":1256,"low":1144,"close":1240,"volume":100},{"time":"Day 3","open":1240,"high":1248,"low":1192,"close":1200,"volume":92}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":1200}],"label":"돌파된 저항선 -> 지지선 전환선 (150)","color":"#3b82f6"}]'::jsonb, ARRAY['가짜 돌파(휩소) 판단에 따른 고배율 숏 진입', '돌파 후 리테스트 성공 확인 시 지지선 눌림목 매수', '추격 매수 기회 상실로 판단하고 거래 포기', '1,280달러 추가 돌파를 타겟으로 시장가 추격 매수']::text[], 1, '강하게 돌파된 저항선은 룰 체인지에 의해 지지선으로 변합니다(역할 전환). 돌파 당시 추격 매수하기보다, 돌파된 선(1,200달러)으로 애플 주가가 되돌아오는 리테스트(Retest) 시점에 저조한 거래량과 지지 캔들을 확인하고 손절선을 바로 밑에 설정하여 눌림목 진입하는 것이 리스크가 가장 적은 프로 트레이더의 정석입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (538, '시장구조/SR', '03_market_structure.md', '가격이 640달러 지지선 근처에서 반등을 시도하고 있으나, 반등의 폭이 직전 고점에 턱없이 못 미치며 저점 부근으로 다시 짓눌리고 있습니다. 즉, 고점들이 계속 낮아지는 하락 우위 삼각수렴(Descending)의 형태가 지지선 바로 위에서 감지됩니다. 이 시점에서 지지선 반등을 믿고 신규 매수(롱)를 진입하는 것은 원칙에 맞습니까?', '[{"time":"Day 1","open":760,"high":784,"low":640,"close":704,"volume":95},{"time":"Day 2","open":704,"high":728,"low":640,"close":672,"volume":108},{"time":"Day 3","open":672,"high":688,"low":640,"close":648,"volume":112}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":640}],"label":"지지선 (80)","color":"#10b981"}]'::jsonb, ARRAY['삼중 바닥 지지로 판단하고 매수 비중 대폭 확대', '디센딩 수렴 확인 후 하방 이탈 위험 대비 관망', '물타기 평단가 관리를 위해 매수 보증금 추가 투입', '추세와 무관하게 숏 포지션으로 전환 후 무기한 보유']::text[], 1, '지지선 부근에서 고점이 점점 낮아지는 ''디센딩'' 형태는 매수 지원 강도가 둔화되고 매도 출하 공급이 가격을 계속 하방으로 압박하고 있음을 증명합니다. 지지 성공보다 지선 하방 붕괴 후 급락할 확률이 높으므로, 지지선이라는 명목만으로 함부로 매수 진입하지 말고 돌파/이탈 컨펌을 기다려 관망하는 것이 현명합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (539, '거래량/유동성', '05_volume_liquidity.md', '애플 주가가 960달러의 장기 저항벽을 거래량이 거의 실리지 않은 얇은 양봉으로 상방으로 살짝 뚫었으나, 바로 다음 날 직전 양봉 몸통을 통째로 덮어버리는 대량 거래량의 장대음봉이 출현하며 928달러로 곤두박질쳤습니다. 매수 포지션을 추격 진입했던 당신의 올바른 조치는?', '[{"time":"Day 1","open":896,"high":944,"low":888,"close":936,"volume":101},{"time":"Day 2","open":936,"high":976,"low":928,"close":968,"volume":347},{"time":"Day 3","open":968,"high":976,"low":920,"close":928,"volume":388}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":960}],"label":"장기 저항선 (120)","color":"#ef4444"}]'::jsonb, ARRAY['불 트랩(Bull Trap) 확인 후 추가 하락 방지 즉시 손절', '저항선 부근 매수세 복귀를 기대하며 전량 홀딩', '평단가 관리 차원에서 추가 물타기 매수 집행', '상황을 판단하기 위해 시장가로 추가 분할 진입']::text[], 0, '거래량 없는 돌파 직후에 거래량 실린 강한 음봉이 기존 돌파선(960달러) 아래로 재진입하여 마감하는 현상은 전형적인 불 트랩(Bull Trap/가짜 돌파) 함정입니다. 돌파 당시 샀던 매수자들의 패닉 셀이 출현하며 하락 가속화가 나오기 쉬우므로 즉시 손절하여 물량을 털어내야 생존할 수 있습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (540, '시장구조/SR', '10_psychology_routine_review.md', '주요 지지선(2,000달러선)이 아래로 무너질 때 제때 손절 처리를 하지 못해 애플 주가가 1,760달러선까지 끌려 내려갔습니다. 다행히 단기 매도 진정세로 반등이 나와 애플 주가가 다시 2,000달러 부근까지 상승하여 회복을 눈앞에 두고 있습니다. 이때 손실을 최소화하는 현명한 시나리오 대처법은?', '[{"time":"Day 1","open":2080,"high":2096,"low":1984,"close":1992,"volume":90},{"time":"Day 2","open":1992,"high":2000,"low":1760,"close":1776,"volume":121},{"time":"Day 3","open":1776,"high":1880,"low":1768,"close":1872,"volume":122},{"time":"Day 4","open":1872,"high":2008,"low":1864,"close":1992,"volume":109}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":2000}],"label":"붕괴된 지지선 -> 저항선으로 변형 (250)","color":"#ef4444"}]'::jsonb, ARRAY['역할 전환(저항선) 도달에 따른 탈출 및 현금화', 'V자 반등 성공 확신에 따른 추가 매수 비중 확대', '원금 회복 및 추가 수익 시까지 영구 홀딩 관망', '하락 추세 지속에 따른 반대 숏 포지션 스위칭']::text[], 0, '하방으로 깨진 지지선은 반등할 때 가장 뚫기 힘든 ''강력한 저항선''으로 성격이 바뀝니다. 따라서 손절 기회를 놓치고 물려있던 트레이더는 반등하여 옛 지지선(2,000달러)에 도달했을 때를 ''최선의 리스크 탈출 기회(탈출구)''로 삼아 전량 매도하거나 비중을 극도로 덜어내야 다가올 2차 하락 파동의 파산을 막을 수 있습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (541, '추세/레짐', '03_market_structure.md', '애플 주가가 매우 가파르게 올라가던 1차 단기 상승 추세선을 강한 음봉 종가로 뚫고 내려왔습니다. 다행히 각도가 완만하고 탄탄한 장기 핵심 상승 추세선은 저 밑에 지지 영역을 유지하고 있습니다. 스윙 트레이더로서 가장 정석적인 포지션 제어 방식은 무엇인가요?', '[{"time":"Day 1","open":800,"high":816,"low":800,"close":816,"volume":93},{"time":"Day 2","open":816,"high":880,"low":816,"close":872,"volume":84},{"time":"Day 3","open":872,"high":1000,"low":872,"close":992,"volume":118},{"time":"Day 4","open":992,"high":1000,"low":912,"close":920,"volume":114}]'::jsonb, '[{"type":"line","points":[{"x":0,"y":800},{"x":3,"y":984}],"label":"가파른 단기 추세선 (붕괴)","color":"#ef4444"},{"type":"line","points":[{"x":0,"y":800},{"x":3,"y":880}],"label":"완만한 장기 추세선 (지탱 중)","color":"#10b981"}]'::jsonb, ARRAY['추세 붕괴 판단에 따른 전량 손절 및 영구 이탈', '가속 추세 이탈에 따른 50% 분할 익절 및 분산', '단기 지지선 붕괴를 무시한 고배율 물타기 매수', '장기 추세선까지 조정을 대비한 신규 매수 대기']::text[], 1, '가파르게 우상향하던 가속 추세선(Accelerated Trendline)이 하방 돌파되는 것은 기존 폭등 랠리의 속도가 둔화되고 완만한 본래 장기 추세선(장기 매물대)을 향해 정상적인 가격 조정을 받기 시작했음을 뜻합니다. 따라서 물량의 50%가량을 털어 수익을 실현하고 남은 물량으로 장기 추세선의 3rd Touch 지지 성공 여부를 테스트하는 것이 리스크 관리의 기본입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (542, '거래량/유동성', '05_volume_liquidity.md', '고점과 저점이 연속으로 낮아지는 명확한 하락 평행 채널 내에서 하락 압력을 받아 숏(매도) 포지션을 잡고 수익 중이었습니다. 그런데 당일 캔들이 대량의 거래량과 함께 장대양봉을 그리며 채널 상단 저항선 위로 종가 안착(상방 돌파)했습니다. 숏 포지션을 쥔 당신의 결단은?', '[{"time":"Day 1","open":800,"high":816,"low":720,"close":736,"volume":93},{"time":"Day 2","open":736,"high":752,"low":656,"close":664,"volume":121},{"time":"Day 3","open":664,"high":680,"low":600,"close":608,"volume":105},{"time":"Day 4","open":608,"high":720,"low":600,"close":712,"volume":111}]'::jsonb, '[{"type":"channel","points":[{"x":0,"y":816},{"x":3,"y":688},{"x":0,"y":720},{"x":3,"y":608}],"label":"하락 평행 채널 상한/하한","color":"#f59e0b"}]'::jsonb, ARRAY['상단 돌파 확인 즉시 숏 전량 손절 및 대피', '채널 재진입 기대로 숏 포지션 추가 물타기', '손절 없이 유지하면서 포지션 본전 도달 대기', '포지션 유지 후 증거금을 출금하여 강제 횡보']::text[], 0, '하락 평행 채널의 상단 저항선 상향 돌파(Breakout)는 기존 하락 트렌드의 사멸과 매수세 지배령 복귀를 뜻합니다. 지표와 거래량이 동반된 돌파 확인 시에는 숏 포지션을 지체 없이 기계적으로 칼손절하여 자산을 보호하는 것이 원칙입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (543, '추세/레짐', '07_multitimeframe_regime.md', '우상향하는 상승 평행 채널 안에서 순항하던 애플 주가가 중심선(Mid-line)을 뚫고 하방으로 이탈 마감했습니다. 이후 중심선 부근까지 반등을 시도했으나 재차 저항을 받고 아래꼬리가 꺾여 채널 하단선을 향해 하락 조정을 재개하려 합니다. 신규 매수(롱) 포지션 진입을 계획 중인 트레이더의 대응법은?', '[{"time":"Day 1","open":800,"high":864,"low":792,"close":848,"volume":94},{"time":"Day 2","open":848,"high":896,"low":816,"close":832,"volume":123},{"time":"Day 3","open":832,"high":848,"low":784,"close":800,"volume":118}]'::jsonb, '[{"type":"channel","points":[{"x":0,"y":880},{"x":2,"y":896},{"x":0,"y":784},{"x":2,"y":800}],"label":"상승 평행 채널","color":"#10b981"}]'::jsonb, ARRAY['채널 내 유지를 기대로 지정가 즉시 매수', '중심선 저항 확인 후 채널 하단 안착 대기', '하방 휩소 판단에 따른 레버리지 추가 매수', '추세와 무관한 숏 포지션 구축 후 관망']::text[], 1, '상승 평행 채널에서 미드라인(Mid-line)은 매우 중요한 심리적 지지와 저항선입니다. 미드라인이 저항선으로 뒤바뀌어 음봉으로 흘러내리는 경우 높은 확률로 채널 하단 경계선까지 가격이 조정을 받게 되므로, 중심선 저항 확인 시점에서는 섣부른 매수 진입을 피하고 채널 하단의 명확한 반등 타점을 유도해야 합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (544, '추세/레짐', '03_market_structure.md', '저점과 저점을 이은 장기 상승 추세선 상의 3번째 터치 포인트(지지선 부근)에 캔들이 매우 조심스럽게 안착하며 아래꼬리를 형성했습니다. 손익비(Risk-to-Reward) 관점에서 가장 이상적인 매수 타점 집행 및 손절 셋업 방법은 무엇입니까?', '[{"time":"Day 1","open":640,"high":720,"low":640,"close":704,"volume":104},{"time":"Day 2","open":704,"high":792,"low":704,"close":760,"volume":115},{"time":"Day 3","open":760,"high":768,"low":720,"close":736,"volume":93}]'::jsonb, '[{"type":"line","points":[{"x":0,"y":640},{"x":1,"y":704},{"x":2,"y":720}],"label":"상승 추세선 (3rd Touch 기대선)","color":"#10b981"}]'::jsonb, ARRAY['손절 라인 없이 지정가로 1차 매수 몰빵 진입', '3rd Touch 타점 진입 및 추세선 하단 칼손절 셋업', '하방 붕괴 예상을 통한 고배율 숏 즉각 진입', '목표가 터치 시까지 무작정 대기 후 추격 매수']::text[], 1, '추세선 상의 3번째 지지 포인트(3rd Touch)는 추세 신뢰도가 형성되는 대단히 성공률 높은 정석적 눌림목 타점입니다. 진입 가격과 손절 라인(추세선 이탈가)의 거리가 매우 가깝기 때문에 기대 수익 대비 잃을 금액이 매우 적어 프로 트레이더들이 가장 선호하는 칼손절 매수 스팟입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (545, '추세/레짐', '08_setup_entry_exit.md', '애플 주가가 장기 하락 추세선을 힘차게 뚫어 상방 돌파(Breakout)했습니다. 하지만 돌파선 바로 위(약 960달러)에 최근 여러 번 강한 매도 잔량이 쏟아지며 가격을 찍어 눌렀던 핵심 매물대 저항선이 떡하니 버티고 있습니다. 당신의 신규 진입 매수 순서는 어떻게 결정해야 안전할까요?', '[{"time":"Day 1","open":1000,"high":1008,"low":880,"close":896,"volume":108},{"time":"Day 2","open":896,"high":904,"low":784,"close":800,"volume":119},{"time":"Day 3","open":800,"high":952,"low":792,"close":944,"volume":113}]'::jsonb, '[{"type":"line","points":[{"x":0,"y":1000},{"x":1,"y":896},{"x":2,"y":840}],"label":"하락 추세선 (돌파됨)","color":"#ef4444"},{"type":"horizontal-line","points":[{"x":0,"y":960}],"label":"수평 매물대 저항선 (120)","color":"#ef4444"}]'::jsonb, ARRAY['돌파 확인 즉시 종가 기준 시장가 100% 매수', '수평 저항 돌파 검증 시까지 매수 유보 및 대기', '돌파 전조 현상 기대로 레버리지 선배팅 집행', '추세선 돌파를 가짜로 간주한 숏 포지션 진입']::text[], 1, '하락 추세선의 돌파는 긍정적이나 수평 매물대 저항선이 바로 위에 있다면 이중 저항 작용에 의해 막히는 경우가 대단히 잦습니다. 추세선 상방 휩소(속임수)에 당하지 않으려면 겹저항 중 최종 관문인 수평 매물대 저항선 돌파 혹은 리테스트 지지를 확인하고 진입하는 것이 보수적이고 안전한 원칙입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (546, '패턴/돌파', '04_patterns_breakout.md', '고점 수평 저항선(800달러)과 저점 상승 지지선으로 이루어진 어센딩 트라이앵글 수렴 도중, 800달러를 돌파할 것을 미리 예측하고 784달러에서 비중 100% 매수로 진입했습니다. 그러나 애플 주가는 돌파에 실패하고 하방 상승 지지선을 대량 거래량 장대음봉으로 뚫어 736달러로 하향 마감했습니다. 올바른 매매 액션은?', '[{"time":"Day 1","open":640,"high":800,"low":640,"close":760,"volume":83},{"time":"Day 2","open":760,"high":800,"low":704,"close":776,"volume":112},{"time":"Day 3","open":776,"high":784,"low":728,"close":736,"volume":127}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":800}],"label":"수평 저항선 (100)","color":"#ef4444"},{"type":"line","points":[{"x":0,"y":640},{"x":1,"y":704},{"x":2,"y":752}],"label":"상승 지지선 (붕괴)","color":"#10b981"}]'::jsonb, ARRAY['하방 이탈 확인 즉시 손절하여 추가 폭락 차단', '조정을 이용해 평단가를 조절하는 분할 물타기', '본전 탈출 시까지 포지션을 유지하며 관망', '손절 라인을 하단으로 조정하고 대기 주문 유지']::text[], 0, '어센딩 트라이앵글은 상방 확률이 다소 높지만, 하단 지지선이 뚫려 무너지는 순간 패턴 실패와 함께 엄청난 실망 매도 매물이 출하됩니다. 특히 돌파를 미리 예견해 들어간 포지션은 즉시 룰 위반을 시정하고 손절(736달러)해야 큰 자산 보호를 할 수 있습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (547, '패턴/돌파', '04_patterns_breakout.md', '하락 바닥권에서 왼쪽 어깨, 머리, 오른쪽 어깨를 그리며 역헤드앤숄더(Inverse Head & Shoulders) 패턴이 완성되었습니다. 가격이 넥라인 저항벽(640달러선)을 돌파했으나 이미 장대양봉으로 높이 솟아(696달러) 추격 매수 타이밍을 아쉽게 놓쳤습니다. 이때 뇌동매매를 피하는 가장 현명한 매수 타점 공략법은?', '[{"time":"Day 1","open":760,"high":760,"low":560,"close":624,"volume":105},{"time":"Day 2","open":624,"high":656,"low":480,"close":600,"volume":123},{"time":"Day 3","open":600,"high":632,"low":544,"close":608,"volume":121},{"time":"Day 4","open":608,"high":704,"low":600,"close":696,"volume":97}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":640}],"label":"넥라인 저항선 (80)","color":"#ef4444"}]'::jsonb, ARRAY['포모(FOMO) 현상에 따른 돌파봉 꼭대기 추격 매수', '돌파 넥라인 부근의 리테스트 조정 눌림목 매수', '반등 랠리 종결 판단에 따른 역베팅 숏 포지션', '추세 전환 확인 후 무조건적인 관심종목 제외']::text[], 1, '강한 패턴 돌파봉 확인 후 뇌동매매로 추격하는 것은 손절 거리가 너무 멀어져 손익비가 최악인 나쁜 습관입니다. 정석 돌파 트레이더는 넥라인 역할 전환 지점(640달러)으로의 되돌림 눌림목(Retest)을 차분히 기다려 리스크를 짧게 끊고 들어가는 훈련을 해야 합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (548, '패턴/돌파', '04_patterns_breakout.md', '지속적인 하락 추세 중, 고점과 저점이 수렴하며 우하향하는 하락 쐐기형(Falling Wedge) 패턴의 끝자락에 도달했습니다. 거래량이 급감하다가 마침내 쐐기형 상단 저항선을 상방으로 뚫는 강한 양봉 종가 마감(880달러)이 포착되었습니다. 합리적인 매수 진입 시 손절가 설정 기준은 무엇인가요?', '[{"time":"Day 1","open":1040,"high":1056,"low":880,"close":896,"volume":111},{"time":"Day 2","open":896,"high":928,"low":816,"close":832,"volume":90},{"time":"Day 3","open":832,"high":864,"low":784,"close":800,"volume":122},{"time":"Day 4","open":800,"high":896,"low":792,"close":880,"volume":113}]'::jsonb, '[]'::jsonb, ARRAY['손절 없이 청산가에 의존하여 장기 홀딩', '상방 돌파 확인 후 진입 및 직전 최저점 손절 셋업', '평단가 개선을 위한 지속적인 분할 물타기 매수', '상단 저항선 돌파 시점을 이용한 숏 포지션 스위칭']::text[], 1, '하락 쐐기형(Falling Wedge)의 상방 돌파는 강력한 반전 신호입니다. 이 패턴의 장점은 진입 즉시 명확하고 짧은 기준점(수렴 바닥 최저가 784달러 혹은 돌파봉 하단)을 손절가로 설정할 수 있어, 리스크 한도를 안전하게 통제한 채 상방 랠리를 도모할 수 있다는 점입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (549, '패턴/돌파', '04_patterns_breakout.md', '애플 주가가 약한 매수세와 거래량 급감 속에 고점과 저점을 높이며 좁게 상승 쐐기형(Rising Wedge)을 그리고 있습니다. 현재 가격은 상승 쐐기형 하단 지지선(2,400달러)에 아주 밀착하여 붕괴 위기에 놓여 있습니다. 이 시점에서 롱(매수) 포지션을 들고 있는 트레이더의 리스크 대응은?', '[{"time":"Day 1","open":2080,"high":2240,"low":2080,"close":2224,"volume":119},{"time":"Day 2","open":2224,"high":2360,"low":2176,"close":2320,"volume":25},{"time":"Day 3","open":2320,"high":2440,"low":2384,"close":2408,"volume":34}]'::jsonb, '[{"type":"line","points":[{"x":0,"y":2080},{"x":1,"y":2176},{"x":2,"y":2384}],"label":"쐐기 하단 지지선 (300)","color":"#ef4444"}]'::jsonb, ARRAY['상승 쐐기형 하방 이탈 위험에 따른 롱 포지션 매도', '상승 지속 확신에 따른 레버리지 추가 불타기', '장기 상승 흐름 기대로 손절 없이 무기한 홀딩', '다른 종목으로의 포지션 분산을 위한 관망']::text[], 0, '상승 쐐기형(Rising Wedge)은 약세 세력이 억지로 쥐어짜며 상승 가격을 만드는 패턴으로, 수렴 끝에서 거래량 소멸과 함께 하방 이탈(Breakdown)하여 폭락할 위험이 매우 높은 대표적인 하락 대비 패턴입니다. 하단 지지선 이탈 낌새 시에는 매수 포지션을 전부 도망쳐 나와야 큰 손실을 막을 수 있습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (550, '패턴/돌파', '04_patterns_breakout.md', '둥근 대야 모양의 바닥(Cup)을 그리며 상승 회복한 애플 주가가 전고점 저항벽 부근에서 하향 채널식 완만한 되돌림 조정 핸들(Handle)을 그리는 중입니다. 이후 핸들의 상단 저항선(1,200달러선)을 강한 거래량의 장대양봉으로 상향 돌파했습니다. 이때 합리적인 트레이더의 대응은?', '[{"time":"Day 1","open":1120,"high":1136,"low":1024,"close":1040,"volume":113},{"time":"Day 2","open":1040,"high":1120,"low":1032,"close":1104,"volume":109},{"time":"Day 3","open":1104,"high":1120,"low":1072,"close":1080,"volume":98},{"time":"Day 4","open":1080,"high":1232,"low":1072,"close":1216,"volume":112}]'::jsonb, '[]'::jsonb, ARRAY['핸들 상방 돌파 확인 후 진입 및 핸들 저점 손절', '하락 지속 판단에 따른 즉각적인 전량 손절', '평단가 부근이므로 추가 손절 설정 없이 관망', '돌파 여부 확인 전 고점 돌파 매수 주문 100%']::text[], 0, '전형적인 강세 지속 패턴인 컵앤핸들(Cup & Handle)입니다. 핸들의 하락 조정 채널 상단 돌파는 매물 소화를 성공적으로 완수하고 본 랠리로 진입한다는 강력한 신호입니다. 손익비 관점에서 핸들의 지지 저점인 1,072달러 아래에 안전 손절을 지정한 뒤 진입 시 우수한 기대 수익을 가질 수 있습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (551, '지표/컨플루언스', '06_technical_indicators.md', '강력한 대세 상승 국면인 종목이 일시 조정을 거쳐 전저점 지지 영역(800달러)에 도달해 저점을 지키고 있습니다(저점 높임 또는 수평). 그런데 이때 보조지표 RSI의 저점은 이전보다 훨씬 깊게 파여 낮아지는 ''히든 상승 다이버전스(Hidden Bullish Divergence)''가 포착되었습니다. 현명한 의사결정은?', '[{"time":"Day 1","open":720,"high":880,"low":704,"close":840,"volume":118},{"time":"Day 2","open":840,"high":856,"low":784,"close":800,"volume":119}]'::jsonb, '[]'::jsonb, ARRAY['하락 전환 신호로 판단하여 전량 즉시 손절', '추세 지속 신호 기대로 지선 부근 추가/신규 매수', '지표 과매수 판단에 따른 계좌 거래 정지', '손절 설정 없이 무제한 레버리지 롱 대응']::text[], 1, '애플 주가의 저점은 높아지는데 보조지표(RSI 등)의 저점은 낮아지는 형태는 ''히든 상승 다이버전스''입니다. 이는 기존의 강력한 상승 트렌드 내부에서 일시 조정을 겪는 매수자들이 활기차게 물량을 주워 담아 다음 상승 랠리를 추진한다는 신호이므로, 짧은 손절 라인(784달러)을 설정하고 매수 비중을 태우기 가장 적합한 정석 타점입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (552, '지표/컨플루언스', '07_multitimeframe_regime.md', '애플 주가가 호재와 함께 밴드 상단선 바깥을 타고 계속 상승하는 강력한 볼린저 밴드 밴드워크(Band Walk) 현상이 발생 중이며, RSI는 80을 넘어 극단적 과매수 수치를 가리키고 있습니다. 이 구간에서 취해야 할 가장 합리적인 리스크 및 포지션 관리 행동은?', '[{"time":"Day 1","open":800,"high":920,"low":792,"close":896,"volume":80},{"time":"Day 2","open":896,"high":1024,"low":880,"close":1000,"volume":87},{"time":"Day 3","open":1000,"high":1112,"low":976,"close":1088,"volume":103}]'::jsonb, '[]'::jsonb, ARRAY['과매수 도달 판단에 따른 고배율 숏 무리한 진입', '추종 손절매(Trailing Stop)를 통한 수익 극대화', '상승폭 만족에 따른 즉각적인 전량 시장가 익절', '손절 가격을 해제하고 시세 지속 시까지 방치']::text[], 1, '강세 추세가 지나치게 강할 경우 볼린저 밴드 상단을 타고 오르는 밴드워크 현상과 RSI 과매수 현상이 영구 유지될 수 있습니다. 이때 단순 과매수 수치를 이유로 숏 포지션을 잡으면 파산합니다. 기존 매수 포지션의 익절선(Trailing Stop)을 상향 관리하여 추세 상승 이익을 극대화하고 신규 진입은 자제하는 것이 정석 리스크 관리입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (553, '지표/컨플루언스', '06_technical_indicators.md', '1시간 봉 차트 상에서 애플 주가가 확실히 낮아졌으나 RSI 저점은 유의미하게 상승한 ''상승 다이버전스''가 확인되어 매수 타점을 노리고 있습니다. 다만 15분 봉 단기 차트에서는 하락 장대음봉 관성이 아직 살아있어 매도 압력이 보입니다. 멀티 타임프레임 트레이더의 진입 의사결정은?', '[{"time":"Hour 1","open":800,"high":816,"low":720,"close":728,"volume":104},{"time":"Hour 2","open":728,"high":736,"low":640,"close":656,"volume":120}]'::jsonb, '[]'::jsonb, ARRAY['단기 음봉 관성 기대로 즉각 숏 포지션 진입', '큰 시간 프레임의 상승 다이버전스 타점 매수', '지표 충돌로 판단하고 시장가 즉시 롱 진입', '변동성 기대로 무작정 도박성 잡코인 진입']::text[], 1, '큰 프레임(1시간 봉)의 다이버전스가 주는 중장기 추세 신뢰도는 작은 프레임의 단기 노이즈보다 압도적으로 강력합니다. 단, 진입 시 타이밍의 정밀도를 높이기 위해 소파동(15분 봉)의 하락 동력이 꺾이고 지지해 주는 단기 확인 캔들이 나오는 찰나에 롱 포지션 타이밍을 잡는 것이 멀티 타임프레임 정석 매매입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (554, '지표/컨플루언스', '06_technical_indicators.md', '애플 주가는 1,600달러 저항대를 뚫고 1,760달러까지 계속 우상향하며 고점을 갱신하고 있으나, MACD 오실레이터의 히스토그램 산 높이는 직전 고점 시점 대비 현저하게 쪼그라들며 꺾여 내려가 하락 다이버전스를 형성 중입니다. 현명한 포지션 보유자의 이익 관리 행동은?', '[{"time":"Day 1","open":1440,"high":1640,"low":1432,"close":1600,"volume":89},{"time":"Day 2","open":1600,"high":1776,"low":1584,"close":1760,"volume":119}]'::jsonb, '[]'::jsonb, ARRAY['추세 지속 확신으로 보유 비중 추가 불타기', '상승 모멘텀 약화 다이버전스 확인 후 50% 익절', '익절 설정 없이 전고점 도달 시까지 홀딩', '고점 붕괴 기대로 숏 포지션 10배 베팅']::text[], 1, '애플 주가는 올라가나 모멘텀 지표인 MACD 오실레이터 고점이 낮아지는 현상은 대표적인 하락 다이버전스로, 매수 에너지가 속 빈 강정처럼 쇠퇴하고 있어 언제든 급격한 폭락 조정이 발생할 수 있는 고위험 신호입니다. 이 시점에는 탐욕을 통제하고 물량의 50% 이상을 분할 매도하여 현금을 챙기는 것이 원칙입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (555, '지표/컨플루언스', '06_technical_indicators.md', '애플 주가가 하락 횡보하던 도중, 단기 지평선인 EMA 20일선이 중장기선인 EMA 50일선에 극도로 밀착하며 수렴했습니다. 당일 대량 거래량의 음봉 캔들이 터지며 단기선이 장기선 아래로 교차하기 직전(데드크로스 임박)이며 주요 지지선 밑으로 떨어졌습니다. 롱(매수) 포지션 보유자의 올바른 대응은?', '[{"time":"Day 1","open":840,"high":848,"low":792,"close":800,"volume":109},{"time":"Day 2","open":800,"high":808,"low":760,"close":768,"volume":101}]'::jsonb, '[]'::jsonb, ARRAY['지지선 이탈 및 데드크로스 확인 즉시 손절', '이평선 지지력을 믿고 하방 물타기 추가 매수', '하락 조정 후 반등 기대로 무기한 홀딩 관망', '청산가 도달 시까지 어떠한 대응 없이 방치']::text[], 0, '20일선과 50일선의 데드크로스 임박 수렴 상태에서 가격이 지지선마저 무너뜨린 것은 하락 가속화 추세가 폭발하기 직전인 매우 위험한 기술적 상태입니다. 하락 추세가 본격 정배열(하락 정배열)화 되기 전에 즉시 전량 손절하고 시장 밖에서 피신해 있는 것이 계좌의 영구 파산을 막는 유일한 생존 규칙입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (556, '리스크/심리', '09_risk_position_management.md', '미국 주식 매수 후 가격이 급락하여 내가 설정해 둔 최대 감내 손실 한도인 계좌 총원금 대비 -2% 라인(손절매 지정 가격)에 완벽하게 닿았습니다. 마침 본전 생각과 함께 ''조금만 더 버티면 반등할 텐데...''하는 강한 뇌동매매 유혹이 솟구칩니다. 이때 원칙 트레이더의 결정은?', '[{"time":"Day 1","open":800,"high":816,"low":792,"close":800,"volume":102},{"time":"Day 2","open":800,"high":808,"low":752,"close":760,"volume":109}]'::jsonb, '[]'::jsonb, ARRAY['손절 라인을 임의로 하향 조정하고 홀딩', '평단가 관리 차원의 지속적 물타기 매수 집행', '원칙에 따라 뇌동을 제어하고 즉시 기계적 손절', '손실은 배제하고 반등 기대를 통한 무기한 보유']::text[], 2, '트레이딩의 승패는 예측이 아닌 ''리스크 통제''에 달려 있습니다. 사전에 정한 계좌 대비 2% 리스크 한도에 도달했을 때 희망 회로를 돌리며 손절을 미루거나 물타기를 집행하는 순간 계좌는 서서히 영으로 깎여 파산합니다. 멘탈의 충동을 통제하고 기계적으로 전량 칼손절하는 것이 절대 파산하지 않는 시장의 1법칙입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (557, '리스크/심리', '10_psychology_routine_review.md', '최근 3회 연속 거래에서 계속해서 손절(Stop Loss)을 맞아 뇌 내의 도파민 체계가 무너지고 심리가 극도로 불안해져 분노와 보복 매매 충동이 밀려옵니다. 이 상황에서 파산을 막는 가장 훌륭한 매매 심리 대처법은?', '[{"time":"Today","open":800,"high":800,"low":800,"close":800}]'::jsonb, '[]'::jsonb, ARRAY['손실 복구를 위해 레버리지를 증액해 즉시 진입', '뇌동 방지를 위해 HTS를 종료하고 매매 일지 작성 및 휴식', '추천 매매 신호 유료 리딩방에 즉시 가입 및 추종', '심리적 회복을 위해 역베팅 숏 포지션 추가']::text[], 1, '연속 손실 후 발생하는 복수심과 분노는 트레이더를 뇌동매매와 계좌 파멸로 이끄는 가장 치명적인 감정 상태입니다. 멘탈 붕괴를 느꼈을 때는 즉각 행동을 멈추고 시스템을 강제 종료하여 시장과 물리적 격리를 통해 냉정을 찾는 것만이 자산을 파산 리스크로부터 살려내는 훌륭한 트레이딩 행동입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (558, '셋업/실행', '09_risk_position_management.md', '진입하고자 하는 매수 자리를 분석해 보니, 기술적 분석 상 이길 수 있는 확률(승률)은 반반인 50% 수준입니다. 그러나 손절 시 기대 손실금액 대비 성공 시 획득할 수 있는 기대 수익금액의 비율(손익비)을 정밀 셋업 해보니 1 : 1.2 수준으로 다소 애매하게 도출되었습니다. 원칙 트레이더의 진입 결정은?', '[{"time":"Today","open":800,"high":800,"low":800,"close":800}]'::jsonb, '[]'::jsonb, ARRAY['단기 변동성 기대로 부적합한 손익비 시장가 진입', '마이너스 기댓값 거래 유보 및 우수 타점 대기', '레버리지를 높여 손익비 구조를 임의 조정 시도', '반대 방향으로 고배율 역베팅을 즉시 실행']::text[], 1, '수학적으로 승률 50%일 때 손익비가 최소 1:2(잃을 때 1, 벌 때 2) 이상이 나오지 않으면 복리 매매 시 수수료와 호가 슬리피지에 밀려 잔고가 무조건 마이너스로 수렴합니다. 타점이 눈에 들어오더라도 사전에 기대 손익비 필터에 걸려 탈락한다면 패스를 선언하고 관망하는 것이 현명한 생존 원칙입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (559, '리스크/심리', '09_risk_position_management.md', '갑작스러운 거시 경제 발표로 내가 매매 중인 종목의 캔들 변동성 폭(ATR)이 평소 시세의 2배 수준으로 널뛰기 시작했습니다. 1회 거래당 내 계좌 원금의 최대 2% 리스크 한도를 동일하게 고수하기 위해 취해야 할 올바른 조치는?', '[{"time":"Day 1","open":800,"high":816,"low":784,"close":800,"volume":94},{"time":"Day 2","open":800,"high":880,"low":720,"close":816,"volume":110}]'::jsonb, '[]'::jsonb, ARRAY['평소 변동성과 동일한 비중 및 손절 거리 고수', '손절 거리를 넓히는 대신 진입 포지션 수량 축소', '변동성이 확대되었으므로 2배 비중으로 적극 지름', '즉시 전량 손절하고 시장 상황 정상화 대기']::text[], 1, '시장 변동성이 커질 때는 손절 스톱 아웃이 잦으므로 손절폭(%)을 넓혀 숨 쉴 공간을 확보해 주는 것이 합리적입니다. 단, 손절폭을 2배로 늘린다면 계좌 대비 리스크 한도가 2배(4%)로 커지므로, 진입 포지션의 계약 수량을 50%로 줄여 리스크 노출 총액을 2%로 완벽하게 동일 통제하는 것이 포지션 사이징(Position Sizing)의 정석 원칙입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (560, '리스크/심리', '09_risk_position_management.md', '투자자 A의 전체 투자 원금은 4,000만 원이며, 1회 거래당 최대 허용 리스크 금액은 원금의 2%인 80만 원입니다. 현재 애플 주가가 80,000원이며, 기술적 분석 상 합리적인 손절선은 지지선 바로 밑인 76,000원(-5%)입니다. 2% 룰 리스크 관리 원칙에 따라 A가 진입(매수)해야 하는 최대 미국 주식 수량은?', '[{"time":"Today","open":80000,"high":80000,"low":80000,"close":80000}]'::jsonb, '[]'::jsonb, ARRAY['500주 (투자금 전액 시장가 매수)', '200주 (손실 한도 80만 원 맞춤 매수)', '50주 (보수적 극단적 비중 축소)', '100주 (절반 비중 고정 매수)']::text[], 1, '포지션 크기 계산 공식은 `최대 매수 규모 = 최대 허용 리스크 금액 / 손절매 비율` 입니다. 이 시나리오에서 `800,000원 / 0.05(5%) = 16,000,000원`이 최대 허용 진입금액이 되며, 이를 애플 주가 80,000원으로 나누면 `200주`가 도출됩니다. 200주 진입 후 -5% 가격 폭락으로 손절 당해도 내 총원금에서 깎이는 돈은 정확히 80만 원(2%)으로 완벽히 리스크 통제됩니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (561, '거래량/유동성', '05_volume_liquidity.md', '애플 주가가 수평 저항선 부근까지 급상승했으나 캔들 몸통(Spread)이 지극히 좁아진 도지 형태로 마감하였고, 거래량은 이전 5일 평균 대비 3배 이상 폭증했습니다. VSA(Volume Spread Analysis) 관점에서 가장 타당한 차트 분석은?', '[{"time":"Day 1","open":800,"high":840,"low":792,"close":832,"volume":88},{"time":"Day 2","open":832,"high":872,"low":824,"close":864,"volume":115},{"time":"Day 3","open":864,"high":880,"low":856,"close":864,"volume":91}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":872},{"x":2,"y":872}],"label":"저항선","color":"#ef4444"}]'::jsonb, ARRAY['강한 매수 기세 기대로 즉시 돌파 매매 풀매수', '저항벽 매도 공급 세력 분산 확인 후 이익 실현', '대량 거래 확인에 따른 손절 해제 후 장기 투자', '반등 실패에 따른 고배율 보복 숏 베팅 가동']::text[], 1, '캔들 몸통 크기(스프레드)가 좁은데 거래량이 매우 크게 폭증했다는 것은 저항선 부근에서 들어오는 매수세만큼 세력의 매도 물량 공급이 쏟아져 막강한 저항 벽을 형성하고 있다는 뜻입니다. VSA에서는 이를 불화(Disharmony)로 규정하며 상승 추세 감속 및 하락 반전의 경고로 해독합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (562, '거래량/유동성', '05_volume_liquidity.md', '애플 주가가 장기 횡보하던 박스권 지지선인 1,600달러를 깨고 1,560달러까지 하락 투매가 발생했으나, 종가 마감 직전 거래량이 크게 실린 긴 아래꼬리를 그리며 다시 1,608달러 위로 복귀 안착했습니다. 이 스톱 헌팅 유동성 현상에서의 실전 트레이더의 대응은?', '[{"time":"Day 1","open":1680,"high":1696,"low":1600,"close":1616,"volume":90},{"time":"Day 2","open":1616,"high":1632,"low":1560,"close":1608,"volume":118}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":1600},{"x":1,"y":1600}],"label":"지지선","color":"#10b981"}]'::jsonb, ARRAY['지지선 붕괴 확정으로 간주한 시장가 숏 추격', '스윕(sweep) 판단 하에 아래꼬리 저점 손절 잡고 롱', '아무런 신호도 아니라고 판단하고 포지션 방치', '지지선 이탈 기대로 전량 손절 후 시장 영구 탈출']::text[], 1, '지지선 아래에 걸려 있던 개인들의 손절 주문(Sell Stop)을 강제로 청산(Liquidity Sweep)시킨 뒤, 세력이 물량을 헐값에 다 받아 삼켜 종가를 지지선 위로 신속하게 복귀시킨 휩소(베어 트랩) 패턴입니다. 아래꼬리 극점(1,560달러)에 아주 좁은 손절 라인을 설정할 수 있어, 기대 손익비가 극대화되는 고확률 상승 반전 매수 타점입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (563, '거래량/유동성', '05_volume_liquidity.md', '애플 주가는 2,000달러에서 2,320달러까지 계속 고점을 높이며 상승 추세를 이어가고 있습니다. 그러나 각 상승 파동마다 터지는 거래량은 전고점 돌파 시점 대비 눈에 띄게 하향 곡선을 그리며 감소하고 있습니다. VSA 기법에 따른 합리적인 진단은?', '[{"time":"Wave 1","open":1840,"high":2080,"low":1824,"close":2040,"volume":84},{"time":"Wave 2","open":2040,"high":2200,"low":2000,"close":2160,"volume":119},{"time":"Wave 3","open":2160,"high":2320,"low":2120,"close":2304,"volume":125}]'::jsonb, '[]'::jsonb, ARRAY['가격 상승으로 인한 매수 지속 강화 초강세', '매도 물량 고갈에 따른 무중력 안심 홀딩', '신규 자금 유입 둔화 거래량 다이버전스로 분할 익절', '지표 조작으로 판단하여 매매 중단 및 차트 종료']::text[], 2, '애플 주가는 상승하여 신고점을 갱신하지만 파동별 거래량이 지속 감소하는 흐름은 ''거래량 다이버전스''로 상승 모멘텀의 내부 엔진이 식어감을 경고합니다. 조만간 가벼운 매도 포격에도 대규모의 차익 실현 폭락 조정이 발생할 수 있는 잠재적 폭락 국면이므로 물량을 덜어내고 현금을 확보해야 합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (564, '거래량/유동성', '05_volume_liquidity.md', '가격이 이전 고점 저항선을 뚫고 강하게 솟구치며 장대양봉을 만들었습니다. 이때 가짜 이탈(Whipsaw / Bull Trap)이 아닌 진성 돌파(True Breakout)로 판정할 수 있는 가장 신뢰도 높은 거래량 기준은?', '[{"time":"Day 1","open":800,"high":816,"low":792,"close":800,"volume":338},{"time":"Day 2","open":800,"high":896,"low":792,"close":880,"volume":387}]'::jsonb, '[]'::jsonb, ARRAY['수렴 끝자락에서 거래량이 최저치인 상태 유지', '평균 대비 1.5~2배 이상 거래량 급증하며 돌파 마감', '거래량이 전혀 변하지 않는 평이한 상태 유지', '호가 스프레드가 가장 좁아지는 횡보 상태']::text[], 1, '참된 저항 돌파(True Breakout)는 저항선 부근의 두터운 대기 매도 공급 물량을 대규모 자금으로 전부 씹어 삼키고 돌파해야 함을 뜻합니다. 따라서 반드시 평균 대비 1.5배~2배 이상의 거래량 분출이 동반되어야 신뢰할 수 있으며, 거래량이 적은 돌파는 꼬리 달고 내려앉는 불 트랩(Bull Trap)일 확률이 매우 높습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (565, '거래량/유동성', '05_volume_liquidity.md', '애플 차트에서 중요 지지선 직전 저점 아래에 엄청난 규모의 롱 포지션 청산 및 매도 손절 주문이 쌓여 있는 유동성 풀(Liquidity Pool) 구간이 감지되었습니다. 세력이 이 구간을 공략할 때 나타날 캔들의 전형적인 무빙 패턴은?', '[{"time":"Day 1","open":400000,"high":404000,"low":393600,"close":396000,"volume":30},{"time":"Day 2","open":396000,"high":398400,"low":384000,"close":396800,"volume":20}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":393600},{"x":1,"y":393600}],"label":"전저점 지지선","color":"#3b82f6"}]'::jsonb, ARRAY['지지선을 장대음봉으로 돌파하여 20% 폭락 마감', '전저점 이탈로 손절 유도 후 지지선 위 아래꼬리 안착', '오차 없이 지지선 터치 후 꼬리 없는 수평 도지 횡보', '거래량 없이 즉각 상승 빔 분출로 전고점 탈환']::text[], 1, '기관 세력(스마트 머니)은 대량 포지션을 구축하기 위해 개인의 손절 주문(Sell Stop)을 의도적으로 터트려 매도 유동성을 유도한 후 이를 다 매수합니다. 이로 인해 애플 주가는 지지선 아래로 일시 급락 후(스톱 헌팅), 아래꼬리를 매우 길게 달며 지선 안쪽으로 급반등 마감하게 됩니다. 이것이 유동성 스윕(Liquidity Sweep)의 정석 패턴입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (566, '거래량/유동성', '05_volume_liquidity.md', '상승 추세 도중 전고점 저항선 부근에서 위꼬리가 아주 긴 캔들이 터졌고, 거래량은 최근 보름 중 최고 수치로 솟구쳤습니다. VSA 관점에서 이 상승 거절(Upside Rejection) 현상에 대한 올바른 대처는?', '[{"time":"Day 1","open":800,"high":920,"low":784,"close":808}]'::jsonb, '[]'::jsonb, ARRAY['강한 저점 매수 기회로 인지하여 비중 대폭 추가', '고점 매도 Rejection 확인 후 기존 롱 포지션 대피', '박스 횡보 수렴 기대로 마틴게일 추가 매수 가동', '이평선 정배열 판단에 따른 포지션 변경 없이 홀딩']::text[], 1, '위꼬리가 매우 긴 캔들이 대량 거래량과 함께 터졌다는 것은 고점 돌파 시도가 있었으나 그 자리에 숨어 있던 세력의 막강한 청산 매도 벽(Supply)을 만나 격렬하게 두들겨 맞고 밀려났음을 의미합니다. 상방 거절의 심리가 지배적이므로 고점 피로 및 하락 전환이 임박한 위험 징후입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (567, '지표/컨플루언스', '06_technical_indicators.md', '애플 주가가 장기 박스권 횡보를 이어가며 볼린저 밴드의 폭이 최근 몇 달 중 가장 좁은 형태로 밀착 수렴(Squeeze)되었습니다. 이 스퀴즈 국면에 대한 올바른 기술적 이해와 매매 시나리오는?', '[{"time":"Week 1","open":800,"high":824,"low":776,"close":808,"volume":111},{"time":"Week 2","open":808,"high":816,"low":792,"close":800,"volume":94}]'::jsonb, '[]'::jsonb, ARRAY['박스권 변동성 부재 기대로 장기 무대응 관망', '에너지 수축 스퀴즈 확인 후 밴드 이탈 돌파 대기', '지표 신뢰 불가 판단으로 볼린저 밴드 지표 삭제', '중심선 지지로 판단하여 고배율 매수 대기 주문']::text[], 1, '볼린저 밴드의 폭이 극도로 좁아지는 스퀴즈(Squeeze) 현상은 시장의 표준편차 변동성이 임계치까지 압축 수렴되었음을 알려줍니다. 에너지 압축 뒤에는 항상 폭발적인 가격 분출(상방/하방 이탈)이 뒤따르므로, 밴드를 뚫고 거래량이 실려 돌파 마감하는 방향으로 추세 추종 시나리오를 설계해야 합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (568, '지표/컨플루언스', '06_technical_indicators.md', '애플 주가는 HL(Higher Low)을 형성하며 이전 직전 저점(720달러)보다 높은 저점(760달러)을 지키고 있으나, RSI 지표는 이전 35 수치보다 더 깊숙하게 25 수치까지 떨어졌습니다. 이 지표 불일치 현상의 공식 명칭과 올바른 포지션 셋업은?', '[{"time":"Day 1","open":800,"high":816,"low":720,"close":728,"volume":91},{"time":"Day 2","open":728,"high":768,"low":760,"close":760,"volume":107}]'::jsonb, '[]'::jsonb, ARRAY['일반 상승 다이버전스 - 추세 종결로 즉각 공매도', '히든 상승 다이버전스 - 지선 눌림목 롱 진입 활용', '일반 하락 다이버전스 - 모든 매수 포지션 정리', '지표 오작동 휩소 구간 판단으로 양방향 관망']::text[], 1, '가격의 저점은 높아졌는데(Higher Low) 모멘텀 지표의 저점은 낮아지는 현상은 ''히든 상승 다이버전스(Hidden Bullish Divergence)''입니다. 이는 추세 반전이 아닌 **기존 강세 추세 지속**을 뜻하며, 조정 눌림목이 완성되고 다음 상승 랠리를 준비한다는 최고의 매수 신호 중 하나입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (569, '지표/컨플루언스', '06_technical_indicators.md', '매수 타점을 신중하게 선별하고자 합니다. 기술적 분석의 성공 확률을 비약적으로 끌어올리는 ''다중 컨플루언스(Confluence)'' 결합 사례로 가장 적합한 조건 구성은?', '[{"time":"Today","open":800,"high":800,"low":800,"close":800}]'::jsonb, '[]'::jsonb, ARRAY['트위터 및 뉴스의 호재 찌라시 확인 즉시 추격', '지지선+이평선+다이버전스+아래꼬리 등 분석 중첩 시', 'RSI 과매수 영역 진입 즉시 롱 포지션 진입', '독립적 분석 없이 오직 보조지표의 단일 수치 신호']::text[], 1, '다중 컨플루언스(Confluence)는 독립적인 기술적 근거들이 동일한 특정 가격 구역에 중첩되는 현상입니다. 지지 저항, 이평선, 보조지표 다이버전스, 캔들 가격행동(Rejection 핀바)이 한 곳에 묶여 매수 자리를 형성할 때 매매를 실행하면, 높은 신뢰도와 좁은 손절 라인 덕분에 장기 기대값이 극대화됩니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (570, '셋업/실행', '08_setup_entry_exit.md', '중요 수평 저항선(960달러)을 상방으로 장대양봉 종가 돌파한 것을 확인하고 롱(매수) 진입 셋업을 준비하고 있습니다. 원칙 트레이더가 뇌동매매 추격을 막고 최상의 손익비를 확보하기 위해 즐겨 쓰는 정석적인 진입 실행법은?', '[{"time":"Day 1","open":880,"high":896,"low":872,"close":888,"volume":81},{"time":"Day 2","open":888,"high":992,"low":880,"close":976,"volume":95}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":960},{"x":1,"y":960}],"label":"저항선","color":"#ef4444"}]'::jsonb, ARRAY['돌파 마감 확인 즉시 시장가 추가 매수 집행', '돌파된 저항선의 지지 전환(Retest) 시 지정가 진입', '반등 조정이 불가능하다고 판단하여 최고점 롱 추격', '속임수 돌파 확신으로 고배율 역베팅 숏 진입']::text[], 1, '저항 돌파 후 즉시 가격을 따라붙는 추격 매수는 휩소 조정 시 심각한 손실을 초래합니다. 돌파된 라인이 S/R Flip을 통해 지지로 작용하는지 확인하는 되돌림 리테스트(Retest) 시점에 진입하는 것이, 지선 바로 아래에 좁은 손절 라인을 설계하고 이익 기대 폭을 넓힐 수 있는 가장 이상적인 정석 실행법입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (571, '셋업/실행', '08_setup_entry_exit.md', '포지션 진입 직후, 가격이 계획대로 내 방향으로 순탄하게 우상향하고 있습니다. 기존 진입 시 설정한 손익비 1:2의 최종 목표가 도달 전에, 리스크 관리 차원에서 계좌 드로다운을 0으로 만드는 정석적인 1차 포지션 관리 행동은?', '[{"time":"Entry","open":800,"high":800,"low":800,"close":800,"volume":86},{"time":"Day 1","open":800,"high":848,"low":800,"close":840,"volume":115}]'::jsonb, '[]'::jsonb, ARRAY['1차 저항대 진입 시 레버리지를 활용해 불타기', '목표가 터치 시까지 100% 비중 무대응 홀딩', '1:1 지점 50% 분할 익절 및 남은 물량 본전 손절 상향', '단기 반등 확인 즉시 전량 기계적 청산 및 퇴장']::text[], 2, '이득이 발생해 손익비 1:1 수준에 오면 물량의 절반을 분할 익절(Scale-out)하고 남은 포지션의 스톱로스를 진입가로 이동(Break-even)시키는 것이 포지션 관리의 기본입니다. 이렇게 셋업하면 차트가 갑자기 폭락세로 뒤집혀도 최소 본전 혹은 반절 익절 약수익으로 끝나 해당 거래의 최대 리스크가 Zero(0)로 봉쇄됩니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (572, '셋업/실행', '08_setup_entry_exit.md', '강력한 장기 상승 추세가 터져 애플 주가가 20일 이평선을 타고 계속해서 폭발적으로 신고가를 갱신하고 있습니다. 이때 익절 시점을 서둘러 잡지 않고, 추세 상승 이익을 최대한 길게 끝까지 빨아먹기 위한 정석 청산 실행법은?', '[{"time":"Day 1","open":800,"high":880,"low":792,"close":864,"volume":99},{"time":"Day 2","open":864,"high":960,"low":856,"close":944,"volume":91},{"time":"Day 3","open":944,"high":1080,"low":936,"close":1056,"volume":91}]'::jsonb, '[]'::jsonb, ARRAY['RSI 과과열 조짐 확인 즉시 시장가 전량 익절', 'Higher Low 지지 직하방으로 손절 추종 익절 셋업', '이익 보존을 포기하고 손익절 라인을 해제 후 홀딩', '즉시 숏 포지션 10배로 맞불을 놓는다']::text[], 1, '강세 추세가 터졌을 때 지레짐작으로 청산하면 상승 파동의 초입만 먹고 끝납니다. 추세 붕괴의 명확한 신호(BOS/MSB)가 나오거나, 가격의 구조적 높은 저점(HL)이 깨질 때까지 손절 라인을 계속 추종해서 상향하는 ''추격 손절매(Trailing Stop)''를 가동하는 것이 추세 이익을 극대화하는 정석 기법입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (573, '셋업/실행', '01_chart_market_basics.md', '차트 분석 결과, 돌파 시점의 체결 변동성과 거래소 호가창의 얇은 매물 상태를 감안할 때 내가 진입하려는 주문 가격에서 체결이 뒤로 밀리는 ''슬리피지(Slippage)''가 심각하게 예상됩니다. 이를 감안한 올바른 주문 실행법은?', '[{"time":"Today","open":800,"high":800,"low":800,"close":800}]'::jsonb, '[]'::jsonb, ARRAY['시장가로 최고 배율을 설정하여 즉시 체결', '돌파 확인 후 지정가 대기 주문으로 단가 조절', '슬리피지를 예방하기 위해 즉각적인 거래 취소', '호가창 스프레드와 무관하게 고배율 레버리지']::text[], 1, '변동성이 크고 호가가 얇은 시장에서 돌파 시 시장가 진입은 나쁜 단가로 체결되는 슬리피지 비용을 발생시켜 시작부터 손실을 크게 안고 갑니다. 돌파 확인 후 되돌림 가격대에서 지정가(Limit Order)를 대기시켜 체결 단가를 내 손아귀에 고정하는 리스크 관리가 필요합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (574, '셋업/실행', '10_psychology_routine_review.md', '원칙 기반의 정석 매매 셋업(Trading Setup)을 설계할 때, 진입 전 반드시 사전에 수치로 명문화되어 결정되어야 할 요소가 아닌 것은?', '[{"time":"Today","open":800,"high":800,"low":800,"close":800}]'::jsonb, '[]'::jsonb, ARRAY['진입 조건(Trigger)과 구체적인 손절 가격(Stop Loss)', '거래 당일 본인의 주관적인 직감과 감정적 목표가', '진입하려는 구체적인 포지션 규모 및 분할 익절선', '거래 아이디어가 무효화되는 구체적 가격 지점']::text[], 1, '매매 셋업은 규칙에 기반한 수치들(진입가, 손절가, 목표가, 수량)로 사전에 철저히 규격화되어야 합니다. 당일의 운이나 주관적 느낌, 예감에 기초한 비과학적 청산 설정은 셋업에서 배제되어야 할 대표적 뇌동매매 요소입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (575, '셋업/실행', '08_setup_entry_exit.md', '하락 횡보하던 애플 주가가 중요 매물대이자 피보나치 되돌림 0.618 지점에 정확히 맞닿아 아래꼬리가 긴 양봉 핀바(Pin Bar)를 그리며 마감했습니다. 룰베이스 트레이더가 진입 버튼을 누를 때 성립된 IF-THEN 시나리오는?', '[{"time":"Day 1","open":800,"high":800,"low":640,"close":656,"volume":90},{"time":"Day 2","open":656,"high":688,"low":624,"close":680,"volume":102}]'::jsonb, '[]'::jsonb, ARRAY['익일 가격 상황과 관계없이 100배 레버리지 진입', '중첩 자리 핀바(rejection) 확인 후 익일 시가 롱 진입', '상단 저항 도달 판단으로 즉각적인 숏 포지션 진입', '돌파 랠리가 완전히 끝날 때까지 HTS 종료 및 관망']::text[], 1, '훌륭한 트레이딩 실행은 ''IF(조건 만족 시) ➔ THEN(원칙대로 포지션 진입 및 손절/목표가 기계적 배치)''의 룰베이스 알고리즘에 의해 움직여야 감정을 배제할 수 있습니다. 지지 구간 중첩과 핀바 출현 조건이 성립했으므로 다음 봉 시가에 진입하되 꼬리 저점 이탈 시 칼손절하여 리스크를 통제하는 것이 정석입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (576, '리스크/심리', '09_risk_position_management.md', '나의 트레이딩 시스템 승률이 40%로 다소 낮게 고정되어 있습니다. 이 시스템을 통해 장기적으로 파산하지 않고 복리로 계좌 자산을 우상향시키기 위해 필수적으로 지켜야 할 손익비(평균손실 대비 평균수익 비율)의 최소 기준은?', '[{"time":"Today","open":800,"high":800,"low":800,"close":800}]'::jsonb, '[]'::jsonb, ARRAY['손익비 1:1 수준 (매매 승률이 낮을 때 파산)', '승률 40% 대비 기댓값 개선을 위한 손익비 1:1.5 이상', '낮은 승률 상태에서 손익비와 무관하게 무조건 파산', '승률 극복을 위한 레버리지 20배 수준 설정']::text[], 1, '승률이 40%일 때 기대값 수학적 수수료 감안 최소 손익비는 1:1.5입니다. 손익비 1.5배 이상 구간만 취하면 10번 중 6번 손절당하고 단 4번만 익절하더라도 계좌 총합은 수익 우위에 서게 됩니다. 저승률 시스템일수록 철저히 손익비가 유리한 진입가 근처 타점만 기계적으로 필터링해 진입해야 생존합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (577, '리스크/심리', '09_risk_position_management.md', '선물 트레이더인 B는 담보금 효율을 극대화한다는 명목으로 50배 레버리지 롱 포지션 진입을 실행했습니다. 진입 가격 대비 B의 포지션 원금이 완전 소멸(강제 청산)되는 역방향 하락 거리(%)는 대략 몇 % 수준입니까?', '[{"time":"Today","open":800,"high":800,"low":800,"close":800}]'::jsonb, '[]'::jsonb, ARRAY['진입 단가 대비 20.0%의 강한 하락 발생 시', '진입 단가 대비 단 -2.0% 변동성 노이즈 터치 시', '진입 단가 대비 50.0%의 강한 폭락 발생 시', '청산가가 산출되지 않는 특이 종목 거래 시']::text[], 1, '청산 거리 계산 공식은 대략 `100% / 레버리지 배수` 입니다. 50배 고배율 레버리지의 경우, 내 포지션 반대 방향으로 단 **-2%**의 시세 변동성(장중 흔한 잔파동 노이즈)만 터치해도 원금이 100% 강제 청산 증발됩니다. 고배율 레버리지는 수학적 확률상 100% 파멸을 초래하는 도박성 거래 행위입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (578, '리스크/심리', '09_risk_position_management.md', '트레이딩 계좌 총자산이 16,000만 원인 트레이더가 있습니다. 1회 거래당 총자산의 2% 룰 원칙에 근거하여 리스크 한도(320만 원)를 설정했습니다. 진입하려는 종목의 손절가 거리가 -8%인 경우, 2% 룰을 완벽하게 충족하는 최대 진입(매수) 금액은?', '[{"time":"Today","open":800,"high":800,"low":800,"close":800}]'::jsonb, '[]'::jsonb, ARRAY['16,000만 원 전액 매수 (손절 폭을 배제한 대규모 베팅)', '4,000만 원 진입 (-8% 손절 시 리스크 한도 320만 원 충족)', '8,000만 원 진입 (손익비 1:1 기준에 맞춘 베팅)', '1,600만 원 진입 (보수적 원칙에 입각한 극단적 축소)']::text[], 1, '포지션 사이징 공식은 `진입금액 = 최대 리스크 허용액(320만 원) / 손절 비율(0.08)` 입니다. 이에 따라 `3,200,000원 / 0.08 = 40,000,000원`이 도출됩니다. 4,000만 원 규모로 매수 진입 시 가격이 급락해 -8% 손절 라인을 때려도 내 총자산에서 깎이는 금액은 정확히 원칙 한도인 320만 원(2%)으로 제한되어 계좌가 완벽히 방어됩니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (579, '리스크/심리', '10_psychology_routine_review.md', '장중에 내가 째려보며 타점을 기다리던 미국 주식이 아무런 조정도 없이 장대양봉을 그리며 갑자기 수직 폭등하기 시작하여 5% 이상 치솟았습니다. 이때 머릿속에 ''나만 두고 날아가는 것 아닌가''하는 극심한 소외감 공포(FOMO)가 솟구칩니다. 원칙 트레이더의 올바른 심리 대응은?', '[{"time":"Day 1","open":800,"high":816,"low":792,"close":800,"volume":102},{"time":"Day 2","open":800,"high":848,"low":800,"close":840,"volume":111}]'::jsonb, '[]'::jsonb, ARRAY['추세 연장 판단으로 시장가 전액 추격 매수', 'FOMO 판단 하에 매수 보류 및 정석 되돌림 타점 대기', '돌파 실패 판단 하에 반대 방향 고배율 숏 베팅', '거래를 종료하고 즉각 미국 주식 시장에서 전량 탈출']::text[], 1, '나만 기회를 잃는다는 공포(FOMO)로 날아가는 장대양봉 꼭대기에서 추격 매수하는 행위는 고점 물리기를 자처하는 가장 흔한 뇌동매매 패턴입니다. 내 타점을 비껴간 상승은 내 돈이 아니라고 인정하고, 사전에 정의한 룰베이스 타점까지 냉정하게 대기하는 것이 장기 생존자의 멘탈 습관입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (580, '리스크/심리', '10_psychology_routine_review.md', '오전 거래에서 원칙을 어긴 무리한 진입으로 인해 3회 연속 스톱아웃(손절)을 당하여 당일 원금의 -6%의 큰 손실을 입었습니다. 본전 생각과 분노로 눈이 뒤집혀 비중을 올려 한 판으로 복수하려는 ''보폭 매매'' 충동이 폭발할 때, 파산을 막는 가장 강력한 멘탈 시스템 룰은?', '[{"time":"Today","open":800,"high":800,"low":800,"close":800}]'::jsonb, '[]'::jsonb, ARRAY['손실 만회를 위해 빌린 돈으로 100배 고배율 복수 베팅', '일일 손실 한도 도달에 따른 매매 강제 종료 및 격리', '주변 유료 전문가 추천 종목을 탐색해 즉각 매수', 'RSI 과매도 상태이므로 즉시 반대 숏 포지션 진입']::text[], 1, '연패를 겪은 후 홧김에 비중을 더 크게 실어 한 번에 본전을 찾으려는 보복 매매는 계좌를 하루 만에 휴지조각으로 만드는 가장 무서운 파산 유도 심리 상태입니다. 이를 막기 위해 하루 최대 손실 한도 한계선(예: 3회 손절 또는 원금의 5%)을 정해두고, 이 한계선 터치 시 즉시 차트를 종료하고 냉각기를 강제 집행하는 룰이 필수입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (601, '캔들/가격행동', '02_candlestick_price_action.md', '하락 추세 지속 도중 바닥권에서 몸통이 짧고 아래꼬리가 몸통의 2배 이상인 아래 캔들이 출현했습니다. 이 캔들의 명칭과 올바른 대응은?', '[{"time":"10:00","open":1200,"high":1220,"low":1180,"close":1190,"volume":88},{"time":"10:15","open":1190,"high":1200,"low":1130,"close":1140,"volume":104},{"time":"10:30","open":1140,"high":1150,"low":1080,"close":1090,"volume":116},{"time":"10:45","open":1090,"high":1100,"low":1010,"close":1020,"volume":100},{"time":"11:00","open":1020,"high":1030,"low":900,"close":1010,"volume":105}]'::jsonb, '[]'::jsonb, ARRAY['역망치형 (Inverted Hammer) - 하락 경고 및 공매도 대기', '망치형 (Hammer) - 저점 지지 및 분할 매수 대기', '도지 (Doji) - 매수세와 매도세의 팽팽한 균형 및 관망', '하락 장악형 (Bearish Engulfing) - 추세 반전 및 즉시 손절']::text[], 1, '마지막 캔들은 아래꼬리가 긴 ''망치형(Hammer)'' 캔들로 하락 압력을 이겨내고 저가 매수세가 밀어 올렸음을 의미하는 대표적 상승 전환 신호입니다. 지지를 확인한 뒤 분할 매수 관점으로 대기해야 합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (602, '캔들/가격행동', '02_candlestick_price_action.md', '나스닥 시세가 장기간 급등한 뒤, 고점 부근에서 위꼬리가 매우 길고 몸통이 짧은 형태의 캔들이 발생했습니다. 이 캔들의 해석으로 가장 적절한 것은?', '[{"time":"Day 1","open":1000,"high":1080,"low":990,"close":1050,"volume":112},{"time":"Day 2","open":1050,"high":1150,"low":1040,"close":1120,"volume":93},{"time":"Day 3","open":1120,"high":1250,"low":1110,"close":1230,"volume":109},{"time":"Day 4","open":1230,"high":1280,"low":1200,"close":1260,"volume":125},{"time":"Day 5","open":1260,"high":1450,"low":1250,"close":1270,"volume":127}]'::jsonb, '[]'::jsonb, ARRAY['유성형 (Shooting Star) - 고점 저항 및 하락 전환 예고', '망치형 (Hammer) - 저점 매수세 유입 및 상승 랠리 기대', '상승 장악형 (Bullish Engulfing) - 추세 반전 및 홀딩 유도', '도지 (Doji) - 추세 지속 가능성 및 일시 관망']::text[], 0, '급등세 끝에서 위꼬리가 몸통보다 훨씬 길게 솟아오른 캔들은 ''유성형(Shooting Star)''입니다. 장중 상승 시도를 강력한 차익 실현 및 매도 압력이 짓눌렀음을 보여주며, 하락 추세 전환의 강력한 경고 시그널입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (603, '캔들/가격행동', '02_candlestick_price_action.md', '직전의 음봉 몸통을 다음 날의 거대한 양봉 몸통이 완전히 감싸 안는 아래 형태가 포착되었습니다. 이 패턴의 이름과 신뢰도는?', '[{"time":"Day 1","open":980,"high":1000,"low":950,"close":960,"volume":85},{"time":"Day 2","open":960,"high":970,"low":920,"close":930,"volume":89},{"time":"Day 3","open":930,"high":950,"low":880,"close":890,"volume":101},{"time":"Day 4","open":870,"high":1020,"low":860,"close":1010,"volume":111}]'::jsonb, '[]'::jsonb, ARRAY['하락 장악형 (Bearish Engulfing) - 추세 반전 신뢰도 낮음', '상승 장악형 (Bullish Engulfing) - 매수 전환 신뢰도 높음', '상승 관통형 (Piercing Line) - 중간 강도의 반전 신호', '석별형 (Evening Star) - 상승 추세 종결 신호']::text[], 1, '전일의 하락 음봉 몸통을 다음 날의 장대 양봉이 완전히 덮어버리는 형태를 ''상승 장악형(Bullish Engulfing)'' 패턴이라고 합니다. 하락 추세 끝에서 나타날 경우 단기 하락세가 종료되고 강력한 매수세가 들어왔음을 뜻해 전환 신뢰도가 매우 높습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (604, '캔들/가격행동', '01_chart_market_basics.md', '시가와 종가가 거의 일치하여 몸통이 거의 없고 위아래 꼬리만 달린 십자(+) 모양 캔들이 출현했습니다. 이 캔들에 대한 올바른 해석은?', '[{"time":"Day 1","open":1500,"high":1550,"low":1480,"close":1520,"volume":110},{"time":"Day 2","open":1520,"high":1560,"low":1510,"close":1540,"volume":121},{"time":"Day 3","open":1540,"high":1590,"low":1500,"close":1540,"volume":102}]'::jsonb, '[]'::jsonb, ARRAY['상승세 동력 상실로 인한 추세의 하방 반전', '매수/매도 세력 균형에 따른 도지(Doji) 횡보', '매도세 지배에 따른 즉각적인 숏 포지션 진입', '하락 세력 이탈로 인한 즉각적인 상승 랠리']::text[], 1, '시가와 종가가 거의 같은 십자 모양의 캔들은 ''도지(Doji)'' 캔들입니다. 이는 힘의 균형이 팽팽함을 시사하며, 기존 추세의 힘이 빠지고 잠재적인 방향성 전환(상승/하락 모두 포함)의 변곡점이 다가오고 있음을 의미합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (605, '캔들/가격행동', '02_candlestick_price_action.md', '상승 추세 고점에서 직전 양봉의 몸통을 거대 음봉이 아래로 덮어버리는 캔들 조합이 발생했습니다. 이 현상을 의미하는 용어는?', '[{"time":"Day 1","open":1200,"high":1250,"low":1190,"close":1240,"volume":85},{"time":"Day 2","open":1240,"high":1300,"low":1230,"close":1290,"volume":98},{"time":"Day 3","open":1300,"high":1310,"low":1150,"close":1160,"volume":127}]'::jsonb, '[]'::jsonb, ARRAY['하락 장악형 (Bearish Engulfing) - 고점 하락 전환 예고', '상승 장악형 (Bullish Engulfing) - 고점 돌파 랠리 예고', '하락 잉태형 (Harami) - 기존 하락세의 일시 둔화', '샛별형 (Morning Star) - 바닥권 상승 반전 예고']::text[], 0, '고점에서 직전 양봉을 음봉이 감싸 안은 형태는 ''하락 장악형(Bearish Engulfing)''입니다. 매수 세력을 매도 공급이 압도했다는 명백한 증거로, 나스닥 시세 추세가 하락으로 반전할 리스크가 큽니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (606, '시장구조/SR', '03_market_structure.md', '나스닥 시세가 장기 저항선인 1,500달러를 거래량 실린 강한 캔들로 돌파한 뒤, 다시 1,500달러 부근으로 내려와 버티고 있습니다. 가장 안전한 진입 방식은?', '[{"time":"Day 1","open":1400,"high":1480,"low":1390,"close":1450,"volume":116},{"time":"Day 2","open":1450,"high":1490,"low":1430,"close":1440,"volume":122},{"time":"Day 3","open":1440,"high":1560,"low":1430,"close":1540,"volume":95},{"time":"Day 4","open":1540,"high":1550,"low":1490,"close":1510,"volume":341},{"time":"Day 5","open":1510,"high":1530,"low":1500,"close":1520,"volume":387}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":1500},{"x":4,"y":1500}],"label":"돌파된 저항선 -> 지지선 전환선","color":"#3b82f6"}]'::jsonb, ARRAY['돌파 시점에 시장가로 즉시 진입하는 추격 매수', '돌파 후 저항선의 지지선 전환(Retest) 확인 시 진입', '이전 최저가 부근인 1,400달러 조정 시까지 대기 매수', '돌파 후 즉시 단기 조정을 예상한 역추세 숏 진입']::text[], 1, '저항선이 강하게 뚫리면 역할 전환(Role Reversal)에 의해 신규 지지선으로 바뀝니다. 돌파 시점에 뇌동매매하기보다는 돌파된 선 부근으로 나스닥 시세가 눌려 지지(Retest)를 완성할 때 진입하는 것이 리스크 대비 기대 수익이 큽니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (607, '거래량/유동성', '05_volume_liquidity.md', '나스닥 시세가 저항선 위로 거래량 없이 장대양봉을 뿜어 올렸으나, 다음 날 곧바로 장대음봉으로 밀어붙이며 저항선 아래로 내려왔습니다. 이 현상의 명칭은?', '[{"time":"Day 1","open":980,"high":1010,"low":970,"close":1000,"volume":101},{"time":"Day 2","open":1000,"high":1020,"low":990,"close":1010,"volume":113},{"time":"Day 3","open":1010,"high":1100,"low":1000,"close":1080,"volume":23},{"time":"Day 4","open":1080,"high":1090,"low":950,"close":960,"volume":27}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":1020},{"x":3,"y":1020}],"label":"저항선","color":"#ef4444"}]'::jsonb, ARRAY['진짜 상승 돌파 (True Breakout)', '불 트랩 (Bull Trap) - 매수자 청산 유도 가짜 돌파', '베어 트랩 (Bear Trap) - 매도자 청산 유도 가짜 하방', '골든 크로스 (Golden Cross) - 이평선 돌파']::text[], 1, '저항선을 일시적으로 뚫었다가 대량 매도세와 함께 직후 캔들에서 하방으로 원상복귀하는 현상을 ''불 트랩(Bull Trap/가짜 돌파)''이라고 합니다. 돌파 후 리테스트를 기다리지 않고 급히 추격 매수했던 투자자들이 고점에 물리는 대표적 함정입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (608, '시장구조/SR', '01_chart_market_basics.md', '아래 차트에서 3번 연속 강하게 반등하며 가격 하락을 저지해 준 주요 가격대는 무엇을 의미하나요?', '[{"time":"Day 1","open":1000,"high":1020,"low":900,"close":910,"volume":117},{"time":"Day 2","open":910,"high":980,"low":900,"close":970,"volume":123},{"time":"Day 3","open":970,"high":1050,"low":960,"close":1040,"volume":118},{"time":"Day 4","open":1040,"high":1060,"low":910,"close":920,"volume":118},{"time":"Day 5","open":920,"high":1000,"low":900,"close":990,"volume":96}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":900},{"x":4,"y":900}],"label":"900달러선","color":"#10b981"}]'::jsonb, ARRAY['강력한 저항선 (Resistance Line) - 매도 매물대', '강력한 지지선 (Support Line) - 매수 매물대', '골든크로스 수렴선 - 이평선 밀집대', '이격도 붕괴선 - 가격 과열 분기점']::text[], 1, '특정 가격(900달러)에 접근할 때마다 대기 중이던 저가 매수세가 유입되어 나스닥 시세의 추가 하락을 방어해 준 이 라인은 ''강력한 지지선(Support Line)''입니다. 이탈하기 전까지는 손절 라인을 바로 밑에 두고 진입하기에 가장 손익비 좋은 구간입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (609, '거래량/유동성', '05_volume_liquidity.md', '지지선 아래로 나스닥 시세가 이탈하여 공매도가 폭증했으나, 이내 거래량이 급증하며 양봉으로 지지선을 회복한 뒤 반등을 시작했습니다. 이 현상의 명칭은?', '[{"time":"Day 1","open":1200,"high":1220,"low":1180,"close":1190,"volume":103},{"time":"Day 2","open":1190,"high":1200,"low":1100,"close":1110,"volume":101},{"time":"Day 3","open":1110,"high":1230,"low":1100,"close":1220,"volume":122}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":1150},{"x":2,"y":1150}],"label":"지지선","color":"#10b981"}]'::jsonb, ARRAY['불 트랩 (Bull Trap) - 가짜 상방 돌파', '베어 트랩 (Bear Trap) - 가짜 하방 이탈', '리테스트 실패 - 지지선 붕괴', '추세 추종 돌파 - 하방 랠리 가속']::text[], 1, '지지선을 아래로 뚫고 내려가 하락세가 지속될 것처럼 유도한 뒤, 매물을 털어내고 강력하게 다시 반등해 올리는 현상을 ''베어 트랩(Bear Trap)''이라고 합니다. 하락 돌파로 생각하고 공매도를 치거나 손절했던 사람들의 손실을 강제하며 가격이 급등하게 만듭니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (610, '시장구조/SR', '04_patterns_breakout.md', '저항선을 뚫어내기 직전 돌파 전조 현상 중 하나인 ''지지점 상승''의 특징을 골라보세요.', '[{"time":"Day 1","open":1000,"high":1050,"low":900,"close":1020,"volume":117},{"time":"Day 2","open":1020,"high":1050,"low":930,"close":1030,"volume":89},{"time":"Day 3","open":1030,"high":1050,"low":960,"close":1040,"volume":125}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":1050},{"x":2,"y":1050}],"label":"저항선 (105)","color":"#ef4444"}]'::jsonb, ARRAY['저항선 부근에서 고점들이 점점 급락하며 붕괴하는 현상', '저항선 부근에서 저점들을 높여가며 밀어 올리는 수렴 현상', '거래량이 완전히 소멸하여 긴 횡보 상태를 보이는 현상', '지속적인 매도세로 인해 갑작스럽게 급락하는 현상']::text[], 1, '저항을 뚫지 못하고 밀려 내려올 때, 이전 저점보다 높은 지점에서 저점을 계속 잡아 올려주는 것은 매도 압력보다 매수 압력이 점점 올라오고 있음을 의미합니다. 수렴 끝에 돌파가 나타날 신뢰도가 매우 높습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (611, '추세/레짐', '03_market_structure.md', '저점들을 연결한 우상향 상승 추세선 아래로 캔들의 종가(마감가격)가 이탈했습니다. 기술적 분석 관점의 올바른 해석은 무엇입니까?', '[{"time":"W-5","open":1000,"high":1050,"low":1000,"close":1030,"volume":112},{"time":"W-4","open":1030,"high":1100,"low":1020,"close":1080,"volume":115},{"time":"W-3","open":1080,"high":1090,"low":1050,"close":1060,"volume":88},{"time":"W-2","open":1060,"high":1150,"low":1070,"close":1130,"volume":114},{"time":"Today","open":1130,"high":1140,"low":1030,"close":1040,"volume":118}]'::jsonb, '[{"type":"line","points":[{"x":0,"y":1000},{"x":2,"y":1050},{"x":4,"y":1100}],"label":"상승 추세선","color":"#10b981"}]'::jsonb, ARRAY['추세선 이탈은 영향이 없으므로 비중 유지', '상승 추세 붕괴로 하락 반전 대비 비중 축소', '일시적인 속임수이므로 추가 불타기 진입', '채널 상단 도달에 따른 즉각적인 매수 대응']::text[], 1, '신뢰받던 우상향 상승 추세선 하방으로 캔들의 종가가 이탈 마감하는 것은 매수 중심의 시장 주도권이 붕괴했음을 뜻합니다. 지지를 잃은 하락 가속화 리스크에 대비해야 합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (612, '추세/레짐', '07_multitimeframe_regime.md', '아래 차트에서 고점들과 저점들이 일정한 평행 통로를 그리며 하락하고 있습니다. 채널 하단에 도달했을 때 단기 반등을 목표로 하는 매매의 명칭과 관점은?', '[{"time":"Day 1","open":1500,"high":1520,"low":1350,"close":1400,"volume":102},{"time":"Day 2","open":1400,"high":1470,"low":1390,"close":1450,"volume":116},{"time":"Day 3","open":1450,"high":1460,"low":1280,"close":1300,"volume":112},{"time":"Day 4","open":1300,"high":1380,"low":1290,"close":1360,"volume":93},{"time":"Day 5","open":1360,"high":1370,"low":1180,"close":1200,"volume":134}]'::jsonb, '[{"type":"channel","points":[{"x":0,"y":1500},{"x":4,"y":1350},{"x":0,"y":1350},{"x":4,"y":1200}],"label":"하향 평행 채널","color":"#f59e0b"}]'::jsonb, ARRAY['추세 추종 매매 - 대세 상승이므로 장기 보유', '채널 하단 반등 매매 - 단기 역추세 매수 대응', '양방향 물타기 매매 - 평단가를 낮춰 탈출 대기', '돌파 매매 - 채널 하방 붕괴 확정 시 매수 대응']::text[], 1, '가격이 평행한 하락 터널 내에서 움직이는 ''하향 평행 채널(Descending Channel)''입니다. 채널 하단 라인 터치 시에는 기술적 단기 반등이 자주 출현하므로, 손절선을 짧게 잡고 반등 타점을 노리는 역추세(Counter-trend) 트레이딩이 가능합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (613, '추세/레짐', '03_market_structure.md', '우상향 상승 평행 채널의 상단 저항선 부근까지 나스닥 시세가 도달했습니다. 합리적인 추세 채널 트레이더의 대응은?', '[{"time":"Day 1","open":1000,"high":1020,"low":990,"close":1010,"volume":86},{"time":"Day 2","open":1010,"high":1080,"low":1010,"close":1070,"volume":95},{"time":"Day 3","open":1070,"high":1090,"low":1040,"close":1050,"volume":101},{"time":"Day 4","open":1050,"high":1150,"low":1050,"close":1140,"volume":92},{"time":"Day 5","open":1140,"high":1160,"low":1120,"close":1130,"volume":99}]'::jsonb, '[{"type":"channel","points":[{"x":0,"y":1020},{"x":4,"y":1150},{"x":0,"y":990},{"x":4,"y":1120}],"label":"상승 평행 채널","color":"#10b981"}]'::jsonb, ARRAY['채널 상방 돌파를 예상한 고배율 레버리지 매수', '채널 상단 저항에 따른 분할 익절 및 대기', '채널 중간 조정 시 지정을 통한 시장가 추격', '채널 붕괴 신호에 따른 전량 기계적 손절']::text[], 1, '상승 채널이라고 해도 상단 저항선에 닿으면 다시 채널 하단이나 중심선까지 조정을 받을 가능성이 매우 큽니다. 따라서 고점 영역에서의 추격매수를 금지하고, 기존 포지션을 분할 익절하는 기회로 삼아야 합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (614, '추세/레짐', '01_chart_market_basics.md', '고점들을 잇는 우하향 하락 추세선을 나스닥 시세가 대량의 거래량을 동반하며 장대양봉 종가로 상향 돌파(Breakout)했습니다. 의미하는 시그널은?', '[{"time":"Day 1","open":1300,"high":1320,"low":1250,"close":1270,"volume":107},{"time":"Day 2","open":1270,"high":1280,"low":1200,"close":1220,"volume":121},{"time":"Day 3","open":1220,"high":1230,"low":1150,"close":1170,"volume":89},{"time":"Day 4","open":1170,"high":1280,"low":1160,"close":1270,"volume":113}]'::jsonb, '[{"type":"line","points":[{"x":0,"y":1310},{"x":2,"y":1220},{"x":3,"y":1180}],"label":"하락 추세선","color":"#ef4444"}]'::jsonb, ARRAY['하락 추세 지속에 따른 숏 포지션 추가 매수', '하락 추세 돌파 및 상승 전환 가능성에 따른 매수', '속임수 돌파를 예상한 즉시 반대 숏 포지션 진입', '추세와 무관하게 횡보 흐름으로 판단해 관망']::text[], 1, '중요한 하락 추세선을 나스닥 시세 몸통이 확실하게 뚫고 마감하는 것은 기존 하락 관성의 지배력이 종료되고 상승 추세로 돌아설 수 있는 가장 대표적인 추세 전환(Reversal) 확인 시그널입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (615, '추세/레짐', '03_market_structure.md', '추세선 작도 시 신뢰도를 판단하는 가장 중요한 규칙은 무엇인가요?', '[{"time":"Day 1","open":1000,"high":1010,"low":1000,"close":1010,"volume":101},{"time":"Day 2","open":1010,"high":1050,"low":1020,"close":1040,"volume":90}]'::jsonb, '[]'::jsonb, ARRAY['차트상 선이 정배열로 정돈되어 그려질 때', '최소 3개 이상의 뚜렷한 저점/고점 터치 확인 시', '가파른 각도로 90도에 가깝게 작도될 때', '보조지표와 결합하여 수평으로 그려질 때']::text[], 1, '두 점만으로도 선을 그릴 수 있지만, 3번째 터치(3rd Touch)에서 정확한 지지나 저항을 보이고 반등해 주는 순간부터 시장 참여자들이 공식 인지하는 신뢰도 높은 추세선이 됩니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (616, '패턴/돌파', '04_patterns_breakout.md', '머리와 양쪽 어깨 형태를 그리며 넥라인 지지선(960달러)을 위태롭게 지탱하다가 하방으로 강한 캔들이 이탈했습니다. 숏(매도) 포지션 진입 시점은?', '[{"time":"Day 1","open":1000,"high":1150,"low":980,"close":1100,"volume":83},{"time":"Day 2","open":1100,"high":1300,"low":950,"close":1050,"volume":92},{"time":"Day 3","open":1050,"high":1140,"low":960,"close":1100,"volume":117},{"time":"Day 4","open":1100,"high":1110,"low":930,"close":940,"volume":107}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":960},{"x":3,"y":960}],"label":"넥라인 지지선","color":"#ef4444"}]'::jsonb, ARRAY['머리 꼭대기(1,300달러) 부근에서 예측 숏 진입', '오른쪽 어깨가 올라가고 있을 때 돌파 전 선진입', '저점들을 연결한 넥라인의 하방 돌파 완료 시', '패턴 완성과 무관하게 오른쪽 어깨 끝에서 대기']::text[], 2, '헤드앤숄더(Head & Shoulders) 패턴은 오른쪽 어깨를 그린 후, 저점 지지선인 ''넥라인(Neckline)''을 거래량을 실어 하방 돌파해야 최종 완성이 선언됩니다. 그전에 진입하면 넥라인 반등 시 극심한 손실을 입습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (617, '패턴/돌파', '04_patterns_breakout.md', '하락 추세 끝에서 나스닥 시세가 비슷한 깊이의 바닥을 두 번(이중바닥) 형성한 뒤, 중간 고점 저항선(넥라인)을 돌파했습니다. 향후 예상 방향성과 매수 타점은?', '[{"time":"Day 1","open":1000,"high":1000,"low":800,"close":850,"volume":115},{"time":"Day 2","open":850,"high":950,"low":840,"close":940,"volume":110},{"time":"Day 3","open":940,"high":950,"low":790,"close":820,"volume":125},{"time":"Day 4","open":820,"high":990,"low":810,"close":980,"volume":103}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":950},{"x":3,"y":950}],"label":"넥라인 (95)","color":"#3b82f6"}]'::jsonb, ARRAY['추가 폭락 가능성에 따른 전량 손절 대응', 'W 패턴 이중 바닥 완성 및 넥라인 돌파 시 매수', '박스권 횡보 판단에 따른 무대응 및 관망', '이중 바닥의 하방 이탈을 예상한 숏 포지션 진입']::text[], 1, 'W자 모양의 ''이중 바닥형(Double Bottom)'' 패턴입니다. 나스닥 시세가 하락을 멈추고 바닥을 두 차례 단단히 지지해 준 뒤 중간 봉우리(넥라인 950달러)를 돌파해 마감하면 추세가 상승으로 강하게 전환될 가능성이 매우 높습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (618, '패턴/돌파', '04_patterns_breakout.md', '급격한 기둥식 나스닥 시세 폭등(깃대) 후, 완만한 하향 평행 채널(깃발) 모양으로 횡보/수렴하다가 채널 상단을 강하게 돌파했습니다. 이 패턴과 예상 목표가는?', '[{"time":"Day 1","open":500,"high":800,"low":490,"close":780,"volume":108},{"time":"Day 2","open":780,"high":790,"low":720,"close":740,"volume":111},{"time":"Day 3","open":740,"high":760,"low":700,"close":710,"volume":104},{"time":"Day 4","open":710,"high":850,"low":700,"close":830,"volume":115}]'::jsonb, '[]'::jsonb, ARRAY['이중 천정형 패턴 - 고점 도달 시 숏 진입', '불 플래그 패턴 - 깃발 돌파 시 추가 상승 기대', '헤드앤숄더 패턴 - 넥라인 하방 돌파 타겟', '대칭 삼각수렴 패턴 - 변동성 축소 후 돌파 대기']::text[], 1, '대표적 강세 지속 패턴인 ''불 플래그(Bull Flag)''입니다. 급격한 상승(깃대) 뒤 숨 고르기 채널(깃발)을 상방 돌파하면, 이전 상승 파동의 크기(깃대 높이)만큼 추가로 수직 랠리를 시작하는 관성이 있습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (619, '패턴/돌파', '04_patterns_breakout.md', '상승 추세의 천정권에서 나스닥 시세가 동일한 가격 저항을 두 번 확인하며 M자 모양을 만든 뒤, 두 고점 사이의 저점 지지선인 넥라인(1,200달러)을 이탈했습니다. 올바른 해석은?', '[{"time":"Day 1","open":1000,"high":1400,"low":990,"close":1350,"volume":119},{"time":"Day 2","open":1350,"high":1360,"low":1200,"close":1220,"volume":103},{"time":"Day 3","open":1220,"high":1400,"low":1210,"close":1380,"volume":106},{"time":"Day 4","open":1380,"high":1390,"low":1150,"close":1160,"volume":94}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":1200},{"x":3,"y":1200}],"label":"넥라인 (120)","color":"#ef4444"}]'::jsonb, ARRAY['상승 추세의 지속 연장에 따른 추가 매수', '이중 천정형(M 패턴) 완성에 따른 하락 반전 대비', '단기 조정에 따른 일시적 횡보 박스권 진입', '방향성 없는 일상적인 잔파동으로 판단해 홀딩']::text[], 1, '고점에서 지지받지 못하고 형성된 M자형 ''이중 천정형(Double Top)'' 패턴입니다. 두 차례 강력한 저항벽(1,400달러)을 넘지 못하고 넥라인(1,200달러)마저 붕괴했으므로 하방 추세가 가속화된다는 신호입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (620, '패턴/돌파', '04_patterns_breakout.md', '고점 저항선은 수평(평평함)을 유지하고 있으나, 저점 지지선은 점점 우상향하며 좁게 수렴하는 차트 형태의 명칭과 일반적인 돌파 방향은?', '[{"time":"Day 1","open":800,"high":1000,"low":800,"close":950,"volume":89},{"time":"Day 2","open":950,"high":1000,"low":860,"close":980,"volume":101},{"time":"Day 3","open":980,"high":1000,"low":920,"close":990,"volume":113}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":1000},{"x":2,"y":1000}],"label":"수평 저항선","color":"#ef4444"},{"type":"line","points":[{"x":0,"y":800},{"x":1,"y":860},{"x":2,"y":920}],"label":"상승 지지선","color":"#10b981"}]'::jsonb, ARRAY['디센딩 트라이앵글 - 일반적으로 하방 돌파 기대', '어센딩 트라이앵글 - 매수 압력 우위로 상방 돌파 기대', '헤드앤숄더 패턴 - 넥라인 하방 돌파 기대', '상향 평행 채널 - 상하단 터치식 채널 매매 기대']::text[], 1, '고점 저항은 평평하고 저점은 계속 높아지는 삼각수렴을 ''어센딩 트라이앵글(Ascending Triangle)''이라고 합니다. 위로 갈수록 저점이 계속 올라가는 현상은 매수세가 가격을 위로 계속 압박하고 있음을 증명하며, 대개 저항선(1,000달러)을 상향 뚫고 오르는 확률이 높습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (621, '지표/컨플루언스', '06_technical_indicators.md', '나스닥 시세는 매일 하락하여 신저가를 갱신하고 있으나, RSI 보조지표의 저점은 점점 높아지는 현상을 발견했습니다. 올바른 용어와 매매 대응법은?', '[{"time":"D-4","open":1100,"high":1120,"low":980,"close":1000,"volume":97},{"time":"D-3","open":1000,"high":1040,"low":960,"close":980,"volume":95},{"time":"D-2","open":980,"high":1010,"low":920,"close":940,"volume":97},{"time":"D-1","open":940,"high":970,"low":930,"close":960,"volume":125},{"time":"Today","open":960,"high":990,"low":950,"close":980,"volume":113}]'::jsonb, '[]'::jsonb, ARRAY['하락 다이버전스 - 가격 상승 둔화에 따른 공매도', '상승 다이버전스 - 하락 둔화 및 반등 신호로 매수', '데드 크로스 - 이평선 하방 교차에 따른 관망', '과매수 이탈 시그널 - 단기 반등에 따른 매수']::text[], 1, '나스닥 시세의 가격 저점은 낮아지나 보조지표(RSI)의 운동 저점이 높아지는 현상을 ''상승 다이버전스(Bullish Divergence)''라고 합니다. 이는 하방 에너지의 실질적 소멸과 상승 압력의 내부 응축을 의미하는 기술적 분석에서 가장 신뢰도 높은 추세 전환 시그널입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (622, '지표/컨플루언스', '06_technical_indicators.md', '나스닥 시세는 급격히 치솟으며 최고가 갱신 랠리를 이어가고 있으나, RSI 지표의 고점은 계속 낮아지고 있습니다. 이 현상을 지칭하는 명칭과 대처법은?', '[{"time":"Day 1","open":1000,"high":1200,"low":990,"close":1180,"volume":87},{"time":"Day 2","open":1180,"high":1220,"low":1150,"close":1200,"volume":108},{"time":"Day 3","open":1200,"high":1350,"low":1190,"close":1330,"volume":93}]'::jsonb, '[]'::jsonb, ARRAY['하락 다이버전스 - 매수 둔화 및 하락 우려로 익절', '상승 다이버전스 - 추가 급등 기대로 신규 매수', '골든 크로스 - 추세 강화에 따른 홀딩', '볼린저 밴드 스퀴즈 - 변동성 수축 후 돌파']::text[], 0, '나스닥 시세는 계속 고점을 높이고 있으나 보조지표의 고점은 꺾여 낮아지는 현상을 ''하락 다이버전스(Bearish Divergence)''라고 합니다. 이는 매수세의 힘이 표면적인 가격 상승에 비해 실질적으로 빠르게 축소되고 있음을 경고하며, 조만간 큰 급락이 발생할 확률이 높습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (623, '지표/컨플루언스', '06_technical_indicators.md', '이동평균선(EMA) 20일선(단기)이 50일선(중기)을 아래에서 위로 강하게 뚫고 솟구쳐 올랐습니다. 이 교차 현상의 정식 명칭은?', '[{"time":"Day 1","open":1000,"high":1020,"low":980,"close":990,"volume":84},{"time":"Day 2","open":990,"high":1040,"low":990,"close":1030,"volume":119},{"time":"Day 3","open":1030,"high":1100,"low":1030,"close":1090,"volume":106}]'::jsonb, '[]'::jsonb, ARRAY['데드 크로스 - 단기 이평의 하방 교차로 매도 신호', '골든 크로스 - 단기 이평의 상방 교차로 매수 신호', '볼린저 스퀴즈 - 변동성 수축 및 돌파 신호', '다이버전스 수렴 - 지표와 가격의 동반 횡보']::text[], 1, '단기 이평선이 장기 이평선을 위로 치고 올라가는 현상을 ''골든 크로스(Golden Cross)''라고 합니다. 이는 최근 매수 평단가가 장기 평균가보다 확연히 높아졌음을 시사하며, 상승 추세가 본 궤도에 올랐음을 입증해 줍니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (624, '지표/컨플루언스', '07_multitimeframe_regime.md', '매우 강력한 원웨이 폭락장 속에서 RSI 지표가 20(과매도 영역) 이하로 깊이 내려왔습니다. 이를 보고 ''과매도 반등''을 노리며 기계적 시장가 풀매수를 때렸을 때 나타나는 가장 빈번한 오류는?', '[{"time":"Day 1","open":1000,"high":1010,"low":880,"close":890,"volume":88},{"time":"Day 2","open":890,"high":900,"low":750,"close":760,"volume":22},{"time":"Day 3","open":760,"high":770,"low":620,"close":630,"volume":23}]'::jsonb, '[]'::jsonb, ARRAY['하락 추세 즉시 종료 및 V자 상승 반등 성공', '강력한 하락장에서의 지표 과매도 고착화 리스크', '거래량 급감으로 인한 호가 정지 및 상장 폐지', '나스닥 시세의 즉각적인 박스권 횡보 및 변동성 축소']::text[], 1, 'RSI 30 이하 과매도 영역은 반등 신호이기도 하지만, 추세가 지나치게 강력한 하락장일 때는 지표만 과매도 구역에 쳐박힌 채 가격은 계속 급락하는 ''과매도 고착화(Oversold Embedded)'' 상태가 이어집니다. 다이버전스나 캔들 반전형 확인 없이 수치만 보고 들어가는 매수는 깡통으로 가는 지름길입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (625, '지표/컨플루언스', '06_technical_indicators.md', '나스닥 시세의 변동성이 극도로 축소되며 볼린저 밴드의 폭이 매우 좁아지는 ''스퀴즈(Squeeze)'' 현상이 나타났습니다. 이후 기대되는 시장 변동성의 원리는 무엇인가요?', '[{"time":"Day 1","open":1000,"high":1010,"low":990,"close":1000,"volume":82},{"time":"Day 2","open":1000,"high":1000,"low":990,"close":990,"volume":109},{"time":"Day 3","open":990,"high":1000,"low":990,"close":1000,"volume":104}]'::jsonb, '[]'::jsonb, ARRAY['변동성 사멸로 인한 장기 횡보 및 거래 정지', '밴드 스퀴즈 후 변동성 팽창에 따른 추세 분출', '나스닥 시세의 하방 붕괴로 인한 강한 하락 파동 시작', '이평선들의 수평 정렬에 따른 완전한 추세 고정']::text[], 1, '볼린저 밴드의 수축(Squeeze)은 시장의 숨 고르기 및 힘 모으기를 뜻합니다. 에너지가 최대한 압축된 후에는 밴드 상단 혹은 하단선을 이탈하며 매우 거대한 변동성 팽창(Expansion) 추세가 시작되므로, 방향성을 유심히 지켜봐야 합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (626, '리스크/심리', '09_risk_position_management.md', '총 투자 원금은 10,000만 원이며, 1회 거래 시 최대 손실 허용액을 원금의 2%(200만 원)로 제한하는 ''2% 룰''을 지키려 합니다. 진입하려는 종목의 손절 라인 폭이 -5%일 때, 최대 매수(진입) 가능 금액은 얼마인가요?', '[{"time":"Day 1","open":100000,"high":105000,"low":98000,"close":102000,"volume":98},{"time":"Day 2","open":102000,"high":103000,"low":100000,"close":100000,"volume":89}]'::jsonb, '[]'::jsonb, ARRAY['10,000만 원 (원금 전액 진입)', '2,000만 원 (원금의 20% 진입)', '4,000만 원 (원금의 40% 진입)', '5,000만 원 (원금의 50% 진입)']::text[], 2, '2% 룰에 기초한 포지션 사이징 공식은 `진입금액 = (총원금 * 리스크비율) / 손절비율` 입니다. 따라서 `200만 원 / 0.05 = 4,000만 원`이 됩니다. 4,000만 원어치 지수 선물을 샀을 때 가격이 -5% 떨어져 강제 손절을 맞아도 내 계좌 총액에서 손실을 보는 돈은 정확히 2%인 200만 원으로 통제됩니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (627, '리스크/심리', '09_risk_position_management.md', '어느 지수 선물에 100,000원에 매수 진입합니다. 손절 라인은 95,000원(-5%)에 배치하고, 목표가는 115,000원(+15%)에 설정했습니다. 이 트레이딩 시나리오의 손익비(Risk-to-Reward Ratio)는 얼마입니까?', '[{"time":"Today","open":100000,"high":100000,"low":100000,"close":100000}]'::jsonb, '[]'::jsonb, ARRAY['1 : 1 (동일한 기대 수익과 리스크)', '1 : 2 (기대 수익이 리스크의 2배)', '1 : 3 (기대 수익이 리스크의 3배)', '2 : 1 (기대 수익이 리스크의 0.5배)']::text[], 2, '손절 폭(5,000원) 대비 익절 폭(15,000원)의 비례를 의미하므로 `1,500 / 500 = 3`, 즉 손익비는 1:3이 됩니다. 이처럼 잃는 돈의 최소 2~3배를 벌 수 있는 손익비 높은 구간만 반복적으로 거래해야 장기적으로 계좌가 생존합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (628, '리스크/심리', '09_risk_position_management.md', '손익비를 엄격히 통제하여 항상 기대 손실의 2배를 버는 매매(손익비 1:2)만 고집합니다. 이 경우 내 계좌 잔고가 손실 없이 제자리걸음(본전)을 유지하기 위해 필요한 수학적인 최소 승률(Win Rate)은 얼마인가요?', '[{"time":"Today","open":1000,"high":1000,"low":1000,"close":1000}]'::jsonb, '[]'::jsonb, ARRAY['50.0% (최소 절반 이상 성공)', '33.3% (3번 중 1번 성공으로 본전)', '25.0% (4번 중 1번 성공으로 본전)', '66.6% (3번 중 2번 성공으로 본전)']::text[], 1, '손익비가 1:2일 경우, 1번 이기면 +2를 벌고 2번 지면 -2를 잃으므로 3번 매매 중 1번만 이겨도 누적 수익은 0이 됩니다. 즉 손익비를 1:2 이상으로 유지하면 수학적으로 승률이 겨우 33.3%만 나와도 절대 파산하지 않고 계좌가 우상향할 발판이 마련됩니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (629, '셋업/실행', '08_setup_entry_exit.md', '100,000원에 산 지수 선물이 150,000원까지 올랐습니다. 이익을 보존하면서 상승세를 끝까지 타기 위해, 최고점 대비 10% 하방 이탈 시 즉시 자동 익절되는 ''추적 손절매(Trailing Stop)''를 적용했습니다. 최고점 150,000원 달성 후 나스닥 시세가 조정받을 때 실제로 청산(익절)되는 가격은 얼마인가요?', '[{"time":"Day 1","open":100000,"high":120000,"low":99000,"close":119000,"volume":106},{"time":"Day 2","open":119000,"high":150000,"low":118000,"close":148000,"volume":114}]'::jsonb, '[]'::jsonb, ARRAY['100,000원 (본전 수준 청산)', '135,000원 (최고점 대비 10% 하방 청산)', '140,000원 (최고점 대비 6.6% 하방 청산)', '120,000원 (최고점 대비 20% 하방 청산)']::text[], 1, '추적 손절매(Trailing Stop)는 가격 상승에 따라 청산 가격을 자동으로 올려주는 주문입니다. 최고점 150,000원을 기록했으므로 청산 트리거 라인은 최고점에서 10% 차감된 `15,000 * 0.9 = 135,000원`으로 확정 셋업되며, 나스닥 시세가 135,000원을 건드리는 순간 자동 이익실현됩니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (630, '리스크/심리', '09_risk_position_management.md', '레버리지 10배를 적용하여 나스닥 지수 롱(매수) 포지션을 구축했습니다. 만약 나스닥 지수 가격이 매수가 대비 몇 % 역방향으로 등락하면 내 투자 원금이 100% 강제 청산(증거금 완전 소멸)당할까요?', '[{"time":"Today","open":500000,"high":501000,"low":499000,"close":500000}]'::jsonb, '[]'::jsonb, ARRAY['5.0% 하락 시', '10.0% 하락 시', '20.0% 하락 시', '100.0% 하락 시']::text[], 1, '레버리지 비율과 청산 거리 비율은 역수 관계입니다. `100% / 레버리지 배수` 공식에 따라, 10배 레버리지는 나스닥 시세가 내 베팅의 반대 방향으로 단 10%만 움직여도 투자 원금이 전부 증발하고 포지션이 강제 종료(Liquidation)됩니다. 고배율 레버리지가 파산의 지름길인 이유입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (631, '캔들/가격행동', '02_candlestick_price_action.md', '상승 추세 고점 영역(1,500달러선)에서 몸통이 매우 작고 아래꼬리가 긴 행잉맨(Hanging Man) 캔들이 출현한 이후, 다음 날 시가가 전일 종가보다 큰 갭을 그리며 낮게 하락 출발(1,450달러)했습니다. 포지션을 보유한 스윙 트레이더로서 가장 적절한 위기 대응 행동은 무엇입니까?', '[{"time":"Day 1","open":1200,"high":1250,"low":1190,"close":1240,"volume":116},{"time":"Day 2","open":1240,"high":1350,"low":1230,"close":1340,"volume":87},{"time":"Day 3","open":1340,"high":1480,"low":1330,"close":1460,"volume":99},{"time":"Day 4","open":1460,"high":1510,"low":1400,"close":1470,"volume":97},{"time":"Day 5","open":1410,"high":1430,"low":1350,"close":1360,"volume":104}]'::jsonb, '[]'::jsonb, ARRAY['상승 랠리를 기대로 보유 비중 확대 및 추격 매수', '일시적 속임수(휩소) 판단으로 추가 레버리지 매수', '행잉맨 출현 후 갭하락에 따른 전량 또는 일부 정리', '조치 없이 전고점 돌파 시까지 무기한 관망 및 홀딩']::text[], 2, '고가권에서 나타난 행잉맨(Hanging Man)은 잠재적 하락 전환 신호이며, 특히 다음날 갭하락 음봉으로 직전 행잉맨의 저가를 깨고 내려가는 움직임은 강력한 하락 컨펌 시그널입니다. 따라서 이 시점에서는 즉시 비중을 전량 정리하거나 최소 절반 이상 매도하여 리스크를 통제하는 것이 정석입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (632, '캔들/가격행동', '01_chart_market_basics.md', '지속적인 하락 추세 도중 바닥권(800달러선)에서 시가와 종가가 일치하고 긴 아래꼬리를 단 십자 형태의 도지(Doji) 캔들이 생성되었습니다. 다음 날 대량의 거래량과 함께 장대양봉이 솟구치며 870달러로 마감하는 샛별형(Morning Star) 조합이 확정되었습니다. 이때 가장 합리적인 매수 진입 지점과 손절가 기준은 무엇입니까?', '[{"time":"Day 1","open":1000,"high":1010,"low":930,"close":940,"volume":109},{"time":"Day 2","open":940,"high":950,"low":880,"close":890,"volume":104},{"time":"Day 3","open":890,"high":900,"low":800,"close":810,"volume":101},{"time":"Day 4","open":800,"high":820,"low":750,"close":800,"volume":126},{"time":"Day 5","open":800,"high":880,"low":790,"close":870,"volume":124}]'::jsonb, '[]'::jsonb, ARRAY['손절 없이 100% 비중으로 시장가 매수', '샛별형 완성에 따라 분할 매수 후 최저점 손절 셋업', '바닥 도달 기대로 주문 없이 무작정 대기', '상승 꼭대기에서 숏 진입 후 손절 없이 방치']::text[], 1, '하락 추세 끝에 도지와 장대양봉이 결합된 샛별형(Morning Star)은 매우 신뢰도 높은 바닥 상승 전환 신호입니다. 이 패턴을 보고 진입할 때는 반등 상승세에 분할 매수로 동참하되, 바닥을 잡아준 도지 캔들의 최저점(750달러) 아래를 최종 손절 라인으로 잡는 것이 수학적으로 가장 리스크 대비 보상 비율(손익비)이 훌륭한 전략입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (633, '거래량/유동성', '02_candlestick_price_action.md', '나스닥 시세가 강력한 횡보 박스권 고점(2,000달러 저항선)에 세 번째 터치하는 와중에, 윗꼬리가 길고 몸통이 매우 얇은 유성형(Shooting Star) 캔들이 이틀 연속 발생했습니다. 거래량 역시 저항선 부근에서 매수세가 더 올라가지 못하고 매도 압력이 실려 나타났습니다. 롱(매수) 포지션을 들고 있는 당신의 합리적인 의사결정은?', '[{"time":"Day 1","open":1750,"high":1850,"low":1740,"close":1820,"volume":97},{"time":"Day 2","open":1820,"high":1950,"low":1800,"close":1930,"volume":97},{"time":"Day 3","open":1930,"high":2020,"low":1900,"close":1910,"volume":107},{"time":"Day 4","open":1910,"high":2010,"low":1880,"close":1890,"volume":118}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":2000}],"label":"박스권 상단 저항선 (200)","color":"#ef4444"}]'::jsonb, ARRAY['신고가 갱신을 예상한 전재산 추가 불타기', '저항 돌파 실패 신호 확인 후 분할 익절 및 관망', '손익 평단가 부근이므로 추가 손절 없이 방치', '거래를 종료하고 다른 신규 급등주를 시장가 추격']::text[], 1, '박스권 상단 저항선(2,000달러)에 부딪히며 나타난 유성형(Shooting Star) 연속 출현은 저항 돌파 실패와 차익 실현 세력의 강력한 등장을 경고하는 캔들 신호입니다. 돌파를 확신하기보다는 리스크 관리 관점에서 물량을 축소(50% 분할 익절)하거나 전량 매도하여 이익을 확정 짓는 것이 현명합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (634, '캔들/가격행동', '02_candlestick_price_action.md', '극심한 하락 추세 중 1,000달러선 아래로 떨어지던 나스닥 시세가 전일 장대음봉을 형성했습니다. 그러나 당일 시가는 갭하락하여 더 낮게 시작했으나, 장중에 강한 매수세가 들어오며 전일 음봉 몸통의 정확히 70% 라인(930달러선) 위로 덮어버리는 관통형(Piercing Line) 상승 캔들로 마감했습니다. 종가 매수(롱) 진입 시 원칙 대응은?', '[{"time":"Day 1","open":1100,"high":1110,"low":1040,"close":1050,"volume":101},{"time":"Day 2","open":1050,"high":1060,"low":970,"close":980,"volume":87},{"time":"Day 3","open":920,"high":1010,"low":910,"close":1000,"volume":89}]'::jsonb, '[]'::jsonb, ARRAY['상승 모멘텀 미달로 매수 보류 및 하방 숏 포지션 진입', '관통형 확인 후 분할 매수 및 당일 최저점 손절 설정', '손절 라인 설정 없이 100% 비중 시장가 매수 집행', '조정을 대기하며 예약 주문 없이 무작정 관망 유지']::text[], 1, '전일 음봉의 50% 이상을 당일 양봉 몸통으로 관통해 올린 ''관통형(Piercing Line)''은 하락 모멘텀이 쇠퇴하고 저가 매수세가 우위를 점하기 시작했음을 뜻하는 바닥 신호입니다. 이 패턴 확인 후 진입할 시에는 손절 한도를 당일 최저점(910달러) 밑에 가깝게 설정할 수 있어 매우 유리한 리스크 대비 기대수익 매매가 성립됩니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (635, '캔들/가격행동', '05_volume_liquidity.md', '강한 급등세를 지속하던 나스닥 시세가 최고점에서 큰 거래량을 터뜨리며 장대양봉을 만들었습니다. 그러나 다음 날, 전일 양봉 몸통의 한가운데 범위 안에서 움직이며 시가와 종가가 모두 갇혀버리는 짧은 음봉인 ''하락 잉태형(Bearish Harami)'' 캔들이 형성되었습니다. 단기 스윙 트레이더로서 당신의 포지션 리스크 관리 행동은?', '[{"time":"Day 1","open":1200,"high":1280,"low":1190,"close":1270,"volume":82},{"time":"Day 2","open":1270,"high":1380,"low":1260,"close":1360,"volume":115},{"time":"Day 3","open":1330,"high":1340,"low":1300,"close":1310,"volume":89}]'::jsonb, '[]'::jsonb, ARRAY['상승 둔화 조짐에 따른 보유 물량 50% 분할 익절', '추세 일시 조정으로 간주하여 비중 확대 추가 매수', '추세 종결 판단에 따른 고배율 숏 포지션 즉시 진입', '이익 실현 없이 전량 장기 보유 전략 유지']::text[], 0, '하락 잉태형(Bearish Harami)은 이전의 강한 상승 추세 동력이 감속하기 시작했으며, 매도 압력이 힘을 기르고 있음을 암시하는 변곡 캔들입니다. 따라서 단기 스윙 트레이더는 물량의 일부(50%)를 분할 익절하여 리스크를 낮추고, 다음 캔들에서 이전 양봉 저점을 깨뜨리는 하락 하방 이탈이 추가되는지 지켜보는 것이 정석입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (636, '시장구조/SR', '03_market_structure.md', '오랫동안 지켜지던 핵심 지지선인 1,000달러 부근에서 매수 진입을 완료했습니다. 그러나 가격이 대량의 거래량을 동반하며 장대음봉으로 지지선을 하방으로 강하게 뚫어냈고, 종가가 지지선 대비 1.5% 아래인 98.50달러로 결정되었습니다. 이 상황에서 원칙을 지키는 올바른 위기 대응 행동은?', '[{"time":"Day 1","open":1050,"high":1080,"low":1020,"close":1030,"volume":113},{"time":"Day 2","open":1030,"high":1040,"low":990,"close":1000,"volume":112},{"time":"Day 3","open":1000,"high":1010,"low":980,"close":985,"volume":123}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":1000}],"label":"중요 지지선 (100)","color":"#10b981"}]'::jsonb, ARRAY['추가 물타기를 위해 자금을 동원하여 평단가 관리', '중요 지지선 붕괴(Breakdown) 확인 후 즉시 전량 손절', '지속 하락 시 추가 평단가 관리를 위해 매수 유보', '하방 이탈 시 즉시 반대 고배율 롱 포지션 진입']::text[], 1, '거래량이 동반된 장대음봉으로 주요 지지선 아래에서 종가가 결정되는 이탈 마감은 매수 지지 세력의 패배이자 추세 붕괴(Breakdown)의 신호입니다. 이 시점에서 물타기를 하거나 존버를 하면 파산적인 하락 조정을 겪을 수 있으므로 즉시 룰에 근거한 ''전량 손절''을 집행해야 계좌를 살릴 수 있습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (637, '시장구조/SR', '03_market_structure.md', '1,500달러의 중요 저항선이 강한 거래량을 실은 돌파봉으로 뚫렸습니다. 이후 나스닥 시세가 숨 고르기 조정을 받으며 1,500달러 부근까지 되돌아왔고(리테스트 구간), 저항선 부근에서 거래량이 크게 감소하며 아래꼬리가 달린 도지 캔들로 안착하는 모습을 보입니다. 이때 가장 안전하고 합리적인 매매 조치는?', '[{"time":"Day 1","open":1400,"high":1460,"low":1390,"close":1440,"volume":107},{"time":"Day 2","open":1440,"high":1570,"low":1430,"close":1550,"volume":92},{"time":"Day 3","open":1550,"high":1560,"low":1490,"close":1500,"volume":105}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":1500}],"label":"돌파된 저항선 -> 지지선 전환선 (150)","color":"#3b82f6"}]'::jsonb, ARRAY['가짜 돌파(휩소) 판단에 따른 고배율 숏 진입', '돌파 후 리테스트 성공 확인 시 지지선 눌림목 매수', '추격 매수 기회 상실로 판단하고 거래 포기', '1,600달러 추가 돌파를 타겟으로 시장가 추격 매수']::text[], 1, '강하게 돌파된 저항선은 룰 체인지에 의해 지지선으로 변합니다(역할 전환). 돌파 당시 추격 매수하기보다, 돌파된 선(1,500달러)으로 나스닥 시세가 되돌아오는 리테스트(Retest) 시점에 저조한 거래량과 지지 캔들을 확인하고 손절선을 바로 밑에 설정하여 눌림목 진입하는 것이 리스크가 가장 적은 프로 트레이더의 정석입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (638, '시장구조/SR', '03_market_structure.md', '가격이 800달러 지지선 근처에서 반등을 시도하고 있으나, 반등의 폭이 직전 고점에 턱없이 못 미치며 저점 부근으로 다시 짓눌리고 있습니다. 즉, 고점들이 계속 낮아지는 하락 우위 삼각수렴(Descending)의 형태가 지지선 바로 위에서 감지됩니다. 이 시점에서 지지선 반등을 믿고 신규 매수(롱)를 진입하는 것은 원칙에 맞습니까?', '[{"time":"Day 1","open":950,"high":980,"low":800,"close":880,"volume":105},{"time":"Day 2","open":880,"high":910,"low":800,"close":840,"volume":84},{"time":"Day 3","open":840,"high":860,"low":800,"close":810,"volume":88}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":800}],"label":"지지선 (80)","color":"#10b981"}]'::jsonb, ARRAY['삼중 바닥 지지로 판단하고 매수 비중 대폭 확대', '디센딩 수렴 확인 후 하방 이탈 위험 대비 관망', '물타기 평단가 관리를 위해 매수 보증금 추가 투입', '추세와 무관하게 숏 포지션으로 전환 후 무기한 보유']::text[], 1, '지지선 부근에서 고점이 점점 낮아지는 ''디센딩'' 형태는 매수 지원 강도가 둔화되고 매도 출하 공급이 가격을 계속 하방으로 압박하고 있음을 증명합니다. 지지 성공보다 지선 하방 붕괴 후 급락할 확률이 높으므로, 지지선이라는 명목만으로 함부로 매수 진입하지 말고 돌파/이탈 컨펌을 기다려 관망하는 것이 현명합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (639, '거래량/유동성', '05_volume_liquidity.md', '나스닥 시세가 1,200달러의 장기 저항벽을 거래량이 거의 실리지 않은 얇은 양봉으로 상방으로 살짝 뚫었으나, 바로 다음 날 직전 양봉 몸통을 통째로 덮어버리는 대량 거래량의 장대음봉이 출현하며 1,160달러로 곤두박질쳤습니다. 매수 포지션을 추격 진입했던 당신의 올바른 조치는?', '[{"time":"Day 1","open":1120,"high":1180,"low":1110,"close":1170,"volume":100},{"time":"Day 2","open":1170,"high":1220,"low":1160,"close":1210,"volume":357},{"time":"Day 3","open":1210,"high":1220,"low":1150,"close":1160,"volume":342}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":1200}],"label":"장기 저항선 (120)","color":"#ef4444"}]'::jsonb, ARRAY['불 트랩(Bull Trap) 확인 후 추가 하락 방지 즉시 손절', '저항선 부근 매수세 복귀를 기대하며 전량 홀딩', '평단가 관리 차원에서 추가 물타기 매수 집행', '상황을 판단하기 위해 시장가로 추가 분할 진입']::text[], 0, '거래량 없는 돌파 직후에 거래량 실린 강한 음봉이 기존 돌파선(1,200달러) 아래로 재진입하여 마감하는 현상은 전형적인 불 트랩(Bull Trap/가짜 돌파) 함정입니다. 돌파 당시 샀던 매수자들의 패닉 셀이 출현하며 하락 가속화가 나오기 쉬우므로 즉시 손절하여 물량을 털어내야 생존할 수 있습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (640, '시장구조/SR', '10_psychology_routine_review.md', '주요 지지선(2,500달러선)이 아래로 무너질 때 제때 손절 처리를 하지 못해 나스닥 시세가 2,200달러선까지 끌려 내려갔습니다. 다행히 단기 매도 진정세로 반등이 나와 나스닥 시세가 다시 2,500달러 부근까지 상승하여 회복을 눈앞에 두고 있습니다. 이때 손실을 최소화하는 현명한 시나리오 대처법은?', '[{"time":"Day 1","open":2600,"high":2620,"low":2480,"close":2490,"volume":83},{"time":"Day 2","open":2490,"high":2500,"low":2200,"close":2220,"volume":121},{"time":"Day 3","open":2220,"high":2350,"low":2210,"close":2340,"volume":119},{"time":"Day 4","open":2340,"high":2510,"low":2330,"close":2490,"volume":105}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":2500}],"label":"붕괴된 지지선 -> 저항선으로 변형 (250)","color":"#ef4444"}]'::jsonb, ARRAY['역할 전환(저항선) 도달에 따른 탈출 및 현금화', 'V자 반등 성공 확신에 따른 추가 매수 비중 확대', '원금 회복 및 추가 수익 시까지 영구 홀딩 관망', '하락 추세 지속에 따른 반대 숏 포지션 스위칭']::text[], 0, '하방으로 깨진 지지선은 반등할 때 가장 뚫기 힘든 ''강력한 저항선''으로 성격이 바뀝니다. 따라서 손절 기회를 놓치고 물려있던 트레이더는 반등하여 옛 지지선(2,500달러)에 도달했을 때를 ''최선의 리스크 탈출 기회(탈출구)''로 삼아 전량 매도하거나 비중을 극도로 덜어내야 다가올 2차 하락 파동의 파산을 막을 수 있습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (641, '추세/레짐', '03_market_structure.md', '나스닥 시세가 매우 가파르게 올라가던 1차 단기 상승 추세선을 강한 음봉 종가로 뚫고 내려왔습니다. 다행히 각도가 완만하고 탄탄한 장기 핵심 상승 추세선은 저 밑에 지지 영역을 유지하고 있습니다. 스윙 트레이더로서 가장 정석적인 포지션 제어 방식은 무엇인가요?', '[{"time":"Day 1","open":1000,"high":1020,"low":1000,"close":1020,"volume":90},{"time":"Day 2","open":1020,"high":1100,"low":1020,"close":1090,"volume":95},{"time":"Day 3","open":1090,"high":1250,"low":1090,"close":1240,"volume":117},{"time":"Day 4","open":1240,"high":1250,"low":1140,"close":1150,"volume":108}]'::jsonb, '[{"type":"line","points":[{"x":0,"y":1000},{"x":3,"y":1230}],"label":"가파른 단기 추세선 (붕괴)","color":"#ef4444"},{"type":"line","points":[{"x":0,"y":1000},{"x":3,"y":1100}],"label":"완만한 장기 추세선 (지탱 중)","color":"#10b981"}]'::jsonb, ARRAY['추세 붕괴 판단에 따른 전량 손절 및 영구 이탈', '가속 추세 이탈에 따른 50% 분할 익절 및 분산', '단기 지지선 붕괴를 무시한 고배율 물타기 매수', '장기 추세선까지 조정을 대비한 신규 매수 대기']::text[], 1, '가파르게 우상향하던 가속 추세선(Accelerated Trendline)이 하방 돌파되는 것은 기존 폭등 랠리의 속도가 둔화되고 완만한 본래 장기 추세선(장기 매물대)을 향해 정상적인 가격 조정을 받기 시작했음을 뜻합니다. 따라서 물량의 50%가량을 털어 수익을 실현하고 남은 물량으로 장기 추세선의 3rd Touch 지지 성공 여부를 테스트하는 것이 리스크 관리의 기본입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (642, '거래량/유동성', '05_volume_liquidity.md', '고점과 저점이 연속으로 낮아지는 명확한 하락 평행 채널 내에서 하락 압력을 받아 숏(매도) 포지션을 잡고 수익 중이었습니다. 그런데 당일 캔들이 대량의 거래량과 함께 장대양봉을 그리며 채널 상단 저항선 위로 종가 안착(상방 돌파)했습니다. 숏 포지션을 쥔 당신의 결단은?', '[{"time":"Day 1","open":1000,"high":1020,"low":900,"close":920,"volume":97},{"time":"Day 2","open":920,"high":940,"low":820,"close":830,"volume":109},{"time":"Day 3","open":830,"high":850,"low":750,"close":760,"volume":122},{"time":"Day 4","open":760,"high":900,"low":750,"close":890,"volume":113}]'::jsonb, '[{"type":"channel","points":[{"x":0,"y":1020},{"x":3,"y":860},{"x":0,"y":900},{"x":3,"y":760}],"label":"하락 평행 채널 상한/하한","color":"#f59e0b"}]'::jsonb, ARRAY['상단 돌파 확인 즉시 숏 전량 손절 및 대피', '채널 재진입 기대로 숏 포지션 추가 물타기', '손절 없이 유지하면서 포지션 본전 도달 대기', '포지션 유지 후 증거금을 출금하여 강제 횡보']::text[], 0, '하락 평행 채널의 상단 저항선 상향 돌파(Breakout)는 기존 하락 트렌드의 사멸과 매수세 지배령 복귀를 뜻합니다. 지표와 거래량이 동반된 돌파 확인 시에는 숏 포지션을 지체 없이 기계적으로 칼손절하여 자산을 보호하는 것이 원칙입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (643, '추세/레짐', '07_multitimeframe_regime.md', '우상향하는 상승 평행 채널 안에서 순항하던 나스닥 시세가 중심선(Mid-line)을 뚫고 하방으로 이탈 마감했습니다. 이후 중심선 부근까지 반등을 시도했으나 재차 저항을 받고 아래꼬리가 꺾여 채널 하단선을 향해 하락 조정을 재개하려 합니다. 신규 매수(롱) 포지션 진입을 계획 중인 트레이더의 대응법은?', '[{"time":"Day 1","open":1000,"high":1080,"low":990,"close":1060,"volume":105},{"time":"Day 2","open":1060,"high":1120,"low":1020,"close":1040,"volume":97},{"time":"Day 3","open":1040,"high":1060,"low":980,"close":1000,"volume":92}]'::jsonb, '[{"type":"channel","points":[{"x":0,"y":1100},{"x":2,"y":1120},{"x":0,"y":980},{"x":2,"y":1000}],"label":"상승 평행 채널","color":"#10b981"}]'::jsonb, ARRAY['채널 내 유지를 기대로 지정가 즉시 매수', '중심선 저항 확인 후 채널 하단 안착 대기', '하방 휩소 판단에 따른 레버리지 추가 매수', '추세와 무관한 숏 포지션 구축 후 관망']::text[], 1, '상승 평행 채널에서 미드라인(Mid-line)은 매우 중요한 심리적 지지와 저항선입니다. 미드라인이 저항선으로 뒤바뀌어 음봉으로 흘러내리는 경우 높은 확률로 채널 하단 경계선까지 가격이 조정을 받게 되므로, 중심선 저항 확인 시점에서는 섣부른 매수 진입을 피하고 채널 하단의 명확한 반등 타점을 유도해야 합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (644, '추세/레짐', '03_market_structure.md', '저점과 저점을 이은 장기 상승 추세선 상의 3번째 터치 포인트(지지선 부근)에 캔들이 매우 조심스럽게 안착하며 아래꼬리를 형성했습니다. 손익비(Risk-to-Reward) 관점에서 가장 이상적인 매수 타점 집행 및 손절 셋업 방법은 무엇입니까?', '[{"time":"Day 1","open":800,"high":900,"low":800,"close":880,"volume":95},{"time":"Day 2","open":880,"high":990,"low":880,"close":950,"volume":102},{"time":"Day 3","open":950,"high":960,"low":900,"close":920,"volume":102}]'::jsonb, '[{"type":"line","points":[{"x":0,"y":800},{"x":1,"y":880},{"x":2,"y":900}],"label":"상승 추세선 (3rd Touch 기대선)","color":"#10b981"}]'::jsonb, ARRAY['손절 라인 없이 지정가로 1차 매수 몰빵 진입', '3rd Touch 타점 진입 및 추세선 하단 칼손절 셋업', '하방 붕괴 예상을 통한 고배율 숏 즉각 진입', '목표가 터치 시까지 무작정 대기 후 추격 매수']::text[], 1, '추세선 상의 3번째 지지 포인트(3rd Touch)는 추세 신뢰도가 형성되는 대단히 성공률 높은 정석적 눌림목 타점입니다. 진입 가격과 손절 라인(추세선 이탈가)의 거리가 매우 가깝기 때문에 기대 수익 대비 잃을 금액이 매우 적어 프로 트레이더들이 가장 선호하는 칼손절 매수 스팟입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (645, '추세/레짐', '08_setup_entry_exit.md', '나스닥 시세가 장기 하락 추세선을 힘차게 뚫어 상방 돌파(Breakout)했습니다. 하지만 돌파선 바로 위(약 1,200달러)에 최근 여러 번 강한 매도 잔량이 쏟아지며 가격을 찍어 눌렀던 핵심 매물대 저항선이 떡하니 버티고 있습니다. 당신의 신규 진입 매수 순서는 어떻게 결정해야 안전할까요?', '[{"time":"Day 1","open":1250,"high":1260,"low":1100,"close":1120,"volume":96},{"time":"Day 2","open":1120,"high":1130,"low":980,"close":1000,"volume":114},{"time":"Day 3","open":1000,"high":1190,"low":990,"close":1180,"volume":89}]'::jsonb, '[{"type":"line","points":[{"x":0,"y":1250},{"x":1,"y":1120},{"x":2,"y":1050}],"label":"하락 추세선 (돌파됨)","color":"#ef4444"},{"type":"horizontal-line","points":[{"x":0,"y":1200}],"label":"수평 매물대 저항선 (120)","color":"#ef4444"}]'::jsonb, ARRAY['돌파 확인 즉시 종가 기준 시장가 100% 매수', '수평 저항 돌파 검증 시까지 매수 유보 및 대기', '돌파 전조 현상 기대로 레버리지 선배팅 집행', '추세선 돌파를 가짜로 간주한 숏 포지션 진입']::text[], 1, '하락 추세선의 돌파는 긍정적이나 수평 매물대 저항선이 바로 위에 있다면 이중 저항 작용에 의해 막히는 경우가 대단히 잦습니다. 추세선 상방 휩소(속임수)에 당하지 않으려면 겹저항 중 최종 관문인 수평 매물대 저항선 돌파 혹은 리테스트 지지를 확인하고 진입하는 것이 보수적이고 안전한 원칙입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (646, '패턴/돌파', '04_patterns_breakout.md', '고점 수평 저항선(1,000달러)과 저점 상승 지지선으로 이루어진 어센딩 트라이앵글 수렴 도중, 1,000달러를 돌파할 것을 미리 예측하고 980달러에서 비중 100% 매수로 진입했습니다. 그러나 나스닥 시세는 돌파에 실패하고 하방 상승 지지선을 대량 거래량 장대음봉으로 뚫어 920달러로 하향 마감했습니다. 올바른 매매 액션은?', '[{"time":"Day 1","open":800,"high":1000,"low":800,"close":950,"volume":117},{"time":"Day 2","open":950,"high":1000,"low":880,"close":970,"volume":105},{"time":"Day 3","open":970,"high":980,"low":910,"close":920,"volume":106}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":1000}],"label":"수평 저항선 (100)","color":"#ef4444"},{"type":"line","points":[{"x":0,"y":800},{"x":1,"y":880},{"x":2,"y":940}],"label":"상승 지지선 (붕괴)","color":"#10b981"}]'::jsonb, ARRAY['하방 이탈 확인 즉시 손절하여 추가 폭락 차단', '조정을 이용해 평단가를 조절하는 분할 물타기', '본전 탈출 시까지 포지션을 유지하며 관망', '손절 라인을 하단으로 조정하고 대기 주문 유지']::text[], 0, '어센딩 트라이앵글은 상방 확률이 다소 높지만, 하단 지지선이 뚫려 무너지는 순간 패턴 실패와 함께 엄청난 실망 매도 매물이 출하됩니다. 특히 돌파를 미리 예견해 들어간 포지션은 즉시 룰 위반을 시정하고 손절(920달러)해야 큰 자산 보호를 할 수 있습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (647, '패턴/돌파', '04_patterns_breakout.md', '하락 바닥권에서 왼쪽 어깨, 머리, 오른쪽 어깨를 그리며 역헤드앤숄더(Inverse Head & Shoulders) 패턴이 완성되었습니다. 가격이 넥라인 저항벽(800달러선)을 돌파했으나 이미 장대양봉으로 높이 솟아(870달러) 추격 매수 타이밍을 아쉽게 놓쳤습니다. 이때 뇌동매매를 피하는 가장 현명한 매수 타점 공략법은?', '[{"time":"Day 1","open":950,"high":950,"low":700,"close":780,"volume":83},{"time":"Day 2","open":780,"high":820,"low":600,"close":750,"volume":104},{"time":"Day 3","open":750,"high":790,"low":680,"close":760,"volume":114},{"time":"Day 4","open":760,"high":880,"low":750,"close":870,"volume":120}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":800}],"label":"넥라인 저항선 (80)","color":"#ef4444"}]'::jsonb, ARRAY['포모(FOMO) 현상에 따른 돌파봉 꼭대기 추격 매수', '돌파 넥라인 부근의 리테스트 조정 눌림목 매수', '반등 랠리 종결 판단에 따른 역베팅 숏 포지션', '추세 전환 확인 후 무조건적인 관심종목 제외']::text[], 1, '강한 패턴 돌파봉 확인 후 뇌동매매로 추격하는 것은 손절 거리가 너무 멀어져 손익비가 최악인 나쁜 습관입니다. 정석 돌파 트레이더는 넥라인 역할 전환 지점(800달러)으로의 되돌림 눌림목(Retest)을 차분히 기다려 리스크를 짧게 끊고 들어가는 훈련을 해야 합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (648, '패턴/돌파', '04_patterns_breakout.md', '지속적인 하락 추세 중, 고점과 저점이 수렴하며 우하향하는 하락 쐐기형(Falling Wedge) 패턴의 끝자락에 도달했습니다. 거래량이 급감하다가 마침내 쐐기형 상단 저항선을 상방으로 뚫는 강한 양봉 종가 마감(1,100달러)이 포착되었습니다. 합리적인 매수 진입 시 손절가 설정 기준은 무엇인가요?', '[{"time":"Day 1","open":1300,"high":1320,"low":1100,"close":1120,"volume":97},{"time":"Day 2","open":1120,"high":1160,"low":1020,"close":1040,"volume":123},{"time":"Day 3","open":1040,"high":1080,"low":980,"close":1000,"volume":104},{"time":"Day 4","open":1000,"high":1120,"low":990,"close":1100,"volume":118}]'::jsonb, '[]'::jsonb, ARRAY['손절 없이 청산가에 의존하여 장기 홀딩', '상방 돌파 확인 후 진입 및 직전 최저점 손절 셋업', '평단가 개선을 위한 지속적인 분할 물타기 매수', '상단 저항선 돌파 시점을 이용한 숏 포지션 스위칭']::text[], 1, '하락 쐐기형(Falling Wedge)의 상방 돌파는 강력한 반전 신호입니다. 이 패턴의 장점은 진입 즉시 명확하고 짧은 기준점(수렴 바닥 최저가 980달러 혹은 돌파봉 하단)을 손절가로 설정할 수 있어, 리스크 한도를 안전하게 통제한 채 상방 랠리를 도모할 수 있다는 점입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (649, '패턴/돌파', '04_patterns_breakout.md', '나스닥 시세가 약한 매수세와 거래량 급감 속에 고점과 저점을 높이며 좁게 상승 쐐기형(Rising Wedge)을 그리고 있습니다. 현재 가격은 상승 쐐기형 하단 지지선(3,000달러)에 아주 밀착하여 붕괴 위기에 놓여 있습니다. 이 시점에서 롱(매수) 포지션을 들고 있는 트레이더의 리스크 대응은?', '[{"time":"Day 1","open":2600,"high":2800,"low":2600,"close":2780,"volume":94},{"time":"Day 2","open":2780,"high":2950,"low":2720,"close":2900,"volume":16},{"time":"Day 3","open":2900,"high":3050,"low":2980,"close":3010,"volume":28}]'::jsonb, '[{"type":"line","points":[{"x":0,"y":2600},{"x":1,"y":2720},{"x":2,"y":2980}],"label":"쐐기 하단 지지선 (300)","color":"#ef4444"}]'::jsonb, ARRAY['상승 쐐기형 하방 이탈 위험에 따른 롱 포지션 매도', '상승 지속 확신에 따른 레버리지 추가 불타기', '장기 상승 흐름 기대로 손절 없이 무기한 홀딩', '다른 종목으로의 포지션 분산을 위한 관망']::text[], 0, '상승 쐐기형(Rising Wedge)은 약세 세력이 억지로 쥐어짜며 상승 가격을 만드는 패턴으로, 수렴 끝에서 거래량 소멸과 함께 하방 이탈(Breakdown)하여 폭락할 위험이 매우 높은 대표적인 하락 대비 패턴입니다. 하단 지지선 이탈 낌새 시에는 매수 포지션을 전부 도망쳐 나와야 큰 손실을 막을 수 있습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (650, '패턴/돌파', '04_patterns_breakout.md', '둥근 대야 모양의 바닥(Cup)을 그리며 상승 회복한 나스닥 시세가 전고점 저항벽 부근에서 하향 채널식 완만한 되돌림 조정 핸들(Handle)을 그리는 중입니다. 이후 핸들의 상단 저항선(1,500달러선)을 강한 거래량의 장대양봉으로 상향 돌파했습니다. 이때 합리적인 트레이더의 대응은?', '[{"time":"Day 1","open":1400,"high":1420,"low":1280,"close":1300,"volume":86},{"time":"Day 2","open":1300,"high":1400,"low":1290,"close":1380,"volume":109},{"time":"Day 3","open":1380,"high":1400,"low":1340,"close":1350,"volume":95},{"time":"Day 4","open":1350,"high":1540,"low":1340,"close":1520,"volume":110}]'::jsonb, '[]'::jsonb, ARRAY['핸들 상방 돌파 확인 후 진입 및 핸들 저점 손절', '하락 지속 판단에 따른 즉각적인 전량 손절', '평단가 부근이므로 추가 손절 설정 없이 관망', '돌파 여부 확인 전 고점 돌파 매수 주문 100%']::text[], 0, '전형적인 강세 지속 패턴인 컵앤핸들(Cup & Handle)입니다. 핸들의 하락 조정 채널 상단 돌파는 매물 소화를 성공적으로 완수하고 본 랠리로 진입한다는 강력한 신호입니다. 손익비 관점에서 핸들의 지지 저점인 1,340달러 아래에 안전 손절을 지정한 뒤 진입 시 우수한 기대 수익을 가질 수 있습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (651, '지표/컨플루언스', '06_technical_indicators.md', '강력한 대세 상승 국면인 종목이 일시 조정을 거쳐 전저점 지지 영역(1,000달러)에 도달해 저점을 지키고 있습니다(저점 높임 또는 수평). 그런데 이때 보조지표 RSI의 저점은 이전보다 훨씬 깊게 파여 낮아지는 ''히든 상승 다이버전스(Hidden Bullish Divergence)''가 포착되었습니다. 현명한 의사결정은?', '[{"time":"Day 1","open":900,"high":1100,"low":880,"close":1050,"volume":89},{"time":"Day 2","open":1050,"high":1070,"low":980,"close":1000,"volume":111}]'::jsonb, '[]'::jsonb, ARRAY['하락 전환 신호로 판단하여 전량 즉시 손절', '추세 지속 신호 기대로 지선 부근 추가/신규 매수', '지표 과매수 판단에 따른 계좌 거래 정지', '손절 설정 없이 무제한 레버리지 롱 대응']::text[], 1, '나스닥 시세의 저점은 높아지는데 보조지표(RSI 등)의 저점은 낮아지는 형태는 ''히든 상승 다이버전스''입니다. 이는 기존의 강력한 상승 트렌드 내부에서 일시 조정을 겪는 매수자들이 활기차게 물량을 주워 담아 다음 상승 랠리를 추진한다는 신호이므로, 짧은 손절 라인(980달러)을 설정하고 매수 비중을 태우기 가장 적합한 정석 타점입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (652, '지표/컨플루언스', '07_multitimeframe_regime.md', '나스닥 시세가 호재와 함께 밴드 상단선 바깥을 타고 계속 상승하는 강력한 볼린저 밴드 밴드워크(Band Walk) 현상이 발생 중이며, RSI는 80을 넘어 극단적 과매수 수치를 가리키고 있습니다. 이 구간에서 취해야 할 가장 합리적인 리스크 및 포지션 관리 행동은?', '[{"time":"Day 1","open":1000,"high":1150,"low":990,"close":1120,"volume":91},{"time":"Day 2","open":1120,"high":1280,"low":1100,"close":1250,"volume":87},{"time":"Day 3","open":1250,"high":1390,"low":1220,"close":1360,"volume":120}]'::jsonb, '[]'::jsonb, ARRAY['과매수 도달 판단에 따른 고배율 숏 무리한 진입', '추종 손절매(Trailing Stop)를 통한 수익 극대화', '상승폭 만족에 따른 즉각적인 전량 시장가 익절', '손절 가격을 해제하고 시세 지속 시까지 방치']::text[], 1, '강세 추세가 지나치게 강할 경우 볼린저 밴드 상단을 타고 오르는 밴드워크 현상과 RSI 과매수 현상이 영구 유지될 수 있습니다. 이때 단순 과매수 수치를 이유로 숏 포지션을 잡으면 파산합니다. 기존 매수 포지션의 익절선(Trailing Stop)을 상향 관리하여 추세 상승 이익을 극대화하고 신규 진입은 자제하는 것이 정석 리스크 관리입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (653, '지표/컨플루언스', '06_technical_indicators.md', '1시간 봉 차트 상에서 나스닥 시세가 확실히 낮아졌으나 RSI 저점은 유의미하게 상승한 ''상승 다이버전스''가 확인되어 매수 타점을 노리고 있습니다. 다만 15분 봉 단기 차트에서는 하락 장대음봉 관성이 아직 살아있어 매도 압력이 보입니다. 멀티 타임프레임 트레이더의 진입 의사결정은?', '[{"time":"Hour 1","open":1000,"high":1020,"low":900,"close":910,"volume":83},{"time":"Hour 2","open":910,"high":920,"low":800,"close":820,"volume":113}]'::jsonb, '[]'::jsonb, ARRAY['단기 음봉 관성 기대로 즉각 숏 포지션 진입', '큰 시간 프레임의 상승 다이버전스 타점 매수', '지표 충돌로 판단하고 시장가 즉시 롱 진입', '변동성 기대로 무작정 도박성 잡코인 진입']::text[], 1, '큰 프레임(1시간 봉)의 다이버전스가 주는 중장기 추세 신뢰도는 작은 프레임의 단기 노이즈보다 압도적으로 강력합니다. 단, 진입 시 타이밍의 정밀도를 높이기 위해 소파동(15분 봉)의 하락 동력이 꺾이고 지지해 주는 단기 확인 캔들이 나오는 찰나에 롱 포지션 타이밍을 잡는 것이 멀티 타임프레임 정석 매매입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (654, '지표/컨플루언스', '06_technical_indicators.md', '나스닥 시세는 2,000달러 저항대를 뚫고 2,200달러까지 계속 우상향하며 고점을 갱신하고 있으나, MACD 오실레이터의 히스토그램 산 높이는 직전 고점 시점 대비 현저하게 쪼그라들며 꺾여 내려가 하락 다이버전스를 형성 중입니다. 현명한 포지션 보유자의 이익 관리 행동은?', '[{"time":"Day 1","open":1800,"high":2050,"low":1790,"close":2000,"volume":114},{"time":"Day 2","open":2000,"high":2220,"low":1980,"close":2200,"volume":105}]'::jsonb, '[]'::jsonb, ARRAY['추세 지속 확신으로 보유 비중 추가 불타기', '상승 모멘텀 약화 다이버전스 확인 후 50% 익절', '익절 설정 없이 전고점 도달 시까지 홀딩', '고점 붕괴 기대로 숏 포지션 10배 베팅']::text[], 1, '나스닥 시세는 올라가나 모멘텀 지표인 MACD 오실레이터 고점이 낮아지는 현상은 대표적인 하락 다이버전스로, 매수 에너지가 속 빈 강정처럼 쇠퇴하고 있어 언제든 급격한 폭락 조정이 발생할 수 있는 고위험 신호입니다. 이 시점에는 탐욕을 통제하고 물량의 50% 이상을 분할 매도하여 현금을 챙기는 것이 원칙입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (655, '지표/컨플루언스', '06_technical_indicators.md', '나스닥 시세가 하락 횡보하던 도중, 단기 지평선인 EMA 20일선이 중장기선인 EMA 50일선에 극도로 밀착하며 수렴했습니다. 당일 대량 거래량의 음봉 캔들이 터지며 단기선이 장기선 아래로 교차하기 직전(데드크로스 임박)이며 주요 지지선 밑으로 떨어졌습니다. 롱(매수) 포지션 보유자의 올바른 대응은?', '[{"time":"Day 1","open":1050,"high":1060,"low":990,"close":1000,"volume":86},{"time":"Day 2","open":1000,"high":1010,"low":950,"close":960,"volume":108}]'::jsonb, '[]'::jsonb, ARRAY['지지선 이탈 및 데드크로스 확인 즉시 손절', '이평선 지지력을 믿고 하방 물타기 추가 매수', '하락 조정 후 반등 기대로 무기한 홀딩 관망', '청산가 도달 시까지 어떠한 대응 없이 방치']::text[], 0, '20일선과 50일선의 데드크로스 임박 수렴 상태에서 가격이 지지선마저 무너뜨린 것은 하락 가속화 추세가 폭발하기 직전인 매우 위험한 기술적 상태입니다. 하락 추세가 본격 정배열(하락 정배열)화 되기 전에 즉시 전량 손절하고 시장 밖에서 피신해 있는 것이 계좌의 영구 파산을 막는 유일한 생존 규칙입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (656, '리스크/심리', '09_risk_position_management.md', '지수 선물 매수 후 가격이 급락하여 내가 설정해 둔 최대 감내 손실 한도인 계좌 총원금 대비 -2% 라인(손절매 지정 가격)에 완벽하게 닿았습니다. 마침 본전 생각과 함께 ''조금만 더 버티면 반등할 텐데...''하는 강한 뇌동매매 유혹이 솟구칩니다. 이때 원칙 트레이더의 결정은?', '[{"time":"Day 1","open":1000,"high":1020,"low":990,"close":1000,"volume":113},{"time":"Day 2","open":1000,"high":1010,"low":940,"close":950,"volume":107}]'::jsonb, '[]'::jsonb, ARRAY['손절 라인을 임의로 하향 조정하고 홀딩', '평단가 관리 차원의 지속적 물타기 매수 집행', '원칙에 따라 뇌동을 제어하고 즉시 기계적 손절', '손실은 배제하고 반등 기대를 통한 무기한 보유']::text[], 2, '트레이딩의 승패는 예측이 아닌 ''리스크 통제''에 달려 있습니다. 사전에 정한 계좌 대비 2% 리스크 한도에 도달했을 때 희망 회로를 돌리며 손절을 미루거나 물타기를 집행하는 순간 계좌는 서서히 영으로 깎여 파산합니다. 멘탈의 충동을 통제하고 기계적으로 전량 칼손절하는 것이 절대 파산하지 않는 시장의 1법칙입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (657, '리스크/심리', '10_psychology_routine_review.md', '최근 3회 연속 거래에서 계속해서 손절(Stop Loss)을 맞아 뇌 내의 도파민 체계가 무너지고 심리가 극도로 불안해져 분노와 보복 매매 충동이 밀려옵니다. 이 상황에서 파산을 막는 가장 훌륭한 매매 심리 대처법은?', '[{"time":"Today","open":1000,"high":1000,"low":1000,"close":1000}]'::jsonb, '[]'::jsonb, ARRAY['손실 복구를 위해 레버리지를 증액해 즉시 진입', '뇌동 방지를 위해 HTS를 종료하고 매매 일지 작성 및 휴식', '추천 매매 신호 유료 리딩방에 즉시 가입 및 추종', '심리적 회복을 위해 역베팅 숏 포지션 추가']::text[], 1, '연속 손실 후 발생하는 복수심과 분노는 트레이더를 뇌동매매와 계좌 파멸로 이끄는 가장 치명적인 감정 상태입니다. 멘탈 붕괴를 느꼈을 때는 즉각 행동을 멈추고 시스템을 강제 종료하여 시장과 물리적 격리를 통해 냉정을 찾는 것만이 자산을 파산 리스크로부터 살려내는 훌륭한 트레이딩 행동입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (658, '셋업/실행', '09_risk_position_management.md', '진입하고자 하는 매수 자리를 분석해 보니, 기술적 분석 상 이길 수 있는 확률(승률)은 반반인 50% 수준입니다. 그러나 손절 시 기대 손실금액 대비 성공 시 획득할 수 있는 기대 수익금액의 비율(손익비)을 정밀 셋업 해보니 1 : 1.2 수준으로 다소 애매하게 도출되었습니다. 원칙 트레이더의 진입 결정은?', '[{"time":"Today","open":1000,"high":1000,"low":1000,"close":1000}]'::jsonb, '[]'::jsonb, ARRAY['단기 변동성 기대로 부적합한 손익비 시장가 진입', '마이너스 기댓값 거래 유보 및 우수 타점 대기', '레버리지를 높여 손익비 구조를 임의 조정 시도', '반대 방향으로 고배율 역베팅을 즉시 실행']::text[], 1, '수학적으로 승률 50%일 때 손익비가 최소 1:2(잃을 때 1, 벌 때 2) 이상이 나오지 않으면 복리 매매 시 수수료와 호가 슬리피지에 밀려 잔고가 무조건 마이너스로 수렴합니다. 타점이 눈에 들어오더라도 사전에 기대 손익비 필터에 걸려 탈락한다면 패스를 선언하고 관망하는 것이 현명한 생존 원칙입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (659, '리스크/심리', '09_risk_position_management.md', '갑작스러운 거시 경제 발표로 내가 매매 중인 종목의 캔들 변동성 폭(ATR)이 평소 시세의 2배 수준으로 널뛰기 시작했습니다. 1회 거래당 내 계좌 원금의 최대 2% 리스크 한도를 동일하게 고수하기 위해 취해야 할 올바른 조치는?', '[{"time":"Day 1","open":1000,"high":1020,"low":980,"close":1000,"volume":102},{"time":"Day 2","open":1000,"high":1100,"low":900,"close":1020,"volume":120}]'::jsonb, '[]'::jsonb, ARRAY['평소 변동성과 동일한 비중 및 손절 거리 고수', '손절 거리를 넓히는 대신 진입 포지션 수량 축소', '변동성이 확대되었으므로 2배 비중으로 적극 지름', '즉시 전량 손절하고 시장 상황 정상화 대기']::text[], 1, '시장 변동성이 커질 때는 손절 스톱 아웃이 잦으므로 손절폭(%)을 넓혀 숨 쉴 공간을 확보해 주는 것이 합리적입니다. 단, 손절폭을 2배로 늘린다면 계좌 대비 리스크 한도가 2배(4%)로 커지므로, 진입 포지션의 계약 수량을 50%로 줄여 리스크 노출 총액을 2%로 완벽하게 동일 통제하는 것이 포지션 사이징(Position Sizing)의 정석 원칙입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (660, '리스크/심리', '09_risk_position_management.md', '투자자 A의 전체 투자 원금은 5,000만 원이며, 1회 거래당 최대 허용 리스크 금액은 원금의 2%인 100만 원입니다. 현재 나스닥 시세가 100,000원이며, 기술적 분석 상 합리적인 손절선은 지지선 바로 밑인 95,000원(-5%)입니다. 2% 룰 리스크 관리 원칙에 따라 A가 진입(매수)해야 하는 최대 지수 선물 수량은?', '[{"time":"Today","open":100000,"high":100000,"low":100000,"close":100000}]'::jsonb, '[]'::jsonb, ARRAY['500주 (투자금 전액 시장가 매수)', '200주 (손실 한도 100만 원 맞춤 매수)', '50주 (보수적 극단적 비중 축소)', '100주 (절반 비중 고정 매수)']::text[], 1, '포지션 크기 계산 공식은 `최대 매수 규모 = 최대 허용 리스크 금액 / 손절매 비율` 입니다. 이 시나리오에서 `1,000,000원 / 0.05(5%) = 20,000,000원`이 최대 허용 진입금액이 되며, 이를 나스닥 시세 100,000원으로 나누면 `200주`가 도출됩니다. 200주 진입 후 -5% 가격 폭락으로 손절 당해도 내 총원금에서 깎이는 돈은 정확히 100만 원(2%)으로 완벽히 리스크 통제됩니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (661, '거래량/유동성', '05_volume_liquidity.md', '나스닥 시세가 수평 저항선 부근까지 급상승했으나 캔들 몸통(Spread)이 지극히 좁아진 도지 형태로 마감하였고, 거래량은 이전 5일 평균 대비 3배 이상 폭증했습니다. VSA(Volume Spread Analysis) 관점에서 가장 타당한 차트 분석은?', '[{"time":"Day 1","open":1000,"high":1050,"low":990,"close":1040,"volume":113},{"time":"Day 2","open":1040,"high":1090,"low":1030,"close":1080,"volume":118},{"time":"Day 3","open":1080,"high":1100,"low":1070,"close":1080,"volume":100}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":1090},{"x":2,"y":1090}],"label":"저항선","color":"#ef4444"}]'::jsonb, ARRAY['강한 매수 기세 기대로 즉시 돌파 매매 풀매수', '저항벽 매도 공급 세력 분산 확인 후 이익 실현', '대량 거래 확인에 따른 손절 해제 후 장기 투자', '반등 실패에 따른 고배율 보복 숏 베팅 가동']::text[], 1, '캔들 몸통 크기(스프레드)가 좁은데 거래량이 매우 크게 폭증했다는 것은 저항선 부근에서 들어오는 매수세만큼 세력의 매도 물량 공급이 쏟아져 막강한 저항 벽을 형성하고 있다는 뜻입니다. VSA에서는 이를 불화(Disharmony)로 규정하며 상승 추세 감속 및 하락 반전의 경고로 해독합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (662, '거래량/유동성', '05_volume_liquidity.md', '나스닥 시세가 장기 횡보하던 박스권 지지선인 2,000달러를 깨고 1,950달러까지 하락 투매가 발생했으나, 종가 마감 직전 거래량이 크게 실린 긴 아래꼬리를 그리며 다시 2,010달러 위로 복귀 안착했습니다. 이 스톱 헌팅 유동성 현상에서의 실전 트레이더의 대응은?', '[{"time":"Day 1","open":2100,"high":2120,"low":2000,"close":2020,"volume":85},{"time":"Day 2","open":2020,"high":2040,"low":1950,"close":2010,"volume":96}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":2000},{"x":1,"y":2000}],"label":"지지선","color":"#10b981"}]'::jsonb, ARRAY['지지선 붕괴 확정으로 간주한 시장가 숏 추격', '스윕(sweep) 판단 하에 아래꼬리 저점 손절 잡고 롱', '아무런 신호도 아니라고 판단하고 포지션 방치', '지지선 이탈 기대로 전량 손절 후 시장 영구 탈출']::text[], 1, '지지선 아래에 걸려 있던 개인들의 손절 주문(Sell Stop)을 강제로 청산(Liquidity Sweep)시킨 뒤, 세력이 물량을 헐값에 다 받아 삼켜 종가를 지지선 위로 신속하게 복귀시킨 휩소(베어 트랩) 패턴입니다. 아래꼬리 극점(1,950달러)에 아주 좁은 손절 라인을 설정할 수 있어, 기대 손익비가 극대화되는 고확률 상승 반전 매수 타점입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (663, '거래량/유동성', '05_volume_liquidity.md', '나스닥 시세는 2,500달러에서 2,900달러까지 계속 고점을 높이며 상승 추세를 이어가고 있습니다. 그러나 각 상승 파동마다 터지는 거래량은 전고점 돌파 시점 대비 눈에 띄게 하향 곡선을 그리며 감소하고 있습니다. VSA 기법에 따른 합리적인 진단은?', '[{"time":"Wave 1","open":2300,"high":2600,"low":2280,"close":2550,"volume":82},{"time":"Wave 2","open":2550,"high":2750,"low":2500,"close":2700,"volume":106},{"time":"Wave 3","open":2700,"high":2900,"low":2650,"close":2880,"volume":104}]'::jsonb, '[]'::jsonb, ARRAY['가격 상승으로 인한 매수 지속 강화 초강세', '매도 물량 고갈에 따른 무중력 안심 홀딩', '신규 자금 유입 둔화 거래량 다이버전스로 분할 익절', '지표 조작으로 판단하여 매매 중단 및 차트 종료']::text[], 2, '나스닥 시세는 상승하여 신고점을 갱신하지만 파동별 거래량이 지속 감소하는 흐름은 ''거래량 다이버전스''로 상승 모멘텀의 내부 엔진이 식어감을 경고합니다. 조만간 가벼운 매도 포격에도 대규모의 차익 실현 폭락 조정이 발생할 수 있는 잠재적 폭락 국면이므로 물량을 덜어내고 현금을 확보해야 합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (664, '거래량/유동성', '05_volume_liquidity.md', '가격이 이전 고점 저항선을 뚫고 강하게 솟구치며 장대양봉을 만들었습니다. 이때 가짜 이탈(Whipsaw / Bull Trap)이 아닌 진성 돌파(True Breakout)로 판정할 수 있는 가장 신뢰도 높은 거래량 기준은?', '[{"time":"Day 1","open":1000,"high":1020,"low":990,"close":1000,"volume":362},{"time":"Day 2","open":1000,"high":1120,"low":990,"close":1100,"volume":401}]'::jsonb, '[]'::jsonb, ARRAY['수렴 끝자락에서 거래량이 최저치인 상태 유지', '평균 대비 1.5~2배 이상 거래량 급증하며 돌파 마감', '거래량이 전혀 변하지 않는 평이한 상태 유지', '호가 스프레드가 가장 좁아지는 횡보 상태']::text[], 1, '참된 저항 돌파(True Breakout)는 저항선 부근의 두터운 대기 매도 공급 물량을 대규모 자금으로 전부 씹어 삼키고 돌파해야 함을 뜻합니다. 따라서 반드시 평균 대비 1.5배~2배 이상의 거래량 분출이 동반되어야 신뢰할 수 있으며, 거래량이 적은 돌파는 꼬리 달고 내려앉는 불 트랩(Bull Trap)일 확률이 매우 높습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (665, '거래량/유동성', '05_volume_liquidity.md', '나스닥 지수 차트에서 중요 지지선 직전 저점 아래에 엄청난 규모의 롱 포지션 청산 및 매도 손절 주문이 쌓여 있는 유동성 풀(Liquidity Pool) 구간이 감지되었습니다. 세력이 이 구간을 공략할 때 나타날 캔들의 전형적인 무빙 패턴은?', '[{"time":"Day 1","open":500000,"high":505000,"low":492000,"close":495000,"volume":33},{"time":"Day 2","open":495000,"high":498000,"low":480000,"close":496000,"volume":20}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":492000},{"x":1,"y":492000}],"label":"전저점 지지선","color":"#3b82f6"}]'::jsonb, ARRAY['지지선을 장대음봉으로 돌파하여 20% 폭락 마감', '전저점 이탈로 손절 유도 후 지지선 위 아래꼬리 안착', '오차 없이 지지선 터치 후 꼬리 없는 수평 도지 횡보', '거래량 없이 즉각 상승 빔 분출로 전고점 탈환']::text[], 1, '기관 세력(스마트 머니)은 대량 포지션을 구축하기 위해 개인의 손절 주문(Sell Stop)을 의도적으로 터트려 매도 유동성을 유도한 후 이를 다 매수합니다. 이로 인해 나스닥 시세는 지지선 아래로 일시 급락 후(스톱 헌팅), 아래꼬리를 매우 길게 달며 지선 안쪽으로 급반등 마감하게 됩니다. 이것이 유동성 스윕(Liquidity Sweep)의 정석 패턴입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (666, '거래량/유동성', '05_volume_liquidity.md', '상승 추세 도중 전고점 저항선 부근에서 위꼬리가 아주 긴 캔들이 터졌고, 거래량은 최근 보름 중 최고 수치로 솟구쳤습니다. VSA 관점에서 이 상승 거절(Upside Rejection) 현상에 대한 올바른 대처는?', '[{"time":"Day 1","open":1000,"high":1150,"low":980,"close":1010}]'::jsonb, '[]'::jsonb, ARRAY['강한 저점 매수 기회로 인지하여 비중 대폭 추가', '고점 매도 Rejection 확인 후 기존 롱 포지션 대피', '박스 횡보 수렴 기대로 마틴게일 추가 매수 가동', '이평선 정배열 판단에 따른 포지션 변경 없이 홀딩']::text[], 1, '위꼬리가 매우 긴 캔들이 대량 거래량과 함께 터졌다는 것은 고점 돌파 시도가 있었으나 그 자리에 숨어 있던 세력의 막강한 청산 매도 벽(Supply)을 만나 격렬하게 두들겨 맞고 밀려났음을 의미합니다. 상방 거절의 심리가 지배적이므로 고점 피로 및 하락 전환이 임박한 위험 징후입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (667, '지표/컨플루언스', '06_technical_indicators.md', '나스닥 시세가 장기 박스권 횡보를 이어가며 볼린저 밴드의 폭이 최근 몇 달 중 가장 좁은 형태로 밀착 수렴(Squeeze)되었습니다. 이 스퀴즈 국면에 대한 올바른 기술적 이해와 매매 시나리오는?', '[{"time":"Week 1","open":1000,"high":1030,"low":970,"close":1010,"volume":86},{"time":"Week 2","open":1010,"high":1020,"low":990,"close":1000,"volume":116}]'::jsonb, '[]'::jsonb, ARRAY['박스권 변동성 부재 기대로 장기 무대응 관망', '에너지 수축 스퀴즈 확인 후 밴드 이탈 돌파 대기', '지표 신뢰 불가 판단으로 볼린저 밴드 지표 삭제', '중심선 지지로 판단하여 고배율 매수 대기 주문']::text[], 1, '볼린저 밴드의 폭이 극도로 좁아지는 스퀴즈(Squeeze) 현상은 시장의 표준편차 변동성이 임계치까지 압축 수렴되었음을 알려줍니다. 에너지 압축 뒤에는 항상 폭발적인 가격 분출(상방/하방 이탈)이 뒤따르므로, 밴드를 뚫고 거래량이 실려 돌파 마감하는 방향으로 추세 추종 시나리오를 설계해야 합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (668, '지표/컨플루언스', '06_technical_indicators.md', '나스닥 시세는 HL(Higher Low)을 형성하며 이전 직전 저점(900달러)보다 높은 저점(950달러)을 지키고 있으나, RSI 지표는 이전 35 수치보다 더 깊숙하게 25 수치까지 떨어졌습니다. 이 지표 불일치 현상의 공식 명칭과 올바른 포지션 셋업은?', '[{"time":"Day 1","open":1000,"high":1020,"low":900,"close":910,"volume":110},{"time":"Day 2","open":910,"high":960,"low":950,"close":950,"volume":97}]'::jsonb, '[]'::jsonb, ARRAY['일반 상승 다이버전스 - 추세 종결로 즉각 공매도', '히든 상승 다이버전스 - 지선 눌림목 롱 진입 활용', '일반 하락 다이버전스 - 모든 매수 포지션 정리', '지표 오작동 휩소 구간 판단으로 양방향 관망']::text[], 1, '가격의 저점은 높아졌는데(Higher Low) 모멘텀 지표의 저점은 낮아지는 현상은 ''히든 상승 다이버전스(Hidden Bullish Divergence)''입니다. 이는 추세 반전이 아닌 **기존 강세 추세 지속**을 뜻하며, 조정 눌림목이 완성되고 다음 상승 랠리를 준비한다는 최고의 매수 신호 중 하나입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (669, '지표/컨플루언스', '06_technical_indicators.md', '매수 타점을 신중하게 선별하고자 합니다. 기술적 분석의 성공 확률을 비약적으로 끌어올리는 ''다중 컨플루언스(Confluence)'' 결합 사례로 가장 적합한 조건 구성은?', '[{"time":"Today","open":1000,"high":1000,"low":1000,"close":1000}]'::jsonb, '[]'::jsonb, ARRAY['트위터 및 뉴스의 호재 찌라시 확인 즉시 추격', '지지선+이평선+다이버전스+아래꼬리 등 분석 중첩 시', 'RSI 과매수 영역 진입 즉시 롱 포지션 진입', '독립적 분석 없이 오직 보조지표의 단일 수치 신호']::text[], 1, '다중 컨플루언스(Confluence)는 독립적인 기술적 근거들이 동일한 특정 가격 구역에 중첩되는 현상입니다. 지지 저항, 이평선, 보조지표 다이버전스, 캔들 가격행동(Rejection 핀바)이 한 곳에 묶여 매수 자리를 형성할 때 매매를 실행하면, 높은 신뢰도와 좁은 손절 라인 덕분에 장기 기대값이 극대화됩니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (670, '셋업/실행', '08_setup_entry_exit.md', '중요 수평 저항선(1,200달러)을 상방으로 장대양봉 종가 돌파한 것을 확인하고 롱(매수) 진입 셋업을 준비하고 있습니다. 원칙 트레이더가 뇌동매매 추격을 막고 최상의 손익비를 확보하기 위해 즐겨 쓰는 정석적인 진입 실행법은?', '[{"time":"Day 1","open":1100,"high":1120,"low":1090,"close":1110,"volume":84},{"time":"Day 2","open":1110,"high":1240,"low":1100,"close":1220,"volume":94}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":1200},{"x":1,"y":1200}],"label":"저항선","color":"#ef4444"}]'::jsonb, ARRAY['돌파 마감 확인 즉시 시장가 추가 매수 집행', '돌파된 저항선의 지지 전환(Retest) 시 지정가 진입', '반등 조정이 불가능하다고 판단하여 최고점 롱 추격', '속임수 돌파 확신으로 고배율 역베팅 숏 진입']::text[], 1, '저항 돌파 후 즉시 가격을 따라붙는 추격 매수는 휩소 조정 시 심각한 손실을 초래합니다. 돌파된 라인이 S/R Flip을 통해 지지로 작용하는지 확인하는 되돌림 리테스트(Retest) 시점에 진입하는 것이, 지선 바로 아래에 좁은 손절 라인을 설계하고 이익 기대 폭을 넓힐 수 있는 가장 이상적인 정석 실행법입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (671, '셋업/실행', '08_setup_entry_exit.md', '포지션 진입 직후, 가격이 계획대로 내 방향으로 순탄하게 우상향하고 있습니다. 기존 진입 시 설정한 손익비 1:2의 최종 목표가 도달 전에, 리스크 관리 차원에서 계좌 드로다운을 0으로 만드는 정석적인 1차 포지션 관리 행동은?', '[{"time":"Entry","open":1000,"high":1000,"low":1000,"close":1000,"volume":115},{"time":"Day 1","open":1000,"high":1060,"low":1000,"close":1050,"volume":123}]'::jsonb, '[]'::jsonb, ARRAY['1차 저항대 진입 시 레버리지를 활용해 불타기', '목표가 터치 시까지 100% 비중 무대응 홀딩', '1:1 지점 50% 분할 익절 및 남은 물량 본전 손절 상향', '단기 반등 확인 즉시 전량 기계적 청산 및 퇴장']::text[], 2, '이득이 발생해 손익비 1:1 수준에 오면 물량의 절반을 분할 익절(Scale-out)하고 남은 포지션의 스톱로스를 진입가로 이동(Break-even)시키는 것이 포지션 관리의 기본입니다. 이렇게 셋업하면 차트가 갑자기 폭락세로 뒤집혀도 최소 본전 혹은 반절 익절 약수익으로 끝나 해당 거래의 최대 리스크가 Zero(0)로 봉쇄됩니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (672, '셋업/실행', '08_setup_entry_exit.md', '강력한 장기 상승 추세가 터져 나스닥 시세가 20일 이평선을 타고 계속해서 폭발적으로 신고가를 갱신하고 있습니다. 이때 익절 시점을 서둘러 잡지 않고, 추세 상승 이익을 최대한 길게 끝까지 빨아먹기 위한 정석 청산 실행법은?', '[{"time":"Day 1","open":1000,"high":1100,"low":990,"close":1080,"volume":94},{"time":"Day 2","open":1080,"high":1200,"low":1070,"close":1180,"volume":96},{"time":"Day 3","open":1180,"high":1350,"low":1170,"close":1320,"volume":89}]'::jsonb, '[]'::jsonb, ARRAY['RSI 과과열 조짐 확인 즉시 시장가 전량 익절', 'Higher Low 지지 직하방으로 손절 추종 익절 셋업', '이익 보존을 포기하고 손익절 라인을 해제 후 홀딩', '즉시 숏 포지션 10배로 맞불을 놓는다']::text[], 1, '강세 추세가 터졌을 때 지레짐작으로 청산하면 상승 파동의 초입만 먹고 끝납니다. 추세 붕괴의 명확한 신호(BOS/MSB)가 나오거나, 가격의 구조적 높은 저점(HL)이 깨질 때까지 손절 라인을 계속 추종해서 상향하는 ''추격 손절매(Trailing Stop)''를 가동하는 것이 추세 이익을 극대화하는 정석 기법입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (673, '셋업/실행', '01_chart_market_basics.md', '차트 분석 결과, 돌파 시점의 체결 변동성과 거래소 호가창의 얇은 매물 상태를 감안할 때 내가 진입하려는 주문 가격에서 체결이 뒤로 밀리는 ''슬리피지(Slippage)''가 심각하게 예상됩니다. 이를 감안한 올바른 주문 실행법은?', '[{"time":"Today","open":1000,"high":1000,"low":1000,"close":1000}]'::jsonb, '[]'::jsonb, ARRAY['시장가로 최고 배율을 설정하여 즉시 체결', '돌파 확인 후 지정가 대기 주문으로 단가 조절', '슬리피지를 예방하기 위해 즉각적인 거래 취소', '호가창 스프레드와 무관하게 고배율 레버리지']::text[], 1, '변동성이 크고 호가가 얇은 시장에서 돌파 시 시장가 진입은 나쁜 단가로 체결되는 슬리피지 비용을 발생시켜 시작부터 손실을 크게 안고 갑니다. 돌파 확인 후 되돌림 가격대에서 지정가(Limit Order)를 대기시켜 체결 단가를 내 손아귀에 고정하는 리스크 관리가 필요합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (674, '셋업/실행', '10_psychology_routine_review.md', '원칙 기반의 정석 매매 셋업(Trading Setup)을 설계할 때, 진입 전 반드시 사전에 수치로 명문화되어 결정되어야 할 요소가 아닌 것은?', '[{"time":"Today","open":1000,"high":1000,"low":1000,"close":1000}]'::jsonb, '[]'::jsonb, ARRAY['진입 조건(Trigger)과 구체적인 손절 가격(Stop Loss)', '거래 당일 본인의 주관적인 직감과 감정적 목표가', '진입하려는 구체적인 포지션 규모 및 분할 익절선', '거래 아이디어가 무효화되는 구체적 가격 지점']::text[], 1, '매매 셋업은 규칙에 기반한 수치들(진입가, 손절가, 목표가, 수량)로 사전에 철저히 규격화되어야 합니다. 당일의 운이나 주관적 느낌, 예감에 기초한 비과학적 청산 설정은 셋업에서 배제되어야 할 대표적 뇌동매매 요소입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (675, '셋업/실행', '08_setup_entry_exit.md', '하락 횡보하던 나스닥 시세가 중요 매물대이자 피보나치 되돌림 0.618 지점에 정확히 맞닿아 아래꼬리가 긴 양봉 핀바(Pin Bar)를 그리며 마감했습니다. 룰베이스 트레이더가 진입 버튼을 누를 때 성립된 IF-THEN 시나리오는?', '[{"time":"Day 1","open":1000,"high":1000,"low":800,"close":820,"volume":110},{"time":"Day 2","open":820,"high":860,"low":780,"close":850,"volume":119}]'::jsonb, '[]'::jsonb, ARRAY['익일 가격 상황과 관계없이 100배 레버리지 진입', '중첩 자리 핀바(rejection) 확인 후 익일 시가 롱 진입', '상단 저항 도달 판단으로 즉각적인 숏 포지션 진입', '돌파 랠리가 완전히 끝날 때까지 HTS 종료 및 관망']::text[], 1, '훌륭한 트레이딩 실행은 ''IF(조건 만족 시) ➔ THEN(원칙대로 포지션 진입 및 손절/목표가 기계적 배치)''의 룰베이스 알고리즘에 의해 움직여야 감정을 배제할 수 있습니다. 지지 구간 중첩과 핀바 출현 조건이 성립했으므로 다음 봉 시가에 진입하되 꼬리 저점 이탈 시 칼손절하여 리스크를 통제하는 것이 정석입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (676, '리스크/심리', '09_risk_position_management.md', '나의 트레이딩 시스템 승률이 40%로 다소 낮게 고정되어 있습니다. 이 시스템을 통해 장기적으로 파산하지 않고 복리로 계좌 자산을 우상향시키기 위해 필수적으로 지켜야 할 손익비(평균손실 대비 평균수익 비율)의 최소 기준은?', '[{"time":"Today","open":1000,"high":1000,"low":1000,"close":1000}]'::jsonb, '[]'::jsonb, ARRAY['손익비 1:1 수준 (매매 승률이 낮을 때 파산)', '승률 40% 대비 기댓값 개선을 위한 손익비 1:1.5 이상', '낮은 승률 상태에서 손익비와 무관하게 무조건 파산', '승률 극복을 위한 레버리지 20배 수준 설정']::text[], 1, '승률이 40%일 때 기대값 수학적 수수료 감안 최소 손익비는 1:1.5입니다. 손익비 1.5배 이상 구간만 취하면 10번 중 6번 손절당하고 단 4번만 익절하더라도 계좌 총합은 수익 우위에 서게 됩니다. 저승률 시스템일수록 철저히 손익비가 유리한 진입가 근처 타점만 기계적으로 필터링해 진입해야 생존합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (677, '리스크/심리', '09_risk_position_management.md', '선물 트레이더인 B는 담보금 효율을 극대화한다는 명목으로 50배 레버리지 롱 포지션 진입을 실행했습니다. 진입 가격 대비 B의 포지션 원금이 완전 소멸(강제 청산)되는 역방향 하락 거리(%)는 대략 몇 % 수준입니까?', '[{"time":"Today","open":1000,"high":1000,"low":1000,"close":1000}]'::jsonb, '[]'::jsonb, ARRAY['진입 단가 대비 20.0%의 강한 하락 발생 시', '진입 단가 대비 단 -2.0% 변동성 노이즈 터치 시', '진입 단가 대비 50.0%의 강한 폭락 발생 시', '청산가가 산출되지 않는 특이 종목 거래 시']::text[], 1, '청산 거리 계산 공식은 대략 `100% / 레버리지 배수` 입니다. 50배 고배율 레버리지의 경우, 내 포지션 반대 방향으로 단 **-2%**의 시세 변동성(장중 흔한 잔파동 노이즈)만 터치해도 원금이 100% 강제 청산 증발됩니다. 고배율 레버리지는 수학적 확률상 100% 파멸을 초래하는 도박성 거래 행위입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (678, '리스크/심리', '09_risk_position_management.md', '트레이딩 계좌 총자산이 20,000만 원인 트레이더가 있습니다. 1회 거래당 총자산의 2% 룰 원칙에 근거하여 리스크 한도(400만 원)를 설정했습니다. 진입하려는 종목의 손절가 거리가 -8%인 경우, 2% 룰을 완벽하게 충족하는 최대 진입(매수) 금액은?', '[{"time":"Today","open":1000,"high":1000,"low":1000,"close":1000}]'::jsonb, '[]'::jsonb, ARRAY['20,000만 원 전액 매수 (손절 폭을 배제한 대규모 베팅)', '5,000만 원 진입 (-8% 손절 시 리스크 한도 400만 원 충족)', '10,000만 원 진입 (손익비 1:1 기준에 맞춘 베팅)', '2,000만 원 진입 (보수적 원칙에 입각한 극단적 축소)']::text[], 1, '포지션 사이징 공식은 `진입금액 = 최대 리스크 허용액(400만 원) / 손절 비율(0.08)` 입니다. 이에 따라 `4,000,000원 / 0.08 = 50,000,000원`이 도출됩니다. 5,000만 원 규모로 매수 진입 시 가격이 급락해 -8% 손절 라인을 때려도 내 총자산에서 깎이는 금액은 정확히 원칙 한도인 400만 원(2%)으로 제한되어 계좌가 완벽히 방어됩니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (679, '리스크/심리', '10_psychology_routine_review.md', '장중에 내가 째려보며 타점을 기다리던 지수 선물이 아무런 조정도 없이 장대양봉을 그리며 갑자기 수직 폭등하기 시작하여 5% 이상 치솟았습니다. 이때 머릿속에 ''나만 두고 날아가는 것 아닌가''하는 극심한 소외감 공포(FOMO)가 솟구칩니다. 원칙 트레이더의 올바른 심리 대응은?', '[{"time":"Day 1","open":1000,"high":1020,"low":990,"close":1000,"volume":92},{"time":"Day 2","open":1000,"high":1060,"low":1000,"close":1050,"volume":118}]'::jsonb, '[]'::jsonb, ARRAY['추세 연장 판단으로 시장가 전액 추격 매수', 'FOMO 판단 하에 매수 보류 및 정석 되돌림 타점 대기', '돌파 실패 판단 하에 반대 방향 고배율 숏 베팅', '거래를 종료하고 즉각 지수 선물 시장에서 전량 탈출']::text[], 1, '나만 기회를 잃는다는 공포(FOMO)로 날아가는 장대양봉 꼭대기에서 추격 매수하는 행위는 고점 물리기를 자처하는 가장 흔한 뇌동매매 패턴입니다. 내 타점을 비껴간 상승은 내 돈이 아니라고 인정하고, 사전에 정의한 룰베이스 타점까지 냉정하게 대기하는 것이 장기 생존자의 멘탈 습관입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (680, '리스크/심리', '10_psychology_routine_review.md', '오전 거래에서 원칙을 어긴 무리한 진입으로 인해 3회 연속 스톱아웃(손절)을 당하여 당일 원금의 -6%의 큰 손실을 입었습니다. 본전 생각과 분노로 눈이 뒤집혀 비중을 올려 한 판으로 복수하려는 ''보폭 매매'' 충동이 폭발할 때, 파산을 막는 가장 강력한 멘탈 시스템 룰은?', '[{"time":"Today","open":1000,"high":1000,"low":1000,"close":1000}]'::jsonb, '[]'::jsonb, ARRAY['손실 만회를 위해 빌린 돈으로 100배 고배율 복수 베팅', '일일 손실 한도 도달에 따른 매매 강제 종료 및 격리', '주변 유료 전문가 추천 종목을 탐색해 즉각 매수', 'RSI 과매도 상태이므로 즉시 반대 숏 포지션 진입']::text[], 1, '연패를 겪은 후 홧김에 비중을 더 크게 실어 한 번에 본전을 찾으려는 보복 매매는 계좌를 하루 만에 휴지조각으로 만드는 가장 무서운 파산 유도 심리 상태입니다. 이를 막기 위해 하루 최대 손실 한도 한계선(예: 3회 손절 또는 원금의 5%)을 정해두고, 이 한계선 터치 시 즉시 차트를 종료하고 냉각기를 강제 집행하는 룰이 필수입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (701, '캔들/가격행동', '02_candlestick_price_action.md', '하락 추세 지속 도중 바닥권에서 몸통이 짧고 아래꼬리가 몸통의 2배 이상인 아래 캔들이 출현했습니다. 이 캔들의 명칭과 올바른 대응은?', '[{"time":"10:00","open":1440,"high":1464,"low":1416,"close":1428,"volume":115},{"time":"10:15","open":1428,"high":1440,"low":1356,"close":1368,"volume":85},{"time":"10:30","open":1368,"high":1380,"low":1296,"close":1308,"volume":97},{"time":"10:45","open":1308,"high":1320,"low":1212,"close":1224,"volume":130},{"time":"11:00","open":1224,"high":1236,"low":1080,"close":1212,"volume":96}]'::jsonb, '[]'::jsonb, ARRAY['역망치형 (Inverted Hammer) - 하락 경고 및 공매도 대기', '망치형 (Hammer) - 저점 지지 및 분할 매수 대기', '도지 (Doji) - 매수세와 매도세의 팽팽한 균형 및 관망', '하락 장악형 (Bearish Engulfing) - 추세 반전 및 즉시 손절']::text[], 1, '마지막 캔들은 아래꼬리가 긴 ''망치형(Hammer)'' 캔들로 하락 압력을 이겨내고 저가 매수세가 밀어 올렸음을 의미하는 대표적 상승 전환 신호입니다. 지지를 확인한 뒤 분할 매수 관점으로 대기해야 합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (702, '캔들/가격행동', '02_candlestick_price_action.md', '엔비디아 주가가 장기간 급등한 뒤, 고점 부근에서 위꼬리가 매우 길고 몸통이 짧은 형태의 캔들이 발생했습니다. 이 캔들의 해석으로 가장 적절한 것은?', '[{"time":"Day 1","open":1200,"high":1296,"low":1188,"close":1260,"volume":102},{"time":"Day 2","open":1260,"high":1380,"low":1248,"close":1344,"volume":120},{"time":"Day 3","open":1344,"high":1500,"low":1332,"close":1476,"volume":113},{"time":"Day 4","open":1476,"high":1536,"low":1440,"close":1512,"volume":92},{"time":"Day 5","open":1512,"high":1740,"low":1500,"close":1524,"volume":115}]'::jsonb, '[]'::jsonb, ARRAY['유성형 (Shooting Star) - 고점 저항 및 하락 전환 예고', '망치형 (Hammer) - 저점 매수세 유입 및 상승 랠리 기대', '상승 장악형 (Bullish Engulfing) - 추세 반전 및 홀딩 유도', '도지 (Doji) - 추세 지속 가능성 및 일시 관망']::text[], 0, '급등세 끝에서 위꼬리가 몸통보다 훨씬 길게 솟아오른 캔들은 ''유성형(Shooting Star)''입니다. 장중 상승 시도를 강력한 차익 실현 및 매도 압력이 짓눌렀음을 보여주며, 하락 추세 전환의 강력한 경고 시그널입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (703, '캔들/가격행동', '02_candlestick_price_action.md', '직전의 음봉 몸통을 다음 날의 거대한 양봉 몸통이 완전히 감싸 안는 아래 형태가 포착되었습니다. 이 패턴의 이름과 신뢰도는?', '[{"time":"Day 1","open":1176,"high":1200,"low":1140,"close":1152,"volume":112},{"time":"Day 2","open":1152,"high":1164,"low":1104,"close":1116,"volume":99},{"time":"Day 3","open":1116,"high":1140,"low":1056,"close":1068,"volume":100},{"time":"Day 4","open":1044,"high":1224,"low":1032,"close":1212,"volume":108}]'::jsonb, '[]'::jsonb, ARRAY['하락 장악형 (Bearish Engulfing) - 추세 반전 신뢰도 낮음', '상승 장악형 (Bullish Engulfing) - 매수 전환 신뢰도 높음', '상승 관통형 (Piercing Line) - 중간 강도의 반전 신호', '석별형 (Evening Star) - 상승 추세 종결 신호']::text[], 1, '전일의 하락 음봉 몸통을 다음 날의 장대 양봉이 완전히 덮어버리는 형태를 ''상승 장악형(Bullish Engulfing)'' 패턴이라고 합니다. 하락 추세 끝에서 나타날 경우 단기 하락세가 종료되고 강력한 매수세가 들어왔음을 뜻해 전환 신뢰도가 매우 높습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (704, '캔들/가격행동', '01_chart_market_basics.md', '시가와 종가가 거의 일치하여 몸통이 거의 없고 위아래 꼬리만 달린 십자(+) 모양 캔들이 출현했습니다. 이 캔들에 대한 올바른 해석은?', '[{"time":"Day 1","open":1800,"high":1860,"low":1776,"close":1824,"volume":82},{"time":"Day 2","open":1824,"high":1872,"low":1812,"close":1848,"volume":101},{"time":"Day 3","open":1848,"high":1908,"low":1800,"close":1848,"volume":126}]'::jsonb, '[]'::jsonb, ARRAY['상승세 동력 상실로 인한 추세의 하방 반전', '매수/매도 세력 균형에 따른 도지(Doji) 횡보', '매도세 지배에 따른 즉각적인 숏 포지션 진입', '하락 세력 이탈로 인한 즉각적인 상승 랠리']::text[], 1, '시가와 종가가 거의 같은 십자 모양의 캔들은 ''도지(Doji)'' 캔들입니다. 이는 힘의 균형이 팽팽함을 시사하며, 기존 추세의 힘이 빠지고 잠재적인 방향성 전환(상승/하락 모두 포함)의 변곡점이 다가오고 있음을 의미합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (705, '캔들/가격행동', '02_candlestick_price_action.md', '상승 추세 고점에서 직전 양봉의 몸통을 거대 음봉이 아래로 덮어버리는 캔들 조합이 발생했습니다. 이 현상을 의미하는 용어는?', '[{"time":"Day 1","open":1440,"high":1500,"low":1428,"close":1488,"volume":110},{"time":"Day 2","open":1488,"high":1560,"low":1476,"close":1548,"volume":117},{"time":"Day 3","open":1560,"high":1572,"low":1380,"close":1392,"volume":94}]'::jsonb, '[]'::jsonb, ARRAY['하락 장악형 (Bearish Engulfing) - 고점 하락 전환 예고', '상승 장악형 (Bullish Engulfing) - 고점 돌파 랠리 예고', '하락 잉태형 (Harami) - 기존 하락세의 일시 둔화', '샛별형 (Morning Star) - 바닥권 상승 반전 예고']::text[], 0, '고점에서 직전 양봉을 음봉이 감싸 안은 형태는 ''하락 장악형(Bearish Engulfing)''입니다. 매수 세력을 매도 공급이 압도했다는 명백한 증거로, 엔비디아 주가 추세가 하락으로 반전할 리스크가 큽니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (706, '시장구조/SR', '03_market_structure.md', '엔비디아 주가가 장기 저항선인 1,800달러를 거래량 실린 강한 캔들로 돌파한 뒤, 다시 1,800달러 부근으로 내려와 버티고 있습니다. 가장 안전한 진입 방식은?', '[{"time":"Day 1","open":1680,"high":1776,"low":1668,"close":1740,"volume":110},{"time":"Day 2","open":1740,"high":1788,"low":1716,"close":1728,"volume":104},{"time":"Day 3","open":1728,"high":1872,"low":1716,"close":1848,"volume":116},{"time":"Day 4","open":1848,"high":1860,"low":1788,"close":1812,"volume":339},{"time":"Day 5","open":1812,"high":1836,"low":1800,"close":1824,"volume":347}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":1800},{"x":4,"y":1800}],"label":"돌파된 저항선 -> 지지선 전환선","color":"#3b82f6"}]'::jsonb, ARRAY['돌파 시점에 시장가로 즉시 진입하는 추격 매수', '돌파 후 저항선의 지지선 전환(Retest) 확인 시 진입', '이전 최저가 부근인 1,680달러 조정 시까지 대기 매수', '돌파 후 즉시 단기 조정을 예상한 역추세 숏 진입']::text[], 1, '저항선이 강하게 뚫리면 역할 전환(Role Reversal)에 의해 신규 지지선으로 바뀝니다. 돌파 시점에 뇌동매매하기보다는 돌파된 선 부근으로 엔비디아 주가가 눌려 지지(Retest)를 완성할 때 진입하는 것이 리스크 대비 기대 수익이 큽니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (707, '거래량/유동성', '05_volume_liquidity.md', '엔비디아 주가가 저항선 위로 거래량 없이 장대양봉을 뿜어 올렸으나, 다음 날 곧바로 장대음봉으로 밀어붙이며 저항선 아래로 내려왔습니다. 이 현상의 명칭은?', '[{"time":"Day 1","open":1176,"high":1212,"low":1164,"close":1200,"volume":113},{"time":"Day 2","open":1200,"high":1224,"low":1188,"close":1212,"volume":85},{"time":"Day 3","open":1212,"high":1320,"low":1200,"close":1296,"volume":33},{"time":"Day 4","open":1296,"high":1308,"low":1140,"close":1152,"volume":26}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":1224},{"x":3,"y":1224}],"label":"저항선","color":"#ef4444"}]'::jsonb, ARRAY['진짜 상승 돌파 (True Breakout)', '불 트랩 (Bull Trap) - 매수자 청산 유도 가짜 돌파', '베어 트랩 (Bear Trap) - 매도자 청산 유도 가짜 하방', '골든 크로스 (Golden Cross) - 이평선 돌파']::text[], 1, '저항선을 일시적으로 뚫었다가 대량 매도세와 함께 직후 캔들에서 하방으로 원상복귀하는 현상을 ''불 트랩(Bull Trap/가짜 돌파)''이라고 합니다. 돌파 후 리테스트를 기다리지 않고 급히 추격 매수했던 투자자들이 고점에 물리는 대표적 함정입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (708, '시장구조/SR', '01_chart_market_basics.md', '아래 차트에서 3번 연속 강하게 반등하며 가격 하락을 저지해 준 주요 가격대는 무엇을 의미하나요?', '[{"time":"Day 1","open":1200,"high":1224,"low":1080,"close":1092,"volume":114},{"time":"Day 2","open":1092,"high":1176,"low":1080,"close":1164,"volume":104},{"time":"Day 3","open":1164,"high":1260,"low":1152,"close":1248,"volume":109},{"time":"Day 4","open":1248,"high":1272,"low":1092,"close":1104,"volume":112},{"time":"Day 5","open":1104,"high":1200,"low":1080,"close":1188,"volume":115}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":1080},{"x":4,"y":1080}],"label":"1,080달러선","color":"#10b981"}]'::jsonb, ARRAY['강력한 저항선 (Resistance Line) - 매도 매물대', '강력한 지지선 (Support Line) - 매수 매물대', '골든크로스 수렴선 - 이평선 밀집대', '이격도 붕괴선 - 가격 과열 분기점']::text[], 1, '특정 가격(1,080달러)에 접근할 때마다 대기 중이던 저가 매수세가 유입되어 엔비디아 주가의 추가 하락을 방어해 준 이 라인은 ''강력한 지지선(Support Line)''입니다. 이탈하기 전까지는 손절 라인을 바로 밑에 두고 진입하기에 가장 손익비 좋은 구간입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (709, '거래량/유동성', '05_volume_liquidity.md', '지지선 아래로 엔비디아 주가가 이탈하여 공매도가 폭증했으나, 이내 거래량이 급증하며 양봉으로 지지선을 회복한 뒤 반등을 시작했습니다. 이 현상의 명칭은?', '[{"time":"Day 1","open":1440,"high":1464,"low":1416,"close":1428,"volume":97},{"time":"Day 2","open":1428,"high":1440,"low":1320,"close":1332,"volume":89},{"time":"Day 3","open":1332,"high":1476,"low":1320,"close":1464,"volume":108}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":1380},{"x":2,"y":1380}],"label":"지지선","color":"#10b981"}]'::jsonb, ARRAY['불 트랩 (Bull Trap) - 가짜 상방 돌파', '베어 트랩 (Bear Trap) - 가짜 하방 이탈', '리테스트 실패 - 지지선 붕괴', '추세 추종 돌파 - 하방 랠리 가속']::text[], 1, '지지선을 아래로 뚫고 내려가 하락세가 지속될 것처럼 유도한 뒤, 매물을 털어내고 강력하게 다시 반등해 올리는 현상을 ''베어 트랩(Bear Trap)''이라고 합니다. 하락 돌파로 생각하고 공매도를 치거나 손절했던 사람들의 손실을 강제하며 가격이 급등하게 만듭니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (710, '시장구조/SR', '04_patterns_breakout.md', '저항선을 뚫어내기 직전 돌파 전조 현상 중 하나인 ''지지점 상승''의 특징을 골라보세요.', '[{"time":"Day 1","open":1200,"high":1260,"low":1080,"close":1224,"volume":95},{"time":"Day 2","open":1224,"high":1260,"low":1116,"close":1236,"volume":86},{"time":"Day 3","open":1236,"high":1260,"low":1152,"close":1248,"volume":103}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":1260},{"x":2,"y":1260}],"label":"저항선 (105)","color":"#ef4444"}]'::jsonb, ARRAY['저항선 부근에서 고점들이 점점 급락하며 붕괴하는 현상', '저항선 부근에서 저점들을 높여가며 밀어 올리는 수렴 현상', '거래량이 완전히 소멸하여 긴 횡보 상태를 보이는 현상', '지속적인 매도세로 인해 갑작스럽게 급락하는 현상']::text[], 1, '저항을 뚫지 못하고 밀려 내려올 때, 이전 저점보다 높은 지점에서 저점을 계속 잡아 올려주는 것은 매도 압력보다 매수 압력이 점점 올라오고 있음을 의미합니다. 수렴 끝에 돌파가 나타날 신뢰도가 매우 높습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (711, '추세/레짐', '03_market_structure.md', '저점들을 연결한 우상향 상승 추세선 아래로 캔들의 종가(마감가격)가 이탈했습니다. 기술적 분석 관점의 올바른 해석은 무엇입니까?', '[{"time":"W-5","open":1200,"high":1260,"low":1200,"close":1236,"volume":105},{"time":"W-4","open":1236,"high":1320,"low":1224,"close":1296,"volume":107},{"time":"W-3","open":1296,"high":1308,"low":1260,"close":1272,"volume":111},{"time":"W-2","open":1272,"high":1380,"low":1284,"close":1356,"volume":118},{"time":"Today","open":1356,"high":1368,"low":1236,"close":1248,"volume":128}]'::jsonb, '[{"type":"line","points":[{"x":0,"y":1200},{"x":2,"y":1260},{"x":4,"y":1320}],"label":"상승 추세선","color":"#10b981"}]'::jsonb, ARRAY['추세선 이탈은 영향이 없으므로 비중 유지', '상승 추세 붕괴로 하락 반전 대비 비중 축소', '일시적인 속임수이므로 추가 불타기 진입', '채널 상단 도달에 따른 즉각적인 매수 대응']::text[], 1, '신뢰받던 우상향 상승 추세선 하방으로 캔들의 종가가 이탈 마감하는 것은 매수 중심의 시장 주도권이 붕괴했음을 뜻합니다. 지지를 잃은 하락 가속화 리스크에 대비해야 합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (712, '추세/레짐', '07_multitimeframe_regime.md', '아래 차트에서 고점들과 저점들이 일정한 평행 통로를 그리며 하락하고 있습니다. 채널 하단에 도달했을 때 단기 반등을 목표로 하는 매매의 명칭과 관점은?', '[{"time":"Day 1","open":1800,"high":1824,"low":1620,"close":1680,"volume":88},{"time":"Day 2","open":1680,"high":1764,"low":1668,"close":1740,"volume":110},{"time":"Day 3","open":1740,"high":1752,"low":1536,"close":1560,"volume":110},{"time":"Day 4","open":1560,"high":1656,"low":1548,"close":1632,"volume":119},{"time":"Day 5","open":1632,"high":1644,"low":1416,"close":1440,"volume":111}]'::jsonb, '[{"type":"channel","points":[{"x":0,"y":1800},{"x":4,"y":1620},{"x":0,"y":1620},{"x":4,"y":1440}],"label":"하향 평행 채널","color":"#f59e0b"}]'::jsonb, ARRAY['추세 추종 매매 - 대세 상승이므로 장기 보유', '채널 하단 반등 매매 - 단기 역추세 매수 대응', '양방향 물타기 매매 - 평단가를 낮춰 탈출 대기', '돌파 매매 - 채널 하방 붕괴 확정 시 매수 대응']::text[], 1, '가격이 평행한 하락 터널 내에서 움직이는 ''하향 평행 채널(Descending Channel)''입니다. 채널 하단 라인 터치 시에는 기술적 단기 반등이 자주 출현하므로, 손절선을 짧게 잡고 반등 타점을 노리는 역추세(Counter-trend) 트레이딩이 가능합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (713, '추세/레짐', '03_market_structure.md', '우상향 상승 평행 채널의 상단 저항선 부근까지 엔비디아 주가가 도달했습니다. 합리적인 추세 채널 트레이더의 대응은?', '[{"time":"Day 1","open":1200,"high":1224,"low":1188,"close":1212,"volume":89},{"time":"Day 2","open":1212,"high":1296,"low":1212,"close":1284,"volume":95},{"time":"Day 3","open":1284,"high":1308,"low":1248,"close":1260,"volume":93},{"time":"Day 4","open":1260,"high":1380,"low":1260,"close":1368,"volume":118},{"time":"Day 5","open":1368,"high":1392,"low":1344,"close":1356,"volume":130}]'::jsonb, '[{"type":"channel","points":[{"x":0,"y":1224},{"x":4,"y":1380},{"x":0,"y":1188},{"x":4,"y":1344}],"label":"상승 평행 채널","color":"#10b981"}]'::jsonb, ARRAY['채널 상방 돌파를 예상한 고배율 레버리지 매수', '채널 상단 저항에 따른 분할 익절 및 대기', '채널 중간 조정 시 지정을 통한 시장가 추격', '채널 붕괴 신호에 따른 전량 기계적 손절']::text[], 1, '상승 채널이라고 해도 상단 저항선에 닿으면 다시 채널 하단이나 중심선까지 조정을 받을 가능성이 매우 큽니다. 따라서 고점 영역에서의 추격매수를 금지하고, 기존 포지션을 분할 익절하는 기회로 삼아야 합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (714, '추세/레짐', '01_chart_market_basics.md', '고점들을 잇는 우하향 하락 추세선을 엔비디아 주가가 대량의 거래량을 동반하며 장대양봉 종가로 상향 돌파(Breakout)했습니다. 의미하는 시그널은?', '[{"time":"Day 1","open":1560,"high":1584,"low":1500,"close":1524,"volume":80},{"time":"Day 2","open":1524,"high":1536,"low":1440,"close":1464,"volume":118},{"time":"Day 3","open":1464,"high":1476,"low":1380,"close":1404,"volume":101},{"time":"Day 4","open":1404,"high":1536,"low":1392,"close":1524,"volume":123}]'::jsonb, '[{"type":"line","points":[{"x":0,"y":1572},{"x":2,"y":1464},{"x":3,"y":1416}],"label":"하락 추세선","color":"#ef4444"}]'::jsonb, ARRAY['하락 추세 지속에 따른 숏 포지션 추가 매수', '하락 추세 돌파 및 상승 전환 가능성에 따른 매수', '속임수 돌파를 예상한 즉시 반대 숏 포지션 진입', '추세와 무관하게 횡보 흐름으로 판단해 관망']::text[], 1, '중요한 하락 추세선을 엔비디아 주가 몸통이 확실하게 뚫고 마감하는 것은 기존 하락 관성의 지배력이 종료되고 상승 추세로 돌아설 수 있는 가장 대표적인 추세 전환(Reversal) 확인 시그널입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (715, '추세/레짐', '03_market_structure.md', '추세선 작도 시 신뢰도를 판단하는 가장 중요한 규칙은 무엇인가요?', '[{"time":"Day 1","open":1200,"high":1212,"low":1200,"close":1212,"volume":83},{"time":"Day 2","open":1212,"high":1260,"low":1224,"close":1248,"volume":100}]'::jsonb, '[]'::jsonb, ARRAY['차트상 선이 정배열로 정돈되어 그려질 때', '최소 3개 이상의 뚜렷한 저점/고점 터치 확인 시', '가파른 각도로 90도에 가깝게 작도될 때', '보조지표와 결합하여 수평으로 그려질 때']::text[], 1, '두 점만으로도 선을 그릴 수 있지만, 3번째 터치(3rd Touch)에서 정확한 지지나 저항을 보이고 반등해 주는 순간부터 시장 참여자들이 공식 인지하는 신뢰도 높은 추세선이 됩니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (716, '패턴/돌파', '04_patterns_breakout.md', '머리와 양쪽 어깨 형태를 그리며 넥라인 지지선(1,152달러)을 위태롭게 지탱하다가 하방으로 강한 캔들이 이탈했습니다. 숏(매도) 포지션 진입 시점은?', '[{"time":"Day 1","open":1200,"high":1380,"low":1176,"close":1320,"volume":86},{"time":"Day 2","open":1320,"high":1560,"low":1140,"close":1260,"volume":111},{"time":"Day 3","open":1260,"high":1368,"low":1152,"close":1320,"volume":101},{"time":"Day 4","open":1320,"high":1332,"low":1116,"close":1128,"volume":105}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":1152},{"x":3,"y":1152}],"label":"넥라인 지지선","color":"#ef4444"}]'::jsonb, ARRAY['머리 꼭대기(1,560달러) 부근에서 예측 숏 진입', '오른쪽 어깨가 올라가고 있을 때 돌파 전 선진입', '저점들을 연결한 넥라인의 하방 돌파 완료 시', '패턴 완성과 무관하게 오른쪽 어깨 끝에서 대기']::text[], 2, '헤드앤숄더(Head & Shoulders) 패턴은 오른쪽 어깨를 그린 후, 저점 지지선인 ''넥라인(Neckline)''을 거래량을 실어 하방 돌파해야 최종 완성이 선언됩니다. 그전에 진입하면 넥라인 반등 시 극심한 손실을 입습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (717, '패턴/돌파', '04_patterns_breakout.md', '하락 추세 끝에서 엔비디아 주가가 비슷한 깊이의 바닥을 두 번(이중바닥) 형성한 뒤, 중간 고점 저항선(넥라인)을 돌파했습니다. 향후 예상 방향성과 매수 타점은?', '[{"time":"Day 1","open":1200,"high":1200,"low":960,"close":1020,"volume":85},{"time":"Day 2","open":1020,"high":1140,"low":1008,"close":1128,"volume":88},{"time":"Day 3","open":1128,"high":1140,"low":948,"close":984,"volume":105},{"time":"Day 4","open":984,"high":1188,"low":972,"close":1176,"volume":113}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":1140},{"x":3,"y":1140}],"label":"넥라인 (95)","color":"#3b82f6"}]'::jsonb, ARRAY['추가 폭락 가능성에 따른 전량 손절 대응', 'W 패턴 이중 바닥 완성 및 넥라인 돌파 시 매수', '박스권 횡보 판단에 따른 무대응 및 관망', '이중 바닥의 하방 이탈을 예상한 숏 포지션 진입']::text[], 1, 'W자 모양의 ''이중 바닥형(Double Bottom)'' 패턴입니다. 엔비디아 주가가 하락을 멈추고 바닥을 두 차례 단단히 지지해 준 뒤 중간 봉우리(넥라인 1,140달러)를 돌파해 마감하면 추세가 상승으로 강하게 전환될 가능성이 매우 높습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (718, '패턴/돌파', '04_patterns_breakout.md', '급격한 기둥식 엔비디아 주가 폭등(깃대) 후, 완만한 하향 평행 채널(깃발) 모양으로 횡보/수렴하다가 채널 상단을 강하게 돌파했습니다. 이 패턴과 예상 목표가는?', '[{"time":"Day 1","open":600,"high":960,"low":588,"close":936,"volume":105},{"time":"Day 2","open":936,"high":948,"low":864,"close":888,"volume":119},{"time":"Day 3","open":888,"high":912,"low":840,"close":852,"volume":88},{"time":"Day 4","open":852,"high":1020,"low":840,"close":996,"volume":110}]'::jsonb, '[]'::jsonb, ARRAY['이중 천정형 패턴 - 고점 도달 시 숏 진입', '불 플래그 패턴 - 깃발 돌파 시 추가 상승 기대', '헤드앤숄더 패턴 - 넥라인 하방 돌파 타겟', '대칭 삼각수렴 패턴 - 변동성 축소 후 돌파 대기']::text[], 1, '대표적 강세 지속 패턴인 ''불 플래그(Bull Flag)''입니다. 급격한 상승(깃대) 뒤 숨 고르기 채널(깃발)을 상방 돌파하면, 이전 상승 파동의 크기(깃대 높이)만큼 추가로 수직 랠리를 시작하는 관성이 있습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (719, '패턴/돌파', '04_patterns_breakout.md', '상승 추세의 천정권에서 엔비디아 주가가 동일한 가격 저항을 두 번 확인하며 M자 모양을 만든 뒤, 두 고점 사이의 저점 지지선인 넥라인(1,440달러)을 이탈했습니다. 올바른 해석은?', '[{"time":"Day 1","open":1200,"high":1680,"low":1188,"close":1620,"volume":81},{"time":"Day 2","open":1620,"high":1632,"low":1440,"close":1464,"volume":106},{"time":"Day 3","open":1464,"high":1680,"low":1452,"close":1656,"volume":109},{"time":"Day 4","open":1656,"high":1668,"low":1380,"close":1392,"volume":92}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":1440},{"x":3,"y":1440}],"label":"넥라인 (120)","color":"#ef4444"}]'::jsonb, ARRAY['상승 추세의 지속 연장에 따른 추가 매수', '이중 천정형(M 패턴) 완성에 따른 하락 반전 대비', '단기 조정에 따른 일시적 횡보 박스권 진입', '방향성 없는 일상적인 잔파동으로 판단해 홀딩']::text[], 1, '고점에서 지지받지 못하고 형성된 M자형 ''이중 천정형(Double Top)'' 패턴입니다. 두 차례 강력한 저항벽(1,680달러)을 넘지 못하고 넥라인(1,440달러)마저 붕괴했으므로 하방 추세가 가속화된다는 신호입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (720, '패턴/돌파', '04_patterns_breakout.md', '고점 저항선은 수평(평평함)을 유지하고 있으나, 저점 지지선은 점점 우상향하며 좁게 수렴하는 차트 형태의 명칭과 일반적인 돌파 방향은?', '[{"time":"Day 1","open":960,"high":1200,"low":960,"close":1140,"volume":118},{"time":"Day 2","open":1140,"high":1200,"low":1032,"close":1176,"volume":113},{"time":"Day 3","open":1176,"high":1200,"low":1104,"close":1188,"volume":104}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":1200},{"x":2,"y":1200}],"label":"수평 저항선","color":"#ef4444"},{"type":"line","points":[{"x":0,"y":960},{"x":1,"y":1032},{"x":2,"y":1104}],"label":"상승 지지선","color":"#10b981"}]'::jsonb, ARRAY['디센딩 트라이앵글 - 일반적으로 하방 돌파 기대', '어센딩 트라이앵글 - 매수 압력 우위로 상방 돌파 기대', '헤드앤숄더 패턴 - 넥라인 하방 돌파 기대', '상향 평행 채널 - 상하단 터치식 채널 매매 기대']::text[], 1, '고점 저항은 평평하고 저점은 계속 높아지는 삼각수렴을 ''어센딩 트라이앵글(Ascending Triangle)''이라고 합니다. 위로 갈수록 저점이 계속 올라가는 현상은 매수세가 가격을 위로 계속 압박하고 있음을 증명하며, 대개 저항선(1,200달러)을 상향 뚫고 오르는 확률이 높습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (721, '지표/컨플루언스', '06_technical_indicators.md', '엔비디아 주가는 매일 하락하여 신저가를 갱신하고 있으나, RSI 보조지표의 저점은 점점 높아지는 현상을 발견했습니다. 올바른 용어와 매매 대응법은?', '[{"time":"D-4","open":1320,"high":1344,"low":1176,"close":1200,"volume":83},{"time":"D-3","open":1200,"high":1248,"low":1152,"close":1176,"volume":95},{"time":"D-2","open":1176,"high":1212,"low":1104,"close":1128,"volume":102},{"time":"D-1","open":1128,"high":1164,"low":1116,"close":1152,"volume":124},{"time":"Today","open":1152,"high":1188,"low":1140,"close":1176,"volume":109}]'::jsonb, '[]'::jsonb, ARRAY['하락 다이버전스 - 가격 상승 둔화에 따른 공매도', '상승 다이버전스 - 하락 둔화 및 반등 신호로 매수', '데드 크로스 - 이평선 하방 교차에 따른 관망', '과매수 이탈 시그널 - 단기 반등에 따른 매수']::text[], 1, '엔비디아 주가의 가격 저점은 낮아지나 보조지표(RSI)의 운동 저점이 높아지는 현상을 ''상승 다이버전스(Bullish Divergence)''라고 합니다. 이는 하방 에너지의 실질적 소멸과 상승 압력의 내부 응축을 의미하는 기술적 분석에서 가장 신뢰도 높은 추세 전환 시그널입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (722, '지표/컨플루언스', '06_technical_indicators.md', '엔비디아 주가는 급격히 치솟으며 최고가 갱신 랠리를 이어가고 있으나, RSI 지표의 고점은 계속 낮아지고 있습니다. 이 현상을 지칭하는 명칭과 대처법은?', '[{"time":"Day 1","open":1200,"high":1440,"low":1188,"close":1416,"volume":94},{"time":"Day 2","open":1416,"high":1464,"low":1380,"close":1440,"volume":97},{"time":"Day 3","open":1440,"high":1620,"low":1428,"close":1596,"volume":104}]'::jsonb, '[]'::jsonb, ARRAY['하락 다이버전스 - 매수 둔화 및 하락 우려로 익절', '상승 다이버전스 - 추가 급등 기대로 신규 매수', '골든 크로스 - 추세 강화에 따른 홀딩', '볼린저 밴드 스퀴즈 - 변동성 수축 후 돌파']::text[], 0, '엔비디아 주가는 계속 고점을 높이고 있으나 보조지표의 고점은 꺾여 낮아지는 현상을 ''하락 다이버전스(Bearish Divergence)''라고 합니다. 이는 매수세의 힘이 표면적인 가격 상승에 비해 실질적으로 빠르게 축소되고 있음을 경고하며, 조만간 큰 급락이 발생할 확률이 높습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (723, '지표/컨플루언스', '06_technical_indicators.md', '이동평균선(EMA) 20일선(단기)이 50일선(중기)을 아래에서 위로 강하게 뚫고 솟구쳐 올랐습니다. 이 교차 현상의 정식 명칭은?', '[{"time":"Day 1","open":1200,"high":1224,"low":1176,"close":1188,"volume":110},{"time":"Day 2","open":1188,"high":1248,"low":1188,"close":1236,"volume":95},{"time":"Day 3","open":1236,"high":1320,"low":1236,"close":1308,"volume":99}]'::jsonb, '[]'::jsonb, ARRAY['데드 크로스 - 단기 이평의 하방 교차로 매도 신호', '골든 크로스 - 단기 이평의 상방 교차로 매수 신호', '볼린저 스퀴즈 - 변동성 수축 및 돌파 신호', '다이버전스 수렴 - 지표와 가격의 동반 횡보']::text[], 1, '단기 이평선이 장기 이평선을 위로 치고 올라가는 현상을 ''골든 크로스(Golden Cross)''라고 합니다. 이는 최근 매수 평단가가 장기 평균가보다 확연히 높아졌음을 시사하며, 상승 추세가 본 궤도에 올랐음을 입증해 줍니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (724, '지표/컨플루언스', '07_multitimeframe_regime.md', '매우 강력한 원웨이 폭락장 속에서 RSI 지표가 20(과매도 영역) 이하로 깊이 내려왔습니다. 이를 보고 ''과매도 반등''을 노리며 기계적 시장가 풀매수를 때렸을 때 나타나는 가장 빈번한 오류는?', '[{"time":"Day 1","open":1200,"high":1212,"low":1056,"close":1068,"volume":107},{"time":"Day 2","open":1068,"high":1080,"low":900,"close":912,"volume":34},{"time":"Day 3","open":912,"high":924,"low":744,"close":756,"volume":16}]'::jsonb, '[]'::jsonb, ARRAY['하락 추세 즉시 종료 및 V자 상승 반등 성공', '강력한 하락장에서의 지표 과매도 고착화 리스크', '거래량 급감으로 인한 호가 정지 및 상장 폐지', '엔비디아 주가의 즉각적인 박스권 횡보 및 변동성 축소']::text[], 1, 'RSI 30 이하 과매도 영역은 반등 신호이기도 하지만, 추세가 지나치게 강력한 하락장일 때는 지표만 과매도 구역에 쳐박힌 채 가격은 계속 급락하는 ''과매도 고착화(Oversold Embedded)'' 상태가 이어집니다. 다이버전스나 캔들 반전형 확인 없이 수치만 보고 들어가는 매수는 깡통으로 가는 지름길입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (725, '지표/컨플루언스', '06_technical_indicators.md', '엔비디아 주가의 변동성이 극도로 축소되며 볼린저 밴드의 폭이 매우 좁아지는 ''스퀴즈(Squeeze)'' 현상이 나타났습니다. 이후 기대되는 시장 변동성의 원리는 무엇인가요?', '[{"time":"Day 1","open":1200,"high":1212,"low":1188,"close":1200,"volume":108},{"time":"Day 2","open":1200,"high":1200,"low":1188,"close":1188,"volume":112},{"time":"Day 3","open":1188,"high":1200,"low":1188,"close":1200,"volume":108}]'::jsonb, '[]'::jsonb, ARRAY['변동성 사멸로 인한 장기 횡보 및 거래 정지', '밴드 스퀴즈 후 변동성 팽창에 따른 추세 분출', '엔비디아 주가의 하방 붕괴로 인한 강한 하락 파동 시작', '이평선들의 수평 정렬에 따른 완전한 추세 고정']::text[], 1, '볼린저 밴드의 수축(Squeeze)은 시장의 숨 고르기 및 힘 모으기를 뜻합니다. 에너지가 최대한 압축된 후에는 밴드 상단 혹은 하단선을 이탈하며 매우 거대한 변동성 팽창(Expansion) 추세가 시작되므로, 방향성을 유심히 지켜봐야 합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (726, '리스크/심리', '09_risk_position_management.md', '총 투자 원금은 12,000만 원이며, 1회 거래 시 최대 손실 허용액을 원금의 2%(240만 원)로 제한하는 ''2% 룰''을 지키려 합니다. 진입하려는 종목의 손절 라인 폭이 -5%일 때, 최대 매수(진입) 가능 금액은 얼마인가요?', '[{"time":"Day 1","open":120000,"high":126000,"low":117600,"close":122400,"volume":95},{"time":"Day 2","open":122400,"high":123600,"low":120000,"close":120000,"volume":120}]'::jsonb, '[]'::jsonb, ARRAY['12,000만 원 (원금 전액 진입)', '2,400만 원 (원금의 20% 진입)', '4,800만 원 (원금의 40% 진입)', '6,000만 원 (원금의 50% 진입)']::text[], 2, '2% 룰에 기초한 포지션 사이징 공식은 `진입금액 = (총원금 * 리스크비율) / 손절비율` 입니다. 따라서 `240만 원 / 0.05 = 4,800만 원`이 됩니다. 4,800만 원어치 성장주을 샀을 때 가격이 -5% 떨어져 강제 손절을 맞아도 내 계좌 총액에서 손실을 보는 돈은 정확히 2%인 240만 원으로 통제됩니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (727, '리스크/심리', '09_risk_position_management.md', '어느 성장주에 120,000원에 매수 진입합니다. 손절 라인은 114,000원(-5%)에 배치하고, 목표가는 138,000원(+15%)에 설정했습니다. 이 트레이딩 시나리오의 손익비(Risk-to-Reward Ratio)는 얼마입니까?', '[{"time":"Today","open":120000,"high":120000,"low":120000,"close":120000}]'::jsonb, '[]'::jsonb, ARRAY['1 : 1 (동일한 기대 수익과 리스크)', '1 : 2 (기대 수익이 리스크의 2배)', '1 : 3 (기대 수익이 리스크의 3배)', '2 : 1 (기대 수익이 리스크의 0.5배)']::text[], 2, '손절 폭(6,000원) 대비 익절 폭(18,000원)의 비례를 의미하므로 `1,500 / 500 = 3`, 즉 손익비는 1:3이 됩니다. 이처럼 잃는 돈의 최소 2~3배를 벌 수 있는 손익비 높은 구간만 반복적으로 거래해야 장기적으로 계좌가 생존합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (728, '리스크/심리', '09_risk_position_management.md', '손익비를 엄격히 통제하여 항상 기대 손실의 2배를 버는 매매(손익비 1:2)만 고집합니다. 이 경우 내 계좌 잔고가 손실 없이 제자리걸음(본전)을 유지하기 위해 필요한 수학적인 최소 승률(Win Rate)은 얼마인가요?', '[{"time":"Today","open":1200,"high":1200,"low":1200,"close":1200}]'::jsonb, '[]'::jsonb, ARRAY['50.0% (최소 절반 이상 성공)', '33.3% (3번 중 1번 성공으로 본전)', '25.0% (4번 중 1번 성공으로 본전)', '66.6% (3번 중 2번 성공으로 본전)']::text[], 1, '손익비가 1:2일 경우, 1번 이기면 +2를 벌고 2번 지면 -2를 잃으므로 3번 매매 중 1번만 이겨도 누적 수익은 0이 됩니다. 즉 손익비를 1:2 이상으로 유지하면 수학적으로 승률이 겨우 33.3%만 나와도 절대 파산하지 않고 계좌가 우상향할 발판이 마련됩니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (729, '셋업/실행', '08_setup_entry_exit.md', '120,000원에 산 성장주이 180,000원까지 올랐습니다. 이익을 보존하면서 상승세를 끝까지 타기 위해, 최고점 대비 10% 하방 이탈 시 즉시 자동 익절되는 ''추적 손절매(Trailing Stop)''를 적용했습니다. 최고점 180,000원 달성 후 엔비디아 주가가 조정받을 때 실제로 청산(익절)되는 가격은 얼마인가요?', '[{"time":"Day 1","open":120000,"high":144000,"low":118800,"close":142800,"volume":80},{"time":"Day 2","open":142800,"high":180000,"low":141600,"close":177600,"volume":98}]'::jsonb, '[]'::jsonb, ARRAY['120,000원 (본전 수준 청산)', '162,000원 (최고점 대비 10% 하방 청산)', '168,000원 (최고점 대비 6.6% 하방 청산)', '144,000원 (최고점 대비 20% 하방 청산)']::text[], 1, '추적 손절매(Trailing Stop)는 가격 상승에 따라 청산 가격을 자동으로 올려주는 주문입니다. 최고점 180,000원을 기록했으므로 청산 트리거 라인은 최고점에서 10% 차감된 `15,000 * 0.9 = 162,000원`으로 확정 셋업되며, 엔비디아 주가가 162,000원을 건드리는 순간 자동 이익실현됩니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (730, '리스크/심리', '09_risk_position_management.md', '레버리지 10배를 적용하여 엔비디아 롱(매수) 포지션을 구축했습니다. 만약 엔비디아 가격이 매수가 대비 몇 % 역방향으로 등락하면 내 투자 원금이 100% 강제 청산(증거금 완전 소멸)당할까요?', '[{"time":"Today","open":600000,"high":601200,"low":598800,"close":600000}]'::jsonb, '[]'::jsonb, ARRAY['5.0% 하락 시', '10.0% 하락 시', '20.0% 하락 시', '100.0% 하락 시']::text[], 1, '레버리지 비율과 청산 거리 비율은 역수 관계입니다. `100% / 레버리지 배수` 공식에 따라, 10배 레버리지는 엔비디아 주가가 내 베팅의 반대 방향으로 단 10%만 움직여도 투자 원금이 전부 증발하고 포지션이 강제 종료(Liquidation)됩니다. 고배율 레버리지가 파산의 지름길인 이유입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (731, '캔들/가격행동', '02_candlestick_price_action.md', '상승 추세 고점 영역(1,800달러선)에서 몸통이 매우 작고 아래꼬리가 긴 행잉맨(Hanging Man) 캔들이 출현한 이후, 다음 날 시가가 전일 종가보다 큰 갭을 그리며 낮게 하락 출발(1,740달러)했습니다. 포지션을 보유한 스윙 트레이더로서 가장 적절한 위기 대응 행동은 무엇입니까?', '[{"time":"Day 1","open":1440,"high":1500,"low":1428,"close":1488,"volume":95},{"time":"Day 2","open":1488,"high":1620,"low":1476,"close":1608,"volume":108},{"time":"Day 3","open":1608,"high":1776,"low":1596,"close":1752,"volume":104},{"time":"Day 4","open":1752,"high":1812,"low":1680,"close":1764,"volume":123},{"time":"Day 5","open":1692,"high":1716,"low":1620,"close":1632,"volume":127}]'::jsonb, '[]'::jsonb, ARRAY['상승 랠리를 기대로 보유 비중 확대 및 추격 매수', '일시적 속임수(휩소) 판단으로 추가 레버리지 매수', '행잉맨 출현 후 갭하락에 따른 전량 또는 일부 정리', '조치 없이 전고점 돌파 시까지 무기한 관망 및 홀딩']::text[], 2, '고가권에서 나타난 행잉맨(Hanging Man)은 잠재적 하락 전환 신호이며, 특히 다음날 갭하락 음봉으로 직전 행잉맨의 저가를 깨고 내려가는 움직임은 강력한 하락 컨펌 시그널입니다. 따라서 이 시점에서는 즉시 비중을 전량 정리하거나 최소 절반 이상 매도하여 리스크를 통제하는 것이 정석입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (732, '캔들/가격행동', '01_chart_market_basics.md', '지속적인 하락 추세 도중 바닥권(960달러선)에서 시가와 종가가 일치하고 긴 아래꼬리를 단 십자 형태의 도지(Doji) 캔들이 생성되었습니다. 다음 날 대량의 거래량과 함께 장대양봉이 솟구치며 1,044달러로 마감하는 샛별형(Morning Star) 조합이 확정되었습니다. 이때 가장 합리적인 매수 진입 지점과 손절가 기준은 무엇입니까?', '[{"time":"Day 1","open":1200,"high":1212,"low":1116,"close":1128,"volume":104},{"time":"Day 2","open":1128,"high":1140,"low":1056,"close":1068,"volume":123},{"time":"Day 3","open":1068,"high":1080,"low":960,"close":972,"volume":97},{"time":"Day 4","open":960,"high":984,"low":900,"close":960,"volume":122},{"time":"Day 5","open":960,"high":1056,"low":948,"close":1044,"volume":108}]'::jsonb, '[]'::jsonb, ARRAY['손절 없이 100% 비중으로 시장가 매수', '샛별형 완성에 따라 분할 매수 후 최저점 손절 셋업', '바닥 도달 기대로 주문 없이 무작정 대기', '상승 꼭대기에서 숏 진입 후 손절 없이 방치']::text[], 1, '하락 추세 끝에 도지와 장대양봉이 결합된 샛별형(Morning Star)은 매우 신뢰도 높은 바닥 상승 전환 신호입니다. 이 패턴을 보고 진입할 때는 반등 상승세에 분할 매수로 동참하되, 바닥을 잡아준 도지 캔들의 최저점(900달러) 아래를 최종 손절 라인으로 잡는 것이 수학적으로 가장 리스크 대비 보상 비율(손익비)이 훌륭한 전략입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (733, '거래량/유동성', '02_candlestick_price_action.md', '엔비디아 주가가 강력한 횡보 박스권 고점(2,400달러 저항선)에 세 번째 터치하는 와중에, 윗꼬리가 길고 몸통이 매우 얇은 유성형(Shooting Star) 캔들이 이틀 연속 발생했습니다. 거래량 역시 저항선 부근에서 매수세가 더 올라가지 못하고 매도 압력이 실려 나타났습니다. 롱(매수) 포지션을 들고 있는 당신의 합리적인 의사결정은?', '[{"time":"Day 1","open":2100,"high":2220,"low":2088,"close":2184,"volume":116},{"time":"Day 2","open":2184,"high":2340,"low":2160,"close":2316,"volume":111},{"time":"Day 3","open":2316,"high":2424,"low":2280,"close":2292,"volume":125},{"time":"Day 4","open":2292,"high":2412,"low":2256,"close":2268,"volume":121}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":2400}],"label":"박스권 상단 저항선 (200)","color":"#ef4444"}]'::jsonb, ARRAY['신고가 갱신을 예상한 전재산 추가 불타기', '저항 돌파 실패 신호 확인 후 분할 익절 및 관망', '손익 평단가 부근이므로 추가 손절 없이 방치', '거래를 종료하고 다른 신규 급등주를 시장가 추격']::text[], 1, '박스권 상단 저항선(2,400달러)에 부딪히며 나타난 유성형(Shooting Star) 연속 출현은 저항 돌파 실패와 차익 실현 세력의 강력한 등장을 경고하는 캔들 신호입니다. 돌파를 확신하기보다는 리스크 관리 관점에서 물량을 축소(50% 분할 익절)하거나 전량 매도하여 이익을 확정 짓는 것이 현명합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (734, '캔들/가격행동', '02_candlestick_price_action.md', '극심한 하락 추세 중 1,200달러선 아래로 떨어지던 엔비디아 주가가 전일 장대음봉을 형성했습니다. 그러나 당일 시가는 갭하락하여 더 낮게 시작했으나, 장중에 강한 매수세가 들어오며 전일 음봉 몸통의 정확히 70% 라인(1,116달러선) 위로 덮어버리는 관통형(Piercing Line) 상승 캔들로 마감했습니다. 종가 매수(롱) 진입 시 원칙 대응은?', '[{"time":"Day 1","open":1320,"high":1332,"low":1248,"close":1260,"volume":92},{"time":"Day 2","open":1260,"high":1272,"low":1164,"close":1176,"volume":108},{"time":"Day 3","open":1104,"high":1212,"low":1092,"close":1200,"volume":125}]'::jsonb, '[]'::jsonb, ARRAY['상승 모멘텀 미달로 매수 보류 및 하방 숏 포지션 진입', '관통형 확인 후 분할 매수 및 당일 최저점 손절 설정', '손절 라인 설정 없이 100% 비중 시장가 매수 집행', '조정을 대기하며 예약 주문 없이 무작정 관망 유지']::text[], 1, '전일 음봉의 50% 이상을 당일 양봉 몸통으로 관통해 올린 ''관통형(Piercing Line)''은 하락 모멘텀이 쇠퇴하고 저가 매수세가 우위를 점하기 시작했음을 뜻하는 바닥 신호입니다. 이 패턴 확인 후 진입할 시에는 손절 한도를 당일 최저점(1,092달러) 밑에 가깝게 설정할 수 있어 매우 유리한 리스크 대비 기대수익 매매가 성립됩니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (735, '캔들/가격행동', '05_volume_liquidity.md', '강한 급등세를 지속하던 엔비디아 주가가 최고점에서 큰 거래량을 터뜨리며 장대양봉을 만들었습니다. 그러나 다음 날, 전일 양봉 몸통의 한가운데 범위 안에서 움직이며 시가와 종가가 모두 갇혀버리는 짧은 음봉인 ''하락 잉태형(Bearish Harami)'' 캔들이 형성되었습니다. 단기 스윙 트레이더로서 당신의 포지션 리스크 관리 행동은?', '[{"time":"Day 1","open":1440,"high":1536,"low":1428,"close":1524,"volume":82},{"time":"Day 2","open":1524,"high":1656,"low":1512,"close":1632,"volume":104},{"time":"Day 3","open":1596,"high":1608,"low":1560,"close":1572,"volume":108}]'::jsonb, '[]'::jsonb, ARRAY['상승 둔화 조짐에 따른 보유 물량 50% 분할 익절', '추세 일시 조정으로 간주하여 비중 확대 추가 매수', '추세 종결 판단에 따른 고배율 숏 포지션 즉시 진입', '이익 실현 없이 전량 장기 보유 전략 유지']::text[], 0, '하락 잉태형(Bearish Harami)은 이전의 강한 상승 추세 동력이 감속하기 시작했으며, 매도 압력이 힘을 기르고 있음을 암시하는 변곡 캔들입니다. 따라서 단기 스윙 트레이더는 물량의 일부(50%)를 분할 익절하여 리스크를 낮추고, 다음 캔들에서 이전 양봉 저점을 깨뜨리는 하락 하방 이탈이 추가되는지 지켜보는 것이 정석입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (736, '시장구조/SR', '03_market_structure.md', '오랫동안 지켜지던 핵심 지지선인 1,200달러 부근에서 매수 진입을 완료했습니다. 그러나 가격이 대량의 거래량을 동반하며 장대음봉으로 지지선을 하방으로 강하게 뚫어냈고, 종가가 지지선 대비 1.5% 아래인 98.60달러로 결정되었습니다. 이 상황에서 원칙을 지키는 올바른 위기 대응 행동은?', '[{"time":"Day 1","open":1260,"high":1296,"low":1224,"close":1236,"volume":115},{"time":"Day 2","open":1236,"high":1248,"low":1188,"close":1200,"volume":95},{"time":"Day 3","open":1200,"high":1212,"low":1176,"close":1182,"volume":94}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":1200}],"label":"중요 지지선 (100)","color":"#10b981"}]'::jsonb, ARRAY['추가 물타기를 위해 자금을 동원하여 평단가 관리', '중요 지지선 붕괴(Breakdown) 확인 후 즉시 전량 손절', '지속 하락 시 추가 평단가 관리를 위해 매수 유보', '하방 이탈 시 즉시 반대 고배율 롱 포지션 진입']::text[], 1, '거래량이 동반된 장대음봉으로 주요 지지선 아래에서 종가가 결정되는 이탈 마감은 매수 지지 세력의 패배이자 추세 붕괴(Breakdown)의 신호입니다. 이 시점에서 물타기를 하거나 존버를 하면 파산적인 하락 조정을 겪을 수 있으므로 즉시 룰에 근거한 ''전량 손절''을 집행해야 계좌를 살릴 수 있습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (737, '시장구조/SR', '03_market_structure.md', '1,800달러의 중요 저항선이 강한 거래량을 실은 돌파봉으로 뚫렸습니다. 이후 엔비디아 주가가 숨 고르기 조정을 받으며 1,800달러 부근까지 되돌아왔고(리테스트 구간), 저항선 부근에서 거래량이 크게 감소하며 아래꼬리가 달린 도지 캔들로 안착하는 모습을 보입니다. 이때 가장 안전하고 합리적인 매매 조치는?', '[{"time":"Day 1","open":1680,"high":1752,"low":1668,"close":1728,"volume":92},{"time":"Day 2","open":1728,"high":1884,"low":1716,"close":1860,"volume":102},{"time":"Day 3","open":1860,"high":1872,"low":1788,"close":1800,"volume":91}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":1800}],"label":"돌파된 저항선 -> 지지선 전환선 (150)","color":"#3b82f6"}]'::jsonb, ARRAY['가짜 돌파(휩소) 판단에 따른 고배율 숏 진입', '돌파 후 리테스트 성공 확인 시 지지선 눌림목 매수', '추격 매수 기회 상실로 판단하고 거래 포기', '1,920달러 추가 돌파를 타겟으로 시장가 추격 매수']::text[], 1, '강하게 돌파된 저항선은 룰 체인지에 의해 지지선으로 변합니다(역할 전환). 돌파 당시 추격 매수하기보다, 돌파된 선(1,800달러)으로 엔비디아 주가가 되돌아오는 리테스트(Retest) 시점에 저조한 거래량과 지지 캔들을 확인하고 손절선을 바로 밑에 설정하여 눌림목 진입하는 것이 리스크가 가장 적은 프로 트레이더의 정석입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (738, '시장구조/SR', '03_market_structure.md', '가격이 960달러 지지선 근처에서 반등을 시도하고 있으나, 반등의 폭이 직전 고점에 턱없이 못 미치며 저점 부근으로 다시 짓눌리고 있습니다. 즉, 고점들이 계속 낮아지는 하락 우위 삼각수렴(Descending)의 형태가 지지선 바로 위에서 감지됩니다. 이 시점에서 지지선 반등을 믿고 신규 매수(롱)를 진입하는 것은 원칙에 맞습니까?', '[{"time":"Day 1","open":1140,"high":1176,"low":960,"close":1056,"volume":110},{"time":"Day 2","open":1056,"high":1092,"low":960,"close":1008,"volume":87},{"time":"Day 3","open":1008,"high":1032,"low":960,"close":972,"volume":93}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":960}],"label":"지지선 (80)","color":"#10b981"}]'::jsonb, ARRAY['삼중 바닥 지지로 판단하고 매수 비중 대폭 확대', '디센딩 수렴 확인 후 하방 이탈 위험 대비 관망', '물타기 평단가 관리를 위해 매수 보증금 추가 투입', '추세와 무관하게 숏 포지션으로 전환 후 무기한 보유']::text[], 1, '지지선 부근에서 고점이 점점 낮아지는 ''디센딩'' 형태는 매수 지원 강도가 둔화되고 매도 출하 공급이 가격을 계속 하방으로 압박하고 있음을 증명합니다. 지지 성공보다 지선 하방 붕괴 후 급락할 확률이 높으므로, 지지선이라는 명목만으로 함부로 매수 진입하지 말고 돌파/이탈 컨펌을 기다려 관망하는 것이 현명합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (739, '거래량/유동성', '05_volume_liquidity.md', '엔비디아 주가가 1,440달러의 장기 저항벽을 거래량이 거의 실리지 않은 얇은 양봉으로 상방으로 살짝 뚫었으나, 바로 다음 날 직전 양봉 몸통을 통째로 덮어버리는 대량 거래량의 장대음봉이 출현하며 1,392달러로 곤두박질쳤습니다. 매수 포지션을 추격 진입했던 당신의 올바른 조치는?', '[{"time":"Day 1","open":1344,"high":1416,"low":1332,"close":1404,"volume":105},{"time":"Day 2","open":1404,"high":1464,"low":1392,"close":1452,"volume":391},{"time":"Day 3","open":1452,"high":1464,"low":1380,"close":1392,"volume":374}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":1440}],"label":"장기 저항선 (120)","color":"#ef4444"}]'::jsonb, ARRAY['불 트랩(Bull Trap) 확인 후 추가 하락 방지 즉시 손절', '저항선 부근 매수세 복귀를 기대하며 전량 홀딩', '평단가 관리 차원에서 추가 물타기 매수 집행', '상황을 판단하기 위해 시장가로 추가 분할 진입']::text[], 0, '거래량 없는 돌파 직후에 거래량 실린 강한 음봉이 기존 돌파선(1,440달러) 아래로 재진입하여 마감하는 현상은 전형적인 불 트랩(Bull Trap/가짜 돌파) 함정입니다. 돌파 당시 샀던 매수자들의 패닉 셀이 출현하며 하락 가속화가 나오기 쉬우므로 즉시 손절하여 물량을 털어내야 생존할 수 있습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (740, '시장구조/SR', '10_psychology_routine_review.md', '주요 지지선(3,000달러선)이 아래로 무너질 때 제때 손절 처리를 하지 못해 엔비디아 주가가 2,640달러선까지 끌려 내려갔습니다. 다행히 단기 매도 진정세로 반등이 나와 엔비디아 주가가 다시 3,000달러 부근까지 상승하여 회복을 눈앞에 두고 있습니다. 이때 손실을 최소화하는 현명한 시나리오 대처법은?', '[{"time":"Day 1","open":3120,"high":3144,"low":2976,"close":2988,"volume":96},{"time":"Day 2","open":2988,"high":3000,"low":2640,"close":2664,"volume":95},{"time":"Day 3","open":2664,"high":2820,"low":2652,"close":2808,"volume":113},{"time":"Day 4","open":2808,"high":3012,"low":2796,"close":2988,"volume":102}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":3000}],"label":"붕괴된 지지선 -> 저항선으로 변형 (250)","color":"#ef4444"}]'::jsonb, ARRAY['역할 전환(저항선) 도달에 따른 탈출 및 현금화', 'V자 반등 성공 확신에 따른 추가 매수 비중 확대', '원금 회복 및 추가 수익 시까지 영구 홀딩 관망', '하락 추세 지속에 따른 반대 숏 포지션 스위칭']::text[], 0, '하방으로 깨진 지지선은 반등할 때 가장 뚫기 힘든 ''강력한 저항선''으로 성격이 바뀝니다. 따라서 손절 기회를 놓치고 물려있던 트레이더는 반등하여 옛 지지선(3,000달러)에 도달했을 때를 ''최선의 리스크 탈출 기회(탈출구)''로 삼아 전량 매도하거나 비중을 극도로 덜어내야 다가올 2차 하락 파동의 파산을 막을 수 있습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (741, '추세/레짐', '03_market_structure.md', '엔비디아 주가가 매우 가파르게 올라가던 1차 단기 상승 추세선을 강한 음봉 종가로 뚫고 내려왔습니다. 다행히 각도가 완만하고 탄탄한 장기 핵심 상승 추세선은 저 밑에 지지 영역을 유지하고 있습니다. 스윙 트레이더로서 가장 정석적인 포지션 제어 방식은 무엇인가요?', '[{"time":"Day 1","open":1200,"high":1224,"low":1200,"close":1224,"volume":85},{"time":"Day 2","open":1224,"high":1320,"low":1224,"close":1308,"volume":94},{"time":"Day 3","open":1308,"high":1500,"low":1308,"close":1488,"volume":93},{"time":"Day 4","open":1488,"high":1500,"low":1368,"close":1380,"volume":129}]'::jsonb, '[{"type":"line","points":[{"x":0,"y":1200},{"x":3,"y":1476}],"label":"가파른 단기 추세선 (붕괴)","color":"#ef4444"},{"type":"line","points":[{"x":0,"y":1200},{"x":3,"y":1320}],"label":"완만한 장기 추세선 (지탱 중)","color":"#10b981"}]'::jsonb, ARRAY['추세 붕괴 판단에 따른 전량 손절 및 영구 이탈', '가속 추세 이탈에 따른 50% 분할 익절 및 분산', '단기 지지선 붕괴를 무시한 고배율 물타기 매수', '장기 추세선까지 조정을 대비한 신규 매수 대기']::text[], 1, '가파르게 우상향하던 가속 추세선(Accelerated Trendline)이 하방 돌파되는 것은 기존 폭등 랠리의 속도가 둔화되고 완만한 본래 장기 추세선(장기 매물대)을 향해 정상적인 가격 조정을 받기 시작했음을 뜻합니다. 따라서 물량의 50%가량을 털어 수익을 실현하고 남은 물량으로 장기 추세선의 3rd Touch 지지 성공 여부를 테스트하는 것이 리스크 관리의 기본입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (742, '거래량/유동성', '05_volume_liquidity.md', '고점과 저점이 연속으로 낮아지는 명확한 하락 평행 채널 내에서 하락 압력을 받아 숏(매도) 포지션을 잡고 수익 중이었습니다. 그런데 당일 캔들이 대량의 거래량과 함께 장대양봉을 그리며 채널 상단 저항선 위로 종가 안착(상방 돌파)했습니다. 숏 포지션을 쥔 당신의 결단은?', '[{"time":"Day 1","open":1200,"high":1224,"low":1080,"close":1104,"volume":89},{"time":"Day 2","open":1104,"high":1128,"low":984,"close":996,"volume":88},{"time":"Day 3","open":996,"high":1020,"low":900,"close":912,"volume":115},{"time":"Day 4","open":912,"high":1080,"low":900,"close":1068,"volume":94}]'::jsonb, '[{"type":"channel","points":[{"x":0,"y":1224},{"x":3,"y":1032},{"x":0,"y":1080},{"x":3,"y":912}],"label":"하락 평행 채널 상한/하한","color":"#f59e0b"}]'::jsonb, ARRAY['상단 돌파 확인 즉시 숏 전량 손절 및 대피', '채널 재진입 기대로 숏 포지션 추가 물타기', '손절 없이 유지하면서 포지션 본전 도달 대기', '포지션 유지 후 증거금을 출금하여 강제 횡보']::text[], 0, '하락 평행 채널의 상단 저항선 상향 돌파(Breakout)는 기존 하락 트렌드의 사멸과 매수세 지배령 복귀를 뜻합니다. 지표와 거래량이 동반된 돌파 확인 시에는 숏 포지션을 지체 없이 기계적으로 칼손절하여 자산을 보호하는 것이 원칙입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (743, '추세/레짐', '07_multitimeframe_regime.md', '우상향하는 상승 평행 채널 안에서 순항하던 엔비디아 주가가 중심선(Mid-line)을 뚫고 하방으로 이탈 마감했습니다. 이후 중심선 부근까지 반등을 시도했으나 재차 저항을 받고 아래꼬리가 꺾여 채널 하단선을 향해 하락 조정을 재개하려 합니다. 신규 매수(롱) 포지션 진입을 계획 중인 트레이더의 대응법은?', '[{"time":"Day 1","open":1200,"high":1296,"low":1188,"close":1272,"volume":92},{"time":"Day 2","open":1272,"high":1344,"low":1224,"close":1248,"volume":110},{"time":"Day 3","open":1248,"high":1272,"low":1176,"close":1200,"volume":112}]'::jsonb, '[{"type":"channel","points":[{"x":0,"y":1320},{"x":2,"y":1344},{"x":0,"y":1176},{"x":2,"y":1200}],"label":"상승 평행 채널","color":"#10b981"}]'::jsonb, ARRAY['채널 내 유지를 기대로 지정가 즉시 매수', '중심선 저항 확인 후 채널 하단 안착 대기', '하방 휩소 판단에 따른 레버리지 추가 매수', '추세와 무관한 숏 포지션 구축 후 관망']::text[], 1, '상승 평행 채널에서 미드라인(Mid-line)은 매우 중요한 심리적 지지와 저항선입니다. 미드라인이 저항선으로 뒤바뀌어 음봉으로 흘러내리는 경우 높은 확률로 채널 하단 경계선까지 가격이 조정을 받게 되므로, 중심선 저항 확인 시점에서는 섣부른 매수 진입을 피하고 채널 하단의 명확한 반등 타점을 유도해야 합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (744, '추세/레짐', '03_market_structure.md', '저점과 저점을 이은 장기 상승 추세선 상의 3번째 터치 포인트(지지선 부근)에 캔들이 매우 조심스럽게 안착하며 아래꼬리를 형성했습니다. 손익비(Risk-to-Reward) 관점에서 가장 이상적인 매수 타점 집행 및 손절 셋업 방법은 무엇입니까?', '[{"time":"Day 1","open":960,"high":1080,"low":960,"close":1056,"volume":95},{"time":"Day 2","open":1056,"high":1188,"low":1056,"close":1140,"volume":87},{"time":"Day 3","open":1140,"high":1152,"low":1080,"close":1104,"volume":91}]'::jsonb, '[{"type":"line","points":[{"x":0,"y":960},{"x":1,"y":1056},{"x":2,"y":1080}],"label":"상승 추세선 (3rd Touch 기대선)","color":"#10b981"}]'::jsonb, ARRAY['손절 라인 없이 지정가로 1차 매수 몰빵 진입', '3rd Touch 타점 진입 및 추세선 하단 칼손절 셋업', '하방 붕괴 예상을 통한 고배율 숏 즉각 진입', '목표가 터치 시까지 무작정 대기 후 추격 매수']::text[], 1, '추세선 상의 3번째 지지 포인트(3rd Touch)는 추세 신뢰도가 형성되는 대단히 성공률 높은 정석적 눌림목 타점입니다. 진입 가격과 손절 라인(추세선 이탈가)의 거리가 매우 가깝기 때문에 기대 수익 대비 잃을 금액이 매우 적어 프로 트레이더들이 가장 선호하는 칼손절 매수 스팟입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (745, '추세/레짐', '08_setup_entry_exit.md', '엔비디아 주가가 장기 하락 추세선을 힘차게 뚫어 상방 돌파(Breakout)했습니다. 하지만 돌파선 바로 위(약 1,440달러)에 최근 여러 번 강한 매도 잔량이 쏟아지며 가격을 찍어 눌렀던 핵심 매물대 저항선이 떡하니 버티고 있습니다. 당신의 신규 진입 매수 순서는 어떻게 결정해야 안전할까요?', '[{"time":"Day 1","open":1500,"high":1512,"low":1320,"close":1344,"volume":93},{"time":"Day 2","open":1344,"high":1356,"low":1176,"close":1200,"volume":97},{"time":"Day 3","open":1200,"high":1428,"low":1188,"close":1416,"volume":95}]'::jsonb, '[{"type":"line","points":[{"x":0,"y":1500},{"x":1,"y":1344},{"x":2,"y":1260}],"label":"하락 추세선 (돌파됨)","color":"#ef4444"},{"type":"horizontal-line","points":[{"x":0,"y":1440}],"label":"수평 매물대 저항선 (120)","color":"#ef4444"}]'::jsonb, ARRAY['돌파 확인 즉시 종가 기준 시장가 100% 매수', '수평 저항 돌파 검증 시까지 매수 유보 및 대기', '돌파 전조 현상 기대로 레버리지 선배팅 집행', '추세선 돌파를 가짜로 간주한 숏 포지션 진입']::text[], 1, '하락 추세선의 돌파는 긍정적이나 수평 매물대 저항선이 바로 위에 있다면 이중 저항 작용에 의해 막히는 경우가 대단히 잦습니다. 추세선 상방 휩소(속임수)에 당하지 않으려면 겹저항 중 최종 관문인 수평 매물대 저항선 돌파 혹은 리테스트 지지를 확인하고 진입하는 것이 보수적이고 안전한 원칙입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (746, '패턴/돌파', '04_patterns_breakout.md', '고점 수평 저항선(1,200달러)과 저점 상승 지지선으로 이루어진 어센딩 트라이앵글 수렴 도중, 1,200달러를 돌파할 것을 미리 예측하고 1,176달러에서 비중 100% 매수로 진입했습니다. 그러나 엔비디아 주가는 돌파에 실패하고 하방 상승 지지선을 대량 거래량 장대음봉으로 뚫어 1,104달러로 하향 마감했습니다. 올바른 매매 액션은?', '[{"time":"Day 1","open":960,"high":1200,"low":960,"close":1140,"volume":100},{"time":"Day 2","open":1140,"high":1200,"low":1056,"close":1164,"volume":96},{"time":"Day 3","open":1164,"high":1176,"low":1092,"close":1104,"volume":111}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":1200}],"label":"수평 저항선 (100)","color":"#ef4444"},{"type":"line","points":[{"x":0,"y":960},{"x":1,"y":1056},{"x":2,"y":1128}],"label":"상승 지지선 (붕괴)","color":"#10b981"}]'::jsonb, ARRAY['하방 이탈 확인 즉시 손절하여 추가 폭락 차단', '조정을 이용해 평단가를 조절하는 분할 물타기', '본전 탈출 시까지 포지션을 유지하며 관망', '손절 라인을 하단으로 조정하고 대기 주문 유지']::text[], 0, '어센딩 트라이앵글은 상방 확률이 다소 높지만, 하단 지지선이 뚫려 무너지는 순간 패턴 실패와 함께 엄청난 실망 매도 매물이 출하됩니다. 특히 돌파를 미리 예견해 들어간 포지션은 즉시 룰 위반을 시정하고 손절(1,104달러)해야 큰 자산 보호를 할 수 있습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (747, '패턴/돌파', '04_patterns_breakout.md', '하락 바닥권에서 왼쪽 어깨, 머리, 오른쪽 어깨를 그리며 역헤드앤숄더(Inverse Head & Shoulders) 패턴이 완성되었습니다. 가격이 넥라인 저항벽(960달러선)을 돌파했으나 이미 장대양봉으로 높이 솟아(1,044달러) 추격 매수 타이밍을 아쉽게 놓쳤습니다. 이때 뇌동매매를 피하는 가장 현명한 매수 타점 공략법은?', '[{"time":"Day 1","open":1140,"high":1140,"low":840,"close":936,"volume":100},{"time":"Day 2","open":936,"high":984,"low":720,"close":900,"volume":105},{"time":"Day 3","open":900,"high":948,"low":816,"close":912,"volume":116},{"time":"Day 4","open":912,"high":1056,"low":900,"close":1044,"volume":92}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":960}],"label":"넥라인 저항선 (80)","color":"#ef4444"}]'::jsonb, ARRAY['포모(FOMO) 현상에 따른 돌파봉 꼭대기 추격 매수', '돌파 넥라인 부근의 리테스트 조정 눌림목 매수', '반등 랠리 종결 판단에 따른 역베팅 숏 포지션', '추세 전환 확인 후 무조건적인 관심종목 제외']::text[], 1, '강한 패턴 돌파봉 확인 후 뇌동매매로 추격하는 것은 손절 거리가 너무 멀어져 손익비가 최악인 나쁜 습관입니다. 정석 돌파 트레이더는 넥라인 역할 전환 지점(960달러)으로의 되돌림 눌림목(Retest)을 차분히 기다려 리스크를 짧게 끊고 들어가는 훈련을 해야 합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (748, '패턴/돌파', '04_patterns_breakout.md', '지속적인 하락 추세 중, 고점과 저점이 수렴하며 우하향하는 하락 쐐기형(Falling Wedge) 패턴의 끝자락에 도달했습니다. 거래량이 급감하다가 마침내 쐐기형 상단 저항선을 상방으로 뚫는 강한 양봉 종가 마감(1,320달러)이 포착되었습니다. 합리적인 매수 진입 시 손절가 설정 기준은 무엇인가요?', '[{"time":"Day 1","open":1560,"high":1584,"low":1320,"close":1344,"volume":99},{"time":"Day 2","open":1344,"high":1392,"low":1224,"close":1248,"volume":112},{"time":"Day 3","open":1248,"high":1296,"low":1176,"close":1200,"volume":105},{"time":"Day 4","open":1200,"high":1344,"low":1188,"close":1320,"volume":111}]'::jsonb, '[]'::jsonb, ARRAY['손절 없이 청산가에 의존하여 장기 홀딩', '상방 돌파 확인 후 진입 및 직전 최저점 손절 셋업', '평단가 개선을 위한 지속적인 분할 물타기 매수', '상단 저항선 돌파 시점을 이용한 숏 포지션 스위칭']::text[], 1, '하락 쐐기형(Falling Wedge)의 상방 돌파는 강력한 반전 신호입니다. 이 패턴의 장점은 진입 즉시 명확하고 짧은 기준점(수렴 바닥 최저가 1,176달러 혹은 돌파봉 하단)을 손절가로 설정할 수 있어, 리스크 한도를 안전하게 통제한 채 상방 랠리를 도모할 수 있다는 점입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (749, '패턴/돌파', '04_patterns_breakout.md', '엔비디아 주가가 약한 매수세와 거래량 급감 속에 고점과 저점을 높이며 좁게 상승 쐐기형(Rising Wedge)을 그리고 있습니다. 현재 가격은 상승 쐐기형 하단 지지선(3,600달러)에 아주 밀착하여 붕괴 위기에 놓여 있습니다. 이 시점에서 롱(매수) 포지션을 들고 있는 트레이더의 리스크 대응은?', '[{"time":"Day 1","open":3120,"high":3360,"low":3120,"close":3336,"volume":105},{"time":"Day 2","open":3336,"high":3540,"low":3264,"close":3480,"volume":18},{"time":"Day 3","open":3480,"high":3660,"low":3576,"close":3612,"volume":32}]'::jsonb, '[{"type":"line","points":[{"x":0,"y":3120},{"x":1,"y":3264},{"x":2,"y":3576}],"label":"쐐기 하단 지지선 (300)","color":"#ef4444"}]'::jsonb, ARRAY['상승 쐐기형 하방 이탈 위험에 따른 롱 포지션 매도', '상승 지속 확신에 따른 레버리지 추가 불타기', '장기 상승 흐름 기대로 손절 없이 무기한 홀딩', '다른 종목으로의 포지션 분산을 위한 관망']::text[], 0, '상승 쐐기형(Rising Wedge)은 약세 세력이 억지로 쥐어짜며 상승 가격을 만드는 패턴으로, 수렴 끝에서 거래량 소멸과 함께 하방 이탈(Breakdown)하여 폭락할 위험이 매우 높은 대표적인 하락 대비 패턴입니다. 하단 지지선 이탈 낌새 시에는 매수 포지션을 전부 도망쳐 나와야 큰 손실을 막을 수 있습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (750, '패턴/돌파', '04_patterns_breakout.md', '둥근 대야 모양의 바닥(Cup)을 그리며 상승 회복한 엔비디아 주가가 전고점 저항벽 부근에서 하향 채널식 완만한 되돌림 조정 핸들(Handle)을 그리는 중입니다. 이후 핸들의 상단 저항선(1,800달러선)을 강한 거래량의 장대양봉으로 상향 돌파했습니다. 이때 합리적인 트레이더의 대응은?', '[{"time":"Day 1","open":1680,"high":1704,"low":1536,"close":1560,"volume":104},{"time":"Day 2","open":1560,"high":1680,"low":1548,"close":1656,"volume":123},{"time":"Day 3","open":1656,"high":1680,"low":1608,"close":1620,"volume":121},{"time":"Day 4","open":1620,"high":1848,"low":1608,"close":1824,"volume":94}]'::jsonb, '[]'::jsonb, ARRAY['핸들 상방 돌파 확인 후 진입 및 핸들 저점 손절', '하락 지속 판단에 따른 즉각적인 전량 손절', '평단가 부근이므로 추가 손절 설정 없이 관망', '돌파 여부 확인 전 고점 돌파 매수 주문 100%']::text[], 0, '전형적인 강세 지속 패턴인 컵앤핸들(Cup & Handle)입니다. 핸들의 하락 조정 채널 상단 돌파는 매물 소화를 성공적으로 완수하고 본 랠리로 진입한다는 강력한 신호입니다. 손익비 관점에서 핸들의 지지 저점인 1,608달러 아래에 안전 손절을 지정한 뒤 진입 시 우수한 기대 수익을 가질 수 있습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (751, '지표/컨플루언스', '06_technical_indicators.md', '강력한 대세 상승 국면인 종목이 일시 조정을 거쳐 전저점 지지 영역(1,200달러)에 도달해 저점을 지키고 있습니다(저점 높임 또는 수평). 그런데 이때 보조지표 RSI의 저점은 이전보다 훨씬 깊게 파여 낮아지는 ''히든 상승 다이버전스(Hidden Bullish Divergence)''가 포착되었습니다. 현명한 의사결정은?', '[{"time":"Day 1","open":1080,"high":1320,"low":1056,"close":1260,"volume":117},{"time":"Day 2","open":1260,"high":1284,"low":1176,"close":1200,"volume":111}]'::jsonb, '[]'::jsonb, ARRAY['하락 전환 신호로 판단하여 전량 즉시 손절', '추세 지속 신호 기대로 지선 부근 추가/신규 매수', '지표 과매수 판단에 따른 계좌 거래 정지', '손절 설정 없이 무제한 레버리지 롱 대응']::text[], 1, '엔비디아 주가의 저점은 높아지는데 보조지표(RSI 등)의 저점은 낮아지는 형태는 ''히든 상승 다이버전스''입니다. 이는 기존의 강력한 상승 트렌드 내부에서 일시 조정을 겪는 매수자들이 활기차게 물량을 주워 담아 다음 상승 랠리를 추진한다는 신호이므로, 짧은 손절 라인(1,176달러)을 설정하고 매수 비중을 태우기 가장 적합한 정석 타점입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (752, '지표/컨플루언스', '07_multitimeframe_regime.md', '엔비디아 주가가 호재와 함께 밴드 상단선 바깥을 타고 계속 상승하는 강력한 볼린저 밴드 밴드워크(Band Walk) 현상이 발생 중이며, RSI는 80을 넘어 극단적 과매수 수치를 가리키고 있습니다. 이 구간에서 취해야 할 가장 합리적인 리스크 및 포지션 관리 행동은?', '[{"time":"Day 1","open":1200,"high":1380,"low":1188,"close":1344,"volume":112},{"time":"Day 2","open":1344,"high":1536,"low":1320,"close":1500,"volume":101},{"time":"Day 3","open":1500,"high":1668,"low":1464,"close":1632,"volume":114}]'::jsonb, '[]'::jsonb, ARRAY['과매수 도달 판단에 따른 고배율 숏 무리한 진입', '추종 손절매(Trailing Stop)를 통한 수익 극대화', '상승폭 만족에 따른 즉각적인 전량 시장가 익절', '손절 가격을 해제하고 시세 지속 시까지 방치']::text[], 1, '강세 추세가 지나치게 강할 경우 볼린저 밴드 상단을 타고 오르는 밴드워크 현상과 RSI 과매수 현상이 영구 유지될 수 있습니다. 이때 단순 과매수 수치를 이유로 숏 포지션을 잡으면 파산합니다. 기존 매수 포지션의 익절선(Trailing Stop)을 상향 관리하여 추세 상승 이익을 극대화하고 신규 진입은 자제하는 것이 정석 리스크 관리입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (753, '지표/컨플루언스', '06_technical_indicators.md', '1시간 봉 차트 상에서 엔비디아 주가가 확실히 낮아졌으나 RSI 저점은 유의미하게 상승한 ''상승 다이버전스''가 확인되어 매수 타점을 노리고 있습니다. 다만 15분 봉 단기 차트에서는 하락 장대음봉 관성이 아직 살아있어 매도 압력이 보입니다. 멀티 타임프레임 트레이더의 진입 의사결정은?', '[{"time":"Hour 1","open":1200,"high":1224,"low":1080,"close":1092,"volume":103},{"time":"Hour 2","open":1092,"high":1104,"low":960,"close":984,"volume":105}]'::jsonb, '[]'::jsonb, ARRAY['단기 음봉 관성 기대로 즉각 숏 포지션 진입', '큰 시간 프레임의 상승 다이버전스 타점 매수', '지표 충돌로 판단하고 시장가 즉시 롱 진입', '변동성 기대로 무작정 도박성 잡코인 진입']::text[], 1, '큰 프레임(1시간 봉)의 다이버전스가 주는 중장기 추세 신뢰도는 작은 프레임의 단기 노이즈보다 압도적으로 강력합니다. 단, 진입 시 타이밍의 정밀도를 높이기 위해 소파동(15분 봉)의 하락 동력이 꺾이고 지지해 주는 단기 확인 캔들이 나오는 찰나에 롱 포지션 타이밍을 잡는 것이 멀티 타임프레임 정석 매매입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (754, '지표/컨플루언스', '06_technical_indicators.md', '엔비디아 주가는 2,400달러 저항대를 뚫고 2,640달러까지 계속 우상향하며 고점을 갱신하고 있으나, MACD 오실레이터의 히스토그램 산 높이는 직전 고점 시점 대비 현저하게 쪼그라들며 꺾여 내려가 하락 다이버전스를 형성 중입니다. 현명한 포지션 보유자의 이익 관리 행동은?', '[{"time":"Day 1","open":2160,"high":2460,"low":2148,"close":2400,"volume":96},{"time":"Day 2","open":2400,"high":2664,"low":2376,"close":2640,"volume":121}]'::jsonb, '[]'::jsonb, ARRAY['추세 지속 확신으로 보유 비중 추가 불타기', '상승 모멘텀 약화 다이버전스 확인 후 50% 익절', '익절 설정 없이 전고점 도달 시까지 홀딩', '고점 붕괴 기대로 숏 포지션 10배 베팅']::text[], 1, '엔비디아 주가는 올라가나 모멘텀 지표인 MACD 오실레이터 고점이 낮아지는 현상은 대표적인 하락 다이버전스로, 매수 에너지가 속 빈 강정처럼 쇠퇴하고 있어 언제든 급격한 폭락 조정이 발생할 수 있는 고위험 신호입니다. 이 시점에는 탐욕을 통제하고 물량의 50% 이상을 분할 매도하여 현금을 챙기는 것이 원칙입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (755, '지표/컨플루언스', '06_technical_indicators.md', '엔비디아 주가가 하락 횡보하던 도중, 단기 지평선인 EMA 20일선이 중장기선인 EMA 50일선에 극도로 밀착하며 수렴했습니다. 당일 대량 거래량의 음봉 캔들이 터지며 단기선이 장기선 아래로 교차하기 직전(데드크로스 임박)이며 주요 지지선 밑으로 떨어졌습니다. 롱(매수) 포지션 보유자의 올바른 대응은?', '[{"time":"Day 1","open":1260,"high":1272,"low":1188,"close":1200,"volume":103},{"time":"Day 2","open":1200,"high":1212,"low":1140,"close":1152,"volume":93}]'::jsonb, '[]'::jsonb, ARRAY['지지선 이탈 및 데드크로스 확인 즉시 손절', '이평선 지지력을 믿고 하방 물타기 추가 매수', '하락 조정 후 반등 기대로 무기한 홀딩 관망', '청산가 도달 시까지 어떠한 대응 없이 방치']::text[], 0, '20일선과 50일선의 데드크로스 임박 수렴 상태에서 가격이 지지선마저 무너뜨린 것은 하락 가속화 추세가 폭발하기 직전인 매우 위험한 기술적 상태입니다. 하락 추세가 본격 정배열(하락 정배열)화 되기 전에 즉시 전량 손절하고 시장 밖에서 피신해 있는 것이 계좌의 영구 파산을 막는 유일한 생존 규칙입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (756, '리스크/심리', '09_risk_position_management.md', '성장주 매수 후 가격이 급락하여 내가 설정해 둔 최대 감내 손실 한도인 계좌 총원금 대비 -2% 라인(손절매 지정 가격)에 완벽하게 닿았습니다. 마침 본전 생각과 함께 ''조금만 더 버티면 반등할 텐데...''하는 강한 뇌동매매 유혹이 솟구칩니다. 이때 원칙 트레이더의 결정은?', '[{"time":"Day 1","open":1200,"high":1224,"low":1188,"close":1200,"volume":109},{"time":"Day 2","open":1200,"high":1212,"low":1128,"close":1140,"volume":115}]'::jsonb, '[]'::jsonb, ARRAY['손절 라인을 임의로 하향 조정하고 홀딩', '평단가 관리 차원의 지속적 물타기 매수 집행', '원칙에 따라 뇌동을 제어하고 즉시 기계적 손절', '손실은 배제하고 반등 기대를 통한 무기한 보유']::text[], 2, '트레이딩의 승패는 예측이 아닌 ''리스크 통제''에 달려 있습니다. 사전에 정한 계좌 대비 2% 리스크 한도에 도달했을 때 희망 회로를 돌리며 손절을 미루거나 물타기를 집행하는 순간 계좌는 서서히 영으로 깎여 파산합니다. 멘탈의 충동을 통제하고 기계적으로 전량 칼손절하는 것이 절대 파산하지 않는 시장의 1법칙입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (757, '리스크/심리', '10_psychology_routine_review.md', '최근 3회 연속 거래에서 계속해서 손절(Stop Loss)을 맞아 뇌 내의 도파민 체계가 무너지고 심리가 극도로 불안해져 분노와 보복 매매 충동이 밀려옵니다. 이 상황에서 파산을 막는 가장 훌륭한 매매 심리 대처법은?', '[{"time":"Today","open":1200,"high":1200,"low":1200,"close":1200}]'::jsonb, '[]'::jsonb, ARRAY['손실 복구를 위해 레버리지를 증액해 즉시 진입', '뇌동 방지를 위해 HTS를 종료하고 매매 일지 작성 및 휴식', '추천 매매 신호 유료 리딩방에 즉시 가입 및 추종', '심리적 회복을 위해 역베팅 숏 포지션 추가']::text[], 1, '연속 손실 후 발생하는 복수심과 분노는 트레이더를 뇌동매매와 계좌 파멸로 이끄는 가장 치명적인 감정 상태입니다. 멘탈 붕괴를 느꼈을 때는 즉각 행동을 멈추고 시스템을 강제 종료하여 시장과 물리적 격리를 통해 냉정을 찾는 것만이 자산을 파산 리스크로부터 살려내는 훌륭한 트레이딩 행동입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (758, '셋업/실행', '09_risk_position_management.md', '진입하고자 하는 매수 자리를 분석해 보니, 기술적 분석 상 이길 수 있는 확률(승률)은 반반인 50% 수준입니다. 그러나 손절 시 기대 손실금액 대비 성공 시 획득할 수 있는 기대 수익금액의 비율(손익비)을 정밀 셋업 해보니 1 : 1.2 수준으로 다소 애매하게 도출되었습니다. 원칙 트레이더의 진입 결정은?', '[{"time":"Today","open":1200,"high":1200,"low":1200,"close":1200}]'::jsonb, '[]'::jsonb, ARRAY['단기 변동성 기대로 부적합한 손익비 시장가 진입', '마이너스 기댓값 거래 유보 및 우수 타점 대기', '레버리지를 높여 손익비 구조를 임의 조정 시도', '반대 방향으로 고배율 역베팅을 즉시 실행']::text[], 1, '수학적으로 승률 50%일 때 손익비가 최소 1:2(잃을 때 1, 벌 때 2) 이상이 나오지 않으면 복리 매매 시 수수료와 호가 슬리피지에 밀려 잔고가 무조건 마이너스로 수렴합니다. 타점이 눈에 들어오더라도 사전에 기대 손익비 필터에 걸려 탈락한다면 패스를 선언하고 관망하는 것이 현명한 생존 원칙입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (759, '리스크/심리', '09_risk_position_management.md', '갑작스러운 거시 경제 발표로 내가 매매 중인 종목의 캔들 변동성 폭(ATR)이 평소 시세의 2배 수준으로 널뛰기 시작했습니다. 1회 거래당 내 계좌 원금의 최대 2% 리스크 한도를 동일하게 고수하기 위해 취해야 할 올바른 조치는?', '[{"time":"Day 1","open":1200,"high":1224,"low":1176,"close":1200,"volume":110},{"time":"Day 2","open":1200,"high":1320,"low":1080,"close":1224,"volume":85}]'::jsonb, '[]'::jsonb, ARRAY['평소 변동성과 동일한 비중 및 손절 거리 고수', '손절 거리를 넓히는 대신 진입 포지션 수량 축소', '변동성이 확대되었으므로 2배 비중으로 적극 지름', '즉시 전량 손절하고 시장 상황 정상화 대기']::text[], 1, '시장 변동성이 커질 때는 손절 스톱 아웃이 잦으므로 손절폭(%)을 넓혀 숨 쉴 공간을 확보해 주는 것이 합리적입니다. 단, 손절폭을 2배로 늘린다면 계좌 대비 리스크 한도가 2배(4%)로 커지므로, 진입 포지션의 계약 수량을 50%로 줄여 리스크 노출 총액을 2%로 완벽하게 동일 통제하는 것이 포지션 사이징(Position Sizing)의 정석 원칙입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (760, '리스크/심리', '09_risk_position_management.md', '투자자 A의 전체 투자 원금은 6,000만 원이며, 1회 거래당 최대 허용 리스크 금액은 원금의 2%인 120만 원입니다. 현재 엔비디아 주가가 120,000원이며, 기술적 분석 상 합리적인 손절선은 지지선 바로 밑인 114,000원(-5%)입니다. 2% 룰 리스크 관리 원칙에 따라 A가 진입(매수)해야 하는 최대 성장주 수량은?', '[{"time":"Today","open":120000,"high":120000,"low":120000,"close":120000}]'::jsonb, '[]'::jsonb, ARRAY['500주 (투자금 전액 시장가 매수)', '200주 (손실 한도 120만 원 맞춤 매수)', '50주 (보수적 극단적 비중 축소)', '100주 (절반 비중 고정 매수)']::text[], 1, '포지션 크기 계산 공식은 `최대 매수 규모 = 최대 허용 리스크 금액 / 손절매 비율` 입니다. 이 시나리오에서 `1,200,000원 / 0.05(5%) = 24,000,000원`이 최대 허용 진입금액이 되며, 이를 엔비디아 주가 120,000원으로 나누면 `200주`가 도출됩니다. 200주 진입 후 -5% 가격 폭락으로 손절 당해도 내 총원금에서 깎이는 돈은 정확히 120만 원(2%)으로 완벽히 리스크 통제됩니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (761, '거래량/유동성', '05_volume_liquidity.md', '엔비디아 주가가 수평 저항선 부근까지 급상승했으나 캔들 몸통(Spread)이 지극히 좁아진 도지 형태로 마감하였고, 거래량은 이전 5일 평균 대비 3배 이상 폭증했습니다. VSA(Volume Spread Analysis) 관점에서 가장 타당한 차트 분석은?', '[{"time":"Day 1","open":1200,"high":1260,"low":1188,"close":1248,"volume":86},{"time":"Day 2","open":1248,"high":1308,"low":1236,"close":1296,"volume":99},{"time":"Day 3","open":1296,"high":1320,"low":1284,"close":1296,"volume":120}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":1308},{"x":2,"y":1308}],"label":"저항선","color":"#ef4444"}]'::jsonb, ARRAY['강한 매수 기세 기대로 즉시 돌파 매매 풀매수', '저항벽 매도 공급 세력 분산 확인 후 이익 실현', '대량 거래 확인에 따른 손절 해제 후 장기 투자', '반등 실패에 따른 고배율 보복 숏 베팅 가동']::text[], 1, '캔들 몸통 크기(스프레드)가 좁은데 거래량이 매우 크게 폭증했다는 것은 저항선 부근에서 들어오는 매수세만큼 세력의 매도 물량 공급이 쏟아져 막강한 저항 벽을 형성하고 있다는 뜻입니다. VSA에서는 이를 불화(Disharmony)로 규정하며 상승 추세 감속 및 하락 반전의 경고로 해독합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (762, '거래량/유동성', '05_volume_liquidity.md', '엔비디아 주가가 장기 횡보하던 박스권 지지선인 2,400달러를 깨고 2,340달러까지 하락 투매가 발생했으나, 종가 마감 직전 거래량이 크게 실린 긴 아래꼬리를 그리며 다시 2,412달러 위로 복귀 안착했습니다. 이 스톱 헌팅 유동성 현상에서의 실전 트레이더의 대응은?', '[{"time":"Day 1","open":2520,"high":2544,"low":2400,"close":2424,"volume":81},{"time":"Day 2","open":2424,"high":2448,"low":2340,"close":2412,"volume":118}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":2400},{"x":1,"y":2400}],"label":"지지선","color":"#10b981"}]'::jsonb, ARRAY['지지선 붕괴 확정으로 간주한 시장가 숏 추격', '스윕(sweep) 판단 하에 아래꼬리 저점 손절 잡고 롱', '아무런 신호도 아니라고 판단하고 포지션 방치', '지지선 이탈 기대로 전량 손절 후 시장 영구 탈출']::text[], 1, '지지선 아래에 걸려 있던 개인들의 손절 주문(Sell Stop)을 강제로 청산(Liquidity Sweep)시킨 뒤, 세력이 물량을 헐값에 다 받아 삼켜 종가를 지지선 위로 신속하게 복귀시킨 휩소(베어 트랩) 패턴입니다. 아래꼬리 극점(2,340달러)에 아주 좁은 손절 라인을 설정할 수 있어, 기대 손익비가 극대화되는 고확률 상승 반전 매수 타점입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (763, '거래량/유동성', '05_volume_liquidity.md', '엔비디아 주가는 3,000달러에서 3,480달러까지 계속 고점을 높이며 상승 추세를 이어가고 있습니다. 그러나 각 상승 파동마다 터지는 거래량은 전고점 돌파 시점 대비 눈에 띄게 하향 곡선을 그리며 감소하고 있습니다. VSA 기법에 따른 합리적인 진단은?', '[{"time":"Wave 1","open":2760,"high":3120,"low":2736,"close":3060,"volume":85},{"time":"Wave 2","open":3060,"high":3300,"low":3000,"close":3240,"volume":96},{"time":"Wave 3","open":3240,"high":3480,"low":3180,"close":3456,"volume":115}]'::jsonb, '[]'::jsonb, ARRAY['가격 상승으로 인한 매수 지속 강화 초강세', '매도 물량 고갈에 따른 무중력 안심 홀딩', '신규 자금 유입 둔화 거래량 다이버전스로 분할 익절', '지표 조작으로 판단하여 매매 중단 및 차트 종료']::text[], 2, '엔비디아 주가는 상승하여 신고점을 갱신하지만 파동별 거래량이 지속 감소하는 흐름은 ''거래량 다이버전스''로 상승 모멘텀의 내부 엔진이 식어감을 경고합니다. 조만간 가벼운 매도 포격에도 대규모의 차익 실현 폭락 조정이 발생할 수 있는 잠재적 폭락 국면이므로 물량을 덜어내고 현금을 확보해야 합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (764, '거래량/유동성', '05_volume_liquidity.md', '가격이 이전 고점 저항선을 뚫고 강하게 솟구치며 장대양봉을 만들었습니다. 이때 가짜 이탈(Whipsaw / Bull Trap)이 아닌 진성 돌파(True Breakout)로 판정할 수 있는 가장 신뢰도 높은 거래량 기준은?', '[{"time":"Day 1","open":1200,"high":1224,"low":1188,"close":1200,"volume":338},{"time":"Day 2","open":1200,"high":1344,"low":1188,"close":1320,"volume":378}]'::jsonb, '[]'::jsonb, ARRAY['수렴 끝자락에서 거래량이 최저치인 상태 유지', '평균 대비 1.5~2배 이상 거래량 급증하며 돌파 마감', '거래량이 전혀 변하지 않는 평이한 상태 유지', '호가 스프레드가 가장 좁아지는 횡보 상태']::text[], 1, '참된 저항 돌파(True Breakout)는 저항선 부근의 두터운 대기 매도 공급 물량을 대규모 자금으로 전부 씹어 삼키고 돌파해야 함을 뜻합니다. 따라서 반드시 평균 대비 1.5배~2배 이상의 거래량 분출이 동반되어야 신뢰할 수 있으며, 거래량이 적은 돌파는 꼬리 달고 내려앉는 불 트랩(Bull Trap)일 확률이 매우 높습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (765, '거래량/유동성', '05_volume_liquidity.md', '엔비디아 차트에서 중요 지지선 직전 저점 아래에 엄청난 규모의 롱 포지션 청산 및 매도 손절 주문이 쌓여 있는 유동성 풀(Liquidity Pool) 구간이 감지되었습니다. 세력이 이 구간을 공략할 때 나타날 캔들의 전형적인 무빙 패턴은?', '[{"time":"Day 1","open":600000,"high":606000,"low":590400,"close":594000,"volume":31},{"time":"Day 2","open":594000,"high":597600,"low":576000,"close":595200,"volume":25}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":590400},{"x":1,"y":590400}],"label":"전저점 지지선","color":"#3b82f6"}]'::jsonb, ARRAY['지지선을 장대음봉으로 돌파하여 20% 폭락 마감', '전저점 이탈로 손절 유도 후 지지선 위 아래꼬리 안착', '오차 없이 지지선 터치 후 꼬리 없는 수평 도지 횡보', '거래량 없이 즉각 상승 빔 분출로 전고점 탈환']::text[], 1, '기관 세력(스마트 머니)은 대량 포지션을 구축하기 위해 개인의 손절 주문(Sell Stop)을 의도적으로 터트려 매도 유동성을 유도한 후 이를 다 매수합니다. 이로 인해 엔비디아 주가는 지지선 아래로 일시 급락 후(스톱 헌팅), 아래꼬리를 매우 길게 달며 지선 안쪽으로 급반등 마감하게 됩니다. 이것이 유동성 스윕(Liquidity Sweep)의 정석 패턴입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (766, '거래량/유동성', '05_volume_liquidity.md', '상승 추세 도중 전고점 저항선 부근에서 위꼬리가 아주 긴 캔들이 터졌고, 거래량은 최근 보름 중 최고 수치로 솟구쳤습니다. VSA 관점에서 이 상승 거절(Upside Rejection) 현상에 대한 올바른 대처는?', '[{"time":"Day 1","open":1200,"high":1380,"low":1176,"close":1212}]'::jsonb, '[]'::jsonb, ARRAY['강한 저점 매수 기회로 인지하여 비중 대폭 추가', '고점 매도 Rejection 확인 후 기존 롱 포지션 대피', '박스 횡보 수렴 기대로 마틴게일 추가 매수 가동', '이평선 정배열 판단에 따른 포지션 변경 없이 홀딩']::text[], 1, '위꼬리가 매우 긴 캔들이 대량 거래량과 함께 터졌다는 것은 고점 돌파 시도가 있었으나 그 자리에 숨어 있던 세력의 막강한 청산 매도 벽(Supply)을 만나 격렬하게 두들겨 맞고 밀려났음을 의미합니다. 상방 거절의 심리가 지배적이므로 고점 피로 및 하락 전환이 임박한 위험 징후입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (767, '지표/컨플루언스', '06_technical_indicators.md', '엔비디아 주가가 장기 박스권 횡보를 이어가며 볼린저 밴드의 폭이 최근 몇 달 중 가장 좁은 형태로 밀착 수렴(Squeeze)되었습니다. 이 스퀴즈 국면에 대한 올바른 기술적 이해와 매매 시나리오는?', '[{"time":"Week 1","open":1200,"high":1236,"low":1164,"close":1212,"volume":87},{"time":"Week 2","open":1212,"high":1224,"low":1188,"close":1200,"volume":86}]'::jsonb, '[]'::jsonb, ARRAY['박스권 변동성 부재 기대로 장기 무대응 관망', '에너지 수축 스퀴즈 확인 후 밴드 이탈 돌파 대기', '지표 신뢰 불가 판단으로 볼린저 밴드 지표 삭제', '중심선 지지로 판단하여 고배율 매수 대기 주문']::text[], 1, '볼린저 밴드의 폭이 극도로 좁아지는 스퀴즈(Squeeze) 현상은 시장의 표준편차 변동성이 임계치까지 압축 수렴되었음을 알려줍니다. 에너지 압축 뒤에는 항상 폭발적인 가격 분출(상방/하방 이탈)이 뒤따르므로, 밴드를 뚫고 거래량이 실려 돌파 마감하는 방향으로 추세 추종 시나리오를 설계해야 합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (768, '지표/컨플루언스', '06_technical_indicators.md', '엔비디아 주가는 HL(Higher Low)을 형성하며 이전 직전 저점(1,080달러)보다 높은 저점(1,140달러)을 지키고 있으나, RSI 지표는 이전 35 수치보다 더 깊숙하게 25 수치까지 떨어졌습니다. 이 지표 불일치 현상의 공식 명칭과 올바른 포지션 셋업은?', '[{"time":"Day 1","open":1200,"high":1224,"low":1080,"close":1092,"volume":90},{"time":"Day 2","open":1092,"high":1152,"low":1140,"close":1140,"volume":109}]'::jsonb, '[]'::jsonb, ARRAY['일반 상승 다이버전스 - 추세 종결로 즉각 공매도', '히든 상승 다이버전스 - 지선 눌림목 롱 진입 활용', '일반 하락 다이버전스 - 모든 매수 포지션 정리', '지표 오작동 휩소 구간 판단으로 양방향 관망']::text[], 1, '가격의 저점은 높아졌는데(Higher Low) 모멘텀 지표의 저점은 낮아지는 현상은 ''히든 상승 다이버전스(Hidden Bullish Divergence)''입니다. 이는 추세 반전이 아닌 **기존 강세 추세 지속**을 뜻하며, 조정 눌림목이 완성되고 다음 상승 랠리를 준비한다는 최고의 매수 신호 중 하나입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (769, '지표/컨플루언스', '06_technical_indicators.md', '매수 타점을 신중하게 선별하고자 합니다. 기술적 분석의 성공 확률을 비약적으로 끌어올리는 ''다중 컨플루언스(Confluence)'' 결합 사례로 가장 적합한 조건 구성은?', '[{"time":"Today","open":1200,"high":1200,"low":1200,"close":1200}]'::jsonb, '[]'::jsonb, ARRAY['트위터 및 뉴스의 호재 찌라시 확인 즉시 추격', '지지선+이평선+다이버전스+아래꼬리 등 분석 중첩 시', 'RSI 과매수 영역 진입 즉시 롱 포지션 진입', '독립적 분석 없이 오직 보조지표의 단일 수치 신호']::text[], 1, '다중 컨플루언스(Confluence)는 독립적인 기술적 근거들이 동일한 특정 가격 구역에 중첩되는 현상입니다. 지지 저항, 이평선, 보조지표 다이버전스, 캔들 가격행동(Rejection 핀바)이 한 곳에 묶여 매수 자리를 형성할 때 매매를 실행하면, 높은 신뢰도와 좁은 손절 라인 덕분에 장기 기대값이 극대화됩니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (770, '셋업/실행', '08_setup_entry_exit.md', '중요 수평 저항선(1,440달러)을 상방으로 장대양봉 종가 돌파한 것을 확인하고 롱(매수) 진입 셋업을 준비하고 있습니다. 원칙 트레이더가 뇌동매매 추격을 막고 최상의 손익비를 확보하기 위해 즐겨 쓰는 정석적인 진입 실행법은?', '[{"time":"Day 1","open":1320,"high":1344,"low":1308,"close":1332,"volume":90},{"time":"Day 2","open":1332,"high":1488,"low":1320,"close":1464,"volume":118}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":1440},{"x":1,"y":1440}],"label":"저항선","color":"#ef4444"}]'::jsonb, ARRAY['돌파 마감 확인 즉시 시장가 추가 매수 집행', '돌파된 저항선의 지지 전환(Retest) 시 지정가 진입', '반등 조정이 불가능하다고 판단하여 최고점 롱 추격', '속임수 돌파 확신으로 고배율 역베팅 숏 진입']::text[], 1, '저항 돌파 후 즉시 가격을 따라붙는 추격 매수는 휩소 조정 시 심각한 손실을 초래합니다. 돌파된 라인이 S/R Flip을 통해 지지로 작용하는지 확인하는 되돌림 리테스트(Retest) 시점에 진입하는 것이, 지선 바로 아래에 좁은 손절 라인을 설계하고 이익 기대 폭을 넓힐 수 있는 가장 이상적인 정석 실행법입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (771, '셋업/실행', '08_setup_entry_exit.md', '포지션 진입 직후, 가격이 계획대로 내 방향으로 순탄하게 우상향하고 있습니다. 기존 진입 시 설정한 손익비 1:2의 최종 목표가 도달 전에, 리스크 관리 차원에서 계좌 드로다운을 0으로 만드는 정석적인 1차 포지션 관리 행동은?', '[{"time":"Entry","open":1200,"high":1200,"low":1200,"close":1200,"volume":110},{"time":"Day 1","open":1200,"high":1272,"low":1200,"close":1260,"volume":94}]'::jsonb, '[]'::jsonb, ARRAY['1차 저항대 진입 시 레버리지를 활용해 불타기', '목표가 터치 시까지 100% 비중 무대응 홀딩', '1:1 지점 50% 분할 익절 및 남은 물량 본전 손절 상향', '단기 반등 확인 즉시 전량 기계적 청산 및 퇴장']::text[], 2, '이득이 발생해 손익비 1:1 수준에 오면 물량의 절반을 분할 익절(Scale-out)하고 남은 포지션의 스톱로스를 진입가로 이동(Break-even)시키는 것이 포지션 관리의 기본입니다. 이렇게 셋업하면 차트가 갑자기 폭락세로 뒤집혀도 최소 본전 혹은 반절 익절 약수익으로 끝나 해당 거래의 최대 리스크가 Zero(0)로 봉쇄됩니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (772, '셋업/실행', '08_setup_entry_exit.md', '강력한 장기 상승 추세가 터져 엔비디아 주가가 20일 이평선을 타고 계속해서 폭발적으로 신고가를 갱신하고 있습니다. 이때 익절 시점을 서둘러 잡지 않고, 추세 상승 이익을 최대한 길게 끝까지 빨아먹기 위한 정석 청산 실행법은?', '[{"time":"Day 1","open":1200,"high":1320,"low":1188,"close":1296,"volume":115},{"time":"Day 2","open":1296,"high":1440,"low":1284,"close":1416,"volume":88},{"time":"Day 3","open":1416,"high":1620,"low":1404,"close":1584,"volume":112}]'::jsonb, '[]'::jsonb, ARRAY['RSI 과과열 조짐 확인 즉시 시장가 전량 익절', 'Higher Low 지지 직하방으로 손절 추종 익절 셋업', '이익 보존을 포기하고 손익절 라인을 해제 후 홀딩', '즉시 숏 포지션 10배로 맞불을 놓는다']::text[], 1, '강세 추세가 터졌을 때 지레짐작으로 청산하면 상승 파동의 초입만 먹고 끝납니다. 추세 붕괴의 명확한 신호(BOS/MSB)가 나오거나, 가격의 구조적 높은 저점(HL)이 깨질 때까지 손절 라인을 계속 추종해서 상향하는 ''추격 손절매(Trailing Stop)''를 가동하는 것이 추세 이익을 극대화하는 정석 기법입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (773, '셋업/실행', '01_chart_market_basics.md', '차트 분석 결과, 돌파 시점의 체결 변동성과 거래소 호가창의 얇은 매물 상태를 감안할 때 내가 진입하려는 주문 가격에서 체결이 뒤로 밀리는 ''슬리피지(Slippage)''가 심각하게 예상됩니다. 이를 감안한 올바른 주문 실행법은?', '[{"time":"Today","open":1200,"high":1200,"low":1200,"close":1200}]'::jsonb, '[]'::jsonb, ARRAY['시장가로 최고 배율을 설정하여 즉시 체결', '돌파 확인 후 지정가 대기 주문으로 단가 조절', '슬리피지를 예방하기 위해 즉각적인 거래 취소', '호가창 스프레드와 무관하게 고배율 레버리지']::text[], 1, '변동성이 크고 호가가 얇은 시장에서 돌파 시 시장가 진입은 나쁜 단가로 체결되는 슬리피지 비용을 발생시켜 시작부터 손실을 크게 안고 갑니다. 돌파 확인 후 되돌림 가격대에서 지정가(Limit Order)를 대기시켜 체결 단가를 내 손아귀에 고정하는 리스크 관리가 필요합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (774, '셋업/실행', '10_psychology_routine_review.md', '원칙 기반의 정석 매매 셋업(Trading Setup)을 설계할 때, 진입 전 반드시 사전에 수치로 명문화되어 결정되어야 할 요소가 아닌 것은?', '[{"time":"Today","open":1200,"high":1200,"low":1200,"close":1200}]'::jsonb, '[]'::jsonb, ARRAY['진입 조건(Trigger)과 구체적인 손절 가격(Stop Loss)', '거래 당일 본인의 주관적인 직감과 감정적 목표가', '진입하려는 구체적인 포지션 규모 및 분할 익절선', '거래 아이디어가 무효화되는 구체적 가격 지점']::text[], 1, '매매 셋업은 규칙에 기반한 수치들(진입가, 손절가, 목표가, 수량)로 사전에 철저히 규격화되어야 합니다. 당일의 운이나 주관적 느낌, 예감에 기초한 비과학적 청산 설정은 셋업에서 배제되어야 할 대표적 뇌동매매 요소입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (775, '셋업/실행', '08_setup_entry_exit.md', '하락 횡보하던 엔비디아 주가가 중요 매물대이자 피보나치 되돌림 0.618 지점에 정확히 맞닿아 아래꼬리가 긴 양봉 핀바(Pin Bar)를 그리며 마감했습니다. 룰베이스 트레이더가 진입 버튼을 누를 때 성립된 IF-THEN 시나리오는?', '[{"time":"Day 1","open":1200,"high":1200,"low":960,"close":984,"volume":87},{"time":"Day 2","open":984,"high":1032,"low":936,"close":1020,"volume":89}]'::jsonb, '[]'::jsonb, ARRAY['익일 가격 상황과 관계없이 100배 레버리지 진입', '중첩 자리 핀바(rejection) 확인 후 익일 시가 롱 진입', '상단 저항 도달 판단으로 즉각적인 숏 포지션 진입', '돌파 랠리가 완전히 끝날 때까지 HTS 종료 및 관망']::text[], 1, '훌륭한 트레이딩 실행은 ''IF(조건 만족 시) ➔ THEN(원칙대로 포지션 진입 및 손절/목표가 기계적 배치)''의 룰베이스 알고리즘에 의해 움직여야 감정을 배제할 수 있습니다. 지지 구간 중첩과 핀바 출현 조건이 성립했으므로 다음 봉 시가에 진입하되 꼬리 저점 이탈 시 칼손절하여 리스크를 통제하는 것이 정석입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (776, '리스크/심리', '09_risk_position_management.md', '나의 트레이딩 시스템 승률이 40%로 다소 낮게 고정되어 있습니다. 이 시스템을 통해 장기적으로 파산하지 않고 복리로 계좌 자산을 우상향시키기 위해 필수적으로 지켜야 할 손익비(평균손실 대비 평균수익 비율)의 최소 기준은?', '[{"time":"Today","open":1200,"high":1200,"low":1200,"close":1200}]'::jsonb, '[]'::jsonb, ARRAY['손익비 1:1 수준 (매매 승률이 낮을 때 파산)', '승률 40% 대비 기댓값 개선을 위한 손익비 1:1.5 이상', '낮은 승률 상태에서 손익비와 무관하게 무조건 파산', '승률 극복을 위한 레버리지 20배 수준 설정']::text[], 1, '승률이 40%일 때 기대값 수학적 수수료 감안 최소 손익비는 1:1.5입니다. 손익비 1.5배 이상 구간만 취하면 10번 중 6번 손절당하고 단 4번만 익절하더라도 계좌 총합은 수익 우위에 서게 됩니다. 저승률 시스템일수록 철저히 손익비가 유리한 진입가 근처 타점만 기계적으로 필터링해 진입해야 생존합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (777, '리스크/심리', '09_risk_position_management.md', '선물 트레이더인 B는 담보금 효율을 극대화한다는 명목으로 50배 레버리지 롱 포지션 진입을 실행했습니다. 진입 가격 대비 B의 포지션 원금이 완전 소멸(강제 청산)되는 역방향 하락 거리(%)는 대략 몇 % 수준입니까?', '[{"time":"Today","open":1200,"high":1200,"low":1200,"close":1200}]'::jsonb, '[]'::jsonb, ARRAY['진입 단가 대비 20.0%의 강한 하락 발생 시', '진입 단가 대비 단 -2.0% 변동성 노이즈 터치 시', '진입 단가 대비 50.0%의 강한 폭락 발생 시', '청산가가 산출되지 않는 특이 종목 거래 시']::text[], 1, '청산 거리 계산 공식은 대략 `100% / 레버리지 배수` 입니다. 50배 고배율 레버리지의 경우, 내 포지션 반대 방향으로 단 **-2%**의 시세 변동성(장중 흔한 잔파동 노이즈)만 터치해도 원금이 100% 강제 청산 증발됩니다. 고배율 레버리지는 수학적 확률상 100% 파멸을 초래하는 도박성 거래 행위입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (778, '리스크/심리', '09_risk_position_management.md', '트레이딩 계좌 총자산이 24,000만 원인 트레이더가 있습니다. 1회 거래당 총자산의 2% 룰 원칙에 근거하여 리스크 한도(480만 원)를 설정했습니다. 진입하려는 종목의 손절가 거리가 -8%인 경우, 2% 룰을 완벽하게 충족하는 최대 진입(매수) 금액은?', '[{"time":"Today","open":1200,"high":1200,"low":1200,"close":1200}]'::jsonb, '[]'::jsonb, ARRAY['24,000만 원 전액 매수 (손절 폭을 배제한 대규모 베팅)', '6,000만 원 진입 (-8% 손절 시 리스크 한도 480만 원 충족)', '12,000만 원 진입 (손익비 1:1 기준에 맞춘 베팅)', '2,400만 원 진입 (보수적 원칙에 입각한 극단적 축소)']::text[], 1, '포지션 사이징 공식은 `진입금액 = 최대 리스크 허용액(480만 원) / 손절 비율(0.08)` 입니다. 이에 따라 `4,800,000원 / 0.08 = 60,000,000원`이 도출됩니다. 6,000만 원 규모로 매수 진입 시 가격이 급락해 -8% 손절 라인을 때려도 내 총자산에서 깎이는 금액은 정확히 원칙 한도인 480만 원(2%)으로 제한되어 계좌가 완벽히 방어됩니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (779, '리스크/심리', '10_psychology_routine_review.md', '장중에 내가 째려보며 타점을 기다리던 성장주이 아무런 조정도 없이 장대양봉을 그리며 갑자기 수직 폭등하기 시작하여 5% 이상 치솟았습니다. 이때 머릿속에 ''나만 두고 날아가는 것 아닌가''하는 극심한 소외감 공포(FOMO)가 솟구칩니다. 원칙 트레이더의 올바른 심리 대응은?', '[{"time":"Day 1","open":1200,"high":1224,"low":1188,"close":1200,"volume":103},{"time":"Day 2","open":1200,"high":1272,"low":1200,"close":1260,"volume":103}]'::jsonb, '[]'::jsonb, ARRAY['추세 연장 판단으로 시장가 전액 추격 매수', 'FOMO 판단 하에 매수 보류 및 정석 되돌림 타점 대기', '돌파 실패 판단 하에 반대 방향 고배율 숏 베팅', '거래를 종료하고 즉각 성장주 시장에서 전량 탈출']::text[], 1, '나만 기회를 잃는다는 공포(FOMO)로 날아가는 장대양봉 꼭대기에서 추격 매수하는 행위는 고점 물리기를 자처하는 가장 흔한 뇌동매매 패턴입니다. 내 타점을 비껴간 상승은 내 돈이 아니라고 인정하고, 사전에 정의한 룰베이스 타점까지 냉정하게 대기하는 것이 장기 생존자의 멘탈 습관입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (780, '리스크/심리', '10_psychology_routine_review.md', '오전 거래에서 원칙을 어긴 무리한 진입으로 인해 3회 연속 스톱아웃(손절)을 당하여 당일 원금의 -6%의 큰 손실을 입었습니다. 본전 생각과 분노로 눈이 뒤집혀 비중을 올려 한 판으로 복수하려는 ''보폭 매매'' 충동이 폭발할 때, 파산을 막는 가장 강력한 멘탈 시스템 룰은?', '[{"time":"Today","open":1200,"high":1200,"low":1200,"close":1200}]'::jsonb, '[]'::jsonb, ARRAY['손실 만회를 위해 빌린 돈으로 100배 고배율 복수 베팅', '일일 손실 한도 도달에 따른 매매 강제 종료 및 격리', '주변 유료 전문가 추천 종목을 탐색해 즉각 매수', 'RSI 과매도 상태이므로 즉시 반대 숏 포지션 진입']::text[], 1, '연패를 겪은 후 홧김에 비중을 더 크게 실어 한 번에 본전을 찾으려는 보복 매매는 계좌를 하루 만에 휴지조각으로 만드는 가장 무서운 파산 유도 심리 상태입니다. 이를 막기 위해 하루 최대 손실 한도 한계선(예: 3회 손절 또는 원금의 5%)을 정해두고, 이 한계선 터치 시 즉시 차트를 종료하고 냉각기를 강제 집행하는 룰이 필수입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (801, '캔들/가격행동', '02_candlestick_price_action.md', '하락 추세 지속 도중 바닥권에서 몸통이 짧고 아래꼬리가 몸통의 2배 이상인 아래 캔들이 출현했습니다. 이 캔들의 명칭과 올바른 대응은?', '[{"time":"10:00","open":2400,"high":2440,"low":2360,"close":2380,"volume":99},{"time":"10:15","open":2380,"high":2400,"low":2260,"close":2280,"volume":92},{"time":"10:30","open":2280,"high":2300,"low":2160,"close":2180,"volume":123},{"time":"10:45","open":2180,"high":2200,"low":2020,"close":2040,"volume":124},{"time":"11:00","open":2040,"high":2060,"low":1800,"close":2020,"volume":112}]'::jsonb, '[]'::jsonb, ARRAY['역망치형 (Inverted Hammer) - 하락 경고 및 공매도 대기', '망치형 (Hammer) - 저점 지지 및 분할 매수 대기', '도지 (Doji) - 매수세와 매도세의 팽팽한 균형 및 관망', '하락 장악형 (Bearish Engulfing) - 추세 반전 및 즉시 손절']::text[], 1, '마지막 캔들은 아래꼬리가 긴 ''망치형(Hammer)'' 캔들로 하락 압력을 이겨내고 저가 매수세가 밀어 올렸음을 의미하는 대표적 상승 전환 신호입니다. 지지를 확인한 뒤 분할 매수 관점으로 대기해야 합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (802, '캔들/가격행동', '02_candlestick_price_action.md', '리플 시세가 장기간 급등한 뒤, 고점 부근에서 위꼬리가 매우 길고 몸통이 짧은 형태의 캔들이 발생했습니다. 이 캔들의 해석으로 가장 적절한 것은?', '[{"time":"Day 1","open":2000,"high":2160,"low":1980,"close":2100,"volume":118},{"time":"Day 2","open":2100,"high":2300,"low":2080,"close":2240,"volume":84},{"time":"Day 3","open":2240,"high":2500,"low":2220,"close":2460,"volume":98},{"time":"Day 4","open":2460,"high":2560,"low":2400,"close":2520,"volume":128},{"time":"Day 5","open":2520,"high":2900,"low":2500,"close":2540,"volume":119}]'::jsonb, '[]'::jsonb, ARRAY['유성형 (Shooting Star) - 고점 저항 및 하락 전환 예고', '망치형 (Hammer) - 저점 매수세 유입 및 상승 랠리 기대', '상승 장악형 (Bullish Engulfing) - 추세 반전 및 홀딩 유도', '도지 (Doji) - 추세 지속 가능성 및 일시 관망']::text[], 0, '급등세 끝에서 위꼬리가 몸통보다 훨씬 길게 솟아오른 캔들은 ''유성형(Shooting Star)''입니다. 장중 상승 시도를 강력한 차익 실현 및 매도 압력이 짓눌렀음을 보여주며, 하락 추세 전환의 강력한 경고 시그널입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (803, '캔들/가격행동', '02_candlestick_price_action.md', '직전의 음봉 몸통을 다음 날의 거대한 양봉 몸통이 완전히 감싸 안는 아래 형태가 포착되었습니다. 이 패턴의 이름과 신뢰도는?', '[{"time":"Day 1","open":1960,"high":2000,"low":1900,"close":1920,"volume":106},{"time":"Day 2","open":1920,"high":1940,"low":1840,"close":1860,"volume":112},{"time":"Day 3","open":1860,"high":1900,"low":1760,"close":1780,"volume":92},{"time":"Day 4","open":1740,"high":2040,"low":1720,"close":2020,"volume":126}]'::jsonb, '[]'::jsonb, ARRAY['하락 장악형 (Bearish Engulfing) - 추세 반전 신뢰도 낮음', '상승 장악형 (Bullish Engulfing) - 매수 전환 신뢰도 높음', '상승 관통형 (Piercing Line) - 중간 강도의 반전 신호', '석별형 (Evening Star) - 상승 추세 종결 신호']::text[], 1, '전일의 하락 음봉 몸통을 다음 날의 장대 양봉이 완전히 덮어버리는 형태를 ''상승 장악형(Bullish Engulfing)'' 패턴이라고 합니다. 하락 추세 끝에서 나타날 경우 단기 하락세가 종료되고 강력한 매수세가 들어왔음을 뜻해 전환 신뢰도가 매우 높습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (804, '캔들/가격행동', '01_chart_market_basics.md', '시가와 종가가 거의 일치하여 몸통이 거의 없고 위아래 꼬리만 달린 십자(+) 모양 캔들이 출현했습니다. 이 캔들에 대한 올바른 해석은?', '[{"time":"Day 1","open":3000,"high":3100,"low":2960,"close":3040,"volume":102},{"time":"Day 2","open":3040,"high":3120,"low":3020,"close":3080,"volume":85},{"time":"Day 3","open":3080,"high":3180,"low":3000,"close":3080,"volume":106}]'::jsonb, '[]'::jsonb, ARRAY['상승세 동력 상실로 인한 추세의 하방 반전', '매수/매도 세력 균형에 따른 도지(Doji) 횡보', '매도세 지배에 따른 즉각적인 숏 포지션 진입', '하락 세력 이탈로 인한 즉각적인 상승 랠리']::text[], 1, '시가와 종가가 거의 같은 십자 모양의 캔들은 ''도지(Doji)'' 캔들입니다. 이는 힘의 균형이 팽팽함을 시사하며, 기존 추세의 힘이 빠지고 잠재적인 방향성 전환(상승/하락 모두 포함)의 변곡점이 다가오고 있음을 의미합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (805, '캔들/가격행동', '02_candlestick_price_action.md', '상승 추세 고점에서 직전 양봉의 몸통을 거대 음봉이 아래로 덮어버리는 캔들 조합이 발생했습니다. 이 현상을 의미하는 용어는?', '[{"time":"Day 1","open":2400,"high":2500,"low":2380,"close":2480,"volume":80},{"time":"Day 2","open":2480,"high":2600,"low":2460,"close":2580,"volume":118},{"time":"Day 3","open":2600,"high":2620,"low":2300,"close":2320,"volume":103}]'::jsonb, '[]'::jsonb, ARRAY['하락 장악형 (Bearish Engulfing) - 고점 하락 전환 예고', '상승 장악형 (Bullish Engulfing) - 고점 돌파 랠리 예고', '하락 잉태형 (Harami) - 기존 하락세의 일시 둔화', '샛별형 (Morning Star) - 바닥권 상승 반전 예고']::text[], 0, '고점에서 직전 양봉을 음봉이 감싸 안은 형태는 ''하락 장악형(Bearish Engulfing)''입니다. 매수 세력을 매도 공급이 압도했다는 명백한 증거로, 리플 시세 추세가 하락으로 반전할 리스크가 큽니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (806, '시장구조/SR', '03_market_structure.md', '리플 시세가 장기 저항선인 3,000달러를 거래량 실린 강한 캔들로 돌파한 뒤, 다시 3,000달러 부근으로 내려와 버티고 있습니다. 가장 안전한 진입 방식은?', '[{"time":"Day 1","open":2800,"high":2960,"low":2780,"close":2900,"volume":90},{"time":"Day 2","open":2900,"high":2980,"low":2860,"close":2880,"volume":117},{"time":"Day 3","open":2880,"high":3120,"low":2860,"close":3080,"volume":123},{"time":"Day 4","open":3080,"high":3100,"low":2980,"close":3020,"volume":378},{"time":"Day 5","open":3020,"high":3060,"low":3000,"close":3040,"volume":369}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":3000},{"x":4,"y":3000}],"label":"돌파된 저항선 -> 지지선 전환선","color":"#3b82f6"}]'::jsonb, ARRAY['돌파 시점에 시장가로 즉시 진입하는 추격 매수', '돌파 후 저항선의 지지선 전환(Retest) 확인 시 진입', '이전 최저가 부근인 2,800달러 조정 시까지 대기 매수', '돌파 후 즉시 단기 조정을 예상한 역추세 숏 진입']::text[], 1, '저항선이 강하게 뚫리면 역할 전환(Role Reversal)에 의해 신규 지지선으로 바뀝니다. 돌파 시점에 뇌동매매하기보다는 돌파된 선 부근으로 리플 시세가 눌려 지지(Retest)를 완성할 때 진입하는 것이 리스크 대비 기대 수익이 큽니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (807, '거래량/유동성', '05_volume_liquidity.md', '리플 시세가 저항선 위로 거래량 없이 장대양봉을 뿜어 올렸으나, 다음 날 곧바로 장대음봉으로 밀어붙이며 저항선 아래로 내려왔습니다. 이 현상의 명칭은?', '[{"time":"Day 1","open":1960,"high":2020,"low":1940,"close":2000,"volume":113},{"time":"Day 2","open":2000,"high":2040,"low":1980,"close":2020,"volume":114},{"time":"Day 3","open":2020,"high":2200,"low":2000,"close":2160,"volume":18},{"time":"Day 4","open":2160,"high":2180,"low":1900,"close":1920,"volume":16}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":2040},{"x":3,"y":2040}],"label":"저항선","color":"#ef4444"}]'::jsonb, ARRAY['진짜 상승 돌파 (True Breakout)', '불 트랩 (Bull Trap) - 매수자 청산 유도 가짜 돌파', '베어 트랩 (Bear Trap) - 매도자 청산 유도 가짜 하방', '골든 크로스 (Golden Cross) - 이평선 돌파']::text[], 1, '저항선을 일시적으로 뚫었다가 대량 매도세와 함께 직후 캔들에서 하방으로 원상복귀하는 현상을 ''불 트랩(Bull Trap/가짜 돌파)''이라고 합니다. 돌파 후 리테스트를 기다리지 않고 급히 추격 매수했던 투자자들이 고점에 물리는 대표적 함정입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (808, '시장구조/SR', '01_chart_market_basics.md', '아래 차트에서 3번 연속 강하게 반등하며 가격 하락을 저지해 준 주요 가격대는 무엇을 의미하나요?', '[{"time":"Day 1","open":2000,"high":2040,"low":1800,"close":1820,"volume":101},{"time":"Day 2","open":1820,"high":1960,"low":1800,"close":1940,"volume":116},{"time":"Day 3","open":1940,"high":2100,"low":1920,"close":2080,"volume":97},{"time":"Day 4","open":2080,"high":2120,"low":1820,"close":1840,"volume":114},{"time":"Day 5","open":1840,"high":2000,"low":1800,"close":1980,"volume":98}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":1800},{"x":4,"y":1800}],"label":"1,800달러선","color":"#10b981"}]'::jsonb, ARRAY['강력한 저항선 (Resistance Line) - 매도 매물대', '강력한 지지선 (Support Line) - 매수 매물대', '골든크로스 수렴선 - 이평선 밀집대', '이격도 붕괴선 - 가격 과열 분기점']::text[], 1, '특정 가격(1,800달러)에 접근할 때마다 대기 중이던 저가 매수세가 유입되어 리플 시세의 추가 하락을 방어해 준 이 라인은 ''강력한 지지선(Support Line)''입니다. 이탈하기 전까지는 손절 라인을 바로 밑에 두고 진입하기에 가장 손익비 좋은 구간입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (809, '거래량/유동성', '05_volume_liquidity.md', '지지선 아래로 리플 시세가 이탈하여 공매도가 폭증했으나, 이내 거래량이 급증하며 양봉으로 지지선을 회복한 뒤 반등을 시작했습니다. 이 현상의 명칭은?', '[{"time":"Day 1","open":2400,"high":2440,"low":2360,"close":2380,"volume":82},{"time":"Day 2","open":2380,"high":2400,"low":2200,"close":2220,"volume":104},{"time":"Day 3","open":2220,"high":2460,"low":2200,"close":2440,"volume":126}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":2300},{"x":2,"y":2300}],"label":"지지선","color":"#10b981"}]'::jsonb, ARRAY['불 트랩 (Bull Trap) - 가짜 상방 돌파', '베어 트랩 (Bear Trap) - 가짜 하방 이탈', '리테스트 실패 - 지지선 붕괴', '추세 추종 돌파 - 하방 랠리 가속']::text[], 1, '지지선을 아래로 뚫고 내려가 하락세가 지속될 것처럼 유도한 뒤, 매물을 털어내고 강력하게 다시 반등해 올리는 현상을 ''베어 트랩(Bear Trap)''이라고 합니다. 하락 돌파로 생각하고 공매도를 치거나 손절했던 사람들의 손실을 강제하며 가격이 급등하게 만듭니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (810, '시장구조/SR', '04_patterns_breakout.md', '저항선을 뚫어내기 직전 돌파 전조 현상 중 하나인 ''지지점 상승''의 특징을 골라보세요.', '[{"time":"Day 1","open":2000,"high":2100,"low":1800,"close":2040,"volume":82},{"time":"Day 2","open":2040,"high":2100,"low":1860,"close":2060,"volume":119},{"time":"Day 3","open":2060,"high":2100,"low":1920,"close":2080,"volume":103}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":2100},{"x":2,"y":2100}],"label":"저항선 (105)","color":"#ef4444"}]'::jsonb, ARRAY['저항선 부근에서 고점들이 점점 급락하며 붕괴하는 현상', '저항선 부근에서 저점들을 높여가며 밀어 올리는 수렴 현상', '거래량이 완전히 소멸하여 긴 횡보 상태를 보이는 현상', '지속적인 매도세로 인해 갑작스럽게 급락하는 현상']::text[], 1, '저항을 뚫지 못하고 밀려 내려올 때, 이전 저점보다 높은 지점에서 저점을 계속 잡아 올려주는 것은 매도 압력보다 매수 압력이 점점 올라오고 있음을 의미합니다. 수렴 끝에 돌파가 나타날 신뢰도가 매우 높습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (811, '추세/레짐', '03_market_structure.md', '저점들을 연결한 우상향 상승 추세선 아래로 캔들의 종가(마감가격)가 이탈했습니다. 기술적 분석 관점의 올바른 해석은 무엇입니까?', '[{"time":"W-5","open":2000,"high":2100,"low":2000,"close":2060,"volume":93},{"time":"W-4","open":2060,"high":2200,"low":2040,"close":2160,"volume":108},{"time":"W-3","open":2160,"high":2180,"low":2100,"close":2120,"volume":111},{"time":"W-2","open":2120,"high":2300,"low":2140,"close":2260,"volume":118},{"time":"Today","open":2260,"high":2280,"low":2060,"close":2080,"volume":112}]'::jsonb, '[{"type":"line","points":[{"x":0,"y":2000},{"x":2,"y":2100},{"x":4,"y":2200}],"label":"상승 추세선","color":"#10b981"}]'::jsonb, ARRAY['추세선 이탈은 영향이 없으므로 비중 유지', '상승 추세 붕괴로 하락 반전 대비 비중 축소', '일시적인 속임수이므로 추가 불타기 진입', '채널 상단 도달에 따른 즉각적인 매수 대응']::text[], 1, '신뢰받던 우상향 상승 추세선 하방으로 캔들의 종가가 이탈 마감하는 것은 매수 중심의 시장 주도권이 붕괴했음을 뜻합니다. 지지를 잃은 하락 가속화 리스크에 대비해야 합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (812, '추세/레짐', '07_multitimeframe_regime.md', '아래 차트에서 고점들과 저점들이 일정한 평행 통로를 그리며 하락하고 있습니다. 채널 하단에 도달했을 때 단기 반등을 목표로 하는 매매의 명칭과 관점은?', '[{"time":"Day 1","open":3000,"high":3040,"low":2700,"close":2800,"volume":87},{"time":"Day 2","open":2800,"high":2940,"low":2780,"close":2900,"volume":119},{"time":"Day 3","open":2900,"high":2920,"low":2560,"close":2600,"volume":125},{"time":"Day 4","open":2600,"high":2760,"low":2580,"close":2720,"volume":119},{"time":"Day 5","open":2720,"high":2740,"low":2360,"close":2400,"volume":100}]'::jsonb, '[{"type":"channel","points":[{"x":0,"y":3000},{"x":4,"y":2700},{"x":0,"y":2700},{"x":4,"y":2400}],"label":"하향 평행 채널","color":"#f59e0b"}]'::jsonb, ARRAY['추세 추종 매매 - 대세 상승이므로 장기 보유', '채널 하단 반등 매매 - 단기 역추세 매수 대응', '양방향 물타기 매매 - 평단가를 낮춰 탈출 대기', '돌파 매매 - 채널 하방 붕괴 확정 시 매수 대응']::text[], 1, '가격이 평행한 하락 터널 내에서 움직이는 ''하향 평행 채널(Descending Channel)''입니다. 채널 하단 라인 터치 시에는 기술적 단기 반등이 자주 출현하므로, 손절선을 짧게 잡고 반등 타점을 노리는 역추세(Counter-trend) 트레이딩이 가능합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (813, '추세/레짐', '03_market_structure.md', '우상향 상승 평행 채널의 상단 저항선 부근까지 리플 시세가 도달했습니다. 합리적인 추세 채널 트레이더의 대응은?', '[{"time":"Day 1","open":2000,"high":2040,"low":1980,"close":2020,"volume":114},{"time":"Day 2","open":2020,"high":2160,"low":2020,"close":2140,"volume":90},{"time":"Day 3","open":2140,"high":2180,"low":2080,"close":2100,"volume":89},{"time":"Day 4","open":2100,"high":2300,"low":2100,"close":2280,"volume":102},{"time":"Day 5","open":2280,"high":2320,"low":2240,"close":2260,"volume":114}]'::jsonb, '[{"type":"channel","points":[{"x":0,"y":2040},{"x":4,"y":2300},{"x":0,"y":1980},{"x":4,"y":2240}],"label":"상승 평행 채널","color":"#10b981"}]'::jsonb, ARRAY['채널 상방 돌파를 예상한 고배율 레버리지 매수', '채널 상단 저항에 따른 분할 익절 및 대기', '채널 중간 조정 시 지정을 통한 시장가 추격', '채널 붕괴 신호에 따른 전량 기계적 손절']::text[], 1, '상승 채널이라고 해도 상단 저항선에 닿으면 다시 채널 하단이나 중심선까지 조정을 받을 가능성이 매우 큽니다. 따라서 고점 영역에서의 추격매수를 금지하고, 기존 포지션을 분할 익절하는 기회로 삼아야 합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (814, '추세/레짐', '01_chart_market_basics.md', '고점들을 잇는 우하향 하락 추세선을 리플 시세가 대량의 거래량을 동반하며 장대양봉 종가로 상향 돌파(Breakout)했습니다. 의미하는 시그널은?', '[{"time":"Day 1","open":2600,"high":2640,"low":2500,"close":2540,"volume":108},{"time":"Day 2","open":2540,"high":2560,"low":2400,"close":2440,"volume":100},{"time":"Day 3","open":2440,"high":2460,"low":2300,"close":2340,"volume":107},{"time":"Day 4","open":2340,"high":2560,"low":2320,"close":2540,"volume":95}]'::jsonb, '[{"type":"line","points":[{"x":0,"y":2620},{"x":2,"y":2440},{"x":3,"y":2360}],"label":"하락 추세선","color":"#ef4444"}]'::jsonb, ARRAY['하락 추세 지속에 따른 숏 포지션 추가 매수', '하락 추세 돌파 및 상승 전환 가능성에 따른 매수', '속임수 돌파를 예상한 즉시 반대 숏 포지션 진입', '추세와 무관하게 횡보 흐름으로 판단해 관망']::text[], 1, '중요한 하락 추세선을 리플 시세 몸통이 확실하게 뚫고 마감하는 것은 기존 하락 관성의 지배력이 종료되고 상승 추세로 돌아설 수 있는 가장 대표적인 추세 전환(Reversal) 확인 시그널입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (815, '추세/레짐', '03_market_structure.md', '추세선 작도 시 신뢰도를 판단하는 가장 중요한 규칙은 무엇인가요?', '[{"time":"Day 1","open":2000,"high":2020,"low":2000,"close":2020,"volume":84},{"time":"Day 2","open":2020,"high":2100,"low":2040,"close":2080,"volume":86}]'::jsonb, '[]'::jsonb, ARRAY['차트상 선이 정배열로 정돈되어 그려질 때', '최소 3개 이상의 뚜렷한 저점/고점 터치 확인 시', '가파른 각도로 90도에 가깝게 작도될 때', '보조지표와 결합하여 수평으로 그려질 때']::text[], 1, '두 점만으로도 선을 그릴 수 있지만, 3번째 터치(3rd Touch)에서 정확한 지지나 저항을 보이고 반등해 주는 순간부터 시장 참여자들이 공식 인지하는 신뢰도 높은 추세선이 됩니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (816, '패턴/돌파', '04_patterns_breakout.md', '머리와 양쪽 어깨 형태를 그리며 넥라인 지지선(1,920달러)을 위태롭게 지탱하다가 하방으로 강한 캔들이 이탈했습니다. 숏(매도) 포지션 진입 시점은?', '[{"time":"Day 1","open":2000,"high":2300,"low":1960,"close":2200,"volume":102},{"time":"Day 2","open":2200,"high":2600,"low":1900,"close":2100,"volume":92},{"time":"Day 3","open":2100,"high":2280,"low":1920,"close":2200,"volume":123},{"time":"Day 4","open":2200,"high":2220,"low":1860,"close":1880,"volume":96}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":1920},{"x":3,"y":1920}],"label":"넥라인 지지선","color":"#ef4444"}]'::jsonb, ARRAY['머리 꼭대기(2,600달러) 부근에서 예측 숏 진입', '오른쪽 어깨가 올라가고 있을 때 돌파 전 선진입', '저점들을 연결한 넥라인의 하방 돌파 완료 시', '패턴 완성과 무관하게 오른쪽 어깨 끝에서 대기']::text[], 2, '헤드앤숄더(Head & Shoulders) 패턴은 오른쪽 어깨를 그린 후, 저점 지지선인 ''넥라인(Neckline)''을 거래량을 실어 하방 돌파해야 최종 완성이 선언됩니다. 그전에 진입하면 넥라인 반등 시 극심한 손실을 입습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (817, '패턴/돌파', '04_patterns_breakout.md', '하락 추세 끝에서 리플 시세가 비슷한 깊이의 바닥을 두 번(이중바닥) 형성한 뒤, 중간 고점 저항선(넥라인)을 돌파했습니다. 향후 예상 방향성과 매수 타점은?', '[{"time":"Day 1","open":2000,"high":2000,"low":1600,"close":1700,"volume":91},{"time":"Day 2","open":1700,"high":1900,"low":1680,"close":1880,"volume":85},{"time":"Day 3","open":1880,"high":1900,"low":1580,"close":1640,"volume":108},{"time":"Day 4","open":1640,"high":1980,"low":1620,"close":1960,"volume":93}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":1900},{"x":3,"y":1900}],"label":"넥라인 (95)","color":"#3b82f6"}]'::jsonb, ARRAY['추가 폭락 가능성에 따른 전량 손절 대응', 'W 패턴 이중 바닥 완성 및 넥라인 돌파 시 매수', '박스권 횡보 판단에 따른 무대응 및 관망', '이중 바닥의 하방 이탈을 예상한 숏 포지션 진입']::text[], 1, 'W자 모양의 ''이중 바닥형(Double Bottom)'' 패턴입니다. 리플 시세가 하락을 멈추고 바닥을 두 차례 단단히 지지해 준 뒤 중간 봉우리(넥라인 1,900달러)를 돌파해 마감하면 추세가 상승으로 강하게 전환될 가능성이 매우 높습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (818, '패턴/돌파', '04_patterns_breakout.md', '급격한 기둥식 리플 시세 폭등(깃대) 후, 완만한 하향 평행 채널(깃발) 모양으로 횡보/수렴하다가 채널 상단을 강하게 돌파했습니다. 이 패턴과 예상 목표가는?', '[{"time":"Day 1","open":1000,"high":1600,"low":980,"close":1560,"volume":110},{"time":"Day 2","open":1560,"high":1580,"low":1440,"close":1480,"volume":96},{"time":"Day 3","open":1480,"high":1520,"low":1400,"close":1420,"volume":121},{"time":"Day 4","open":1420,"high":1700,"low":1400,"close":1660,"volume":120}]'::jsonb, '[]'::jsonb, ARRAY['이중 천정형 패턴 - 고점 도달 시 숏 진입', '불 플래그 패턴 - 깃발 돌파 시 추가 상승 기대', '헤드앤숄더 패턴 - 넥라인 하방 돌파 타겟', '대칭 삼각수렴 패턴 - 변동성 축소 후 돌파 대기']::text[], 1, '대표적 강세 지속 패턴인 ''불 플래그(Bull Flag)''입니다. 급격한 상승(깃대) 뒤 숨 고르기 채널(깃발)을 상방 돌파하면, 이전 상승 파동의 크기(깃대 높이)만큼 추가로 수직 랠리를 시작하는 관성이 있습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (819, '패턴/돌파', '04_patterns_breakout.md', '상승 추세의 천정권에서 리플 시세가 동일한 가격 저항을 두 번 확인하며 M자 모양을 만든 뒤, 두 고점 사이의 저점 지지선인 넥라인(2,400달러)을 이탈했습니다. 올바른 해석은?', '[{"time":"Day 1","open":2000,"high":2800,"low":1980,"close":2700,"volume":119},{"time":"Day 2","open":2700,"high":2720,"low":2400,"close":2440,"volume":85},{"time":"Day 3","open":2440,"high":2800,"low":2420,"close":2760,"volume":92},{"time":"Day 4","open":2760,"high":2780,"low":2300,"close":2320,"volume":130}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":2400},{"x":3,"y":2400}],"label":"넥라인 (120)","color":"#ef4444"}]'::jsonb, ARRAY['상승 추세의 지속 연장에 따른 추가 매수', '이중 천정형(M 패턴) 완성에 따른 하락 반전 대비', '단기 조정에 따른 일시적 횡보 박스권 진입', '방향성 없는 일상적인 잔파동으로 판단해 홀딩']::text[], 1, '고점에서 지지받지 못하고 형성된 M자형 ''이중 천정형(Double Top)'' 패턴입니다. 두 차례 강력한 저항벽(2,800달러)을 넘지 못하고 넥라인(2,400달러)마저 붕괴했으므로 하방 추세가 가속화된다는 신호입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (820, '패턴/돌파', '04_patterns_breakout.md', '고점 저항선은 수평(평평함)을 유지하고 있으나, 저점 지지선은 점점 우상향하며 좁게 수렴하는 차트 형태의 명칭과 일반적인 돌파 방향은?', '[{"time":"Day 1","open":1600,"high":2000,"low":1600,"close":1900,"volume":90},{"time":"Day 2","open":1900,"high":2000,"low":1720,"close":1960,"volume":96},{"time":"Day 3","open":1960,"high":2000,"low":1840,"close":1980,"volume":88}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":2000},{"x":2,"y":2000}],"label":"수평 저항선","color":"#ef4444"},{"type":"line","points":[{"x":0,"y":1600},{"x":1,"y":1720},{"x":2,"y":1840}],"label":"상승 지지선","color":"#10b981"}]'::jsonb, ARRAY['디센딩 트라이앵글 - 일반적으로 하방 돌파 기대', '어센딩 트라이앵글 - 매수 압력 우위로 상방 돌파 기대', '헤드앤숄더 패턴 - 넥라인 하방 돌파 기대', '상향 평행 채널 - 상하단 터치식 채널 매매 기대']::text[], 1, '고점 저항은 평평하고 저점은 계속 높아지는 삼각수렴을 ''어센딩 트라이앵글(Ascending Triangle)''이라고 합니다. 위로 갈수록 저점이 계속 올라가는 현상은 매수세가 가격을 위로 계속 압박하고 있음을 증명하며, 대개 저항선(2,000달러)을 상향 뚫고 오르는 확률이 높습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (821, '지표/컨플루언스', '06_technical_indicators.md', '리플 시세는 매일 하락하여 신저가를 갱신하고 있으나, RSI 보조지표의 저점은 점점 높아지는 현상을 발견했습니다. 올바른 용어와 매매 대응법은?', '[{"time":"D-4","open":2200,"high":2240,"low":1960,"close":2000,"volume":98},{"time":"D-3","open":2000,"high":2080,"low":1920,"close":1960,"volume":120},{"time":"D-2","open":1960,"high":2020,"low":1840,"close":1880,"volume":99},{"time":"D-1","open":1880,"high":1940,"low":1860,"close":1920,"volume":126},{"time":"Today","open":1920,"high":1980,"low":1900,"close":1960,"volume":125}]'::jsonb, '[]'::jsonb, ARRAY['하락 다이버전스 - 가격 상승 둔화에 따른 공매도', '상승 다이버전스 - 하락 둔화 및 반등 신호로 매수', '데드 크로스 - 이평선 하방 교차에 따른 관망', '과매수 이탈 시그널 - 단기 반등에 따른 매수']::text[], 1, '리플 시세의 가격 저점은 낮아지나 보조지표(RSI)의 운동 저점이 높아지는 현상을 ''상승 다이버전스(Bullish Divergence)''라고 합니다. 이는 하방 에너지의 실질적 소멸과 상승 압력의 내부 응축을 의미하는 기술적 분석에서 가장 신뢰도 높은 추세 전환 시그널입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (822, '지표/컨플루언스', '06_technical_indicators.md', '리플 시세는 급격히 치솟으며 최고가 갱신 랠리를 이어가고 있으나, RSI 지표의 고점은 계속 낮아지고 있습니다. 이 현상을 지칭하는 명칭과 대처법은?', '[{"time":"Day 1","open":2000,"high":2400,"low":1980,"close":2360,"volume":111},{"time":"Day 2","open":2360,"high":2440,"low":2300,"close":2400,"volume":94},{"time":"Day 3","open":2400,"high":2700,"low":2380,"close":2660,"volume":91}]'::jsonb, '[]'::jsonb, ARRAY['하락 다이버전스 - 매수 둔화 및 하락 우려로 익절', '상승 다이버전스 - 추가 급등 기대로 신규 매수', '골든 크로스 - 추세 강화에 따른 홀딩', '볼린저 밴드 스퀴즈 - 변동성 수축 후 돌파']::text[], 0, '리플 시세는 계속 고점을 높이고 있으나 보조지표의 고점은 꺾여 낮아지는 현상을 ''하락 다이버전스(Bearish Divergence)''라고 합니다. 이는 매수세의 힘이 표면적인 가격 상승에 비해 실질적으로 빠르게 축소되고 있음을 경고하며, 조만간 큰 급락이 발생할 확률이 높습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (823, '지표/컨플루언스', '06_technical_indicators.md', '이동평균선(EMA) 20일선(단기)이 50일선(중기)을 아래에서 위로 강하게 뚫고 솟구쳐 올랐습니다. 이 교차 현상의 정식 명칭은?', '[{"time":"Day 1","open":2000,"high":2040,"low":1960,"close":1980,"volume":110},{"time":"Day 2","open":1980,"high":2080,"low":1980,"close":2060,"volume":109},{"time":"Day 3","open":2060,"high":2200,"low":2060,"close":2180,"volume":123}]'::jsonb, '[]'::jsonb, ARRAY['데드 크로스 - 단기 이평의 하방 교차로 매도 신호', '골든 크로스 - 단기 이평의 상방 교차로 매수 신호', '볼린저 스퀴즈 - 변동성 수축 및 돌파 신호', '다이버전스 수렴 - 지표와 가격의 동반 횡보']::text[], 1, '단기 이평선이 장기 이평선을 위로 치고 올라가는 현상을 ''골든 크로스(Golden Cross)''라고 합니다. 이는 최근 매수 평단가가 장기 평균가보다 확연히 높아졌음을 시사하며, 상승 추세가 본 궤도에 올랐음을 입증해 줍니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (824, '지표/컨플루언스', '07_multitimeframe_regime.md', '매우 강력한 원웨이 폭락장 속에서 RSI 지표가 20(과매도 영역) 이하로 깊이 내려왔습니다. 이를 보고 ''과매도 반등''을 노리며 기계적 시장가 풀매수를 때렸을 때 나타나는 가장 빈번한 오류는?', '[{"time":"Day 1","open":2000,"high":2020,"low":1760,"close":1780,"volume":108},{"time":"Day 2","open":1780,"high":1800,"low":1500,"close":1520,"volume":34},{"time":"Day 3","open":1520,"high":1540,"low":1240,"close":1260,"volume":16}]'::jsonb, '[]'::jsonb, ARRAY['하락 추세 즉시 종료 및 V자 상승 반등 성공', '강력한 하락장에서의 지표 과매도 고착화 리스크', '거래량 급감으로 인한 호가 정지 및 상장 폐지', '리플 시세의 즉각적인 박스권 횡보 및 변동성 축소']::text[], 1, 'RSI 30 이하 과매도 영역은 반등 신호이기도 하지만, 추세가 지나치게 강력한 하락장일 때는 지표만 과매도 구역에 쳐박힌 채 가격은 계속 급락하는 ''과매도 고착화(Oversold Embedded)'' 상태가 이어집니다. 다이버전스나 캔들 반전형 확인 없이 수치만 보고 들어가는 매수는 깡통으로 가는 지름길입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (825, '지표/컨플루언스', '06_technical_indicators.md', '리플 시세의 변동성이 극도로 축소되며 볼린저 밴드의 폭이 매우 좁아지는 ''스퀴즈(Squeeze)'' 현상이 나타났습니다. 이후 기대되는 시장 변동성의 원리는 무엇인가요?', '[{"time":"Day 1","open":2000,"high":2020,"low":1980,"close":2000,"volume":109},{"time":"Day 2","open":2000,"high":2000,"low":1980,"close":1980,"volume":120},{"time":"Day 3","open":1980,"high":2000,"low":1980,"close":2000,"volume":104}]'::jsonb, '[]'::jsonb, ARRAY['변동성 사멸로 인한 장기 횡보 및 거래 정지', '밴드 스퀴즈 후 변동성 팽창에 따른 추세 분출', '리플 시세의 하방 붕괴로 인한 강한 하락 파동 시작', '이평선들의 수평 정렬에 따른 완전한 추세 고정']::text[], 1, '볼린저 밴드의 수축(Squeeze)은 시장의 숨 고르기 및 힘 모으기를 뜻합니다. 에너지가 최대한 압축된 후에는 밴드 상단 혹은 하단선을 이탈하며 매우 거대한 변동성 팽창(Expansion) 추세가 시작되므로, 방향성을 유심히 지켜봐야 합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (826, '리스크/심리', '09_risk_position_management.md', '총 투자 원금은 20,000만 원이며, 1회 거래 시 최대 손실 허용액을 원금의 2%(400만 원)로 제한하는 ''2% 룰''을 지키려 합니다. 진입하려는 종목의 손절 라인 폭이 -5%일 때, 최대 매수(진입) 가능 금액은 얼마인가요?', '[{"time":"Day 1","open":200000,"high":210000,"low":196000,"close":204000,"volume":96},{"time":"Day 2","open":204000,"high":206000,"low":200000,"close":200000,"volume":109}]'::jsonb, '[]'::jsonb, ARRAY['20,000만 원 (원금 전액 진입)', '4,000만 원 (원금의 20% 진입)', '8,000만 원 (원금의 40% 진입)', '10,000만 원 (원금의 50% 진입)']::text[], 2, '2% 룰에 기초한 포지션 사이징 공식은 `진입금액 = (총원금 * 리스크비율) / 손절비율` 입니다. 따라서 `400만 원 / 0.05 = 8,000만 원`이 됩니다. 8,000만 원어치 메이저 코인을 샀을 때 가격이 -5% 떨어져 강제 손절을 맞아도 내 계좌 총액에서 손실을 보는 돈은 정확히 2%인 400만 원으로 통제됩니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (827, '리스크/심리', '09_risk_position_management.md', '어느 메이저 코인에 200,000원에 매수 진입합니다. 손절 라인은 190,000원(-5%)에 배치하고, 목표가는 230,000원(+15%)에 설정했습니다. 이 트레이딩 시나리오의 손익비(Risk-to-Reward Ratio)는 얼마입니까?', '[{"time":"Today","open":200000,"high":200000,"low":200000,"close":200000}]'::jsonb, '[]'::jsonb, ARRAY['1 : 1 (동일한 기대 수익과 리스크)', '1 : 2 (기대 수익이 리스크의 2배)', '1 : 3 (기대 수익이 리스크의 3배)', '2 : 1 (기대 수익이 리스크의 0.5배)']::text[], 2, '손절 폭(10,000원) 대비 익절 폭(30,000원)의 비례를 의미하므로 `1,500 / 500 = 3`, 즉 손익비는 1:3이 됩니다. 이처럼 잃는 돈의 최소 2~3배를 벌 수 있는 손익비 높은 구간만 반복적으로 거래해야 장기적으로 계좌가 생존합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (828, '리스크/심리', '09_risk_position_management.md', '손익비를 엄격히 통제하여 항상 기대 손실의 2배를 버는 매매(손익비 1:2)만 고집합니다. 이 경우 내 계좌 잔고가 손실 없이 제자리걸음(본전)을 유지하기 위해 필요한 수학적인 최소 승률(Win Rate)은 얼마인가요?', '[{"time":"Today","open":2000,"high":2000,"low":2000,"close":2000}]'::jsonb, '[]'::jsonb, ARRAY['50.0% (최소 절반 이상 성공)', '33.3% (3번 중 1번 성공으로 본전)', '25.0% (4번 중 1번 성공으로 본전)', '66.6% (3번 중 2번 성공으로 본전)']::text[], 1, '손익비가 1:2일 경우, 1번 이기면 +2를 벌고 2번 지면 -2를 잃으므로 3번 매매 중 1번만 이겨도 누적 수익은 0이 됩니다. 즉 손익비를 1:2 이상으로 유지하면 수학적으로 승률이 겨우 33.3%만 나와도 절대 파산하지 않고 계좌가 우상향할 발판이 마련됩니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (829, '셋업/실행', '08_setup_entry_exit.md', '200,000원에 산 메이저 코인이 300,000원까지 올랐습니다. 이익을 보존하면서 상승세를 끝까지 타기 위해, 최고점 대비 10% 하방 이탈 시 즉시 자동 익절되는 ''추적 손절매(Trailing Stop)''를 적용했습니다. 최고점 300,000원 달성 후 리플 시세가 조정받을 때 실제로 청산(익절)되는 가격은 얼마인가요?', '[{"time":"Day 1","open":200000,"high":240000,"low":198000,"close":238000,"volume":118},{"time":"Day 2","open":238000,"high":300000,"low":236000,"close":296000,"volume":88}]'::jsonb, '[]'::jsonb, ARRAY['200,000원 (본전 수준 청산)', '270,000원 (최고점 대비 10% 하방 청산)', '280,000원 (최고점 대비 6.6% 하방 청산)', '240,000원 (최고점 대비 20% 하방 청산)']::text[], 1, '추적 손절매(Trailing Stop)는 가격 상승에 따라 청산 가격을 자동으로 올려주는 주문입니다. 최고점 300,000원을 기록했으므로 청산 트리거 라인은 최고점에서 10% 차감된 `15,000 * 0.9 = 270,000원`으로 확정 셋업되며, 리플 시세가 270,000원을 건드리는 순간 자동 이익실현됩니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (830, '리스크/심리', '09_risk_position_management.md', '레버리지 10배를 적용하여 리플 롱(매수) 포지션을 구축했습니다. 만약 리플 가격이 매수가 대비 몇 % 역방향으로 등락하면 내 투자 원금이 100% 강제 청산(증거금 완전 소멸)당할까요?', '[{"time":"Today","open":1000000,"high":1002000,"low":998000,"close":1000000}]'::jsonb, '[]'::jsonb, ARRAY['5.0% 하락 시', '10.0% 하락 시', '20.0% 하락 시', '100.0% 하락 시']::text[], 1, '레버리지 비율과 청산 거리 비율은 역수 관계입니다. `100% / 레버리지 배수` 공식에 따라, 10배 레버리지는 리플 시세가 내 베팅의 반대 방향으로 단 10%만 움직여도 투자 원금이 전부 증발하고 포지션이 강제 종료(Liquidation)됩니다. 고배율 레버리지가 파산의 지름길인 이유입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (831, '캔들/가격행동', '02_candlestick_price_action.md', '상승 추세 고점 영역(3,000달러선)에서 몸통이 매우 작고 아래꼬리가 긴 행잉맨(Hanging Man) 캔들이 출현한 이후, 다음 날 시가가 전일 종가보다 큰 갭을 그리며 낮게 하락 출발(2,900달러)했습니다. 포지션을 보유한 스윙 트레이더로서 가장 적절한 위기 대응 행동은 무엇입니까?', '[{"time":"Day 1","open":2400,"high":2500,"low":2380,"close":2480,"volume":97},{"time":"Day 2","open":2480,"high":2700,"low":2460,"close":2680,"volume":103},{"time":"Day 3","open":2680,"high":2960,"low":2660,"close":2920,"volume":127},{"time":"Day 4","open":2920,"high":3020,"low":2800,"close":2940,"volume":114},{"time":"Day 5","open":2820,"high":2860,"low":2700,"close":2720,"volume":96}]'::jsonb, '[]'::jsonb, ARRAY['상승 랠리를 기대로 보유 비중 확대 및 추격 매수', '일시적 속임수(휩소) 판단으로 추가 레버리지 매수', '행잉맨 출현 후 갭하락에 따른 전량 또는 일부 정리', '조치 없이 전고점 돌파 시까지 무기한 관망 및 홀딩']::text[], 2, '고가권에서 나타난 행잉맨(Hanging Man)은 잠재적 하락 전환 신호이며, 특히 다음날 갭하락 음봉으로 직전 행잉맨의 저가를 깨고 내려가는 움직임은 강력한 하락 컨펌 시그널입니다. 따라서 이 시점에서는 즉시 비중을 전량 정리하거나 최소 절반 이상 매도하여 리스크를 통제하는 것이 정석입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (832, '캔들/가격행동', '01_chart_market_basics.md', '지속적인 하락 추세 도중 바닥권(1,600달러선)에서 시가와 종가가 일치하고 긴 아래꼬리를 단 십자 형태의 도지(Doji) 캔들이 생성되었습니다. 다음 날 대량의 거래량과 함께 장대양봉이 솟구치며 1,740달러로 마감하는 샛별형(Morning Star) 조합이 확정되었습니다. 이때 가장 합리적인 매수 진입 지점과 손절가 기준은 무엇입니까?', '[{"time":"Day 1","open":2000,"high":2020,"low":1860,"close":1880,"volume":95},{"time":"Day 2","open":1880,"high":1900,"low":1760,"close":1780,"volume":93},{"time":"Day 3","open":1780,"high":1800,"low":1600,"close":1620,"volume":91},{"time":"Day 4","open":1600,"high":1640,"low":1500,"close":1600,"volume":118},{"time":"Day 5","open":1600,"high":1760,"low":1580,"close":1740,"volume":105}]'::jsonb, '[]'::jsonb, ARRAY['손절 없이 100% 비중으로 시장가 매수', '샛별형 완성에 따라 분할 매수 후 최저점 손절 셋업', '바닥 도달 기대로 주문 없이 무작정 대기', '상승 꼭대기에서 숏 진입 후 손절 없이 방치']::text[], 1, '하락 추세 끝에 도지와 장대양봉이 결합된 샛별형(Morning Star)은 매우 신뢰도 높은 바닥 상승 전환 신호입니다. 이 패턴을 보고 진입할 때는 반등 상승세에 분할 매수로 동참하되, 바닥을 잡아준 도지 캔들의 최저점(1,500달러) 아래를 최종 손절 라인으로 잡는 것이 수학적으로 가장 리스크 대비 보상 비율(손익비)이 훌륭한 전략입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (833, '거래량/유동성', '02_candlestick_price_action.md', '리플 시세가 강력한 횡보 박스권 고점(4,000달러 저항선)에 세 번째 터치하는 와중에, 윗꼬리가 길고 몸통이 매우 얇은 유성형(Shooting Star) 캔들이 이틀 연속 발생했습니다. 거래량 역시 저항선 부근에서 매수세가 더 올라가지 못하고 매도 압력이 실려 나타났습니다. 롱(매수) 포지션을 들고 있는 당신의 합리적인 의사결정은?', '[{"time":"Day 1","open":3500,"high":3700,"low":3480,"close":3640,"volume":114},{"time":"Day 2","open":3640,"high":3900,"low":3600,"close":3860,"volume":93},{"time":"Day 3","open":3860,"high":4040,"low":3800,"close":3820,"volume":102},{"time":"Day 4","open":3820,"high":4020,"low":3760,"close":3780,"volume":107}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":4000}],"label":"박스권 상단 저항선 (200)","color":"#ef4444"}]'::jsonb, ARRAY['신고가 갱신을 예상한 전재산 추가 불타기', '저항 돌파 실패 신호 확인 후 분할 익절 및 관망', '손익 평단가 부근이므로 추가 손절 없이 방치', '거래를 종료하고 다른 신규 급등주를 시장가 추격']::text[], 1, '박스권 상단 저항선(4,000달러)에 부딪히며 나타난 유성형(Shooting Star) 연속 출현은 저항 돌파 실패와 차익 실현 세력의 강력한 등장을 경고하는 캔들 신호입니다. 돌파를 확신하기보다는 리스크 관리 관점에서 물량을 축소(50% 분할 익절)하거나 전량 매도하여 이익을 확정 짓는 것이 현명합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (834, '캔들/가격행동', '02_candlestick_price_action.md', '극심한 하락 추세 중 2,000달러선 아래로 떨어지던 리플 시세가 전일 장대음봉을 형성했습니다. 그러나 당일 시가는 갭하락하여 더 낮게 시작했으나, 장중에 강한 매수세가 들어오며 전일 음봉 몸통의 정확히 70% 라인(1,860달러선) 위로 덮어버리는 관통형(Piercing Line) 상승 캔들로 마감했습니다. 종가 매수(롱) 진입 시 원칙 대응은?', '[{"time":"Day 1","open":2200,"high":2220,"low":2080,"close":2100,"volume":92},{"time":"Day 2","open":2100,"high":2120,"low":1940,"close":1960,"volume":114},{"time":"Day 3","open":1840,"high":2020,"low":1820,"close":2000,"volume":91}]'::jsonb, '[]'::jsonb, ARRAY['상승 모멘텀 미달로 매수 보류 및 하방 숏 포지션 진입', '관통형 확인 후 분할 매수 및 당일 최저점 손절 설정', '손절 라인 설정 없이 100% 비중 시장가 매수 집행', '조정을 대기하며 예약 주문 없이 무작정 관망 유지']::text[], 1, '전일 음봉의 50% 이상을 당일 양봉 몸통으로 관통해 올린 ''관통형(Piercing Line)''은 하락 모멘텀이 쇠퇴하고 저가 매수세가 우위를 점하기 시작했음을 뜻하는 바닥 신호입니다. 이 패턴 확인 후 진입할 시에는 손절 한도를 당일 최저점(1,820달러) 밑에 가깝게 설정할 수 있어 매우 유리한 리스크 대비 기대수익 매매가 성립됩니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (835, '캔들/가격행동', '05_volume_liquidity.md', '강한 급등세를 지속하던 리플 시세가 최고점에서 큰 거래량을 터뜨리며 장대양봉을 만들었습니다. 그러나 다음 날, 전일 양봉 몸통의 한가운데 범위 안에서 움직이며 시가와 종가가 모두 갇혀버리는 짧은 음봉인 ''하락 잉태형(Bearish Harami)'' 캔들이 형성되었습니다. 단기 스윙 트레이더로서 당신의 포지션 리스크 관리 행동은?', '[{"time":"Day 1","open":2400,"high":2560,"low":2380,"close":2540,"volume":108},{"time":"Day 2","open":2540,"high":2760,"low":2520,"close":2720,"volume":117},{"time":"Day 3","open":2660,"high":2680,"low":2600,"close":2620,"volume":112}]'::jsonb, '[]'::jsonb, ARRAY['상승 둔화 조짐에 따른 보유 물량 50% 분할 익절', '추세 일시 조정으로 간주하여 비중 확대 추가 매수', '추세 종결 판단에 따른 고배율 숏 포지션 즉시 진입', '이익 실현 없이 전량 장기 보유 전략 유지']::text[], 0, '하락 잉태형(Bearish Harami)은 이전의 강한 상승 추세 동력이 감속하기 시작했으며, 매도 압력이 힘을 기르고 있음을 암시하는 변곡 캔들입니다. 따라서 단기 스윙 트레이더는 물량의 일부(50%)를 분할 익절하여 리스크를 낮추고, 다음 캔들에서 이전 양봉 저점을 깨뜨리는 하락 하방 이탈이 추가되는지 지켜보는 것이 정석입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (836, '시장구조/SR', '03_market_structure.md', '오랫동안 지켜지던 핵심 지지선인 2,000달러 부근에서 매수 진입을 완료했습니다. 그러나 가격이 대량의 거래량을 동반하며 장대음봉으로 지지선을 하방으로 강하게 뚫어냈고, 종가가 지지선 대비 1.5% 아래인 98.100달러로 결정되었습니다. 이 상황에서 원칙을 지키는 올바른 위기 대응 행동은?', '[{"time":"Day 1","open":2100,"high":2160,"low":2040,"close":2060,"volume":102},{"time":"Day 2","open":2060,"high":2080,"low":1980,"close":2000,"volume":108},{"time":"Day 3","open":2000,"high":2020,"low":1960,"close":1970,"volume":113}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":2000}],"label":"중요 지지선 (100)","color":"#10b981"}]'::jsonb, ARRAY['추가 물타기를 위해 자금을 동원하여 평단가 관리', '중요 지지선 붕괴(Breakdown) 확인 후 즉시 전량 손절', '지속 하락 시 추가 평단가 관리를 위해 매수 유보', '하방 이탈 시 즉시 반대 고배율 롱 포지션 진입']::text[], 1, '거래량이 동반된 장대음봉으로 주요 지지선 아래에서 종가가 결정되는 이탈 마감은 매수 지지 세력의 패배이자 추세 붕괴(Breakdown)의 신호입니다. 이 시점에서 물타기를 하거나 존버를 하면 파산적인 하락 조정을 겪을 수 있으므로 즉시 룰에 근거한 ''전량 손절''을 집행해야 계좌를 살릴 수 있습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (837, '시장구조/SR', '03_market_structure.md', '3,000달러의 중요 저항선이 강한 거래량을 실은 돌파봉으로 뚫렸습니다. 이후 리플 시세가 숨 고르기 조정을 받으며 3,000달러 부근까지 되돌아왔고(리테스트 구간), 저항선 부근에서 거래량이 크게 감소하며 아래꼬리가 달린 도지 캔들로 안착하는 모습을 보입니다. 이때 가장 안전하고 합리적인 매매 조치는?', '[{"time":"Day 1","open":2800,"high":2920,"low":2780,"close":2880,"volume":116},{"time":"Day 2","open":2880,"high":3140,"low":2860,"close":3100,"volume":120},{"time":"Day 3","open":3100,"high":3120,"low":2980,"close":3000,"volume":117}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":3000}],"label":"돌파된 저항선 -> 지지선 전환선 (150)","color":"#3b82f6"}]'::jsonb, ARRAY['가짜 돌파(휩소) 판단에 따른 고배율 숏 진입', '돌파 후 리테스트 성공 확인 시 지지선 눌림목 매수', '추격 매수 기회 상실로 판단하고 거래 포기', '3,200달러 추가 돌파를 타겟으로 시장가 추격 매수']::text[], 1, '강하게 돌파된 저항선은 룰 체인지에 의해 지지선으로 변합니다(역할 전환). 돌파 당시 추격 매수하기보다, 돌파된 선(3,000달러)으로 리플 시세가 되돌아오는 리테스트(Retest) 시점에 저조한 거래량과 지지 캔들을 확인하고 손절선을 바로 밑에 설정하여 눌림목 진입하는 것이 리스크가 가장 적은 프로 트레이더의 정석입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (838, '시장구조/SR', '03_market_structure.md', '가격이 1,600달러 지지선 근처에서 반등을 시도하고 있으나, 반등의 폭이 직전 고점에 턱없이 못 미치며 저점 부근으로 다시 짓눌리고 있습니다. 즉, 고점들이 계속 낮아지는 하락 우위 삼각수렴(Descending)의 형태가 지지선 바로 위에서 감지됩니다. 이 시점에서 지지선 반등을 믿고 신규 매수(롱)를 진입하는 것은 원칙에 맞습니까?', '[{"time":"Day 1","open":1900,"high":1960,"low":1600,"close":1760,"volume":94},{"time":"Day 2","open":1760,"high":1820,"low":1600,"close":1680,"volume":100},{"time":"Day 3","open":1680,"high":1720,"low":1600,"close":1620,"volume":102}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":1600}],"label":"지지선 (80)","color":"#10b981"}]'::jsonb, ARRAY['삼중 바닥 지지로 판단하고 매수 비중 대폭 확대', '디센딩 수렴 확인 후 하방 이탈 위험 대비 관망', '물타기 평단가 관리를 위해 매수 보증금 추가 투입', '추세와 무관하게 숏 포지션으로 전환 후 무기한 보유']::text[], 1, '지지선 부근에서 고점이 점점 낮아지는 ''디센딩'' 형태는 매수 지원 강도가 둔화되고 매도 출하 공급이 가격을 계속 하방으로 압박하고 있음을 증명합니다. 지지 성공보다 지선 하방 붕괴 후 급락할 확률이 높으므로, 지지선이라는 명목만으로 함부로 매수 진입하지 말고 돌파/이탈 컨펌을 기다려 관망하는 것이 현명합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (839, '거래량/유동성', '05_volume_liquidity.md', '리플 시세가 2,400달러의 장기 저항벽을 거래량이 거의 실리지 않은 얇은 양봉으로 상방으로 살짝 뚫었으나, 바로 다음 날 직전 양봉 몸통을 통째로 덮어버리는 대량 거래량의 장대음봉이 출현하며 2,320달러로 곤두박질쳤습니다. 매수 포지션을 추격 진입했던 당신의 올바른 조치는?', '[{"time":"Day 1","open":2240,"high":2360,"low":2220,"close":2340,"volume":93},{"time":"Day 2","open":2340,"high":2440,"low":2320,"close":2420,"volume":387},{"time":"Day 3","open":2420,"high":2440,"low":2300,"close":2320,"volume":341}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":2400}],"label":"장기 저항선 (120)","color":"#ef4444"}]'::jsonb, ARRAY['불 트랩(Bull Trap) 확인 후 추가 하락 방지 즉시 손절', '저항선 부근 매수세 복귀를 기대하며 전량 홀딩', '평단가 관리 차원에서 추가 물타기 매수 집행', '상황을 판단하기 위해 시장가로 추가 분할 진입']::text[], 0, '거래량 없는 돌파 직후에 거래량 실린 강한 음봉이 기존 돌파선(2,400달러) 아래로 재진입하여 마감하는 현상은 전형적인 불 트랩(Bull Trap/가짜 돌파) 함정입니다. 돌파 당시 샀던 매수자들의 패닉 셀이 출현하며 하락 가속화가 나오기 쉬우므로 즉시 손절하여 물량을 털어내야 생존할 수 있습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (840, '시장구조/SR', '10_psychology_routine_review.md', '주요 지지선(5,000달러선)이 아래로 무너질 때 제때 손절 처리를 하지 못해 리플 시세가 4,400달러선까지 끌려 내려갔습니다. 다행히 단기 매도 진정세로 반등이 나와 리플 시세가 다시 5,000달러 부근까지 상승하여 회복을 눈앞에 두고 있습니다. 이때 손실을 최소화하는 현명한 시나리오 대처법은?', '[{"time":"Day 1","open":5200,"high":5240,"low":4960,"close":4980,"volume":108},{"time":"Day 2","open":4980,"high":5000,"low":4400,"close":4440,"volume":87},{"time":"Day 3","open":4440,"high":4700,"low":4420,"close":4680,"volume":99},{"time":"Day 4","open":4680,"high":5020,"low":4660,"close":4980,"volume":95}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":5000}],"label":"붕괴된 지지선 -> 저항선으로 변형 (250)","color":"#ef4444"}]'::jsonb, ARRAY['역할 전환(저항선) 도달에 따른 탈출 및 현금화', 'V자 반등 성공 확신에 따른 추가 매수 비중 확대', '원금 회복 및 추가 수익 시까지 영구 홀딩 관망', '하락 추세 지속에 따른 반대 숏 포지션 스위칭']::text[], 0, '하방으로 깨진 지지선은 반등할 때 가장 뚫기 힘든 ''강력한 저항선''으로 성격이 바뀝니다. 따라서 손절 기회를 놓치고 물려있던 트레이더는 반등하여 옛 지지선(5,000달러)에 도달했을 때를 ''최선의 리스크 탈출 기회(탈출구)''로 삼아 전량 매도하거나 비중을 극도로 덜어내야 다가올 2차 하락 파동의 파산을 막을 수 있습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (841, '추세/레짐', '03_market_structure.md', '리플 시세가 매우 가파르게 올라가던 1차 단기 상승 추세선을 강한 음봉 종가로 뚫고 내려왔습니다. 다행히 각도가 완만하고 탄탄한 장기 핵심 상승 추세선은 저 밑에 지지 영역을 유지하고 있습니다. 스윙 트레이더로서 가장 정석적인 포지션 제어 방식은 무엇인가요?', '[{"time":"Day 1","open":2000,"high":2040,"low":2000,"close":2040,"volume":81},{"time":"Day 2","open":2040,"high":2200,"low":2040,"close":2180,"volume":90},{"time":"Day 3","open":2180,"high":2500,"low":2180,"close":2480,"volume":110},{"time":"Day 4","open":2480,"high":2500,"low":2280,"close":2300,"volume":116}]'::jsonb, '[{"type":"line","points":[{"x":0,"y":2000},{"x":3,"y":2460}],"label":"가파른 단기 추세선 (붕괴)","color":"#ef4444"},{"type":"line","points":[{"x":0,"y":2000},{"x":3,"y":2200}],"label":"완만한 장기 추세선 (지탱 중)","color":"#10b981"}]'::jsonb, ARRAY['추세 붕괴 판단에 따른 전량 손절 및 영구 이탈', '가속 추세 이탈에 따른 50% 분할 익절 및 분산', '단기 지지선 붕괴를 무시한 고배율 물타기 매수', '장기 추세선까지 조정을 대비한 신규 매수 대기']::text[], 1, '가파르게 우상향하던 가속 추세선(Accelerated Trendline)이 하방 돌파되는 것은 기존 폭등 랠리의 속도가 둔화되고 완만한 본래 장기 추세선(장기 매물대)을 향해 정상적인 가격 조정을 받기 시작했음을 뜻합니다. 따라서 물량의 50%가량을 털어 수익을 실현하고 남은 물량으로 장기 추세선의 3rd Touch 지지 성공 여부를 테스트하는 것이 리스크 관리의 기본입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (842, '거래량/유동성', '05_volume_liquidity.md', '고점과 저점이 연속으로 낮아지는 명확한 하락 평행 채널 내에서 하락 압력을 받아 숏(매도) 포지션을 잡고 수익 중이었습니다. 그런데 당일 캔들이 대량의 거래량과 함께 장대양봉을 그리며 채널 상단 저항선 위로 종가 안착(상방 돌파)했습니다. 숏 포지션을 쥔 당신의 결단은?', '[{"time":"Day 1","open":2000,"high":2040,"low":1800,"close":1840,"volume":93},{"time":"Day 2","open":1840,"high":1880,"low":1640,"close":1660,"volume":119},{"time":"Day 3","open":1660,"high":1700,"low":1500,"close":1520,"volume":118},{"time":"Day 4","open":1520,"high":1800,"low":1500,"close":1780,"volume":113}]'::jsonb, '[{"type":"channel","points":[{"x":0,"y":2040},{"x":3,"y":1720},{"x":0,"y":1800},{"x":3,"y":1520}],"label":"하락 평행 채널 상한/하한","color":"#f59e0b"}]'::jsonb, ARRAY['상단 돌파 확인 즉시 숏 전량 손절 및 대피', '채널 재진입 기대로 숏 포지션 추가 물타기', '손절 없이 유지하면서 포지션 본전 도달 대기', '포지션 유지 후 증거금을 출금하여 강제 횡보']::text[], 0, '하락 평행 채널의 상단 저항선 상향 돌파(Breakout)는 기존 하락 트렌드의 사멸과 매수세 지배령 복귀를 뜻합니다. 지표와 거래량이 동반된 돌파 확인 시에는 숏 포지션을 지체 없이 기계적으로 칼손절하여 자산을 보호하는 것이 원칙입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (843, '추세/레짐', '07_multitimeframe_regime.md', '우상향하는 상승 평행 채널 안에서 순항하던 리플 시세가 중심선(Mid-line)을 뚫고 하방으로 이탈 마감했습니다. 이후 중심선 부근까지 반등을 시도했으나 재차 저항을 받고 아래꼬리가 꺾여 채널 하단선을 향해 하락 조정을 재개하려 합니다. 신규 매수(롱) 포지션 진입을 계획 중인 트레이더의 대응법은?', '[{"time":"Day 1","open":2000,"high":2160,"low":1980,"close":2120,"volume":118},{"time":"Day 2","open":2120,"high":2240,"low":2040,"close":2080,"volume":89},{"time":"Day 3","open":2080,"high":2120,"low":1960,"close":2000,"volume":89}]'::jsonb, '[{"type":"channel","points":[{"x":0,"y":2200},{"x":2,"y":2240},{"x":0,"y":1960},{"x":2,"y":2000}],"label":"상승 평행 채널","color":"#10b981"}]'::jsonb, ARRAY['채널 내 유지를 기대로 지정가 즉시 매수', '중심선 저항 확인 후 채널 하단 안착 대기', '하방 휩소 판단에 따른 레버리지 추가 매수', '추세와 무관한 숏 포지션 구축 후 관망']::text[], 1, '상승 평행 채널에서 미드라인(Mid-line)은 매우 중요한 심리적 지지와 저항선입니다. 미드라인이 저항선으로 뒤바뀌어 음봉으로 흘러내리는 경우 높은 확률로 채널 하단 경계선까지 가격이 조정을 받게 되므로, 중심선 저항 확인 시점에서는 섣부른 매수 진입을 피하고 채널 하단의 명확한 반등 타점을 유도해야 합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (844, '추세/레짐', '03_market_structure.md', '저점과 저점을 이은 장기 상승 추세선 상의 3번째 터치 포인트(지지선 부근)에 캔들이 매우 조심스럽게 안착하며 아래꼬리를 형성했습니다. 손익비(Risk-to-Reward) 관점에서 가장 이상적인 매수 타점 집행 및 손절 셋업 방법은 무엇입니까?', '[{"time":"Day 1","open":1600,"high":1800,"low":1600,"close":1760,"volume":81},{"time":"Day 2","open":1760,"high":1980,"low":1760,"close":1900,"volume":94},{"time":"Day 3","open":1900,"high":1920,"low":1800,"close":1840,"volume":95}]'::jsonb, '[{"type":"line","points":[{"x":0,"y":1600},{"x":1,"y":1760},{"x":2,"y":1800}],"label":"상승 추세선 (3rd Touch 기대선)","color":"#10b981"}]'::jsonb, ARRAY['손절 라인 없이 지정가로 1차 매수 몰빵 진입', '3rd Touch 타점 진입 및 추세선 하단 칼손절 셋업', '하방 붕괴 예상을 통한 고배율 숏 즉각 진입', '목표가 터치 시까지 무작정 대기 후 추격 매수']::text[], 1, '추세선 상의 3번째 지지 포인트(3rd Touch)는 추세 신뢰도가 형성되는 대단히 성공률 높은 정석적 눌림목 타점입니다. 진입 가격과 손절 라인(추세선 이탈가)의 거리가 매우 가깝기 때문에 기대 수익 대비 잃을 금액이 매우 적어 프로 트레이더들이 가장 선호하는 칼손절 매수 스팟입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (845, '추세/레짐', '08_setup_entry_exit.md', '리플 시세가 장기 하락 추세선을 힘차게 뚫어 상방 돌파(Breakout)했습니다. 하지만 돌파선 바로 위(약 2,400달러)에 최근 여러 번 강한 매도 잔량이 쏟아지며 가격을 찍어 눌렀던 핵심 매물대 저항선이 떡하니 버티고 있습니다. 당신의 신규 진입 매수 순서는 어떻게 결정해야 안전할까요?', '[{"time":"Day 1","open":2500,"high":2520,"low":2200,"close":2240,"volume":97},{"time":"Day 2","open":2240,"high":2260,"low":1960,"close":2000,"volume":96},{"time":"Day 3","open":2000,"high":2380,"low":1980,"close":2360,"volume":115}]'::jsonb, '[{"type":"line","points":[{"x":0,"y":2500},{"x":1,"y":2240},{"x":2,"y":2100}],"label":"하락 추세선 (돌파됨)","color":"#ef4444"},{"type":"horizontal-line","points":[{"x":0,"y":2400}],"label":"수평 매물대 저항선 (120)","color":"#ef4444"}]'::jsonb, ARRAY['돌파 확인 즉시 종가 기준 시장가 100% 매수', '수평 저항 돌파 검증 시까지 매수 유보 및 대기', '돌파 전조 현상 기대로 레버리지 선배팅 집행', '추세선 돌파를 가짜로 간주한 숏 포지션 진입']::text[], 1, '하락 추세선의 돌파는 긍정적이나 수평 매물대 저항선이 바로 위에 있다면 이중 저항 작용에 의해 막히는 경우가 대단히 잦습니다. 추세선 상방 휩소(속임수)에 당하지 않으려면 겹저항 중 최종 관문인 수평 매물대 저항선 돌파 혹은 리테스트 지지를 확인하고 진입하는 것이 보수적이고 안전한 원칙입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (846, '패턴/돌파', '04_patterns_breakout.md', '고점 수평 저항선(2,000달러)과 저점 상승 지지선으로 이루어진 어센딩 트라이앵글 수렴 도중, 2,000달러를 돌파할 것을 미리 예측하고 1,960달러에서 비중 100% 매수로 진입했습니다. 그러나 리플 시세는 돌파에 실패하고 하방 상승 지지선을 대량 거래량 장대음봉으로 뚫어 1,840달러로 하향 마감했습니다. 올바른 매매 액션은?', '[{"time":"Day 1","open":1600,"high":2000,"low":1600,"close":1900,"volume":112},{"time":"Day 2","open":1900,"high":2000,"low":1760,"close":1940,"volume":114},{"time":"Day 3","open":1940,"high":1960,"low":1820,"close":1840,"volume":90}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":2000}],"label":"수평 저항선 (100)","color":"#ef4444"},{"type":"line","points":[{"x":0,"y":1600},{"x":1,"y":1760},{"x":2,"y":1880}],"label":"상승 지지선 (붕괴)","color":"#10b981"}]'::jsonb, ARRAY['하방 이탈 확인 즉시 손절하여 추가 폭락 차단', '조정을 이용해 평단가를 조절하는 분할 물타기', '본전 탈출 시까지 포지션을 유지하며 관망', '손절 라인을 하단으로 조정하고 대기 주문 유지']::text[], 0, '어센딩 트라이앵글은 상방 확률이 다소 높지만, 하단 지지선이 뚫려 무너지는 순간 패턴 실패와 함께 엄청난 실망 매도 매물이 출하됩니다. 특히 돌파를 미리 예견해 들어간 포지션은 즉시 룰 위반을 시정하고 손절(1,840달러)해야 큰 자산 보호를 할 수 있습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (847, '패턴/돌파', '04_patterns_breakout.md', '하락 바닥권에서 왼쪽 어깨, 머리, 오른쪽 어깨를 그리며 역헤드앤숄더(Inverse Head & Shoulders) 패턴이 완성되었습니다. 가격이 넥라인 저항벽(1,600달러선)을 돌파했으나 이미 장대양봉으로 높이 솟아(1,740달러) 추격 매수 타이밍을 아쉽게 놓쳤습니다. 이때 뇌동매매를 피하는 가장 현명한 매수 타점 공략법은?', '[{"time":"Day 1","open":1900,"high":1900,"low":1400,"close":1560,"volume":100},{"time":"Day 2","open":1560,"high":1640,"low":1200,"close":1500,"volume":114},{"time":"Day 3","open":1500,"high":1580,"low":1360,"close":1520,"volume":117},{"time":"Day 4","open":1520,"high":1760,"low":1500,"close":1740,"volume":113}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":1600}],"label":"넥라인 저항선 (80)","color":"#ef4444"}]'::jsonb, ARRAY['포모(FOMO) 현상에 따른 돌파봉 꼭대기 추격 매수', '돌파 넥라인 부근의 리테스트 조정 눌림목 매수', '반등 랠리 종결 판단에 따른 역베팅 숏 포지션', '추세 전환 확인 후 무조건적인 관심종목 제외']::text[], 1, '강한 패턴 돌파봉 확인 후 뇌동매매로 추격하는 것은 손절 거리가 너무 멀어져 손익비가 최악인 나쁜 습관입니다. 정석 돌파 트레이더는 넥라인 역할 전환 지점(1,600달러)으로의 되돌림 눌림목(Retest)을 차분히 기다려 리스크를 짧게 끊고 들어가는 훈련을 해야 합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (848, '패턴/돌파', '04_patterns_breakout.md', '지속적인 하락 추세 중, 고점과 저점이 수렴하며 우하향하는 하락 쐐기형(Falling Wedge) 패턴의 끝자락에 도달했습니다. 거래량이 급감하다가 마침내 쐐기형 상단 저항선을 상방으로 뚫는 강한 양봉 종가 마감(2,200달러)이 포착되었습니다. 합리적인 매수 진입 시 손절가 설정 기준은 무엇인가요?', '[{"time":"Day 1","open":2600,"high":2640,"low":2200,"close":2240,"volume":108},{"time":"Day 2","open":2240,"high":2320,"low":2040,"close":2080,"volume":114},{"time":"Day 3","open":2080,"high":2160,"low":1960,"close":2000,"volume":118},{"time":"Day 4","open":2000,"high":2240,"low":1980,"close":2200,"volume":129}]'::jsonb, '[]'::jsonb, ARRAY['손절 없이 청산가에 의존하여 장기 홀딩', '상방 돌파 확인 후 진입 및 직전 최저점 손절 셋업', '평단가 개선을 위한 지속적인 분할 물타기 매수', '상단 저항선 돌파 시점을 이용한 숏 포지션 스위칭']::text[], 1, '하락 쐐기형(Falling Wedge)의 상방 돌파는 강력한 반전 신호입니다. 이 패턴의 장점은 진입 즉시 명확하고 짧은 기준점(수렴 바닥 최저가 1,960달러 혹은 돌파봉 하단)을 손절가로 설정할 수 있어, 리스크 한도를 안전하게 통제한 채 상방 랠리를 도모할 수 있다는 점입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (849, '패턴/돌파', '04_patterns_breakout.md', '리플 시세가 약한 매수세와 거래량 급감 속에 고점과 저점을 높이며 좁게 상승 쐐기형(Rising Wedge)을 그리고 있습니다. 현재 가격은 상승 쐐기형 하단 지지선(6,000달러)에 아주 밀착하여 붕괴 위기에 놓여 있습니다. 이 시점에서 롱(매수) 포지션을 들고 있는 트레이더의 리스크 대응은?', '[{"time":"Day 1","open":5200,"high":5600,"low":5200,"close":5560,"volume":82},{"time":"Day 2","open":5560,"high":5900,"low":5440,"close":5800,"volume":29},{"time":"Day 3","open":5800,"high":6100,"low":5960,"close":6020,"volume":34}]'::jsonb, '[{"type":"line","points":[{"x":0,"y":5200},{"x":1,"y":5440},{"x":2,"y":5960}],"label":"쐐기 하단 지지선 (300)","color":"#ef4444"}]'::jsonb, ARRAY['상승 쐐기형 하방 이탈 위험에 따른 롱 포지션 매도', '상승 지속 확신에 따른 레버리지 추가 불타기', '장기 상승 흐름 기대로 손절 없이 무기한 홀딩', '다른 종목으로의 포지션 분산을 위한 관망']::text[], 0, '상승 쐐기형(Rising Wedge)은 약세 세력이 억지로 쥐어짜며 상승 가격을 만드는 패턴으로, 수렴 끝에서 거래량 소멸과 함께 하방 이탈(Breakdown)하여 폭락할 위험이 매우 높은 대표적인 하락 대비 패턴입니다. 하단 지지선 이탈 낌새 시에는 매수 포지션을 전부 도망쳐 나와야 큰 손실을 막을 수 있습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (850, '패턴/돌파', '04_patterns_breakout.md', '둥근 대야 모양의 바닥(Cup)을 그리며 상승 회복한 리플 시세가 전고점 저항벽 부근에서 하향 채널식 완만한 되돌림 조정 핸들(Handle)을 그리는 중입니다. 이후 핸들의 상단 저항선(3,000달러선)을 강한 거래량의 장대양봉으로 상향 돌파했습니다. 이때 합리적인 트레이더의 대응은?', '[{"time":"Day 1","open":2800,"high":2840,"low":2560,"close":2600,"volume":91},{"time":"Day 2","open":2600,"high":2800,"low":2580,"close":2760,"volume":121},{"time":"Day 3","open":2760,"high":2800,"low":2680,"close":2700,"volume":94},{"time":"Day 4","open":2700,"high":3080,"low":2680,"close":3040,"volume":104}]'::jsonb, '[]'::jsonb, ARRAY['핸들 상방 돌파 확인 후 진입 및 핸들 저점 손절', '하락 지속 판단에 따른 즉각적인 전량 손절', '평단가 부근이므로 추가 손절 설정 없이 관망', '돌파 여부 확인 전 고점 돌파 매수 주문 100%']::text[], 0, '전형적인 강세 지속 패턴인 컵앤핸들(Cup & Handle)입니다. 핸들의 하락 조정 채널 상단 돌파는 매물 소화를 성공적으로 완수하고 본 랠리로 진입한다는 강력한 신호입니다. 손익비 관점에서 핸들의 지지 저점인 2,680달러 아래에 안전 손절을 지정한 뒤 진입 시 우수한 기대 수익을 가질 수 있습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (851, '지표/컨플루언스', '06_technical_indicators.md', '강력한 대세 상승 국면인 종목이 일시 조정을 거쳐 전저점 지지 영역(2,000달러)에 도달해 저점을 지키고 있습니다(저점 높임 또는 수평). 그런데 이때 보조지표 RSI의 저점은 이전보다 훨씬 깊게 파여 낮아지는 ''히든 상승 다이버전스(Hidden Bullish Divergence)''가 포착되었습니다. 현명한 의사결정은?', '[{"time":"Day 1","open":1800,"high":2200,"low":1760,"close":2100,"volume":116},{"time":"Day 2","open":2100,"high":2140,"low":1960,"close":2000,"volume":103}]'::jsonb, '[]'::jsonb, ARRAY['하락 전환 신호로 판단하여 전량 즉시 손절', '추세 지속 신호 기대로 지선 부근 추가/신규 매수', '지표 과매수 판단에 따른 계좌 거래 정지', '손절 설정 없이 무제한 레버리지 롱 대응']::text[], 1, '리플 시세의 저점은 높아지는데 보조지표(RSI 등)의 저점은 낮아지는 형태는 ''히든 상승 다이버전스''입니다. 이는 기존의 강력한 상승 트렌드 내부에서 일시 조정을 겪는 매수자들이 활기차게 물량을 주워 담아 다음 상승 랠리를 추진한다는 신호이므로, 짧은 손절 라인(1,960달러)을 설정하고 매수 비중을 태우기 가장 적합한 정석 타점입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (852, '지표/컨플루언스', '07_multitimeframe_regime.md', '리플 시세가 호재와 함께 밴드 상단선 바깥을 타고 계속 상승하는 강력한 볼린저 밴드 밴드워크(Band Walk) 현상이 발생 중이며, RSI는 80을 넘어 극단적 과매수 수치를 가리키고 있습니다. 이 구간에서 취해야 할 가장 합리적인 리스크 및 포지션 관리 행동은?', '[{"time":"Day 1","open":2000,"high":2300,"low":1980,"close":2240,"volume":94},{"time":"Day 2","open":2240,"high":2560,"low":2200,"close":2500,"volume":107},{"time":"Day 3","open":2500,"high":2780,"low":2440,"close":2720,"volume":88}]'::jsonb, '[]'::jsonb, ARRAY['과매수 도달 판단에 따른 고배율 숏 무리한 진입', '추종 손절매(Trailing Stop)를 통한 수익 극대화', '상승폭 만족에 따른 즉각적인 전량 시장가 익절', '손절 가격을 해제하고 시세 지속 시까지 방치']::text[], 1, '강세 추세가 지나치게 강할 경우 볼린저 밴드 상단을 타고 오르는 밴드워크 현상과 RSI 과매수 현상이 영구 유지될 수 있습니다. 이때 단순 과매수 수치를 이유로 숏 포지션을 잡으면 파산합니다. 기존 매수 포지션의 익절선(Trailing Stop)을 상향 관리하여 추세 상승 이익을 극대화하고 신규 진입은 자제하는 것이 정석 리스크 관리입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (853, '지표/컨플루언스', '06_technical_indicators.md', '1시간 봉 차트 상에서 리플 시세가 확실히 낮아졌으나 RSI 저점은 유의미하게 상승한 ''상승 다이버전스''가 확인되어 매수 타점을 노리고 있습니다. 다만 15분 봉 단기 차트에서는 하락 장대음봉 관성이 아직 살아있어 매도 압력이 보입니다. 멀티 타임프레임 트레이더의 진입 의사결정은?', '[{"time":"Hour 1","open":2000,"high":2040,"low":1800,"close":1820,"volume":81},{"time":"Hour 2","open":1820,"high":1840,"low":1600,"close":1640,"volume":112}]'::jsonb, '[]'::jsonb, ARRAY['단기 음봉 관성 기대로 즉각 숏 포지션 진입', '큰 시간 프레임의 상승 다이버전스 타점 매수', '지표 충돌로 판단하고 시장가 즉시 롱 진입', '변동성 기대로 무작정 도박성 잡코인 진입']::text[], 1, '큰 프레임(1시간 봉)의 다이버전스가 주는 중장기 추세 신뢰도는 작은 프레임의 단기 노이즈보다 압도적으로 강력합니다. 단, 진입 시 타이밍의 정밀도를 높이기 위해 소파동(15분 봉)의 하락 동력이 꺾이고 지지해 주는 단기 확인 캔들이 나오는 찰나에 롱 포지션 타이밍을 잡는 것이 멀티 타임프레임 정석 매매입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (854, '지표/컨플루언스', '06_technical_indicators.md', '리플 시세는 4,000달러 저항대를 뚫고 4,400달러까지 계속 우상향하며 고점을 갱신하고 있으나, MACD 오실레이터의 히스토그램 산 높이는 직전 고점 시점 대비 현저하게 쪼그라들며 꺾여 내려가 하락 다이버전스를 형성 중입니다. 현명한 포지션 보유자의 이익 관리 행동은?', '[{"time":"Day 1","open":3600,"high":4100,"low":3580,"close":4000,"volume":108},{"time":"Day 2","open":4000,"high":4440,"low":3960,"close":4400,"volume":122}]'::jsonb, '[]'::jsonb, ARRAY['추세 지속 확신으로 보유 비중 추가 불타기', '상승 모멘텀 약화 다이버전스 확인 후 50% 익절', '익절 설정 없이 전고점 도달 시까지 홀딩', '고점 붕괴 기대로 숏 포지션 10배 베팅']::text[], 1, '리플 시세는 올라가나 모멘텀 지표인 MACD 오실레이터 고점이 낮아지는 현상은 대표적인 하락 다이버전스로, 매수 에너지가 속 빈 강정처럼 쇠퇴하고 있어 언제든 급격한 폭락 조정이 발생할 수 있는 고위험 신호입니다. 이 시점에는 탐욕을 통제하고 물량의 50% 이상을 분할 매도하여 현금을 챙기는 것이 원칙입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (855, '지표/컨플루언스', '06_technical_indicators.md', '리플 시세가 하락 횡보하던 도중, 단기 지평선인 EMA 20일선이 중장기선인 EMA 50일선에 극도로 밀착하며 수렴했습니다. 당일 대량 거래량의 음봉 캔들이 터지며 단기선이 장기선 아래로 교차하기 직전(데드크로스 임박)이며 주요 지지선 밑으로 떨어졌습니다. 롱(매수) 포지션 보유자의 올바른 대응은?', '[{"time":"Day 1","open":2100,"high":2120,"low":1980,"close":2000,"volume":95},{"time":"Day 2","open":2000,"high":2020,"low":1900,"close":1920,"volume":92}]'::jsonb, '[]'::jsonb, ARRAY['지지선 이탈 및 데드크로스 확인 즉시 손절', '이평선 지지력을 믿고 하방 물타기 추가 매수', '하락 조정 후 반등 기대로 무기한 홀딩 관망', '청산가 도달 시까지 어떠한 대응 없이 방치']::text[], 0, '20일선과 50일선의 데드크로스 임박 수렴 상태에서 가격이 지지선마저 무너뜨린 것은 하락 가속화 추세가 폭발하기 직전인 매우 위험한 기술적 상태입니다. 하락 추세가 본격 정배열(하락 정배열)화 되기 전에 즉시 전량 손절하고 시장 밖에서 피신해 있는 것이 계좌의 영구 파산을 막는 유일한 생존 규칙입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (856, '리스크/심리', '09_risk_position_management.md', '메이저 코인 매수 후 가격이 급락하여 내가 설정해 둔 최대 감내 손실 한도인 계좌 총원금 대비 -2% 라인(손절매 지정 가격)에 완벽하게 닿았습니다. 마침 본전 생각과 함께 ''조금만 더 버티면 반등할 텐데...''하는 강한 뇌동매매 유혹이 솟구칩니다. 이때 원칙 트레이더의 결정은?', '[{"time":"Day 1","open":2000,"high":2040,"low":1980,"close":2000,"volume":87},{"time":"Day 2","open":2000,"high":2020,"low":1880,"close":1900,"volume":87}]'::jsonb, '[]'::jsonb, ARRAY['손절 라인을 임의로 하향 조정하고 홀딩', '평단가 관리 차원의 지속적 물타기 매수 집행', '원칙에 따라 뇌동을 제어하고 즉시 기계적 손절', '손실은 배제하고 반등 기대를 통한 무기한 보유']::text[], 2, '트레이딩의 승패는 예측이 아닌 ''리스크 통제''에 달려 있습니다. 사전에 정한 계좌 대비 2% 리스크 한도에 도달했을 때 희망 회로를 돌리며 손절을 미루거나 물타기를 집행하는 순간 계좌는 서서히 영으로 깎여 파산합니다. 멘탈의 충동을 통제하고 기계적으로 전량 칼손절하는 것이 절대 파산하지 않는 시장의 1법칙입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (857, '리스크/심리', '10_psychology_routine_review.md', '최근 3회 연속 거래에서 계속해서 손절(Stop Loss)을 맞아 뇌 내의 도파민 체계가 무너지고 심리가 극도로 불안해져 분노와 보복 매매 충동이 밀려옵니다. 이 상황에서 파산을 막는 가장 훌륭한 매매 심리 대처법은?', '[{"time":"Today","open":2000,"high":2000,"low":2000,"close":2000}]'::jsonb, '[]'::jsonb, ARRAY['손실 복구를 위해 레버리지를 증액해 즉시 진입', '뇌동 방지를 위해 HTS를 종료하고 매매 일지 작성 및 휴식', '추천 매매 신호 유료 리딩방에 즉시 가입 및 추종', '심리적 회복을 위해 역베팅 숏 포지션 추가']::text[], 1, '연속 손실 후 발생하는 복수심과 분노는 트레이더를 뇌동매매와 계좌 파멸로 이끄는 가장 치명적인 감정 상태입니다. 멘탈 붕괴를 느꼈을 때는 즉각 행동을 멈추고 시스템을 강제 종료하여 시장과 물리적 격리를 통해 냉정을 찾는 것만이 자산을 파산 리스크로부터 살려내는 훌륭한 트레이딩 행동입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (858, '셋업/실행', '09_risk_position_management.md', '진입하고자 하는 매수 자리를 분석해 보니, 기술적 분석 상 이길 수 있는 확률(승률)은 반반인 50% 수준입니다. 그러나 손절 시 기대 손실금액 대비 성공 시 획득할 수 있는 기대 수익금액의 비율(손익비)을 정밀 셋업 해보니 1 : 1.2 수준으로 다소 애매하게 도출되었습니다. 원칙 트레이더의 진입 결정은?', '[{"time":"Today","open":2000,"high":2000,"low":2000,"close":2000}]'::jsonb, '[]'::jsonb, ARRAY['단기 변동성 기대로 부적합한 손익비 시장가 진입', '마이너스 기댓값 거래 유보 및 우수 타점 대기', '레버리지를 높여 손익비 구조를 임의 조정 시도', '반대 방향으로 고배율 역베팅을 즉시 실행']::text[], 1, '수학적으로 승률 50%일 때 손익비가 최소 1:2(잃을 때 1, 벌 때 2) 이상이 나오지 않으면 복리 매매 시 수수료와 호가 슬리피지에 밀려 잔고가 무조건 마이너스로 수렴합니다. 타점이 눈에 들어오더라도 사전에 기대 손익비 필터에 걸려 탈락한다면 패스를 선언하고 관망하는 것이 현명한 생존 원칙입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (859, '리스크/심리', '09_risk_position_management.md', '갑작스러운 거시 경제 발표로 내가 매매 중인 종목의 캔들 변동성 폭(ATR)이 평소 시세의 2배 수준으로 널뛰기 시작했습니다. 1회 거래당 내 계좌 원금의 최대 2% 리스크 한도를 동일하게 고수하기 위해 취해야 할 올바른 조치는?', '[{"time":"Day 1","open":2000,"high":2040,"low":1960,"close":2000,"volume":87},{"time":"Day 2","open":2000,"high":2200,"low":1800,"close":2040,"volume":88}]'::jsonb, '[]'::jsonb, ARRAY['평소 변동성과 동일한 비중 및 손절 거리 고수', '손절 거리를 넓히는 대신 진입 포지션 수량 축소', '변동성이 확대되었으므로 2배 비중으로 적극 지름', '즉시 전량 손절하고 시장 상황 정상화 대기']::text[], 1, '시장 변동성이 커질 때는 손절 스톱 아웃이 잦으므로 손절폭(%)을 넓혀 숨 쉴 공간을 확보해 주는 것이 합리적입니다. 단, 손절폭을 2배로 늘린다면 계좌 대비 리스크 한도가 2배(4%)로 커지므로, 진입 포지션의 계약 수량을 50%로 줄여 리스크 노출 총액을 2%로 완벽하게 동일 통제하는 것이 포지션 사이징(Position Sizing)의 정석 원칙입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (860, '리스크/심리', '09_risk_position_management.md', '투자자 A의 전체 투자 원금은 10,000만 원이며, 1회 거래당 최대 허용 리스크 금액은 원금의 2%인 200만 원입니다. 현재 리플 시세가 200,000원이며, 기술적 분석 상 합리적인 손절선은 지지선 바로 밑인 190,000원(-5%)입니다. 2% 룰 리스크 관리 원칙에 따라 A가 진입(매수)해야 하는 최대 메이저 코인 수량은?', '[{"time":"Today","open":200000,"high":200000,"low":200000,"close":200000}]'::jsonb, '[]'::jsonb, ARRAY['500주 (투자금 전액 시장가 매수)', '200주 (손실 한도 200만 원 맞춤 매수)', '50주 (보수적 극단적 비중 축소)', '100주 (절반 비중 고정 매수)']::text[], 1, '포지션 크기 계산 공식은 `최대 매수 규모 = 최대 허용 리스크 금액 / 손절매 비율` 입니다. 이 시나리오에서 `2,000,000원 / 0.05(5%) = 40,000,000원`이 최대 허용 진입금액이 되며, 이를 리플 시세 200,000원으로 나누면 `200주`가 도출됩니다. 200주 진입 후 -5% 가격 폭락으로 손절 당해도 내 총원금에서 깎이는 돈은 정확히 200만 원(2%)으로 완벽히 리스크 통제됩니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (861, '거래량/유동성', '05_volume_liquidity.md', '리플 시세가 수평 저항선 부근까지 급상승했으나 캔들 몸통(Spread)이 지극히 좁아진 도지 형태로 마감하였고, 거래량은 이전 5일 평균 대비 3배 이상 폭증했습니다. VSA(Volume Spread Analysis) 관점에서 가장 타당한 차트 분석은?', '[{"time":"Day 1","open":2000,"high":2100,"low":1980,"close":2080,"volume":83},{"time":"Day 2","open":2080,"high":2180,"low":2060,"close":2160,"volume":117},{"time":"Day 3","open":2160,"high":2200,"low":2140,"close":2160,"volume":98}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":2180},{"x":2,"y":2180}],"label":"저항선","color":"#ef4444"}]'::jsonb, ARRAY['강한 매수 기세 기대로 즉시 돌파 매매 풀매수', '저항벽 매도 공급 세력 분산 확인 후 이익 실현', '대량 거래 확인에 따른 손절 해제 후 장기 투자', '반등 실패에 따른 고배율 보복 숏 베팅 가동']::text[], 1, '캔들 몸통 크기(스프레드)가 좁은데 거래량이 매우 크게 폭증했다는 것은 저항선 부근에서 들어오는 매수세만큼 세력의 매도 물량 공급이 쏟아져 막강한 저항 벽을 형성하고 있다는 뜻입니다. VSA에서는 이를 불화(Disharmony)로 규정하며 상승 추세 감속 및 하락 반전의 경고로 해독합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (862, '거래량/유동성', '05_volume_liquidity.md', '리플 시세가 장기 횡보하던 박스권 지지선인 4,000달러를 깨고 3,900달러까지 하락 투매가 발생했으나, 종가 마감 직전 거래량이 크게 실린 긴 아래꼬리를 그리며 다시 4,020달러 위로 복귀 안착했습니다. 이 스톱 헌팅 유동성 현상에서의 실전 트레이더의 대응은?', '[{"time":"Day 1","open":4200,"high":4240,"low":4000,"close":4040,"volume":104},{"time":"Day 2","open":4040,"high":4080,"low":3900,"close":4020,"volume":96}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":4000},{"x":1,"y":4000}],"label":"지지선","color":"#10b981"}]'::jsonb, ARRAY['지지선 붕괴 확정으로 간주한 시장가 숏 추격', '스윕(sweep) 판단 하에 아래꼬리 저점 손절 잡고 롱', '아무런 신호도 아니라고 판단하고 포지션 방치', '지지선 이탈 기대로 전량 손절 후 시장 영구 탈출']::text[], 1, '지지선 아래에 걸려 있던 개인들의 손절 주문(Sell Stop)을 강제로 청산(Liquidity Sweep)시킨 뒤, 세력이 물량을 헐값에 다 받아 삼켜 종가를 지지선 위로 신속하게 복귀시킨 휩소(베어 트랩) 패턴입니다. 아래꼬리 극점(3,900달러)에 아주 좁은 손절 라인을 설정할 수 있어, 기대 손익비가 극대화되는 고확률 상승 반전 매수 타점입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (863, '거래량/유동성', '05_volume_liquidity.md', '리플 시세는 5,000달러에서 5,800달러까지 계속 고점을 높이며 상승 추세를 이어가고 있습니다. 그러나 각 상승 파동마다 터지는 거래량은 전고점 돌파 시점 대비 눈에 띄게 하향 곡선을 그리며 감소하고 있습니다. VSA 기법에 따른 합리적인 진단은?', '[{"time":"Wave 1","open":4600,"high":5200,"low":4560,"close":5100,"volume":110},{"time":"Wave 2","open":5100,"high":5500,"low":5000,"close":5400,"volume":84},{"time":"Wave 3","open":5400,"high":5800,"low":5300,"close":5760,"volume":105}]'::jsonb, '[]'::jsonb, ARRAY['가격 상승으로 인한 매수 지속 강화 초강세', '매도 물량 고갈에 따른 무중력 안심 홀딩', '신규 자금 유입 둔화 거래량 다이버전스로 분할 익절', '지표 조작으로 판단하여 매매 중단 및 차트 종료']::text[], 2, '리플 시세는 상승하여 신고점을 갱신하지만 파동별 거래량이 지속 감소하는 흐름은 ''거래량 다이버전스''로 상승 모멘텀의 내부 엔진이 식어감을 경고합니다. 조만간 가벼운 매도 포격에도 대규모의 차익 실현 폭락 조정이 발생할 수 있는 잠재적 폭락 국면이므로 물량을 덜어내고 현금을 확보해야 합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (864, '거래량/유동성', '05_volume_liquidity.md', '가격이 이전 고점 저항선을 뚫고 강하게 솟구치며 장대양봉을 만들었습니다. 이때 가짜 이탈(Whipsaw / Bull Trap)이 아닌 진성 돌파(True Breakout)로 판정할 수 있는 가장 신뢰도 높은 거래량 기준은?', '[{"time":"Day 1","open":2000,"high":2040,"low":1980,"close":2000,"volume":348},{"time":"Day 2","open":2000,"high":2240,"low":1980,"close":2200,"volume":376}]'::jsonb, '[]'::jsonb, ARRAY['수렴 끝자락에서 거래량이 최저치인 상태 유지', '평균 대비 1.5~2배 이상 거래량 급증하며 돌파 마감', '거래량이 전혀 변하지 않는 평이한 상태 유지', '호가 스프레드가 가장 좁아지는 횡보 상태']::text[], 1, '참된 저항 돌파(True Breakout)는 저항선 부근의 두터운 대기 매도 공급 물량을 대규모 자금으로 전부 씹어 삼키고 돌파해야 함을 뜻합니다. 따라서 반드시 평균 대비 1.5배~2배 이상의 거래량 분출이 동반되어야 신뢰할 수 있으며, 거래량이 적은 돌파는 꼬리 달고 내려앉는 불 트랩(Bull Trap)일 확률이 매우 높습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (865, '거래량/유동성', '05_volume_liquidity.md', '리플 차트에서 중요 지지선 직전 저점 아래에 엄청난 규모의 롱 포지션 청산 및 매도 손절 주문이 쌓여 있는 유동성 풀(Liquidity Pool) 구간이 감지되었습니다. 세력이 이 구간을 공략할 때 나타날 캔들의 전형적인 무빙 패턴은?', '[{"time":"Day 1","open":1000000,"high":1010000,"low":984000,"close":990000,"volume":33},{"time":"Day 2","open":990000,"high":996000,"low":960000,"close":992000,"volume":24}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":984000},{"x":1,"y":984000}],"label":"전저점 지지선","color":"#3b82f6"}]'::jsonb, ARRAY['지지선을 장대음봉으로 돌파하여 20% 폭락 마감', '전저점 이탈로 손절 유도 후 지지선 위 아래꼬리 안착', '오차 없이 지지선 터치 후 꼬리 없는 수평 도지 횡보', '거래량 없이 즉각 상승 빔 분출로 전고점 탈환']::text[], 1, '기관 세력(스마트 머니)은 대량 포지션을 구축하기 위해 개인의 손절 주문(Sell Stop)을 의도적으로 터트려 매도 유동성을 유도한 후 이를 다 매수합니다. 이로 인해 리플 시세는 지지선 아래로 일시 급락 후(스톱 헌팅), 아래꼬리를 매우 길게 달며 지선 안쪽으로 급반등 마감하게 됩니다. 이것이 유동성 스윕(Liquidity Sweep)의 정석 패턴입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (866, '거래량/유동성', '05_volume_liquidity.md', '상승 추세 도중 전고점 저항선 부근에서 위꼬리가 아주 긴 캔들이 터졌고, 거래량은 최근 보름 중 최고 수치로 솟구쳤습니다. VSA 관점에서 이 상승 거절(Upside Rejection) 현상에 대한 올바른 대처는?', '[{"time":"Day 1","open":2000,"high":2300,"low":1960,"close":2020}]'::jsonb, '[]'::jsonb, ARRAY['강한 저점 매수 기회로 인지하여 비중 대폭 추가', '고점 매도 Rejection 확인 후 기존 롱 포지션 대피', '박스 횡보 수렴 기대로 마틴게일 추가 매수 가동', '이평선 정배열 판단에 따른 포지션 변경 없이 홀딩']::text[], 1, '위꼬리가 매우 긴 캔들이 대량 거래량과 함께 터졌다는 것은 고점 돌파 시도가 있었으나 그 자리에 숨어 있던 세력의 막강한 청산 매도 벽(Supply)을 만나 격렬하게 두들겨 맞고 밀려났음을 의미합니다. 상방 거절의 심리가 지배적이므로 고점 피로 및 하락 전환이 임박한 위험 징후입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (867, '지표/컨플루언스', '06_technical_indicators.md', '리플 시세가 장기 박스권 횡보를 이어가며 볼린저 밴드의 폭이 최근 몇 달 중 가장 좁은 형태로 밀착 수렴(Squeeze)되었습니다. 이 스퀴즈 국면에 대한 올바른 기술적 이해와 매매 시나리오는?', '[{"time":"Week 1","open":2000,"high":2060,"low":1940,"close":2020,"volume":91},{"time":"Week 2","open":2020,"high":2040,"low":1980,"close":2000,"volume":117}]'::jsonb, '[]'::jsonb, ARRAY['박스권 변동성 부재 기대로 장기 무대응 관망', '에너지 수축 스퀴즈 확인 후 밴드 이탈 돌파 대기', '지표 신뢰 불가 판단으로 볼린저 밴드 지표 삭제', '중심선 지지로 판단하여 고배율 매수 대기 주문']::text[], 1, '볼린저 밴드의 폭이 극도로 좁아지는 스퀴즈(Squeeze) 현상은 시장의 표준편차 변동성이 임계치까지 압축 수렴되었음을 알려줍니다. 에너지 압축 뒤에는 항상 폭발적인 가격 분출(상방/하방 이탈)이 뒤따르므로, 밴드를 뚫고 거래량이 실려 돌파 마감하는 방향으로 추세 추종 시나리오를 설계해야 합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (868, '지표/컨플루언스', '06_technical_indicators.md', '리플 시세는 HL(Higher Low)을 형성하며 이전 직전 저점(1,800달러)보다 높은 저점(1,900달러)을 지키고 있으나, RSI 지표는 이전 35 수치보다 더 깊숙하게 25 수치까지 떨어졌습니다. 이 지표 불일치 현상의 공식 명칭과 올바른 포지션 셋업은?', '[{"time":"Day 1","open":2000,"high":2040,"low":1800,"close":1820,"volume":111},{"time":"Day 2","open":1820,"high":1920,"low":1900,"close":1900,"volume":121}]'::jsonb, '[]'::jsonb, ARRAY['일반 상승 다이버전스 - 추세 종결로 즉각 공매도', '히든 상승 다이버전스 - 지선 눌림목 롱 진입 활용', '일반 하락 다이버전스 - 모든 매수 포지션 정리', '지표 오작동 휩소 구간 판단으로 양방향 관망']::text[], 1, '가격의 저점은 높아졌는데(Higher Low) 모멘텀 지표의 저점은 낮아지는 현상은 ''히든 상승 다이버전스(Hidden Bullish Divergence)''입니다. 이는 추세 반전이 아닌 **기존 강세 추세 지속**을 뜻하며, 조정 눌림목이 완성되고 다음 상승 랠리를 준비한다는 최고의 매수 신호 중 하나입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (869, '지표/컨플루언스', '06_technical_indicators.md', '매수 타점을 신중하게 선별하고자 합니다. 기술적 분석의 성공 확률을 비약적으로 끌어올리는 ''다중 컨플루언스(Confluence)'' 결합 사례로 가장 적합한 조건 구성은?', '[{"time":"Today","open":2000,"high":2000,"low":2000,"close":2000}]'::jsonb, '[]'::jsonb, ARRAY['트위터 및 뉴스의 호재 찌라시 확인 즉시 추격', '지지선+이평선+다이버전스+아래꼬리 등 분석 중첩 시', 'RSI 과매수 영역 진입 즉시 롱 포지션 진입', '독립적 분석 없이 오직 보조지표의 단일 수치 신호']::text[], 1, '다중 컨플루언스(Confluence)는 독립적인 기술적 근거들이 동일한 특정 가격 구역에 중첩되는 현상입니다. 지지 저항, 이평선, 보조지표 다이버전스, 캔들 가격행동(Rejection 핀바)이 한 곳에 묶여 매수 자리를 형성할 때 매매를 실행하면, 높은 신뢰도와 좁은 손절 라인 덕분에 장기 기대값이 극대화됩니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (870, '셋업/실행', '08_setup_entry_exit.md', '중요 수평 저항선(2,400달러)을 상방으로 장대양봉 종가 돌파한 것을 확인하고 롱(매수) 진입 셋업을 준비하고 있습니다. 원칙 트레이더가 뇌동매매 추격을 막고 최상의 손익비를 확보하기 위해 즐겨 쓰는 정석적인 진입 실행법은?', '[{"time":"Day 1","open":2200,"high":2240,"low":2180,"close":2220,"volume":119},{"time":"Day 2","open":2220,"high":2480,"low":2200,"close":2440,"volume":89}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":2400},{"x":1,"y":2400}],"label":"저항선","color":"#ef4444"}]'::jsonb, ARRAY['돌파 마감 확인 즉시 시장가 추가 매수 집행', '돌파된 저항선의 지지 전환(Retest) 시 지정가 진입', '반등 조정이 불가능하다고 판단하여 최고점 롱 추격', '속임수 돌파 확신으로 고배율 역베팅 숏 진입']::text[], 1, '저항 돌파 후 즉시 가격을 따라붙는 추격 매수는 휩소 조정 시 심각한 손실을 초래합니다. 돌파된 라인이 S/R Flip을 통해 지지로 작용하는지 확인하는 되돌림 리테스트(Retest) 시점에 진입하는 것이, 지선 바로 아래에 좁은 손절 라인을 설계하고 이익 기대 폭을 넓힐 수 있는 가장 이상적인 정석 실행법입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (871, '셋업/실행', '08_setup_entry_exit.md', '포지션 진입 직후, 가격이 계획대로 내 방향으로 순탄하게 우상향하고 있습니다. 기존 진입 시 설정한 손익비 1:2의 최종 목표가 도달 전에, 리스크 관리 차원에서 계좌 드로다운을 0으로 만드는 정석적인 1차 포지션 관리 행동은?', '[{"time":"Entry","open":2000,"high":2000,"low":2000,"close":2000,"volume":92},{"time":"Day 1","open":2000,"high":2120,"low":2000,"close":2100,"volume":107}]'::jsonb, '[]'::jsonb, ARRAY['1차 저항대 진입 시 레버리지를 활용해 불타기', '목표가 터치 시까지 100% 비중 무대응 홀딩', '1:1 지점 50% 분할 익절 및 남은 물량 본전 손절 상향', '단기 반등 확인 즉시 전량 기계적 청산 및 퇴장']::text[], 2, '이득이 발생해 손익비 1:1 수준에 오면 물량의 절반을 분할 익절(Scale-out)하고 남은 포지션의 스톱로스를 진입가로 이동(Break-even)시키는 것이 포지션 관리의 기본입니다. 이렇게 셋업하면 차트가 갑자기 폭락세로 뒤집혀도 최소 본전 혹은 반절 익절 약수익으로 끝나 해당 거래의 최대 리스크가 Zero(0)로 봉쇄됩니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (872, '셋업/실행', '08_setup_entry_exit.md', '강력한 장기 상승 추세가 터져 리플 시세가 20일 이평선을 타고 계속해서 폭발적으로 신고가를 갱신하고 있습니다. 이때 익절 시점을 서둘러 잡지 않고, 추세 상승 이익을 최대한 길게 끝까지 빨아먹기 위한 정석 청산 실행법은?', '[{"time":"Day 1","open":2000,"high":2200,"low":1980,"close":2160,"volume":108},{"time":"Day 2","open":2160,"high":2400,"low":2140,"close":2360,"volume":120},{"time":"Day 3","open":2360,"high":2700,"low":2340,"close":2640,"volume":94}]'::jsonb, '[]'::jsonb, ARRAY['RSI 과과열 조짐 확인 즉시 시장가 전량 익절', 'Higher Low 지지 직하방으로 손절 추종 익절 셋업', '이익 보존을 포기하고 손익절 라인을 해제 후 홀딩', '즉시 숏 포지션 10배로 맞불을 놓는다']::text[], 1, '강세 추세가 터졌을 때 지레짐작으로 청산하면 상승 파동의 초입만 먹고 끝납니다. 추세 붕괴의 명확한 신호(BOS/MSB)가 나오거나, 가격의 구조적 높은 저점(HL)이 깨질 때까지 손절 라인을 계속 추종해서 상향하는 ''추격 손절매(Trailing Stop)''를 가동하는 것이 추세 이익을 극대화하는 정석 기법입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (873, '셋업/실행', '01_chart_market_basics.md', '차트 분석 결과, 돌파 시점의 체결 변동성과 거래소 호가창의 얇은 매물 상태를 감안할 때 내가 진입하려는 주문 가격에서 체결이 뒤로 밀리는 ''슬리피지(Slippage)''가 심각하게 예상됩니다. 이를 감안한 올바른 주문 실행법은?', '[{"time":"Today","open":2000,"high":2000,"low":2000,"close":2000}]'::jsonb, '[]'::jsonb, ARRAY['시장가로 최고 배율을 설정하여 즉시 체결', '돌파 확인 후 지정가 대기 주문으로 단가 조절', '슬리피지를 예방하기 위해 즉각적인 거래 취소', '호가창 스프레드와 무관하게 고배율 레버리지']::text[], 1, '변동성이 크고 호가가 얇은 시장에서 돌파 시 시장가 진입은 나쁜 단가로 체결되는 슬리피지 비용을 발생시켜 시작부터 손실을 크게 안고 갑니다. 돌파 확인 후 되돌림 가격대에서 지정가(Limit Order)를 대기시켜 체결 단가를 내 손아귀에 고정하는 리스크 관리가 필요합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (874, '셋업/실행', '10_psychology_routine_review.md', '원칙 기반의 정석 매매 셋업(Trading Setup)을 설계할 때, 진입 전 반드시 사전에 수치로 명문화되어 결정되어야 할 요소가 아닌 것은?', '[{"time":"Today","open":2000,"high":2000,"low":2000,"close":2000}]'::jsonb, '[]'::jsonb, ARRAY['진입 조건(Trigger)과 구체적인 손절 가격(Stop Loss)', '거래 당일 본인의 주관적인 직감과 감정적 목표가', '진입하려는 구체적인 포지션 규모 및 분할 익절선', '거래 아이디어가 무효화되는 구체적 가격 지점']::text[], 1, '매매 셋업은 규칙에 기반한 수치들(진입가, 손절가, 목표가, 수량)로 사전에 철저히 규격화되어야 합니다. 당일의 운이나 주관적 느낌, 예감에 기초한 비과학적 청산 설정은 셋업에서 배제되어야 할 대표적 뇌동매매 요소입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (875, '셋업/실행', '08_setup_entry_exit.md', '하락 횡보하던 리플 시세가 중요 매물대이자 피보나치 되돌림 0.618 지점에 정확히 맞닿아 아래꼬리가 긴 양봉 핀바(Pin Bar)를 그리며 마감했습니다. 룰베이스 트레이더가 진입 버튼을 누를 때 성립된 IF-THEN 시나리오는?', '[{"time":"Day 1","open":2000,"high":2000,"low":1600,"close":1640,"volume":117},{"time":"Day 2","open":1640,"high":1720,"low":1560,"close":1700,"volume":94}]'::jsonb, '[]'::jsonb, ARRAY['익일 가격 상황과 관계없이 100배 레버리지 진입', '중첩 자리 핀바(rejection) 확인 후 익일 시가 롱 진입', '상단 저항 도달 판단으로 즉각적인 숏 포지션 진입', '돌파 랠리가 완전히 끝날 때까지 HTS 종료 및 관망']::text[], 1, '훌륭한 트레이딩 실행은 ''IF(조건 만족 시) ➔ THEN(원칙대로 포지션 진입 및 손절/목표가 기계적 배치)''의 룰베이스 알고리즘에 의해 움직여야 감정을 배제할 수 있습니다. 지지 구간 중첩과 핀바 출현 조건이 성립했으므로 다음 봉 시가에 진입하되 꼬리 저점 이탈 시 칼손절하여 리스크를 통제하는 것이 정석입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (876, '리스크/심리', '09_risk_position_management.md', '나의 트레이딩 시스템 승률이 40%로 다소 낮게 고정되어 있습니다. 이 시스템을 통해 장기적으로 파산하지 않고 복리로 계좌 자산을 우상향시키기 위해 필수적으로 지켜야 할 손익비(평균손실 대비 평균수익 비율)의 최소 기준은?', '[{"time":"Today","open":2000,"high":2000,"low":2000,"close":2000}]'::jsonb, '[]'::jsonb, ARRAY['손익비 1:1 수준 (매매 승률이 낮을 때 파산)', '승률 40% 대비 기댓값 개선을 위한 손익비 1:1.5 이상', '낮은 승률 상태에서 손익비와 무관하게 무조건 파산', '승률 극복을 위한 레버리지 20배 수준 설정']::text[], 1, '승률이 40%일 때 기대값 수학적 수수료 감안 최소 손익비는 1:1.5입니다. 손익비 1.5배 이상 구간만 취하면 10번 중 6번 손절당하고 단 4번만 익절하더라도 계좌 총합은 수익 우위에 서게 됩니다. 저승률 시스템일수록 철저히 손익비가 유리한 진입가 근처 타점만 기계적으로 필터링해 진입해야 생존합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (877, '리스크/심리', '09_risk_position_management.md', '선물 트레이더인 B는 담보금 효율을 극대화한다는 명목으로 50배 레버리지 롱 포지션 진입을 실행했습니다. 진입 가격 대비 B의 포지션 원금이 완전 소멸(강제 청산)되는 역방향 하락 거리(%)는 대략 몇 % 수준입니까?', '[{"time":"Today","open":2000,"high":2000,"low":2000,"close":2000}]'::jsonb, '[]'::jsonb, ARRAY['진입 단가 대비 20.0%의 강한 하락 발생 시', '진입 단가 대비 단 -2.0% 변동성 노이즈 터치 시', '진입 단가 대비 50.0%의 강한 폭락 발생 시', '청산가가 산출되지 않는 특이 종목 거래 시']::text[], 1, '청산 거리 계산 공식은 대략 `100% / 레버리지 배수` 입니다. 50배 고배율 레버리지의 경우, 내 포지션 반대 방향으로 단 **-2%**의 시세 변동성(장중 흔한 잔파동 노이즈)만 터치해도 원금이 100% 강제 청산 증발됩니다. 고배율 레버리지는 수학적 확률상 100% 파멸을 초래하는 도박성 거래 행위입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (878, '리스크/심리', '09_risk_position_management.md', '트레이딩 계좌 총자산이 40,000만 원인 트레이더가 있습니다. 1회 거래당 총자산의 2% 룰 원칙에 근거하여 리스크 한도(800만 원)를 설정했습니다. 진입하려는 종목의 손절가 거리가 -8%인 경우, 2% 룰을 완벽하게 충족하는 최대 진입(매수) 금액은?', '[{"time":"Today","open":2000,"high":2000,"low":2000,"close":2000}]'::jsonb, '[]'::jsonb, ARRAY['40,000만 원 전액 매수 (손절 폭을 배제한 대규모 베팅)', '10,000만 원 진입 (-8% 손절 시 리스크 한도 800만 원 충족)', '20,000만 원 진입 (손익비 1:1 기준에 맞춘 베팅)', '4,000만 원 진입 (보수적 원칙에 입각한 극단적 축소)']::text[], 1, '포지션 사이징 공식은 `진입금액 = 최대 리스크 허용액(800만 원) / 손절 비율(0.08)` 입니다. 이에 따라 `8,000,000원 / 0.08 = 100,000,000원`이 도출됩니다. 10,000만 원 규모로 매수 진입 시 가격이 급락해 -8% 손절 라인을 때려도 내 총자산에서 깎이는 금액은 정확히 원칙 한도인 800만 원(2%)으로 제한되어 계좌가 완벽히 방어됩니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (879, '리스크/심리', '10_psychology_routine_review.md', '장중에 내가 째려보며 타점을 기다리던 메이저 코인이 아무런 조정도 없이 장대양봉을 그리며 갑자기 수직 폭등하기 시작하여 5% 이상 치솟았습니다. 이때 머릿속에 ''나만 두고 날아가는 것 아닌가''하는 극심한 소외감 공포(FOMO)가 솟구칩니다. 원칙 트레이더의 올바른 심리 대응은?', '[{"time":"Day 1","open":2000,"high":2040,"low":1980,"close":2000,"volume":101},{"time":"Day 2","open":2000,"high":2120,"low":2000,"close":2100,"volume":98}]'::jsonb, '[]'::jsonb, ARRAY['추세 연장 판단으로 시장가 전액 추격 매수', 'FOMO 판단 하에 매수 보류 및 정석 되돌림 타점 대기', '돌파 실패 판단 하에 반대 방향 고배율 숏 베팅', '거래를 종료하고 즉각 메이저 코인 시장에서 전량 탈출']::text[], 1, '나만 기회를 잃는다는 공포(FOMO)로 날아가는 장대양봉 꼭대기에서 추격 매수하는 행위는 고점 물리기를 자처하는 가장 흔한 뇌동매매 패턴입니다. 내 타점을 비껴간 상승은 내 돈이 아니라고 인정하고, 사전에 정의한 룰베이스 타점까지 냉정하게 대기하는 것이 장기 생존자의 멘탈 습관입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (880, '리스크/심리', '10_psychology_routine_review.md', '오전 거래에서 원칙을 어긴 무리한 진입으로 인해 3회 연속 스톱아웃(손절)을 당하여 당일 원금의 -6%의 큰 손실을 입었습니다. 본전 생각과 분노로 눈이 뒤집혀 비중을 올려 한 판으로 복수하려는 ''보폭 매매'' 충동이 폭발할 때, 파산을 막는 가장 강력한 멘탈 시스템 룰은?', '[{"time":"Today","open":2000,"high":2000,"low":2000,"close":2000}]'::jsonb, '[]'::jsonb, ARRAY['손실 만회를 위해 빌린 돈으로 100배 고배율 복수 베팅', '일일 손실 한도 도달에 따른 매매 강제 종료 및 격리', '주변 유료 전문가 추천 종목을 탐색해 즉각 매수', 'RSI 과매도 상태이므로 즉시 반대 숏 포지션 진입']::text[], 1, '연패를 겪은 후 홧김에 비중을 더 크게 실어 한 번에 본전을 찾으려는 보복 매매는 계좌를 하루 만에 휴지조각으로 만드는 가장 무서운 파산 유도 심리 상태입니다. 이를 막기 위해 하루 최대 손실 한도 한계선(예: 3회 손절 또는 원금의 5%)을 정해두고, 이 한계선 터치 시 즉시 차트를 종료하고 냉각기를 강제 집행하는 룰이 필수입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (901, '캔들/가격행동', '02_candlestick_price_action.md', '하락 추세 지속 도중 바닥권에서 몸통이 짧고 아래꼬리가 몸통의 2배 이상인 아래 캔들이 출현했습니다. 이 캔들의 명칭과 올바른 대응은?', '[{"time":"10:00","open":6000,"high":6100,"low":5900,"close":5950,"volume":82},{"time":"10:15","open":5950,"high":6000,"low":5650,"close":5700,"volume":86},{"time":"10:30","open":5700,"high":5750,"low":5400,"close":5450,"volume":121},{"time":"10:45","open":5450,"high":5500,"low":5050,"close":5100,"volume":123},{"time":"11:00","open":5100,"high":5150,"low":4500,"close":5050,"volume":102}]'::jsonb, '[]'::jsonb, ARRAY['역망치형 (Inverted Hammer) - 하락 경고 및 공매도 대기', '망치형 (Hammer) - 저점 지지 및 분할 매수 대기', '도지 (Doji) - 매수세와 매도세의 팽팽한 균형 및 관망', '하락 장악형 (Bearish Engulfing) - 추세 반전 및 즉시 손절']::text[], 1, '마지막 캔들은 아래꼬리가 긴 ''망치형(Hammer)'' 캔들로 하락 압력을 이겨내고 저가 매수세가 밀어 올렸음을 의미하는 대표적 상승 전환 신호입니다. 지지를 확인한 뒤 분할 매수 관점으로 대기해야 합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (902, '캔들/가격행동', '02_candlestick_price_action.md', '골드 가격가 장기간 급등한 뒤, 고점 부근에서 위꼬리가 매우 길고 몸통이 짧은 형태의 캔들이 발생했습니다. 이 캔들의 해석으로 가장 적절한 것은?', '[{"time":"Day 1","open":5000,"high":5400,"low":4950,"close":5250,"volume":106},{"time":"Day 2","open":5250,"high":5750,"low":5200,"close":5600,"volume":97},{"time":"Day 3","open":5600,"high":6250,"low":5550,"close":6150,"volume":113},{"time":"Day 4","open":6150,"high":6400,"low":6000,"close":6300,"volume":119},{"time":"Day 5","open":6300,"high":7250,"low":6250,"close":6350,"volume":106}]'::jsonb, '[]'::jsonb, ARRAY['유성형 (Shooting Star) - 고점 저항 및 하락 전환 예고', '망치형 (Hammer) - 저점 매수세 유입 및 상승 랠리 기대', '상승 장악형 (Bullish Engulfing) - 추세 반전 및 홀딩 유도', '도지 (Doji) - 추세 지속 가능성 및 일시 관망']::text[], 0, '급등세 끝에서 위꼬리가 몸통보다 훨씬 길게 솟아오른 캔들은 ''유성형(Shooting Star)''입니다. 장중 상승 시도를 강력한 차익 실현 및 매도 압력이 짓눌렀음을 보여주며, 하락 추세 전환의 강력한 경고 시그널입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (903, '캔들/가격행동', '02_candlestick_price_action.md', '직전의 음봉 몸통을 다음 날의 거대한 양봉 몸통이 완전히 감싸 안는 아래 형태가 포착되었습니다. 이 패턴의 이름과 신뢰도는?', '[{"time":"Day 1","open":4900,"high":5000,"low":4750,"close":4800,"volume":91},{"time":"Day 2","open":4800,"high":4850,"low":4600,"close":4650,"volume":98},{"time":"Day 3","open":4650,"high":4750,"low":4400,"close":4450,"volume":112},{"time":"Day 4","open":4350,"high":5100,"low":4300,"close":5050,"volume":108}]'::jsonb, '[]'::jsonb, ARRAY['하락 장악형 (Bearish Engulfing) - 추세 반전 신뢰도 낮음', '상승 장악형 (Bullish Engulfing) - 매수 전환 신뢰도 높음', '상승 관통형 (Piercing Line) - 중간 강도의 반전 신호', '석별형 (Evening Star) - 상승 추세 종결 신호']::text[], 1, '전일의 하락 음봉 몸통을 다음 날의 장대 양봉이 완전히 덮어버리는 형태를 ''상승 장악형(Bullish Engulfing)'' 패턴이라고 합니다. 하락 추세 끝에서 나타날 경우 단기 하락세가 종료되고 강력한 매수세가 들어왔음을 뜻해 전환 신뢰도가 매우 높습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (904, '캔들/가격행동', '01_chart_market_basics.md', '시가와 종가가 거의 일치하여 몸통이 거의 없고 위아래 꼬리만 달린 십자(+) 모양 캔들이 출현했습니다. 이 캔들에 대한 올바른 해석은?', '[{"time":"Day 1","open":7500,"high":7750,"low":7400,"close":7600,"volume":105},{"time":"Day 2","open":7600,"high":7800,"low":7550,"close":7700,"volume":95},{"time":"Day 3","open":7700,"high":7950,"low":7500,"close":7700,"volume":98}]'::jsonb, '[]'::jsonb, ARRAY['상승세 동력 상실로 인한 추세의 하방 반전', '매수/매도 세력 균형에 따른 도지(Doji) 횡보', '매도세 지배에 따른 즉각적인 숏 포지션 진입', '하락 세력 이탈로 인한 즉각적인 상승 랠리']::text[], 1, '시가와 종가가 거의 같은 십자 모양의 캔들은 ''도지(Doji)'' 캔들입니다. 이는 힘의 균형이 팽팽함을 시사하며, 기존 추세의 힘이 빠지고 잠재적인 방향성 전환(상승/하락 모두 포함)의 변곡점이 다가오고 있음을 의미합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (905, '캔들/가격행동', '02_candlestick_price_action.md', '상승 추세 고점에서 직전 양봉의 몸통을 거대 음봉이 아래로 덮어버리는 캔들 조합이 발생했습니다. 이 현상을 의미하는 용어는?', '[{"time":"Day 1","open":6000,"high":6250,"low":5950,"close":6200,"volume":89},{"time":"Day 2","open":6200,"high":6500,"low":6150,"close":6450,"volume":123},{"time":"Day 3","open":6500,"high":6550,"low":5750,"close":5800,"volume":89}]'::jsonb, '[]'::jsonb, ARRAY['하락 장악형 (Bearish Engulfing) - 고점 하락 전환 예고', '상승 장악형 (Bullish Engulfing) - 고점 돌파 랠리 예고', '하락 잉태형 (Harami) - 기존 하락세의 일시 둔화', '샛별형 (Morning Star) - 바닥권 상승 반전 예고']::text[], 0, '고점에서 직전 양봉을 음봉이 감싸 안은 형태는 ''하락 장악형(Bearish Engulfing)''입니다. 매수 세력을 매도 공급이 압도했다는 명백한 증거로, 골드 가격 추세가 하락으로 반전할 리스크가 큽니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (906, '시장구조/SR', '03_market_structure.md', '골드 가격가 장기 저항선인 7,500달러를 거래량 실린 강한 캔들로 돌파한 뒤, 다시 7,500달러 부근으로 내려와 버티고 있습니다. 가장 안전한 진입 방식은?', '[{"time":"Day 1","open":7000,"high":7400,"low":6950,"close":7250,"volume":119},{"time":"Day 2","open":7250,"high":7450,"low":7150,"close":7200,"volume":122},{"time":"Day 3","open":7200,"high":7800,"low":7150,"close":7700,"volume":96},{"time":"Day 4","open":7700,"high":7750,"low":7450,"close":7550,"volume":332},{"time":"Day 5","open":7550,"high":7650,"low":7500,"close":7600,"volume":336}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":7500},{"x":4,"y":7500}],"label":"돌파된 저항선 -> 지지선 전환선","color":"#3b82f6"}]'::jsonb, ARRAY['돌파 시점에 시장가로 즉시 진입하는 추격 매수', '돌파 후 저항선의 지지선 전환(Retest) 확인 시 진입', '이전 최저가 부근인 7,000달러 조정 시까지 대기 매수', '돌파 후 즉시 단기 조정을 예상한 역추세 숏 진입']::text[], 1, '저항선이 강하게 뚫리면 역할 전환(Role Reversal)에 의해 신규 지지선으로 바뀝니다. 돌파 시점에 뇌동매매하기보다는 돌파된 선 부근으로 골드 가격가 눌려 지지(Retest)를 완성할 때 진입하는 것이 리스크 대비 기대 수익이 큽니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (907, '거래량/유동성', '05_volume_liquidity.md', '골드 가격가 저항선 위로 거래량 없이 장대양봉을 뿜어 올렸으나, 다음 날 곧바로 장대음봉으로 밀어붙이며 저항선 아래로 내려왔습니다. 이 현상의 명칭은?', '[{"time":"Day 1","open":4900,"high":5050,"low":4850,"close":5000,"volume":87},{"time":"Day 2","open":5000,"high":5100,"low":4950,"close":5050,"volume":107},{"time":"Day 3","open":5050,"high":5500,"low":5000,"close":5400,"volume":20},{"time":"Day 4","open":5400,"high":5450,"low":4750,"close":4800,"volume":26}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":5100},{"x":3,"y":5100}],"label":"저항선","color":"#ef4444"}]'::jsonb, ARRAY['진짜 상승 돌파 (True Breakout)', '불 트랩 (Bull Trap) - 매수자 청산 유도 가짜 돌파', '베어 트랩 (Bear Trap) - 매도자 청산 유도 가짜 하방', '골든 크로스 (Golden Cross) - 이평선 돌파']::text[], 1, '저항선을 일시적으로 뚫었다가 대량 매도세와 함께 직후 캔들에서 하방으로 원상복귀하는 현상을 ''불 트랩(Bull Trap/가짜 돌파)''이라고 합니다. 돌파 후 리테스트를 기다리지 않고 급히 추격 매수했던 투자자들이 고점에 물리는 대표적 함정입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (908, '시장구조/SR', '01_chart_market_basics.md', '아래 차트에서 3번 연속 강하게 반등하며 가격 하락을 저지해 준 주요 가격대는 무엇을 의미하나요?', '[{"time":"Day 1","open":5000,"high":5100,"low":4500,"close":4550,"volume":80},{"time":"Day 2","open":4550,"high":4900,"low":4500,"close":4850,"volume":102},{"time":"Day 3","open":4850,"high":5250,"low":4800,"close":5200,"volume":97},{"time":"Day 4","open":5200,"high":5300,"low":4550,"close":4600,"volume":93},{"time":"Day 5","open":4600,"high":5000,"low":4500,"close":4950,"volume":134}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":4500},{"x":4,"y":4500}],"label":"4,500달러선","color":"#10b981"}]'::jsonb, ARRAY['강력한 저항선 (Resistance Line) - 매도 매물대', '강력한 지지선 (Support Line) - 매수 매물대', '골든크로스 수렴선 - 이평선 밀집대', '이격도 붕괴선 - 가격 과열 분기점']::text[], 1, '특정 가격(4,500달러)에 접근할 때마다 대기 중이던 저가 매수세가 유입되어 골드 가격의 추가 하락을 방어해 준 이 라인은 ''강력한 지지선(Support Line)''입니다. 이탈하기 전까지는 손절 라인을 바로 밑에 두고 진입하기에 가장 손익비 좋은 구간입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (909, '거래량/유동성', '05_volume_liquidity.md', '지지선 아래로 골드 가격가 이탈하여 공매도가 폭증했으나, 이내 거래량이 급증하며 양봉으로 지지선을 회복한 뒤 반등을 시작했습니다. 이 현상의 명칭은?', '[{"time":"Day 1","open":6000,"high":6100,"low":5900,"close":5950,"volume":98},{"time":"Day 2","open":5950,"high":6000,"low":5500,"close":5550,"volume":120},{"time":"Day 3","open":5550,"high":6150,"low":5500,"close":6100,"volume":95}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":5750},{"x":2,"y":5750}],"label":"지지선","color":"#10b981"}]'::jsonb, ARRAY['불 트랩 (Bull Trap) - 가짜 상방 돌파', '베어 트랩 (Bear Trap) - 가짜 하방 이탈', '리테스트 실패 - 지지선 붕괴', '추세 추종 돌파 - 하방 랠리 가속']::text[], 1, '지지선을 아래로 뚫고 내려가 하락세가 지속될 것처럼 유도한 뒤, 매물을 털어내고 강력하게 다시 반등해 올리는 현상을 ''베어 트랩(Bear Trap)''이라고 합니다. 하락 돌파로 생각하고 공매도를 치거나 손절했던 사람들의 손실을 강제하며 가격이 급등하게 만듭니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (910, '시장구조/SR', '04_patterns_breakout.md', '저항선을 뚫어내기 직전 돌파 전조 현상 중 하나인 ''지지점 상승''의 특징을 골라보세요.', '[{"time":"Day 1","open":5000,"high":5250,"low":4500,"close":5100,"volume":107},{"time":"Day 2","open":5100,"high":5250,"low":4650,"close":5150,"volume":115},{"time":"Day 3","open":5150,"high":5250,"low":4800,"close":5200,"volume":100}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":5250},{"x":2,"y":5250}],"label":"저항선 (105)","color":"#ef4444"}]'::jsonb, ARRAY['저항선 부근에서 고점들이 점점 급락하며 붕괴하는 현상', '저항선 부근에서 저점들을 높여가며 밀어 올리는 수렴 현상', '거래량이 완전히 소멸하여 긴 횡보 상태를 보이는 현상', '지속적인 매도세로 인해 갑작스럽게 급락하는 현상']::text[], 1, '저항을 뚫지 못하고 밀려 내려올 때, 이전 저점보다 높은 지점에서 저점을 계속 잡아 올려주는 것은 매도 압력보다 매수 압력이 점점 올라오고 있음을 의미합니다. 수렴 끝에 돌파가 나타날 신뢰도가 매우 높습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (911, '추세/레짐', '03_market_structure.md', '저점들을 연결한 우상향 상승 추세선 아래로 캔들의 종가(마감가격)가 이탈했습니다. 기술적 분석 관점의 올바른 해석은 무엇입니까?', '[{"time":"W-5","open":5000,"high":5250,"low":5000,"close":5150,"volume":82},{"time":"W-4","open":5150,"high":5500,"low":5100,"close":5400,"volume":111},{"time":"W-3","open":5400,"high":5450,"low":5250,"close":5300,"volume":89},{"time":"W-2","open":5300,"high":5750,"low":5350,"close":5650,"volume":114},{"time":"Today","open":5650,"high":5700,"low":5150,"close":5200,"volume":117}]'::jsonb, '[{"type":"line","points":[{"x":0,"y":5000},{"x":2,"y":5250},{"x":4,"y":5500}],"label":"상승 추세선","color":"#10b981"}]'::jsonb, ARRAY['추세선 이탈은 영향이 없으므로 비중 유지', '상승 추세 붕괴로 하락 반전 대비 비중 축소', '일시적인 속임수이므로 추가 불타기 진입', '채널 상단 도달에 따른 즉각적인 매수 대응']::text[], 1, '신뢰받던 우상향 상승 추세선 하방으로 캔들의 종가가 이탈 마감하는 것은 매수 중심의 시장 주도권이 붕괴했음을 뜻합니다. 지지를 잃은 하락 가속화 리스크에 대비해야 합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (912, '추세/레짐', '07_multitimeframe_regime.md', '아래 차트에서 고점들과 저점들이 일정한 평행 통로를 그리며 하락하고 있습니다. 채널 하단에 도달했을 때 단기 반등을 목표로 하는 매매의 명칭과 관점은?', '[{"time":"Day 1","open":7500,"high":7600,"low":6750,"close":7000,"volume":101},{"time":"Day 2","open":7000,"high":7350,"low":6950,"close":7250,"volume":119},{"time":"Day 3","open":7250,"high":7300,"low":6400,"close":6500,"volume":122},{"time":"Day 4","open":6500,"high":6900,"low":6450,"close":6800,"volume":119},{"time":"Day 5","open":6800,"high":6850,"low":5900,"close":6000,"volume":108}]'::jsonb, '[{"type":"channel","points":[{"x":0,"y":7500},{"x":4,"y":6750},{"x":0,"y":6750},{"x":4,"y":6000}],"label":"하향 평행 채널","color":"#f59e0b"}]'::jsonb, ARRAY['추세 추종 매매 - 대세 상승이므로 장기 보유', '채널 하단 반등 매매 - 단기 역추세 매수 대응', '양방향 물타기 매매 - 평단가를 낮춰 탈출 대기', '돌파 매매 - 채널 하방 붕괴 확정 시 매수 대응']::text[], 1, '가격이 평행한 하락 터널 내에서 움직이는 ''하향 평행 채널(Descending Channel)''입니다. 채널 하단 라인 터치 시에는 기술적 단기 반등이 자주 출현하므로, 손절선을 짧게 잡고 반등 타점을 노리는 역추세(Counter-trend) 트레이딩이 가능합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (913, '추세/레짐', '03_market_structure.md', '우상향 상승 평행 채널의 상단 저항선 부근까지 골드 가격가 도달했습니다. 합리적인 추세 채널 트레이더의 대응은?', '[{"time":"Day 1","open":5000,"high":5100,"low":4950,"close":5050,"volume":97},{"time":"Day 2","open":5050,"high":5400,"low":5050,"close":5350,"volume":107},{"time":"Day 3","open":5350,"high":5450,"low":5200,"close":5250,"volume":123},{"time":"Day 4","open":5250,"high":5750,"low":5250,"close":5700,"volume":96},{"time":"Day 5","open":5700,"high":5800,"low":5600,"close":5650,"volume":97}]'::jsonb, '[{"type":"channel","points":[{"x":0,"y":5100},{"x":4,"y":5750},{"x":0,"y":4950},{"x":4,"y":5600}],"label":"상승 평행 채널","color":"#10b981"}]'::jsonb, ARRAY['채널 상방 돌파를 예상한 고배율 레버리지 매수', '채널 상단 저항에 따른 분할 익절 및 대기', '채널 중간 조정 시 지정을 통한 시장가 추격', '채널 붕괴 신호에 따른 전량 기계적 손절']::text[], 1, '상승 채널이라고 해도 상단 저항선에 닿으면 다시 채널 하단이나 중심선까지 조정을 받을 가능성이 매우 큽니다. 따라서 고점 영역에서의 추격매수를 금지하고, 기존 포지션을 분할 익절하는 기회로 삼아야 합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (914, '추세/레짐', '01_chart_market_basics.md', '고점들을 잇는 우하향 하락 추세선을 골드 가격가 대량의 거래량을 동반하며 장대양봉 종가로 상향 돌파(Breakout)했습니다. 의미하는 시그널은?', '[{"time":"Day 1","open":6500,"high":6600,"low":6250,"close":6350,"volume":84},{"time":"Day 2","open":6350,"high":6400,"low":6000,"close":6100,"volume":115},{"time":"Day 3","open":6100,"high":6150,"low":5750,"close":5850,"volume":123},{"time":"Day 4","open":5850,"high":6400,"low":5800,"close":6350,"volume":100}]'::jsonb, '[{"type":"line","points":[{"x":0,"y":6550},{"x":2,"y":6100},{"x":3,"y":5900}],"label":"하락 추세선","color":"#ef4444"}]'::jsonb, ARRAY['하락 추세 지속에 따른 숏 포지션 추가 매수', '하락 추세 돌파 및 상승 전환 가능성에 따른 매수', '속임수 돌파를 예상한 즉시 반대 숏 포지션 진입', '추세와 무관하게 횡보 흐름으로 판단해 관망']::text[], 1, '중요한 하락 추세선을 골드 가격 몸통이 확실하게 뚫고 마감하는 것은 기존 하락 관성의 지배력이 종료되고 상승 추세로 돌아설 수 있는 가장 대표적인 추세 전환(Reversal) 확인 시그널입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (915, '추세/레짐', '03_market_structure.md', '추세선 작도 시 신뢰도를 판단하는 가장 중요한 규칙은 무엇인가요?', '[{"time":"Day 1","open":5000,"high":5050,"low":5000,"close":5050,"volume":94},{"time":"Day 2","open":5050,"high":5250,"low":5100,"close":5200,"volume":122}]'::jsonb, '[]'::jsonb, ARRAY['차트상 선이 정배열로 정돈되어 그려질 때', '최소 3개 이상의 뚜렷한 저점/고점 터치 확인 시', '가파른 각도로 90도에 가깝게 작도될 때', '보조지표와 결합하여 수평으로 그려질 때']::text[], 1, '두 점만으로도 선을 그릴 수 있지만, 3번째 터치(3rd Touch)에서 정확한 지지나 저항을 보이고 반등해 주는 순간부터 시장 참여자들이 공식 인지하는 신뢰도 높은 추세선이 됩니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (916, '패턴/돌파', '04_patterns_breakout.md', '머리와 양쪽 어깨 형태를 그리며 넥라인 지지선(4,800달러)을 위태롭게 지탱하다가 하방으로 강한 캔들이 이탈했습니다. 숏(매도) 포지션 진입 시점은?', '[{"time":"Day 1","open":5000,"high":5750,"low":4900,"close":5500,"volume":114},{"time":"Day 2","open":5500,"high":6500,"low":4750,"close":5250,"volume":95},{"time":"Day 3","open":5250,"high":5700,"low":4800,"close":5500,"volume":115},{"time":"Day 4","open":5500,"high":5550,"low":4650,"close":4700,"volume":121}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":4800},{"x":3,"y":4800}],"label":"넥라인 지지선","color":"#ef4444"}]'::jsonb, ARRAY['머리 꼭대기(6,500달러) 부근에서 예측 숏 진입', '오른쪽 어깨가 올라가고 있을 때 돌파 전 선진입', '저점들을 연결한 넥라인의 하방 돌파 완료 시', '패턴 완성과 무관하게 오른쪽 어깨 끝에서 대기']::text[], 2, '헤드앤숄더(Head & Shoulders) 패턴은 오른쪽 어깨를 그린 후, 저점 지지선인 ''넥라인(Neckline)''을 거래량을 실어 하방 돌파해야 최종 완성이 선언됩니다. 그전에 진입하면 넥라인 반등 시 극심한 손실을 입습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (917, '패턴/돌파', '04_patterns_breakout.md', '하락 추세 끝에서 골드 가격가 비슷한 깊이의 바닥을 두 번(이중바닥) 형성한 뒤, 중간 고점 저항선(넥라인)을 돌파했습니다. 향후 예상 방향성과 매수 타점은?', '[{"time":"Day 1","open":5000,"high":5000,"low":4000,"close":4250,"volume":117},{"time":"Day 2","open":4250,"high":4750,"low":4200,"close":4700,"volume":101},{"time":"Day 3","open":4700,"high":4750,"low":3950,"close":4100,"volume":122},{"time":"Day 4","open":4100,"high":4950,"low":4050,"close":4900,"volume":112}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":4750},{"x":3,"y":4750}],"label":"넥라인 (95)","color":"#3b82f6"}]'::jsonb, ARRAY['추가 폭락 가능성에 따른 전량 손절 대응', 'W 패턴 이중 바닥 완성 및 넥라인 돌파 시 매수', '박스권 횡보 판단에 따른 무대응 및 관망', '이중 바닥의 하방 이탈을 예상한 숏 포지션 진입']::text[], 1, 'W자 모양의 ''이중 바닥형(Double Bottom)'' 패턴입니다. 골드 가격가 하락을 멈추고 바닥을 두 차례 단단히 지지해 준 뒤 중간 봉우리(넥라인 4,750달러)를 돌파해 마감하면 추세가 상승으로 강하게 전환될 가능성이 매우 높습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (918, '패턴/돌파', '04_patterns_breakout.md', '급격한 기둥식 골드 가격 폭등(깃대) 후, 완만한 하향 평행 채널(깃발) 모양으로 횡보/수렴하다가 채널 상단을 강하게 돌파했습니다. 이 패턴과 예상 목표가는?', '[{"time":"Day 1","open":2500,"high":4000,"low":2450,"close":3900,"volume":92},{"time":"Day 2","open":3900,"high":3950,"low":3600,"close":3700,"volume":97},{"time":"Day 3","open":3700,"high":3800,"low":3500,"close":3550,"volume":88},{"time":"Day 4","open":3550,"high":4250,"low":3500,"close":4150,"volume":95}]'::jsonb, '[]'::jsonb, ARRAY['이중 천정형 패턴 - 고점 도달 시 숏 진입', '불 플래그 패턴 - 깃발 돌파 시 추가 상승 기대', '헤드앤숄더 패턴 - 넥라인 하방 돌파 타겟', '대칭 삼각수렴 패턴 - 변동성 축소 후 돌파 대기']::text[], 1, '대표적 강세 지속 패턴인 ''불 플래그(Bull Flag)''입니다. 급격한 상승(깃대) 뒤 숨 고르기 채널(깃발)을 상방 돌파하면, 이전 상승 파동의 크기(깃대 높이)만큼 추가로 수직 랠리를 시작하는 관성이 있습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (919, '패턴/돌파', '04_patterns_breakout.md', '상승 추세의 천정권에서 골드 가격가 동일한 가격 저항을 두 번 확인하며 M자 모양을 만든 뒤, 두 고점 사이의 저점 지지선인 넥라인(6,000달러)을 이탈했습니다. 올바른 해석은?', '[{"time":"Day 1","open":5000,"high":7000,"low":4950,"close":6750,"volume":97},{"time":"Day 2","open":6750,"high":6800,"low":6000,"close":6100,"volume":112},{"time":"Day 3","open":6100,"high":7000,"low":6050,"close":6900,"volume":114},{"time":"Day 4","open":6900,"high":6950,"low":5750,"close":5800,"volume":121}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":6000},{"x":3,"y":6000}],"label":"넥라인 (120)","color":"#ef4444"}]'::jsonb, ARRAY['상승 추세의 지속 연장에 따른 추가 매수', '이중 천정형(M 패턴) 완성에 따른 하락 반전 대비', '단기 조정에 따른 일시적 횡보 박스권 진입', '방향성 없는 일상적인 잔파동으로 판단해 홀딩']::text[], 1, '고점에서 지지받지 못하고 형성된 M자형 ''이중 천정형(Double Top)'' 패턴입니다. 두 차례 강력한 저항벽(7,000달러)을 넘지 못하고 넥라인(6,000달러)마저 붕괴했으므로 하방 추세가 가속화된다는 신호입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (920, '패턴/돌파', '04_patterns_breakout.md', '고점 저항선은 수평(평평함)을 유지하고 있으나, 저점 지지선은 점점 우상향하며 좁게 수렴하는 차트 형태의 명칭과 일반적인 돌파 방향은?', '[{"time":"Day 1","open":4000,"high":5000,"low":4000,"close":4750,"volume":101},{"time":"Day 2","open":4750,"high":5000,"low":4300,"close":4900,"volume":112},{"time":"Day 3","open":4900,"high":5000,"low":4600,"close":4950,"volume":126}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":5000},{"x":2,"y":5000}],"label":"수평 저항선","color":"#ef4444"},{"type":"line","points":[{"x":0,"y":4000},{"x":1,"y":4300},{"x":2,"y":4600}],"label":"상승 지지선","color":"#10b981"}]'::jsonb, ARRAY['디센딩 트라이앵글 - 일반적으로 하방 돌파 기대', '어센딩 트라이앵글 - 매수 압력 우위로 상방 돌파 기대', '헤드앤숄더 패턴 - 넥라인 하방 돌파 기대', '상향 평행 채널 - 상하단 터치식 채널 매매 기대']::text[], 1, '고점 저항은 평평하고 저점은 계속 높아지는 삼각수렴을 ''어센딩 트라이앵글(Ascending Triangle)''이라고 합니다. 위로 갈수록 저점이 계속 올라가는 현상은 매수세가 가격을 위로 계속 압박하고 있음을 증명하며, 대개 저항선(5,000달러)을 상향 뚫고 오르는 확률이 높습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (921, '지표/컨플루언스', '06_technical_indicators.md', '골드 가격는 매일 하락하여 신저가를 갱신하고 있으나, RSI 보조지표의 저점은 점점 높아지는 현상을 발견했습니다. 올바른 용어와 매매 대응법은?', '[{"time":"D-4","open":5500,"high":5600,"low":4900,"close":5000,"volume":111},{"time":"D-3","open":5000,"high":5200,"low":4800,"close":4900,"volume":105},{"time":"D-2","open":4900,"high":5050,"low":4600,"close":4700,"volume":110},{"time":"D-1","open":4700,"high":4850,"low":4650,"close":4800,"volume":126},{"time":"Today","open":4800,"high":4950,"low":4750,"close":4900,"volume":110}]'::jsonb, '[]'::jsonb, ARRAY['하락 다이버전스 - 가격 상승 둔화에 따른 공매도', '상승 다이버전스 - 하락 둔화 및 반등 신호로 매수', '데드 크로스 - 이평선 하방 교차에 따른 관망', '과매수 이탈 시그널 - 단기 반등에 따른 매수']::text[], 1, '골드 가격의 가격 저점은 낮아지나 보조지표(RSI)의 운동 저점이 높아지는 현상을 ''상승 다이버전스(Bullish Divergence)''라고 합니다. 이는 하방 에너지의 실질적 소멸과 상승 압력의 내부 응축을 의미하는 기술적 분석에서 가장 신뢰도 높은 추세 전환 시그널입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (922, '지표/컨플루언스', '06_technical_indicators.md', '골드 가격는 급격히 치솟으며 최고가 갱신 랠리를 이어가고 있으나, RSI 지표의 고점은 계속 낮아지고 있습니다. 이 현상을 지칭하는 명칭과 대처법은?', '[{"time":"Day 1","open":5000,"high":6000,"low":4950,"close":5900,"volume":112},{"time":"Day 2","open":5900,"high":6100,"low":5750,"close":6000,"volume":121},{"time":"Day 3","open":6000,"high":6750,"low":5950,"close":6650,"volume":92}]'::jsonb, '[]'::jsonb, ARRAY['하락 다이버전스 - 매수 둔화 및 하락 우려로 익절', '상승 다이버전스 - 추가 급등 기대로 신규 매수', '골든 크로스 - 추세 강화에 따른 홀딩', '볼린저 밴드 스퀴즈 - 변동성 수축 후 돌파']::text[], 0, '골드 가격는 계속 고점을 높이고 있으나 보조지표의 고점은 꺾여 낮아지는 현상을 ''하락 다이버전스(Bearish Divergence)''라고 합니다. 이는 매수세의 힘이 표면적인 가격 상승에 비해 실질적으로 빠르게 축소되고 있음을 경고하며, 조만간 큰 급락이 발생할 확률이 높습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (923, '지표/컨플루언스', '06_technical_indicators.md', '이동평균선(EMA) 20일선(단기)이 50일선(중기)을 아래에서 위로 강하게 뚫고 솟구쳐 올랐습니다. 이 교차 현상의 정식 명칭은?', '[{"time":"Day 1","open":5000,"high":5100,"low":4900,"close":4950,"volume":110},{"time":"Day 2","open":4950,"high":5200,"low":4950,"close":5150,"volume":109},{"time":"Day 3","open":5150,"high":5500,"low":5150,"close":5450,"volume":107}]'::jsonb, '[]'::jsonb, ARRAY['데드 크로스 - 단기 이평의 하방 교차로 매도 신호', '골든 크로스 - 단기 이평의 상방 교차로 매수 신호', '볼린저 스퀴즈 - 변동성 수축 및 돌파 신호', '다이버전스 수렴 - 지표와 가격의 동반 횡보']::text[], 1, '단기 이평선이 장기 이평선을 위로 치고 올라가는 현상을 ''골든 크로스(Golden Cross)''라고 합니다. 이는 최근 매수 평단가가 장기 평균가보다 확연히 높아졌음을 시사하며, 상승 추세가 본 궤도에 올랐음을 입증해 줍니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (924, '지표/컨플루언스', '07_multitimeframe_regime.md', '매우 강력한 원웨이 폭락장 속에서 RSI 지표가 20(과매도 영역) 이하로 깊이 내려왔습니다. 이를 보고 ''과매도 반등''을 노리며 기계적 시장가 풀매수를 때렸을 때 나타나는 가장 빈번한 오류는?', '[{"time":"Day 1","open":5000,"high":5050,"low":4400,"close":4450,"volume":110},{"time":"Day 2","open":4450,"high":4500,"low":3750,"close":3800,"volume":25},{"time":"Day 3","open":3800,"high":3850,"low":3100,"close":3150,"volume":34}]'::jsonb, '[]'::jsonb, ARRAY['하락 추세 즉시 종료 및 V자 상승 반등 성공', '강력한 하락장에서의 지표 과매도 고착화 리스크', '거래량 급감으로 인한 호가 정지 및 상장 폐지', '골드 가격의 즉각적인 박스권 횡보 및 변동성 축소']::text[], 1, 'RSI 30 이하 과매도 영역은 반등 신호이기도 하지만, 추세가 지나치게 강력한 하락장일 때는 지표만 과매도 구역에 쳐박힌 채 가격은 계속 급락하는 ''과매도 고착화(Oversold Embedded)'' 상태가 이어집니다. 다이버전스나 캔들 반전형 확인 없이 수치만 보고 들어가는 매수는 깡통으로 가는 지름길입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (925, '지표/컨플루언스', '06_technical_indicators.md', '골드 가격의 변동성이 극도로 축소되며 볼린저 밴드의 폭이 매우 좁아지는 ''스퀴즈(Squeeze)'' 현상이 나타났습니다. 이후 기대되는 시장 변동성의 원리는 무엇인가요?', '[{"time":"Day 1","open":5000,"high":5050,"low":4950,"close":5000,"volume":103},{"time":"Day 2","open":5000,"high":5000,"low":4950,"close":4950,"volume":118},{"time":"Day 3","open":4950,"high":5000,"low":4950,"close":5000,"volume":123}]'::jsonb, '[]'::jsonb, ARRAY['변동성 사멸로 인한 장기 횡보 및 거래 정지', '밴드 스퀴즈 후 변동성 팽창에 따른 추세 분출', '골드 가격의 하방 붕괴로 인한 강한 하락 파동 시작', '이평선들의 수평 정렬에 따른 완전한 추세 고정']::text[], 1, '볼린저 밴드의 수축(Squeeze)은 시장의 숨 고르기 및 힘 모으기를 뜻합니다. 에너지가 최대한 압축된 후에는 밴드 상단 혹은 하단선을 이탈하며 매우 거대한 변동성 팽창(Expansion) 추세가 시작되므로, 방향성을 유심히 지켜봐야 합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (926, '리스크/심리', '09_risk_position_management.md', '총 투자 원금은 50,000만 원이며, 1회 거래 시 최대 손실 허용액을 원금의 2%(1,000만 원)로 제한하는 ''2% 룰''을 지키려 합니다. 진입하려는 종목의 손절 라인 폭이 -5%일 때, 최대 매수(진입) 가능 금액은 얼마인가요?', '[{"time":"Day 1","open":500000,"high":525000,"low":490000,"close":510000,"volume":85},{"time":"Day 2","open":510000,"high":515000,"low":500000,"close":500000,"volume":106}]'::jsonb, '[]'::jsonb, ARRAY['50,000만 원 (원금 전액 진입)', '10,000만 원 (원금의 20% 진입)', '20,000만 원 (원금의 40% 진입)', '25,000만 원 (원금의 50% 진입)']::text[], 2, '2% 룰에 기초한 포지션 사이징 공식은 `진입금액 = (총원금 * 리스크비율) / 손절비율` 입니다. 따라서 `1,000만 원 / 0.05 = 20,000만 원`이 됩니다. 20,000만 원어치 원자재을 샀을 때 가격이 -5% 떨어져 강제 손절을 맞아도 내 계좌 총액에서 손실을 보는 돈은 정확히 2%인 1,000만 원으로 통제됩니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (927, '리스크/심리', '09_risk_position_management.md', '어느 원자재에 500,000원에 매수 진입합니다. 손절 라인은 475,000원(-5%)에 배치하고, 목표가는 575,000원(+15%)에 설정했습니다. 이 트레이딩 시나리오의 손익비(Risk-to-Reward Ratio)는 얼마입니까?', '[{"time":"Today","open":500000,"high":500000,"low":500000,"close":500000}]'::jsonb, '[]'::jsonb, ARRAY['1 : 1 (동일한 기대 수익과 리스크)', '1 : 2 (기대 수익이 리스크의 2배)', '1 : 3 (기대 수익이 리스크의 3배)', '2 : 1 (기대 수익이 리스크의 0.5배)']::text[], 2, '손절 폭(25,000원) 대비 익절 폭(75,000원)의 비례를 의미하므로 `1,500 / 500 = 3`, 즉 손익비는 1:3이 됩니다. 이처럼 잃는 돈의 최소 2~3배를 벌 수 있는 손익비 높은 구간만 반복적으로 거래해야 장기적으로 계좌가 생존합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (928, '리스크/심리', '09_risk_position_management.md', '손익비를 엄격히 통제하여 항상 기대 손실의 2배를 버는 매매(손익비 1:2)만 고집합니다. 이 경우 내 계좌 잔고가 손실 없이 제자리걸음(본전)을 유지하기 위해 필요한 수학적인 최소 승률(Win Rate)은 얼마인가요?', '[{"time":"Today","open":5000,"high":5000,"low":5000,"close":5000}]'::jsonb, '[]'::jsonb, ARRAY['50.0% (최소 절반 이상 성공)', '33.3% (3번 중 1번 성공으로 본전)', '25.0% (4번 중 1번 성공으로 본전)', '66.6% (3번 중 2번 성공으로 본전)']::text[], 1, '손익비가 1:2일 경우, 1번 이기면 +2를 벌고 2번 지면 -2를 잃으므로 3번 매매 중 1번만 이겨도 누적 수익은 0이 됩니다. 즉 손익비를 1:2 이상으로 유지하면 수학적으로 승률이 겨우 33.3%만 나와도 절대 파산하지 않고 계좌가 우상향할 발판이 마련됩니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (929, '셋업/실행', '08_setup_entry_exit.md', '500,000원에 산 원자재이 750,000원까지 올랐습니다. 이익을 보존하면서 상승세를 끝까지 타기 위해, 최고점 대비 10% 하방 이탈 시 즉시 자동 익절되는 ''추적 손절매(Trailing Stop)''를 적용했습니다. 최고점 750,000원 달성 후 골드 가격가 조정받을 때 실제로 청산(익절)되는 가격은 얼마인가요?', '[{"time":"Day 1","open":500000,"high":600000,"low":495000,"close":595000,"volume":88},{"time":"Day 2","open":595000,"high":750000,"low":590000,"close":740000,"volume":103}]'::jsonb, '[]'::jsonb, ARRAY['500,000원 (본전 수준 청산)', '675,000원 (최고점 대비 10% 하방 청산)', '700,000원 (최고점 대비 6.6% 하방 청산)', '600,000원 (최고점 대비 20% 하방 청산)']::text[], 1, '추적 손절매(Trailing Stop)는 가격 상승에 따라 청산 가격을 자동으로 올려주는 주문입니다. 최고점 750,000원을 기록했으므로 청산 트리거 라인은 최고점에서 10% 차감된 `15,000 * 0.9 = 675,000원`으로 확정 셋업되며, 골드 가격가 675,000원을 건드리는 순간 자동 이익실현됩니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (930, '리스크/심리', '09_risk_position_management.md', '레버리지 10배를 적용하여 금 선물 롱(매수) 포지션을 구축했습니다. 만약 금 선물 가격이 매수가 대비 몇 % 역방향으로 등락하면 내 투자 원금이 100% 강제 청산(증거금 완전 소멸)당할까요?', '[{"time":"Today","open":2500000,"high":2505000,"low":2495000,"close":2500000}]'::jsonb, '[]'::jsonb, ARRAY['5.0% 하락 시', '10.0% 하락 시', '20.0% 하락 시', '100.0% 하락 시']::text[], 1, '레버리지 비율과 청산 거리 비율은 역수 관계입니다. `100% / 레버리지 배수` 공식에 따라, 10배 레버리지는 골드 가격가 내 베팅의 반대 방향으로 단 10%만 움직여도 투자 원금이 전부 증발하고 포지션이 강제 종료(Liquidation)됩니다. 고배율 레버리지가 파산의 지름길인 이유입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (931, '캔들/가격행동', '02_candlestick_price_action.md', '상승 추세 고점 영역(7,500달러선)에서 몸통이 매우 작고 아래꼬리가 긴 행잉맨(Hanging Man) 캔들이 출현한 이후, 다음 날 시가가 전일 종가보다 큰 갭을 그리며 낮게 하락 출발(7,250달러)했습니다. 포지션을 보유한 스윙 트레이더로서 가장 적절한 위기 대응 행동은 무엇입니까?', '[{"time":"Day 1","open":6000,"high":6250,"low":5950,"close":6200,"volume":112},{"time":"Day 2","open":6200,"high":6750,"low":6150,"close":6700,"volume":105},{"time":"Day 3","open":6700,"high":7400,"low":6650,"close":7300,"volume":89},{"time":"Day 4","open":7300,"high":7550,"low":7000,"close":7350,"volume":127},{"time":"Day 5","open":7050,"high":7150,"low":6750,"close":6800,"volume":114}]'::jsonb, '[]'::jsonb, ARRAY['상승 랠리를 기대로 보유 비중 확대 및 추격 매수', '일시적 속임수(휩소) 판단으로 추가 레버리지 매수', '행잉맨 출현 후 갭하락에 따른 전량 또는 일부 정리', '조치 없이 전고점 돌파 시까지 무기한 관망 및 홀딩']::text[], 2, '고가권에서 나타난 행잉맨(Hanging Man)은 잠재적 하락 전환 신호이며, 특히 다음날 갭하락 음봉으로 직전 행잉맨의 저가를 깨고 내려가는 움직임은 강력한 하락 컨펌 시그널입니다. 따라서 이 시점에서는 즉시 비중을 전량 정리하거나 최소 절반 이상 매도하여 리스크를 통제하는 것이 정석입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (932, '캔들/가격행동', '01_chart_market_basics.md', '지속적인 하락 추세 도중 바닥권(4,000달러선)에서 시가와 종가가 일치하고 긴 아래꼬리를 단 십자 형태의 도지(Doji) 캔들이 생성되었습니다. 다음 날 대량의 거래량과 함께 장대양봉이 솟구치며 4,350달러로 마감하는 샛별형(Morning Star) 조합이 확정되었습니다. 이때 가장 합리적인 매수 진입 지점과 손절가 기준은 무엇입니까?', '[{"time":"Day 1","open":5000,"high":5050,"low":4650,"close":4700,"volume":82},{"time":"Day 2","open":4700,"high":4750,"low":4400,"close":4450,"volume":95},{"time":"Day 3","open":4450,"high":4500,"low":4000,"close":4050,"volume":93},{"time":"Day 4","open":4000,"high":4100,"low":3750,"close":4000,"volume":101},{"time":"Day 5","open":4000,"high":4400,"low":3950,"close":4350,"volume":103}]'::jsonb, '[]'::jsonb, ARRAY['손절 없이 100% 비중으로 시장가 매수', '샛별형 완성에 따라 분할 매수 후 최저점 손절 셋업', '바닥 도달 기대로 주문 없이 무작정 대기', '상승 꼭대기에서 숏 진입 후 손절 없이 방치']::text[], 1, '하락 추세 끝에 도지와 장대양봉이 결합된 샛별형(Morning Star)은 매우 신뢰도 높은 바닥 상승 전환 신호입니다. 이 패턴을 보고 진입할 때는 반등 상승세에 분할 매수로 동참하되, 바닥을 잡아준 도지 캔들의 최저점(3,750달러) 아래를 최종 손절 라인으로 잡는 것이 수학적으로 가장 리스크 대비 보상 비율(손익비)이 훌륭한 전략입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (933, '거래량/유동성', '02_candlestick_price_action.md', '골드 가격가 강력한 횡보 박스권 고점(10,000달러 저항선)에 세 번째 터치하는 와중에, 윗꼬리가 길고 몸통이 매우 얇은 유성형(Shooting Star) 캔들이 이틀 연속 발생했습니다. 거래량 역시 저항선 부근에서 매수세가 더 올라가지 못하고 매도 압력이 실려 나타났습니다. 롱(매수) 포지션을 들고 있는 당신의 합리적인 의사결정은?', '[{"time":"Day 1","open":8750,"high":9250,"low":8700,"close":9100,"volume":114},{"time":"Day 2","open":9100,"high":9750,"low":9000,"close":9650,"volume":110},{"time":"Day 3","open":9650,"high":10100,"low":9500,"close":9550,"volume":110},{"time":"Day 4","open":9550,"high":10050,"low":9400,"close":9450,"volume":123}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":10000}],"label":"박스권 상단 저항선 (200)","color":"#ef4444"}]'::jsonb, ARRAY['신고가 갱신을 예상한 전재산 추가 불타기', '저항 돌파 실패 신호 확인 후 분할 익절 및 관망', '손익 평단가 부근이므로 추가 손절 없이 방치', '거래를 종료하고 다른 신규 급등주를 시장가 추격']::text[], 1, '박스권 상단 저항선(10,000달러)에 부딪히며 나타난 유성형(Shooting Star) 연속 출현은 저항 돌파 실패와 차익 실현 세력의 강력한 등장을 경고하는 캔들 신호입니다. 돌파를 확신하기보다는 리스크 관리 관점에서 물량을 축소(50% 분할 익절)하거나 전량 매도하여 이익을 확정 짓는 것이 현명합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (934, '캔들/가격행동', '02_candlestick_price_action.md', '극심한 하락 추세 중 5,000달러선 아래로 떨어지던 골드 가격가 전일 장대음봉을 형성했습니다. 그러나 당일 시가는 갭하락하여 더 낮게 시작했으나, 장중에 강한 매수세가 들어오며 전일 음봉 몸통의 정확히 70% 라인(4,650달러선) 위로 덮어버리는 관통형(Piercing Line) 상승 캔들로 마감했습니다. 종가 매수(롱) 진입 시 원칙 대응은?', '[{"time":"Day 1","open":5500,"high":5550,"low":5200,"close":5250,"volume":93},{"time":"Day 2","open":5250,"high":5300,"low":4850,"close":4900,"volume":91},{"time":"Day 3","open":4600,"high":5050,"low":4550,"close":5000,"volume":91}]'::jsonb, '[]'::jsonb, ARRAY['상승 모멘텀 미달로 매수 보류 및 하방 숏 포지션 진입', '관통형 확인 후 분할 매수 및 당일 최저점 손절 설정', '손절 라인 설정 없이 100% 비중 시장가 매수 집행', '조정을 대기하며 예약 주문 없이 무작정 관망 유지']::text[], 1, '전일 음봉의 50% 이상을 당일 양봉 몸통으로 관통해 올린 ''관통형(Piercing Line)''은 하락 모멘텀이 쇠퇴하고 저가 매수세가 우위를 점하기 시작했음을 뜻하는 바닥 신호입니다. 이 패턴 확인 후 진입할 시에는 손절 한도를 당일 최저점(4,550달러) 밑에 가깝게 설정할 수 있어 매우 유리한 리스크 대비 기대수익 매매가 성립됩니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (935, '캔들/가격행동', '05_volume_liquidity.md', '강한 급등세를 지속하던 골드 가격가 최고점에서 큰 거래량을 터뜨리며 장대양봉을 만들었습니다. 그러나 다음 날, 전일 양봉 몸통의 한가운데 범위 안에서 움직이며 시가와 종가가 모두 갇혀버리는 짧은 음봉인 ''하락 잉태형(Bearish Harami)'' 캔들이 형성되었습니다. 단기 스윙 트레이더로서 당신의 포지션 리스크 관리 행동은?', '[{"time":"Day 1","open":6000,"high":6400,"low":5950,"close":6350,"volume":92},{"time":"Day 2","open":6350,"high":6900,"low":6300,"close":6800,"volume":100},{"time":"Day 3","open":6650,"high":6700,"low":6500,"close":6550,"volume":106}]'::jsonb, '[]'::jsonb, ARRAY['상승 둔화 조짐에 따른 보유 물량 50% 분할 익절', '추세 일시 조정으로 간주하여 비중 확대 추가 매수', '추세 종결 판단에 따른 고배율 숏 포지션 즉시 진입', '이익 실현 없이 전량 장기 보유 전략 유지']::text[], 0, '하락 잉태형(Bearish Harami)은 이전의 강한 상승 추세 동력이 감속하기 시작했으며, 매도 압력이 힘을 기르고 있음을 암시하는 변곡 캔들입니다. 따라서 단기 스윙 트레이더는 물량의 일부(50%)를 분할 익절하여 리스크를 낮추고, 다음 캔들에서 이전 양봉 저점을 깨뜨리는 하락 하방 이탈이 추가되는지 지켜보는 것이 정석입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (936, '시장구조/SR', '03_market_structure.md', '오랫동안 지켜지던 핵심 지지선인 5,000달러 부근에서 매수 진입을 완료했습니다. 그러나 가격이 대량의 거래량을 동반하며 장대음봉으로 지지선을 하방으로 강하게 뚫어냈고, 종가가 지지선 대비 1.5% 아래인 98.250달러로 결정되었습니다. 이 상황에서 원칙을 지키는 올바른 위기 대응 행동은?', '[{"time":"Day 1","open":5250,"high":5400,"low":5100,"close":5150,"volume":119},{"time":"Day 2","open":5150,"high":5200,"low":4950,"close":5000,"volume":100},{"time":"Day 3","open":5000,"high":5050,"low":4900,"close":4925,"volume":102}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":5000}],"label":"중요 지지선 (100)","color":"#10b981"}]'::jsonb, ARRAY['추가 물타기를 위해 자금을 동원하여 평단가 관리', '중요 지지선 붕괴(Breakdown) 확인 후 즉시 전량 손절', '지속 하락 시 추가 평단가 관리를 위해 매수 유보', '하방 이탈 시 즉시 반대 고배율 롱 포지션 진입']::text[], 1, '거래량이 동반된 장대음봉으로 주요 지지선 아래에서 종가가 결정되는 이탈 마감은 매수 지지 세력의 패배이자 추세 붕괴(Breakdown)의 신호입니다. 이 시점에서 물타기를 하거나 존버를 하면 파산적인 하락 조정을 겪을 수 있으므로 즉시 룰에 근거한 ''전량 손절''을 집행해야 계좌를 살릴 수 있습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (937, '시장구조/SR', '03_market_structure.md', '7,500달러의 중요 저항선이 강한 거래량을 실은 돌파봉으로 뚫렸습니다. 이후 골드 가격가 숨 고르기 조정을 받으며 7,500달러 부근까지 되돌아왔고(리테스트 구간), 저항선 부근에서 거래량이 크게 감소하며 아래꼬리가 달린 도지 캔들로 안착하는 모습을 보입니다. 이때 가장 안전하고 합리적인 매매 조치는?', '[{"time":"Day 1","open":7000,"high":7300,"low":6950,"close":7200,"volume":112},{"time":"Day 2","open":7200,"high":7850,"low":7150,"close":7750,"volume":109},{"time":"Day 3","open":7750,"high":7800,"low":7450,"close":7500,"volume":96}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":7500}],"label":"돌파된 저항선 -> 지지선 전환선 (150)","color":"#3b82f6"}]'::jsonb, ARRAY['가짜 돌파(휩소) 판단에 따른 고배율 숏 진입', '돌파 후 리테스트 성공 확인 시 지지선 눌림목 매수', '추격 매수 기회 상실로 판단하고 거래 포기', '8,000달러 추가 돌파를 타겟으로 시장가 추격 매수']::text[], 1, '강하게 돌파된 저항선은 룰 체인지에 의해 지지선으로 변합니다(역할 전환). 돌파 당시 추격 매수하기보다, 돌파된 선(7,500달러)으로 골드 가격가 되돌아오는 리테스트(Retest) 시점에 저조한 거래량과 지지 캔들을 확인하고 손절선을 바로 밑에 설정하여 눌림목 진입하는 것이 리스크가 가장 적은 프로 트레이더의 정석입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (938, '시장구조/SR', '03_market_structure.md', '가격이 4,000달러 지지선 근처에서 반등을 시도하고 있으나, 반등의 폭이 직전 고점에 턱없이 못 미치며 저점 부근으로 다시 짓눌리고 있습니다. 즉, 고점들이 계속 낮아지는 하락 우위 삼각수렴(Descending)의 형태가 지지선 바로 위에서 감지됩니다. 이 시점에서 지지선 반등을 믿고 신규 매수(롱)를 진입하는 것은 원칙에 맞습니까?', '[{"time":"Day 1","open":4750,"high":4900,"low":4000,"close":4400,"volume":117},{"time":"Day 2","open":4400,"high":4550,"low":4000,"close":4200,"volume":115},{"time":"Day 3","open":4200,"high":4300,"low":4000,"close":4050,"volume":96}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":4000}],"label":"지지선 (80)","color":"#10b981"}]'::jsonb, ARRAY['삼중 바닥 지지로 판단하고 매수 비중 대폭 확대', '디센딩 수렴 확인 후 하방 이탈 위험 대비 관망', '물타기 평단가 관리를 위해 매수 보증금 추가 투입', '추세와 무관하게 숏 포지션으로 전환 후 무기한 보유']::text[], 1, '지지선 부근에서 고점이 점점 낮아지는 ''디센딩'' 형태는 매수 지원 강도가 둔화되고 매도 출하 공급이 가격을 계속 하방으로 압박하고 있음을 증명합니다. 지지 성공보다 지선 하방 붕괴 후 급락할 확률이 높으므로, 지지선이라는 명목만으로 함부로 매수 진입하지 말고 돌파/이탈 컨펌을 기다려 관망하는 것이 현명합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (939, '거래량/유동성', '05_volume_liquidity.md', '골드 가격가 6,000달러의 장기 저항벽을 거래량이 거의 실리지 않은 얇은 양봉으로 상방으로 살짝 뚫었으나, 바로 다음 날 직전 양봉 몸통을 통째로 덮어버리는 대량 거래량의 장대음봉이 출현하며 5,800달러로 곤두박질쳤습니다. 매수 포지션을 추격 진입했던 당신의 올바른 조치는?', '[{"time":"Day 1","open":5600,"high":5900,"low":5550,"close":5850,"volume":106},{"time":"Day 2","open":5850,"high":6100,"low":5800,"close":6050,"volume":366},{"time":"Day 3","open":6050,"high":6100,"low":5750,"close":5800,"volume":392}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":6000}],"label":"장기 저항선 (120)","color":"#ef4444"}]'::jsonb, ARRAY['불 트랩(Bull Trap) 확인 후 추가 하락 방지 즉시 손절', '저항선 부근 매수세 복귀를 기대하며 전량 홀딩', '평단가 관리 차원에서 추가 물타기 매수 집행', '상황을 판단하기 위해 시장가로 추가 분할 진입']::text[], 0, '거래량 없는 돌파 직후에 거래량 실린 강한 음봉이 기존 돌파선(6,000달러) 아래로 재진입하여 마감하는 현상은 전형적인 불 트랩(Bull Trap/가짜 돌파) 함정입니다. 돌파 당시 샀던 매수자들의 패닉 셀이 출현하며 하락 가속화가 나오기 쉬우므로 즉시 손절하여 물량을 털어내야 생존할 수 있습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (940, '시장구조/SR', '10_psychology_routine_review.md', '주요 지지선(12,500달러선)이 아래로 무너질 때 제때 손절 처리를 하지 못해 골드 가격가 11,000달러선까지 끌려 내려갔습니다. 다행히 단기 매도 진정세로 반등이 나와 골드 가격가 다시 12,500달러 부근까지 상승하여 회복을 눈앞에 두고 있습니다. 이때 손실을 최소화하는 현명한 시나리오 대처법은?', '[{"time":"Day 1","open":13000,"high":13100,"low":12400,"close":12450,"volume":81},{"time":"Day 2","open":12450,"high":12500,"low":11000,"close":11100,"volume":104},{"time":"Day 3","open":11100,"high":11750,"low":11050,"close":11700,"volume":124},{"time":"Day 4","open":11700,"high":12550,"low":11650,"close":12450,"volume":108}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":12500}],"label":"붕괴된 지지선 -> 저항선으로 변형 (250)","color":"#ef4444"}]'::jsonb, ARRAY['역할 전환(저항선) 도달에 따른 탈출 및 현금화', 'V자 반등 성공 확신에 따른 추가 매수 비중 확대', '원금 회복 및 추가 수익 시까지 영구 홀딩 관망', '하락 추세 지속에 따른 반대 숏 포지션 스위칭']::text[], 0, '하방으로 깨진 지지선은 반등할 때 가장 뚫기 힘든 ''강력한 저항선''으로 성격이 바뀝니다. 따라서 손절 기회를 놓치고 물려있던 트레이더는 반등하여 옛 지지선(12,500달러)에 도달했을 때를 ''최선의 리스크 탈출 기회(탈출구)''로 삼아 전량 매도하거나 비중을 극도로 덜어내야 다가올 2차 하락 파동의 파산을 막을 수 있습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (941, '추세/레짐', '03_market_structure.md', '골드 가격가 매우 가파르게 올라가던 1차 단기 상승 추세선을 강한 음봉 종가로 뚫고 내려왔습니다. 다행히 각도가 완만하고 탄탄한 장기 핵심 상승 추세선은 저 밑에 지지 영역을 유지하고 있습니다. 스윙 트레이더로서 가장 정석적인 포지션 제어 방식은 무엇인가요?', '[{"time":"Day 1","open":5000,"high":5100,"low":5000,"close":5100,"volume":92},{"time":"Day 2","open":5100,"high":5500,"low":5100,"close":5450,"volume":118},{"time":"Day 3","open":5450,"high":6250,"low":5450,"close":6200,"volume":98},{"time":"Day 4","open":6200,"high":6250,"low":5700,"close":5750,"volume":110}]'::jsonb, '[{"type":"line","points":[{"x":0,"y":5000},{"x":3,"y":6150}],"label":"가파른 단기 추세선 (붕괴)","color":"#ef4444"},{"type":"line","points":[{"x":0,"y":5000},{"x":3,"y":5500}],"label":"완만한 장기 추세선 (지탱 중)","color":"#10b981"}]'::jsonb, ARRAY['추세 붕괴 판단에 따른 전량 손절 및 영구 이탈', '가속 추세 이탈에 따른 50% 분할 익절 및 분산', '단기 지지선 붕괴를 무시한 고배율 물타기 매수', '장기 추세선까지 조정을 대비한 신규 매수 대기']::text[], 1, '가파르게 우상향하던 가속 추세선(Accelerated Trendline)이 하방 돌파되는 것은 기존 폭등 랠리의 속도가 둔화되고 완만한 본래 장기 추세선(장기 매물대)을 향해 정상적인 가격 조정을 받기 시작했음을 뜻합니다. 따라서 물량의 50%가량을 털어 수익을 실현하고 남은 물량으로 장기 추세선의 3rd Touch 지지 성공 여부를 테스트하는 것이 리스크 관리의 기본입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (942, '거래량/유동성', '05_volume_liquidity.md', '고점과 저점이 연속으로 낮아지는 명확한 하락 평행 채널 내에서 하락 압력을 받아 숏(매도) 포지션을 잡고 수익 중이었습니다. 그런데 당일 캔들이 대량의 거래량과 함께 장대양봉을 그리며 채널 상단 저항선 위로 종가 안착(상방 돌파)했습니다. 숏 포지션을 쥔 당신의 결단은?', '[{"time":"Day 1","open":5000,"high":5100,"low":4500,"close":4600,"volume":104},{"time":"Day 2","open":4600,"high":4700,"low":4100,"close":4150,"volume":121},{"time":"Day 3","open":4150,"high":4250,"low":3750,"close":3800,"volume":110},{"time":"Day 4","open":3800,"high":4500,"low":3750,"close":4450,"volume":97}]'::jsonb, '[{"type":"channel","points":[{"x":0,"y":5100},{"x":3,"y":4300},{"x":0,"y":4500},{"x":3,"y":3800}],"label":"하락 평행 채널 상한/하한","color":"#f59e0b"}]'::jsonb, ARRAY['상단 돌파 확인 즉시 숏 전량 손절 및 대피', '채널 재진입 기대로 숏 포지션 추가 물타기', '손절 없이 유지하면서 포지션 본전 도달 대기', '포지션 유지 후 증거금을 출금하여 강제 횡보']::text[], 0, '하락 평행 채널의 상단 저항선 상향 돌파(Breakout)는 기존 하락 트렌드의 사멸과 매수세 지배령 복귀를 뜻합니다. 지표와 거래량이 동반된 돌파 확인 시에는 숏 포지션을 지체 없이 기계적으로 칼손절하여 자산을 보호하는 것이 원칙입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (943, '추세/레짐', '07_multitimeframe_regime.md', '우상향하는 상승 평행 채널 안에서 순항하던 골드 가격가 중심선(Mid-line)을 뚫고 하방으로 이탈 마감했습니다. 이후 중심선 부근까지 반등을 시도했으나 재차 저항을 받고 아래꼬리가 꺾여 채널 하단선을 향해 하락 조정을 재개하려 합니다. 신규 매수(롱) 포지션 진입을 계획 중인 트레이더의 대응법은?', '[{"time":"Day 1","open":5000,"high":5400,"low":4950,"close":5300,"volume":82},{"time":"Day 2","open":5300,"high":5600,"low":5100,"close":5200,"volume":123},{"time":"Day 3","open":5200,"high":5300,"low":4900,"close":5000,"volume":119}]'::jsonb, '[{"type":"channel","points":[{"x":0,"y":5500},{"x":2,"y":5600},{"x":0,"y":4900},{"x":2,"y":5000}],"label":"상승 평행 채널","color":"#10b981"}]'::jsonb, ARRAY['채널 내 유지를 기대로 지정가 즉시 매수', '중심선 저항 확인 후 채널 하단 안착 대기', '하방 휩소 판단에 따른 레버리지 추가 매수', '추세와 무관한 숏 포지션 구축 후 관망']::text[], 1, '상승 평행 채널에서 미드라인(Mid-line)은 매우 중요한 심리적 지지와 저항선입니다. 미드라인이 저항선으로 뒤바뀌어 음봉으로 흘러내리는 경우 높은 확률로 채널 하단 경계선까지 가격이 조정을 받게 되므로, 중심선 저항 확인 시점에서는 섣부른 매수 진입을 피하고 채널 하단의 명확한 반등 타점을 유도해야 합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (944, '추세/레짐', '03_market_structure.md', '저점과 저점을 이은 장기 상승 추세선 상의 3번째 터치 포인트(지지선 부근)에 캔들이 매우 조심스럽게 안착하며 아래꼬리를 형성했습니다. 손익비(Risk-to-Reward) 관점에서 가장 이상적인 매수 타점 집행 및 손절 셋업 방법은 무엇입니까?', '[{"time":"Day 1","open":4000,"high":4500,"low":4000,"close":4400,"volume":105},{"time":"Day 2","open":4400,"high":4950,"low":4400,"close":4750,"volume":118},{"time":"Day 3","open":4750,"high":4800,"low":4500,"close":4600,"volume":125}]'::jsonb, '[{"type":"line","points":[{"x":0,"y":4000},{"x":1,"y":4400},{"x":2,"y":4500}],"label":"상승 추세선 (3rd Touch 기대선)","color":"#10b981"}]'::jsonb, ARRAY['손절 라인 없이 지정가로 1차 매수 몰빵 진입', '3rd Touch 타점 진입 및 추세선 하단 칼손절 셋업', '하방 붕괴 예상을 통한 고배율 숏 즉각 진입', '목표가 터치 시까지 무작정 대기 후 추격 매수']::text[], 1, '추세선 상의 3번째 지지 포인트(3rd Touch)는 추세 신뢰도가 형성되는 대단히 성공률 높은 정석적 눌림목 타점입니다. 진입 가격과 손절 라인(추세선 이탈가)의 거리가 매우 가깝기 때문에 기대 수익 대비 잃을 금액이 매우 적어 프로 트레이더들이 가장 선호하는 칼손절 매수 스팟입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (945, '추세/레짐', '08_setup_entry_exit.md', '골드 가격가 장기 하락 추세선을 힘차게 뚫어 상방 돌파(Breakout)했습니다. 하지만 돌파선 바로 위(약 6,000달러)에 최근 여러 번 강한 매도 잔량이 쏟아지며 가격을 찍어 눌렀던 핵심 매물대 저항선이 떡하니 버티고 있습니다. 당신의 신규 진입 매수 순서는 어떻게 결정해야 안전할까요?', '[{"time":"Day 1","open":6250,"high":6300,"low":5500,"close":5600,"volume":94},{"time":"Day 2","open":5600,"high":5650,"low":4900,"close":5000,"volume":90},{"time":"Day 3","open":5000,"high":5950,"low":4950,"close":5900,"volume":107}]'::jsonb, '[{"type":"line","points":[{"x":0,"y":6250},{"x":1,"y":5600},{"x":2,"y":5250}],"label":"하락 추세선 (돌파됨)","color":"#ef4444"},{"type":"horizontal-line","points":[{"x":0,"y":6000}],"label":"수평 매물대 저항선 (120)","color":"#ef4444"}]'::jsonb, ARRAY['돌파 확인 즉시 종가 기준 시장가 100% 매수', '수평 저항 돌파 검증 시까지 매수 유보 및 대기', '돌파 전조 현상 기대로 레버리지 선배팅 집행', '추세선 돌파를 가짜로 간주한 숏 포지션 진입']::text[], 1, '하락 추세선의 돌파는 긍정적이나 수평 매물대 저항선이 바로 위에 있다면 이중 저항 작용에 의해 막히는 경우가 대단히 잦습니다. 추세선 상방 휩소(속임수)에 당하지 않으려면 겹저항 중 최종 관문인 수평 매물대 저항선 돌파 혹은 리테스트 지지를 확인하고 진입하는 것이 보수적이고 안전한 원칙입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (946, '패턴/돌파', '04_patterns_breakout.md', '고점 수평 저항선(5,000달러)과 저점 상승 지지선으로 이루어진 어센딩 트라이앵글 수렴 도중, 5,000달러를 돌파할 것을 미리 예측하고 4,900달러에서 비중 100% 매수로 진입했습니다. 그러나 골드 가격는 돌파에 실패하고 하방 상승 지지선을 대량 거래량 장대음봉으로 뚫어 4,600달러로 하향 마감했습니다. 올바른 매매 액션은?', '[{"time":"Day 1","open":4000,"high":5000,"low":4000,"close":4750,"volume":115},{"time":"Day 2","open":4750,"high":5000,"low":4400,"close":4850,"volume":92},{"time":"Day 3","open":4850,"high":4900,"low":4550,"close":4600,"volume":102}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":5000}],"label":"수평 저항선 (100)","color":"#ef4444"},{"type":"line","points":[{"x":0,"y":4000},{"x":1,"y":4400},{"x":2,"y":4700}],"label":"상승 지지선 (붕괴)","color":"#10b981"}]'::jsonb, ARRAY['하방 이탈 확인 즉시 손절하여 추가 폭락 차단', '조정을 이용해 평단가를 조절하는 분할 물타기', '본전 탈출 시까지 포지션을 유지하며 관망', '손절 라인을 하단으로 조정하고 대기 주문 유지']::text[], 0, '어센딩 트라이앵글은 상방 확률이 다소 높지만, 하단 지지선이 뚫려 무너지는 순간 패턴 실패와 함께 엄청난 실망 매도 매물이 출하됩니다. 특히 돌파를 미리 예견해 들어간 포지션은 즉시 룰 위반을 시정하고 손절(4,600달러)해야 큰 자산 보호를 할 수 있습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (947, '패턴/돌파', '04_patterns_breakout.md', '하락 바닥권에서 왼쪽 어깨, 머리, 오른쪽 어깨를 그리며 역헤드앤숄더(Inverse Head & Shoulders) 패턴이 완성되었습니다. 가격이 넥라인 저항벽(4,000달러선)을 돌파했으나 이미 장대양봉으로 높이 솟아(4,350달러) 추격 매수 타이밍을 아쉽게 놓쳤습니다. 이때 뇌동매매를 피하는 가장 현명한 매수 타점 공략법은?', '[{"time":"Day 1","open":4750,"high":4750,"low":3500,"close":3900,"volume":96},{"time":"Day 2","open":3900,"high":4100,"low":3000,"close":3750,"volume":106},{"time":"Day 3","open":3750,"high":3950,"low":3400,"close":3800,"volume":93},{"time":"Day 4","open":3800,"high":4400,"low":3750,"close":4350,"volume":92}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":4000}],"label":"넥라인 저항선 (80)","color":"#ef4444"}]'::jsonb, ARRAY['포모(FOMO) 현상에 따른 돌파봉 꼭대기 추격 매수', '돌파 넥라인 부근의 리테스트 조정 눌림목 매수', '반등 랠리 종결 판단에 따른 역베팅 숏 포지션', '추세 전환 확인 후 무조건적인 관심종목 제외']::text[], 1, '강한 패턴 돌파봉 확인 후 뇌동매매로 추격하는 것은 손절 거리가 너무 멀어져 손익비가 최악인 나쁜 습관입니다. 정석 돌파 트레이더는 넥라인 역할 전환 지점(4,000달러)으로의 되돌림 눌림목(Retest)을 차분히 기다려 리스크를 짧게 끊고 들어가는 훈련을 해야 합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (948, '패턴/돌파', '04_patterns_breakout.md', '지속적인 하락 추세 중, 고점과 저점이 수렴하며 우하향하는 하락 쐐기형(Falling Wedge) 패턴의 끝자락에 도달했습니다. 거래량이 급감하다가 마침내 쐐기형 상단 저항선을 상방으로 뚫는 강한 양봉 종가 마감(5,500달러)이 포착되었습니다. 합리적인 매수 진입 시 손절가 설정 기준은 무엇인가요?', '[{"time":"Day 1","open":6500,"high":6600,"low":5500,"close":5600,"volume":118},{"time":"Day 2","open":5600,"high":5800,"low":5100,"close":5200,"volume":110},{"time":"Day 3","open":5200,"high":5400,"low":4900,"close":5000,"volume":125},{"time":"Day 4","open":5000,"high":5600,"low":4950,"close":5500,"volume":121}]'::jsonb, '[]'::jsonb, ARRAY['손절 없이 청산가에 의존하여 장기 홀딩', '상방 돌파 확인 후 진입 및 직전 최저점 손절 셋업', '평단가 개선을 위한 지속적인 분할 물타기 매수', '상단 저항선 돌파 시점을 이용한 숏 포지션 스위칭']::text[], 1, '하락 쐐기형(Falling Wedge)의 상방 돌파는 강력한 반전 신호입니다. 이 패턴의 장점은 진입 즉시 명확하고 짧은 기준점(수렴 바닥 최저가 4,900달러 혹은 돌파봉 하단)을 손절가로 설정할 수 있어, 리스크 한도를 안전하게 통제한 채 상방 랠리를 도모할 수 있다는 점입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (949, '패턴/돌파', '04_patterns_breakout.md', '골드 가격가 약한 매수세와 거래량 급감 속에 고점과 저점을 높이며 좁게 상승 쐐기형(Rising Wedge)을 그리고 있습니다. 현재 가격은 상승 쐐기형 하단 지지선(15,000달러)에 아주 밀착하여 붕괴 위기에 놓여 있습니다. 이 시점에서 롱(매수) 포지션을 들고 있는 트레이더의 리스크 대응은?', '[{"time":"Day 1","open":13000,"high":14000,"low":13000,"close":13900,"volume":83},{"time":"Day 2","open":13900,"high":14750,"low":13600,"close":14500,"volume":29},{"time":"Day 3","open":14500,"high":15250,"low":14900,"close":15050,"volume":19}]'::jsonb, '[{"type":"line","points":[{"x":0,"y":13000},{"x":1,"y":13600},{"x":2,"y":14900}],"label":"쐐기 하단 지지선 (300)","color":"#ef4444"}]'::jsonb, ARRAY['상승 쐐기형 하방 이탈 위험에 따른 롱 포지션 매도', '상승 지속 확신에 따른 레버리지 추가 불타기', '장기 상승 흐름 기대로 손절 없이 무기한 홀딩', '다른 종목으로의 포지션 분산을 위한 관망']::text[], 0, '상승 쐐기형(Rising Wedge)은 약세 세력이 억지로 쥐어짜며 상승 가격을 만드는 패턴으로, 수렴 끝에서 거래량 소멸과 함께 하방 이탈(Breakdown)하여 폭락할 위험이 매우 높은 대표적인 하락 대비 패턴입니다. 하단 지지선 이탈 낌새 시에는 매수 포지션을 전부 도망쳐 나와야 큰 손실을 막을 수 있습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (950, '패턴/돌파', '04_patterns_breakout.md', '둥근 대야 모양의 바닥(Cup)을 그리며 상승 회복한 골드 가격가 전고점 저항벽 부근에서 하향 채널식 완만한 되돌림 조정 핸들(Handle)을 그리는 중입니다. 이후 핸들의 상단 저항선(7,500달러선)을 강한 거래량의 장대양봉으로 상향 돌파했습니다. 이때 합리적인 트레이더의 대응은?', '[{"time":"Day 1","open":7000,"high":7100,"low":6400,"close":6500,"volume":112},{"time":"Day 2","open":6500,"high":7000,"low":6450,"close":6900,"volume":103},{"time":"Day 3","open":6900,"high":7000,"low":6700,"close":6750,"volume":98},{"time":"Day 4","open":6750,"high":7700,"low":6700,"close":7600,"volume":108}]'::jsonb, '[]'::jsonb, ARRAY['핸들 상방 돌파 확인 후 진입 및 핸들 저점 손절', '하락 지속 판단에 따른 즉각적인 전량 손절', '평단가 부근이므로 추가 손절 설정 없이 관망', '돌파 여부 확인 전 고점 돌파 매수 주문 100%']::text[], 0, '전형적인 강세 지속 패턴인 컵앤핸들(Cup & Handle)입니다. 핸들의 하락 조정 채널 상단 돌파는 매물 소화를 성공적으로 완수하고 본 랠리로 진입한다는 강력한 신호입니다. 손익비 관점에서 핸들의 지지 저점인 6,700달러 아래에 안전 손절을 지정한 뒤 진입 시 우수한 기대 수익을 가질 수 있습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (951, '지표/컨플루언스', '06_technical_indicators.md', '강력한 대세 상승 국면인 종목이 일시 조정을 거쳐 전저점 지지 영역(5,000달러)에 도달해 저점을 지키고 있습니다(저점 높임 또는 수평). 그런데 이때 보조지표 RSI의 저점은 이전보다 훨씬 깊게 파여 낮아지는 ''히든 상승 다이버전스(Hidden Bullish Divergence)''가 포착되었습니다. 현명한 의사결정은?', '[{"time":"Day 1","open":4500,"high":5500,"low":4400,"close":5250,"volume":98},{"time":"Day 2","open":5250,"high":5350,"low":4900,"close":5000,"volume":112}]'::jsonb, '[]'::jsonb, ARRAY['하락 전환 신호로 판단하여 전량 즉시 손절', '추세 지속 신호 기대로 지선 부근 추가/신규 매수', '지표 과매수 판단에 따른 계좌 거래 정지', '손절 설정 없이 무제한 레버리지 롱 대응']::text[], 1, '골드 가격의 저점은 높아지는데 보조지표(RSI 등)의 저점은 낮아지는 형태는 ''히든 상승 다이버전스''입니다. 이는 기존의 강력한 상승 트렌드 내부에서 일시 조정을 겪는 매수자들이 활기차게 물량을 주워 담아 다음 상승 랠리를 추진한다는 신호이므로, 짧은 손절 라인(4,900달러)을 설정하고 매수 비중을 태우기 가장 적합한 정석 타점입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (952, '지표/컨플루언스', '07_multitimeframe_regime.md', '골드 가격가 호재와 함께 밴드 상단선 바깥을 타고 계속 상승하는 강력한 볼린저 밴드 밴드워크(Band Walk) 현상이 발생 중이며, RSI는 80을 넘어 극단적 과매수 수치를 가리키고 있습니다. 이 구간에서 취해야 할 가장 합리적인 리스크 및 포지션 관리 행동은?', '[{"time":"Day 1","open":5000,"high":5750,"low":4950,"close":5600,"volume":97},{"time":"Day 2","open":5600,"high":6400,"low":5500,"close":6250,"volume":117},{"time":"Day 3","open":6250,"high":6950,"low":6100,"close":6800,"volume":121}]'::jsonb, '[]'::jsonb, ARRAY['과매수 도달 판단에 따른 고배율 숏 무리한 진입', '추종 손절매(Trailing Stop)를 통한 수익 극대화', '상승폭 만족에 따른 즉각적인 전량 시장가 익절', '손절 가격을 해제하고 시세 지속 시까지 방치']::text[], 1, '강세 추세가 지나치게 강할 경우 볼린저 밴드 상단을 타고 오르는 밴드워크 현상과 RSI 과매수 현상이 영구 유지될 수 있습니다. 이때 단순 과매수 수치를 이유로 숏 포지션을 잡으면 파산합니다. 기존 매수 포지션의 익절선(Trailing Stop)을 상향 관리하여 추세 상승 이익을 극대화하고 신규 진입은 자제하는 것이 정석 리스크 관리입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (953, '지표/컨플루언스', '06_technical_indicators.md', '1시간 봉 차트 상에서 골드 가격가 확실히 낮아졌으나 RSI 저점은 유의미하게 상승한 ''상승 다이버전스''가 확인되어 매수 타점을 노리고 있습니다. 다만 15분 봉 단기 차트에서는 하락 장대음봉 관성이 아직 살아있어 매도 압력이 보입니다. 멀티 타임프레임 트레이더의 진입 의사결정은?', '[{"time":"Hour 1","open":5000,"high":5100,"low":4500,"close":4550,"volume":80},{"time":"Hour 2","open":4550,"high":4600,"low":4000,"close":4100,"volume":115}]'::jsonb, '[]'::jsonb, ARRAY['단기 음봉 관성 기대로 즉각 숏 포지션 진입', '큰 시간 프레임의 상승 다이버전스 타점 매수', '지표 충돌로 판단하고 시장가 즉시 롱 진입', '변동성 기대로 무작정 도박성 잡코인 진입']::text[], 1, '큰 프레임(1시간 봉)의 다이버전스가 주는 중장기 추세 신뢰도는 작은 프레임의 단기 노이즈보다 압도적으로 강력합니다. 단, 진입 시 타이밍의 정밀도를 높이기 위해 소파동(15분 봉)의 하락 동력이 꺾이고 지지해 주는 단기 확인 캔들이 나오는 찰나에 롱 포지션 타이밍을 잡는 것이 멀티 타임프레임 정석 매매입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (954, '지표/컨플루언스', '06_technical_indicators.md', '골드 가격는 10,000달러 저항대를 뚫고 11,000달러까지 계속 우상향하며 고점을 갱신하고 있으나, MACD 오실레이터의 히스토그램 산 높이는 직전 고점 시점 대비 현저하게 쪼그라들며 꺾여 내려가 하락 다이버전스를 형성 중입니다. 현명한 포지션 보유자의 이익 관리 행동은?', '[{"time":"Day 1","open":9000,"high":10250,"low":8950,"close":10000,"volume":89},{"time":"Day 2","open":10000,"high":11100,"low":9900,"close":11000,"volume":95}]'::jsonb, '[]'::jsonb, ARRAY['추세 지속 확신으로 보유 비중 추가 불타기', '상승 모멘텀 약화 다이버전스 확인 후 50% 익절', '익절 설정 없이 전고점 도달 시까지 홀딩', '고점 붕괴 기대로 숏 포지션 10배 베팅']::text[], 1, '골드 가격는 올라가나 모멘텀 지표인 MACD 오실레이터 고점이 낮아지는 현상은 대표적인 하락 다이버전스로, 매수 에너지가 속 빈 강정처럼 쇠퇴하고 있어 언제든 급격한 폭락 조정이 발생할 수 있는 고위험 신호입니다. 이 시점에는 탐욕을 통제하고 물량의 50% 이상을 분할 매도하여 현금을 챙기는 것이 원칙입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (955, '지표/컨플루언스', '06_technical_indicators.md', '골드 가격가 하락 횡보하던 도중, 단기 지평선인 EMA 20일선이 중장기선인 EMA 50일선에 극도로 밀착하며 수렴했습니다. 당일 대량 거래량의 음봉 캔들이 터지며 단기선이 장기선 아래로 교차하기 직전(데드크로스 임박)이며 주요 지지선 밑으로 떨어졌습니다. 롱(매수) 포지션 보유자의 올바른 대응은?', '[{"time":"Day 1","open":5250,"high":5300,"low":4950,"close":5000,"volume":105},{"time":"Day 2","open":5000,"high":5050,"low":4750,"close":4800,"volume":102}]'::jsonb, '[]'::jsonb, ARRAY['지지선 이탈 및 데드크로스 확인 즉시 손절', '이평선 지지력을 믿고 하방 물타기 추가 매수', '하락 조정 후 반등 기대로 무기한 홀딩 관망', '청산가 도달 시까지 어떠한 대응 없이 방치']::text[], 0, '20일선과 50일선의 데드크로스 임박 수렴 상태에서 가격이 지지선마저 무너뜨린 것은 하락 가속화 추세가 폭발하기 직전인 매우 위험한 기술적 상태입니다. 하락 추세가 본격 정배열(하락 정배열)화 되기 전에 즉시 전량 손절하고 시장 밖에서 피신해 있는 것이 계좌의 영구 파산을 막는 유일한 생존 규칙입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (956, '리스크/심리', '09_risk_position_management.md', '원자재 매수 후 가격이 급락하여 내가 설정해 둔 최대 감내 손실 한도인 계좌 총원금 대비 -2% 라인(손절매 지정 가격)에 완벽하게 닿았습니다. 마침 본전 생각과 함께 ''조금만 더 버티면 반등할 텐데...''하는 강한 뇌동매매 유혹이 솟구칩니다. 이때 원칙 트레이더의 결정은?', '[{"time":"Day 1","open":5000,"high":5100,"low":4950,"close":5000,"volume":98},{"time":"Day 2","open":5000,"high":5050,"low":4700,"close":4750,"volume":117}]'::jsonb, '[]'::jsonb, ARRAY['손절 라인을 임의로 하향 조정하고 홀딩', '평단가 관리 차원의 지속적 물타기 매수 집행', '원칙에 따라 뇌동을 제어하고 즉시 기계적 손절', '손실은 배제하고 반등 기대를 통한 무기한 보유']::text[], 2, '트레이딩의 승패는 예측이 아닌 ''리스크 통제''에 달려 있습니다. 사전에 정한 계좌 대비 2% 리스크 한도에 도달했을 때 희망 회로를 돌리며 손절을 미루거나 물타기를 집행하는 순간 계좌는 서서히 영으로 깎여 파산합니다. 멘탈의 충동을 통제하고 기계적으로 전량 칼손절하는 것이 절대 파산하지 않는 시장의 1법칙입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (957, '리스크/심리', '10_psychology_routine_review.md', '최근 3회 연속 거래에서 계속해서 손절(Stop Loss)을 맞아 뇌 내의 도파민 체계가 무너지고 심리가 극도로 불안해져 분노와 보복 매매 충동이 밀려옵니다. 이 상황에서 파산을 막는 가장 훌륭한 매매 심리 대처법은?', '[{"time":"Today","open":5000,"high":5000,"low":5000,"close":5000}]'::jsonb, '[]'::jsonb, ARRAY['손실 복구를 위해 레버리지를 증액해 즉시 진입', '뇌동 방지를 위해 HTS를 종료하고 매매 일지 작성 및 휴식', '추천 매매 신호 유료 리딩방에 즉시 가입 및 추종', '심리적 회복을 위해 역베팅 숏 포지션 추가']::text[], 1, '연속 손실 후 발생하는 복수심과 분노는 트레이더를 뇌동매매와 계좌 파멸로 이끄는 가장 치명적인 감정 상태입니다. 멘탈 붕괴를 느꼈을 때는 즉각 행동을 멈추고 시스템을 강제 종료하여 시장과 물리적 격리를 통해 냉정을 찾는 것만이 자산을 파산 리스크로부터 살려내는 훌륭한 트레이딩 행동입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (958, '셋업/실행', '09_risk_position_management.md', '진입하고자 하는 매수 자리를 분석해 보니, 기술적 분석 상 이길 수 있는 확률(승률)은 반반인 50% 수준입니다. 그러나 손절 시 기대 손실금액 대비 성공 시 획득할 수 있는 기대 수익금액의 비율(손익비)을 정밀 셋업 해보니 1 : 1.2 수준으로 다소 애매하게 도출되었습니다. 원칙 트레이더의 진입 결정은?', '[{"time":"Today","open":5000,"high":5000,"low":5000,"close":5000}]'::jsonb, '[]'::jsonb, ARRAY['단기 변동성 기대로 부적합한 손익비 시장가 진입', '마이너스 기댓값 거래 유보 및 우수 타점 대기', '레버리지를 높여 손익비 구조를 임의 조정 시도', '반대 방향으로 고배율 역베팅을 즉시 실행']::text[], 1, '수학적으로 승률 50%일 때 손익비가 최소 1:2(잃을 때 1, 벌 때 2) 이상이 나오지 않으면 복리 매매 시 수수료와 호가 슬리피지에 밀려 잔고가 무조건 마이너스로 수렴합니다. 타점이 눈에 들어오더라도 사전에 기대 손익비 필터에 걸려 탈락한다면 패스를 선언하고 관망하는 것이 현명한 생존 원칙입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (959, '리스크/심리', '09_risk_position_management.md', '갑작스러운 거시 경제 발표로 내가 매매 중인 종목의 캔들 변동성 폭(ATR)이 평소 시세의 2배 수준으로 널뛰기 시작했습니다. 1회 거래당 내 계좌 원금의 최대 2% 리스크 한도를 동일하게 고수하기 위해 취해야 할 올바른 조치는?', '[{"time":"Day 1","open":5000,"high":5100,"low":4900,"close":5000,"volume":106},{"time":"Day 2","open":5000,"high":5500,"low":4500,"close":5100,"volume":108}]'::jsonb, '[]'::jsonb, ARRAY['평소 변동성과 동일한 비중 및 손절 거리 고수', '손절 거리를 넓히는 대신 진입 포지션 수량 축소', '변동성이 확대되었으므로 2배 비중으로 적극 지름', '즉시 전량 손절하고 시장 상황 정상화 대기']::text[], 1, '시장 변동성이 커질 때는 손절 스톱 아웃이 잦으므로 손절폭(%)을 넓혀 숨 쉴 공간을 확보해 주는 것이 합리적입니다. 단, 손절폭을 2배로 늘린다면 계좌 대비 리스크 한도가 2배(4%)로 커지므로, 진입 포지션의 계약 수량을 50%로 줄여 리스크 노출 총액을 2%로 완벽하게 동일 통제하는 것이 포지션 사이징(Position Sizing)의 정석 원칙입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (960, '리스크/심리', '09_risk_position_management.md', '투자자 A의 전체 투자 원금은 25,000만 원이며, 1회 거래당 최대 허용 리스크 금액은 원금의 2%인 500만 원입니다. 현재 골드 가격가 500,000원이며, 기술적 분석 상 합리적인 손절선은 지지선 바로 밑인 475,000원(-5%)입니다. 2% 룰 리스크 관리 원칙에 따라 A가 진입(매수)해야 하는 최대 원자재 수량은?', '[{"time":"Today","open":500000,"high":500000,"low":500000,"close":500000}]'::jsonb, '[]'::jsonb, ARRAY['500주 (투자금 전액 시장가 매수)', '200주 (손실 한도 500만 원 맞춤 매수)', '50주 (보수적 극단적 비중 축소)', '100주 (절반 비중 고정 매수)']::text[], 1, '포지션 크기 계산 공식은 `최대 매수 규모 = 최대 허용 리스크 금액 / 손절매 비율` 입니다. 이 시나리오에서 `5,000,000원 / 0.05(5%) = 100,000,000원`이 최대 허용 진입금액이 되며, 이를 골드 가격 500,000원으로 나누면 `200주`가 도출됩니다. 200주 진입 후 -5% 가격 폭락으로 손절 당해도 내 총원금에서 깎이는 돈은 정확히 500만 원(2%)으로 완벽히 리스크 통제됩니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (961, '거래량/유동성', '05_volume_liquidity.md', '골드 가격가 수평 저항선 부근까지 급상승했으나 캔들 몸통(Spread)이 지극히 좁아진 도지 형태로 마감하였고, 거래량은 이전 5일 평균 대비 3배 이상 폭증했습니다. VSA(Volume Spread Analysis) 관점에서 가장 타당한 차트 분석은?', '[{"time":"Day 1","open":5000,"high":5250,"low":4950,"close":5200,"volume":103},{"time":"Day 2","open":5200,"high":5450,"low":5150,"close":5400,"volume":89},{"time":"Day 3","open":5400,"high":5500,"low":5350,"close":5400,"volume":107}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":5450},{"x":2,"y":5450}],"label":"저항선","color":"#ef4444"}]'::jsonb, ARRAY['강한 매수 기세 기대로 즉시 돌파 매매 풀매수', '저항벽 매도 공급 세력 분산 확인 후 이익 실현', '대량 거래 확인에 따른 손절 해제 후 장기 투자', '반등 실패에 따른 고배율 보복 숏 베팅 가동']::text[], 1, '캔들 몸통 크기(스프레드)가 좁은데 거래량이 매우 크게 폭증했다는 것은 저항선 부근에서 들어오는 매수세만큼 세력의 매도 물량 공급이 쏟아져 막강한 저항 벽을 형성하고 있다는 뜻입니다. VSA에서는 이를 불화(Disharmony)로 규정하며 상승 추세 감속 및 하락 반전의 경고로 해독합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (962, '거래량/유동성', '05_volume_liquidity.md', '골드 가격가 장기 횡보하던 박스권 지지선인 10,000달러를 깨고 9,750달러까지 하락 투매가 발생했으나, 종가 마감 직전 거래량이 크게 실린 긴 아래꼬리를 그리며 다시 10,050달러 위로 복귀 안착했습니다. 이 스톱 헌팅 유동성 현상에서의 실전 트레이더의 대응은?', '[{"time":"Day 1","open":10500,"high":10600,"low":10000,"close":10100,"volume":107},{"time":"Day 2","open":10100,"high":10200,"low":9750,"close":10050,"volume":101}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":10000},{"x":1,"y":10000}],"label":"지지선","color":"#10b981"}]'::jsonb, ARRAY['지지선 붕괴 확정으로 간주한 시장가 숏 추격', '스윕(sweep) 판단 하에 아래꼬리 저점 손절 잡고 롱', '아무런 신호도 아니라고 판단하고 포지션 방치', '지지선 이탈 기대로 전량 손절 후 시장 영구 탈출']::text[], 1, '지지선 아래에 걸려 있던 개인들의 손절 주문(Sell Stop)을 강제로 청산(Liquidity Sweep)시킨 뒤, 세력이 물량을 헐값에 다 받아 삼켜 종가를 지지선 위로 신속하게 복귀시킨 휩소(베어 트랩) 패턴입니다. 아래꼬리 극점(9,750달러)에 아주 좁은 손절 라인을 설정할 수 있어, 기대 손익비가 극대화되는 고확률 상승 반전 매수 타점입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (963, '거래량/유동성', '05_volume_liquidity.md', '골드 가격는 12,500달러에서 14,500달러까지 계속 고점을 높이며 상승 추세를 이어가고 있습니다. 그러나 각 상승 파동마다 터지는 거래량은 전고점 돌파 시점 대비 눈에 띄게 하향 곡선을 그리며 감소하고 있습니다. VSA 기법에 따른 합리적인 진단은?', '[{"time":"Wave 1","open":11500,"high":13000,"low":11400,"close":12750,"volume":101},{"time":"Wave 2","open":12750,"high":13750,"low":12500,"close":13500,"volume":109},{"time":"Wave 3","open":13500,"high":14500,"low":13250,"close":14400,"volume":110}]'::jsonb, '[]'::jsonb, ARRAY['가격 상승으로 인한 매수 지속 강화 초강세', '매도 물량 고갈에 따른 무중력 안심 홀딩', '신규 자금 유입 둔화 거래량 다이버전스로 분할 익절', '지표 조작으로 판단하여 매매 중단 및 차트 종료']::text[], 2, '골드 가격는 상승하여 신고점을 갱신하지만 파동별 거래량이 지속 감소하는 흐름은 ''거래량 다이버전스''로 상승 모멘텀의 내부 엔진이 식어감을 경고합니다. 조만간 가벼운 매도 포격에도 대규모의 차익 실현 폭락 조정이 발생할 수 있는 잠재적 폭락 국면이므로 물량을 덜어내고 현금을 확보해야 합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (964, '거래량/유동성', '05_volume_liquidity.md', '가격이 이전 고점 저항선을 뚫고 강하게 솟구치며 장대양봉을 만들었습니다. 이때 가짜 이탈(Whipsaw / Bull Trap)이 아닌 진성 돌파(True Breakout)로 판정할 수 있는 가장 신뢰도 높은 거래량 기준은?', '[{"time":"Day 1","open":5000,"high":5100,"low":4950,"close":5000,"volume":370},{"time":"Day 2","open":5000,"high":5600,"low":4950,"close":5500,"volume":354}]'::jsonb, '[]'::jsonb, ARRAY['수렴 끝자락에서 거래량이 최저치인 상태 유지', '평균 대비 1.5~2배 이상 거래량 급증하며 돌파 마감', '거래량이 전혀 변하지 않는 평이한 상태 유지', '호가 스프레드가 가장 좁아지는 횡보 상태']::text[], 1, '참된 저항 돌파(True Breakout)는 저항선 부근의 두터운 대기 매도 공급 물량을 대규모 자금으로 전부 씹어 삼키고 돌파해야 함을 뜻합니다. 따라서 반드시 평균 대비 1.5배~2배 이상의 거래량 분출이 동반되어야 신뢰할 수 있으며, 거래량이 적은 돌파는 꼬리 달고 내려앉는 불 트랩(Bull Trap)일 확률이 매우 높습니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (965, '거래량/유동성', '05_volume_liquidity.md', '금 선물 차트에서 중요 지지선 직전 저점 아래에 엄청난 규모의 롱 포지션 청산 및 매도 손절 주문이 쌓여 있는 유동성 풀(Liquidity Pool) 구간이 감지되었습니다. 세력이 이 구간을 공략할 때 나타날 캔들의 전형적인 무빙 패턴은?', '[{"time":"Day 1","open":2500000,"high":2525000,"low":2460000,"close":2475000,"volume":25},{"time":"Day 2","open":2475000,"high":2490000,"low":2400000,"close":2480000,"volume":20}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":2460000},{"x":1,"y":2460000}],"label":"전저점 지지선","color":"#3b82f6"}]'::jsonb, ARRAY['지지선을 장대음봉으로 돌파하여 20% 폭락 마감', '전저점 이탈로 손절 유도 후 지지선 위 아래꼬리 안착', '오차 없이 지지선 터치 후 꼬리 없는 수평 도지 횡보', '거래량 없이 즉각 상승 빔 분출로 전고점 탈환']::text[], 1, '기관 세력(스마트 머니)은 대량 포지션을 구축하기 위해 개인의 손절 주문(Sell Stop)을 의도적으로 터트려 매도 유동성을 유도한 후 이를 다 매수합니다. 이로 인해 골드 가격는 지지선 아래로 일시 급락 후(스톱 헌팅), 아래꼬리를 매우 길게 달며 지선 안쪽으로 급반등 마감하게 됩니다. 이것이 유동성 스윕(Liquidity Sweep)의 정석 패턴입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (966, '거래량/유동성', '05_volume_liquidity.md', '상승 추세 도중 전고점 저항선 부근에서 위꼬리가 아주 긴 캔들이 터졌고, 거래량은 최근 보름 중 최고 수치로 솟구쳤습니다. VSA 관점에서 이 상승 거절(Upside Rejection) 현상에 대한 올바른 대처는?', '[{"time":"Day 1","open":5000,"high":5750,"low":4900,"close":5050}]'::jsonb, '[]'::jsonb, ARRAY['강한 저점 매수 기회로 인지하여 비중 대폭 추가', '고점 매도 Rejection 확인 후 기존 롱 포지션 대피', '박스 횡보 수렴 기대로 마틴게일 추가 매수 가동', '이평선 정배열 판단에 따른 포지션 변경 없이 홀딩']::text[], 1, '위꼬리가 매우 긴 캔들이 대량 거래량과 함께 터졌다는 것은 고점 돌파 시도가 있었으나 그 자리에 숨어 있던 세력의 막강한 청산 매도 벽(Supply)을 만나 격렬하게 두들겨 맞고 밀려났음을 의미합니다. 상방 거절의 심리가 지배적이므로 고점 피로 및 하락 전환이 임박한 위험 징후입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (967, '지표/컨플루언스', '06_technical_indicators.md', '골드 가격가 장기 박스권 횡보를 이어가며 볼린저 밴드의 폭이 최근 몇 달 중 가장 좁은 형태로 밀착 수렴(Squeeze)되었습니다. 이 스퀴즈 국면에 대한 올바른 기술적 이해와 매매 시나리오는?', '[{"time":"Week 1","open":5000,"high":5150,"low":4850,"close":5050,"volume":91},{"time":"Week 2","open":5050,"high":5100,"low":4950,"close":5000,"volume":88}]'::jsonb, '[]'::jsonb, ARRAY['박스권 변동성 부재 기대로 장기 무대응 관망', '에너지 수축 스퀴즈 확인 후 밴드 이탈 돌파 대기', '지표 신뢰 불가 판단으로 볼린저 밴드 지표 삭제', '중심선 지지로 판단하여 고배율 매수 대기 주문']::text[], 1, '볼린저 밴드의 폭이 극도로 좁아지는 스퀴즈(Squeeze) 현상은 시장의 표준편차 변동성이 임계치까지 압축 수렴되었음을 알려줍니다. 에너지 압축 뒤에는 항상 폭발적인 가격 분출(상방/하방 이탈)이 뒤따르므로, 밴드를 뚫고 거래량이 실려 돌파 마감하는 방향으로 추세 추종 시나리오를 설계해야 합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (968, '지표/컨플루언스', '06_technical_indicators.md', '골드 가격는 HL(Higher Low)을 형성하며 이전 직전 저점(4,500달러)보다 높은 저점(4,750달러)을 지키고 있으나, RSI 지표는 이전 35 수치보다 더 깊숙하게 25 수치까지 떨어졌습니다. 이 지표 불일치 현상의 공식 명칭과 올바른 포지션 셋업은?', '[{"time":"Day 1","open":5000,"high":5100,"low":4500,"close":4550,"volume":94},{"time":"Day 2","open":4550,"high":4800,"low":4750,"close":4750,"volume":121}]'::jsonb, '[]'::jsonb, ARRAY['일반 상승 다이버전스 - 추세 종결로 즉각 공매도', '히든 상승 다이버전스 - 지선 눌림목 롱 진입 활용', '일반 하락 다이버전스 - 모든 매수 포지션 정리', '지표 오작동 휩소 구간 판단으로 양방향 관망']::text[], 1, '가격의 저점은 높아졌는데(Higher Low) 모멘텀 지표의 저점은 낮아지는 현상은 ''히든 상승 다이버전스(Hidden Bullish Divergence)''입니다. 이는 추세 반전이 아닌 **기존 강세 추세 지속**을 뜻하며, 조정 눌림목이 완성되고 다음 상승 랠리를 준비한다는 최고의 매수 신호 중 하나입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (969, '지표/컨플루언스', '06_technical_indicators.md', '매수 타점을 신중하게 선별하고자 합니다. 기술적 분석의 성공 확률을 비약적으로 끌어올리는 ''다중 컨플루언스(Confluence)'' 결합 사례로 가장 적합한 조건 구성은?', '[{"time":"Today","open":5000,"high":5000,"low":5000,"close":5000}]'::jsonb, '[]'::jsonb, ARRAY['트위터 및 뉴스의 호재 찌라시 확인 즉시 추격', '지지선+이평선+다이버전스+아래꼬리 등 분석 중첩 시', 'RSI 과매수 영역 진입 즉시 롱 포지션 진입', '독립적 분석 없이 오직 보조지표의 단일 수치 신호']::text[], 1, '다중 컨플루언스(Confluence)는 독립적인 기술적 근거들이 동일한 특정 가격 구역에 중첩되는 현상입니다. 지지 저항, 이평선, 보조지표 다이버전스, 캔들 가격행동(Rejection 핀바)이 한 곳에 묶여 매수 자리를 형성할 때 매매를 실행하면, 높은 신뢰도와 좁은 손절 라인 덕분에 장기 기대값이 극대화됩니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (970, '셋업/실행', '08_setup_entry_exit.md', '중요 수평 저항선(6,000달러)을 상방으로 장대양봉 종가 돌파한 것을 확인하고 롱(매수) 진입 셋업을 준비하고 있습니다. 원칙 트레이더가 뇌동매매 추격을 막고 최상의 손익비를 확보하기 위해 즐겨 쓰는 정석적인 진입 실행법은?', '[{"time":"Day 1","open":5500,"high":5600,"low":5450,"close":5550,"volume":96},{"time":"Day 2","open":5550,"high":6200,"low":5500,"close":6100,"volume":123}]'::jsonb, '[{"type":"horizontal-line","points":[{"x":0,"y":6000},{"x":1,"y":6000}],"label":"저항선","color":"#ef4444"}]'::jsonb, ARRAY['돌파 마감 확인 즉시 시장가 추가 매수 집행', '돌파된 저항선의 지지 전환(Retest) 시 지정가 진입', '반등 조정이 불가능하다고 판단하여 최고점 롱 추격', '속임수 돌파 확신으로 고배율 역베팅 숏 진입']::text[], 1, '저항 돌파 후 즉시 가격을 따라붙는 추격 매수는 휩소 조정 시 심각한 손실을 초래합니다. 돌파된 라인이 S/R Flip을 통해 지지로 작용하는지 확인하는 되돌림 리테스트(Retest) 시점에 진입하는 것이, 지선 바로 아래에 좁은 손절 라인을 설계하고 이익 기대 폭을 넓힐 수 있는 가장 이상적인 정석 실행법입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (971, '셋업/실행', '08_setup_entry_exit.md', '포지션 진입 직후, 가격이 계획대로 내 방향으로 순탄하게 우상향하고 있습니다. 기존 진입 시 설정한 손익비 1:2의 최종 목표가 도달 전에, 리스크 관리 차원에서 계좌 드로다운을 0으로 만드는 정석적인 1차 포지션 관리 행동은?', '[{"time":"Entry","open":5000,"high":5000,"low":5000,"close":5000,"volume":114},{"time":"Day 1","open":5000,"high":5300,"low":5000,"close":5250,"volume":87}]'::jsonb, '[]'::jsonb, ARRAY['1차 저항대 진입 시 레버리지를 활용해 불타기', '목표가 터치 시까지 100% 비중 무대응 홀딩', '1:1 지점 50% 분할 익절 및 남은 물량 본전 손절 상향', '단기 반등 확인 즉시 전량 기계적 청산 및 퇴장']::text[], 2, '이득이 발생해 손익비 1:1 수준에 오면 물량의 절반을 분할 익절(Scale-out)하고 남은 포지션의 스톱로스를 진입가로 이동(Break-even)시키는 것이 포지션 관리의 기본입니다. 이렇게 셋업하면 차트가 갑자기 폭락세로 뒤집혀도 최소 본전 혹은 반절 익절 약수익으로 끝나 해당 거래의 최대 리스크가 Zero(0)로 봉쇄됩니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (972, '셋업/실행', '08_setup_entry_exit.md', '강력한 장기 상승 추세가 터져 골드 가격가 20일 이평선을 타고 계속해서 폭발적으로 신고가를 갱신하고 있습니다. 이때 익절 시점을 서둘러 잡지 않고, 추세 상승 이익을 최대한 길게 끝까지 빨아먹기 위한 정석 청산 실행법은?', '[{"time":"Day 1","open":5000,"high":5500,"low":4950,"close":5400,"volume":87},{"time":"Day 2","open":5400,"high":6000,"low":5350,"close":5900,"volume":118},{"time":"Day 3","open":5900,"high":6750,"low":5850,"close":6600,"volume":124}]'::jsonb, '[]'::jsonb, ARRAY['RSI 과과열 조짐 확인 즉시 시장가 전량 익절', 'Higher Low 지지 직하방으로 손절 추종 익절 셋업', '이익 보존을 포기하고 손익절 라인을 해제 후 홀딩', '즉시 숏 포지션 10배로 맞불을 놓는다']::text[], 1, '강세 추세가 터졌을 때 지레짐작으로 청산하면 상승 파동의 초입만 먹고 끝납니다. 추세 붕괴의 명확한 신호(BOS/MSB)가 나오거나, 가격의 구조적 높은 저점(HL)이 깨질 때까지 손절 라인을 계속 추종해서 상향하는 ''추격 손절매(Trailing Stop)''를 가동하는 것이 추세 이익을 극대화하는 정석 기법입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (973, '셋업/실행', '01_chart_market_basics.md', '차트 분석 결과, 돌파 시점의 체결 변동성과 거래소 호가창의 얇은 매물 상태를 감안할 때 내가 진입하려는 주문 가격에서 체결이 뒤로 밀리는 ''슬리피지(Slippage)''가 심각하게 예상됩니다. 이를 감안한 올바른 주문 실행법은?', '[{"time":"Today","open":5000,"high":5000,"low":5000,"close":5000}]'::jsonb, '[]'::jsonb, ARRAY['시장가로 최고 배율을 설정하여 즉시 체결', '돌파 확인 후 지정가 대기 주문으로 단가 조절', '슬리피지를 예방하기 위해 즉각적인 거래 취소', '호가창 스프레드와 무관하게 고배율 레버리지']::text[], 1, '변동성이 크고 호가가 얇은 시장에서 돌파 시 시장가 진입은 나쁜 단가로 체결되는 슬리피지 비용을 발생시켜 시작부터 손실을 크게 안고 갑니다. 돌파 확인 후 되돌림 가격대에서 지정가(Limit Order)를 대기시켜 체결 단가를 내 손아귀에 고정하는 리스크 관리가 필요합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (974, '셋업/실행', '10_psychology_routine_review.md', '원칙 기반의 정석 매매 셋업(Trading Setup)을 설계할 때, 진입 전 반드시 사전에 수치로 명문화되어 결정되어야 할 요소가 아닌 것은?', '[{"time":"Today","open":5000,"high":5000,"low":5000,"close":5000}]'::jsonb, '[]'::jsonb, ARRAY['진입 조건(Trigger)과 구체적인 손절 가격(Stop Loss)', '거래 당일 본인의 주관적인 직감과 감정적 목표가', '진입하려는 구체적인 포지션 규모 및 분할 익절선', '거래 아이디어가 무효화되는 구체적 가격 지점']::text[], 1, '매매 셋업은 규칙에 기반한 수치들(진입가, 손절가, 목표가, 수량)로 사전에 철저히 규격화되어야 합니다. 당일의 운이나 주관적 느낌, 예감에 기초한 비과학적 청산 설정은 셋업에서 배제되어야 할 대표적 뇌동매매 요소입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (975, '셋업/실행', '08_setup_entry_exit.md', '하락 횡보하던 골드 가격가 중요 매물대이자 피보나치 되돌림 0.618 지점에 정확히 맞닿아 아래꼬리가 긴 양봉 핀바(Pin Bar)를 그리며 마감했습니다. 룰베이스 트레이더가 진입 버튼을 누를 때 성립된 IF-THEN 시나리오는?', '[{"time":"Day 1","open":5000,"high":5000,"low":4000,"close":4100,"volume":91},{"time":"Day 2","open":4100,"high":4300,"low":3900,"close":4250,"volume":113}]'::jsonb, '[]'::jsonb, ARRAY['익일 가격 상황과 관계없이 100배 레버리지 진입', '중첩 자리 핀바(rejection) 확인 후 익일 시가 롱 진입', '상단 저항 도달 판단으로 즉각적인 숏 포지션 진입', '돌파 랠리가 완전히 끝날 때까지 HTS 종료 및 관망']::text[], 1, '훌륭한 트레이딩 실행은 ''IF(조건 만족 시) ➔ THEN(원칙대로 포지션 진입 및 손절/목표가 기계적 배치)''의 룰베이스 알고리즘에 의해 움직여야 감정을 배제할 수 있습니다. 지지 구간 중첩과 핀바 출현 조건이 성립했으므로 다음 봉 시가에 진입하되 꼬리 저점 이탈 시 칼손절하여 리스크를 통제하는 것이 정석입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (976, '리스크/심리', '09_risk_position_management.md', '나의 트레이딩 시스템 승률이 40%로 다소 낮게 고정되어 있습니다. 이 시스템을 통해 장기적으로 파산하지 않고 복리로 계좌 자산을 우상향시키기 위해 필수적으로 지켜야 할 손익비(평균손실 대비 평균수익 비율)의 최소 기준은?', '[{"time":"Today","open":5000,"high":5000,"low":5000,"close":5000}]'::jsonb, '[]'::jsonb, ARRAY['손익비 1:1 수준 (매매 승률이 낮을 때 파산)', '승률 40% 대비 기댓값 개선을 위한 손익비 1:1.5 이상', '낮은 승률 상태에서 손익비와 무관하게 무조건 파산', '승률 극복을 위한 레버리지 20배 수준 설정']::text[], 1, '승률이 40%일 때 기대값 수학적 수수료 감안 최소 손익비는 1:1.5입니다. 손익비 1.5배 이상 구간만 취하면 10번 중 6번 손절당하고 단 4번만 익절하더라도 계좌 총합은 수익 우위에 서게 됩니다. 저승률 시스템일수록 철저히 손익비가 유리한 진입가 근처 타점만 기계적으로 필터링해 진입해야 생존합니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (977, '리스크/심리', '09_risk_position_management.md', '선물 트레이더인 B는 담보금 효율을 극대화한다는 명목으로 50배 레버리지 롱 포지션 진입을 실행했습니다. 진입 가격 대비 B의 포지션 원금이 완전 소멸(강제 청산)되는 역방향 하락 거리(%)는 대략 몇 % 수준입니까?', '[{"time":"Today","open":5000,"high":5000,"low":5000,"close":5000}]'::jsonb, '[]'::jsonb, ARRAY['진입 단가 대비 20.0%의 강한 하락 발생 시', '진입 단가 대비 단 -2.0% 변동성 노이즈 터치 시', '진입 단가 대비 50.0%의 강한 폭락 발생 시', '청산가가 산출되지 않는 특이 종목 거래 시']::text[], 1, '청산 거리 계산 공식은 대략 `100% / 레버리지 배수` 입니다. 50배 고배율 레버리지의 경우, 내 포지션 반대 방향으로 단 **-2%**의 시세 변동성(장중 흔한 잔파동 노이즈)만 터치해도 원금이 100% 강제 청산 증발됩니다. 고배율 레버리지는 수학적 확률상 100% 파멸을 초래하는 도박성 거래 행위입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (978, '리스크/심리', '09_risk_position_management.md', '트레이딩 계좌 총자산이 100,000만 원인 트레이더가 있습니다. 1회 거래당 총자산의 2% 룰 원칙에 근거하여 리스크 한도(2,000만 원)를 설정했습니다. 진입하려는 종목의 손절가 거리가 -8%인 경우, 2% 룰을 완벽하게 충족하는 최대 진입(매수) 금액은?', '[{"time":"Today","open":5000,"high":5000,"low":5000,"close":5000}]'::jsonb, '[]'::jsonb, ARRAY['100,000만 원 전액 매수 (손절 폭을 배제한 대규모 베팅)', '25,000만 원 진입 (-8% 손절 시 리스크 한도 2,000만 원 충족)', '50,000만 원 진입 (손익비 1:1 기준에 맞춘 베팅)', '10,000만 원 진입 (보수적 원칙에 입각한 극단적 축소)']::text[], 1, '포지션 사이징 공식은 `진입금액 = 최대 리스크 허용액(2,000만 원) / 손절 비율(0.08)` 입니다. 이에 따라 `20,000,000원 / 0.08 = 250,000,000원`이 도출됩니다. 25,000만 원 규모로 매수 진입 시 가격이 급락해 -8% 손절 라인을 때려도 내 총자산에서 깎이는 금액은 정확히 원칙 한도인 2,000만 원(2%)으로 제한되어 계좌가 완벽히 방어됩니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (979, '리스크/심리', '10_psychology_routine_review.md', '장중에 내가 째려보며 타점을 기다리던 원자재이 아무런 조정도 없이 장대양봉을 그리며 갑자기 수직 폭등하기 시작하여 5% 이상 치솟았습니다. 이때 머릿속에 ''나만 두고 날아가는 것 아닌가''하는 극심한 소외감 공포(FOMO)가 솟구칩니다. 원칙 트레이더의 올바른 심리 대응은?', '[{"time":"Day 1","open":5000,"high":5100,"low":4950,"close":5000,"volume":112},{"time":"Day 2","open":5000,"high":5300,"low":5000,"close":5250,"volume":91}]'::jsonb, '[]'::jsonb, ARRAY['추세 연장 판단으로 시장가 전액 추격 매수', 'FOMO 판단 하에 매수 보류 및 정석 되돌림 타점 대기', '돌파 실패 판단 하에 반대 방향 고배율 숏 베팅', '거래를 종료하고 즉각 원자재 시장에서 전량 탈출']::text[], 1, '나만 기회를 잃는다는 공포(FOMO)로 날아가는 장대양봉 꼭대기에서 추격 매수하는 행위는 고점 물리기를 자처하는 가장 흔한 뇌동매매 패턴입니다. 내 타점을 비껴간 상승은 내 돈이 아니라고 인정하고, 사전에 정의한 룰베이스 타점까지 냉정하게 대기하는 것이 장기 생존자의 멘탈 습관입니다.');
INSERT INTO public.quizzes (id, category, theory_ref, question, chart_data, drawings, options, correct_index, explanation) VALUES (980, '리스크/심리', '10_psychology_routine_review.md', '오전 거래에서 원칙을 어긴 무리한 진입으로 인해 3회 연속 스톱아웃(손절)을 당하여 당일 원금의 -6%의 큰 손실을 입었습니다. 본전 생각과 분노로 눈이 뒤집혀 비중을 올려 한 판으로 복수하려는 ''보폭 매매'' 충동이 폭발할 때, 파산을 막는 가장 강력한 멘탈 시스템 룰은?', '[{"time":"Today","open":5000,"high":5000,"low":5000,"close":5000}]'::jsonb, '[]'::jsonb, ARRAY['손실 만회를 위해 빌린 돈으로 100배 고배율 복수 베팅', '일일 손실 한도 도달에 따른 매매 강제 종료 및 격리', '주변 유료 전문가 추천 종목을 탐색해 즉각 매수', 'RSI 과매도 상태이므로 즉시 반대 숏 포지션 진입']::text[], 1, '연패를 겪은 후 홧김에 비중을 더 크게 실어 한 번에 본전을 찾으려는 보복 매매는 계좌를 하루 만에 휴지조각으로 만드는 가장 무서운 파산 유도 심리 상태입니다. 이를 막기 위해 하루 최대 손실 한도 한계선(예: 3회 손절 또는 원금의 5%)을 정해두고, 이 한계선 터치 시 즉시 차트를 종료하고 냉각기를 강제 집행하는 룰이 필수입니다.');
